INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:0-fool', 'tarot', '0-fool', 0, '愚者', 'The Fool', 'https://images.pexels.com/photos/6985001/pexels-photo-6985001.jpeg', '{"keywords":["新開始","冒險","純真","自由","信任"],"arcana":"major","number":0}', '{"uprightMeaning":"愚者象徵全新的開始和無限的可能性。這張牌代表你即將踏上一段充滿冒險的旅程，帶著純真的心和開放的態度去探索未知。現在是放下過去包袱，以嬰兒般的好奇心擁抱新經驗的時刻。愚者鼓勵你相信宇宙的安排，即使前方的道路看似不確定，也要勇敢地跨出第一步。這是一個充滿自由精神和自發性的時期，適合嘗試新事物、學習新技能或開展新計劃。保持輕鬆愉快的心情，不要過度擔憂結果，讓生命的河流自然地引領你前進。","reversedMeaning":"逆位的愚者提醒你需要更加謹慎和深思熟慮。你可能正在做出魯莽的決定，而沒有考慮到潛在的風險和後果。這張牌顯示出缺乏計劃、方向不明確，或是過度天真的態度可能會為你帶來困擾。現在不是盲目跳躍的時候，而是需要停下來評估情況，做好充分準備。你可能因為害怕失敗而猶豫不決，或是因為過度自信而忽視了重要的細節。逆位的愚者建議你在行動前先建立穩固的基礎，並認真思考這個決定是否真的適合你。","detailedInterpretation":{"coreKeywords":{"upright":["新開始","冒險","自由","純真","信任宇宙"],"reversed":["魯莽","猶豫不決","缺乏計劃","過度天真","恐懼"],"uprightExplanation":"愚者正位代表生命旅程的起點，象徵著不帶成見和恐懼的純粹探索精神。這是零號牌，包含所有可能性，也尚未被任何經驗限制。正位愚者的能量是輕盈、自由、充滿希望的，如同初生的嬰兒對世界充滿好奇。這個階段的你不需要知道所有答案，反而應該保持開放和彈性。愚者踏出懸崖的那一步，看似危險，實則是對宇宙最深的信任。這是「信念之躍」的時刻，你被召喚去相信看不見的道路會在你腳下展開。","reversedExplanation":"愚者逆位顯示你可能在兩個極端之間搖擺：要麼過度謹慎而錯失機會，要麼過度衝動而缺乏準備。逆位時，那份純真變成了天真，自由變成了無方向感。你可能因為過去的傷痛而不敢再次冒險，或是因為太過自信而忽略了實際的風險。這張牌提醒你，真正的智慧不是不跳躍，而是在跳躍前先看清楚懸崖的高度。有時候逆位愚者也代表你已經準備好了，但恐懼讓你停留在原地。需要的不是更多準備，而是面對恐懼的勇氣。"},"energyFlow":{"direction":"往前","type":"輸出","description":"這是一股向外擴展、探索未知的能量。愚者的能量像孩童般好奇，充滿活力地往前邁進，不受過去束縛。能量流動是自由的、開放的，不設限制。"},"timing":{"speed":"快速","description":"事情會突然展開，機會來得迅速。這是立即行動的時機，不要等待。通常在1-3週內會看到明顯的開始或變化。"},"advice":{"upright":"放下恐懼，相信直覺，立即跨出第一步。不需要計劃得很完美，重要的是開始行動。保持開放的心態，擁抱未知。","reversed":"先停下來評估風險，做好基本規劃再行動。不要被衝動驅使，給自己時間思考清楚。尋求他人意見，補足盲點。"},"chakra":{"primary":"頂輪 + 海底輪","issue":"與宇宙連結不足（頂輪），或缺乏安全感導致無法前進（海底輪）","healingNote":"若感到害怕或卡住，可透過水晶療癒平衡海底輪，建立內在安全感。若過於魯莽，則需平衡頂輪與海底輪的連結，讓靈性指引與實際行動取得平衡。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂正在呼喚你踏上新的旅程。這不是魯莽，而是靈魂的智慧在引導你。宇宙已經為你準備好道路，你只需要信任並跨出第一步。所有偉大的旅程都始於一個勇敢的決定。","reversed":"你的靈魂想要你學習「智慧的勇氣」。這不是要你停滯不前，而是要你在行動前先與內在智慧連結。真正的自由來自於清晰的意識，而非盲目的跳躍。給自己時間準備，但不要讓恐懼阻止你最終的前進。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:1-magician', 'tarot', '1-magician', 1, '魔術師', 'The Magician', 'https://images.pexels.com/photos/6985164/pexels-photo-6985164.jpeg', '{"keywords":["力量","技能","專注","顯化","行動"],"arcana":"major","number":1}', '{"uprightMeaning":"魔術師代表你已經擁有實現目標所需的一切工具和資源。這張牌象徵著強大的顯化能力和創造力，提醒你現在正是將想法轉化為現實的最佳時機。你具備了技能、知識和決心，能夠掌控局面並達成所願。魔術師連接天地能量，展現出專注力和行動力的完美結合。這是一個充滿力量和自信的時期，你能夠運用自己的才華和智慧來影響周遭的環境。把握當下的機會，相信自己的能力，勇敢地展現你的才華。無論是事業、學習還是個人成長，你都能夠創造出令人驚艷的成果。","reversedMeaning":"逆位的魔術師警告你可能正在濫用自己的能力或才華。你可能缺乏自信，懷疑自己的技能，或是無法有效地運用手中的資源。這張牌也可能指出操控、欺騙或不誠實的行為，無論是你對他人，或是他人對你。你可能感到力不從心，無法將想法付諸實行，或是發現自己的努力並沒有產生預期的效果。現在需要重新審視你的動機和方法，確保你是以正直和真誠的方式行事。避免走捷徑或使用不當手段來達成目標，因為這最終只會帶來更多問題。","detailedInterpretation":{"coreKeywords":{"upright":["顯化","行動力","掌控","創造","工具齊備"],"reversed":["操控","自我懷疑","濫用能力","欺騙","能力卡住"],"uprightExplanation":"魔術師正位代表你已經掌握了顯化的力量，就像煉金術士將鉛轉化為黃金。這張牌的核心是「我擁有我所需的一切」，你不需要再等待、再學習、再準備，所有資源都已經在你手中。魔術師一手指天、一手指地，連結天地能量，象徵靈性與物質的完美整合。正位時，這股能量是清晰、專注、有方向的，你知道自己要什麼，也知道如何達成。這是行動的時刻，不是思考的時刻。你的意念就是你的魔杖，能夠創造實相。","reversedExplanation":"魔術師逆位警告你力量被誤用或被阻塞。要麼你懷疑自己的能力，明明手上有工具卻不敢使用；要麼你用不正當的方式來達成目標，透過操控、欺騙或走捷徑。逆位時，那股顯化的力量變成了耍手段的小聰明。你可能感到自己是個冒牌貨，總覺得不夠資格。或者相反，你過度相信自己的能力，認為可以操控一切，包括他人的意志。這張牌提醒你：真正的力量來自真誠，而非技巧。當魔術師的魔法失靈，回到誠實和謙卑是唯一的解答。"},"energyFlow":{"direction":"往前","type":"輸出 + 轉化","description":"魔術師是將天（靈性）與地（物質）連結的能量，屬於高度專注的顯化力量。能量從上到下流動，將想法轉化為實際行動。這是主動創造的能量，不等待機會，而是自己創造機會。"},"timing":{"speed":"快速","description":"事情會快速啟動並展開。魔術師代表「現在就做」的能量，通常在1-2週內就會看到初步成果。只要開始行動，進展會很明確。"},"advice":{"upright":"立即開始行動，運用你手上的資源。不要再等待「完美時機」，現在就是最好的時機。專注在你的目標上，相信自己有能力做到。","reversed":"停下來檢視你的動機是否純正。不要用操控或欺騙的方式達成目標。重新建立對自己能力的信心，誠實面對自己的不足並學習補強。"},"chakra":{"primary":"太陽神經叢（第三輪）","issue":"個人力量感不足，無法展現自信，或過度控制想要掌控一切","healingNote":"魔術師的能量與太陽神經叢直接相關，這是你的力量中心。如果感到無力或過度想控制，代表這個脈輪失衡。透過水晶療癒（如黃水晶、虎眼石）可以重建力量感。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂想要你知道：你已經具備了所需的一切。現在不是學習新東西的時候，而是運用你已經擁有的。宇宙已經給你工具，剩下的是你的選擇。當你開始行動，天地能量會支持你。你是自己生命的魔術師。","reversed":"你的靈魂在提醒你：真正的力量來自真誠，而非操控。如果你用欺騙的方式得到的東西，最終會失去。現在是時候誠實面對自己的陰影面，承認自己的不足，然後從真實的自己開始重建力量。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:2-high-priestess', 'tarot', '2-high-priestess', 2, '女祭司', 'The High Priestess', 'https://images.pexels.com/photos/8066708/pexels-photo-8066708.jpeg', '{"keywords":["直覺","智慧","神秘","潛意識","內在"],"arcana":"major","number":2}', '{"uprightMeaning":"女祭司是智慧與直覺的化身，她守護著神秘的知識和潛意識的領域。這張牌出現時，提醒你要傾聽內在的聲音，相信你的直覺和第六感。現在不是依賴邏輯分析的時候，而是需要深入探索內心深處的智慧。女祭司鼓勵你靜心冥想，與你的靈性自我連結，從內在尋找答案。這段時期適合學習神秘學、靈性修行或是深入了解自己的潛意識。保持耐心和接受的態度，因為有些事情需要時間才能揭示。女祭司也代表秘密和隱藏的知識，提醒你某些訊息可能尚未完全顯露。","reversedMeaning":"逆位的女祭司顯示你可能正在忽視自己的直覺，或是被外在的噪音所干擾而無法聽見內心的聲音。你可能過度依賴理性思考，而壓抑了情感和靈性的層面。這張牌也可能暗示有秘密被隱瞞，或是你對某些重要訊息視而不見。你可能感到與自己的內在智慧脫節，無法接觸到更深層的理解。現在需要重新建立與直覺的連結，花時間獨處和反思。逆位的女祭司也提醒你要誠實面對自己，不要隱藏真相或逃避內心深處的感受。學會平衡理性與感性，才能做出最明智的決定。","detailedInterpretation":{"coreKeywords":{"upright":["直覺","內在智慧","神秘","等待","接收訊息"],"reversed":["忽視直覺","過度理性","秘密隱瞞","與內在斷連","資訊不明"],"uprightExplanation":"女祭司正位代表通往潛意識和靈性智慧的門戶。她坐在黑白兩柱之間，守護著隱藏的知識，象徵著二元性的平衡與神秘的面紗。正位時，這張牌要求你停止向外尋找答案，而是轉向內在。你的直覺此刻比邏輯更可靠，你的夢境比清醒時的思考更真實。女祭司不主動給予答案，而是等待你準備好接收。這是一個安靜、內斂、被動接收的能量，不適合採取行動，而適合觀察、等待、聆聽。答案會在對的時機自然浮現。","reversedExplanation":"女祭司逆位顯示你與內在智慧的連結被切斷了。外在世界的噪音太大，你聽不見內心微小的聲音。你可能過度依賴理性分析，用頭腦去計算每一步，卻忽略了直覺的指引。逆位時，也可能代表有秘密被隱瞞，或是你選擇對某些真相視而不見。你可能害怕面對內在深處的東西，因此用忙碌來逃避獨處。這張牌提醒你：真相不會因為你不看就消失。是時候誠實面對自己，重新建立與內在的連結。關掉外在的聲音，才能聽見內在的智慧。"},"energyFlow":{"direction":"向內","type":"接收","description":"女祭司的能量是內向接收的，屬於被動等待而非主動出擊。她坐在黑白柱之間，守護著通往潛意識的門。這是靜止、觀察、接收靈性訊息的能量。"},"timing":{"speed":"緩慢","description":"事情需要時間醞釀，不要急。女祭司代表「時機未到」，通常需要1-3個月的等待期。答案會在對的時間自然顯現，強求只會適得其反。"},"advice":{"upright":"先不要做決定，靜下來聽你的直覺。多冥想、多獨處、多觀察。答案已經在你心裡，只是還沒浮上意識層面。保持耐心，訊息會自己來找你。","reversed":"重新連結你的直覺。減少外在噪音，關掉社群媒體，給自己安靜的空間。如果有秘密，誠實面對。不要再逃避內在的聲音，它一直在試著告訴你真相。"},"chakra":{"primary":"第三眼輪（眉心輪）","issue":"直覺力被阻斷，無法接收靈性訊息，或過度依賴邏輯思維","healingNote":"女祭司與第三眼輪直接相關，這是直覺和靈視的中心。如果感到與直覺斷連或無法接收訊息，代表此脈輪需要被活化。透過水晶療癒（如紫水晶、拉長石）可以打開第三眼。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂想要你知道：答案不在外面，而在裡面。你一直在尋找的智慧，其實你早就知道了。停止向外求索，回到內在的寧靜。在那個寂靜之中，你會聽見宇宙一直在對你說的話。","reversed":"你的靈魂在提醒你：你已經離自己太遠了。外在世界的聲音蓋過了你內心的真實。是時候誠實面對你一直在逃避的真相。你的直覺一直都在，只是你選擇不聽。回來，回到你自己。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:3-empress', 'tarot', '3-empress', 3, '皇后', 'The Empress', 'https://images.pexels.com/photos/8066811/pexels-photo-8066811.jpeg', '{"keywords":["豐饒","母性","創造","美麗","富足"],"arcana":"major","number":3}', '{"uprightMeaning":"皇后象徵著豐盛、滋養和創造力的能量。她代表大自然的富饒和母性的慈愛，為生命帶來成長和繁榮。當這張牌出現時，預示著豐收的時期即將到來，無論是物質上的富足還是精神上的滿足。皇后鼓勵你連結自然，享受生活中的美好事物，並以愛和關懷對待自己和他人。這是培養創意項目、建立家庭或是滋養人際關係的絕佳時機。皇后也代表感官的愉悅和藝術的美感，提醒你要欣賞生活中的美麗與和諧。她的能量溫柔而強大，帶來療癒和成長，讓一切事物都能在愛的滋養下茁壯成長。","reversedMeaning":"逆位的皇后可能顯示創造力受阻或感到缺乏滋養。你可能過度依賴他人，或是反過來過度照顧別人而忽略了自己的需求。這張牌也可能指出過度保護或窒息性的關係，無論是你對他人還是他人對你。你可能感到與自己的創造力或女性能量脫節，或是在物質和情感上感到匱乏。逆位的皇后提醒你需要重新找回自我照顧的平衡，學會設立健康的界限。不要讓對他人的責任感壓垮了自己，也不要因為害怕失去而過度控制。重新連結大自然和自己的身體，培養自愛和自我價值感，才能真正地給予他人愛與支持。","detailedInterpretation":{"coreKeywords":{"upright":["豐盛","滋養","創造力","母性能量","豐收"],"reversed":["匱乏","過度付出","創造力受阻","失衡","窒息關係"],"uprightExplanation":"皇后正位象徵大地母親的豐饒能量，代表創造、滋養和無條件的愛。她坐在大自然中，周圍是成熟的麥田和流動的溪水，象徵生命的富足與成長。正位時，這張牌帶來的是接納、溫柔、耐心的力量。皇后不強迫任何事物成長，而是提供最好的環境，讓一切自然茁壯。這是女性能量的展現，不是透過征服和控制，而是透過愛和關懷來影響。正位皇后提醒你：豐盛是你的本質，而非你需要努力爭取的東西。當你照顧好自己，富足會自然流向你。","reversedExplanation":"皇后逆位顯示滋養的能量失衡了。你可能過度照顧他人而忘記照顧自己，成為一個耗盡的給予者。或者相反，你完全忽略了自己的創造力和需要被愛的渴望。逆位時，母性能量可能變成窒息和過度保護，你可能用「為你好」的名義控制他人。這張牌也可能指出你與自己的身體和大自然失去了連結，感到匱乏和空虛。逆位皇后提醒你：你不能從一個空杯子倒水給別人。停止過度付出，先把愛給自己。真正的豐盛來自內在的富足，而非外在的累積。"},"energyFlow":{"direction":"向外擴展","type":"滋養型輸出","description":"皇后的能量像大地母親一樣，是溫柔豐盛的流動。她給予滋養、支持成長，讓一切在愛中茁壯。這是創造性的能量，但不急躁，而是耐心地等待果實成熟。"},"timing":{"speed":"自然節奏（中速）","description":"事情會按照自然的節奏發展，就像種子發芽需要時間。通常在1-2個月內會看到成果。不要催促，讓它自然成長。"},"advice":{"upright":"好好照顧自己，滋養你的身心靈。多接觸大自然，享受美好事物。現在是創造和孕育的好時機，但要有耐心。好好愛自己，才能給出愛。","reversed":"停止過度付出。你不是所有人的媽媽，先照顧好自己。如果感到匱乏，先檢視你是否忽略了自己的需求。學會說不，設立界限。"},"chakra":{"primary":"心輪 + 臍輪","issue":"過度給予導致心輪耗損，或創造力卡在臍輪無法流動","healingNote":"皇后連結心輪（愛與給予）和臍輪（創造力）。如果過度付出到疲憊，心輪需要被補充能量。如果創造力卡住，臍輪需要被活化。透過玫瑰晶、月光石等水晶可以平衡女性能量。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂想要你知道：你值得被滋養，值得享受美好。生命不是只有付出和努力，也包括接受和享受。允許自己被愛，允許豐盛流向你。你是大地的孩子，富足是你的本質。","reversed":"你的靈魂在提醒你：你已經忘記如何接受了。你習慣當給予者，卻不知道如何接收。這種失衡正在耗損你的能量。是時候停下來，先把愛給自己。你不需要透過付出來證明你的價值。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:4-emperor', 'tarot', '4-emperor', 4, '皇帝', 'The Emperor', 'https://images.pexels.com/photos/7195147/pexels-photo-7195147.jpeg', '{"keywords":["權威","結構","領導","穩定","父性"],"arcana":"major","number":4}', '{"uprightMeaning":"皇帝代表權威、結構和穩定的力量。他象徵著領導能力、組織才能和建立秩序的智慧。當這張牌出現時，提醒你需要以理性和邏輯的方式來處理事務，建立清晰的規則和界限。皇帝鼓勵你承擔責任，展現領導才能，以堅定而公正的態度來指引方向。這是建立事業、制定計劃或是鞏固成果的好時機。皇帝的能量穩重可靠，能夠提供保護和安全感。他提醒你要有紀律和決心，透過努力和毅力來達成長期目標。同時，皇帝也代表父性的智慧和經驗，能夠給予實際的建議和支持。","reversedMeaning":"逆位的皇帝警告你可能過於專制或控制慾過強。你可能正在濫用權力，以強硬的方式對待他人，或是過於僵化而無法適應變化。這張牌也可能顯示缺乏紀律和方向，無法有效地管理自己或他人。你可能逃避責任，缺乏領導能力，或是對權威產生反抗。逆位的皇帝提醒你需要在控制和彈性之間找到平衡。不要讓恐懼驅使你過度控制一切，也不要完全放棄結構和秩序。學會以更開放和包容的方式來行使權力，尊重他人的自主性。同時也要審視自己是否過於依賴外在的權威，而忽略了內在的智慧。","detailedInterpretation":{"coreKeywords":{"upright":["權威","結構","掌控","領導力","穩定"],"reversed":["過度控制","專制","缺乏紀律","逃避責任","僵化"],"uprightExplanation":"皇帝正位代表父性能量的穩定力量，象徵秩序、權威和建構。他坐在石頭王座上，背後是堅硬的山脈，代表不可動搖的基礎。正位時，這張牌帶來的是理性、邏輯、策略性的思考。皇帝不依賴情緒或直覺，而是依據經驗和智慧做出決策。他建立規則、設定界限、創造結構，讓一切井然有序。這是陽性能量的展現，透過掌控和領導來保護和穩定。正位皇帝提醒你：有時候你需要當自己生命的國王，建立屬於你的秩序和紀律。","reversedExplanation":"皇帝逆位顯示權威能量被扭曲或缺失。你可能變得過度控制，用嚴格的規則壓迫自己或他人，將保護變成了束縛。或者相反，你完全缺乏紀律和方向，逃避應該承擔的責任，成為一個軟弱的領導者。逆位時，父性能量可能變成專制和獨裁，你可能用「為了大家好」的理由來壓制異議。這張牌也可能指出你對權威的反抗，拒絕所有規則和結構。逆位皇帝提醒你：真正的力量不是控制，而是穩定中的彈性。你需要在秩序與自由之間找到平衡點。"},"energyFlow":{"direction":"由上而下","type":"建構與掌控","description":"皇帝的能量是由上而下的指揮與建構，屬於陽性的主導力量。他建立秩序、設立規則、掌控局面。這是穩固、實際、有條理的能量。"},"timing":{"speed":"穩定緩慢","description":"事情會按照計劃穩步推進，不會突然發生。皇帝代表長期建設，通常需要2-6個月才能看到穩固的成果。這是馬拉松，不是短跑。"},"advice":{"upright":"建立清楚的計劃和結構。設定界限，承擔領導責任。現在需要的是紀律和策略，不是情緒和衝動。像CEO一樣思考，理性決策。","reversed":"放鬆你的控制欲。你無法掌控一切，也不需要。檢視你是否用「保護」之名在控制他人。或者，如果你太散漫，是時候建立一些紀律了。找到平衡。"},"chakra":{"primary":"太陽神經叢 + 海底輪","issue":"權力感失衡：過度控制或完全失控，安全感不足導致需要掌控","healingNote":"皇帝連結太陽神經叢（個人力量）和海底輪（安全感）。過度控制通常源於內在的不安全感。如果你需要控制一切才感到安心，代表海底輪需要療癒。透過黑曜石、紅碧玉等水晶可以建立真正的安全感。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂想要你知道：真正的力量來自於穩定的基礎。你有能力建構自己的帝國，但需要耐心和策略。承擔起責任，不要逃避。你比自己想像的更有能力掌控局面。","reversed":"你的靈魂在提醒你：控制是恐懼的另一種形式。當你需要掌控一切才能放心，代表你不信任生命的流動。或者，你是否在逃避應負的責任？真正的力量不是控制，而是穩定中的信任。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:5-hierophant', 'tarot', '5-hierophant', 5, '教皇', 'The Hierophant', 'https://images.pexels.com/photos/8066886/pexels-photo-8066886.jpeg', '{"keywords":["傳統","教育","信仰","導師","智慧"],"arcana":"major","number":5}', '{"uprightMeaning":"教皇代表傳統智慧、精神導師和正式的學習。他守護著文化、宗教和社會的傳統價值觀，提供道德和精神上的指引。當這張牌出現時，可能意味著你正在尋求更深層的意義和靈性的理解。這是向導師學習、加入團體或是遵循既定體系的時機。教皇鼓勵你尊重傳統和習俗，從前人的智慧中汲取經驗。這段時期適合進行正式的教育、參與宗教儀式或是接受靈性的指導。教皇也代表承諾和忠誠，可能與婚姻、入會或其他正式的結合有關。他提醒你文化傳承和集體智慧的重要性，以及遵循道德準則帶來的穩定感。","reversedMeaning":"逆位的教皇顯示你可能正在挑戰傳統或質疑既定的信念體系。你渴望走自己的路，不願意盲目遵循他人制定的規則。這張牌可能代表叛逆、非傳統的想法或是對權威的不信任。你可能感到現有的體系過於僵化，無法滿足你的個人需求和價值觀。逆位的教皇鼓勵你發展自己的信念和哲學，而不是盲從外在的教條。然而，這張牌也提醒你不要為了反對而反對，而是要深思熟慮地選擇自己的道路。在追求個人自由的同時，也要意識到某些傳統智慧的價值。找到尊重傳統與個人創新之間的平衡點，才能真正走出屬於自己的道路。","detailedInterpretation":{"coreKeywords":{"upright":["傳統","導師","學習","信仰體系","正式承諾"],"reversed":["反叛","質疑權威","打破傳統","自我信念","靈性自由"],"uprightExplanation":"教皇正位代表傳統智慧和靈性權威的傳承。他是連結天與地、神聖與世俗的橋樑，守護著文化、宗教和社會的價值體系。正位時，這張牌帶來的是正式的學習、導師的指引、以及對既定規則的尊重。教皇不創造新的道路，而是指引你走前人已經驗證有效的路。這是向傳統學習的時刻，透過正式的儀式、教育或承諾來深化你的理解。正位教皇提醒你：不是所有的輪子都需要重新發明。站在巨人的肩膀上，你可以看得更遠。","reversedExplanation":"教皇逆位顯示你正在質疑或拒絕外在的權威和傳統。你可能感到既有的信仰體系不再能滿足你的靈性需求，或是發現傳統的做法限制了你的成長。逆位時，這股反叛的能量可以是解放的，也可以是盲目的。你可能正在建立屬於自己的信念系統，不再需要導師或宗教來告訴你什麼是真理。但這張牌也警告不要為了反對而反對，成為一個憤世嫉俗的叛逆者。逆位教皇提醒你：真正的靈性自由不是拒絕所有傳統，而是有智慧地選擇哪些適合你，哪些該放下。"},"energyFlow":{"direction":"由上而下傳承","type":"傳授與接收","description":"教皇的能量是傳承性的，從導師流向學生，從傳統流向現代。這是學習、接受指導、融入體系的能量。不是創新，而是吸收已有的智慧。"},"timing":{"speed":"按照既定流程（中慢速）","description":"事情會按照傳統或正式的流程進行，不會很快。如果涉及正式承諾、教育或認證，通常需要3-6個月。遵循正確步驟比速度更重要。"},"advice":{"upright":"尋求導師或專家的指導。不要自己亂摸索，跟有經驗的人學習。遵循既定的規則和流程，不要想走捷徑。如果要做承諾（如婚姻、合約），現在是好時機。","reversed":"質疑你一直遵循的規則：它們真的適合你嗎？不要盲目跟隨傳統或權威。但也不要為反對而反對，要有智慧地選擇自己的道路。建立屬於你的信念體系。"},"chakra":{"primary":"喉輪 + 頂輪","issue":"無法表達真實信念（喉輪），或盲目跟隨外在權威而失去與高我的連結（頂輪）","healingNote":"教皇連結喉輪（真實表達）和頂輪（靈性連結）。如果你無法說出自己的信念，或盲目遵循他人的教條，這兩個脈輪需要平衡。透過青金石、白水晶等水晶可以強化真實的靈性表達。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂想要你知道：向前人學習並不代表失去自我。傳統中有智慧，不要因為追求「與眾不同」而忽略了已經被證實有效的道路。尋找值得你信任的導師，讓自己站在巨人的肩膀上。","reversed":"你的靈魂在提醒你：沒有任何外在的權威可以定義你的靈性真理。你一直在尋找的答案不在任何宗教、任何導師那裡，而在你自己心中。是時候拿回你的靈性主權，建立屬於你自己的信念。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:6-lovers', 'tarot', '6-lovers', 6, '戀人', 'The Lovers', 'https://images.pexels.com/photos/8066948/pexels-photo-8066948.jpeg', '{"keywords":["愛情","選擇","和諧","夥伴","結合"],"arcana":"major","number":6}', '{"uprightMeaning":"戀人牌代表深刻的連結、和諧的關係和重要的選擇。這張牌不僅象徵浪漫的愛情，更代表任何形式的深度結合和夥伴關係。當戀人牌出現時，提醒你正面臨一個重要的決定，這個決定需要你忠於自己的價值觀和信念。戀人牌鼓勵你尋求和諧與平衡，在關係中建立相互尊重和理解。這是深化親密關係、建立重要合作或是做出與價值觀相關的選擇的時機。這張牌也代表內在的整合，將對立的部分統一成和諧的整體。戀人牌提醒你愛始於自我接納，只有當你真實地做自己時，才能建立真正深刻而有意義的連結。","reversedMeaning":"逆位的戀人牌顯示關係中可能存在失衡、誤解或價值觀的衝突。你可能正在經歷關係困難，感到與伴侶或重要他人之間缺乏和諧。這張牌也可能指出你在重要決定上感到困惑，無法做出選擇，或是做出了與內心真實渴望不一致的決定。你可能背叛了自己的價值觀，或是在關係中失去了自我。逆位的戀人牌提醒你需要重新審視你的關係和選擇，確保它們真正反映了你的核心價值。不要為了取悅他人而犧牲自己的真實性。這也是一個反思內在衝突和不和諧的時機，學會愛自己並做出真正符合自己的決定。","detailedInterpretation":{"coreKeywords":{"upright":["真愛","靈魂伴侶","價值觀一致","重要選擇","內在整合"],"reversed":["價值觀衝突","關係失衡","選擇困難","背叛自我","不和諧"],"uprightExplanation":"戀人正位代表靈魂層面的連結與選擇。這不只是關於浪漫愛情，而是關於「對齊」—與另一個人、與自己的價值觀、與更高的目的對齊。圖像中天使拉斐爾在上方祝福，象徵神聖的結合。正位時，這張牌強調的是「忠於自己」的選擇。無論是選擇一段關係、一份工作或人生方向，關鍵是這個選擇是否與你的核心價值一致。戀人不是妥協，而是兩個完整的個體選擇走在一起。正位戀人提醒你：真正的愛是讓你成為更真實的自己，而非失去自我。","reversedExplanation":"戀人逆位顯示價值觀的衝突或關係中的失衡。你可能為了維持關係而犧牲了自己的價值觀，或是陷入一個讓你無法做自己的連結中。逆位時，天使的祝福被阻擋，代表這段連結缺乏神聖的對齊。你可能面臨艱難的選擇卻無法決定，因為每個選項都讓你背叛部分的自己。或者，你已經做出了選擇，但內心知道這不是真正適合你的。逆位戀人提醒你：如果一段關係需要你放棄自己才能維持，那它不是真愛。是時候誠實面對：你的選擇是否反映了真實的你？"},"energyFlow":{"direction":"相互流動","type":"結合與整合","description":"戀人的能量是相互的、平等的、雙向流動的。不是一方給予一方接受，而是兩股能量交融、整合、創造出新的和諧。這是陰陽平衡、二元統一的能量。"},"timing":{"speed":"關鍵時刻","description":"戀人代表「現在就是決定的時刻」。這不是一個漸進的過程，而是一個清晰的選擇點。通常在數週內，你會面臨或已經面臨重要的決定。"},"advice":{"upright":"忠於你的價值觀做選擇。不要妥協你的核心信念來取悅他人。如果是關於關係，確保你們的價值觀對齊。真正的愛會讓你成為更好的自己，而非失去自己。","reversed":"檢視你的關係或選擇：它們是否讓你背叛了自己？不要為了維持關係而犧牲你的真實性。如果你無法做決定，問自己：哪個選擇讓你更像真實的自己？"},"chakra":{"primary":"心輪","issue":"心輪失衡：要麼過度開放而失去界限，要麼封閉而無法真正連結","healingNote":"戀人的核心是心輪的能量—愛的給予與接收。如果關係讓你感到耗竭，代表你的心輪界限不清。如果你無法深度連結，代表心輪需要被打開。透過玫瑰晶、綠東陵等水晶可以平衡心輪能量。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂想要你知道：真正的愛是靈魂的認出。當你遇見對的人、對的選擇，你的靈魂會知道。不要用頭腦去分析，而是感受你的心。真愛不需要你改變自己，而是讓你成為最真實的自己。","reversed":"你的靈魂在提醒你：如果你需要假裝才能被愛，那不是真愛。你值得一段讓你自由做自己的關係。停止妥協你的靈魂來維持一個不對的連結。有時候，最愛自己的方式就是選擇離開。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:7-chariot', 'tarot', '7-chariot', 7, '戰車', 'The Chariot', 'https://images.pexels.com/photos/7195232/pexels-photo-7195232.jpeg', '{"keywords":["勝利","意志","控制","前進","決心"],"arcana":"major","number":7}', '{"uprightMeaning":"戰車象徵著勝利、意志力和堅定的決心。這張牌代表透過專注和自律，你能夠克服障礙並達成目標。戰車手掌控著兩匹相反方向的馬，象徵著整合對立力量並朝著明確方向前進的能力。當這張牌出現時，預示著成功即將到來，但需要你保持堅定的意志和清晰的目標。這是採取行動、展現決心並克服挑戰的時機。戰車鼓勵你相信自己的能力，不要讓外在的干擾動搖你的決心。透過自律和專注，你能夠駕馭生命的戰車朝向勝利。這張牌也代表旅程和進展，無論是實際的旅行還是人生道路上的前進。","reversedMeaning":"逆位的戰車顯示你可能失去了方向感或控制力。你可能感到被對立的力量拉扯，無法做出決定或採取一致的行動。這張牌也可能指出過度侵略、強硬或缺乏自制力的行為。你可能在追求目標時過於急躁，或是使用強迫的方式來達成所願，這可能導致衝突和阻力。逆位的戰車提醒你需要重新找回內在的平衡和方向感。不要讓外在的壓力或內在的衝突阻止你前進。學會以更靈活和包容的方式來應對挑戰，而不是一味地強推。暫停下來重新評估你的目標和方法，確保你走在正確的道路上，並以更和諧的方式來達成目標。","detailedInterpretation":{"coreKeywords":{"upright":["勝利","意志力","掌控方向","突破","動力十足"],"reversed":["失控","方向不明","過度侵略","內在衝突","缺乏紀律"],"uprightExplanation":"戰車正位代表透過意志力和自律達成勝利。戰車手駕馭兩匹顏色相反的獅子，象徵整合對立力量並朝著明確目標前進。正位時，這張牌強調的是「掌控」—不是控制外在環境，而是掌控自己的方向和能量。你清楚知道自己要去哪裡，並且有足夠的決心克服一切障礙。戰車不是靠蠻力，而是靠意志和專注。正位戰車提醒你：當你內在統一、目標明確，外在世界會為你讓路。現在是全力以赴的時刻，勝利在望。","reversedExplanation":"戰車逆位顯示你失去了方向感或控制力。兩匹獅子往不同方向拉扯，你被內在的衝突撕裂，無法前進。逆位時，要麼你過於侵略性地強推，製造更多阻力；要麼你完全失去動力，停滯不前。你可能有目標但缺乏執行力，或是執行力很強但方向錯誤。逆位戰車提醒你：在往前衝之前，先整合你內在的對立面。你的猶豫不決或過度激進都源自內在的不統一。停下來，重新校準方向，然後再出發。"},"energyFlow":{"direction":"向前推進","type":"聚焦突破","description":"戰車的能量是高度聚焦、單一方向、強力推進的。這是突破性的能量，衝破障礙、克服阻力、朝目標前進。能量是線性的、有方向的、不分散的。"},"timing":{"speed":"快速推進","description":"事情會快速發展，有明顯的進展。戰車代表「衝刺期」，通常在2-4週內會看到突破性的進展。保持動能很重要。"},"advice":{"upright":"全力以赴，不要分心。現在是執行的時候，不是計劃的時候。保持專注，整合你的能量朝同一個方向。勝利需要紀律和決心，堅持下去。","reversed":"停下來重新評估方向。你的內在有衝突需要先解決。不要用強硬的方式硬推，先整合你的對立面。或者，如果你太消極，是時候重拾動力了。"},"chakra":{"primary":"太陽神經叢 + 臍輪","issue":"意志力不足或過度使用意志力導致疲憊，行動力被阻塞","healingNote":"戰車連結太陽神經叢（意志力）和臍輪（行動力）。如果感到無力前進或過度疲憊，這兩個脈輪需要平衡。透過黃水晶、琥珀等水晶可以恢復動力。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂想要你知道：你有能力達成任何你真正想要的目標。當你的意志與靈魂對齊，沒有什麼可以阻擋你。現在不是懷疑的時候，而是全力以赴的時刻。相信自己，勝利屬於你。","reversed":"你的靈魂在提醒你：你正被內在的衝突撕裂。一部分的你想前進，另一部分卻在抗拒。在你能真正前進之前，需要先整合這些對立面。或者，你是否在錯誤的方向上用力？聆聽你的靈魂，它會告訴你真正該去的地方。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:8-strength', 'tarot', '8-strength', 8, '力量', 'Strength', 'https://images.pexels.com/photos/8066999/pexels-photo-8066999.jpeg', '{"keywords":["勇氣","耐心","同情","內在力量","自控"],"arcana":"major","number":8}', '{"uprightMeaning":"力量牌代表的不是蠻力，而是溫柔、耐心和內在的勇氣。這張牌展現了以愛和同情心來馴服野性本能的能力。當力量牌出現時，提醒你真正的力量來自內在，來自對自己和他人的接納與理解。這是展現勇氣、克服恐懼並以溫柔堅定的方式面對挑戰的時機。力量牌鼓勵你相信自己的內在力量，不需要使用強迫或暴力的方式來達成目標。透過耐心、自制和慈悲，你能夠克服任何障礙。這張牌也代表情緒的掌控和精神的韌性，提醒你即使在困難時刻也要保持冷靜和優雅。真正的力量在於以愛來轉化恐懼，以理解來化解衝突。","reversedMeaning":"逆位的力量牌顯示你可能正在經歷自我懷疑、軟弱或缺乏自信的時期。你可能被恐懼和不安全感所控制，無法展現真正的力量。這張牌也可能指出過度強硬或缺乏耐心的行為，你可能試圖用強迫的方式來控制情況，而非以溫柔的方式來引導。逆位的力量牌提醒你需要重新連結自己的內在力量和勇氣。不要讓外在的批評或內在的恐懼削弱你的信心。學會以慈悲和寬容對待自己，接納自己的弱點和不完美。真正的力量來自於接受和整合所有的自己，包括那些你認為是軟弱的部分。透過自我接納和內在的和平，你將找回真正的力量。","detailedInterpretation":{"coreKeywords":{"upright":["內在力量","溫柔堅定","情緒掌控","勇氣","慈悲"],"reversed":["自我懷疑","缺乏自信","過度強硬","失控","內在衝突"],"uprightExplanation":"力量牌正位展現的是馴獅女的智慧——她不用武力征服獅子，而是用愛與溫柔馴服牠。這張牌的核心訊息是：真正的力量不是壓制，而是整合。正位時，你有能力面對內在的野性和恐懼，不是透過對抗，而是透過接納和理解。這是情緒成熟的展現，你能夠在憤怒中保持冷靜，在恐懼中保持勇氣。力量牌代表「柔能克剛」的智慧，你越是溫柔堅定，就越是強大。這張牌提醒你：你內在的野獸不是敵人，而是等待被愛的部分。當你以慈悲對待自己的陰影面，你就擁有了無可撼動的力量。","reversedExplanation":"力量牌逆位顯示你與內在力量失去了連結。要麼你被恐懼和自我懷疑壓倒，覺得自己軟弱無力；要麼你用過度強硬的方式來掩飾內心的脆弱，變成控制狂或暴君。逆位時，獅子要麼被壓抑得太深，要麼完全失控地咆哮。你可能對自己或他人太過嚴厲，用批判代替了慈悲。這張牌提醒你：真正的力量來自內在的平衡，而非外在的征服。如果你感到無力，不是因為你不夠強，而是因為你用錯了方式。停止與自己作戰，開始與自己和解。真正的勇氣是承認脆弱，真正的力量是溫柔以對。"},"energyFlow":{"direction":"向內整合","type":"平衡與掌控","description":"力量牌的能量是向內收攝的整合力量，像是將野性的本能與理性的意識融合。這是一股穩定、持續、溫柔而堅定的能量，不爆發，但持久有力。"},"timing":{"speed":"中速持續","description":"力量牌代表需要耐心和時間的過程。改變不會一夜發生，但會持續穩定地進展。通常需要2-3個月的時間來建立真正的內在力量和情緒掌控。"},"advice":{"upright":"以溫柔堅定的方式面對挑戰。不要用暴力或強迫，而是用愛與耐心。相信你的內在力量足以應對一切。保持冷靜，以慈悲對待自己和他人。","reversed":"停止與自己作戰。檢視你是否過度強硬或過度軟弱，找回平衡點。學習接納自己的脆弱，用愛而非恐懼來引導自己。重建內在的自信和力量感。"},"chakra":{"primary":"心輪 + 太陽神經叢","issue":"心輪受傷導致無法以愛面對，或太陽神經叢失衡導致力量感不足或過度控制","healingNote":"力量牌需要心輪（愛與慈悲）與太陽神經叢（個人力量）的平衡。如果感到無力或過度強硬，代表這兩個脈輪需要調和。透過玫瑰石英（心輪）和黃水晶（太陽神經叢）的水晶療癒可以恢復平衡。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂想要你知道：你比你想像的更強大，也比你想像的更溫柔。真正的力量不是壓制你的恐懼，而是溫柔地擁抱它。當你停止與自己的野性對抗，開始與它共舞，你就擁有了無可撼動的力量。你的溫柔就是你的力量。","reversed":"你的靈魂在提醒你：你不需要證明自己有多強。你也不需要假裝自己毫無恐懼。真正的勇氣是承認你會害怕，但依然選擇前進。停止用強硬來保護脆弱，開始用愛來療癒恐懼。你的力量一直都在，只是被錯誤的信念蒙蔽了。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:9-hermit', 'tarot', '9-hermit', 9, '隱士', 'The Hermit', 'https://images.pexels.com/photos/8067040/pexels-photo-8067040.jpeg', '{"keywords":["內省","智慧","獨處","真理","指引"],"arcana":"major","number":9}', '{"uprightMeaning":"隱士代表內省、獨處和尋求內在真理的時期。這張牌提醒你現在需要退出日常的喧囂，給自己一段寧靜的時光來反思和探索內在世界。隱士手持明燈，象徵著智慧和指引，照亮通往真理的道路。這是深入自我探索、靈性修行或是尋求更深層意義的時機。獨處並不代表孤獨，而是一個與真實自我連結的機會。這段時期適合學習、閱讀、冥想或是進行任何形式的內在工作。隱士鼓勵你相信內在的指引，從自己的經驗中汲取智慧。透過深度的內省和反思，你將找到生命問題的答案和前進的方向。","reversedMeaning":"逆位的隱士顯示你可能過度孤立自己，拒絕他人的幫助和支持。你可能感到孤獨和疏離，或是逃避社會互動而陷入自我封閉。這張牌也可能指出你正在過度內向，忽略了外在世界的需要和機會。你可能因為害怕被傷害或失望而築起高牆，但這反而阻礙了成長和連結。逆位的隱士提醒你需要在獨處和社交之間找到平衡。雖然內省很重要，但完全孤立可能導致停滯和消極。嘗試打開心扉，接受他人的幫助和觀點。有時候，與他人分享你的想法和感受能帶來新的啟發和理解。","detailedInterpretation":{"coreKeywords":{"upright":["內在智慧","靈性追尋","獨處反思","指引明燈","深度探索"],"reversed":["孤立封閉","拒絕指引","逃避社交","過度孤獨","迷失方向"],"uprightExplanation":"隱士正位代表靈魂深處的追尋之旅。他手持明燈站在山頂，象徵著透過內省和獨處而獲得的智慧之光。正位時，這張牌呼喚你退出外在世界的喧囂，進入內在寧靜的聖所。隱士不是逃避，而是為了更深的連結而暫時離開。這是尋找生命意義、靈性成長的關鍵時期。你需要獨處來消化過去的經驗，整理內心的思緒，聆聽靈魂的呼喚。隱士的燈不是照亮別人，而是先照亮自己的道路。只有當你找到了自己的光，才能成為他人的指引。這張牌提醒你：答案不在外面，而在你內心最深處。","reversedExplanation":"隱士逆位顯示你可能過度孤立自己，將獨處變成了逃避。你可能因為害怕被傷害而築起高牆，拒絕與外界連結。逆位時，隱士變成了孤僻的隱居者，不是為了尋找智慧，而是為了逃避生活。你可能感到極度孤獨，卻又不願意打開心扉。這張牌也可能指出你忽視了內在的指引，太過外向而失去了與自己的連結。有時候逆位隱士代表你已經完成了內在探索，是時候重新回到世界，分享你的智慧。平衡是關鍵——既不要完全孤立，也不要完全外放。"},"energyFlow":{"direction":"向內深潛","type":"接收與反思","description":"隱士的能量是向內深潛的，像是潛入意識的深海尋找珍珠。這是靜默、沉思、向內探索的能量，需要獨處和寧靜的空間。"},"timing":{"speed":"緩慢深入","description":"隱士代表需要時間的深度過程。真正的智慧不能被催促，通常需要3-6個月的內在探索和反思期。不要急，讓洞見自然浮現。"},"advice":{"upright":"給自己獨處的時間和空間。減少社交活動，多冥想、閱讀、反思。向內尋找答案，而非向外求索。相信你的內在智慧會在寧靜中浮現。","reversed":"檢視你是在獨處還是在孤立。如果你過度封閉，試著打開心扉，接受他人的幫助。如果你太過外向，給自己一些安靜的時間。找到獨處與社交的平衡。"},"chakra":{"primary":"頂輪","issue":"與靈性指引斷連，無法接收更高智慧，或過度沉溺在靈性世界而脫離實際","healingNote":"隱士與頂輪的連結最為深刻，這是靈性覺知的中心。如果感到迷失或無法接收內在指引，代表頂輪需要被活化。透過白水晶、紫水晶的水晶療癒可以打開靈性通道。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂想要你知道：現在是退隱的時候了。不是因為你軟弱，而是因為你需要重新充電和尋找方向。在寧靜中，你會聽見一直被忽略的真理。你的明燈在等待你點亮它，但這需要獨處和內省。這段旅程只有你能走。","reversed":"你的靈魂在提醒你：孤立不是力量，而是恐懼。你已經躲藏得夠久了，是時候重新與世界連結。或者相反，你已經在外面待得太久，忘記了回到自己的重要性。平衡獨處與連結，你會找到真正的智慧。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:10-wheel', 'tarot', '10-wheel', 10, '命運之輪', 'Wheel of Fortune', 'https://images.pexels.com/photos/7195307/pexels-photo-7195307.jpeg', '{"keywords":["變化","命運","循環","運氣","轉折"],"arcana":"major","number":10}', '{"uprightMeaning":"命運之輪代表生命的循環、變化和轉折點。這張牌提醒你萬事萬物都在不斷變化，沒有什麼是永恆不變的。當命運之輪出現時，預示著重要的改變即將到來，可能是好運的來臨或是新的機會。這張牌鼓勵你接受生命的起伏，理解高峰和低谷都是自然循環的一部分。命運之輪也代表業力和因果法則，提醒你過去的行為會影響現在和未來。現在是順應潮流、把握機會的時候。保持開放和靈活的態度，因為變化往往帶來成長和進步。相信宇宙的安排，即使在困難時刻也要保持信心，因為輪子總是會繼續轉動。","reversedMeaning":"逆位的命運之輪顯示你可能正在經歷不順利的時期，或是抗拒必要的變化。你可能感到失控，彷彿被命運擺佈而無法掌握自己的人生。這張牌也可能指出壞運氣或是不利的轉變，讓你感到沮喪和無力。然而，逆位的命運之輪提醒你即使在困境中，你仍然擁有選擇如何回應的力量。不要陷入受害者心態，而是要主動創造改變。這可能是重新評估你的處境，學習困境帶來的教訓的時機。記住，輪子不會永遠停在低點，困難終將過去。保持耐心和韌性，相信時機到來時一切都會好轉。","detailedInterpretation":{"coreKeywords":{"upright":["命運轉折","業力循環","好運來臨","改變時機","宇宙法則"],"reversed":["運勢低落","抗拒改變","壞運氣","失控","業力清算"],"uprightExplanation":"命運之輪正位象徵生命的自然循環和轉折點的到來。輪子永遠在轉動，代表沒有什麼是永恆不變的——高峰會過去，低谷也會過去。正位時，這張牌通常預示著好運和正向的改變，宇宙的能量正在為你轉向有利的方向。這是業力的展現，你過去種下的善因正在開花結果。命運之輪提醒你順應宇宙的流動，不要抗拒改變。當輪子轉到你這邊時，把握機會；當它轉走時，保持信心等待下一個循環。這張牌教導你接受生命的起伏，理解一切都是更大計劃的一部分。","reversedExplanation":"命運之輪逆位顯示你可能正經歷運勢的低潮，或是強烈抗拒必要的改變。輪子依然在轉，但你可能感到被命運擺佈，失去了控制感。逆位時，這可能是業力清算的時期，過去的行為帶來了不利的後果。然而，這張牌提醒你：即使在最低點，輪子終究會再次轉動。你不是命運的受害者，你依然可以選擇如何回應。逆位命運之輪要求你臣服於當下的處境，接受暫時的困難，並相信這也會過去。有時候，逆位代表你需要主動創造改變，而非被動等待。"},"energyFlow":{"direction":"循環流動","type":"轉化與變動","description":"命運之輪的能量是循環性的，像四季更迭、潮汐起落。這是宇宙的自然節奏，不受個人意志控制，但可以順應和理解。能量在高峰與低谷之間流動。"},"timing":{"speed":"突然轉變","description":"命運之輪代表突如其來的轉折點。改變可能在1-4週內突然發生，通常是意外的、無法預測的。時機由宇宙決定，不是你能控制的。"},"advice":{"upright":"順應宇宙的流動，把握當前的好運。保持開放和彈性，接受改變帶來的機會。記住一切都是暫時的，好好享受但不要執著。感恩你過去的善行帶來的回報。","reversed":"接受當前的低潮，這也是暫時的。不要抗拒改變或陷入受害者心態。檢視你的業力——你種下了什麼因？這是學習和成長的時期。保持信心，輪子會再次轉動。"},"chakra":{"primary":"全脈輪（特別是頂輪與海底輪）","issue":"無法接受生命的起伏循環，或與宇宙法則失去連結","healingNote":"命運之輪影響整體能量系統，特別是頂輪（與宇宙法則連結）和海底輪（接地與臣服）。如果無法接受改變或感到失控，需要平衡這兩個脈輪。透過水晶療癒可以幫助你重新與宇宙節奏連結。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂想要你知道：一切都是神聖時機的展現。你過去的善行正在回報你，宇宙正在為你開啟新的可能性。享受這個轉折點，但記住輪子會繼續轉動。學會在流動中保持中心，在變化中保持穩定。","reversed":"你的靈魂在提醒你：低潮不是懲罰，而是生命循環的自然部分。你正在經歷必要的業力清理，這會讓你變得更強大。輪子在低點停留不會太久，但你需要學會在困境中依然保持信心。這個困難是通往下一個高峰的必經之路。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:11-justice', 'tarot', '11-justice', 11, '正義', 'Justice', 'https://images.pexels.com/photos/8067125/pexels-photo-8067125.jpeg', '{"keywords":["公平","真理","因果","平衡","法律"],"arcana":"major","number":11}', '{"uprightMeaning":"正義牌代表公平、真理和業力的平衡。這張牌提醒你所有的行為都會產生相應的結果，善有善報，惡有惡報。當正義牌出現時，可能意味著一個需要做出公正決定的時刻，或是過去的行為正在顯現其後果。這張牌鼓勵你以誠實和正直的態度行事，做出符合道德和良心的選擇。正義也代表法律事務、合約和協議，提醒你確保一切都是公平和透明的。這是承擔責任、面對真相並尋求平衡的時機。正義女神手持天平和利劍，象徵著客觀的判斷和果斷的行動。她提醒你要理性分析，不帶偏見地看待事物，做出最公正的決定。","reversedMeaning":"逆位的正義牌顯示可能存在不公平、偏見或不誠實的情況。你可能正在經歷不公正的對待，或是自己行為不正直。這張牌也可能指出逃避責任、拒絕承認錯誤或是無法做出公正的判斷。你可能對某些情況抱有偏見，無法客觀地看待真相。逆位的正義牌提醒你需要誠實地面對自己的行為和動機。如果你造成了傷害，現在是時候承擔責任並彌補過失。如果你受到不公平的對待，不要保持沉默，而是要為自己發聲。這張牌也可能指出法律問題或合約糾紛，需要尋求專業的幫助。重新建立平衡和公正，從誠實和負責任開始。","detailedInterpretation":{"coreKeywords":{"upright":["公正決斷","因果真理","負責任","平衡法則","誠實正直"],"reversed":["不公平","逃避責任","偏見","不誠實","失衡"],"uprightExplanation":"正義牌正位代表宇宙的平衡法則和因果律的展現。她手持天平和利劍，象徵公正的衡量和果斷的執行。正位時，這張牌提醒你：你種下什麼因，就會收穫什麼果。這是業力法則的具體展現，所有的行為都會帶來相應的後果。正義要求你誠實面對自己的選擇和行為，承擔應有的責任。這張牌也可能指出法律事務、合約或重要決定的時刻，需要你保持客觀和公正。正義不是報復，而是恢復平衡。當你以正直和誠實行事，正義會站在你這邊。這張牌提醒你：真相終將大白，公平終將到來。","reversedExplanation":"正義牌逆位顯示存在不公平、偏見或逃避責任的情況。你可能正經歷不公正的對待，或是自己行為不正直卻不願承認。逆位時，天平失衡了，真相被掩蓋，責任被推卸。你可能對自己或他人有偏見，無法客觀看待事實。這張牌也可能指出你在逃避該面對的後果，或是拒絕承認自己的錯誤。逆位正義提醒你：逃避只會讓問題更嚴重。業力不會因為你不看就消失。誠實面對真相，承擔你的責任，才能恢復平衡。如果你受到不公平對待，勇敢站出來為自己發聲。真理可能被暫時隱藏，但終將浮現。"},"energyFlow":{"direction":"平衡對稱","type":"衡量與調整","description":"正義的能量是平衡性的，像天平的兩端尋求平衡點。這是理性、客觀、不帶情緒的能量，追求公正和真理。能量在對立兩極之間尋找中心點。"},"timing":{"speed":"依法則而定","description":"正義代表因果法則的展現，時機取決於業力的成熟。通常在1-3個月內會看到公正的結果，但可能更長。正義不急不徐，但終將到來。"},"advice":{"upright":"以誠實和正直行事。做公正的決定，不偏不倚。承擔你的責任，也要求他人承擔他們的責任。相信真相和公平終將勝出。如有法律事務，現在是好時機。","reversed":"誠實檢視自己的行為——你是否在逃避責任？如果受到不公平對待，為自己站出來。放下偏見和批判，客觀看待事實。承認錯誤，彌補過失，恢復平衡。"},"chakra":{"primary":"太陽神經叢 + 喉輪","issue":"無法為自己發聲（喉輪），或缺乏承擔責任的力量（太陽神經叢）","healingNote":"正義牌連結太陽神經叢（個人力量與責任）和喉輪（說出真理）。如果無法說真話或承擔責任，這兩個脈輪需要平衡。透過黃水晶（太陽神經叢）和藍晶石（喉輪）的水晶療癒可以恢復平衡。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂想要你知道：宇宙是公正的，你所做的一切都會回到你身上。現在是收穫你正直行為的果實的時刻。繼續以誠實和公平對待自己和他人，業力會支持你。真理是你最大的力量。","reversed":"你的靈魂在提醒你：你無法永遠逃避後果。你種下的因，早晚會結果。誠實面對你的行為，承擔你的責任。如果你受到不公平對待，不要沉默——宇宙需要你為自己發聲。只有當你恢復內在的正直，外在的公平才會到來。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:12-hanged', 'tarot', '12-hanged', 12, '倒吊者', 'The Hanged Man', 'https://images.pexels.com/photos/8067181/pexels-photo-8067181.jpeg', '{"keywords":["暫停","新視角","放手","犧牲","等待"],"arcana":"major","number":12}', '{"uprightMeaning":"倒吊者代表暫停、放手和從新角度看待事物的智慧。這張牌提醒你有時候，停下來並改變觀點比一直往前衝更有價值。倒吊者自願懸掛在樹上，象徵著自我犧牲和奉獻，為了更高的目標而暫時放棄舒適。這是一個反思和等待的時期，不是行動的時候。你可能需要改變你看待問題的方式，從不同的角度來理解情況。倒吊者鼓勵你接受當下的狀態，即使感覺不舒服或違反直覺。這段時期適合靈性修行、冥想和內在探索。透過放下控制和接受不確定性，你將獲得新的洞見和智慧。倒吊者提醒你有時候放手就是最好的前進方式。","reversedMeaning":"逆位的倒吊者顯示你可能正在抗拒必要的暫停或改變觀點。你可能感到停滯不前，卻又不願意做出改變來打破僵局。這張牌也可能指出拖延、無謂的犧牲或是感到被困住而無法前進。你可能執著於舊的思維模式，拒絕從新的角度看待問題。逆位的倒吊者提醒你需要採取行動，打破停滯的狀態。如果你一直在等待，現在可能是時候主動做些什麼了。然而，這張牌也可能警告你不要為了改變而改變，或是做出倉促的決定。審視你所抗拒的是什麼，以及為什麼你不願意改變觀點。有時候，接受當下的狀態並耐心等待才是明智之舉。","detailedInterpretation":{"coreKeywords":{"upright":["臣服等待","轉換視角","暫停反思","犧牲奉獻","放下控制"],"reversed":["抗拒停滯","拖延","無謂犧牲","僵化思維","不願改變"],"uprightExplanation":"倒吊者正位代表一個深刻的暫停和視角轉換的時期。他倒掛在樹上，卻面帶平靜，象徵著透過臣服和放下控制而獲得的智慧。正位時，這張牌要求你停止掙扎，接受當下無法改變的狀況。這不是被動的放棄，而是主動的臣服——選擇用不同的角度看待問題。倒吊者提醒你：有時候倒過來看，世界會變得更清晰。這是犧牲小我完成大我的時期，你需要放棄某些東西來獲得更重要的領悟。這段等待期是必要的，急躁只會延長過程。倒吊者教導你在靜止中成長，在等待中蛻變。","reversedExplanation":"倒吊者逆位顯示你可能正在抗拒必要的暫停，或是陷入無意義的停滯。你可能拒絕改變視角，固執地堅持舊有的思維模式。逆位時，那個暫停變成了拖延，犧牲變成了無謂的受苦。你可能感到被困住，卻不願意做出改變來打破僵局。這張牌也可能指出你已經等待夠久了，是時候採取行動了。逆位倒吊者提醒你：等待有其價值，但無限期的等待就是逃避。檢視你是在耐心等待，還是在恐懼中拖延。有時候，最大的改變來自於願意看見不同的可能性。"},"energyFlow":{"direction":"暫停靜止","type":"內化與轉化","description":"倒吊者的能量是暫停和內化的，像蛹在繭中的蛻變。表面看似靜止，內在卻在深度轉化。這是臣服、接納、倒轉視角的能量。"},"timing":{"speed":"延遲等待","description":"倒吊者代表明確的等待期。事情不會快速發展，需要2-6個月的暫停和反思。這是宇宙要你學會耐心的時期。急也沒用，該等的還是要等。"},"advice":{"upright":"停下來，不要再掙扎。接受當前的狀況，用不同的角度看待問題。這個暫停是必要的，耐心等待會帶來深刻的洞見。問問自己：我需要放下什麼？","reversed":"檢視你是在等待還是在拖延。如果是拖延，是時候行動了。如果你一直抗拒改變視角，試著倒過來看看。打破停滯需要你願意改變思維模式。"},"chakra":{"primary":"頂輪 + 海底輪","issue":"無法臣服於更高指引（頂輪），或過度需要控制感（海底輪）","healingNote":"倒吊者需要頂輪（靈性臣服）與海底輪（接地安全感）的平衡。如果無法放下控制或抗拒等待，代表這兩個脈輪需要調和。透過水晶療癒可以幫助你學會信任和臣服。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂想要你知道：這個暫停不是懲罰，而是禮物。在這段等待中，你正在經歷深刻的內在轉化。倒過來看，你會發現一直忽略的真理。臣服不是放棄，而是更高層次的智慧。信任這個過程，蛻變正在發生。","reversed":"你的靈魂在提醒你：你已經等待夠久了，或者你根本不願意等待。如果是前者，是時候行動了；如果是後者，學會臣服吧。抗拒只會延長痛苦。有時候，最勇敢的行動就是願意停下來，願意用新的眼光看待一切。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:13-death', 'tarot', '13-death', 13, '死神', 'Death', 'https://images.pexels.com/photos/7195358/pexels-photo-7195358.jpeg', '{"keywords":["轉變","結束","重生","放下","過渡"],"arcana":"major","number":13}', '{"uprightMeaning":"死神牌代表結束、轉變和重生，而非實際的死亡。這張牌象徵著一個重要階段的結束和新階段的開始。當死神出現時，提醒你需要放下過去，讓舊的事物死去，才能為新的可能性騰出空間。這可能涉及結束一段關係、離開一份工作、改變信念或是放棄舊的行為模式。雖然改變可能令人不安，但死神帶來的是必要的轉變和更新。這張牌鼓勵你接受生命的自然循環，理解結束是新開始的前提。死神騎著白馬，象徵著純淨和轉化的力量。不要抗拒這個過程，而是要擁抱變化，信任新的事物將會帶來成長和進化。","reversedMeaning":"逆位的死神顯示你可能正在抗拒必要的結束和改變。你可能緊抓著已經不再適合你的人、事、物，害怕放手會失去一切。這張牌也可能指出停滯不前，無法完成轉變的過程。你可能一直處於過渡狀態，既無法放下過去，也無法真正迎接未來。逆位的死神提醒你拒絕改變只會造成更多的痛苦和困難。有些事情已經走到盡頭，繼續強求只會消耗你的能量。這張牌鼓勵你誠實地面對現實，接受某些事物需要結束的事實。放手並不代表失敗，而是為了讓更好的事物進入你的生命。允許自己經歷悲傷和失落的過程，然後勇敢地向前邁進。","detailedInterpretation":{"coreKeywords":{"upright":["徹底轉變","結束重生","放下過去","蛻變更新","必然結局"],"reversed":["抗拒結束","無法放手","停滯不前","恐懼改變","緩慢轉變"],"uprightExplanation":"死神正位代表深刻而徹底的轉變，象徵著舊循環的結束和新循環的開始。死神騎著白馬，代表純淨的轉化力量，他帶走的是過時和不再服務你的事物。正位時，這張牌要求你接受某個重要階段的結束，無論是關係、工作、信念還是生活方式。這不是實際的死亡，而是象徵性的死亡和重生。死神提醒你：只有當舊的死去，新的才能誕生。這個轉變可能令人痛苦，但它是必要且無法避免的。抗拒只會延長痛苦。死神教導你放下執著，信任轉變的過程。在死亡的另一端，永遠是重生。","reversedExplanation":"死神逆位顯示你正在強烈抗拒必要的結束和轉變。你可能緊抓著已經死去的事物不放，害怕面對失去和未知。逆位時，那個必然的結束被延遲了，但這只會造成更多痛苦和停滯。你可能一直處於過渡期，既無法放下過去，也無法真正迎接未來。這張牌也可能指出你害怕改變到願意付出任何代價來維持現狀。逆位死神提醒你：有些事情已經走到盡頭，強行維持只會消耗你的生命力。放手不是失敗，而是智慧。只有當你允許死亡發生，重生才能開始。"},"energyFlow":{"direction":"清理釋放","type":"轉化與重生","description":"死神的能量是清理和釋放的，像秋天落葉為春天的新芽騰出空間。這是不可逆的轉化能量，舊的必須死去，新的才能誕生。能量從結束流向重生。"},"timing":{"speed":"不可避免的終結","description":"死神代表無法避免的結束，時機由生命本身決定。轉變期通常是1-3個月，但完整的重生可能需要更長時間。該來的終會來，無法加速也無法延遲。"},"advice":{"upright":"接受這個結束，不要抗拒。放下已經不再適合你的人事物。信任轉變的過程，即使你看不見新的開始。允許自己哀悼失去，然後勇敢地向前走。","reversed":"誠實面對：你在緊抓什麼？為什麼你不願意放手？恐懼是正常的，但不能讓它阻止必要的轉變。有些事情必須結束，你越早接受，就能越早開始新生活。"},"chakra":{"primary":"海底輪 + 全脈輪淨化","issue":"對失去的恐懼導致海底輪失衡，或整體能量系統需要深度清理","healingNote":"死神的轉化影響所有脈輪，特別是海底輪（生存與安全感）。如果無法接受結束或轉變，需要重建安全感和信任。透過黑曜石、煙晶的水晶療癒可以幫助釋放和轉化。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂想要你知道：這個結束是必要的祝福。你緊抓的東西已經完成了它的使命，是時候放手了。死亡不是終點，而是轉化的門戶。在你放下的那一刻，新的生命就會開始。信任這個神聖的過程，重生正在等待你。","reversed":"你的靈魂在提醒你：你無法永遠停在兩個世界之間。該死去的必須死去，你越抗拒，就越痛苦。放手不會讓你失去一切，反而會讓你獲得真正重要的東西。停止與生命的自然流動對抗，允許轉變發生。你的重生在另一邊等著你。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:14-temperance', 'tarot', '14-temperance', 14, '節制', 'Temperance', 'https://images.pexels.com/photos/8067252/pexels-photo-8067252.jpeg', '{"keywords":["平衡","調節","耐心","和諧","中庸"],"arcana":"major","number":14}', '{"uprightMeaning":"節制牌代表平衡、調和和中庸之道。這張牌展現了天使在兩個杯子之間倒水，象徵著能量的流動和融合。當節制牌出現時，提醒你需要在生活的各個層面尋求平衡和和諧。這可能涉及整合對立的元素，找到工作與生活的平衡，或是調和理性與感性。節制鼓勵你保持耐心和節制，避免極端和過度。這是療癒、適應和整合的時期，需要你以溫和漸進的方式前進。節制也代表靈性的煉金術，將不同的元素轉化為和諧的整體。這張牌提醒你中庸之道的智慧，凡事適可而止。透過耐心和調節，你能夠創造內在的和平與外在的和諧。","reversedMeaning":"逆位的節制牌顯示你可能正在經歷失衡、過度或缺乏節制的情況。你可能在某些領域過度投入，而忽略了其他重要的層面。這張牌也可能指出缺乏耐心，想要快速得到結果而跳過必要的過程。你可能感到內在或外在的不和諧，無法整合對立的元素。逆位的節制牌提醒你需要重新找回平衡。檢視你的生活，看看哪些地方過度或不足。學會節制和適度，避免走向極端。這張牌也可能警告你過度沉溺於某些習慣或行為，需要更多的自我控制。花時間調整和校準，以溫和的方式進行改變。記住，平衡不是一個終點，而是一個持續的過程。","detailedInterpretation":{"coreKeywords":{"upright":["和諧平衡","中庸之道","整合調和","耐心漸進","煉金術"],"reversed":["失衡過度","缺乏節制","極端行為","不耐煩","無法整合"],"uprightExplanation":"節制牌正位代表煉金術般的整合與平衡藝術。天使一手持陽性能量的杯，一手持陰性能量的杯，水在兩者之間流動，象徵對立元素的和諧融合。正位時，這張牌教導你中庸之道的智慧——不走極端，在各種力量之間找到平衡點。節制不是壓抑，而是調和。這是療癒和整合的時期，你正在學習將生活中看似矛盾的部分融合成和諧的整體。節制要求你保持耐心，以溫和漸進的方式前進。這張牌提醒你：真正的力量不在於極端，而在於平衡。當你找到中心點，你就掌握了生命的煉金術。","reversedExplanation":"節制牌逆位顯示你正經歷失衡和過度的狀態。你可能在某些領域投入太多而忽略其他重要面向，或是在不同極端之間劇烈擺盪。逆位時，那股整合的能量被阻斷了，對立的元素無法和諧共存。你可能缺乏耐心，想要快速得到結果而跳過必要的過程。這張牌也可能指出過度沉溺於某些習慣或行為，失去了節制和自我控制。逆位節制提醒你：失衡會帶來疾病和痛苦。檢視你的生活，看看哪裡過度哪裡不足。真正的療癒需要時間和耐心，無法一蹴而就。回到中心，重新找到平衡。"},"energyFlow":{"direction":"雙向流動與整合","type":"調和與平衡","description":"節制的能量是雙向流動的，像是在對立的兩極之間建立橋樑。這是溫和、漸進、持續調整的能量，追求動態的平衡而非靜態的穩定。能量在整合中轉化。"},"timing":{"speed":"漸進緩慢","description":"節制代表需要時間和耐心的漸進過程。真正的整合和平衡無法被催促，通常需要2-4個月的持續調整。慢工出細活，不要急。"},"advice":{"upright":"尋找中庸之道，避免走向極端。在工作與生活、理性與感性、給予與接收之間找到平衡。保持耐心，以溫和的方式進行改變。整合對立，而非選邊站。","reversed":"檢視你的生活是否失衡。哪些地方過度了？哪些地方被忽略了？學習節制和自我控制。不要急於求成，給自己時間慢慢調整。回到中心點，重建和諧。"},"chakra":{"primary":"心輪","issue":"心輪失衡導致無法整合對立能量，過度偏向某一極端","healingNote":"節制牌與心輪的平衡功能直接相關，心輪是上三輪與下三輪的橋樑。如果感到失衡或無法整合矛盾，代表心輪需要被調和。透過玫瑰石英、綠東陵的水晶療癒可以恢復平衡能力。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂想要你知道：生命的藝術在於平衡，而非完美。你正在學習煉金術——將對立轉化為和諧。保持耐心，中庸之道是最有力量的道路。你不需要選擇一邊，你可以整合兩邊。在平衡中，你會發現真正的自己。","reversed":"你的靈魂在提醒你：你已經失去了中心。過度和缺乏都是失衡的表現。停下來，檢視你的生活。你不能一直在極端之間擺盪。真正的療癒來自溫和的調整，而非劇烈的改變。回到你的中心，從那裡重新開始。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:15-devil', 'tarot', '15-devil', 15, '惡魔', 'The Devil', 'https://images.pexels.com/photos/8067289/pexels-photo-8067289.jpeg', '{"keywords":["束縛","成癮","物質","依賴","限制"],"arcana":"major","number":15}', '{"uprightMeaning":"惡魔牌代表束縛、成癮和物質慾望的控制。這張牌展現了被鎖鏈綁住的人們，但仔細看會發現鎖鏈是鬆的，象徵著束縛往往是自己造成的。當惡魔牌出現時，提醒你可能被某些習慣、信念或關係所困，感到無法自拔。這可能涉及物質成癮、有毒的關係、強迫性行為或是限制性的思維模式。惡魔也代表陰影自我和被壓抑的慾望，提醒你需要面對內心深處的恐懼和黑暗面。這張牌不是要評判你，而是要喚醒你的意識，讓你認識到自己被什麼所控制。只有意識到束縛的存在，你才能選擇解放自己。惡魔提醒你有力量打破鎖鏈，重獲自由。","reversedMeaning":"逆位的惡魔牌通常是一個積極的信號，代表你正在掙脫束縛，獲得解放和覺醒。你可能正在克服成癮、離開有毒的關係或是打破限制性的信念。這張牌顯示你開始看清真相，不再被幻象所迷惑。然而，逆位的惡魔也可能指出你仍然否認問題的存在，或是低估了束縛的力量。你可能假裝一切都好，而實際上仍然被困在不健康的模式中。逆位的惡魔提醒你解放是一個過程，需要勇氣和誠實。不要害怕面對你的陰影面，因為接納和整合它們才能真正獲得自由。這是一個強大的轉化時期，你有機會重新掌控自己的生命。","detailedInterpretation":{"coreKeywords":{"upright":["自我束縛","成癮依賴","物質誘惑","陰影面","虛假安全"],"reversed":["掙脫束縛","覺醒解放","克服成癮","面對陰影","突破限制"],"uprightExplanation":"惡魔正位代表自我創造的束縛和限制。牌面上的人們被鬆散的鎖鏈綁住，象徵著束縛其實是可以掙脫的，但他們選擇了留下。正位時，這張牌揭露你被什麼所控制——成癮、有毒的關係、物質慾望、限制性信念，或是對安全感的過度追求。惡魔代表你的陰影面，那些你不願承認的慾望和恐懼。這張牌不是在評判你，而是要喚醒你的意識。只有當你認識到自己被什麼束縛，才能選擇解放。惡魔提醒你：最可怕的監獄是你自己建造的。你手中一直握著鑰匙，只是你害怕自由。","reversedExplanation":"惡魔逆位通常是正面的訊號，代表你正在掙脫束縛，獲得覺醒和解放。你開始看清那些控制你的事物的真面目，不再被幻象所迷惑。逆位時，你正在打破鎖鏈，克服成癮，離開有毒的關係，或是突破限制性的信念。然而，逆位惡魔也可能指出你仍在否認問題的存在，假裝一切都好。有時候逆位代表你低估了束縛的力量，以為自己已經自由了，實際上只是換了一種形式的牢籠。真正的解放需要勇氣面對陰影，誠實承認自己的弱點。只有當你完全看見束縛，才能真正獲得自由。"},"energyFlow":{"direction":"向下沉重","type":"束縛與限制","description":"惡魔的能量是向下沉重的，像是被重力拉扯。這是密集、黏著、難以掙脫的能量，讓人感到被困住和無力。能量被困在物質層面，無法上升。"},"timing":{"speed":"停滯緩慢","description":"惡魔代表被困住的狀態，時間感被扭曲。掙脫束縛需要覺醒和持續的努力，通常需要3-6個月或更長。改變不會自動發生，需要你主動打破模式。"},"advice":{"upright":"誠實面對你被什麼束縛。不要再欺騙自己說「我可以隨時停止」。面對你的陰影面，承認你的弱點和慾望。記住：鎖鏈是鬆的，你隨時可以離開。問問自己：我為什麼選擇留在這裡？","reversed":"如果你正在掙脫束縛，繼續努力，自由就在前方。如果你在否認問題，是時候誠實面對了。打破舊模式需要勇氣和毅力。尋求支持，你不需要獨自面對。真正的解放從承認開始。"},"chakra":{"primary":"海底輪 + 臍輪","issue":"過度執著物質安全（海底輪），或被慾望和成癮控制（臍輪）","healingNote":"惡魔與下三輪的失衡有關，特別是海底輪（恐懼與安全）和臍輪（慾望與成癮）。如果感到被束縛或無法掙脫，需要清理和平衡這些脈輪。透過黑曜石、煙晶的水晶療癒可以幫助釋放和轉化。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂想要你知道：你比你以為的更自由。那些束縛你的鎖鏈是鬆的，你隨時可以離開。但首先，你必須承認它們的存在。不要害怕看見你的陰影面，它只是需要被愛和接納的部分。你擁有選擇的力量。","reversed":"你的靈魂在慶祝你的覺醒。你正在打破束縛，重獲自由。這條路不容易，但你已經開始了。不要回頭，不要被舊有的舒適感誘惑。真正的自由在前方等著你。或者，你的靈魂在提醒你：停止否認。你還沒有真正自由，只是換了一種形式的牢籠。誠實面對自己吧。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:16-tower', 'tarot', '16-tower', 16, '高塔', 'The Tower', 'https://images.pexels.com/photos/7195409/pexels-photo-7195409.jpeg', '{"keywords":["突變","動盪","啟示","破壞","覺醒"],"arcana":"major","number":16}', '{"uprightMeaning":"高塔牌代表突然的改變、崩潰和覺醒的時刻。這張牌展現了被閃電擊中的高塔，象徵著建立在虛假基礎上的結構正在崩塌。當高塔出現時，預示著劇烈的變化即將到來，這可能是震撼性的啟示、突發的事件或是長期累積問題的爆發。雖然高塔帶來的變化可能令人痛苦和不安，但它的目的是摧毀不再服務你的舊結構，為真實和穩固的基礎騰出空間。高塔提醒你有時候系統需要完全重置，才能重建得更好。這是一個覺醒和真相揭露的時刻，即使過程艱難，最終會帶來解放和成長。接受這個必要的破壞，信任從廢墟中將會誕生新的可能性。","reversedMeaning":"逆位的高塔顯示你可能正在逃避或延遲必要的改變和崩潰。你可能感覺到即將發生的劇變，但試圖阻止或控制它。這張牌也可能指出你對改變的恐懼如此強烈，以至於寧願維持不健康的現狀。逆位的高塔提醒你抗拒只會讓事情變得更糟。當基礎已經不穩固時，繼續建造只會讓最終的崩潰更加嚴重。然而，這張牌也可能代表你正在從創傷或劇變中恢復，雖然過程緩慢但正在重建。逆位的高塔鼓勵你不要害怕必要的改變，接受某些事物需要結束。與其抗拒不可避免的事，不如主動做出改變，以更可控的方式進行轉化。","detailedInterpretation":{"coreKeywords":{"upright":["突然崩潰","震撼啟示","破壞重建","虛假結構倒塌","解放覺醒"],"reversed":["逃避災難","緩慢崩解","恐懼改變","災後重建","抗拒真相"],"uprightExplanation":"高塔正位代表突如其來的劇變和震撼性的覺醒時刻。閃電擊中高塔，象徵宇宙以強力的方式打破虛假的結構和幻象。正位時，這張牌預示著你的世界將會被震動，那些建立在錯誤基礎上的信念、關係或系統將會崩塌。這是痛苦的，但也是必要的。高塔不會摧毀真實的東西，只會摧毀虛假和不穩固的部分。這是強制性的覺醒——當你不願意自願改變時，宇宙會替你做決定。高塔提醒你：有時候整個系統需要被推倒重建。在廢墟中，你會看見一直被隱藏的真相。這個崩潰是解放的開始。","reversedExplanation":"高塔逆位顯示你可能正在逃避或延遲必要的崩潰。你感覺到地基在震動，知道災難即將發生，卻試圖阻止或控制它。逆位時，崩潰可能以較慢、較不劇烈的方式發生，或是你正從創傷中恢復。這張牌也可能指出你對改變的恐懼如此強烈，寧願維持搖搖欲墜的現狀。逆位高塔提醒你：拖延只會讓最終的崩潰更嚴重。當基礎已經不穩時，繼續在上面建造是危險的。有時候，最勇敢的選擇是主動拆除，而非等待崩塌。逆位也可能代表你正在災後重建，雖然緩慢但正在進步。"},"energyFlow":{"direction":"向下爆破","type":"破壞與清理","description":"高塔的能量是爆炸性的、破壞性的，像閃電一樣突然而猛烈。這是摧毀舊結構、清除阻礙的能量，雖然震撼但也帶來解放。能量從上而下強力衝擊。"},"timing":{"speed":"突然迅速","description":"高塔代表突發事件，通常在1-2週內發生。這是無法預測的劇變，來得快去得也快。雖然崩潰是瞬間的，但重建需要更長時間，通常3-6個月。"},"advice":{"upright":"不要抗拒這個崩潰，它是必要的。放下對舊結構的執著，接受這個劇變。在廢墟中尋找真相和新的可能性。這不是終點，而是重建的開始。給自己時間療癒，但不要停留在受害者的角色。","reversed":"如果你感覺到即將崩潰，與其抗拒不如主動面對。檢視你的基礎是否穩固，如果不穩，自己拆除比等待崩塌更好。如果你正在重建，繼續前進，一步一步來。不要回去修復已經倒塌的舊結構。"},"chakra":{"primary":"全脈輪系統重置","issue":"整個能量系統被震撼，需要重建和重新對齊","healingNote":"高塔影響整個脈輪系統，是深度的能量重置。經歷高塔時，所有脈輪都可能失衡。需要全面的療癒和重建，從海底輪開始重新建立穩固的基礎。透過水晶療癒可以幫助重新對齊和穩定能量。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂想要你知道：這個崩潰是必要的祝福。那座高塔已經困住你太久了，是時候被摧毀。在廢墟中，你會發現真實的自己。不要害怕失去一切，因為你將會重建得更真實、更穩固。這是強制性的解放，擁抱它。","reversed":"你的靈魂在提醒你：你無法永遠阻止崩潰。拖延只會讓它更嚴重。如果基礎不穩，最好主動拆除重建。或者，你的靈魂在說：是的，你經歷了劇變，但你還活著。現在是重建的時候了。不要試圖重建舊的高塔，建造新的、真實的結構吧。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:17-star', 'tarot', '17-star', 17, '星星', 'The Star', 'https://images.pexels.com/photos/8067352/pexels-photo-8067352.jpeg', '{"keywords":["希望","信念","靈感","寧靜","更新"],"arcana":"major","number":17}', '{"uprightMeaning":"星星牌代表希望、信念和靈性的更新。這張牌通常在高塔之後出現，象徵著在黑暗和混亂之後，重新找到光明和方向。當星星出現時，帶來平靜、療癒和樂觀的能量。這是一個重新連結靈性、恢復信心並展望未來的時期。星星鼓勵你相信宇宙的指引，即使在困難時刻也要保持希望。這張牌也代表靈感、創造力和與更高自我的連結。星星的能量純淨而安寧，提醒你在寧靜中找到力量。這是療癒舊傷、恢復活力並重新相信美好未來的時機。星星照亮你的道路，提醒你永遠不要失去希望，因為黎明總會到來。","reversedMeaning":"逆位的星星顯示你可能正在經歷絕望、失去信念或是缺乏方向的時期。你可能感到沮喪和無望，看不到未來的光明。這張牌也可能指出你與靈性的連結斷裂，或是失去了對生命意義的信心。你可能被自我懷疑和消極思想所困擾，無法看到自己的潛力和價值。逆位的星星提醒你即使在最黑暗的時刻，希望仍然存在。不要讓暫時的挫折擊垮你的信念。這是一個需要重新連結內在光芒的時期。尋找能夠激勵和提升你的事物，無論是自然、藝術還是靈性修行。記住，失去希望只是暫時的，你有力量重新點燃內心的星光。保持信念，光明終將重現。","detailedInterpretation":{"coreKeywords":{"upright":["希望重燃","靈性療癒","純淨信念","靈感指引","寧靜更新"],"reversed":["失去希望","信念動搖","靈性枯竭","自我懷疑","迷失方向"],"uprightExplanation":"星星正位代表在黑暗之後重新找到希望之光。這張牌通常在高塔之後出現，象徵在崩潰和混亂過後，平靜和療癒的到來。正位時，星星帶來純淨的希望、靈性的更新和對未來的信心。這是你重新與靈性連結、恢復信念的時期。星星的能量溫柔而療癒，像清泉洗滌傷口。這張牌提醒你：即使經歷了最黑暗的夜晚，星光依然閃耀。星星代表你的真實本質——純淨、充滿希望、與宇宙連結。正位星星鼓勵你保持信念，相信美好的未來正在展開。這是靈感湧現、創造力復甦的時期。你的療癒之旅已經開始。","reversedExplanation":"星星逆位顯示你可能正經歷絕望、失去信念或靈性枯竭的時期。黑暗似乎太過濃重，你看不見任何光明。逆位時，希望之光被雲層遮蔽，你失去了方向和意義感。你可能被自我懷疑和消極思想壓倒，無法相信事情會好轉。這張牌也可能指出你與靈性的連結斷裂，感到空虛和迷失。逆位星星提醒你：星光一直都在，只是暫時被遮蔽。即使你看不見，希望依然存在。這是重新建立信念、尋找生命意義的時期。從小事開始，重新點燃你內在的光。逆位也可能代表你對未來過度樂觀而脫離現實。"},"energyFlow":{"direction":"向下流動療癒","type":"接收與更新","description":"星星的能量是從天而降的療癒之水，溫柔地流動、滋養、更新。這是純淨、平靜、充滿希望的能量，像星光一樣柔和卻持久。能量從宇宙流向大地，帶來靈性的滋養。"},"timing":{"speed":"緩慢療癒","description":"星星代表療癒和恢復的時期，不能被催促。真正的更新需要時間，通常需要2-6個月。這是靜養和恢復的時期，讓星光慢慢療癒你。"},"advice":{"upright":"保持希望和信念。這是療癒的時期，給自己時間恢復。連結你的靈性，尋找能啟發你的事物。相信美好的未來正在展開。多接觸自然，讓星光療癒你的傷口。","reversed":"不要讓絕望吞沒你。即使看不見光明，它依然存在。從小事開始重建信念——一個感恩的時刻、一個美好的瞬間。尋求支持，你不需要獨自在黑暗中。重新連結你的靈性，希望會回來的。"},"chakra":{"primary":"頂輪 + 喉輪","issue":"與宇宙連結斷裂（頂輪），或無法表達真實自我（喉輪）","healingNote":"星星與頂輪（靈性連結）和喉輪（真實表達）有關。如果失去希望或無法表達真實自我，這兩個脈輪需要療癒。透過透石膏、海藍寶的水晶療癒可以重建連結和信任。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂想要你知道：最黑暗的夜晚已經過去了。星光正在照耀你的道路，療癒正在發生。你不需要做什麼，只需要保持開放，允許希望重新進入你的心。你的本質是純淨和充滿光的。記得這一點，你就永遠不會迷失。","reversed":"你的靈魂在提醒你：絕望是暫時的，希望是永恆的。你感覺不到星光，並不代表它不在。放下懷疑，重新相信美好。你經歷的黑暗不是你的本質，你的本質是光。慢慢來，希望會一點一點回到你心中。不要放棄。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:18-moon', 'tarot', '18-moon', 18, '月亮', 'The Moon', 'https://images.pexels.com/photos/8067409/pexels-photo-8067409.jpeg', '{"keywords":["幻覺","直覺","潛意識","恐懼","神秘"],"arcana":"major","number":18}', '{"uprightMeaning":"月亮牌代表幻象、潛意識和內在恐懼的領域。這張牌展現了月光下模糊不清的景象，象徵著事物並非表面所見。當月亮出現時，提醒你正處於一個充滿不確定性和混亂的時期，真相可能被隱藏或扭曲。月亮鼓勵你深入探索潛意識，面對內心深處的恐懼和陰影。這張牌也代表直覺、夢境和心理的深層領域。月亮的能量神秘而強大，能夠揭示隱藏的真相和未知的領域。這是一個需要信任直覺，並勇敢面對內心恐懼的時期。不要被幻象所迷惑，而是要看穿表象，找到真正的真相。月亮提醒你有些事物需要在黑暗中孕育，才能在適當的時機顯現。","reversedMeaning":"逆位的月亮顯示幻象正在消散，真相開始浮現。你可能正在從混亂和困惑中走出來，逐漸看清事物的本質。這張牌也可能指出你正在釋放長期壓抑的恐懼和焦慮，開始面對內心的陰影。然而，逆位的月亮也可能代表你仍然被恐懼所困，或是拒絕面對潛意識的訊息。你可能壓抑情緒和直覺，試圖用理性來控制一切。逆位的月亮提醒你不要忽視內在的聲音和感受。給自己時間和空間來處理複雜的情緒，不要急於求清晰。有時候，接受不確定性和模糊性是必要的。隨著時間推移，真相自然會顯現。相信自己的直覺，它會引導你穿越迷霧。","detailedInterpretation":{"coreKeywords":{"upright":["幻象迷霧","潛意識探索","直覺指引","恐懼浮現","神秘真相"],"reversed":["真相揭露","走出迷霧","釋放恐懼","清晰顯現","逃避直覺"],"uprightExplanation":"月亮正位代表進入潛意識的神秘領域，在那裡真相被幻象所掩蓋。月光下的景象模糊不清，象徵你正處於不確定和混亂的時期。正位時，這張牌提醒你事物並非表面所見，需要深入探索才能發現真相。月亮代表你的潛意識、夢境和直覺，也代表內心深處的恐懼和陰影。這是一個需要面對未知、信任直覺的時期。月亮不會給你清晰的答案，而是要求你在模糊中前進，用感覺而非邏輯。這張牌也可能指出欺騙、幻象或是你自己的投射。月亮提醒你：在黑暗中孕育的東西需要時間才能顯現。不要急於求清晰，允許神秘存在。","reversedExplanation":"月亮逆位通常代表幻象開始消散，真相逐漸清晰。你正在從混亂和困惑中走出來，看清事物的本質。逆位時，你可能正在釋放長期壓抑的恐懼和焦慮，開始面對潛意識的內容。這是積極的轉變，代表清明即將到來。然而，逆位月亮也可能指出你仍在逃避或否認潛意識的訊息。你可能用理性來壓抑直覺，拒絕面對內心的恐懼。這張牌提醒你：真正的清晰來自於面對黑暗，而非逃避。有時候逆位代表你需要接受不確定性，而非強求清晰。月亮的智慧不在於理解，而在於信任。"},"energyFlow":{"direction":"潮汐起伏","type":"潛意識波動","description":"月亮的能量是波動不定的，像潮汐受月亮影響而漲落。這是神秘、曖昧、情緒性的能量，無法用理性掌握。能量在意識與潛意識之間流動，帶來夢境和幻象。"},"timing":{"speed":"模糊不定","description":"月亮代表時機不明確，事情被隱藏或混亂。可能需要1-3個月的混亂期才會清晰。不要急著做決定，讓迷霧自然散去。真相需要時間才能完全顯現。"},"advice":{"upright":"信任你的直覺，即使看不清全貌。不要急於做決定，給自己時間觀察和感受。記錄你的夢境，探索你的潛意識。面對你的恐懼，不要讓它們在黑暗中茁壯。接受不確定性。","reversed":"如果真相正在浮現，接受它，即使它不舒服。如果你在逃避直覺，停下來聽聽內在的聲音。釋放你一直壓抑的恐懼和情緒。從迷霧中走出來，重新相信你的感知。"},"chakra":{"primary":"第三眼輪 + 臍輪","issue":"直覺被恐懼干擾（第三眼輪），或情緒失控（臍輪）","healingNote":"月亮與第三眼輪（直覺）和臍輪（情緒）相關。如果感到困惑或被恐懼壓倒，這兩個脈輪需要平衡。透過月光石、拉長石的水晶療癒可以淨化幻象，連結真實直覺。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂想要你知道：不是所有的真相都能被立即理解。有些事物需要在黑暗中孕育，在模糊中成形。你的恐懼不是敵人，而是等待被理解的訊息。信任你的直覺，即使它帶你走入未知。月亮的光雖然不明亮，但它會照亮你需要看見的路。","reversed":"你的靈魂在慶祝：迷霧正在散去，你正在看清真相。或者，你的靈魂在提醒你：停止逃避你已經知道的事實。你的直覺一直在告訴你真相，只是你不願意聽。面對你的恐懼，走出否認。真正的清明來自於勇敢地看見一切，包括你不想看見的部分。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:19-sun', 'tarot', '19-sun', 19, '太陽', 'The Sun', 'https://images.pexels.com/photos/8067459/pexels-photo-8067459.jpeg', '{"keywords":["喜悅","成功","活力","正面","慶祝"],"arcana":"major","number":19}', '{"uprightMeaning":"太陽牌代表喜悅、成功和純粹的快樂。這是塔羅牌中最積極正面的牌之一，象徵著光明、溫暖和生命力。當太陽出現時，預示著美好的時光即將到來，你的努力將獲得回報，成功唾手可得。太陽照亮一切，帶來清晰、真相和啟發。這是一個充滿活力、自信和樂觀的時期，適合展現真實的自我，享受生命的美好。太陽也代表童真、純潔和簡單的快樂，提醒你保持開放和真誠的心。這張牌鼓勵你慶祝成就，分享快樂，並以正面的態度面對生活。太陽的能量無條件而豐富，滋養萬物生長。這是收穫果實、感恩美好並充滿希望地展望未來的時刻。","reversedMeaning":"逆位的太陽通常仍然是積極的，但可能顯示暫時的陰霾或延遲的喜悅。你可能感到缺乏活力、自信心下降或是無法完全享受成功。這張牌也可能指出過度樂觀或是忽視問題的存在。你可能戴著玫瑰色眼鏡看世界，而沒有實際地評估情況。逆位的太陽提醒你即使在困難時刻，光明仍然存在，只是暫時被雲層遮蔽。不要讓暫時的挫折影響你的信心和樂觀。這張牌鼓勵你尋找生活中的正面事物，即使它們很小。重新連結內在的喜悅和活力，不要讓外在環境決定你的幸福感。記住，太陽總會再次升起，陰霾終將散去。保持耐心和信念，美好的日子即將到來。","detailedInterpretation":{"coreKeywords":{"upright":["純粹喜悅","成功達成","生命活力","真實自我","光明照耀"],"reversed":["暫時陰霾","過度樂觀","喜悅延遲","缺乏自信","忽視陰影"],"uprightExplanation":"太陽正位代表生命最純粹的喜悅和成功的展現。太陽無條件地照耀萬物，象徵豐盛、溫暖和生命力的高峰。正位時，這張牌帶來清晰、真相和絕對的正面能量。這是收穫的時刻，你的努力獲得了回報，成功是明確而可見的。太陽代表你的真實自我——純真、充滿活力、無所畏懼。這是童真般的快樂，不帶條件和複雜。太陽照亮一切，沒有陰影可以躲藏，沒有欺騙可以存在。正位太陽鼓勵你自信地展現自己，慶祝你的成就，分享你的喜悅。這是生命中最光明的時刻，盡情享受吧。這張牌提醒你：你值得所有的美好。","reversedExplanation":"太陽逆位通常仍然是正面的，但光芒可能暫時被遮蔽。你可能感到活力下降、自信不足或無法完全享受成功。逆位時，可能存在延遲、暫時的挫折或內在的陰霾。你可能過度樂觀而忽視實際問題，或是戴著玫瑰色眼鏡看世界。這張牌也可能指出你害怕展現真實的自己，或是內在的陰影還未被完全療癒。逆位太陽提醒你：即使陽光被雲層遮蔽，它依然在那裡。不要讓暫時的困難奪走你的喜悅。這張牌鼓勵你尋找生活中的光明面，重建自信和活力。太陽終將穿透雲層，照亮你的道路。"},"energyFlow":{"direction":"向外放射","type":"擴展與給予","description":"太陽的能量是向外放射的，無條件地給予光和熱。這是豐盛、溫暖、充滿生命力的能量，照亮一切，滋養萬物。能量是開放、正面、無限的。"},"timing":{"speed":"快速光明","description":"太陽代表快速而明確的進展。成功和喜悅會迅速到來，通常在1-4週內。這是收穫的時刻，果實已經成熟，陽光正照耀著你。"},"advice":{"upright":"盡情享受這個美好時光。慶祝你的成功，分享你的喜悅。自信地展現真實的自己，不要隱藏你的光芒。感恩你所擁有的一切。這是行動和創造的好時機。","reversed":"尋找生活中的光明面，即使它們很小。不要讓暫時的困難擊垮你的樂觀。重建你的自信，記住你的價值。檢視你是否過度樂觀而忽視問題。陽光會再次照耀，保持信念。"},"chakra":{"primary":"太陽神經叢 + 心輪","issue":"個人力量和自信不足（太陽神經叢），或心輪封閉無法感受喜悅（心輪）","healingNote":"太陽與太陽神經叢（個人力量）和心輪（喜悅）直接相關。如果感到缺乏活力或無法感受快樂，這兩個脈輪需要被激活。透過黃水晶、橙色方解石的水晶療癒可以重燃內在的陽光。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂在慶祝：你已經走過了黑暗，來到了光明。這是你努力的收穫，你應得的喜悅。不要謙虛或縮小自己，盡情閃耀吧！你的光芒不會讓別人黯淡，反而會照亮他們。記住這個時刻，當未來再次陷入黑暗時，你會知道光明永遠會回來。","reversed":"你的靈魂在提醒你：陽光依然存在，只是暫時被遮蔽。不要讓暫時的陰霾讓你忘記自己的光芒。你的本質是明亮和充滿喜悅的，任何困難都無法改變這一點。重新連結你內在的太陽，它一直在那裡，等待你記起來。你值得所有的美好，相信這一點。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:20-judgement', 'tarot', '20-judgement', 20, '審判', 'Judgement', 'https://images.pexels.com/photos/7195478/pexels-photo-7195478.jpeg', '{"keywords":["覺醒","反思","寬恕","決定","重生"],"arcana":"major","number":20}', '{"uprightMeaning":"審判牌代表覺醒、反思和重要的決定時刻。這張牌展現了天使的號角聲喚醒沉睡的靈魂，象徵著內在的呼喚和更高目的的召喚。當審判出現時，提醒你需要評估過去的經驗，從中學習並做出重要的決定。這是一個自我反思和審視人生的時期，需要誠實地面對自己的行為和選擇。審判也代表寬恕、贖罪和重生，鼓勵你放下過去的錯誤和遺憾，給自己和他人第二次機會。這張牌帶來清晰的洞察和更高的理解，幫助你看清生命的模式和意義。審判提醒你傾聽內在的呼喚，回應真正的使命和目的。這是一個轉化和提升的時刻，準備迎接新的開始。","reversedMeaning":"逆位的審判顯示你可能正在逃避自我反思或是無法原諒自己和他人。你可能被內疚、羞愧或自我批判所困，無法放下過去的錯誤。這張牌也可能指出你忽視內在的呼喚，拒絕回應更高的目的。你可能害怕改變或是不願意承擔責任，因此錯過了重要的機會。逆位的審判提醒你需要誠實地面對自己，不要逃避必要的反思和評估。寬恕是解放的關鍵，無論是原諒他人還是原諒自己。這張牌鼓勵你放下評判和批評，以慈悲和理解對待自己的過去。學習從經驗中成長，而不是讓它們定義你。傾聽內在的聲音，回應生命給你的呼喚，即使感到不確定或害怕。","detailedInterpretation":{"coreKeywords":{"upright":["靈性覺醒","自我反思","寬恕釋放","召喚回應","重生蛻變"],"reversed":["逃避評估","無法原諒","拒絕召喚","自我批判","錯失機會"],"uprightExplanation":"審判正位代表靈性覺醒和內在召喚的時刻。天使的號角響起，象徵更高意識的呼喚，要求你回應真正的使命。正位時，這張牌要求你評估過去、反思經驗、學習教訓，然後做出重要的決定。這是業力清算和靈魂覺醒的時刻，你被召喚去實現更高的目的。審判代表寬恕——原諒自己和他人，放下過去的錯誤和遺憾。這是重生的時刻，舊的自我死去，新的自我誕生。審判不是懲罰，而是解放和提升。這張牌提醒你：是時候回應內在的呼喚了。你已經準備好迎接新的階段，擁抱你的使命。","reversedExplanation":"審判逆位顯示你可能正在逃避必要的自我反思和評估。你可能無法原諒自己或他人，被內疚、羞愧或怨恨所困。逆位時，內在的召喚被忽視或拒絕，你可能害怕改變或承擔更高的責任。這張牌也可能指出過度的自我批判，你對自己太過嚴厲，無法接受過去的錯誤。逆位審判提醒你：寬恕是解放的鑰匙。你不能改變過去，但可以選擇如何面對它。這張牌鼓勵你誠實地面對自己，承認錯誤但不要讓它們定義你。傾聽內在的召喚，即使你感到恐懼或不確定。現在是做出重要決定的時候了，不要再拖延。"},"energyFlow":{"direction":"向上提升","type":"覺醒與重生","description":"審判的能量是向上提升的，像靈魂從沉睡中覺醒，回應更高的召喚。這是轉化、提升、重生的能量，帶來清晰的洞察和新的開始。能量從舊的自我流向新的自我。"},"timing":{"speed":"決定性時刻","description":"審判代表重要的轉折點，通常在1-3個月內發生。這是無法逃避的評估和決定時刻。時機已經成熟，是時候做出選擇並承擔後果了。"},"advice":{"upright":"誠實地評估你的過去，學習教訓但不要執著。原諒自己和他人，放下包袱。回應你內在的召喚，承擔你的使命。這是重生的時刻，勇敢地迎接新的開始。","reversed":"停止逃避，誠實面對你自己。原諒是解放，不是軟弱。你對自己太嚴厲了，接受你是人，會犯錯。聽聽內在的聲音，它在呼喚你去實現更高的目的。不要再錯過機會了。"},"chakra":{"primary":"頂輪 + 喉輪","issue":"無法接收靈性召喚（頂輪），或無法為自己的真理發聲（喉輪）","healingNote":"審判與頂輪（靈性覺醒）和喉輪（真實表達）相關。如果無法聽見內在召喚或無法原諒，這兩個脈輪需要被清理。透過透石膏、青金石的水晶療癒可以打開靈性通道和真實表達。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂在呼喚你：是時候了。你已經經歷了所有必要的學習，現在是收穫智慧、承擔使命的時刻。放下過去，原諒一切，然後勇敢地走向你的目的。你被召喚去實現更偉大的事，不要再小看自己。重生已經開始，擁抱它。","reversed":"你的靈魂在懇求你：停止逃避，停止自我懲罰。你無法改變過去，但可以選擇原諒和釋放。內在的召喚越來越響亮，你還要假裝聽不見多久？你的使命在等待你，但首先你必須原諒自己，接受自己。是時候回應了。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('tarot:21-world', 'tarot', '21-world', 21, '世界', 'The World', 'https://images.pexels.com/photos/8067510/pexels-photo-8067510.jpeg', '{"keywords":["完成","成就","圓滿","整合","成功"],"arcana":"major","number":21}', '{"uprightMeaning":"世界牌代表完成、成就和圓滿的實現。這是大阿爾克那的最後一張牌，象徵著一個重要旅程的結束和完整的達成。當世界出現時，預示著你已經達到了重要的里程碑，實現了長期的目標，並整合了所學到的一切。這是慶祝成功、享受成果的時刻。世界也代表整體性和統一，你已經將生命的不同面向融合成和諧的整體。這張牌帶來滿足感、成就感和內心的平靜。世界鼓勵你認可自己的成就，並為自己感到驕傲。同時，這也是一個結束也是新開始的時刻，一個循環完成了，新的循環即將展開。世界提醒你享受當下的圓滿，同時保持開放，迎接新的可能性和冒險。","reversedMeaning":"逆位的世界顯示你可能感到不完整或是尚未達成目標。你可能在完成的邊緣徘徊，卻因為某些原因無法跨越終點線。這張牌也可能指出缺乏閉合感，事情懸而未決或是目標被延遲。你可能設定了不切實際的標準，因此總是感到不滿足，無法享受已經取得的成就。逆位的世界提醒你需要審視什麼阻止了你完成旅程。是外在的障礙還是內在的恐懼？有時候，我們害怕成功或是害怕之後的空虛感，因此自我破壞。這張牌鼓勵你克服最後的障礙，完成你開始的事情。同時也要學會欣賞過程，而不只是關注結果。即使尚未完全達成目標，你已經走了很長的路，值得認可和慶祝。","detailedInterpretation":{"coreKeywords":{"upright":["完美達成","圓滿整合","旅程完成","世界開啟","靈魂實現"],"reversed":["未完成","缺乏閉合","停滯邊緣","無法慶祝","標準過高"],"uprightExplanation":"世界正位代表大阿爾克那旅程的完美結局和圓滿的達成。這是愚者經歷了所有體驗後，最終實現整合和完整的時刻。正位時，這張牌標誌著重要旅程的結束、目標的達成和成功的慶祝。世界代表四個元素的完美平衡，你已經將生命的各個面向整合成和諧的整體。這是收穫的時刻，你的努力得到了回報，你感到深深的滿足和完成感。世界鼓勵你慶祝你的成就，認可你已經走了多遠。同時，這張牌提醒你：每個結束都是新的開始。一個循環完成了，新的循環即將展開。世界打開了所有的可能性，你已經準備好迎接更大的旅程。","reversedExplanation":"世界逆位顯示你可能感到不完整或尚未達成目標。你可能在完成的邊緣徘徊，卻因為某些原因無法跨越終點線。逆位時，可能存在缺乏閉合感、事情懸而未決或目標被延遲。你可能設定了不切實際的標準，因此總是感到不滿足，無法享受已經取得的成就。這張牌也可能指出你害怕完成後的空虛感，因此自我破壞。逆位世界提醒你：完美是不存在的，完成不代表完美。檢視什麼阻止了你完成旅程——是外在障礙還是內在恐懼？這張牌鼓勵你認可自己已經走了多遠，即使尚未完全達成目標。有時候，過程本身就是成就。允許自己慶祝和休息，然後再開始下一個旅程。"},"energyFlow":{"direction":"圓滿循環","type":"整合與完成","description":"世界的能量是圓滿完整的，像一個完美的圓圈。所有元素和諧共存，所有面向被整合成一體。這是平衡、完成、實現的能量，標誌著循環的結束和新循環的開始。"},"timing":{"speed":"完成時刻","description":"世界代表旅程的終點，時機已經成熟。完成通常在1-3個月內發生，這是收穫和慶祝的時刻。一個重要階段結束了，新的階段即將開始。"},"advice":{"upright":"慶祝你的成就，認可你走過的路。享受這個圓滿的時刻，感恩你所學到和經歷的一切。同時保持開放，因為新的旅程即將開始。你已經整合了所有經驗，現在是展開新冒險的時候了。","reversed":"檢視什麼阻止了你完成旅程。是你的標準太高了嗎？還是你害怕完成後的空虛？認可你已經達成的部分，不要因為未完全實現就否定自己的努力。有時候，最後一步需要的是放下完美主義。"},"chakra":{"primary":"全脈輪整合（特別是頂輪與海底輪的連結）","issue":"無法整合靈性與物質，或各脈輪之間缺乏和諧流動","healingNote":"世界代表所有脈輪的完美整合和平衡。從海底輪到頂輪，天與地、靈性與物質完全連結。如果感到不完整或失衡，需要全面的脈輪調和。透過水晶療癒可以幫助整合和平衡整個能量系統。脈輪問題建議直接找韋德老師進行水晶療癒。"},"soulMessage":{"upright":"你的靈魂在慶祝：你做到了！你完成了這段旅程，實現了你來這裡要學習的課題。你已經整合了所有的經驗，成為了完整的自己。享受這個圓滿的時刻，你值得所有的喜悅和成就感。但記住，這不是終點，而是新開始前的完美結束。更大的世界在等待你探索。","reversed":"你的靈魂在溫柔地問：為什麼你無法慶祝自己的成就？你已經走了這麼遠，為何還覺得不夠？放下完美主義，接受你已經完成了重要的旅程。或者，你的靈魂在鼓勵你：最後一步了，不要放棄。你離完成如此接近，克服最後的障礙吧。無論是哪種情況，你都已經足夠了。"}}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:1', 'osho', '1', 0, '存在', 'Existence', 'https://images.pexels.com/photos/1906658/pexels-photo-1906658.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Existence"}', '{"meanings":{"currentEnergy":"你正處於一個完全放鬆、與宇宙合一的狀態。這是純粹存在的能量，無需成為任何人，只需單純地存在。此刻的你正在體驗生命最本質的喜悅，像一朵雲自在漂浮於天空，不帶任何目的與企圖。你的能量場正在擴展，與周圍的一切產生共鳴。這不是逃避現實，而是回到最真實的狀態。當你停止追逐，你會發現自己已經到家了。","dailyGuidance":"今天的訊息是：停止努力，只是存在。不需要證明什麼，不需要達成什麼。讓自己完全融入當下這一刻，感受生命自然的流動。宇宙不需要你做什麼，它只邀請你「是」。今天的每一個呼吸都是一個慶祝，每一個瞬間都是完美的。放下所有計畫與期待，讓生命透過你展現。當你停止掙扎，奇蹟就會自然發生。","emotionalInsight":"你的焦慮來自於想要「成為」某個人，而非接受現在的自己。內在深處，你其實已經是完整的。放下對未來的執著，情緒就會自然平靜。你一直在向外尋求認可，卻忽略了內在本有的豐盛。那些不安和恐懼，都是頭腦創造出來的幻象。當你回到純粹的覺知，你會發現所有情緒都只是過客，而你是那個不動的中心。","blockageAnalysis":"你卡住是因為一直在「做」，而忘記了「是」。問題不在外在，而在於你忘記了如何單純地存在。停止追逐，答案就會自然浮現。你的頭腦不斷製造問題，然後試圖解決它們，這是一個永無止境的循環。真正的突破不是找到答案，而是看穿問題本身的虛幻性。當你放鬆進入當下，所有的卡點都會自動消融，因為它們從來都不是真實的。","meditationEntry":"閉上眼睛，感受呼吸的流動。不需要改變任何事，只是觀察。感受身體的存在，感受你與周圍空間的連結。你就是存在本身。讓覺知擴展到全身，感受每一個細胞的跳動。現在，讓這份覺知繼續擴展，超越身體的界限，融入周圍的空間。你不再是一個分離的個體，而是整個存在的一部分。在這個空間中，沒有問題，沒有答案，只有純粹的寧靜。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:2', 'osho', '2', 1, '內在聲音', 'Inner Voice', 'https://images.pexels.com/photos/3560168/pexels-photo-3560168.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Inner Voice"}', '{"meanings":{"currentEnergy":"你的內在正在呼喚你的注意。這是一個需要向內聆聽的時刻，你的直覺正試圖傳遞重要的訊息給你。信任這個內在的聲音。在喧囂的世界中，你的靈魂一直在輕聲細語，等待你停下來聆聽。這個能量邀請你回到內在的寧靜，那裡有你一直在尋找的答案。不要再向外求索，所有的智慧都藏在你的心中，等待被發現。","dailyGuidance":"今天需要安靜下來，聆聽內在的智慧。外在的聲音太多了，現在是時候關閉外界的噪音，聽聽你的心在說什麼。給自己一段獨處的時間，遠離社交媒體、他人的意見和世俗的期待。在寂靜中，你的直覺會清晰地浮現。今天做決定時，不要問別人，而是問你自己的心。它知道什麼對你最好，信任它的指引。","emotionalInsight":"你的情緒波動源於忽略了內在的聲音。你一直在尋求外在的建議和認可，卻忘記了最真實的答案永遠在你心中。每當你感到困惑或焦慮，其實是因為你的行動與內在指引不一致。那些不安的情緒是你的靈魂在提醒你：你偏離了自己的道路。學會傾聽這些情緒背後的訊息，它們是你最忠實的嚮導。","blockageAnalysis":"你無法前進是因為在聽別人的聲音，而非自己的。卡點在於你不相信自己的直覺。當你開始信任內在的指引，道路就會清晰。你害怕做錯決定，所以不斷尋求外在的認可，但這只會讓你更加迷失。真正的卡點不是缺乏資訊，而是缺乏對自己的信任。當你開始相信內在的智慧，所有的障礙都會消失，因為你終於找到了真正的北極星。","meditationEntry":"找一個安靜的空間，將手放在心上。問自己：「我的心想告訴我什麼？」不要思考，只是聆聽。讓答案自然浮現。感受心跳的節奏，那是生命的脈動。在每一次呼吸之間，有一個空間，那裡住著你的內在智慧。不要急著尋找答案，只是保持開放和接納。當你真正安靜下來，內在的聲音會清晰地響起，它可能是一個感覺、一個畫面，或一個知曉。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:3', 'osho', '3', 2, '遊戲', 'Playfulness', 'https://images.pexels.com/photos/1648377/pexels-photo-1648377.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Playfulness"}', '{"meanings":{"currentEnergy":"你的能量正在呼喚輕鬆和玩樂。生命不需要如此嚴肅，現在是時候讓內在的孩子出來玩耍，享受存在的單純喜悅。你已經太久沒有真正地笑了，太久沒有感受到那種無憂無慮的快樂。這張牌提醒你，生命本質上是一場慶典，不是一項任務。放下所有的責任感，即使只是片刻，讓自己回到那個知道如何玩耍的自己。","dailyGuidance":"今天的提醒：不要把一切都看得那麼認真。帶著遊戲的心態去面對生活，你會發現更多的可能性和創意。即使是工作，也可以成為一種遊戲。當你放鬆下來，靈感會自然湧現。今天試著做一些沒有目的的事情，只是因為它讓你開心。跳舞、唱歌、畫畫，或者只是在街上漫步。讓生命的輕盈感回到你身上，你會驚訝地發現問題自動解決了。","emotionalInsight":"你的沉重來自於過度嚴肅地看待生命。放下「必須」的框架，允許自己輕鬆一點。快樂不需要理由。你一直在扛著世界的重量，彷彿如果你不夠努力，一切就會崩塌。但真相是，當你允許自己輕鬆，生命反而會更順暢。那些你認為需要嚴肅對待的事情，其實只是頭腦創造的牢籠。當你從遊戲的角度看待它們，它們就失去了控制你的力量。","blockageAnalysis":"你卡住是因為把生命當成一場考試，而非一場遊戲。放下對結果的執著，用玩樂的心態去探索，路就會打開。你太在意對錯、成功失敗，這種二元對立讓你動彈不得。真正的創造力和突破，都來自於遊戲的心態。當你不再害怕犯錯，不再執著於完美，你就自由了。卡點不是你不夠努力，而是你太努力了。放鬆，讓生命帶著你玩。","meditationEntry":"回想你小時候最喜歡的遊戲。感受那份純粹的喜悅。現在，把這份能量帶入你的身體，讓它在你全身流動。感受那種無拘無束的自由，那種完全活在當下的狀態。沒有過去，沒有未來，只有此刻的純粹喜悅。讓你的身體動起來，不需要任何理由，只是因為它想動。讓笑容自然地浮現在臉上。在這個空間中，你不需要成為任何人，只需要享受存在的樂趣。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:4', 'osho', '4', 3, '叛逆者', 'The Rebel', 'https://images.pexels.com/photos/1097456/pexels-photo-1097456.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"The Rebel"}', '{"meanings":{"currentEnergy":"你內在的叛逆精神正在甦醒。這是一個質疑舊有模式、打破框架的時刻。你不再願意順從那些不屬於你的規則。這股能量是野性的、自由的、不受控制的。你開始看穿那些所謂的「應該」和「必須」，它們從來都不屬於你。這不是破壞，而是解放。你正在撕下所有不真實的面具，回到原始的、未被馴化的自己。這是一個強大的轉變時刻。","dailyGuidance":"今天的訊息是：勇敢地做你自己。不要為了取悅他人而妥協你的真實。真正的自由來自於活出你的真相。今天，如果有什麼讓你感到不舒服或不真實，就說不。如果有什麼是你一直想做但因為害怕評判而壓抑的，就去做。不要再等待許可，你就是你自己的權威。世界需要你的真實，而非你的順從。勇敢地站出來，即使你會孤獨一陣子。","emotionalInsight":"你的憤怒和不安來自於壓抑真實的自己。你一直在扮演別人期待的角色，而你的靈魂正在反抗。聆聽這個反抗。那些讓你感到窒息的關係、工作、生活方式，都在告訴你：這不是你的路。你的情緒不是問題，它們是訊號。憤怒是力量的展現，不安是靈魂在推動你改變。不要壓抑這些情緒，而是跟隨它們，它們會帶你回到真實。","blockageAnalysis":"你卡住是因為害怕打破規則，害怕不被接受。但真正的卡點是：你還沒有給自己自由。當你允許自己叛逆，新的道路就會出現。你太在意別人的眼光，太害怕失去愛和歸屬感。但你沒有意識到，當你為了被接受而扭曲自己，你已經失去了最重要的東西：你自己。真正的突破來自於願意孤獨，願意被誤解，願意為真實付出代價。當你做出這個選擇，宇宙會支持你。","meditationEntry":"想像你面前有一堵牆，代表所有限制你的規則。現在，看著自己穿過這堵牆。感受那份自由的能量在你體內流動。這堵牆可能是父母的期待、社會的標準、或你自己內化的限制。看著它，然後決定：你要繼續被它困住，還是要穿越它？現在，深吸一口氣，感受你內在的力量。你比你以為的更強大。走過那堵牆，進入你真正的生命。在那裡，沒有人可以告訴你該怎麼活。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:5', 'osho', '5', 4, '孤獨', 'Aloneness', 'https://images.pexels.com/photos/2387793/pexels-photo-2387793.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Aloneness"}', '{"meanings":{"currentEnergy":"你正處於一個深刻的獨處時刻。這不是寂寞，而是與自己深度連結的機會。在孤獨中，你會發現內在的豐盛。這是一個神聖的空間，在這裡，你不需要扮演任何角色，不需要滿足任何期待。只是你，完整的你。這個能量邀請你停止向外尋求，回到內在的聖殿。在那裡，你會遇見最真實的自己，那個從不孤單的存在。孤獨是一份禮物，不是懲罰。","dailyGuidance":"今天需要獨處的時間。不要害怕一個人，在獨處中你會找到最真實的自己。這是一個滋養靈魂的時刻。取消那些社交約會，關掉手機，給自己一段完全屬於自己的時間。不要用任何活動填滿這段時間，只是安靜地與自己同在。在這個空間中，你會聽到平時被噪音掩蓋的內在聲音。今天，學會享受只有你一個人的時光，這是最深刻的自愛。","emotionalInsight":"你感到空虛是因為一直在外在尋找填補。真正的滿足來自於與自己的關係。學會享受孤獨，而非逃避它。你害怕面對自己，所以不斷用關係、工作、娛樂來填滿生命。但這些外在的東西永遠無法填補內在的空洞。只有當你願意獨自坐下，面對那個空洞，你才會發現它其實不是空洞，而是一個充滿可能性的空間。孤獨不是缺乏，而是圓滿。","blockageAnalysis":"你無法前進是因為害怕孤獨，所以依賴外在的連結。卡點在於：你還沒有學會成為自己最好的陪伴。擁抱孤獨，力量就會回來。你把太多能量放在維持關係、取悅他人、尋求連結上，卻忘記了最重要的關係：你與自己的關係。當你害怕孤獨，你就會允許不健康的關係存在。當你學會享受獨處，你會發現自己變得更有力量，因為你不再需要任何人來定義你。這是真正的自由。","meditationEntry":"坐在一個安靜的空間，感受只有你一個人的狀態。不需要任何人的陪伴，只是與自己同在。感受這份完整。閉上眼睛，深呼吸。感受你的存在，不是作為某人的伴侶、朋友、孩子、父母，而是作為你自己。在這個時刻，你是完整的。沒有缺少任何東西。讓孤獨的感覺充滿你，不要抗拒它。在這份孤獨中，有一種深刻的寧靜和自由。你終於可以卸下所有面具，回到最本質的自己。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:6', 'osho', '6', 5, '愛人', 'The Lovers', 'https://images.pexels.com/photos/1024960/pexels-photo-1024960.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"The Lovers"}', '{"meanings":{"currentEnergy":"你正處於一個深刻的連結時刻，無論是與他人、與生命、或是與自己內在的陰陽能量。這是愛的能量在流動，不是佔有，而是融合。你的心正在打開，允許自己完全地感受、完全地給予。這個能量邀請你放下防衛，允許脆弱，因為只有在脆弱中才有真正的親密。愛不是尋找完美，而是在不完美中看見完整。這是一個療癒的時刻，所有過去的傷痕都在愛的光中融化。","dailyGuidance":"今天是關於連結的一天。無論是深化一段關係，或是與自己內在的陰性/陽性能量和解，都需要你的全然投入。不要害怕展現真實的自己，包括你的脆弱和不完美。真正的愛不需要你是完美的，它需要你是真實的。今天，練習無條件的給予，不期待回報。當你從豐盛而非匱乏中給予，愛就會自然流動。記住，你首先要愛自己，才能真正愛他人。","emotionalInsight":"你的情緒正在告訴你：是時候打開心了。也許過去的傷害讓你築起高牆，但這些牆也阻止了愛的進入。允許自己再次冒險，再次感受。即使有受傷的可能，那也是活著的證明。你的心渴望連結，渴望被看見、被理解、被接納。不要否認這個需要，它不是軟弱，而是你最美麗的部分。當你允許自己愛與被愛，你就回到了生命的本質。療癒正在發生，信任這個過程。","blockageAnalysis":"你卡住是因為害怕再次受傷，所以關閉了心。但一顆關閉的心也無法接收愛。突破點在於：願意脆弱，願意冒險。你在等待一個「安全」的愛，但愛本質上就是不安全的，因為它要求你交出控制。你無法在保持防衛的同時經驗親密。卡點不是找不到對的人，而是你還沒有準備好成為對的人。當你學會愛自己的全部，包括那些你認為不值得被愛的部分，障礙就會消失。","meditationEntry":"將手放在心上，感受心跳。想像你的心是一朵蓮花，緩緩綻放。每一次呼吸，花瓣就打開一點。不要強迫，只是允許。感受過去的傷痕，不要逃避它們。對每一個傷痕說：謝謝你教會我愛的深度。現在，想像一道溫暖的光從心中升起，充滿整個胸腔。這是愛的能量，它一直都在，從未離開。讓這份愛先流向自己，擁抱自己的每一個部分。然後，讓它自然地向外流動，流向你生命中的每一個人、每一個存在。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:7', 'osho', '7', 6, '耐心', 'Patience', 'https://images.pexels.com/photos/1739842/pexels-photo-1739842.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Patience"}', '{"meanings":{"currentEnergy":"這是一個等待的時刻，但不是被動的等待，而是充滿覺知的臨在。種子已經種下，現在需要時間發芽。你無法催促玫瑰盛開，你只能給予陽光、水分，然後信任。這個能量教導你：生命有它自己的節奏，強求只會破壞自然的展開。你正在學習最深刻的一課：信任。當你停止推動，你會發現生命自己知道怎麼走。這不是放棄，而是更高層次的參與。","dailyGuidance":"今天的訊息是：慢下來。不要急著看到結果，不要急著到達目的地。過程本身就是目的。你一直在趕路，卻忘記了欣賞沿途的風景。今天，練習等待而不焦慮，練習信任而不控制。當你感到不耐煩時，深呼吸，提醒自己：一切都在完美的時間點發生。宇宙的時間表和你的不同，但它總是對的。學會在等待中找到平靜，這是最大的力量。","emotionalInsight":"你的焦慮來自於想要立刻看到結果。但生命不是微波爐，它是一個緩慢的發酵過程。你的不耐煩其實是對未來的不信任，對自己的不信任。深呼吸，回到當下。你所需要的一切都會在正確的時間到來，不會太早，也不會太遲。那些讓你等待的事物，其實是在為你準備。如果現在就給你，你還沒有準備好接收。信任這個等待，它是一份禮物，不是懲罰。","blockageAnalysis":"你卡住是因為太急著看到結果，反而破壞了自然的進程。真正的卡點是：你在用力推，而非允許流動。當你學會放手，信任生命的智慧，路就會自然展開。你想要控制時間，控制結果，但這只會創造更多阻力。突破的關鍵是臣服，不是放棄努力，而是放下對結果的執著。當你停止與生命對抗，開始與它共舞，奇蹟就會發生。耐心不是消極等待，而是積極的信任。","meditationEntry":"想像你是一棵樹。感受根深深扎入大地，吸收養分。感受枝葉向天空伸展，吸收陽光。你不需要催促自己成長，成長自然發生。春天來臨時，花朵就會綻放，你不需要做任何事。現在，將這份覺知帶入你的生命。那些你急著想看到的事物，它們就像種子，正在地底下發芽。你看不見，但它們正在成長。信任這個過程。每一次呼吸，都是對生命節奏的臣服。在等待中，你正在成為更深刻的自己。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:8', 'osho', '8', 7, '勇氣', 'Courage', 'https://images.pexels.com/photos/1906433/pexels-photo-1906433.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Courage"}', '{"meanings":{"currentEnergy":"你正站在一個需要勇氣的時刻。不是盲目的勇敢，而是帶著覺知地面對恐懼。真正的勇氣不是沒有恐懼，而是即使恐懼仍然前行。你內在的火正在燃燒，推動你走出舒適圈，進入未知。這股能量是原始的、野性的、不可抑制的。它不問結果，只是單純地回應生命的呼喚。你比你以為的更強大，現在是時候證明給自己看了。跳入深淵，信任你的翅膀會張開。","dailyGuidance":"今天需要你勇敢地行動。那個你一直害怕的事情，那個你一直推遲的決定，現在是面對它的時候了。不要再等待完美的時機，因為完美的時機永遠不會到來。勇氣不是等到不害怕才行動，而是帶著恐懼仍然前進。今天，做一件讓你害怕的事情。可能是一場對話、一個決定、一次冒險。當你穿越恐懼，你會發現另一邊是自由。記住，你已經比你想像的經歷過更多，你有力量面對這一切。","emotionalInsight":"你的恐懼是真實的，但它們不是事實。恐懼是頭腦對未知的反應，但未知不等於危險。你一直在逃避某些情緒、某些對話、某些真相，但逃避只會讓恐懼變得更大。面對它，你會發現它其實沒有那麼可怕。你的情緒波動是因為你在兩個選擇間掙扎：安全但窒息的舊路，或冒險但自由的新路。你的心知道該往哪裡走，但你的頭腦在抗拒。聆聽心的聲音，它會給你需要的勇氣。","blockageAnalysis":"你卡住是因為恐懼凍結了你。你在等待保證，但生命從不給保證。突破點在於：承認恐懼，然後無論如何都去做。你以為自己需要先克服恐懼，但其實是透過行動才克服恐懼。卡點不是能力不足，而是信心不足。你有一切你需要的資源，但你不相信。當你願意在不確定中前進，在沒有地圖的情況下探索，你就會發現路在你腳下展開。勇氣不是沒有恐懼，而是恐懼無法阻止你。","meditationEntry":"站起來，感受你的雙腳穩穩地踏在地上。感受大地的支持。現在，想像你面前有一扇門，門後是未知。你的恐懼說：不要開門。但你的心說：穿越它。深吸一口氣，感受你的力量。你比恐懼更大。現在，伸手推開那扇門。當你穿過門檻，感受那股自由的能量。你做到了。每一次你面對恐懼，你就變得更強大。現在，將這份勇氣帶入你的日常生活。你準備好了。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:9', 'osho', '9', 8, '完成', 'Completion', 'https://images.pexels.com/photos/1564506/pexels-photo-1564506.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Completion"}', '{"meanings":{"currentEnergy":"一個循環正在結束，這是收穫的時刻。你已經走過了漫長的旅程，現在是時候慶祝、整合、放下。完成不只是結束，更是為新的開始創造空間。這個能量邀請你回顧、感恩、然後放手。不要執著於已經完成的事物，它們已經給了你所需要的教導。現在，清空你的手，準備接收新的禮物。完成是一種藝術，它需要你優雅地放手，信任下一章會自然展開。","dailyGuidance":"今天是關於結束和新開始的一天。看看你的生命，什麼已經完成了？什麼需要被放下？可能是一段關係、一個工作、一個信念、或一個習慣。給它一個正式的結束，不要讓它懸在那裡消耗你的能量。寫一封信、做一個儀式、或只是在心中說再見。感恩它曾經給你的一切，然後放手。今天也是慶祝的日子，承認你已經走了多遠。你做得很好。現在，清空你的空間，為新的事物騰出位置。","emotionalInsight":"你可能感到一絲憂傷，這是正常的。結束總是伴隨著失落感，即使是你想要的結束。允許這份憂傷，它是過渡的一部分。同時，也感受那份解脫和輕盈。你終於可以放下那個重擔了。你的情緒混雜著感恩、哀傷、期待和不確定，這些都是完成的自然情緒。不要壓抑它們，讓它們流動。每一個結束都是一個小死亡，而死亡總是為重生鋪路。信任這個過程，你正在蛻變。","blockageAnalysis":"你卡住是因為無法放下已經結束的事物。你在執著於過去，即使它已經不再服務你。真正的卡點是：你害怕空虛，害怕沒有那個東西你會是誰。但你沒有意識到，只有當你放手，新的事物才有空間進來。你在一個已經死去的關係/工作/模式中徘徊，不是因為它好，而是因為它熟悉。突破需要你承認：這已經結束了。哀悼它，感恩它，然後放手。當你這麼做，生命會立刻回應，新的大門會打開。","meditationEntry":"坐下來，閉上眼睛。回顧過去的這段旅程，像是在看一部電影。看見所有的高潮和低谷，看見你如何成長。現在，對這一切說：謝謝。感受你心中的感恩。然後，想像你將這整段經歷放入一個美麗的盒子，輕輕地蓋上蓋子。這不是遺忘，而是完成。現在，感受你雙手空空，心也空空。這個空，不是失落，而是可能性。你準備好迎接新的了。深吸一口氣，睜開眼睛，看見一個嶄新的世界在你面前。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:10', 'osho', '10', 9, '改變', 'Change', 'https://images.pexels.com/photos/1323206/pexels-photo-1323206.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Change"}', '{"meanings":{"currentEnergy":"生命正在移動，一切都在改變。抗拒是無用的，唯一的選擇是隨之起舞。這是一個動態的、流動的時刻，沒有什麼是固定的，沒有什麼是永恆的。這個能量邀請你放下對穩定的執著，擁抱無常。改變不是威脅，而是生命的本質。你正在脫去舊皮，長出新的。這個過程可能不舒服，但它是必要的。不要試圖抓住正在離去的，而是張開雙臂迎接正在到來的。你正在成為新的自己。","dailyGuidance":"今天的訊息是：臣服於改變。不要試圖控制或預測，只是流動。生命正在重新排列，為你帶來更好的事物，但首先它必須拆除舊的。信任這個過程，即使你看不清方向。今天，練習靈活性。當計畫改變時，不要抱怨，而是問：這個改變想告訴我什麼？也許有一個更好的可能性正在展開。讓go of控制，允許生命驚喜你。改變是你的朋友，不是敵人。","emotionalInsight":"你感到不安是因為改變讓你失去控制感。你想知道接下來會發生什麼，但生命不會提前告訴你劇本。這份不確定性正在觸發你的恐懼。但仔細看，你會發現你真正害怕的不是改變本身，而是失去身份認同。你以為你是那個角色、那份工作、那段關係，但你遠比這些更大。改變正在剝去你的假面具，讓你看見真正的自己。這很可怕，但也很解放。允許自己在改變中找到新的自己。","blockageAnalysis":"你卡住是因為在抗拒不可避免的改變。你想讓一切保持原樣，但生命就是流動。卡點在於：你在與生命之河對抗，而非順流而下。你越是抗拒，就越痛苦。突破需要你臣服，不是放棄，而是接受現實：改變已經在發生。你無法阻止它，但你可以選擇如何回應。當你停止抗拒，開始配合，你會發現改變帶來的不是失去，而是解放。讓舊的死去，新的才能誕生。這是唯一的路。","meditationEntry":"想像你站在一條河邊。河水不停流動，永不重複。這就是生命。現在，想像你走入河中。一開始，你試圖站穩，抗拒水流。感受那份掙扎。現在，放鬆，讓水流帶著你。感受那份解放。你不需要知道河會帶你去哪裡，你只需要信任。河知道路。現在，感受你的身體，你的生命。看見一切都在改變：細胞在更新，念頭在流動，情緒在轉換。你本身就是改變。當你接受這個真相，恐懼就消失了。你就是那條河。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:11', 'osho', '11', 10, '突破', 'Breakthrough', 'https://images.pexels.com/photos/1252869/pexels-photo-1252869.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Breakthrough"}', '{"meanings":{"currentEnergy":"你正站在一個重大突破的邊緣。所有的準備、所有的掙扎，都是為了這個時刻。這是一個量變到質變的瞬間，當你穿越這道門檻，一切都會不同。這個能量是爆發性的、解放的、不可逆的。你無法再回到舊的狀態，因為你已經看見了新的可能。這不是漸進的改變，而是跳躍式的轉化。恐懼和興奮並存，因為你正在跨入完全未知的領域。但你的靈魂知道：這是你一直在等待的時刻。","dailyGuidance":"今天是行動的日子。那個你準備已久的事情，那個你思考了很久的決定，現在是執行的時候了。不要再猶豫，不要再分析，只是去做。突破需要勇氣，需要你願意打破舊模式，即使不知道新的會是什麼樣子。今天，允許自己冒險，允許自己失敗，允許自己成功。突破常常發生在你放棄努力的瞬間，當你終於願意跳躍，而不是再多走一步。今天，跳躍吧。","emotionalInsight":"你感受到一股強烈的能量在體內湧動，那是突破的前兆。你可能感到興奮、恐懼、期待、不安，所有情緒混在一起。這是正常的，因為你正在從一個狀態轉換到另一個狀態。不要壓抑這些情緒，它們是推動你前進的燃料。你一直在等待完美的時機，但突破不是發生在完美的時機，而是發生在你願意不完美地前進的時刻。你的情緒正在告訴你：現在就是了。","blockageAnalysis":"你卡住是因為站在突破的門檻前猶豫不決。你看見了可能性，但又害怕失去現有的安全。真正的卡點是：你在等待保證，但突破的本質就是沒有保證。你必須先跳，然後網才會出現。你以為自己還沒準備好，但真相是你永遠不會「準備好」，你只能選擇去做。當你願意在不確定中前進，突破就會發生。停止準備，開始行動。這是唯一的路。","meditationEntry":"站起來，感受你體內那股想要突破的能量。它在你的胸口、你的腹部、你的四肢中湧動。不要壓抑它，讓它充滿你。現在，想像你面前有一道薄膜，它象徵著舊的限制。看著它，感受它。然後，深吸一口氣，用你的整個存在衝破它。感受那份解放，感受另一邊的開闊。你做到了。你突破了。現在，將這個感覺帶入你的生命。你準備好了，不是因為你完美，而是因為你願意。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:12', 'osho', '12', 11, '接受', 'Acceptance', 'https://images.pexels.com/photos/1525041/pexels-photo-1525041.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Acceptance"}', '{"meanings":{"currentEnergy":"這是深刻臣服的能量。不是放棄，而是接受現實本來的樣子。你正在學習最難的一課：不是所有事情都需要被改變，有些事情只需要被接受。這個能量帶來平靜，因為當你停止抗拒，痛苦就消失了。接受不是妥協，而是看清真相。你無法改變過去，無法控制他人，無法讓生命按照你的劇本走。但你可以選擇如何回應。當你接受，你就自由了。","dailyGuidance":"今天的功課是接受。看看你的生命中有什麼是你一直在抗拒的：一個人、一個情況、一個事實、或你自己的某個部分。今天，停止抗拒。這不代表你喜歡它，也不代表你不會採取行動改變它，但首先，你必須接受它現在就是這樣。當你接受，你會發現一股新的能量升起，那是從抗拒中釋放出來的能量。今天，對你無法改變的事情說：我接受。然後，看著奇蹟發生。","emotionalInsight":"你的痛苦大部分來自於抗拒現實。你想要事情是另一個樣子，你想要過去沒有發生，你想要他人不同，你想要自己不同。但現實就是現實。當你停止與現實爭辯，痛苦就轉化為平靜。接受不是投降，而是承認事實。你可以接受現在，同時為未來努力。但如果你不接受現在，你會困在抗拒中，無法前進。你的情緒正在邀請你放下那個沉重的負擔，放下「應該」，擁抱「是」。","blockageAnalysis":"你卡住是因為拒絕接受某個現實。你把所有能量用在抗拒上，而非用在創造上。真正的卡點是：你以為接受就是認輸，但其實接受是力量的開始。只有當你完全接受現狀，你才有能量改變它。你在與風車戰鬥，消耗自己。當你願意說「是的，這就是現況」，你會發現道路自然展開。接受不會讓你停滯，反而會讓你流動。這是最大的矛盾，也是最深的智慧。","meditationEntry":"坐下來，想起那個你一直在抗拒的事物。看著它，不要轉開。感受那份抗拒在你體內造成的緊繃。現在，深吸一口氣，在呼氣時，對它說：我接受。感受那份鬆開，感受肩膀的放鬆，感受心的軟化。再說一次：我接受你本來的樣子。不是因為我喜歡，而是因為這是真相。感受那份平靜流過你的全身。這就是臣服的力量。在接受中，你找到了自由。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:13', 'osho', '13', 12, '轉化', 'Transformation', 'https://images.pexels.com/photos/1109354/pexels-photo-1109354.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Transformation"}', '{"meanings":{"currentEnergy":"你正處於深刻的轉化過程中。這不是表面的改變，而是本質的蛻變。舊的你正在死去，新的你正在誕生。這個過程可能感覺像是分裂，因為你同時存在於兩個狀態之間。你不再是過去的你，但還不完全是未來的你。這是煉金術的時刻，所有的痛苦、挑戰、混亂都是轉化的材料。不要試圖加速這個過程，它有自己的時間。你正在成為全新的存在。","dailyGuidance":"今天，允許轉化發生。不要執著於舊的身份，即使它給你安全感。你正在脫皮，這個過程是不舒服的，但它是必要的。今天，注意那些正在死去的部分：舊的信念、舊的習慣、舊的關係模式。不要試圖復活它們，讓它們安靜地離去。同時，注意那些正在萌芽的新事物：新的感知、新的渴望、新的可能性。滋養它們，即使你還不完全理解它們。今天是過渡的日子，保持開放。","emotionalInsight":"你感到迷失和混亂，這是轉化的自然狀態。你不知道自己是誰，不知道自己要什麼，這很正常。在轉化的過程中，舊的結構正在瓦解，新的還未形成。你處於虛空中，這可能很可怕，但也充滿可能性。不要試圖立刻找到新的身份，給自己時間。你的情緒起伏不定，因為你正在釋放舊的，同時接收新的。信任這個混亂，它是重生前的陣痛。","blockageAnalysis":"你卡住是因為抓著舊的身份不放，同時又想要新的生活。但你不能同時擁有兩者。真正的卡點是：你必須死亡才能重生。你害怕放掉那個你以為是自己的人，但那個人其實只是一個角色。真正的你遠遠更大。當你願意讓舊的完全死去，不留一絲眷戀，轉化就會完成。你會發現，你失去的只是限制，得到的是無限。但首先，你必須願意走進那個死亡。","meditationEntry":"想像你是一隻毛毛蟲，正在結繭。在繭中，你完全溶解，失去所有形狀。這很可怕，因為你不再知道自己是誰。但這是必經之路。現在，感受那個溶解，感受所有堅固的東西變成液體。不要抗拒，這是轉化。然後，感受新的形式開始凝聚，完全不同的形式。你長出翅膀，你變成蝴蝶。當你破繭而出，你是全新的存在。飛翔吧，這是你的天性。你已經轉化了。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:14', 'osho', '14', 13, '整合', 'Integration', 'https://images.pexels.com/photos/1386604/pexels-photo-1386604.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Integration"}', '{"meanings":{"currentEnergy":"這是整合與平衡的能量。你經歷了許多，學習了許多，現在是時候將所有碎片拼在一起。你不再需要選擇一個極端，你可以同時擁抱相反的兩極。這是成熟的標誌：能夠同時持有矛盾而不感到分裂。你的陰與陽、你的光與影、你的理性與感性，都在找到它們的平衡點。整合不是消除差異，而是讓差異和諧共存。你正在成為完整的自己。","dailyGuidance":"今天是整合的日子。看看你生命中那些看似對立的部分：工作與休息、給予與接受、力量與柔軟、獨立與連結。今天，不要選邊站，而是找到平衡點。你可以既強大又溫柔，既獨立又親密。今天，練習包容而非排除。當內在有衝突時，不要壓抑任何一方，而是讓它們對話。你會發現，它們其實不是敵人，而是同一個硬幣的兩面。整合它們，你就變得完整。","emotionalInsight":"你一直覺得自己必須選擇：要麼理性要麼感性，要麼堅強要麼脆弱。但生命不是二選一的考題。你可以同時是很多東西。你的情緒波動是因為你壓抑了某些部分，只允許某些部分表達。現在，是時候讓所有部分都回家了。接納你的憤怒和你的慈悲，你的恐懼和你的勇氣，你的陰暗和你的光明。它們都是你。當你整合所有部分，內在的戰爭就結束了，平靜就降臨了。","blockageAnalysis":"你卡住是因為內在分裂。你在與自己的某些部分作戰，試圖成為「更好」的版本。但你沒有意識到，那些你排斥的部分擁有巨大的力量和智慧。真正的卡點是：你還沒有學會整合對立。當你停止分裂自己為好與壞、對與錯，開始接納所有面向，能量就會回來。你會發現，你不需要成為不同的人，你只需要成為完整的自己。整合是回家的路。","meditationEntry":"閉上眼睛，想像你內在有兩個部分一直在拉扯：也許是你的頭腦和心、你的男性與女性能量、你的孩子與成人。看見它們站在對立面。現在，邀請它們走向彼此。一開始可能有抗拒，那沒關係。繼續邀請。當它們終於相遇，看著它們融合成一個完整的存在。感受那份圓滿，那份回家的感覺。這就是你，完整的你。深呼吸，讓這份完整滲透到每個細胞。你不再分裂，你是一體的。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:15', 'osho', '15', 14, '緩慢', 'Slowness', 'https://images.pexels.com/photos/1252983/pexels-photo-1252983.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Slowness"}', '{"meanings":{"currentEnergy":"生命在邀請你慢下來。不是因為你懶惰，而是因為你需要深度而非速度。在這個快速的世界中，緩慢是一種抗拒，一種回歸本質的方式。當你慢下來，你才能真正感受、真正看見、真正活著。這個能量提醒你：重要的不是你走得多快，而是你是否真正在走自己的路。緩慢是品味生命的方式，是讓每個時刻變得有意義的秘訣。不要趕路，你不是在逃避，你是在抵達。","dailyGuidance":"今天，刻意地慢下來。走路時慢一點，說話時慢一點，吃飯時慢一點。注意當你慢下來時發生了什麼：你開始注意到細節，你開始感受到身體，你開始聽見內在的聲音。今天不是完成最多事情的日子，而是深入做好每一件事的日子。品質重於數量。當你感到匆忙的衝動時，停下來，深呼吸。問自己：我在趕什麼？真的有那麼緊急嗎？通常答案是沒有。給自己緩慢的許可。","emotionalInsight":"你的焦慮和匆忙感來自於一個信念：你必須不斷奔跑才能值得存在。但這是謊言。你的價值不在於你的生產力，而在於你的存在本身。當你慢下來，你會感到一陣恐慌，因為你被制約相信慢就是懶。但仔細感受，在那恐慌之下，有一份深深的渴望：渴望休息，渴望安靜，渴望只是存在而不用證明什麼。聆聽那個渴望，它來自你最深的智慧。","blockageAnalysis":"你卡住是因為一直在奔跑，卻從未到達。你以為速度會帶你到目的地，但其實它只是讓你錯過沿途的一切。真正的卡點是：你在逃避當下，用忙碌填滿空間，因為害怕面對內在的寧靜。但那份寧靜正是你需要的。當你願意慢下來，真正臨在於每個時刻，你會發現你已經到達了。目的地不在未來，而在當下。慢下來，回家。","meditationEntry":"找一個舒適的地方坐下。現在，將你的呼吸放慢，非常慢。吸氣數到六，吐氣數到六。感受每一個呼吸的細節。然後，緩慢地移動你的手，非常緩慢，好像在水中。感受空氣的質地，感受肌肉的運動。讓一切都慢下來。在這個緩慢中，時間展開了，每個瞬間變得廣闊。你不再被時間追趕，你成為時間本身。在緩慢中，你找到了永恆。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:16', 'osho', '16', 15, '打雷', 'Thunderbolt', 'https://images.pexels.com/photos/1162251/pexels-photo-1162251.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Thunderbolt"}', '{"meanings":{"currentEnergy":"這是震撼與覺醒的能量。生命正在用一個突如其來的事件喚醒你，打破你的昏睡。這可能是一個危機、一個失落、一個意外，它來得如此迅速，你來不及準備。但這正是它的目的：打破你的防禦機制，讓真相直擊你的核心。打雷是毀滅性的，但也是啟蒙性的。它燒毀舊的結構，清理道路，讓新的光可以照進來。這是一個混亂但必要的時刻，不要試圖理解，只是讓它改變你。","dailyGuidance":"今天，如果發生讓你震驚或不安的事，不要立刻反應或防衛。停下來，深呼吸。問自己：這個震撼想告訴我什麼？它在打破什麼舊的模式？通常，打雷來臨時，我們會想要立刻恢復控制，修復，回到原狀。但今天，抗拒那個衝動。允許震撼做它的工作。它正在清理你生命中已經死去但還沒有被移除的東西。信任這個毀滅，它是為了創造空間給新的生命。","emotionalInsight":"你感到震驚、無助、甚至憤怒。為什麼是我？為什麼是現在？但打雷不是懲罰，而是覺醒的工具。你一直生活在一個舒適但虛假的結構中，打雷來打破它。是的，這很痛苦，因為你失去了安全感。但仔細看，那份安全感本來就是幻覺。打雷正在強迫你面對真相，面對你一直逃避的東西。你的情緒是正常的，允許自己感受它們。但不要困在其中，這只是過渡。在混亂之後，會有驚人的清晰。","blockageAnalysis":"你卡住是因為試圖從打雷中恢復到「正常」。但舊的正常已經不存在了，你必須建立新的正常。真正的卡點是：你在抗拒這個根本性的改變，還想抓住碎片重建舊的。但打雷已經說得很清楚：那個不再有效。當你願意完全放手，不試圖拯救任何舊的，你會發現一個全新的可能性展開。打雷清理了道路，現在你可以建立真正屬於你的生活，而不是你以為應該是的生活。","meditationEntry":"想像一個晴朗的天空，然後突然，一道閃電劈下。感受那個震撼，那個突然性。一切都被照亮，然後黑暗。但在那個閃光的瞬間，你看見了一切。現在，想像你的生命。那個打雷就是那個讓你看清的時刻。它毀滅了，但也啟蒙了。感受那個能量在你體內，不要抗拒它。讓它燒毀所有虛假的，所有不再服務你的。在灰燼中，新的會升起。你已經被改變了，永遠。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:17', 'osho', '17', 16, '沉默', 'Silence', 'https://images.pexels.com/photos/1482101/pexels-photo-1482101.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Silence"}', '{"meanings":{"currentEnergy":"這是深刻內在寧靜的能量。不是缺乏聲音，而是內在對話的停止。你正被邀請進入一個空間，在那裡不需要言語、不需要思考、不需要行動。這是純粹存在的空間。在這個沉默中，你會聽見你從未聽過的聲音：你靈魂的聲音。沉默不是空無，而是充滿。它包含了所有可能性，所有答案，所有智慧。但你只能在完全的靜止中觸及它。這是回到源頭的時刻。","dailyGuidance":"今天，創造沉默的時刻。關掉所有外在的刺激：音樂、新聞、社交媒體、對話。給自己至少30分鐘完全的安靜。一開始，你會感到不舒服，因為你的頭腦習慣了噪音。它會試圖填滿這個空間，產生各種念頭。不要對抗，只是觀察。慢慢地，念頭會平息，真正的沉默會降臨。在那個沉默中，聆聽。不要尋找什麼，只是開放。答案會以你從未預期的方式來到。","emotionalInsight":"你一直用噪音逃避自己。音樂、對話、工作、娛樂，都是為了不要面對內在的沉默。因為在沉默中，你必須面對你一直壓抑的情緒、你一直逃避的問題、你一直否認的真相。這很可怕。但沉默也是療癒的空間。在那裡，你可以終於聽見自己真正的聲音，不是社會的、父母的、朋友的，而是你自己的。你的情緒需要被聽見，而它們只會在沉默中說話。給它們空間。","blockageAnalysis":"你卡住是因為頭腦太吵。它不停地計畫、分析、擔憂、回憶，你無法聽見靈魂的指引。真正的卡點是：你以為答案在外面，在更多的資訊、更多的建議、更多的行動中。但其實答案一直在內在，在沉默的中心。當你願意停止所有外在的尋找，走進內在的寧靜，你會發現你一直在尋找的東西就在那裡。沉默不是放棄，而是回歸。在那裡，一切都清晰了。","meditationEntry":"找一個不會被打擾的地方。坐下，閉上眼睛。不要嘗試冥想或做任何特殊的事，只是坐著。讓所有聲音來去：外在的車聲、風聲、內在的念頭。不要抓住它們，不要推開它們。慢慢地，一個空隙會出現，在一個念頭結束和下一個念頭開始之間。注意那個空隙。那就是沉默。它可能只持續一秒，但它是無限的。每次你觸及它，它會變得更長、更深。在那個沉默中，你是完整的。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:18', 'osho', '18', 17, '過去世', 'Past Lives', 'https://images.pexels.com/photos/1421903/pexels-photo-1421903.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Past Lives"}', '{"meanings":{"currentEnergy":"你正在被邀請看見更大的圖景。你現在面對的議題不只是這一生的，它有更深的根源。過去的模式、未解決的業力、前世的創傷，都在影響你的現在。這不是要你執著於過去，而是要你理解：你正在療癒的不只是這一生的傷，而是世世代代的傷。這個認知會給你力量，因為你會明白你的掙扎有意義，你正在打破一個古老的循環。這是靈魂的工作。","dailyGuidance":"今天，當你面對一個重複出現的模式時，問自己：這個感覺有多老？它是來自童年，還是更久之前？有時候，某些恐懼、某些吸引、某些排斥，它們的強度超過了這一生的經驗可以解釋的。那是因為它們有更深的根。今天，不要只是解決表面的問題，而是感受那個更深的層次。給自己一個意圖：我願意療癒這個模式，不管它來自何時。這個意圖本身就有力量。","emotionalInsight":"你有時候會感到一種莫名的悲傷、一種說不清的恐懼、一種無法解釋的熟悉感。這些不只是這一生的情緒，它們是靈魂的記憶。你不需要記得前世的細節才能療癒它們，你只需要承認：這個痛苦比我的故事更大。這個認知本身就是療癒的開始。你的情緒是通往更深層次的門，不要關閉它，走進去。在那裡，你會找到你一直在尋找的解放。","blockageAnalysis":"你卡住是因為在與一個你看不見全貌的模式戰鬥。你試圖用這一生的方法解決一個多生累積的問題，當然感到無力。真正的卡點是：你需要承認這個問題比你想的更深。這不是弱點，而是智慧。當你願意看見更大的圖景，你會發現這不是你個人的失敗，而是你靈魂選擇要療癒的功課。有了這個理解，你可以用更多的慈悲和耐心對待自己。療癒需要時間，因為傷口很古老。","meditationEntry":"閉上眼睛，想像你站在一條長長的走廊。每一扇門代表一個前世。你不需要打開它們，只是知道它們在那裡。現在，感受你現在的生命。看見一條線連接著現在和過去。有些模式從很久以前就跟著你：一個恐懼、一個渴望、一個天賦。感受它。然後，對著那條走廊說：謝謝你們帶我來到這裡。現在，我準備好了。我會完成這個循環。感受那份力量，你不是在單獨戰鬥。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:19', 'osho', '19', 18, '無心', 'No-Mind', 'https://images.pexels.com/photos/1367192/pexels-photo-1367192.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"No-Mind"}', '{"meanings":{"currentEnergy":"這是超越頭腦的狀態。不是沒有思考，而是不被思考控制。你正被邀請進入一個空間，在那裡你不是你的念頭，你是觀察念頭的意識。這是解放的開始，因為一旦你看清念頭只是念頭，它們就失去了控制你的力量。無心是自發性的、新鮮的、活在當下的。它不依賴過去或未來，它只存在於此刻。這是禪的狀態，是純粹的存在。在這裡，沒有問題，因為沒有解釋的需要。","dailyGuidance":"今天，練習觀察你的念頭而不認同它們。當一個念頭升起，比如「我很焦慮」，重新表述為「有一個焦慮的念頭在這裡」。看見差異嗎？你不是焦慮，你是那個意識到焦慮的存在。今天，每當你陷入思考時，輕輕地問自己：誰在觀察這個念頭？那個觀察者就是真正的你。它是寧靜的、不動的、永遠在那裡的。越多你安住在那個觀察者，越少你被念頭拖著走。","emotionalInsight":"你的痛苦不是來自於情緒本身，而是來自於你對情緒的念頭。你感到悲傷，然後頭腦說「這不應該」，「這會永遠持續」，「這證明我失敗了」。這些念頭創造了痛苦。但如果你只是感受悲傷，不加上故事，它只是一個能量的流動，會來也會去。今天，練習感受情緒而不思考它。讓悲傷就是悲傷，讓喜悅就是喜悅。你會發現，在無心的狀態中，所有情緒都是美麗的，因為它們都是生命的表達。","blockageAnalysis":"你卡住是因為過度思考。你試圖想出一條路，分析所有可能性，預測所有結果。但生命不是一個可以被解決的難題，它是一個要被活出的奧秘。真正的卡點是：你相信頭腦可以給你答案，但頭腦只能給你更多問題。當你願意放下思考，進入無心的狀態，你會發現行動自然發生。不是計畫的行動，而是自發的、直覺的、完全正確的行動。信任那個超越頭腦的智慧，它一直都在。","meditationEntry":"坐下，開始注意你的念頭。看著它們像雲一樣飄過天空。不要跟隨它們，不要批判它們，只是看著。一個念頭來，一個念頭去。慢慢地，你會注意到念頭之間的空隙。那個空隙就是無心，那就是你真正的家。每次你注意到那個空隙，停留在那裡。不要做任何事，只是安住。在那個空間中，沒有問題，沒有答案，只有純粹的存在。這就是自由。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:20', 'osho', '20', 19, '超越幻象', 'Beyond Illusion', 'https://images.pexels.com/photos/1274260/pexels-photo-1274260.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Beyond Illusion"}', '{"meanings":{"currentEnergy":"你正在看穿幻象，看見事物本來的樣子。你一直生活在一個由信念、期待、恐懼構成的虛擬世界，現在那個世界的牆正在倒塌。這可能讓人迷失方向，因為你失去了所有的參考點。但這也是最大的禮物：看見真相。你開始明白，你以為重要的很多事其實不重要，你以為真實的很多事其實是幻象。這是覺醒的開始，從夢中醒來，看見生命本來的光輝。","dailyGuidance":"今天，質疑你的假設。那些你以為是「就是這樣」的事，真的是嗎？你認為你需要某樣東西才能快樂，真的嗎？你相信某個人或情況限制了你，真的嗎？今天，看穿這些故事。它們是真的，還是你相信它們，所以它們看起來是真的？當你開始質疑，幻象就開始瓦解。你會發現，你比你以為的更自由。你的快樂不依賴於外在條件，你的力量從來沒有被奪走。你一直是完整的，只是忘記了。","emotionalInsight":"你感到一種奇怪的混合：失落和解放。失落是因為舊的世界觀正在瓦解，那些你抓著的信念不再有效。解放是因為你終於看見，那些信念其實是牢籠。你的情緒正在幫助你穿越這個轉變。允許悲傷，因為你正在哀悼一個幻象。允許喜悅，因為你正在發現真相。這是一個微妙的時刻，你站在兩個世界之間。不要急著重建新的信念，先享受這個開闊的空間。真相不需要被相信，它只需要被看見。","blockageAnalysis":"你卡住是因為還在執著於某個幻象。也許是完美的關係、完美的生活、完美的自己。但那個完美不存在，它只是頭腦創造的形象。真正的卡點是：你在追逐一個海市蜃樓，越追越遠。當你願意停下來，看清那是幻象，你會發現真正的美就在這裡，在不完美的現實中。真實的關係、真實的生活、真實的你，比任何幻想都更豐富、更有生命力。停止追逐，開始看見。這就是自由。","meditationEntry":"想像你在看一部電影，非常投入。你與角色一起哭、一起笑、一起恐懼。然後，突然，燈亮了。你看見螢幕，看見座位，你記起：這只是電影。那個釋然的感覺，那個「啊，原來如此」的時刻，就是超越幻象。現在，看看你的生命。你一直以為的那些「真實」，如果只是一部電影呢？不是說它們不重要，而是說它們不是全部。你是那個看電影的人，不是螢幕上的角色。記住這個，一切都改變了。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:21', 'osho', '21', 20, '創造力', 'Creativity', 'https://images.pexels.com/photos/1292241/pexels-photo-1292241.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Creativity"}', '{"meanings":{"currentEnergy":"這是原始創造力正在你內在流動的時刻。不是關於技巧或才華，而是關於讓生命通過你表達自己。你是一個管道，能量想要通過你誕生為某種新的形式。這可能是藝術、可能是一個計畫、可能是一種新的生活方式。重點不是結果，而是那個創造的過程本身。當你處於創造狀態時，你與存在合一，你成為生命力的化身。這是最深的喜悅，因為你不再是旁觀者，而是參與者。","dailyGuidance":"今天，給自己時間去創造些什麼，不管是什麼。畫畫、寫作、跳舞、做飯、重新布置房間，任何讓你感覺在表達某種內在衝動的事。重點不是要做得好，而是要做。不要批判過程，不要比較結果。只是讓自己成為管道，讓某種東西通過你流動出來。如果你感到卡住，不要強迫。離開一會兒，做些完全不同的事，讓潛意識工作。創造力需要鬆弛，不是緊張。","emotionalInsight":"你內在有一個被壓抑的創造者，渴望表達。也許你被告知你沒有才華，或者創造是浪費時間，應該做「有用」的事。這些聲音扼殺了你的生命力。但創造性不是奢侈品，而是必需品。它是你的靈魂說話的方式。當你壓抑它，你會感到沉悶、無聊、失去意義。當你釋放它，即使做的只是小事，你會感到活著。今天，給那個內在的創造者聲音。它不需要完美，只需要真實。","blockageAnalysis":"你卡住是因為在等待「正確的時刻」或「好的想法」。但創造力不是等來的，而是做出來的。真正的卡點是：你對結果太執著，怕做得不夠好、不夠有價值、不夠特別。但所有偉大的創造都始於玩耍和實驗。當你願意做「壞的」作品，允許自己混亂和不完美，創造力就開始流動。它不是關於產品，而是關於過程。開始做，答案會在做的過程中顯現。","meditationEntry":"想像你是一條空的河道。現在，感覺源頭的水開始流動。它不問去哪裡，不問為什麼，它只是流。感受那個流動在你體內。它可能是色彩、聲音、動作、文字。不要試圖控制它或給它形狀，只是讓它流。你的工作只是保持開放，讓它通過。在這個過程中，你不是在創造，你是在允許創造發生。這就是真正的創造力：臣服於比你更大的力量，讓它借你表達。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:22', 'osho', '22', 21, '頭腦', 'Mind', 'https://images.pexels.com/photos/3861958/pexels-photo-3861958.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Mind"}', '{"meanings":{"currentEnergy":"你的頭腦現在非常活躍，也許過度活躍。它在分析、計畫、擔憂、解決問題。這不一定是壞事，頭腦是一個美妙的工具，但它是一個糟糕的主人。這張牌提醒你：你不是你的頭腦，你是那個使用頭腦的意識。現在是時候建立一些距離，觀察你的思考而不被它控制。頭腦可以是僕人，但當它接管時，它會創造無盡的問題。學會何時使用它，何時關閉它。","dailyGuidance":"今天，觀察你的頭腦在做什麼。它在擔心未來嗎？在反芻過去嗎？在批判自己或他人嗎？每次你抓到它在做這些，輕輕地標記：「頭腦在擔心」，「頭腦在批判」。這個簡單的標記創造了距離。你開始看見，這只是頭腦在做它習慣的事，但你不需要相信每一個念頭。今天，也練習給頭腦休息。做一些不需要思考的事：走路、洗碗、摸寵物。讓頭腦放鬆。","emotionalInsight":"你的很多情緒困擾其實來自於過度思考。你不只是感受情緒，你還在想它、分析它、擔心它。這創造了第二層的痛苦。原始的情緒可能只持續幾分鐘，但頭腦可以讓它持續幾天、幾年。今天，練習分離：這是情緒（身體的感覺），那是關於情緒的念頭（頭腦的故事）。允許情緒在身體中流動，但不要被頭腦的故事捲走。情緒會過去，故事會永續。選擇感受，不是思考。","blockageAnalysis":"你卡住是因為在試圖用頭腦解決一個頭腦無法解決的問題。有些問題需要直覺、有些需要時間、有些根本不是問題，只是頭腦創造出來的。真正的卡點是：你相信如果你想得夠多，答案就會出現。但有時候，答案只會在你停止思考時出現。當你讓頭腦安靜下來，更深的智慧有空間說話。那不是邏輯的智慧，而是存在的智慧。信任它。","meditationEntry":"閉上眼睛，想像你的頭腦是一個喧鬧的市場。到處都是攤販在叫賣：你應該這樣、你應該那樣、記得那件事、擔心這件事。現在，想像你慢慢走出那個市場。聲音越來越遠。你來到一個安靜的地方，可能是森林、海邊、山頂。在那裡，市場的聲音只是遠方的嗡嗡聲，你可以聽見別的：風聲、你的呼吸、寧靜。這個地方一直都在，它是你的中心。隨時可以回來。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:23', 'osho', '23', 22, '冰期', 'Ice-olation', 'https://images.pexels.com/photos/1289842/pexels-photo-1289842.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Ice-olation"}', '{"meanings":{"currentEnergy":"你感到冰凍、麻木、與世界和自己都隔離。這是情緒的冬天，一切都停滯了。你可能是為了保護自己而建立了這個冰牆，因為感受太痛了。或者你只是耗盡了，需要休息。這張牌承認：是的，你在冰期中，這很艱難。但冰期也有它的目的：它讓種子在地下安全，等待春天。這不是永久的狀態，而是一個季節。在這個寒冷中，允許自己休眠。不要強迫成長，先療癒。","dailyGuidance":"今天，不要強迫自己感受或做任何事。如果你麻木，就麻木。如果你想躲避，就躲避。這不是放棄，而是尊重你現在的狀態。你的身心在說：我需要休息。聆聽它。做最低限度的必要事情，其他的都可以等。今天的目標不是改善或前進，而是生存和溫柔。對自己溫柔，像對待一個生病的朋友。冰期不會永遠持續，但它需要時間融化。不要催促它，允許它的節奏。","emotionalInsight":"你的麻木不是冷漠，而是防禦。你曾經感受得太深，受傷得太重，現在你的系統關閉了情緒通道來保護你。這是智慧的，但也是代價高昂的。在冰牆後面，你是安全的，但也是孤獨的。你的情緒在等待，等待足夠安全的時候再出來。不要強迫它們，但也不要永遠躲在冰牆後。當你準備好時，開始小心地融化：一點溫暖、一點連結、一點脆弱。慢慢來，你的時機會知道。","blockageAnalysis":"你卡住是因為試圖在冰凍的土地上種植。但現在不是春天，是冬天。真正的卡點是：你以為你應該感覺更多、做更多、是更多。但自然有季節，你也有。冬天不是失敗，而是必要的休眠。當你接受你在冬天，停止對抗它，你會發現一種奇怪的平靜。你不需要馬上融化，你只需要等待和休息。春天會來，但它有自己的時間表。信任那個時機。","meditationEntry":"想像你是一棵在冬天的樹。你的葉子都掉了，枝幹光禿禿的。從外面看，你好像死了。但在內在，在看不見的地方，生命依然存在。樹汁慢慢流動，根在地下安靜地工作，準備春天。你不是死了，只是在休眠。感受那個內在的生命，即使外在看起來荒涼。它還在，它只是在等待正確的時刻再次綻放。不要急，信任這個週期。你會再次開花。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:24', 'osho', '24', 23, '參與', 'Participation', 'https://images.pexels.com/photos/1157557/pexels-photo-1157557.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Participation"}', '{"meanings":{"currentEnergy":"生命在邀請你參與，不是旁觀。你一直站在邊緣，看著別人跳舞、冒險、活著。也許是恐懼，也許是羞怯，也許是覺得自己不夠格。但現在是時候走進去了。參與不是關於做對或做好，而是關於在場、投入、全心全意地在這裡。當你參與，生命就變得真實。你不再是觀眾，你成為故事的一部分。這需要勇氣，因為參與意味著冒險被看見、可能失敗、可能受傷。但那也意味著真正活著。","dailyGuidance":"今天，說「是」。當機會出現時，當有人邀請你時，當你的心說「也許」時，說是。不要退縮到你的安全區，不要找藉口，不要等到「準備好」。今天，參與一些讓你稍微不舒服的事：發言、分享、嘗試新的。觀察你的抗拒，但不要讓它阻止你。每次你參與，你會發現其實沒有想像中可怕，而且常常很有趣。生命在你參與時才開始。","emotionalInsight":"你的孤獨和疏離感來自於不參與。你在保護自己不受傷害，但代價是你也隔絕了喜悅、連結、歸屬感。你看著別人的生活，羨慕他們的親密和活力，但你不知道那些都來自於參與的意願。是的，參與會帶來脆弱，可能受傷。但不參與的痛苦更深，因為那是慢性的空虛。你的情緒在渴望連結，渴望被看見，渴望屬於某處。給自己那個禮物，走進去。","blockageAnalysis":"你卡住是因為在等待保證：保證不會失敗、不會被拒絕、不會看起來愚蠢。但生命不提供那種保證。真正的卡點是：你想要結果而不冒風險。但參與就是風險。當你願意放棄對結果的控制，只是投入過程，你會發現一種自由。你不是為了成功而參與，你是為了活著而參與。成功或失敗都只是故事，真正重要的是你在場了。那本身就是勝利。","meditationEntry":"想像生命是一個巨大的舞蹈。每個人都在跳，以自己的方式。現在看看你自己。你站在哪裡？邊緣？角落？還是在舞池中央？如果你在邊緣，感受那個想要進去的衝動。可能有恐懼，但也有渴望。現在，想像你走進去。沒有人在評判你，每個人都太忙於自己的舞蹈。你開始移動，笨拙也好，優雅也好。重點是你在動，你在參與。感受那個解放。這就是活著。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:25', 'osho', '25', 24, '投射', 'Projection', 'https://images.pexels.com/photos/1054218/pexels-photo-1054218.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Projection"}', '{"meanings":{"currentEnergy":"你現在看見的不是真相，而是你的投射。你把自己內在的恐懼、渴望、未解決的問題投射到外在的人和情況上。你以為問題在那裡，但其實它在這裡，在你裡面。這不是你的錯，投射是人類的自然機制。但它讓你困在一個幻覺中，你在與鏡子裡的影子戰鬥，而不是面對真正的源頭。這張牌邀請你把投影機轉回來，照向內在。那個最困擾你的，其實是要教你關於你自己的事。","dailyGuidance":"今天，當你對某人或某事有強烈反應時，停下來問：這觸發了我什麼？如果某人的行為讓你憤怒，問：我在哪裡也這樣做，但不承認？如果你被某人吸引，問：我在他們身上看見我渴望在自己身上發展的什麼特質？外在是鏡子，它反映你的內在。今天，用這個鏡子了解自己，而不是批判別人。這個轉變會把責備變成洞察，把受害者變成學習者。","emotionalInsight":"你的很多情緒痛苦來自於投射。你感到被傷害，因為你相信某人在針對你。但多數時候，他們只是在活自己的生命，處理自己的傷口。你的傷口讓你把他們的行為詮釋為針對你。這不是說你的痛苦不真實，而是說它的源頭可能不在你以為的地方。當你收回投射，停止歸咎，你會發現一個力量：你可以療癒自己的傷口，不需要別人改變。自由就在那裡。","blockageAnalysis":"你卡住是因為在等待外在世界改變來讓你感覺好一點。但如果那個外在只是你的投射呢？真正的卡點是：你在給別人和情況一個力量他們其實沒有。你的情緒反應的強度顯示，這不只是關於現在和這個人，而是關於過去和你內在未療癒的部分。當你願意面對那個內在的傷口，直接療癒它，外在自然會改變，因為你不再用同樣的濾鏡看世界。問題消失了，不是因為它被解決了，而是因為它從來不在外面。","meditationEntry":"想像你在一個黑暗的房間裡，手上拿著手電筒。你照向別人：他們做錯了、他們傷害了你、他們應該不同。每次你這樣做，你看見一個怪物。現在，慢慢地，把手電筒轉向自己。照亮你的恐懼、你的傷口、你的陰影。一開始可能很嚇人。但隨著你持續照亮，你發現那些不是怪物，只是你的一部分，等待被看見和愛。當你照亮你自己，外面的怪物消失了。房間不是變亮了，而是你看見真相了。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:26', 'osho', '26', 25, '強烈', 'Intensity', 'https://images.pexels.com/photos/1166990/pexels-photo-1166990.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Intensity"}', '{"meanings":{"currentEnergy":"你現在的生命充滿強度。情緒強烈、經驗強烈、一切都放大了。這不是一個冷靜或平衡的時期，而是一個燃燒的時期。你可能感到overwhelmed，但這個強度也是一種祝福。它在燃燒掉舊的、不再服務你的部分。它在喚醒你，讓你無法再沉睡或麻木。這個強度需要被尊重，不是被壓抑。允許它流動，它會自然地找到平衡。但現在，不要抗拒這個火。","dailyGuidance":"今天，不要試圖冷靜下來或「正常」。如果你感到強烈，就允許那個強度。找到安全的方式表達它：運動、創作、大叫、大笑、大哭。讓那個能量移動，不要困住它。同時，照顧你的身體。強度會消耗能量，所以吃好、休息、接地。避免重大決定，因為在這個強度中，你的視野可能扭曲。但也不要壓抑自己。這是一個感受一切、活得淋漓盡致的時候。","emotionalInsight":"你的情緒現在像海嘯，一波接一波。這可能嚇人，但這也是療癒。那些被壓抑多年的情緒終於找到了出口。不要試圖控制它們或講道理，只是讓它們通過。在強度中，你會發現一個真相：情緒不會殺死你。你比你以為的更強大，能承受更多。這個過程在清理你的情緒體，為新的開始騰出空間。信任這個過程，即使它混亂。之後會有寧靜，但現在先讓暴風雨過去。","blockageAnalysis":"你卡住是因為在試圖控制這個強度，讓它變得可管理。但這個能量太大了，不能被控制，只能被引導。真正的卡點是：你害怕如果你真的放手，你會失控或傷害自己或別人。但壓抑只會讓壓力累積，最終爆炸。當你找到健康的管道——運動、藝術、大自然——讓這個能量流動，它就不再危險，而是變成動力。不要困住這個火，給它一個方向。","meditationEntry":"想像你內在有一個火山。它不是死的，它是活的，有岩漿在翻騰。你可以試圖蓋住它，假裝它不在，但那會導致爆發。或者，你可以承認它，創造一個受控的釋放。看著那個火山，感受它的力量。那不是敵人，那是生命力。現在，想像給它一個管道：一條熔岩河，安全地流向大海。火山還在，力量還在，但現在它在為你工作，而不是對抗你。這就是與強度共處的藝術。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:27', 'osho', '27', 26, '陷入愛中', 'Falling in Love', 'https://images.pexels.com/photos/1024967/pexels-photo-1024967.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Falling in Love"}', '{"meanings":{"currentEnergy":"你正在經歷愛的魔法，那個讓世界變得明亮的時刻。這可能是對一個人的愛、對生命的愛、對你自己的愛。不管對象是什麼，你在體驗那個美麗的打開、那個脆弱和勇敢的混合。陷入愛中是一個臣服，你放下防禦，讓某種更大的東西進入。這是祝福，但也要保持警覺：不要失去自己在這個過程中。真正的愛不是失去自己，而是更深地找到自己。","dailyGuidance":"今天，享受這個打開的感覺，那個對生命說是的衝動。讓自己感受喜悅、興奮、希望。但也記得呼吸，保持與地面的連結。在愛的陶醉中，很容易失去判斷力，把對方理想化或忽略紅旗。今天，感受愛，但也保持一點觀察者的意識。問自己：我是在愛這個人/事物本來的樣子，還是在愛我的幻想？真正的愛能看見真相，並且依然愛。","emotionalInsight":"你的心現在完全打開，像一朵花向太陽。這是美麗的，但也讓你極度脆弱。你的情緒像坐雲霄飛車，高峰和低谷都很極端。這是正常的，這是愛的本質。但不要讓這個強度蒙蔽你。記住，陷入愛中是一個階段，不是永久狀態。享受它，但也準備好它會演變。真正的愛是在激情退去後依然留下的：尊重、信任、承諾。現在享受激情，但也為更深的階段打基礎。","blockageAnalysis":"如果你渴望愛但感覺卡住，問自己：我允許自己接收愛嗎？很多人說想要愛，但當它出現時，他們退縮，因為不相信自己值得或害怕受傷。真正的卡點是：你的心想打開，但你的傷口讓你建了一道牆。開始小心地拆那道牆。不是一次全部，而是一塊磚、一塊磚。允許小的冒險、小的脆弱。愛不會等你完全準備好，但它會等你願意嘗試。","meditationEntry":"回想一個你完全打開的時刻，也許是在大自然中、也許是抱著一個孩子、也許是聽音樂。那個時刻，你的心沒有防衛，你只是在那裡，完全活著。感受那個記憶，讓它在你體內重新活過來。那個打開，那個是，那就是愛的本質。它不是關於另一個人，而是關於你的狀態。你可以選擇活在那個狀態，不管外在情況。這就是真正陷入愛中：與生命本身相愛。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:28', 'osho', '28', 27, '懶惰', 'Laziness', 'https://images.pexels.com/photos/296878/pexels-photo-296878.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Laziness"}', '{"meanings":{"currentEnergy":"你現在感到一種深深的不想動。不是因為累，而是一種存在層面的懶惰。你不想努力、不想改變、不想成長。你只想待著，什麼都不做。這可能是抗拒，也可能是智慧。這張牌問你：這個懶惰是在服務你還是傷害你？如果它是休息和整合的需要，那就榮譽它。但如果它是恐懼的偽裝，逃避你知道該做的事，那就需要溫柔地面對它。","dailyGuidance":"今天，誠實地看你的懶惰。列出你在拖延的事，問每一件：我為什麼不想做這個？答案會告訴你很多。可能是這件事根本不重要，是別人的期待，不是你的真心。那就放下它。或者可能是它很重要，但你害怕失敗或成功。那就承認恐懼，但還是做。有時候懶惰的治療是行動：開始做，動力會跟著來。有時候懶惰的治療是許可：允許自己真正休息，不帶罪惡感。今天，分辨你需要哪一種。","emotionalInsight":"你的懶惰可能是一種情緒疲勞。你太久了一直在努力、在推動、在證明自己，現在你的靈魂在罷工。它在說：夠了，我需要休息。這不是軟弱，這是智慧。但如果這個懶惰已經持續很久，它可能變成了抑鬱或絕望的形式。你可能失去了意義感，不知道為什麼要努力。如果是這樣，你需要重新連結你的「為什麼」。不是別人告訴你的應該，而是你內心真正在乎的。當你找到那個，能量會自然回來。","blockageAnalysis":"你卡住是因為在等待動力出現再開始行動。但動力通常是行動的結果，不是原因。真正的卡點是：你想要保證努力會有結果，所以你在等待完美時機或完美計畫。但那個時機永遠不會來。突破懶惰的方法是：做最小的第一步，不管感覺如何。通常，一旦你開始，你會發現其實沒那麼難，而且開始享受過程。行動創造清晰，清晰創造動力。不要等，開始。","meditationEntry":"想像你躺在一個非常舒適的床上。太舒適了，你不想起來。但窗外，有一個美麗的日子在等你：陽光、新鮮空氣、冒險。你知道如果你起來，你會享受。但床太舒適了，起來需要努力。現在，想像你的未來自己，已經起來、已經出去、已經經歷了那個美好的一天，回來告訴現在的你：值得。那個小小的努力，那個跨過阻力的時刻，開啟了一整天的喜悅。聽那個聲音，讓它給你力量站起來。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:29', 'osho', '29', 28, '信任', 'Trust', 'https://images.pexels.com/photos/1029604/pexels-photo-1029604.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Trust"}', '{"meanings":{"currentEnergy":"現在是學習信任的時刻，特別是在不確定中信任。你可能面對未知，沒有地圖，不知道會發生什麼。這張牌說：放手，跳躍，信任網會接住你。這不是盲目的信任，而是深深的知道：生命在支持你，即使你看不見怎麼支持。這個信任不是頭腦的決定，而是心的臣服。你不能強迫它，但你可以練習它。每次你放手控制，每次你說「我不知道，但我信任」，你就在加深這個能力。","dailyGuidance":"今天，練習小的信任行動。也許是不過度計畫，允許一天自然展開。也許是相信某人會遵守承諾，不去檢查或提醒。也許是相信你的身體知道它需要什麼，聽它的訊號。每次你想要控制或擔心，停下來，深呼吸，說「我信任」。觀察會發生什麼。通常，你會發現事情自己解決了，比你強迫的結果更好。信任不是被動，而是積極的放手。它是做你該做的，然後放下結果。","emotionalInsight":"你的信任可能被過去背叛了。也許是人背叛你，也許是生命背叛你，沒有按你期待的方式展開。那個傷讓你變得警惕，總是準備好被失望。但這個保護姿態也切斷了你與生命的流動。你在一個防禦狀態中，疲憊且孤獨。重建信任不是忘記過去或變得天真，而是認識到：那個背叛是一個經驗，不是全部經驗。你可以學習分辨誰和什麼值得信任，並且給他們機會。從小的開始，證明給自己看：信任是可能的。","blockageAnalysis":"你卡住是因為想要保證和控制才能信任。但那不是信任，那是確定性。真正的信任是在不確定中的跳躍。真正的卡點是：你相信如果你不掌控一切，一切會崩潰。但那個持續的控制讓你筋疲力盡，而且常常適得其反，因為你的控制推開了機會和幫助。當你願意鬆手，信任生命，你會發現一個奇蹟：事情常常比你安排的更好。不是因為你放棄責任，而是因為你允許更大的智慧參與。","meditationEntry":"回想學游泳的時刻，或者想像它。一開始，你緊抓著邊緣，害怕水。然後，有一刻，你讓自己浮起來。你不知道水會支撐你，但你嘗試了。然後，奇蹟：水真的支撐你。你的身體放鬆，你開始漂浮。那個時刻，那就是信任。生命就像水，它會支撐你，但你必須放鬆，停止掙扎。當你緊繃，你會下沉。當你放鬆，你會浮起來。記住這個感覺。隨時可以回到它。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:30', 'osho', '30', 29, '理解', 'Understanding', 'https://images.pexels.com/photos/346885/pexels-photo-346885.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Understanding"}', '{"meanings":{"currentEnergy":"光正在照進之前黑暗的地方。你開始理解一些長期困惑你的事：為什麼某段關係是那樣、為什麼你重複某個模式、為什麼某個傷這麼深。這個理解不只是智力的，而是整體的：你的心和身體也明白了。這種理解帶來解放，因為當你真正理解時，很多東西自然脫落。你不再需要原諒或努力放下，它們只是不再重要了。這是深層療癒的時刻。","dailyGuidance":"今天，給自己時間整合你新的理解。可能需要寫下來、說出來、或只是坐著消化。這個理解可能改變你看很多事情的方式，允許那個重組發生。不要急著行動或做決定，先讓新的視角沉澱。同時，帶著這個新的理解，溫柔地看你的過去。你會發現，很多你以為是錯誤或失敗的，其實是必要的步驟，帶你到現在的理解。這個新的視角是一個禮物，珍惜它。","emotionalInsight":"你的情緒正在獲得脈絡。之前，你只是感受痛苦、憤怒、悲傷，但不知道為什麼這麼強烈。現在，你開始看見連結：這個現在的情況觸發了過去的傷、這個人提醒你某個早期的關係、這個恐懼根源於某個童年經驗。這個理解不會立刻消除痛苦，但它改變了你與痛苦的關係。你不再被它困惑或控制，你看見它的邏輯，它的起源。這個看見本身就是療癒。慢慢地，理解會轉化痛苦。","blockageAnalysis":"你可能在過度分析，試圖理解每一個細節，但真正的理解不會通過分析來。真正的卡點是：你想用頭腦理解一個心的問題。有些事不能被思考透徹，只能被感受透徹。如果你卡在分析中，試著放下為什麼，只是感受是什麼。允許身體和心有它們自己的智慧。有時候，理解會在你停止試圖理解時突然出現，像一個「啊哈」時刻。那不是來自努力，而是來自放鬆和開放。","meditationEntry":"想像你在看一幅畫，非常靠近，近到只看見顏色和筆觸，但不知道它是什麼。讓人困惑和沮喪。現在，慢慢後退。當你有了距離，圖像開始浮現。再退一點，突然，你看見了：是一張臉，一個風景，一個故事。那個「啊」的時刻，那就是理解。你的生命也是這樣。當你太近，太在其中，你只看見混亂。但當你能獲得一點距離，看更大的圖像，意義出現了。你的經驗不是隨機的，它們是一個織錦的一部分。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:31', 'osho', '31', 30, '控制', 'Control', 'https://images.pexels.com/photos/3760278/pexels-photo-3760278.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Control"}', '{"meanings":{"currentEnergy":"你現在抓得太緊了。你試圖控制每一個細節：人們怎麼看你、事情怎麼發展、未來會怎樣。這個控制的衝動來自恐懼：害怕如果你放手，一切會崩潰。但這個緊抓反而讓你更焦慮、更累、更孤獨。生命不能被控制，它只能被活。這張牌邀請你看見：你的控制其實是一個幻覺。你從來沒有真正掌控過，你只是假裝而已，而那個假裝耗盡了你。是時候放手了。","dailyGuidance":"今天，注意你想要控制的時刻。也許是想控制對話的走向、想讓事情按你的計畫進行、想確保沒有意外。每次你察覺那個衝動，問：如果我放手這個控制，最壞會怎樣？通常，最壞的情況並不像你想的那麼糟。然後，練習小的放手：讓別人做決定、接受計畫改變、允許事情自然展開。觀察當你放手控制，你的身體感覺如何。可能會有焦慮，但也會有解放。","emotionalInsight":"你的控制背後藏著深深的不安全感。也許童年時，生命感覺混亂和不可預測，所以你學會要掌控一切來感到安全。但現在，這個策略不再服務你，它變成了監獄。真正的安全不是來自控制外在，而是來自信任自己：不管發生什麼，我都能應對。你已經度過了很多你以為無法度過的事。你比你的控制需求更強大。開始信任那個內在力量，慢慢放手外在的控制。","blockageAnalysis":"你卡住是因為相信控制等於安全，放手等於危險。真正的卡點是：你沒有認識到控制的代價。它可能給你一個安全的幻覺，但它也切斷了自發性、驚喜、流動、連結。人們感覺被你控制時會退縮，機會感覺被你的剛性拒絕時會繞過你。當你願意鬆手，信任生命的流，你會發現一個矛盾：放手控制反而帶來更多真實的安全，因為你變得更有彈性、更能適應。控制是脆性的，信任是韌性的。","meditationEntry":"想像你在緊握一把沙子。你握得越緊，越多沙子從指縫間流走。你的手累了、痛了，但你不敢放鬆，因為你怕失去所有的沙。現在，想像你慢慢打開手掌，讓它平攤。沙子沒有都流走，有一些停留在你的掌心。而且，你的手現在放鬆了、自由了。你可以接收新的東西。這就是放手控制的樣子。你不會失去一切，但你會得到自由。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:32', 'osho', '32', 31, '政治', 'Politics', 'https://images.pexels.com/photos/6077447/pexels-photo-6077447.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Politics"}', '{"meanings":{"currentEnergy":"你現在陷入權力遊戲、操控、和策略中。也許是職場政治、家庭動態、或社交圈的權力鬥爭。你發現自己在計算、在防禦、在試圖佔上風。這耗盡了你的能量，讓你遠離你的真實。這張牌不是在譴責你，而是在照亮：當你活在政治中，你失去了真誠。你變成了一個棋手，而不是一個真實的人。問自己：我為什麼在玩這個遊戲？值得這個代價嗎？","dailyGuidance":"今天，注意你在做政治性選擇的時刻：說你不真正相信的話來取悅某人、隱藏你的真實想法來避免衝突、操控情況來得到你想要的。每次你察覺，問：如果我真誠地表達，會怎樣？可能會有後果，但也會有自由。今天，選擇至少一個時刻，你真誠而不是策略性地回應。感受那個不同。真誠可能讓你失去遊戲，但它讓你贏回自己。","emotionalInsight":"活在政治中讓你情緒疲憊和憤世嫉俗。你開始不信任任何人，因為你假設每個人都在操控。你失去了天真和自發性。這是保護，但也是孤立。真正的連結不可能在政治中發生，因為沒有人看見真實的你，你也沒有看見真實的他們。如果你渴望真實的關係，你需要願意走出政治遊戲。這需要勇氣，因為你會變得脆弱。但那個脆弱是通往真實親密的唯一路。","blockageAnalysis":"你卡住是因為相信如果你不玩政治遊戲，你會輸。但輸什麼？如果「贏」意味著你要背叛自己、活在恐懼中、永遠戴著面具，那個「贏」其實是最大的輸。真正的卡點是：你沒有考慮第三個選項，不是玩遊戲也不是被動受害，而是完全退出遊戲。選擇一個你可以真誠的環境，或者創造一個。當你停止玩政治，你也停止吸引政治性的人和情況。你開始吸引同樣重視真誠的人。","meditationEntry":"想像你在一個舞會上，每個人都戴著面具，跳著精心編排的舞步。你也戴著面具，在遵循規則。很累，很假，但你不敢脫下面具，因為你怕被拒絕。現在，想像你停下來，慢慢脫下面具。一開始，人們可能震驚或不舒服。但然後，有一個人也脫下了他們的面具。然後另一個。慢慢地，整個舞會改變了。不再是精心編排的舞蹈，而是真實的連結。那個改變始於一個人的勇氣：你。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:33', 'osho', '33', 32, '慶祝', 'Celebration', 'https://images.pexels.com/photos/1268558/pexels-photo-1268558.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Celebration"}', '{"meanings":{"currentEnergy":"現在是慶祝的時刻，不是等待特別的理由，而是慶祝存在本身。你活著、你呼吸、你有這個時刻，這就足夠了。這張牌邀請你從嚴肅、沉重、總是在努力的模式中出來，進入喜悅和玩樂。生命不只是一個要完成的任務清單，它也是一個要享受的派對。你可以選擇在這個旅程中微笑、跳舞、大笑。慶祝不是自私或不負責任，它是榮譽生命的禮物。","dailyGuidance":"今天，找理由慶祝。不需要是大事：太陽出來了、咖啡很好喝、你讀了一本好書、你跟朋友笑了。注意那些小的喜悅，讓它們變大。也許放你喜歡的音樂跳舞、給自己買一個小禮物、或只是花時間在讓你快樂的事上。今天，優先喜悅而不是生產力。觀察當你給自己許可快樂，你的整體能量如何改變。慶祝不是浪費時間，它是補充生命力。","emotionalInsight":"你可能活在一個內在的嚴格父母的監督下，它說你只有在完成所有事、證明自己之後才能快樂。但那個「之後」永遠不會到，因為總有更多事要做。這張牌說：現在就快樂，不需要理由。你的內在小孩在渴望玩樂、自發性、無目的的喜悅。給它許可。那個許可會療癒很多舊的傷，那些你被告知要嚴肅、要努力、要延遲滿足的訊息。慶祝是一個反叛行動，對抗那些內化的壓迫。","blockageAnalysis":"你卡住是因為感到內疚或不值得快樂。也許你相信世界上有太多痛苦，你怎麼能快樂？或者你相信你還沒賺得快樂的權利。真正的卡點是：你不明白快樂不是一個你要賺得的獎賞，而是你的自然狀態。而且，你的快樂不會拿走別人的快樂，反而，它是有傳染性的。當你慶祝，你給別人許可也這樣做。你的喜悅不是自私，它是一個對世界的貢獻。我們需要更多喜悅，從你開始。","meditationEntry":"回想童年時一個你完全在玩樂中的時刻。也許是在沙灘上、在雪地裡、在遊樂場上。那個時刻，你沒有在想明天或昨天，你完全在現在，完全快樂，不需要理由。感受那個記憶在你體內。那個能力，那個慶祝生命的能力，沒有離開你。它只是被埋在責任和期待下。但它還在，等著被喚醒。你可以隨時回到那個狀態。玩樂不是只給孩子的，它是給所有活著的人的。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:34', 'osho', '34', 33, '分享', 'Sharing', 'https://images.pexels.com/photos/3184338/pexels-photo-3184338.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Sharing"}', '{"meanings":{"currentEnergy":"你現在有豐盛，不只是物質上，也是情緒、智慧、經驗上。這張牌邀請你分享，不是因為你應該或為了獲得回報，而是因為分享是喜悅的自然溢出。當你有，而你給，給的行動本身就豐富你。這不是犧牲或損失，而是循環。你接收過，現在你傳遞。這個流動讓能量活著，讓豐盛增加。囤積會讓能量停滯，分享會讓它繁榮。","dailyGuidance":"今天，找機會分享。也許是你的時間、你的微笑、你的知識、你的資源。注意分享對你感覺如何。真正的分享是輕鬆的，不帶期待或怨恨。如果你感到怨恨，那不是分享，那是義務，停下來。只分享你真心想給的。同時，練習接收。分享是雙向的，允許別人也給你。很多人善於給但不善於收，但那打斷了循環。今天，既是一個給予者也是一個接收者。","emotionalInsight":"你對分享的關係反映了你對值得感的信念。如果你很難給，可能是因為你在匱乏心態中，相信沒有足夠的。如果你很難收，可能是因為你不相信你值得接收。真正的分享來自豐盛感：我有足夠，所以我可以給；我值得，所以我可以收。培養這個豐盛感，即使在你的物質情況有限時。豐盛首先是一個內在狀態，然後它顯化在外在。當你感覺豐盛，分享變得自然且愉快。","blockageAnalysis":"你可能卡在給太多或給太少。給太多通常是在試圖買愛或避免拒絕；給太少通常是在保護自己免於損失或利用。真正的卡點是：你不在一個平衡的給與收的流動中。檢視你的動機。你給是因為你真心想給，還是因為恐懼或期待？你不給是因為你真的沒有，還是因為吝嗇或恐懼？平衡的分享來自一個充滿的杯子，你從溢出的部分給，不是從杯子本身。先填滿你的杯子，然後自然地分享。","meditationEntry":"想像你站在一條河邊。河水不斷流動，從上游來，到下游去。它不囤積水，它讓水流動。因為這個流動，河保持新鮮、活著、豐富。如果它築一個壩，水會變得停滯。你也是一條河，能量和資源流經你。當你讓它們流動——接收和給出——你保持活著和豐富。當你囤積或關閉，你變得停滯。流動是生命的本質。你不是一個容器要被填滿，你是一個管道要讓豐盛流過。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:35', 'osho', '35', 34, '妥協', 'Compromise', 'https://images.pexels.com/photos/3184611/pexels-photo-3184611.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Compromise"}', '{"meanings":{"currentEnergy":"你現在面對一個選擇：堅持你的立場還是妥協？這張牌不是在說妥協總是對或錯，而是在邀請你檢視：你為什麼要妥協？如果是為了和平、理解、或因為你看見另一個觀點的價值，妥協是智慧。但如果是因為害怕衝突、想取悅、或失去你自己的中心，妥協是背叛。關鍵是：在妥協中，你還保有你的完整性嗎？還是你在出賣自己的真相？","dailyGuidance":"今天，當你面對需要妥協的情況，慢下來，感受你的身體。真正的妥協在你身體裡感覺是開放的，像「我可以看見另一邊，我願意找中間路」。錯誤的妥協感覺是緊縮的，像「我不想這樣但我別無選擇」。如果是後者，那不是妥協，那是屈服。在那個情況，你需要設立界限，即使不舒服。記住：妥協關於找雙贏，屈服關於你輸。不要混淆這兩者。","emotionalInsight":"你可能有一個模式：總是妥協、總是讓步、總是把別人的需要放在你的前面。這來自一個信念：衝突是危險的，取悅別人是安全的。但這個模式讓你累積怨恨和失去自我。或者，你可能有相反的模式：從不妥協、總是堅持己見、看妥協為軟弱。這來自一個信念：讓步是失敗，控制是力量。但這個模式讓你孤立和剛性。真正的智慧是在這兩個極端之間：知道什麼時候彎曲，什麼時候堅定。","blockageAnalysis":"你卡住是因為在一個非黑即白的思維：要麼我贏要麼你贏。真正的卡點是：你不相信雙贏是可能的。你看關係為一個零和遊戲，所以每個妥協感覺像損失。但大多數情況，有第三個選項，一個你們兩個都沒想到的解決方案，它榮譽雙方的需要。找到它需要創意、溝通、和願意放下「我是對的」的姿態。當你從對錯思維轉到「我們怎麼都得到我們需要的」思維，突破就出現了。","meditationEntry":"想像兩個人在拔河,每個人都用盡全力拉,沒人願意讓步。他們都累了、沮喪了,但都不願放手,因為那感覺像輸。現在,想像其中一個人有一個主意:如果我們放下繩子,一起找一個我們都想去的方向呢?一開始另一個人懷疑,但然後他們嘗試了。他們發現當他們不在對抗,而是在合作,他們可以去很遠的地方。妥協不是弱化你的力量,而是結合它。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:36', 'osho', '36', 35, '保守', 'Conservativeness', 'https://images.pexels.com/photos/3760067/pexels-photo-3760067.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Conservativeness"}', '{"meanings":{"currentEnergy":"你現在緊抓著已知、熟悉、和安全。改變在敲門,但你鎖著它,說「不,謝謝,我很好」。這個保守來自恐懼:害怕失去你有的、害怕未知、害怕犯錯。但這個緊抓讓你停滯。生命是流動的,當你試圖凍結它,你不是創造安全,而是創造一個監獄。這張牌不是在說你應該魯莽或不負責任,而是在邀請你檢視:你的保守是保護你,還是限制你?","dailyGuidance":"今天,注意你說「不」是因為習慣而不是真正的偏好的時刻。也許是新的提議、不同的做法、或一個小的改變。問自己:我拒絕是因為這真的不適合我,還是只是因為它不熟悉?今天,試著對一個小的改變說「是」。不需要是大的,也許只是走不同的路回家、嘗試新的食物、或用不同的方式做熟悉的事。感受那個新鮮感,即使它有點不舒服。不舒服不等於危險。","emotionalInsight":"你的保守可能根源於過去的失去或背叛。也許你曾經信任、開放、冒險,然後被傷害了。所以你學會縮回去,建一個牆,說「再也不會了」。這個保護是可理解的,但它也讓你失去活力和可能性。真正的療癒不是永遠保守,而是重建你的信任能力:信任自己能應對,信任生命雖然有時會傷害你,但也會給你美好。當你準備好,慢慢地,開始打開那個牆上的小窗,讓一些新鮮空氣進來。","blockageAnalysis":"你卡住是因為把安全和不變混為一談。真正的卡點是:你認為如果你保持一切一樣,你可以避免痛苦。但這是一個幻覺。改變會發生,不管你抗拒還是接受。唯一的區別是,當你抗拒,你增加了你的痛苦;當你接受,你可以流動。而且,試圖保持不變需要巨大的能量,像試圖阻止河流。當你放鬆那個努力,當你允許自然的流動,你會發現你有更多能量去創造、去享受、去活。","meditationEntry":"想像你是一棵樹。秋天來了,你的葉子開始變色,準備掉落。但你緊抓著它們,說「不,我需要這些葉子,它們是我的一部分,沒有它們我會死」。但樹不是這樣工作的。樹知道,要讓新的生長發生,舊的必須被釋放。當葉子掉落,樹不是在失去,而是在準備新生。冬天的休息,然後春天的爆發。這是自然的循環。你也是。你抓著的東西,那些「必須保持一樣」的東西,可能正是阻止你新生的東西。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:37', 'osho', '37', 36, '平凡時刻', 'Ordinariness', 'https://images.pexels.com/photos/1109543/pexels-photo-1109543.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Ordinariness"}', '{"meanings":{"currentEnergy":"這是一個平凡的時刻,沒有戲劇、沒有高峰、沒有危機。只是日常生活的簡單流動。你可能感到無聊或失望,期待更多刺激或意義。但這張牌邀請你重新看平凡:它不是缺乏某些東西,而是一個深度的當下。在平凡中,你可以呼吸、休息、注意小事。那些小事——早晨的咖啡、陽光穿過窗戶、朋友的笑聲——它們就是生命。不是在等待真正的生命開始,這就是它。","dailyGuidance":"今天,給你的平凡任務完整的注意力。當你洗碗,感受水的溫度、肥皂的質地、碗的乾淨。當你走路,感受你的腳接觸地面、空氣在你皮膚上、你周圍的聲音。不要趕著到下一個事、不要在頭腦裡計畫或反芻。只是在這裡。你會發現,當你真正在場,沒有什麼是真正平凡的。每一個時刻都有它自己的質地、它自己的豐富。平凡變成神聖,當你帶著覺知去接近它。","emotionalInsight":"你可能一直在追求非凡:非凡的成就、非凡的關係、非凡的體驗。這個追求讓你總是在別處,永遠不滿足於這裡。但矛盾的是,真正的滿足和深度不是在非凡中找到,而是在對平凡的深度欣賞中。當你可以在一個安靜的夜晚、一個簡單的晚餐、一個平常的對話中找到美和意義,你就自由了。你不再依賴外在的刺激或驗證。你的快樂變得穩定和內在生成。","blockageAnalysis":"你卡住是因為貶低平凡,追逐非凡。真正的卡點是:你把非凡理想化,以為那裡有你在這裡找不到的東西。但非凡時刻是稀有的,如果你只為那些活,你會錯過大部分的生命。而且,諷刺的是,非凡通常在平凡中生長。那些偉大的頓悟、深度的連結、創意的突破,它們通常發生在平凡的時刻,當你放鬆和在場時。當你學會愛平凡,非凡會以它自己的時間到來,作為一個意外的禮物,不是一個你要追逐的東西。","meditationEntry":"想像你在一個美術館,尋找那幅「最偉大」的畫。你快速走過每一幅,評判、比較、找那個會讓你「哇」的。但在這個尋找中,你沒有真正看任何一幅畫。現在,停下來,真正看你面前的這一幅。不是特別出名或珍貴的,只是這一幅。看它的顏色、筆觸、構圖。給它時間。慢慢地,你開始看見它的美、它的深度、它的故事。它不需要是「最偉大的」來值得你的注意。它只需要是它自己。生命也是這樣。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:38', 'osho', '38', 37, '壓力', 'Stress', 'https://images.pexels.com/photos/3807755/pexels-photo-3807755.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Stress"}', '{"meanings":{"currentEnergy":"你現在在壓力下,感覺被壓迫、透不過氣、在極限邊緣。太多要做、太多責任、太多期待。你的身體緊繃,你的頭腦跑不停,你的情緒在邊緣。這張牌是一個警告:這個狀態不可持續。你需要停下來、呼吸、重新評估。什麼是真正必要的?什麼是你強加在自己身上的?你能放下什麼?你能請求幫助嗎?壓力不是一個你要推過去的東西,而是一個信號,說你需要改變某些東西。","dailyGuidance":"今天,你的首要任務不是完成更多事,而是降低你的壓力水平。這可能意味著說不、取消、延遲、或請求幫助。檢視你的待辦清單,問:什麼會真正發生如果我不做這個?通常,後果沒有你想的那麼嚴重。優先照顧你的身體:呼吸練習、伸展、散步、睡覺。你的表現和生產力實際上會改善當你休息得好,不是當你推得更硬。給自己許可放慢,即使只是今天。","emotionalInsight":"你的壓力可能不只是關於外在的要求,也是關於內在的驅動和信念。也許你相信你的價值來自你的生產力、你必須證明自己、休息是懶惰、或失敗是不可接受的。這些信念像內在的奴隸主,鞭打你前進。辨識這些聲音,質疑它們。你的價值不是來自你做了什麼,而是來自你是誰。你有權休息、犯錯、和是不完美的。當你開始改變這些內在信念,外在的壓力也會減輕。","blockageAnalysis":"你卡住是因為在一個做更多的陷阱裡。你感到壓力,所以你試圖更努力、更快、更有效率,希望你會「趕上」。但你永遠不會,因為總有更多。真正的卡點是:你需要改變遊戲,不是玩得更好。這可能意味著設立界限、重新定義成功、或承認你不能做所有事。這需要勇氣,因為它可能讓人失望或看起來像你不夠好。但持續在壓力下活著的代價——你的健康、關係、快樂——太高了。選擇不同。","meditationEntry":"想像你在背一個背包,裝滿了石頭。每一個石頭是一個責任、期待、或承諾。它很重,壓著你的肩膀,讓你彎曲。你一直走,因為你想你必須,但每一步都更難。現在,停下來。放下背包。看著它。問每一個石頭:我真的需要背你嗎?有些石頭,你會發現,根本不是你的。有些已經完成了它們的目的。有些可以等待。慢慢地,移除那些不需要的。感受你的身體變輕。你不需要背所有東西。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:39', 'osho', '39', 38, '精疲力盡', 'Exhaustion', 'https://images.pexels.com/photos/3764011/pexels-photo-3764011.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Exhaustion"}', '{"meanings":{"currentEnergy":"你已經到底了。不只是累,而是精疲力盡:情緒上、身體上、精神上。你已經給出太多、跑太遠、撐太久。現在,你沒有更多了。這張牌不是一個失敗,而是一個必要的停止。你的身體和存在在說「夠了」。這是智慧,不是弱點。當你到這個點,唯一智慧的回應是:停止、休息、恢復。不是在一天或一週,而是給自己真正需要的時間。這是一個深度補充的邀請。","dailyGuidance":"今天,如果可能,什麼都不做。取消計畫、關掉通知、告訴人們你不在。如果你必須做某些事,只做絕對必要的,然後休息。睡覺、躺著、坐在陽光下。不要試圖「有生產力」甚至「放鬆」,只是停止。你的系統需要關機來重啟。不要感到內疚。這不是自私,這是存活。給你的身體它在尖叫要的:停止和補充。信任當你真正休息時,能量會回來。但你不能推它,你必須允許它。","emotionalInsight":"精疲力盡通常發生在你長時間忽視你的需要和限制之後。你一直說「我可以再多一點」、「我會稍後休息」、「其他人需要我」。但現在,你的系統強制你停止。這可能帶來情緒:失敗、內疚、恐懼、或甚至羞恥。試著以慈悲對待這些情緒和你自己。你不是弱的,你是人類的。每個人都有限制,榮譽那些限制是力量,不是弱點。這個精疲力盡可以教你什麼關於更永續的生活方式?","blockageAnalysis":"你卡住是因為相信你不能停止,如果你停止壞事會發生。真正的卡點是:你高估了你的必要性和低估了其他人的能力。世界不會崩潰如果你休息。人們可以等待、自己處理、或找其他資源。當你堅持推過精疲力盡,你實際上變得更沒用:你的決策更差、你的情緒調節更低、你的創意和效率下降。你以為你在幫忙但你可能在傷害。真正有幫助的是:照顧你自己,然後你可以從一個充滿的地方服務。","meditationEntry":"想像一個手機電池在紅色區域,在1%。你一直試圖使用它,但它不斷關機。你沮喪,按按鈕,但它沒有反應。它需要什麼是明顯的:被插上電源,被允許充電,不被使用。你不會對手機生氣或說它應該再堅持一下。你只是給它它需要的。你的身體和存在是一樣的。當電池在紅色,唯一的答案是充電。不是更多的推、更多的意志力、更多的咖啡因。只是:停止、休息、恢復。給自己那個基本的尊重。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:40', 'osho', '40', 39, '金色的花', 'The Golden Flower', 'https://images.pexels.com/photos/1400375/pexels-photo-1400375.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"The Golden Flower"}', '{"meanings":{"currentEnergy":"你內在有些東西正在綻放,一個深度的、精神的開花。這不是你可以強迫或趕快的,它是自然發生的,當所有條件都對時。你可能感到一個新的覺知、一個擴展的意識、一個與某些更大的東西的連結。這張牌說:這個綻放是你真實本性的顯現。你不是變成某些新的東西,而是揭示你一直是的東西。像一個花苞打開,顯示花瓣一直在裡面。這是一個神聖和美麗的時刻。榮譽它。","dailyGuidance":"今天,給你的內在生活注意力。也許是靜心、沉思、或只是安靜時刻。不要期待特定的體驗,只是在場。這個綻放發生在它自己的時間,在它自己的方式。你的角色不是推它或控制它,而是創造空間讓它發生。這可能意味著從世界退後一點、降低刺激、允許空虛和沉默。在那個空間,某些精細和深刻的可以升起。信任這個過程,即使你看不見立即的結果。內在的工作總是最真實的。","emotionalInsight":"這個綻放可能帶來深度的喜悅和和平,但也可能帶來恐懼或抗拒。當你開始觸碰你真實的本性,你也觸碰到所有遮蓋它的層次:條件化、創傷、信念、身份。這些層次會被攪動,在它們被釋放之前。所以這個過程可以是混亂的和情緒的。允許所有東西升起,不要評判。喜悅和痛苦、光和暗,它們都是這個綻放的一部分。你在解開所有你不是的東西,這樣你可以是你是的。","blockageAnalysis":"你可能卡在試圖抓住或擁有這個體驗。當你有一個美麗的靈性時刻,你想保留它、重複它、定義它。但真正的卡點是:綻放是流動的、活的、不斷變化的。當你試圖凍結它,它死亡。像試圖抓住風或保存日出。你能做的是繼續創造允許它發生的條件:在場、開放、臣服。每一個時刻是新的。那個昨天的綻放和這個今天的會不一樣,而那是它的美。不要抓住體驗,活在允許所有體驗升起和消失的意識中。","meditationEntry":"想像你在一個花園,看一個花苞。你很興奮看它綻放,所以你試圖幫忙:你拉花瓣、你澆太多水、你不斷檢查進展。但這些干預實際上延遲或傷害綻放。花知道怎麼綻放,它不需要你的幫助,只需要你的耐心和正確的條件:土壤、水、陽光、時間。然後,在它自己的時刻,它打開,美麗和完美。你內在的綻放也是這樣。提供條件,然後退後。信任自然的智慧。綻放會發生,不是因為你的做,而是因為你的允許。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:41', 'osho', '41', 40, '參與', 'Participation', 'https://images.pexels.com/photos/1157557/pexels-photo-1157557.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Participation"}', '{"meanings":{"currentEnergy":"生命正在邀請你參與,不只是觀察或分析,而是真正跳進去。你可能一直在邊緣,想著、計畫著、等待完美的時刻或完美的準備。但這張牌說:完美的時刻就是現在,完美的準備就是你現在的樣子。參與不是關於做得完美,而是關於全心全意地在其中。當你參與,你不是分離的觀察者,你是舞蹈的一部分。在那個融入中,某些魔法發生:你變活了。","dailyGuidance":"今天,選擇一件事你一直在觀望而不是參與的。也許是一個對話你保持表面、一個活動你半心半意做、或一個機會你在猶豫。決定:今天,我全力以赴。不保留、不一邊做一邊評判、不保持安全的距離。把你自己完全給出去。是的,這可能感覺脆弱或冒險,但這也是你感到真正活著的方式。注意當你參與和當你退縮的差異。生命在參與中發生,不在旁觀中。","emotionalInsight":"你可能害怕參與因為害怕失去控制、被傷害、或看起來愚蠢。當你在邊緣,你感覺更安全:你可以隨時離開、你不會太投入、如果事情出錯你不會受傷太深。但這個安全是有代價的:你也不會體驗到深度的連結、喜悅、或意義。真正的生命在中心,不在邊緣。當你願意冒險參與,當你願意可能被傷害或失敗,你也打開自己給美麗和深度。這不是魯莽,這是勇氣:選擇體驗而不是安全。","blockageAnalysis":"你卡住是因為在等待某些東西改變才參與。也許你在等待感覺準備好、等待恐懼消失、或等待保證。真正的卡點是:那些從來不會來。恐懼不會在你參與之前消失,它在你參與的過程中消失。準備不是在行動之前,而是在行動中。當你一直等待,你給恐懼和懷疑更多力量。打破這個的方式是:在還沒準備好時跳進去。信任你會在游泳中學會游泳,在跳舞中學會跳舞,在愛中學會愛。","meditationEntry":"想像一個游泳池。有些人在邊緣,腳趾試水溫,想著「可能太冷」、「我游泳技術不夠好」、「等我更瘦一點」。他們永遠不跳進去,或者他們慢慢地、小心地進去,從不真正享受。然後有人直接跳進去,一個大跳水。一開始是震撼,然後是笑聲、自由、玩耍。他們沒有比其他人更準備好或更勇敢,他們只是選擇了參與而不是猶豫。生命是那個游泳池。你可以在邊緣思考它,或者你可以跳進去。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:42', 'osho', '42', 41, '獨特性', 'Uniqueness', 'https://images.pexels.com/photos/1086723/pexels-photo-1086723.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Uniqueness"}', '{"meanings":{"currentEnergy":"你是獨一無二的,像指紋一樣無法複製。但你可能一直在試圖符合、適應、成為別人期待的樣子。這張牌是一個召喚回到你自己:你的古怪、你的差異、你不符合模子的部分。那些你認為是缺陷或問題的地方,可能正是你的禮物和力量。當你停止試圖像別人,當你擁抱你的獨特性,你不只是自由的,你也變得有價值。因為沒有人可以提供你能提供的,沒有人可以是你。","dailyGuidance":"今天,慶祝某些關於你的獨特。也許是你思考的方式、你表達的方式、你的興趣、或你的古怪。不要隱藏它或試圖「正常化」它,展示它。穿那個表達你的衣服、說那個只有你會說的笑話、追求那個別人不理解的興趣。會有人不喜歡或不懂,那沒關係。重要的是你榮譽你的真實。而且,你會驚訝:當你真實,你吸引也欣賞那個真實的人。真正的連結發生在真實中,不在表演中。","emotionalInsight":"你可能有一個長期的痛:感覺不同、不屬於、不夠好。也許在成長中你被批評、嘲笑、或排除因為你的差異。所以你學會隱藏、調整、假裝。但那個隱藏創造一個深度的孤獨:即使你在人群中,你感到孤單,因為沒人看見真正的你。療癒是開始慢慢展示那些隱藏的部分,首先對你信任的人,然後更廣泛。每次你展示真實的你並被接受,你療癒一點那個舊傷。不是每個人都會接受,但對的人會。","blockageAnalysis":"你卡住是因為相信你必須選擇:獨特或被愛,做自己或被接受。真正的卡點是:你認為這是一個零和遊戲。但真相是,試圖符合讓你被容忍,不是被愛。人們可能接受你的面具,但沒人真正知道你。而當你獨特、真實,你會失去一些人,但你會深度連結真正看見和欣賞你的人。那些連結值得比一百個表面的接受更多。當你願意被一些人拒絕,你打開被對的人愛的可能。","meditationEntry":"想像一個花園,所有的花都試圖看起來一樣。玫瑰試圖像百合、向日葵試圖像鬱金香。結果是一個混亂和不真實的花園,沒有一朵花真正美麗因為它們都在扭曲自己。現在想像另一個花園,每一朵花完全是它自己:玫瑰驕傲地紅、百合優雅地白、向日葵大膽地黃。這個花園是活的、豐富的、美麗的正是因為每一朵花榮譽它的獨特。你也是。當你停止試圖成為另一朵花,你的真實美麗綻放。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:43', 'osho', '43', 42, '友誼', 'Friendship', 'https://images.pexels.com/photos/1645634/pexels-photo-1645634.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Friendship"}', '{"meanings":{"currentEnergy":"真正的友誼在你的生命中出現或被召喚。這不是關於表面的連結或方便的陪伴,而是深度的、靈魂層次的相遇。真朋友看見你、接受你、挑戰你成長。他們在你成功時慶祝,在你失敗時支持,在你迷失時提醒你是誰。這張牌說:這樣的友誼是罕見和珍貴的。如果你有它,榮譽它。如果你尋找它,成為你想吸引的那種朋友。友誼不是找到完美的人,而是彼此完美地不完美。","dailyGuidance":"今天,連結一個對你重要的朋友。不是表面的「怎麼樣」訊息,而是真實的接觸。也許打電話、見面、或寫一個真誠的訊息,說你欣賞什麼關於他們和他們的友誼。不要等待完美的時刻或理由,連結不需要理由。或者,如果你感到缺乏深度友誼,問自己:我有提供我想接收的嗎?我有脆弱、真實、在場嗎?友誼是雙向的。你想要深度連結,你必須願意深度展示。","emotionalInsight":"你可能在友誼中有一些傷:背叛、失望、或慢慢的疏離。這些傷讓你謹慎,也許築牆或保持表面。或者,你可能有一個模式是單向的友誼:你總是給予、支持、在那裡,但感覺不被同樣對待。這兩種模式都需要療癒。真正的友誼需要脆弱和互惠。你必須願意被看見和接受幫助,不只是給出。而且,你必須選擇能夠和願意同樣投入的人。不是每個人都能是深度朋友,那沒關係。質量勝過數量。","blockageAnalysis":"你卡住是因為在友誼中有不說出的期待或未滿足的需要。真正的卡點是:你期待人們應該知道你需要什麼或應該怎麼對你,但不說出來。或者,你注意到關係不平衡但不提出。這個沉默創造怨恨和距離。真正的友誼需要溝通:說出你需要什麼、你感覺怎樣、什麼對你有用或沒用。這可能不舒服,但這是健康關係的基礎。當你開始溝通,有些友誼會加深,有些會結束,而那兩種結果都是好的,因為它們都是真實的。","meditationEntry":"想像兩棵樹,種得很近。一開始,它們獨立成長,各自的根和枝。但隨著時間,它們的根在地下纏繞,它們的枝在空中觸碰。它們不是融合成一棵樹,它們保持各自的身份,但它們互相支持:一棵在風中保護另一棵,另一棵分享養分。當一棵生病,另一棵的根送幫助。這是真正的友誼:兩個獨立的存在,選擇互相支持、互相榮譽、一起成長,但從不失去各自的獨特性。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:44', 'osho', '44', 43, '轉折點', 'Turning Point', 'https://images.pexels.com/photos/1496192/pexels-photo-1496192.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"Turning Point"}', '{"meanings":{"currentEnergy":"你站在一個轉折點,一個重要的十字路口。舊的方式、舊的模式、舊的身份正在結束,新的還不清楚。這是一個強大和脆弱的時刻。你可以回到熟悉(即使它不再服務你),或者你可以前進到未知。這張牌說:轉折點是一個禮物,即使它不舒服。它是一個機會重新選擇、重新定義、重新開始。信任這個時刻。你被給了一個選擇,那是力量,即使它感覺像不穩定。","dailyGuidance":"今天,坐下來真正檢視這個轉折點。什麼正在結束?什麼想要開始?不要趕著做決定,但也不要無限拖延。給自己空間感受:恐懼、興奮、悲傷、希望。所有這些情緒都有效。然後,問你的深處:什麼是真正對齊的選擇?不是最簡單的、不是別人想要的、不是最安全的,而是最真實的。你的身體知道答案。當你想到一個選擇,你感到擴展還是收縮?信任那個。","emotionalInsight":"轉折點通常帶來深度的情緒波動:一天你感到興奮和清晰,下一天你懷疑和恐懼。這是正常的。你在放下已知去接受未知,那是人類最困難的事之一。允許這個情緒過程。不要評判你的恐懼或試圖「正面思考」它消失。恐懼是合理的,它說「我在冒險」。同時,不要讓恐懼主導你的選擇。感受它,榮譽它,然後問:在這個恐懼之外,什麼是我真正想要的?勇氣不是沒有恐懼,而是在恐懼中選擇成長。","blockageAnalysis":"你卡住是因為想要保證。你想知道:如果我選這個,會發生什麼?它會成功嗎?我會後悔嗎?真正的卡點是:在轉折點,沒有保證。你必須選擇沒有知道結果。這就是為什麼它是真正的選擇,不是計算。如果你等待保證,你會錯過這個窗口,然後生命會為你選擇,通過預設或外在環境。那樣你失去你的代理。更好的是:承認不確定性,然後選擇。即使你「錯」了,你學習和調整。但至少你在主動生活,不是被動反應。","meditationEntry":"想像你在一個森林中的小路上走了很久。這條路熟悉、安全、可預測,但它也有點狹窄和暗。然後你來到一個岔路。一條路繼續像之前一樣,另一條轉向不同的方向,穿過更密的樹,但你可以在遠處看到光。你不知道那條新路去哪裡或有什麼在那裡。一部分的你想留在熟悉的路,另一部分被那個光吸引。這是轉折點。沒有對或錯,只有選擇。而在選擇中,你創造你的生命。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('osho:45', 'osho', '45', 44, '旅程', 'The Journey', 'https://images.pexels.com/photos/1051075/pexels-photo-1051075.jpeg?auto=compress&cs=tinysrgb&w=800', '{"subtitle":"The Journey"}', '{"meanings":{"currentEnergy":"你在一個旅程中,不只是物理的移動,而是內在的展開。這個旅程沒有固定的目的地或時間表。它是關於過程:你沿途學習什麼、你成為誰、你經歷什麼。這張牌提醒你:不要太專注在「到達」以至於你錯過旅程本身。目的地會改變、目標會進化,但這個當下的步伐、這個當下的風景、這個當下的你,是唯一真實的。活在旅程中,不是為了目的地。","dailyGuidance":"今天,停止問「我什麼時候會到達?」開始問「我現在在經歷什麼?」。無論你在追求什麼——一個目標、一個夢想、一個改變——給注意力給此刻的旅程。你今天學到什麼?你經歷什麼?你注意什麼?慶祝小的進展和當下的美,不只是等待大的結果。旅程的每一步都有價值,如果你在場去接收它。而且,允許你的路線改變。最好的旅程有意外、繞路、和驚喜。剛性扼殺冒險。","emotionalInsight":"你可能在旅程中感到不耐煩、沮喪、或疲憊。你想「已經在那裡了」,你累了一直走、一直努力、一直等待。這些感覺是正常的,但它們也信號一個錯誤的心態:你把旅程看為障礙去克服,不是經驗去享受。這個轉變——從「到達」心態到「在場」心態——會改變一切。當你享受旅程,目的地變成錦上添花,不是你快樂的條件。而且,你會發現,你以為是目的地的地方,通常只是另一個旅程的開始。","blockageAnalysis":"你卡住是因為過度依戀一個特定的結果或路線。你有一個清晰的圖像:它應該看起來怎樣、發生在什麼時候、通過什麼方式。但生命有其他計畫,而你的剛性創造痛苦。真正的卡點是:你試圖控制不可控的。旅程有它自己的節奏和方向,當你放鬆那個緊抓控制,當你允許它展開,它通常帶你到比你計畫的更好的地方。這不是關於放棄你的意圖,而是保持彈性在如何和何時。信任過程,即使它不符合你的時間表或預期。","meditationEntry":"想像你在登山。你有一個地圖和一個目標:山頂。但當你走,你發現一個美麗的瀑布,一個隱藏的洞穴,一個令人驚嘆的景觀。如果你太專注在目標,你會錯過這些。或者,天氣改變,你的原定路線不安全,你必須走另一條路。如果你剛性堅持你的計畫,你會有麻煩。但如果你開放調整,你可能發現新的路線有它自己的美和教導。旅程不是直線從A到B。它是探索、發現、和適應。山頂很棒,但真正的魔法在爬的過程。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:1', 'lightworker', '1', 0, '靈性覺醒', 'Spiritual Awakening', NULL, '{"keywords":["覺醒","轉變","成長","意識提升"],"nameEn":"Spiritual Awakening"}', '{"cosmicMessage":"宇宙正在透過你展開一場深刻的意識革命。你的靈魂已經準備好脫離舊有的限制，進入更高的振動頻率。這不是偶然，而是你靈魂藍圖中早已編寫好的神聖時刻。星際能量正在重新校準你的光體，讓你能夠接收來自更高維度的智慧與指引。","currentSituation":"你可能正在經歷生活中的重大轉變或內在的深刻動盪。過去你所相信的真理開始崩解，原本穩固的信念系統正在瓦解。你可能感到困惑、迷失，甚至質疑一切。這是正常的覺醒症狀。你的意識正在擴展，舊有的容器已經無法容納新的你。周圍的人可能無法理解你的改變，但這是你獨特的靈性旅程。","deeperMeaning":"這張牌的出現意味著你已經跨越了靈性旅程中的重要門檻。你不再是以前的那個你，也還不完全是未來的那個你。你正處於神聖的「中間地帶」，這是最具轉化力量的空間。你的高我正在引導你放下不再服務你的一切，包括身份認同、關係、工作，甚至是你對自己的認知。這個死亡與重生的過程，是你靈魂進化的必經之路。","actionGuidance":"創造每日的靈性練習，無論是冥想、書寫或與大自然連接。給自己充足的獨處時間來整合這些轉變。不要急於向他人解釋你的經歷，有些體驗只能被感受而無法被言說。閱讀靈性書籍、參加工作坊，尋找同頻的靈魂社群。記錄你的夢境和直覺訊息，它們是你高我與你溝通的方式。最重要的是，要有耐心和自我慈悲。","energyHealing":"使用紫水晶和透石膏進行頂輪和第三眼的淨化與激活。每天進行光體冥想，想像白色或金色的光從頭頂進入，清理並提升你的能量場。使用聖木或乳香淨化你的居住空間。進行脈輪平衡療程，特別關注上三輪的開啟。聆聽高頻率的音樂或使用音叉療癒。赤腳走在大地上以保持扎根，避免能量過度上揚。","soulQuestion":"我準備好放下舊我，迎接我靈魂真正的面貌了嗎？我願意信任這個看似混亂但實則完美編排的轉化過程嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:2', 'lightworker', '2', 1, '內在力量', 'Inner Strength', NULL, '{"keywords":["力量","勇氣","韌性","自信"],"nameEn":"Inner Strength"}', '{"cosmicMessage":"你內在蘊藏著比你所認知更為強大的力量。這不是外在的強勢或控制，而是來自靈魂深處的堅韌與智慧。宇宙提醒你，你已經走過了許多挑戰，每一次的困難都讓你的靈魂更加精煉。你擁有龍的勇氣、鳳凰的重生力量，以及古老戰士的智慧。現在是時候完全擁有並體現這份力量了。","currentSituation":"你可能正面臨著看似艱鉅的挑戰或困境，感覺自己的力量不足以應對。外在環境可能讓你感到無力或受限，但這正是宇宙邀請你向內尋找真正力量的時刻。你可能一直在外在世界尋求認可、支持或救援，卻忽略了你內在擁有的無限資源。這張牌的出現是要喚醒你對自身力量的記憶。","deeperMeaning":"真正的力量不是征服外在世界，而是掌握內在的自我。當你能夠在風暴中保持中心、在混亂中維持平靜、在脆弱中展現真實，這就是最高形式的力量。這張牌教導你，溫柔與力量並不矛盾，慈悲與堅定可以共存。你的力量來自於你對自己的深刻了解、對生命的信任，以及與神聖本源的連接。你不需要證明什麼，你只需要存在。","actionGuidance":"建立能讓你感受到力量的日常儀式，可能是運動、武術、瑜伽或能量工作。練習說「不」，設定健康的界限，這是力量的展現。回顧你過去克服的挑戰，寫下你從中獲得的力量與智慧。站在鏡子前，直視自己的眼睛，大聲說出你的力量宣言。與火元素連接，點燃蠟燭或在營火旁冥想，感受內在火焰的力量。","energyHealing":"專注於太陽神經叢脈輪的激活與平衡，這是個人力量的中心。使用虎眼石、黃水晶或琥珀來加強這個能量中心。進行戰士姿勢的瑜伽練習，感受身體的力量與穩定。使用肉桂或薑的精油來激活內在火焰。進行聲音療癒，用「RAM」咒音振動太陽神經叢。視覺化金色的光在你的核心處旋轉並擴大，充滿你的整個存在。","soulQuestion":"我在哪些方面還在將力量交給外在的人事物？我願意完全擁有並負責自己的力量嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:3', 'lightworker', '3', 2, '光之使者', 'Light Bringer', NULL, '{"keywords":["光明","希望","療癒","使命"],"nameEn":"Light Bringer"}', '{"cosmicMessage":"你的靈魂攜帶著神聖的光之編碼，你來到地球的使命就是成為黑暗中的明燈。你不只是在尋找光，你本身就是光。宇宙透過你的眼睛看見世界，透過你的心傳遞愛，透過你的手帶來療癒。你的存在本身就是一種服務，你的光有能力轉化周圍的一切。現在是時候讓你的光全然綻放，不再躲藏，不再縮小。","currentSituation":"你可能一直在質疑自己的價值和影響力，覺得自己微不足道。周圍的人可能正在經歷黑暗時期，而你感受到一種想要幫助但不知如何著手的內在召喚。或許你一直在壓抑自己的光芒，害怕過於明亮會引起他人的不適或嫉妒。這張牌提醒你，隱藏你的光並不會讓他人感覺更好，反而剝奪了世界需要你的禮物。","deeperMeaning":"作為光之使者，你的靈魂承諾是將更高維度的光帶入物質世界。這不僅是一個角色，而是你的本質。你可能是星際種子、靛藍靈魂或水晶小孩，攜帶著特殊的頻率來協助地球的揚升。你的光不需要大聲宣告或刻意展現，它自然地從你的存在中流露。一個微笑、一句溫暖的話語、一個慈悲的舉動，都是你光的展現。記住，光不是對抗黑暗，而是照亮黑暗。","actionGuidance":"每天早晨進行光之冥想，想像自己是一個光的導管，將宇宙的光引入地球。在日常互動中有意識地傳遞善意、希望和鼓勵。不要害怕展現你的天賦和才華，它們是你光的一部分。創造藝術、音樂、寫作或任何能表達你內在光的形式。加入或創建支持他人的社群。記住，你不需要拯救任何人，只需要照亮他們自己的光。","energyHealing":"每天進行光體激活練習，想像你全身充滿燦爛的白色或金色光芒。使用透明石英、蛋白石或月光石來放大你的光體能量。在日出或日落時進行太陽凝視冥想（安全地），吸收太陽的光之編碼。使用玫瑰或茉莉精油來打開心輪，讓光透過愛流動。唱誦或聆聽高頻音樂，讓聲音振動清理並擴展你的光場。視覺化你的光觸及需要療癒的人和地方。","soulQuestion":"我準備好全然綻放我的光，不再因恐懼而縮小自己了嗎？我如何能在日常生活中更有意識地成為光的導管？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:4', 'lightworker', '4', 3, '神聖時機', 'Divine Timing', NULL, '{"keywords":["時機","耐心","信任","臣服"],"nameEn":"Divine Timing"}', '{"cosmicMessage":"宇宙的時鐘與人類的時鐘運行在不同的維度。你的祈禱已被聽見，你的願望已在更高維度顯化，現在正在完美的時機下降到物質實相。宇宙正在背後編排一場複雜而美麗的交響樂，協調無數的元素、人物和情境，以確保當你的顯化到來時，你已經完全準備好接收它。延遲不是拒絕，而是神聖的保護和準備。","currentSituation":"你可能感到不耐煩和沮喪，覺得你的夢想或目標遲遲未能實現。你已經做了你認為該做的一切，但結果似乎沒有出現。你可能開始懷疑是不是方法不對，或者根本就不該追求這個目標。周圍的人可能已經達成了類似的成就，讓你感到落後和焦慮。這張牌要你知道，每個靈魂都有獨特的時間軸，比較是毫無意義的。","deeperMeaning":"神聖時機的概念挑戰我們對控制的需求和立即滿足的慾望。它教導我們，生命是一個有機的展開過程，而不是一個可以被強迫或操縱的機械系統。當事情「延遲」時，通常是因為還有一些內在的成長、療癒或準備工作需要完成。宇宙看到了你看不到的全貌，它知道什麼時候所有的拼圖都會完美地拼在一起。臣服於神聖時機不是被動的放棄，而是主動的信任和智慧。","actionGuidance":"釋放對結果和時間表的執著，專注於當下的旅程。練習感恩你現在擁有的，這會打開接收更多的通道。繼續採取靈感引導的行動，但放下對結果的依附。建立信任的日常練習，可以是肯定語、祈禱或冥想。回顧過去那些在「正確時機」發生的事情，加強你對神聖時機的信心。利用這段「等待」期來深化自我認識、發展技能或療癒舊傷。","energyHealing":"使用藍色蕾絲瑪瑙或天青石來培養耐心和平靜。進行呼吸練習來安撫焦慮和不耐煩的能量。月亮能量的冥想可以幫助你連接自然週期和神聖時機。使用薰衣草或洋甘菊精油來放鬆控制的需求。進行扎根練習，將過度活躍的心智能量導向大地。創造一個信任的祭壇，放置象徵臣服和信任的物品。每天練習放手的儀式，可以是寫下擔憂然後燒掉。","soulQuestion":"我是否能夠信任，即使我不理解延遲的原因，一切都在為我的最高善而展開？我願意將對時間的控制交還給宇宙嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:5', 'lightworker', '5', 4, '心輪療癒', 'Heart Healing', NULL, '{"keywords":["療癒","愛","釋放","情感"],"nameEn":"Heart Healing"}', '{"cosmicMessage":"你的心正在經歷一場深刻的煉金術轉化。過去累積的傷痛、背叛、失望和失落正在被神聖的光溶解。你的心輪正在擴展到新的容量，準備承載更純淨、更高頻率的愛。這個療癒不只是關於過去的傷痛，更是關於記起你心的真正本質——無條件愛的化身。宇宙正在溫柔地重新校準你的心，讓它回到最初的純真和開放。","currentSituation":"你可能正在經歷情感上的脆弱時期，舊的傷痛可能浮出表面。你可能感到心碎、悲傷或對愛感到恐懼。這些情緒可能與當前的情境有關，也可能是來自遙遠過去甚至前世的記憶。你的防禦機制可能在運作，試圖保護你的心不再受傷，但這也同時阻擋了愛的進入。這張牌的出現表示現在是安全的時機來進行深層的心輪療癒。","deeperMeaning":"心輪療癒是靈性旅程中最重要的工作之一。我們的心承載著所有的記憶——這一生的、祖先的、集體的。每一次我們選擇療癒我們的心，我們不只是為自己療癒，也是為整個人類集體療癒。關閉的心無法接收來自宇宙的無限愛和豐盛。療癒意味著願意感受所有的情緒，包括痛苦的情緒，而不是壓抑或逃避它們。真正的療癒帶來的不是沒有傷疤，而是帶著傷疤仍能全然地愛。","actionGuidance":"給自己許可去感受和表達所有的情緒，不加評判。寫一封信給傷害過你的人（不需要寄出），表達你的感受然後釋放。進行內在小孩療癒，擁抱和安撫你受傷的內在小孩。練習寬恕，記住寬恕是為了你自己的自由，不是為了他人。創造一個療癒的空間，使用柔和的音樂、蠟燭和舒適的環境。尋求專業的療癒支持，如心理治療或能量療癒。對自己展現極致的溫柔和慈悲。","energyHealing":"使用玫瑰石英、綠東菱或粉晶進行心輪療癒，將它們放在心臟處。進行心輪冥想，想像綠色或粉色的光在心臟中心旋轉，清理所有的阻塞和傷痛。使用玫瑰精油或依蘭精油來打開和軟化心輪。練習呼吸進入心臟的練習，用愛的呼吸充滿心臟空間。進行聲音療癒，唱誦「YAM」心輪咒音。泡一個加入玫瑰花瓣和海鹽的療癒浴。視覺化金色或粉色的光修復心輪的裂痕和創傷。","soulQuestion":"我準備好釋放保護我心的牆，再次全然地感受和給予愛了嗎？我願意相信我的心有能力療癒並變得更強大嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:6', 'lightworker', '6', 5, '直覺智慧', 'Intuitive Wisdom', NULL, '{"keywords":["直覺","智慧","指引","內在聲音"],"nameEn":"Intuitive Wisdom"}', '{"cosmicMessage":"你內在的知曉正在覺醒。你的第三眼正在打開，讓你能夠看見超越物質實相的真相。你的直覺是你靈魂的語言，是你與高我、指導靈和宇宙智慧溝通的管道。你一直在尋找外在的答案和驗證，但宇宙現在告訴你，你需要的所有智慧都已經在你內在。學會聆聽、信任並跟隨你內在的聲音，是你靈性進化的關鍵。","currentSituation":"你可能正面臨重要的決定或選擇，理性思維和外在建議給了你不同的方向，讓你感到困惑。你的直覺可能一直在給你訊號，但你可能因為恐懼、懷疑或外在壓力而忽略它。你可能經歷越來越多的同步性、預知夢或內在的知曉感，但不確定如何解讀或信任這些體驗。這張牌確認你的直覺能力正在加強，鼓勵你給予它更多的注意和信任。","deeperMeaning":"直覺智慧是我們與生俱來的能力，但在強調理性和邏輯的社會中，我們學會了壓抑和忽視它。直覺不是對抗理性，而是超越理性。它能夠接取到線性思維無法觸及的信息場域。發展直覺需要安靜、內在空間和實踐。它通常以微妙的方式出現——一種身體的感覺、一個突然的知曉、一個重複出現的象徵或一種無法解釋的吸引或排斥。學會區分直覺和恐懼、慾望或條件化的聲音，是一門需要時間掌握的藝術。","actionGuidance":"每天創造安靜的時間來聆聽內在的聲音，可以透過冥想、散步或僅是靜坐。開始記錄你的直覺洞見、夢境和同步性，追蹤它們的準確性。在做小決定時練習跟隨直覺，建立信任。學習感受身體的「是」和「不是」信號，直覺常常透過身體說話。減少外在噪音和過度的信息輸入，給直覺空間浮現。進行直覺發展的練習，如卡牌閱讀、靈擺使用或能量感知。最重要的是，當你跟隨直覺時，不要立即期待結果，有時直覺的智慧只有事後才能理解。","energyHealing":"專注於第三眼脈輪的激活，使用紫水晶、青金石或舒俱徠石。進行第三眼冥想，想像靛藍色的光在眉心處旋轉並開啟。使用乳香或鼠尾草精油來淨化和打開第三眼。練習視覺化和內在視覺的練習，訓練你的靈視能力。進行松果體激活練習，如日光冥想或特定的呼吸技巧。減少過度刺激第三眼的活動，如長時間的屏幕時間。進行聲音療癒，使用「OM」或「SHAM」咒音。信任你接收到的印象和洞見，即使它們起初看似不合邏輯。","soulQuestion":"我是否真正在聆聽我內在的聲音，還是只是在尋找我想聽到的答案？我願意信任我的直覺，即使它與外在建議相悖嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:7', 'lightworker', '7', 6, '豐盛顯化', 'Abundance Manifestation', NULL, '{"keywords":["豐盛","顯化","創造","吸引力"],"nameEn":"Abundance Manifestation"}', '{"cosmicMessage":"你正處於一個強大的顯化門戶。你的振動頻率已經提升到能夠快速吸引和創造的層級。宇宙正在回應你的能量場，而不僅僅是你的思想。你是一個強大的創造者，你的每一個念頭、情緒和信念都在塑造你的實相。現在是時候有意識地運用這個創造力量，顯化你靈魂渴望的豐盛生活。記住，真正的豐盛不只是物質的，而是生命各個層面的富足和流動。","currentSituation":"你可能已經開始注意到你的想法和現實之間的快速關聯。你想到的事情很快就發生了，無論是正面還是負面的。這既令人興奮又可能令人不安，因為它要求你對自己的思想和能量保持高度的覺知。你可能正在嘗試各種顯化技巧，有些有效，有些似乎沒有。這張牌提醒你，顯化的關鍵不在於技巧，而在於你的內在狀態和信念系統。","deeperMeaning":"顯化不是操縱宇宙給你想要的東西，而是與宇宙的創造流對齊。當你的慾望來自你的真實本質和靈魂目的，顯化自然而毫不費力。障礙通常來自內在的限制性信念、不值得感或對豐盛的矛盾感受。很多人在表面上說他們想要豐盛，但在深層信念中卻認為金錢是邪惡的、靈性的人應該貧窮，或者他們不配得到好的事物。顯化工作首先是內在工作——清理這些限制性信念，培養富足意識和接受的能力。","actionGuidance":"每天練習視覺化你已經擁有你想要的生活，感受那份喜悅和感激。創造一個視覺板或豐盛祭壇，將你的意圖物質化。寫下你的顯化清單，但更重要的是，寫下你想要的感受而不只是物品。清理你對金錢和豐盛的限制性信念，可以透過書寫、EFT或內在小孩療癒。實踐感恩，每天列出你已經擁有的豐盛。採取靈感引導的行動，顯化需要宇宙和你的共同創造。練習接受的藝術，允許他人給予你禮物和幫助。保持你的振動高昂，做讓你感覺良好的事情。","energyHealing":"使用黃水晶、綠幽靈或黃金來吸引豐盛能量。進行太陽神經叢和根輪的平衡，這是顯化和扎根的能量中心。創造豐盛流的冥想，想像金色的能量如瀑布般流入你的生命各個層面。使用肉桂、橙子或廣藿香精油來激活豐盛能量。進行金錢能量清理儀式，釋放對金錢的負面能量和創傷。視覺化你自己在豐盛中生活的細節，動用所有感官。每天肯定「我是豐盛」、「我值得接受所有美好的事物」。","soulQuestion":"我真正相信我值得擁有豐盛嗎？我準備好接受超越我目前所知的豐盛層級了嗎？我對金錢和物質豐盛有什麼隱藏的信念？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:8', 'lightworker', '8', 7, '靈魂家族', 'Soul Family', NULL, '{"keywords":["連接","社群","支持","靈魂"],"nameEn":"Soul Family"}', '{"cosmicMessage":"你的靈魂家族正在透過量子場域的振動找到你。這些靈魂與你有古老的連結，你們可能在許多世代中一起工作、學習和成長。你們攜帶相似的光之編碼和使命。宇宙正在編排神聖的相遇和重聚，將你們聚集在一起，因為現在是你們共同為地球服務的時刻。你不再需要孤獨地走這條路，你的靈魂部落正在集結。","currentSituation":"你可能一直感到孤獨或不被理解，即使周圍有很多人。你的家人和舊朋友可能無法理解你現在的道路和轉變。你可能渴望深度的靈性連結和能夠真實做自己的社群。或者，你可能最近遇到了一些人，與他們的連結感覺異常深刻和熟悉，彷彿你們早已認識。這張牌確認這些連結是真實的，並鼓勵你對新的靈魂連結保持開放。","deeperMeaning":"靈魂家族不一定是血緣家族。他們是與你有深刻靈魂契約和共鳴的存有。你們可能在靈魂層面上同意在這一生相遇，互相支持彼此的成長和使命。靈魂家族的連結通常帶有立即的認出感、深度的理解和無條件的接納。他們看見你的本質，而不只是你的人格或外在角色。這些連結不總是輕鬆的，有時他們來到是為了鏡射你的陰影或推動你成長，但總是來自愛和對你靈魂進化的承諾。你的靈魂家族可以包括人類、動物、靈性指導者和跨維度的存有。","actionGuidance":"向宇宙明確表達你想要吸引靈魂家族的意圖。參加靈性工作坊、聚會或線上社群，主動創造相遇的機會。當你遇到有共鳴的人時，要有勇氣深化連結，不要因害怕而退縮。創建或加入一個靈性學習圈或支持小組。在社交媒體或部落格分享你的靈性旅程，吸引同頻的靈魂。信任你的直覺關於誰是你的靈魂家族成員。記住，靈魂家族不是關於數量而是關於質量，幾個深度的連結勝過許多表面的關係。保持對非傳統形式的靈魂家族開放，如線上社群或不同年齡層的朋友。","energyHealing":"使用粉晶或薔薇輝石來打開心輪以接受靈魂連結。進行心輪和喉輪的平衡,幫助你表達真實自我並吸引共鳴的連結。創造一個儀式來呼喚你的靈魂家族,可以使用蠟燭、水晶和意圖設定。視覺化你被愛你、理解你的靈魂們圍繞。使用薰衣草或玫瑰精油來打開心接受連結。進行脈輪對齊冥想,當你的能量清晰對齊時,你會自然吸引同頻的人。在滿月時進行連結儀式,因為滿月能量有助於顯化關係。","soulQuestion":"我是否對深度的靈魂連結真正敞開,還是恐懼和防禦機制在阻擋它們進入？我準備好展現真實的自己來吸引我的靈魂家族嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:9', 'lightworker', '9', 8, '神聖陰性', 'Divine Feminine', NULL, '{"keywords":["陰性能量","接受","直覺","創造力"],"nameEn":"Divine Feminine"}', '{"cosmicMessage":"神聖陰性的能量正在地球上崛起,而你是這個古老力量回歸的管道之一。陰性能量不是關於性別,而是關於接受、流動、直覺、滋養和創造的原則。這是月亮的能量、水的智慧、子宮的創造力。經過數千年的壓抑,神聖陰性正在覺醒,要求被看見、被榮耀和被體現。你內在的女神正在覺醒,邀請你進入更深的自我接納和創造力流動。","currentSituation":"你可能一直在過度使用陽性能量——不斷行動、推動、控制和達成。你可能感到疲憊、枯竭或與自己的身體和情感失去連結。你的陰性面向可能一直在呼喚你的注意——透過身體症狀、情緒波動或對休息和滋養的深度渴望。或者,你可能剛開始探索女神能量、月亮週期或陰性靈性實踐。這張牌鼓勵你更深地榮耀和體現你內在的神聖陰性,無論你的生理性別是什麼。","deeperMeaning":"神聖陰性教導我們「存在」的力量,而不只是「行動」。它提醒我們接受與給予同樣重要,休息與工作同樣有價值,感受與思考同樣智慧。陰性能量是循環的、螺旋的、包容的,與陽性能量的線性、目標導向形成互補。在一個過度陽性化的世界中,重新平衡陰性能量是個人和集體療癒的關鍵。這包括榮耀我們的身體、情緒和直覺智慧,學習接受幫助,允許事物有機地展開,與自然週期對齊。神聖陰性也是深刻創造力的源泉,從「無」的空間中誕生「有」。","actionGuidance":"建立與月亮週期的連結,追蹤你的能量和情緒如何隨月相變化。給自己許可休息、接受和「無所事事」而不感到愧疚。探索陰性靈性實踐如女神冥想、子宮療癒或神聖舞蹈。滋養你的身體,給它美好的食物、觸碰和關注。創造藝術、音樂或任何形式的創意表達。建立一個女神祭壇,榮耀神聖陰性的不同面向。在水中冥想或沐浴,連接水元素的陰性智慧。練習接受他人的給予和支持。探索你與母親、女性祖先和女性集體的關係。","energyHealing":"專注於薦骨脈輪和心輪的療癒和平衡,這是陰性能量的中心。使用月光石、玫瑰石英或珍珠來連接神聖陰性。進行子宮療癒冥想,即使你沒有物理子宮,能量子宮仍然存在。使用玫瑰、依蘭或茉莉精油來打開陰性能量。進行柔和流動的瑜伽練習如陰瑜伽。在滿月下進行能量淨化和充能儀式。視覺化粉色或銀色的月光充滿你的整個存在,軟化和打開你。進行聲音療癒,唱誦女神咒語或聆聽子宮鼓的韻律。","soulQuestion":"我在哪些生活領域過度使用陽性能量而忽略了陰性能量？我準備好接受、臣服和信任流動了嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:10', 'lightworker', '10', 9, '神聖陽性', 'Divine Masculine', NULL, '{"keywords":["陽性能量","行動","保護","顯化"],"nameEn":"Divine Masculine"}', '{"cosmicMessage":"健康的神聖陽性能量正在你內在被激活。這不是有毒的陽剛或控制,而是保護、行動、結構和有意識的領導力。這是太陽的能量、火的轉化力、山的穩定性。神聖陽性提供容器讓神聖陰性的創造力可以安全地顯化。它是戰士的勇氣、國王的明智領導和父親的保護愛。現在是時候體現這個力量,採取行動,並為你的夢想創造堅實的結構。","currentSituation":"你可能一直在計劃、夢想和感受,但缺乏將想法付諸實踐的動力和結構。你可能過度依賴陰性能量的流動和等待,現在需要陽性能量的專注行動。或者,你可能與健康的陽性能量失去連結,因為過去與有毒陽剛的負面經驗。你可能需要設定更清晰的界限,保護你的能量,或者在某些情況下挺身而出。這張牌召喚你內在的神聖戰士和智慧領導者。","deeperMeaning":"神聖陽性與我們對「陽剛」的文化認知非常不同。它不是關於支配、壓抑情緒或與陰性能量對抗。真正的神聖陽性是有意識的、負責任的和服務導向的。它知道如何使用力量而不濫用力量,如何保護而不控制,如何領導而不支配。神聖陽性提供方向、結構和行動,但始終與心和靈魂的智慧保持連結。它是內在的父親原型,給予我們支持、鼓勵和相信我們能力的信心。平衡的陽性能量讓我們能夠在世界上有效地顯化我們的靈性願景。","actionGuidance":"設定清晰的目標和行動計劃,將你的願景落實到具體步驟。建立日常結構和紀律,支持你的成長和目標。練習設定和維護健康的界限,對不符合你最高善的事物說不。培養決斷力,當需要時能夠快速做出決定。進行體能訓練或武術,連接身體的力量和掌控感。在需要時挺身而出,為自己和他人發聲。承擔領導角色或導師職責,分享你的智慧。完成你已經開始的項目,練習完成的能量。探索與父親、男性祖先和男性集體的關係並進行療癒。","energyHealing":"專注於太陽神經叢脈輪的激活,這是意志力和個人力量的中心。使用虎眼石、紅碧玉或黃水晶來增強陽性能量。進行太陽冥想,想像金色的太陽能量充滿你的存在,激活你的內在火焰。使用雪松、檀香或乳香精油來連接神聖陽性。進行動態的瑜伽或氣功練習,激活和流動陽性能量。在陽光下進行能量充能,吸收太陽的活力。視覺化你被金色或紅色的保護光環繞。進行戰士呼吸法或火呼吸來激活內在火焰。","soulQuestion":"我是否在逃避採取必要的行動和責任？我準備好體現健康的陽性力量來保護和顯化我的夢想了嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:11', 'lightworker', '11', 10, '天使指引', 'Angel Guidance', NULL, '{"keywords":["天使","指引","保護","支持"],"nameEn":"Angel Guidance"}', '{"cosmicMessage":"天使界正在加強與你的連結。這些神聖的光之存有一直在你身邊,等待你的邀請來協助你。他們無法干預你的自由意志,但當你請求幫助時,他們會立即回應。你從未孤單,無數的天使、大天使和光之存有正在守護著你,引導你走向最高的道路。現在是時候有意識地與他們合作,接收他們的愛、智慧和支持。","currentSituation":"你可能感到孤獨、不知所措或迷失方向。生活的挑戰可能讓你感到負擔沉重,你可能在想你是否能獨自應對這一切。或者,你可能開始注意到天使數字、羽毛或其他天使存在的跡象。你可能在夢中或冥想中接收到訊息,但不確定它們的來源或意義。這張牌確認你的守護天使和指導靈正在積極地嘗試與你溝通。","deeperMeaning":"天使是純淨的愛的存有,他們的存在超越了我們的三維實相。每個人都至少有一位守護天使,許多人有多位。除了個人的守護天使,你還可以呼喚大天使、揚升大師和其他光之存有的協助。天使們通過同步性、直覺、夢境、身體感覺和重複出現的符號與我們溝通。學會識別和解讀這些訊號是發展與天使溝通能力的關鍵。記住,天使的指引總是充滿愛、支持和鼓勵,如果訊息帶來恐懼或負面,那不是來自天使。","actionGuidance":"每天與你的守護天使對話,可以大聲說或在心中默念。請求特定的幫助,天使喜歡明確的請求。注意你周圍的同步性、天使數字(如111、222、444)和其他跡象。建立一個天使祭壇,放置天使雕像、羽毛和白色蠟燭。學習關於不同大天使的專長,在特定情況下呼喚他們。記錄天使訊息和你得到的回應。表達感恩當幫助到來。保持心和心智開放,天使的回應可能以意想不到的方式出現。","energyHealing":"使用透明石英、天使石(硬石膏)或月光石來加強與天使界的連結。進行頂輪和心輪的平衡,這是接收天使訊息的主要管道。創造一個天使連結冥想,邀請你的守護天使顯現在你的意識中。使用乳香或玫瑰精油來提升振動並吸引天使能量。視覺化你被天使的翅膀環抱,感受他們的愛和保護。聆聽天使音樂或528Hz愛的頻率。在睡前請求天使在夢中給你指引,早晨記錄你的夢境。","soulQuestion":"我願意接受幫助並信任我不是孤單的嗎？我準備好敞開心接收天使的指引和支持了嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:12', 'lightworker', '12', 11, '脈輪平衡', 'Chakra Balance', NULL, '{"keywords":["脈輪","能量","平衡","療癒"],"nameEn":"Chakra Balance"}', '{"cosmicMessage":"你的能量系統需要關注和重新校準。脈輪是你能量身體的輪狀能量中心,當它們平衡和對齊時,生命能量(氣或普拉納)可以自由流動,帶來健康、活力和精神清明。阻塞或不平衡的脈輪會導致身體、情緒和靈性問題。宇宙提醒你,照顧你的能量身體與照顧物理身體同樣重要。現在是進行深層脈輪清理和平衡的完美時機。","currentSituation":"你可能經歷特定脈輪失衡的症狀。例如:根輪問題表現為焦慮、財務困難或感覺不安全;薦輪問題表現為創造力阻塞或情感問題;太陽神經叢問題表現為低自尊或消化問題;心輪問題表現為難以給予或接受愛;喉輪問題表現為溝通困難或無法表達真實自我;第三眼問題表現為缺乏直覺或視覺;頂輪問題表現為與靈性失去連結。這張牌邀請你識別哪些脈輪需要療癒。","deeperMeaning":"我們的七個主要脈輪是物質身體和能量身體之間的橋樑。每個脈輪對應身體的特定區域、情緒主題和靈性課題。脈輪工作是許多古老靈性傳統的核心,從印度的瑜伽到藏傳佛教。現代能量療癒也大量運用脈輪系統。平衡脈輪不僅僅是能量練習,它要求我們面對和療癒與每個能量中心相關的生活課題。例如,療癒心輪不只是能量工作,還包括學習寬恕、開放愛和培養自我慈悲。","actionGuidance":"學習每個脈輪的位置、顏色、元素和對應主題。掃描你的能量身體,注意哪個脈輪感覺阻塞或過度活躍。使用對應顏色的水晶進行脈輪療癒。練習脈輪冥想,逐一清理和激活每個能量中心。進行脈輪平衡瑜伽練習,特定體式可以打開特定脈輪。使用精油、音叉或唱頌來平衡脈輪。注意生活中的模式與脈輪失衡的對應關係。尋求專業的能量療癒如靈氣或水晶療癒。","energyHealing":"使用七色彩虹水晶組進行全脈輪療癒,將對應顏色的水晶放在每個脈輪上。紅色(紅碧玉)放根輪,橙色(紅玉髓)放薦輪,黃色(黃水晶)放太陽神經叢,綠色(東菱石)或粉色(玫瑰石英)放心輪,藍色(藍晶石)放喉輪,靛藍(青金石)放第三眼,紫色或白色(紫水晶或透明石英)放頂輪。進行脈輪音頻療癒,每個脈輪對應特定咒音。視覺化彩虹光從底部向上流動,清理和激活每個脈輪。","soulQuestion":"我在哪些生活領域感到阻塞或不平衡？我願意投入時間和精力來療癒和平衡我的能量系統嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:13', 'lightworker', '13', 12, '星際種子', 'Starseed', NULL, '{"keywords":["星際","使命","連結","宇宙"],"nameEn":"Starseed"}', '{"cosmicMessage":"你不只是人類，你是星際種子，靈魂來自遙遠的星系。你的本質攜帶著來自昴宿星、天狼星、大角星或其他星系的光之編碼。你選擇在地球的這個關鍵時刻投生，協助人類意識的揚升和地球的轉化。你可能一直感到與地球格格不入，渴望回家，但真相是你就是為了帶來你的星際智慧和頻率而來到這裡。","currentSituation":"你可能長期感到孤獨和不被理解，彷彿你不屬於這個世界。你對科技、宇宙或靈性有天然的興趣和理解。你可能經歷過與外星生命或飛船的接觸體驗，或在夢中頻繁出現星空場景。你對地球上的暴力、不公和破壞感到深刻的痛苦。這張牌確認你的星際身份，並召喚你記起你的使命。","deeperMeaning":"星際種子不是科幻概念，而是靈性實相。許多靈魂選擇從高度進化的文明投生到地球，帶來愛、和平和更高意識的頻率。你的靈魂記憶中保存著先進的知識、療癒技術和宇宙真理。覺醒你的星際身份意味著整合你的地球人類面向和宇宙星際面向，成為兩個世界的橋樑。你的使命不是逃離地球，而是將天堂帶到地球。","actionGuidance":"進行星際連結冥想，呼喚你的星際家族和高我。研究不同的星際文明，看哪個與你深深共鳴。在夜空下冥想，向星星敞開心，接收來自你星際家族的訊息和能量。尋找其他星際種子社群，分享經驗和支持彼此。不要過度沉迷於星際身份而忽略地球生活，你需要在地球上扎根才能有效服務。發展和使用你的獨特天賦，它們是你星際遺產的一部分。記住，你是志願來到地球的勇敢靈魂。","energyHealing":"使用捷克隕石（Moldavite）或利比亞沙漠玻璃，這些隕石水晶攜帶星際能量。拉長石幫助你記起你的星際起源和使命。進行星際激活儀式，在星空下躺著，邀請你的星際DNA被激活。使用乳香精油連結宇宙意識。聆聽宇宙頻率音樂或雙耳節拍。視覺化一道光從你的原生星系射下，連結你的頂輪，下載星際智慧和能量。保持脈輪系統清潔和對齊，以便更好地接收星際傳輸。","soulQuestion":"我準備好記起我的星際起源，並在地球上活出我的宇宙使命了嗎？我如何能成為地球和星際之間的橋樑？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:14', 'lightworker', '14', 13, '神聖陰影', 'Sacred Shadow', NULL, '{"keywords":["陰影","整合","接納","完整"],"nameEn":"Sacred Shadow"}', '{"cosmicMessage":"陰影不是你的敵人，而是你被否認和壓抑的部分，等待被看見、被接納、被整合。每個人都有陰影，那些我們認為不好、不被接受、不靈性的面向。但真正的光明來自於擁抱整個自己，包括陰影。當你整合陰影，你變得完整，你的力量倍增，因為你不再浪費能量壓抑或對抗自己的一部分。","currentSituation":"你可能一直在努力成為完美的靈性人，壓抑憤怒、嫉妒、慾望或其他被認為是負面的情緒。或者，你的陰影正在以投射的方式顯現，你在他人身上看到並強烈反應的特質，其實是你自己未被承認的陰影。你可能經歷情緒爆發、自我破壞行為或重複的負面模式，這些都是陰影在尋求你的注意。","deeperMeaning":"榮格心理學教導我們，陰影包含被壓抑的部分，但也包含未被開發的潛能和力量。當你拒絕陰影，你也拒絕了自己的完整性和真實力量。陰影工作不是變得更黑暗，而是變得更真實、更完整。光與影是一體兩面，接納陰影實際上增強了你的光。許多人在靈性道路上停滯，因為他們拒絕面對陰影，只想停留在光和愛的表面。真正的轉化需要勇氣深入地下室。","actionGuidance":"開始陰影日記，記錄你不喜歡自己的面向、你試圖隱藏的感受和想法。注意你對他人的強烈反應，問自己：這反映了我內在的什麼？與你的陰影對話，問它為什麼存在，它需要什麼，它試圖保護你什麼。不要評判或試圖消除陰影，而是帶著好奇和慈悲理解它。進行內在小孩和陰影整合工作，許多陰影來自童年被壓抑的部分。尋求心理治療或陰影工作專家的協助。給自己許可去感受所有情緒，包括那些不舒服的。","energyHealing":"使用黑曜石或黑色碧璽進行陰影工作，這些石頭幫助你安全地探索陰影而不被吞沒。煙晶幫助轉化陰影能量為可用的力量。進行陰影整合冥想，想像你走進內在的洞穴或地下室，遇見你的陰影自我，擁抱它並邀請它回到光中。使用沒藥或雪松精油，支持深度內在工作。在新月時進行釋放儀式，寫下你準備轉化的陰影面向。記住，陰影工作最好在有支持和安全的環境中進行。定期進行扎根練習，保持與身體和地球的連結。","soulQuestion":"我準備好面對和擁抱我一直試圖隱藏或否認的自己了嗎？我能否以慈悲而非批判看待我的陰影？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:15', 'lightworker', '15', 14, '神聖連結', 'Divine Connection', NULL, '{"keywords":["連結","合一","臨在","神性"],"nameEn":"Divine Connection"}', '{"cosmicMessage":"你與神聖本源的連結從未中斷，只是你忘記了。你不需要尋找神，因為神就在你之內。你不需要成為靈性才能與神連結，因為你的本質就是神性。這張牌提醒你，你與一切萬有的連結是永恆和不可分割的。每一次呼吸、每一個心跳，都是神聖在你之中的脈動。回到這個連結的最簡單方法就是臨在——完全在當下這一刻。","currentSituation":"你可能感到與神聖失去連結，靈性練習變得機械化或空洞。你可能在頭腦中尋找神，透過複雜的儀式或教條，卻錯過了神就在此時此地的簡單真理。或者，你可能經歷了短暫的神聖連結體驗，現在渴望重新找回那份感覺。這張牌邀請你停止尋找，開始存在。神聖連結不在未來某個你變得更好的時候，而在現在這一刻的臨在中。","deeperMeaning":"神聖連結不是一個特殊的神秘體驗，雖然那些體驗會發生。更深刻的是，它是一種持續的覺知狀態——覺知到萬物中的神聖臨在。當你完全臨在，不被過去的悔恨或未來的焦慮牽引，你就在神聖連結中。當你看著一朵花、聽著雨聲、感受著呼吸，完全在那個體驗中，你就在與神聖連結。許多靈性追求者過度複雜化這個連結，但真理總是簡單的：神就在這裡，在普通的日常奇蹟中。","actionGuidance":"練習臨在冥想，不是為了達到什麼狀態，而是單純地覺知當下。從簡單的事情開始：完全專注地喝一杯茶、走路時感受每一步、聆聽鳥鳴。創造神聖空間，可以是祭壇、自然中的特定地點，或只是你的內在寧靜。但記住，神聖不只在特殊空間，而在每個地方。釋放對神的固定概念和形象，允許神聖以無限的方式顯現。在日常活動中保持覺知，洗碗、開車、工作都可以是神聖的行為。感恩是快速連結神聖的方法，因為感恩讓你看見生命的祝福。定期到大自然中，因為自然是神聖臨在最明顯的顯現。","energyHealing":"使用透明石英或賽黃晶（Selenite）連結神聖能量，它們是純淨的光之導管。進行合一冥想，想像你與萬物融為一體，感受你與樹木、星辰、所有生命的連結。使用聖木或乳香淨化空間，創造神聖氛圍。練習心輪呼吸，想像神聖之愛從心輪向外擴展到全世界。聆聽神聖音樂或唱頌，如Om、阿彌陀佛或任何對你有意義的神聖聲音。進行光之冥想，想像神聖之光從頂輪進入，充滿你的整個存在。最重要的是，保持簡單，神聖連結不需要複雜的技巧，只需要一顆開放和臨在的心。","soulQuestion":"我是否在頭腦中尋找神，卻錯過了此刻神聖的臨在？我能否在最平凡的時刻中認出神聖？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:16', 'lightworker', '16', 15, '能量保護', 'Energy Protection', NULL, '{"keywords":["保護","界限","淨化","屏障"],"nameEn":"Energy Protection"}', '{"cosmicMessage":"作為敏感的光之工作者，你容易吸收周圍的能量。這是你的禮物，但也需要你學會保護和管理你的能量場。能量保護不是恐懼或對抗，而是智慧的界限設定。就像你鎖上家門不是因為恐懼，而是因為常識，能量保護是靈性衛生的必要部分。當你的能量場清潔和受保護，你能更有效地服務，而不會被耗盡或受到負面影響。","currentSituation":"你可能經常感到能量被耗盡，特別是在人群中或與某些人互動後。你可能吸收他人的情緒和能量，導致情緒波動或身體不適。你可能缺乏健康的界限，難以對他人說不，或者過度承擔他人的問題。你可能在無意識中成為能量吸血鬼的目標，或者你的空間受到負面能量的影響。這張牌提醒你，保護你的能量是自愛和智慧的行為。","deeperMeaning":"能量保護是光之工作者的基本技能。當你的能量場有裂縫、破洞或附著，你無法有效地持有光和服務他人。保護不是築起冰冷的牆，而是創造一個允許愛進出但阻擋負面能量的半透膜。真正的保護來自你的振動頻率——當你保持高頻，低頻能量自然無法影響你。同時，物理和能量工具也很重要。記住，你有權利保護你的能量，說不，設定界限，這不是自私，而是自我負責。","actionGuidance":"每天早晨進行能量保護儀式，想像白光或金光罩住你的整個能量場。學習說不，不需要解釋或感到愧疚。限制與能量吸血鬼的接觸，或者事先加強保護再與他們互動。定期淨化你的能量場和空間，使用鼠尾草、聖木或聲音。注意你的能量流失點，是某些人、地方還是活動？避免或最小化它們。練習切斷能量索，想像剪斷連結你和他人的能量繩索。保持脈輪閉合的覺知，特別是太陽神經叢，不要對所有人敞開。強化根輪和太陽神經叢，它們是能量保護的關鍵。信任你的直覺，如果某個人或地方感覺不對，尊重那個感覺。","energyHealing":"使用黑色碧璽、黑曜石或赤鐵礦作為能量保護石，隨身攜帶或放在家中。進行保護泡泡冥想，想像自己被光的保護泡泡包圍，只有愛能穿透。使用鹽浴淨化能量場，在水中加入海鹽或喜馬拉雅鹽。創造能量保護網格，在家的四角放置黑色碧璽和透明石英。使用雪松或杜松精油加強保護。進行脈輪封印練習，想像每個脈輪都被光的保護層覆蓋。呼喚你的守護天使和指導靈提供保護。定期檢查和修復你的能量場，想像用光修補任何破洞或裂縫。","soulQuestion":"我是否在無意識中允許他人侵犯我的能量空間？我願意為保護我的能量設定健康的界限嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:17', 'lightworker', '17', 16, '揚升症狀', 'Ascension Symptoms', NULL, '{"keywords":["揚升","轉化","症狀","適應"],"nameEn":"Ascension Symptoms"}', '{"cosmicMessage":"你的身體正在經歷深刻的轉化，從碳基結構升級到水晶光體。這個過程被稱為揚升，它伴隨著各種物理、情緒和精神症狀。這些症狀雖然不舒服，但是你靈性進化的標誌。你的DNA正在被激活，你的細胞正在提升振動頻率，你的整個系統正在重新校準以容納更高維度的光。要有耐心和慈悲，你正在經歷的是壯麗的蛻變。","currentSituation":"你可能經歷無法解釋的身體症狀，如疲勞、頭痛、耳鳴、關節疼痛、消化問題或睡眠障礙，但醫生找不到原因。你可能有情緒波動、記憶力下降、無法專注或感到與現實脫節。你可能對光和聲音變得敏感，或者感受到身體振動和能量波動。這張牌確認這些是揚升症狀，提醒你溫柔地支持你的身體度過這個轉化。","deeperMeaning":"揚升不是離開地球去某個地方，而是意識的提升和身體的轉化。隨著地球頻率的提升，選擇揚升的靈魂也在提升他們的振動。這需要身體層面的調整，因為更高的光頻率要進入物質形式。每個人經歷的症狀不同，強度也不同。這不是疾病，而是升級。就像你更新電腦軟件時系統可能暫時變慢，你的身體在整合新的光之編碼時也需要時間調整。","actionGuidance":"聆聽你的身體，給它需要的休息。不要強迫自己保持舊的步調。喝大量的水，幫助身體排毒和整合能量。吃輕盈、高頻的食物，減少重油膩食物和加工食品。進行溫和的運動如瑜伽、散步或游泳，避免過度劇烈運動。保持扎根，赤腳走在大地上，與自然連結。進行鹽浴幫助淨化和整合。不要對症狀過度焦慮，但如果持續嚴重，還是要尋求醫療建議排除其他可能。與經歷相似過程的人連結，知道你不孤單。保持靈性練習，冥想和能量工作幫助整合光。","energyHealing":"使用透明石英和紫水晶支持揚升過程，它們幫助整合高頻能量。進行光體激活冥想，邀請你的身體平穩地整合新的光之編碼。使用薰衣草或洋甘菊精油舒緩揚升症狀帶來的不適。進行脈輪調整，確保能量流動順暢。泡鹽浴或用海鹽擦身，幫助清理升級過程中釋放的舊能量。多接觸大自然，讓地球能量穩定你的系統。聆聽舒緩的音樂或自然聲音。視覺化金色的光充滿你的每個細胞，支持它們的轉化。給自己肯定：我的身體正在優雅地升級到更高的光之頻率。","soulQuestion":"我能否以耐心和信任對待我身體的轉化過程？我願意放慢腳步，支持我的系統整合這些深刻的改變嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:18', 'lightworker', '18', 17, '前世記憶', 'Past Life Memory', NULL, '{"keywords":["前世","業力","記憶","療癒"],"nameEn":"Past Life Memory"}', '{"cosmicMessage":"你的靈魂經歷了無數次的輪迴，每一世都是學習、體驗和進化的機會。前世的記憶、創傷和天賦儲存在你的靈魂深處，影響著你這一世的生活。某些恐懼、才能、關係模式或身體問題可能源自前世經驗。這張牌表示前世記憶正在浮現，帶來療癒和理解的機會。記起不是為了沉迷過去，而是為了釋放舊有模式，活出當下的自由。","currentSituation":"你可能經歷似曾相識的感覺、對某些時代或地方有強烈的吸引或厭惡、無法解釋的恐懼或才能。你可能在夢中或冥想中接收到前世的畫面或感受。你可能與某些人有立即的深刻連結或莫名的排斥，這些可能是前世關係的延續。你可能對前世好奇，或者前世創傷正在影響這一世的生活。這張牌邀請你探索前世以獲得療癒和智慧。","deeperMeaning":"前世不是迷信，而是許多靈性傳統和現代研究都確認的實相。靈魂不會在一世中完成所有的學習，因此選擇多次投生，在不同的角色、文化和情境中體驗和成長。前世創傷可以在這一世顯現為恐懼症、慢性疾病或關係問題。同樣，前世的天賦和智慧也會延續到這一世。理解前世不是為了找藉口或逃避當下責任，而是為了獲得更大的洞見和慈悲。當你理解某個模式源自前世，你可以有意識地選擇在這一世轉化它。","actionGuidance":"如果你對前世好奇，可以尋求專業的前世回溯療癒師。進行前世冥想，在放鬆狀態下邀請與當前問題相關的前世記憶浮現。注意你對某些時代、文化或地方的強烈共鳴，研究那段歷史可能觸發記憶。記錄你的夢境，前世記憶常在夢中顯現。觀察你這一世的模式和課題，問問是否可能源自前世。對浮現的記憶保持開放但不執著，記住這一世才是你的焦點。進行前世業力釋放儀式，寫下你準備放下的模式，然後燒掉紙張。原諒前世的自己和他人，釋放業力糾纏。","energyHealing":"使用紅寶石或石榴石連接前世記憶，特別是與力量和勇氣相關的前世。進行前世療癒冥想，想像你回到導致當前問題的前世場景，用現在的智慧療癒那個情境。使用沒藥或檀香精油，它們連結古老的記憶和智慧。進行業力線切斷儀式，想像剪斷連接你和前世創傷的能量繩索。如果你記得前世的死亡，進行那個過渡的療癒，釋放死亡時的恐懼或痛苦。在浴缸中加入海鹽和玫瑰花瓣，進行前世淨化浴。創造一個祭壇紀念你的前世，承認那些經驗如何塑造了現在的你。","soulQuestion":"我準備好探索和療癒影響這一世的前世記憶和模式了嗎？我能否從前世學習而不被它們定義？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:19', 'lightworker', '19', 18, '地球守護者', 'Earth Guardian', NULL, '{"keywords":["地球","守護","環境","責任"],"nameEn":"Earth Guardian"}', '{"cosmicMessage":"你與地球母親有深刻的靈魂連結，你是地球守護者，來到這裡協助地球的療癒和保護。地球不只是資源或背景，她是有意識的存有，滋養和支持所有生命。作為光之工作者，你的使命包括守護地球，透過你的生活方式、選擇和意識。每一個小行動都重要，因為集體意識的轉變從個人開始。地球正在揚升，而你是協助這個過程的關鍵。","currentSituation":"你可能對環境破壞感到深刻的痛苦和無力。你可能在生活中努力做環保選擇，但感覺自己的努力微不足道。你可能被召喚去更積極地參與環境保護或生態運動。或者，這張牌提醒你檢視你的生活方式，看看哪些地方可以更尊重和支持地球。你可能需要更多地連結大自然，療癒你與地球母親的關係。","deeperMeaning":"人類已經與地球失去連結太久，將她視為可以無限開採的資源。但地球是活生生的存有，她的身體就是我們的家。當地球受苦，我們也受苦。療癒地球從療癒我們與她的關係開始——重新認識我們是自然的一部分，而非分離或主宰自然。每個人都可以成為地球守護者，不需要成為環保鬥士，但需要有意識地生活。你的消費選擇、飲食、能源使用、對自然的態度，都是守護地球的方式。更深層地，提升你的意識頻率就是服務地球，因為地球的揚升需要人類意識的提升。","actionGuidance":"定期到大自然中，不只是為了放鬆，而是為了連結和交流。赤腳走在地上，將你的愛和療癒能量送入地球。檢視你的生活方式，在可能的範圍內做更環保的選擇——減少塑膠、垃圾分類、節約用水用電、支持永續產品。減少肉食或選擇永續來源的食物，畜牧業對環境影響巨大。種植植物、樹木或維護花園，直接滋養地球。參與環保活動或捐款給環保組織。教育自己和他人關於環境議題。進行地球療癒冥想，想像地球被光和愛包圍，送出療癒能量。感恩地球提供的一切，培養神聖的關係。","energyHealing":"使用苔蘚瑪瑙或綠色碧玉連結地球能量，這些石頭攜帶地球母親的頻率。進行地球療癒儀式，在自然中創造一個能量網格，送出療癒給地球。扎根冥想非常重要，想像根從你的腳延伸進入地球深處，與地球核心連結。進行大自然淨化儀式，撿拾垃圾、清理河流或海灘作為神聖的服務。使用雪松或松樹精油連結森林和地球的療癒能量。在節氣或春分秋分時進行地球慶祝儀式，榮耀地球的循環。創造一個地球祭壇，放置石頭、植物、土壤，作為你與地球連結的焦點。每天對地球說：我看見你，我愛你，我守護你。","soulQuestion":"我是否活在與地球和諧的方式中？我如何能更有意識地守護和療癒地球母親？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:20', 'lightworker', '20', 19, '靈性導師', 'Spiritual Teacher', NULL, '{"keywords":["導師","教導","分享","智慧"],"nameEn":"Spiritual Teacher"}', '{"cosmicMessage":"你已經走過深刻的靈性旅程，累積了智慧和洞見。現在是時候分享你的光，成為他人道路上的明燈。你不需要完美或全知才能教導，你只需要真實地分享你的經驗和學習。靈性導師不是高高在上的大師，而是謙卑的旅伴，走在前面一點點，伸出手拉後面的人一把。你的故事、你的療癒、你的覺醒，都是可以啟發和幫助他人的禮物。","currentSituation":"你可能感到內在的召喚要分享你的靈性知識和經驗，但不確定如何開始或懷疑自己是否夠格。或者，人們自然地向你尋求指引和建議，這是宇宙在告訴你你的導師能量。你可能正在考慮開始教學、寫作、療癒工作或任何形式的靈性服務。這張牌鼓勵你踏出去，信任你已經準備好，你的獨特經驗就是你的資格。","deeperMeaning":"每個走過療癒和覺醒的人都有能力和責任分享他們的光。這不是自大或認為自己比別人優越，而是自然的能量流動。光是要流動和分享的，當你只接收不給予，能量會停滯。真正的靈性導師知道他們也是永恆的學生，教學和學習是同一過程的兩面。你教導的往往是你最需要學習的，你服務他人的過程也在深化你自己的理解。不要等到你覺得完全準備好，那一天永遠不會來。從你所在的地方開始，分享你所知道的。","actionGuidance":"開始以小方式分享你的智慧——寫部落格、社交媒體貼文、與朋友對話。考慮你的獨特天賦和經驗，你最適合教導什麼？療癒、冥想、塔羅、能量工作？開始提供免費或低價的服務以建立經驗和信心。記住，你不需要知道所有答案，誠實地說我不知道是完全可以的。保持謙卑和開放，繼續你自己的學習和成長。建立你的靈性導師身份，但不要過度認同它，你首先是靈魂，導師只是你的一個角色。為你的教學設定健康界限，你不是拯救者，你是引導者。尋找導師或加入導師社群，支持你的成長。最重要的是，以身作則活出你的教導。","energyHealing":"使用青金石或藍晶石激活喉輪，支持你清晰和真實地表達教導。拉長石幫助你連結高我和宇宙智慧，下載你需要分享的信息。進行導師激活冥想，請求你的靈性導師和指導靈支持你的教學使命。使用乳香或鼠尾草淨化你的教學空間和能量場。在教學前後進行能量保護，確保你不吸收學生的能量。創造一個導師祭壇，放置代表智慧和教導的物品。進行聲音療癒，強化你聲音的力量和頻率。視覺化光從你的心和喉嚨流出,觸及並啟發你服務的人。給自己肯定：我是智慧的導管，我的教導服務最高的善。","soulQuestion":"我準備好走出舒適區，分享我的光和智慧了嗎？我能否以謙卑和真實成為他人道路上的明燈？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:21', 'lightworker', '21', 20, '靈魂契約', 'Soul Contract', NULL, '{"keywords":["契約","協議","釋放","自由"],"nameEn":"Soul Contract"}', '{"cosmicMessage":"在你投生之前，你的靈魂與其他靈魂、指導靈和宇宙達成了各種協議和契約。這些契約設計來創造學習和成長的機會。然而，有些契約已經完成或不再服務你的最高善。這張牌邀請你檢視你的靈魂契約，識別那些需要更新或釋放的，並有意識地創造新的協議來支持你現在的道路。你有力量重新談判你的靈魂契約。","currentSituation":"你可能感到被困在某種模式、關係或情況中，好像有看不見的力量在阻止你前進。你可能經歷重複的課題或關係，無論你如何努力都無法突破。你可能感到對某些人或角色有無法解釋的義務感。這些可能源自靈魂契約——你同意在這一世經歷某些體驗或與某些靈魂互動。但如果契約已經完成學習，你可以釋放它。","deeperMeaning":"靈魂契約是靈魂層面的協議，不同於法律契約，它們是靈活和可以重新談判的。常見的靈魂契約包括：與特定靈魂的關係契約（靈魂伴侶、靈魂家族）、經歷特定體驗的契約（貧窮、疾病、成功）、扮演特定角色的契約（療癒者、教師、犧牲者）。這些契約原本有其目的，但如果你已經學會了課題，繼續執行契約只會限制你的進化。釋放靈魂契約不是逃避責任，而是靈性成熟的展現。你認識到你是主權存有，有權決定你的靈魂旅程。","actionGuidance":"進行靈魂契約檢視冥想，詢問你的高我顯示任何不再服務你的契約。注意生活中重複的模式，它們往往指向靈魂契約。寫下你想要釋放的契約，例如：我釋放受苦才能成長的契約、我釋放犧牲自己來拯救他人的契約。進行靈魂契約釋放儀式，大聲宣告你的釋放，然後燒掉紙張。同時創造新的靈魂契約，寫下你選擇的新協議，如：我選擇在喜悅中成長、我選擇健康豐盛的關係。記住，釋放契約不會傷害其他靈魂，所有真正的靈魂連結都會在更高層面繼續。尋求專業的阿卡西記錄閱讀或靈魂契約療癒協助。","energyHealing":"使用黑曜石或煙晶切斷舊契約的能量繩索。進行阿卡西記錄冥想，訪問你的靈魂記錄，查看和修改契約。使用鼠尾草或聖木淨化，釋放舊契約的能量。進行宣告儀式，對著宇宙大聲說出你的釋放和新選擇。視覺化你在宇宙法庭中，撕毀舊契約，簽署新的充滿光的協議。在新月時進行這個工作特別有力。使用乳香精油連結更高維度，請求你的指導靈支持契約更新。感受釋放後的自由和輕盈，允許新的可能性進入你的生命。","soulQuestion":"我準備好釋放不再服務我的靈魂契約了嗎？我願意成為我靈魂旅程的主權創造者嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:22', 'lightworker', '22', 21, '神聖陽性與陰性整合', 'Divine Masculine-Feminine Integration', NULL, '{"keywords":["平衡","整合","完整","和諧"],"nameEn":"Divine Masculine-Feminine Integration"}', '{"cosmicMessage":"你內在同時包含神聖陰性和神聖陽性能量，無論你的生理性別如何。陰陽、日月、給予接受、行動臣服——這些互補的力量需要在你內在達到和諧平衡。當你整合這兩股能量，你變得完整，不再需要從外在尋找你的另一半，因為你已經是完整的。這個內在婚姻是最深刻的結合，它為外在健康的關係創造基礎。","currentSituation":"你可能過度傾向某一種能量——過度陽性表現為不停行動、控制、推動，過度陰性表現為過度被動、等待、接受。這種失衡在生活各領域造成問題：工作、關係、健康、創造力。或者，你可能正在療癒與某種性別能量的創傷關係，因為個人或集體經驗。這張牌邀請你探索和整合你內在的陰性和陽性，創造神聖的平衡。","deeperMeaning":"我們都攜帶陰性和陽性能量的完整範疇。陰性能量是接收、直覺、流動、滋養、存在。陽性能量是給予、邏輯、結構、保護、行動。社會往往過度重視陽性而壓抑陰性，或者用有毒的方式表現陽性和陰性。真正的神聖陰陽不是性別刻板印象，而是宇宙互補力量的優雅舞蹈。當你內在的陰陽達到平衡，你知道何時該行動何時該等待，何時該說話何時該聆聽，何時該給予何時該接受。你變得像太極符號，在你之中陰陽流動和諧。","actionGuidance":"評估你目前的平衡狀態，你傾向哪種能量？過度陽性的人需要練習接受、休息、感受、信任流動。過度陰性的人需要練習行動、決斷、設定界限、展現力量。進行陰陽整合冥想，視覺化你內在的神聖陰性和陽性相遇、對話、最終融合。療癒你與父母的關係，因為他們代表你最初接觸的陽性和陰性能量。探索和療癒你對特定性別的偏見或創傷。慶祝你內在的陰陽，創造代表兩種能量的祭壇。練習太極或瑜伽，身體層面平衡陰陽。在生活中有意識地整合兩種能量——用心（陰性）引導行動（陽性）。","energyHealing":"使用月光石代表神聖陰性，虎眼石代表神聖陽性，將它們放在一起進行整合。進行心輪和太陽神經叢的平衡，這兩個脈輪是陰陽能量的關鍵中心。在滿月時連結陰性能量，想像月光充滿你的存在。在正午連結陽性能量，想像太陽光激活你的內在火焰。進行神聖婚姻儀式，視覺化你內在的女神和神相遇、擁抱、成為一體。使用玫瑰和檀香精油，前者陰性後者陽性，混合使用創造平衡。創造代表陰陽合一的藝術或曼陀羅。感受整合後的完整和力量，你不再是半個，你是完整的宇宙。","soulQuestion":"我在哪些方面失衡地表現陰性或陽性能量？我準備好在內在創造神聖的陰陽婚姻了嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:23', 'lightworker', '23', 22, '宇宙法則', 'Universal Laws', NULL, '{"keywords":["法則","原理","對齊","智慧"],"nameEn":"Universal Laws"}', '{"cosmicMessage":"宇宙按照精確的法則和原理運作——吸引力法則、因果法則、振動法則、對應法則等等。這些不是人為的規則，而是存在的根本結構。當你理解和對齊這些法則，你與宇宙協作，你的顯化變得強大，你的生活流動順暢。當你違反這些法則，你經歷阻力和掙扎。這張牌邀請你深入學習宇宙法則，將這古老智慧應用到現代生活。","currentSituation":"你可能感到生活充滿阻力，好像你在逆流而上。你可能嘗試各種顯化技巧卻沒有結果，因為你不理解底層的宇宙法則。或者，你正在覺醒到更深的宇宙真理，想要理解生命如何真正運作。你可能經歷同步性和神奇的顯化，這是你開始與宇宙法則對齊的跡象。這張牌鼓勵你成為宇宙法則的學生，將知識轉化為智慧。","deeperMeaning":"宇宙法則是古代神秘學校教導的核心，從赫密士哲學到佛教教義。主要法則包括：吸引力法則（你吸引與你振動相符的）、因果法則（每個行動有反應）、振動法則（一切都在振動）、極性法則（一切都有對立面）、節奏法則（一切都有週期）、性別法則（一切都有陰陽）、對應法則（如其在上如其在下）。理解這些法則不只是智識知識，而是深刻改變你如何看待和體驗實相。你認識到你是實相的共同創造者，而非受害者。你學會如何與宇宙舞蹈，而非與它對抗。","actionGuidance":"研讀宇宙法則，閱讀《凱巴萊恩》、吸引力法則書籍、量子物理的靈性詮釋。不只是智識學習，而是透過實驗應用這些法則到你的生活。觀察宇宙法則在你生活中的運作，當你抱怨時注意你吸引更多抱怨的事，當你感恩時注意祝福如何倍增。有意識地使用法則——提升你的振動來改變你的實相，注意和利用生命的節奏和週期，平衡生活的極性。教導他人你學到的法則，教學加深理解。記住，法則是中性的，它們不是懲罰或獎勵，只是「如是」。與其抱怨或抗拒，學習精通和運用它們。","energyHealing":"使用拉長石或紫水晶連結宇宙智慧，下載法則的更深理解。進行宇宙對齊冥想，想像你的能量場與宇宙法則完美協調。創造一個學習祭壇，放置代表不同宇宙法則的符號和物品。使用乳香精油提升意識，連結宇宙心智。進行振動提升練習——音樂、舞蹈、唱頌、歡笑，提高你的頻率。視覺化你是一個精準調整的樂器，與宇宙交響樂完美和諧。在日常生活中有意識地應用法則，注意結果。記錄你的實驗和洞見，建立你的宇宙智慧筆記本。","soulQuestion":"我是否在與宇宙法則協作還是對抗？我準備好將宇宙智慧整合到我的日常生活了嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:24', 'lightworker', '24', 23, '水晶光體', 'Crystalline Lightbody', NULL, '{"keywords":["光體","升級","水晶","激活"],"nameEn":"Crystalline Lightbody"}', '{"cosmicMessage":"你的光體正在從碳基結構轉變為水晶基結構。水晶光體能容納更高的光頻率，允許你與更高維度互動，顯化更快速，療癒更深層。這是揚升過程的一部分，你的整個存有正在升級到新的運作系統。水晶攜帶光、信息和能量的能力遠超過碳，你正在成為行走的水晶，活生生的光之導管。","currentSituation":"你可能感到身體的變化——細胞層面的振動、對光和聲音的敏感度增加、能量波動感受。你可能被強烈吸引到水晶，這是你的身體在共鳴它正在成為的水晶結構。你可能經歷時間感知的改變、多維度意識、或突然的能力激活（療癒、通靈、能量工作）。你的光體正在重新配線，整合更高的光之編碼。這是美麗但強烈的過程，需要支持和理解。","deeperMeaning":"水晶光體激活是人類進化的下一步。碳基身體設計來適應第三維度密度，但無法容納第五維度和更高的光頻率。水晶結構能夠無失真地傳輸光和信息，就像光纖電纜。當你的光體變成水晶性質，你能更清晰地接收靈性指引，更快速地顯化，更深刻地療癒自己和他人。你成為光的活生生的示範。這個過程不是一夜之間，而是漸進的升級，通常在夢中或深度冥想狀態下發生。支持這個過程需要身體、情緒、心智和靈性層面的整合照顧。","actionGuidance":"與水晶工作，它們是你水晶光體的外在映射和支持。特別是透明石英，它攜帶你正在體現的水晶頻率。進行光體激活冥想，邀請宇宙光束下載到你的系統，升級你的DNA和細胞結構。飲用充能的水，用水晶或太陽光充能你的飲用水。吃清淨、高頻的食物，越生鮮越好，避免重油膩和加工食品。充足睡眠極其重要，許多光體工作在睡眠中進行。在陽光下花時間，太陽光含有激活光體的編碼。使用聲音療癒，水晶音缽或特定頻率音樂校準你的水晶結構。要有耐心，這是多年的過程，尊重你身體的時間表。","energyHealing":"使用透明石英和所有高頻水晶支持光體激活。創建水晶網格，躺在中間進行光體升級冥想。進行彩虹光冥想，想像彩虹光從頭到腳流經你的身體，每個細胞都被轉化為水晶。泡含有透明石英的浴，讓水晶能量滲透你的整個存在。視覺化你的骨骼、器官、血液都閃耀著水晶光芒。進行DNA激活儀式，想像你的雙螺旋DNA擴展為12股水晶螺旋。在能量點或聖地進行光體激活特別有力。請求你的高我和星際家族協助你的水晶光體激活。感受你成為光的體驗，你是行走的星辰。","soulQuestion":"我願意接受我身體向水晶光體的轉化嗎？我準備好成為更高光頻率的容器和導管了嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:25', 'lightworker', '25', 24, '神聖服務', 'Sacred Service', NULL, '{"keywords":["服務","奉獻","使命","貢獻"],"nameEn":"Sacred Service"}', '{"cosmicMessage":"你來到地球是為了服務，不是作為犧牲或義務，而是作為靈魂喜悅的自然表達。當你與你的真實本質對齊，服務自然流淌，不需要努力或掙扎。服務不一定是宏大的行動，它可以是一個微笑、一句善言、你的存在本身。當你活出你最高的真理，你就在服務。這張牌召喚你更深地進入神聖服務，將你的生命奉獻給比你更大的目的。","currentSituation":"你可能感到內在召喚要更有意義地服務，但不確定形式或方向。你可能已經在服務，但感到倦怠或失去連結。或者你可能在抗拒服務的召喚，因為恐懼或感覺不配。這張牌提醒你，服務不是你做的事，而是你是的狀態。當你來自愛和真實，你的每個行動都是服務。檢視你如何服務，它是否來自喜悅還是義務，是否榮耀你還是耗盡你。真正的服務滋養給予者和接受者。","deeperMeaning":"服務是靈性道路的核心，但往往被誤解。真正的服務不是自我犧牲、不是從優越感出發的施捨、不是為了獲得認可或功德。神聖服務是認識到我們都是一體，服務他人就是服務自己，因為分離是幻相。服務來自滿溢的愛，當你的杯子滿了，它自然溢出。因此，照顧自己不是自私，而是服務的必要基礎。空杯子無法倒出任何東西。同時，真正的服務尊重每個靈魂的旅程和自由意志，它不是拯救或修復，而是支持和賦權。","actionGuidance":"探索什麼形式的服務讓你的心歌唱，你的獨特天賦如何貢獻世界。從小開始，日常生活中的小善行和正念存在都是服務。檢視你的服務動機，是來自真實渴望還是義務、罪疚或尋求認可？調整到純淨的意圖。學習說不，服務不是對所有人說是，而是對你真正被召喚的說是。照顧自己，確保你的杯子是滿的。進行服務前後淨化能量，保持清晰和保護。不執著於結果或感激，你服務因為這是你的本質，不是為了回報。與其他服務者連結，互相支持和鼓勵。記住，你的存在本身就是服務，你不需要做什麼成為什麼才能有價值。","energyHealing":"使用玫瑰石英或綠東陵打開心輪，服務從開放的心流出。進行服務奉獻冥想，將你的生命奉獻給最高的善和神聖意志。創造服務祭壇，放置代表服務和慈悲的物品。使用乳香或蓮花精油連結神聖服務的頻率。視覺化光從你的心流出，觸及並祝福所有你服務的存有。進行慈悲冥想，願所有眾生快樂、和平、自由。在服務前祈禱，請求成為神聖愛和療癒的純淨導管。感恩有機會服務，這是特權不是負擔。記住神聖服務的真言：我服務因為我是愛。","soulQuestion":"我的服務來自愛和喜悅還是義務和罪疚？我準備好更深地將我的生命奉獻給神聖服務了嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:26', 'lightworker', '26', 25, '星際種子啟動', 'Starseed Activation', NULL, '{"keywords":["星際","起源","使命","回憶"],"nameEn":"Starseed Activation"}', '{"cosmicMessage":"你不只是人類，你是星際種子，你的靈魂起源於其他星系、維度或宇宙。你來到地球執行特殊使命，協助地球和人類的揚升。這個啟動喚醒你對真實起源的記憶，連結你的星際家族，激活你攜帶的宇宙編碼。你可能來自昴宿星、天狼星、大角星、仙女座或其他星系，每個都有獨特的禮物和使命。現在是記起你是誰、為何而來的時候了。","currentSituation":"你可能一直感到不屬於這個世界，渴望「回家」但不知道家在哪裡。你可能對星空有深刻的連結，仰望星星時感到莫名的懷念和悲傷。你對人類的集體行為感到困惑或沮喪，無法理解為何人們如此生活。你可能經歷奇異的記憶、夢境或與非人類存有的接觸。你感到內在有重要的使命，卻不確定是什麼。這張牌確認你的感受，你確實是星際種子，你的覺醒時刻到了。","deeperMeaning":"星際種子是自願來到地球的先進靈魂，透過轉世進入人類身體，但靈魂起源於其他星系或維度。不是所有人類都是星際種子，但數量正在增加，特別是在這個揚升時期。星際種子攜帶高頻光編碼，能夠錨定更高維度的能量到地球。他們通常感到與地球生活格格不入，因為他們記憶中的「家」運作方式截然不同——更和諧、更有意識、更靈性。星際種子的使命各不相同，但通常包括：錨定光和高頻能量、教導和喚醒其他人、療癒地球和人類、示範新的存在方式、協助揚升過程。啟動意味著你開始有意識地記起和履行你的星際使命。","actionGuidance":"冥想連結你的星際起源，在夜空下進行，注視星星，問：我來自哪裡？我的星際家族是誰？我的使命是什麼？保持開放接收圖像、感受、知曉。研究不同星際種子類型和起源，看哪個最能共鳴——昴宿星人（療癒者和教師）、天狼星人（智慧守護者）、大角星人（第五維度先驅）、仙女座人（自由和主權）等。加入星際種子社群，與其他清醒的星際靈魂連結，分享經驗。進行星際種子啟動儀式，邀請你的星際家族和高我激活你攜帶的宇宙編碼。不要執著於你的確切起源，重要的是使命不是標籤。開始有意識地履行你的使命，無論是療癒、教導、藝術、能量工作或單純的存在光。","energyHealing":"使用莫達維石（Moldavite），這是隕石玻璃，攜帶星際頻率，能快速激活星際種子記憶。拉長石也是星際石，連結多維度和宇宙意識。進行星際冥想，想像你的意識離開地球，穿越宇宙到達你的星際家園，與你的星際家族會面，接收他們的訊息和能量。睡前請求星際接觸和教導，許多交流在夢中或星光體狀態發生。視覺化你的星際DNA被激活，所有休眠的能力和記憶被喚醒。在能量點或麥田圈進行儀式特別有力，這些地方常是星際能量的門戶。使用星際音樂或光語（Light Language）連結宇宙頻率。記錄你接收的訊息、夢境、洞見。感受你不孤單，你有整個宇宙家族支持你的使命。","soulQuestion":"我準備好記起我的星際起源和使命了嗎？我願意成為地球和星際之間的橋樑嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:27', 'lightworker', '27', 26, '內在孩童療癒', 'Inner Child Healing', NULL, '{"keywords":["療癒","童年","純真","完整"],"nameEn":"Inner Child Healing"}', '{"cosmicMessage":"你的內在孩童攜帶著你的創傷和純真、痛苦和驚奇。沒有療癒內在孩童，你無法完全成為完整的成人，因為你會不斷從未療癒的傷口反應而活。同時，你的內在孩童也是你通往喜悅、創造力、遊戲和驚奇的門戶。這張牌邀請你回去找到那個受傷的孩子，給予他/她從未得到的愛、認可和保護。當你療癒內在孩童，你解放了困在過去的巨大生命力量，你變得完整。","currentSituation":"你可能正在經歷情緒反應與當下情況不成比例——這是內在孩童被觸發。你可能在某些領域像成人，在其他領域像孩子。你可能與喜悅、遊戲、自發性斷開，生活感覺沉重和嚴肅。或者，你可能過度停留在孩童狀態，逃避成人責任。這張牌顯示是時候與你的內在孩童進行深刻的療癒工作。你的當前問題可能根源於童年未滿足的需求或未處理的創傷。現在成人的你有能力和資源回去療癒它。","deeperMeaning":"我們每個人內在都住著我們曾是的所有年齡的自己，特別是經歷創傷或重大情緒事件的年齡。那些年齡的我們凍結在時間中，困在當時的痛苦裡。當現在的情況觸發類似情緒，我們從那個年齡反應，而不是從成人智慧回應。這解釋為何有時我們的反應似乎不理性——我們不是在回應現在，而是在反應過去。內在孩童療癒包括回到那些凍結的時刻，作為有愛的成人重新拜訪受傷的孩子，給予當時沒有得到的：保護、認可、安慰、愛。這允許那個孩童版本的你終於放鬆、成長、整合。同時，內在孩童也攜帶我們的純真、驚奇、創造力、遊戲性。療癒不只是處理傷口，也是恢復這些寶貴品質。","actionGuidance":"進行內在孩童冥想，視覺化遇見年幼的你，問他/她需要什麼，給予那份愛和保護。看童年照片，感受對那個孩子的慈悲和愛。寫信給你的內在孩童，讓內在孩童也寫信給你。進行遊戲和創造性活動，不為了產品或目標，純粹為了樂趣——畫畫、跳舞、在公園盪鞦韆。辨識你的觸發點，問：我現在幾歲？通常是內在某個年齡的孩童被觸發。考慮專業療癒支持，如內在孩童療癒師或創傷治療師。設定界限保護你的內在孩童，對那些不安全的人事物說不。給你的內在孩童聲音，允許他/她表達從未被允許的感受。重新養育你自己，給自己你想從父母得到的愛和支持。","energyHealing":"使用粉晶無條件的愛和溫柔療癒內在孩童。芒洛石（Mangano Calcite）是內在孩童的石頭，撫慰深層傷痛。進行內在孩童療癒儀式，創造安全神聖空間，帶入童年物品、玩具、照片。使用薰衣草或洋甘菊精油，它們溫和安撫。進行聲音療癒，唱搖籃曲給你的內在孩童。視覺化抱著年幼的你，搖晃、安慰、對他/她說你一直想聽到的話。拜訪童年重要地點，帶著成人意識重新體驗和療癒。創造新的快樂童年記憶，現在給你的內在孩童你想要的經驗。在心輪進行深度療癒，釋放儲存的童年痛苦。感受內在孩童與成人自我整合，你變得完整而有力量。","soulQuestion":"我準備好面對和療癒我的童年傷口了嗎？我願意成為我內在孩童永遠需要的有愛的父母嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:28', 'lightworker', '28', 27, '宇宙母親', 'Cosmic Mother', NULL, '{"keywords":["母性","滋養","創造","保護"],"nameEn":"Cosmic Mother"}', '{"cosmicMessage":"宇宙母親是萬物的創造和滋養原則，她是大地女神、聖母、神聖陰性的最高表達。她是無條件的愛、無盡的慈悲、永恆的接納。每個靈魂都是她的孩子，她從不評判、從不拋棄、永遠歡迎回歸。這張牌帶來母親的療癒能量，無論你與生理母親的關係如何，宇宙母親永遠愛你、支持你、保護你。她也召喚你體現母性能量——滋養自己和他人、創造美和生命、保護脆弱者。","currentSituation":"你可能正需要母性的滋養和支持，感到疲憊、孤獨或無助。你可能在療癒與母親或母性人物的關係。你可能被召喚去更深地體現母性能量——無論你的性別或是否有孩子——透過照顧、滋養、創造、保護。你可能需要允許自己被照顧，接受滋養，這對許多習慣照顧他人的人來說很困難。這張牌提醒你，你永遠不孤單，宇宙母親的愛總是環繞著你。","deeperMeaning":"母性原則是宇宙的基本力量之一，與父性原則互補。如果父性是結構、秩序、保護，母性是流動、滋養、生命。母親給予生命、餵養生命、保護生命直到它能獨立。母親的愛是無條件的，不基於功績或表現，只因為你存在。宇宙母親有許多面貌和名字——蓋亞、聖母瑪利亞、觀音、伊希斯、帕查媽媽——但都代表同一神聖陰性源頭。她不只是溫柔和養育，也是狂野和保護的，像母獅保護幼獅。她教導我們接受、臣服、信任生命過程。她提醒我們地球是我們的母親，所有生命彼此相關。我們可以透過連結大自然、滋養自己和他人、創造美和生命、保護脆弱和珍貴的事物來體現母性能量。","actionGuidance":"連結宇宙母親，無論透過你共鳴的神聖母親面貌——聖母、觀音、地球母親等。建立與她的每日連結，邀請她的愛和指引。如果你與生理母親關係困難，進行療癒工作，分離人類母親和神聖母親。滋養你自己如同慈愛的母親照顧孩子——健康食物、休息、安慰、鼓勵。連結大地母親，赤腳走在土地上，感受她的支持和滋養。創造美和生命，無論是實體的（植物、藝術、食物）或無形的（社群、愛、和平）。保護脆弱和珍貴的，為那些沒有聲音的說話。如果你是母親，榮耀這神聖角色但記住照顧自己。如果你想成為母親，知道母性有許多形式，不只是生物學的。體現母親能量：無條件愛、慈悲、滋養、保護、創造。","energyHealing":"使用月光石連結宇宙母親和神聖陰性。玫瑰石英帶來母親無條件的愛。進行子宮療癒（無論你是否有子宮），這是母性能量的神聖中心。想像宇宙母親抱著你，搖晃你，對你唱歌。感受被完全接納和愛著。在滿月進行宇宙母親儀式，月亮是她的象徵。使用玫瑰或茉莉精油，母親花朵的香氣。創造母親祭壇，放置代表滋養和創造的物品——種子、花朵、水、泥土。進行地球母親冥想，想像你被地球擁抱和支持。練習對自己說母親會說的話：你已經足夠、你被愛著、你是完美的。視覺化從宇宙母親的心到你的心有一條光之臍帶，永遠滋養和連結你。","soulQuestion":"我允許自己接受宇宙母親的愛和滋養嗎？我準備好在我的生命中體現神聖母性能量了嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:29', 'lightworker', '29', 28, '靈魂契約重寫', 'Soul Contract Rewrite', NULL, '{"keywords":["契約","自由","選擇","重寫"],"nameEn":"Soul Contract Rewrite"}', '{"cosmicMessage":"在轉世前，你的靈魂創造了某些契約和協議——與其他靈魂、與你的靈魂家族、與宇宙本身。這些契約設計來促進特定學習和成長。但有些契約已經完成或不再服務你的最高利益，有些是在恐懼或義務中創造的。你不是這些契約的囚犯，你有神聖權利重新檢視、修改或解除不再對齊的契約。這張牌給你權力重寫你的靈魂契約，從更清晰的意識和自由選擇創造新的協議。","currentSituation":"你可能感到被困在某些模式、關係或情況中，好像有看不見的力量讓你重複某些經驗。你可能感到與某人或某情況有「業力」連結，無法解開。你可能攜帶家族或祖先契約，不知不覺地重複他們的模式。或者，你覺醒到你有更多選擇和力量，不想再被舊契約限制。這張牌確認，是的，有靈魂契約在運作，而且你有力量改變它們。","deeperMeaning":"靈魂契約是靈魂間的協議，在靈魂層面創造，通常在轉世前。例如，你可能與某個靈魂約定在這一生互相教導某個課題，這解釋為何某些困難關係無法輕易離開——有靈魂協議在完成學習前保持連結。家族契約可能包括重複某些模式或承擔某些角色。業力契約涉及平衡前世的行動。還有與你的高我和靈魂家族的契約，關於這一生的使命和學習。重要的是理解：這些契約是為了服務你的成長，不是懲罰。而且，隨著你進化和覺醒，舊契約可能已經完成或變得過時。你有神聖權利重新檢視和修改契約。靈魂契約重寫不是逃避學習，而是從更高意識創造對齊你當前進化狀態的新協議。","actionGuidance":"辨識你可能有的靈魂契約，特別在重複模式、困難關係、限制性信念的領域。進行冥想或書寫，請求顯示你的靈魂契約。注意哪些感覺沉重、限制、不再真實。進行正式的契約釋放和重寫儀式：在神聖空間，點燃蠟燭，寫下你想釋放的契約，宣告你的意圖釋放或修改它，然後安全地燃燒紙張。創造新契約，從你當前的清晰和自由書寫你選擇的協議。記住加入『為了所有相關者的最高利益』和『如果這對齊我的靈魂路徑』。邀請你的高我、指導靈和相關靈魂的高我見證新契約。注意釋放後生活的變化，有些關係或情況可能自然改變或結束。對此保持和平，信任一切都在神聖秩序中。","energyHealing":"使用黑碧璽或黑曜石切斷不再服務你的能量連結和契約。青金石支持說出你的真理和主權。進行臍輪療癒，這是靈魂契約常錨定的地方，釋放舊連結。視覺化金色剪刀由天使長麥可揮舞，切斷綁定你的契約之繩。進行前世回溯療癒，如果契約來自前世，在那個時空釋放它。創造主權宣言：我是自由的主權存有，我選擇只保持對齊我最高利益的契約。使用聖木或白鼠尾草淨化，清理舊契約的能量殘留。在新月進行契約重寫儀式，這是新開始的最佳時機。進行扎根冥想，在重寫後保持穩定和中心。感恩完成的契約教導你的一切，然後自由地前進。","soulQuestion":"我準備好釋放不再服務我的靈魂契約了嗎？我願意從自由和清晰創造新的靈魂協議嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:30', 'lightworker', '30', 29, '神聖時機', 'Divine Timing', NULL, '{"keywords":["時機","耐心","信任","完美"],"nameEn":"Divine Timing"}', '{"cosmicMessage":"宇宙有其完美的時機，一切都在精確的神聖時刻發生。你的願望不是被延遲而是在醞釀，你的祈禱不是未被聽見而是正在被完美編排。有些事物需要時間成熟，就像果實不能被催促成熟，你的顯化也有其自然時程。這張牌要求你信任過程，臣服於神聖時機，知道當時機成熟，一切會毫不費力地到位。你的工作是準備好、保持對齊、信任。","currentSituation":"你可能感到不耐煩、沮喪或擔憂，因為你期望的事情還沒發生。你可能質疑你的願望是否會實現，或者你是否在正確的道路上。你可能感到被「卡住」，生活停滯不前。這張牌向你保證，幕後正在發生你看不見的對齊和編排。延遲不是否定，而是保護和完美。有時宇宙說「還不是時候」是因為有更好的版本正在準備，或你還需要成長和準備。信任這個神聖的等待期。","deeperMeaning":"神聖時機是理解宇宙智慧遠超過我們有限視角的藝術。我們從線性時間和立即性的角度看待，但宇宙從永恆和完美編排的角度運作。每件事都連結到其他事，你的顯化可能涉及其他人、事件、學習的協調。強求在時機未成熟時讓事情發生，可能得到不完整或不對齊的結果。想像你種下種子，你不會每天挖出來看它是否在長。你澆水、提供陽光、信任自然過程。同樣，你的願望和祈禱是你種下的種子，你的工作是保持信念、繼續滋養你的願景、信任在看不見的地方生長正在發生。當時機成熟，顯化會自然爆發到你的實相，常常是毫不費力且完美超越你的期待。","actionGuidance":"練習臣服和信任，每當你感到不耐煩時，深呼吸並肯定『我信任神聖時機』。專注於你能控制的——你的態度、行動、準備——而釋放你不能控制的——時機。利用等待期準備自己，學習、成長、清理障礙，確保當機會到來時你已準備好。保持與你願望的情感連結，定期視覺化和感受它已實現，但不執著於何時。尋找和慶祝小的進展和標誌，宇宙常給你信號你在正確的道路上。向宇宙請求耐心和信任的恩典。與大自然連結，觀察自然的節奏和季節，一切都有其時機。練習活在當下，不是活在期待的未來，享受此刻的禮物。記住過去神聖時機為你工作的時刻，那些看似延遲最終是完美的情況。","energyHealing":"使用天青石連結神聖時機和天使指引，特別是耐心天使。紅色碧玉幫助扎根和耐心，在等待中保持穩定。進行臣服冥想，視覺化將你的願望和時程表交給宇宙，看著它被金光包圍和完美照顧。使用薰衣草或雪松精油，它們帶來平靜和信任。創造神聖時機祭壇，包括時鐘、種子、蝴蝶（轉化需要時間）等象徵。進行自然節奏冥想，想像你與宇宙的心跳同步，放鬆到宇宙的時機。在月亮儀式中榮耀週期和時機，理解滿月前需要新月。練習感恩冥想，感謝一切在完美時機到來的方式。當你感到不耐煩時，將手放在心口，呼吸，連結當下。創造肯定語：宇宙的時機是完美的，我信任並放鬆到神聖流動中。","soulQuestion":"我能信任並臣服於神聖時機嗎？我願意釋放控制並允許宇宙完美編排嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:31', 'lightworker', '31', 30, '量子飛躍', 'Quantum Leap', NULL, '{"keywords":["飛躍","轉化","突破","量子"],"nameEn":"Quantum Leap"}', '{"cosmicMessage":"量子飛躍不是漸進的成長，而是突然的、非線性的跳躍到完全不同的實相層面。就像電子在原子軌道間跳躍，你即將在意識和生活體驗中做出量子飛躍。這可能表現為突然的覺醒、生活情況的戲劇性改善、能力的啟動或視角的完全轉變。宇宙正在準備你進行這個飛躍，它將改變你體驗實相的基本方式。你即將進入全新的時間線和可能性場域。","currentSituation":"你可能感到巨大轉變即將來臨的預感或緊張感，像暴風雨前的寧靜。你可能已經體驗到現實開始以奇怪的方式改變——同步性增加、時間感知改變、夢境強度提升。或者，你可能感到被困在舊實相中，渴望突破但不知如何發生。這張牌告訴你，飛躍不需要你用力推或掙扎。它需要你釋放舊實相的執著，信任跳躍，允許自己被提升到新的層次。量子飛躍常常在我們最終放手的那一刻發生。","deeperMeaning":"量子物理揭示實相不是固定的，而是充滿無限可能性的量子場。我們的意識和選擇決定哪些可能性坍縮成我們體驗的實相。量子飛躍發生在我們的意識突然轉變到完全不同的頻率，讓我們進入全新的時間線和體驗。這不是透過努力或掙扎達成，而是透過意識的根本轉變——釋放舊身份、信念、故事，對齊新的可能性。靈性量子飛躍可能包括：從受害者意識到創造者意識、從匱乏到豐盛、從恐懼到愛、從分離到合一。這些不是需要多年才能達成的漸進變化，而是可以在一個洞見、一個決定、一個臣服的時刻發生的飛躍。關鍵是願意完全放下舊的，在未知中信任飛躍。","actionGuidance":"辨識你準備跳躍的領域——可能是意識、關係、事業、健康或靈性覺醒。清晰地設定你想要飛躍到的願景，但不執著於「如何」。進行意識轉變的練習，如視角轉換冥想——從你新實相的視角看當前情況。釋放所有綁定你到舊實相的執著——物品、信念、關係、身份。創造空間讓新的進入。對量子場保持開放，認識到所有可能性同時存在，你的意識選擇經驗哪一個。練習活在新實相的感覺中，不是將來時而是現在時。當恐懼或懷疑升起時，認出這是舊實相試圖拉你回去，選擇新的信念。準備迎接生活的快速變化，量子飛躍後你的外在世界會迅速重組對齊新的內在實相。信任並跳躍。","energyHealing":"使用莫達維石（Moldavite）促進快速轉化和量子飛躍。透明石英放大你的意圖並連結量子場。進行量子飛躍冥想，視覺化你同時存在於多個時間線，有意識地選擇跳到最高的時間線。使用DNA激活技術，想像你的DNA螺旋閃耀光芒，解鎖量子能力。進行實相轉換儀式，象徵性地從一個空間（舊實相）跨越到另一個（新實相）。使用尤加利精油清理舊能量，檀香精油錨定新實相。創造新實相的物理錨點——物品、圖像、象徵代表你的新現實。進行時間線跳躍練習，想像多個版本的你的未來，選擇並融入最高版本。在能量點或強大的天文事件（如獅子門或春分）進行飛躍儀式特別有力。慶祝你的勇氣飛躍到未知。","soulQuestion":"我準備好放下已知的一切，飛躍到全新的實相層次了嗎？我信任量子場支持我的飛躍嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:32', 'lightworker', '32', 31, '神聖叛逆', 'Sacred Rebellion', NULL, '{"keywords":["叛逆","突破","自由","真實"],"nameEn":"Sacred Rebellion"}', '{"cosmicMessage":"有一種叛逆是靈魂的呼喚，不是來自憤怒或反抗，而是來自對真實的深刻忠誠。當社會、文化或集體意識試圖將你塑造成不是你的樣子，神聖叛逆是說「不」的勇氣。這不是為了叛逆而叛逆，而是為了真實而拒絕虛假。這張牌召喚你成為神聖叛逆者——挑戰不再服務的規範、打破限制性的規則、活出你的真實即使它不受歡迎。你的叛逆是為了更高的愛和真理，不是破壞而是創造。","currentSituation":"你可能感到被社會期望、家族傳統或集體信念窒息。你內在有一個聲音說「這不對」或「一定有另一種方式」。你可能害怕表達你真實的信念、選擇或生活方式，因為擔心被評判或拒絕。或者，你已經在某種程度上反叛，但感到內疚或不確定這是否正確。這張牌確認你的叛逆是神聖的，是你的靈魂拒絕被馴化。現在是時候更充分地擁有你的叛逆，用愛和清晰而非憤怒和反應。","deeperMeaning":"歷史上的偉大轉變常由神聖叛逆者推動——那些敢於質疑現狀、挑戰權威、活出不同願景的人。耶穌是叛逆者，佛陀是叛逆者，所有的先知、神秘主義者、改革者都是。他們不是為了反叛而反叛，而是因為他們看到更高的真理，無法假裝沒看到。神聖叛逆與純粹的反抗不同。反抗是反應性的，對抗它所反對的。神聖叛逆是創造性的，為它所擁護的而站立。它來自愛不是恐懼，來自願景不是憤怒。它尊重他人的道路但堅定地走自己的。在這個覺醒時代，我們需要神聖叛逆者——那些敢於活出新範式、挑戰舊系統、示範另一種可能的人。這不是容易的道路，但它是真實的道路。","actionGuidance":"辨識你生命中需要神聖叛逆的領域——哪裡你在遵守不對齊你真實的規則或期望？從清晰不是憤怒開始行動，知道你為什麼選擇不同的道路。與你的靈魂核心價值對齊，讓它們指導你的叛逆。準備面對不理解或反對，不是每個人都會慶祝你的真實。尋找你的叛逆部落，那些同樣選擇真實超過舒適的人。用你的生命成為另一種可能的示範，這是最有力的教導。設定界限保護你的真實，對試圖控制或限制你的人事物說不。記住你的叛逆不是對抗某人，而是為了某些事——真理、自由、愛、正義。保持心的開放即使你站在立場上。慶祝其他神聖叛逆者和你不同但同樣真實的道路。你的叛逆是你給世界的禮物。","energyHealing":"使用紅色碧玉連結你的根輪和生命力量，給你勇氣叛逆。青金石支持說出你的真理。進行解放儀式，象徵性地打破束縛你的鎖鏈或規則。視覺化你是神聖戰士，不為暴力而戰而是為真理和愛而站立。使用黑曜石切斷他人期望和能量控制的連結。進行野性自我冥想，連結你未馴化、原始、自由的本質。使用雪松或杜松精油，它們帶來力量和清晰。創造叛逆宣言：我選擇真實超過認可，自由超過舒適，我的道路超過他人的期望。在火的儀式中燃燒你選擇釋放的限制和規則。與大自然中的野性動物能量連結——狼、鷹、獅子。穿戴或展示象徵你的叛逆和真實的物品或顏色。記住叛逆不是憤怒而是愛——對你真實自我的愛足以保護它。","soulQuestion":"我準備好為我的真實站立即使不受歡迎嗎？我願意成為神聖叛逆者為新範式開路嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:33', 'lightworker', '33', 32, '前世智慧', 'Past Life Wisdom', NULL, '{"keywords":["前世","業力","智慧","整合"],"nameEn":"Past Life Wisdom"}', '{"cosmicMessage":"你的靈魂已經存在了無數個生命，在不同的時代、文化、身體和角色中體驗。每一世都帶來學習、智慧和有時未完成的業力。這張牌顯示你的前世正在影響你的當前生命，可能是透過未解決的業力、攜帶的才能、深層恐懼或莫名的連結。現在是時候有意識地接觸你的前世智慧，療癒前世創傷，整合前世的禮物，完成未完成的循環。你攜帶遠古的智慧，當你記起時，它會在這一世服務你。","currentSituation":"你可能經歷對某些時期、地點或文化的強烈吸引或厭惡，無法用當前生命解釋。你可能有天生的才能或知識，沒有在這一世學習過。你可能在某些關係中感到「我們以前認識」的深刻熟悉感。或者，你可能有無法解釋的恐懼、身體症狀或模式，根源於前世經歷。這張牌邀請你探索前世連結，不是出於好奇，而是為了療癒和整合。","deeperMeaning":"輪迴是靈魂進化的學校，每一生是一個學期，學習特定課程、發展特定品質、平衡特定業力。我們與某些靈魂一次又一次轉世，以不同關係形式（父母、孩子、愛人、朋友、敵人）互相教導。有時我們在一世創造的業力需要在未來生平衡——不是作為懲罰，而是作為學習和進化的機會。同時，我們在前世發展的才能和智慧不會丟失，而是存在於我們的靈魂記憶中，可以在當前生被激活。前世創傷也可能攜帶到當前生，表現為無法解釋的恐懼、身體問題或關係模式。前世工作幫助我們：理解當前生的挑戰和模式、療癒前世創傷、啟動前世才能、完成業力循環、整合靈魂的完整旅程。","actionGuidance":"如果你被召喚，探索前世回溯療癒，透過合格的前世治療師或冥想。辨識你生命中可能有前世根源的模式——重複的關係動態、無法解釋的恐懼、身體症狀、天生的才能。進行前世冥想，請求顯示對你當前療癒最相關的前世。注意你的夢境，前世記憶常在夢中浮現。探索你被吸引的時期、文化或地點，研究它們可能觸發記憶。注意「前世出血」——當前世的情緒、信念或經驗影響當前，例如沒有理由的恐懼某事物。進行前世療癒儀式，視覺化你回到前世的創傷時刻，帶著當前的智慧和愛療癒它。完成業力循環，如果你認識到與某人的業力連結，有意識地選擇新的方式互動。感恩你的靈魂旅程的所有經驗，它們塑造了今天的你。","energyHealing":"使用紫水晶或拉長石連結前世記憶和多維度意識。進行阿卡西記錄冥想，連結你的靈魂記錄和所有前世。視覺化金色光穿越時間線，療癒所有生命中的創傷和業力。使用乳香精油連結靈魂記憶和古代智慧。創造前世療癒儀式，邀請你的高我和指導靈協助。進行臍輪療癒，這是業力連結常錨定的地方，釋放前世業力。如果特定前世浮現，視覺化你在那一生的自己，給予愛、療癒、寬恕。進行魂體整合，想像你所有生命的智慧和禮物整合到當前的你。在儀式中榮耀你的靈魂旅程，點燃蠟燭代表你經歷的所有生命。記住你不是你的前世，你是永恆的靈魂在持續進化的旅程中。","soulQuestion":"我準備好探索和療癒我的前世了嗎？我願意整合我靈魂旅程的完整智慧嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:34', 'lightworker', '34', 33, '神聖男性', 'Divine Masculine', NULL, '{"keywords":["陽性","力量","保護","行動"],"nameEn":"Divine Masculine"}', '{"cosmicMessage":"神聖男性能量是宇宙的結構原則——方向、保護、行動、邏輯、力量。它不是有毒的男性氣質（支配、控制、侵略），而是健康的陽性表達（保護、供應、創造結構、明智行動）。無論你的性別，你內在都有神聖男性能量。這張牌召喚你榮耀和整合你的神聖男性，特別如果你壓抑它或以扭曲的方式表達它。健康的神聖男性給予生命方向和結構，在行動中顯化願景，保護珍貴的事物。","currentSituation":"你可能需要更多的陽性能量——明確方向、採取行動、設定結構、保護界限。或者，你可能以不健康的方式表達陽性——過度控制、侵略、支配。男性可能在療癒他們與男性氣質的關係，在有毒和壓抑之間尋找健康平衡。女性可能在學習整合內在的神聖男性，而不放棄陰性力量。這張牌邀請你探索和癒合你與男性能量的關係，無論個人還是集體層面。","deeperMeaning":"健康的神聖男性特質包括：明確的目的和方向、智慧的行動、保護而非控制、邏輯與直覺的平衡、給予結構和支持、勇氣面對挑戰、負責任和可靠。集體上，我們經歷了有毒男性氣質的時代（戰爭、支配、壓迫、環境剝削），作為反應，一些運動壓抑所有男性能量。真正的療癒不是壓抑而是轉化——從有毒男性到神聖男性。我們需要健康的神聖男性，特別在這個轉變時代。它提供方向給集體願景，保護新生和脆弱的，在混亂中創造結構，在夢想和顯化之間架橋。與神聖陰性（存在、接收、流動）配對，神聖男性（行動、給予、結構）創造完美平衡和強大顯化。","actionGuidance":"評估你的神聖男性健康狀況——你過度、不足還是扭曲地表達？需要更多的人：練習採取行動即使不完美、設定明確目標和計劃、建立結構和紀律、設定和維護界限、在需要時保護你的能量空間價值。需要平衡的人：放鬆控制、信任流動不只是推動、平衡邏輯與直覺、力量與溫柔並存。療癒與父親或男性人物的關係，他們是你最初接觸的男性能量。探索健康的男性榜樣和原型——國王、戰士、魔法師、愛人的成熟表達。如果你是男性，榮耀你的男性氣質為神聖禮物，拒絕有毒和壓抑的極端。與大自然中的男性能量連結——山、太陽、雄鹿、老鷹。練習陽性冥想，連結你內在的神聖戰士和智慧國王。","energyHealing":"使用虎眼石或紅碧玉連結神聖男性力量和扎根。進行太陽神經叢和根輪激活，這是陽性能量中心。在正午進行太陽冥想，吸收太陽的陽性力量。視覺化你內在的神聖男性——可能為國王、戰士、智者——健康、強大、慈悲。使用雪松或檀香精油，它們是男性木的香氣，帶來扎根和力量。進行神聖男性儀式，創造代表健康男性的祭壇——劍（辨識力）、權杖（行動）、山（穩定）、太陽（力量）。在火元素儀式中連結陽性的轉化和行動力量。練習力量姿勢和戰士瑜伽姿勢，身體層面體現神聖男性。療癒父親傷口，視覺化健康的父親能量療癒你，給你當時缺乏的保護和肯定。整合你的內在國王和女王，內在男性和女性和諧共治。","soulQuestion":"我準備好擁抱和整合我的神聖男性能量了嗎？我能釋放有毒模式並體現健康的陽性力量嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:35', 'lightworker', '35', 34, '宇宙豐盛', 'Cosmic Abundance', NULL, '{"keywords":["豐盛","富足","流動","接收"],"nameEn":"Cosmic Abundance"}', '{"cosmicMessage":"宇宙的本質是無限豐盛。看看大自然——無數的星辰、種子、花朵、生命形式。創造是慷慨的、豐富的、源源不絕的。匱乏是幻相，是錯誤信念的結果。這張牌提醒你，你生活在豐盛的宇宙中，你值得接收宇宙的豐盛禮物。不只是金錢，而是所有形式的豐盛——愛、健康、機會、喜悅、美、連結、創造力。當你對齊豐盛意識，從匱乏轉變到富足，你打開接收的門，宇宙的豐盛可以自然流向你。","currentSituation":"你可能在某個或多個生命領域經歷匱乏——財務、愛、健康、機會、支持。這可能是實際的匱乏或更深層的匱乏意識，即使外在看起來充足。你可能難以接收，更習慣給予。你可能攜帶關於金錢、富足或值得的限制性信念。或者，你正在覺醒到豐盛意識，開始經歷生命以新方式支持你。這張牌邀請你徹底轉變你與豐盛的關係，從匱乏到富足，從掙扎到流動。","deeperMeaning":"豐盛意識與匱乏意識是根本不同的實相觀。匱乏意識相信資源有限、競爭是必要的、你必須掙扎才能得到、沒有足夠給所有人。豐盛意識相信資源無限、合作增強所有人、流動和接收是自然的、宇宙支持所有人繁盛。這兩種意識創造完全不同的體驗，因為我們吸引與我們的意識共振的。療癒豐盛需要辨識和釋放匱乏編程——通常來自童年、家族、社會或前世。它需要釋放關於金錢、富足、值得的內疚、羞恥或恐懼。它需要平衡給予和接收——許多靈性人過度給予而阻塞接收。真正的豐盛是允許宇宙的愛以所有形式流向你，包括金錢，知道你接收越多，你能給予越多。","actionGuidance":"辨識和釋放你的匱乏編程。完成這句話：關於金錢/豐盛，我相信......注意任何限制性信念並用豐盛肯定語取代。療癒你與金錢的關係，感謝它為你提供的服務，允許自己想要和享受物質豐盛。練習接收，允許他人給予你——讚美、幫助、禮物——不需回報。注意你阻塞豐盛的方式——過度給予、拒絕接收、感到不配、過度控制。感恩你已經擁有的，感恩創造豐盛的磁場。視覺化豐盛以所有形式流向你，感受已經擁有的富足。採取啟發性行動創造多重收入來源或豐盛機會，但來自遊戲和靈感不是恐懼和匱乏。慷慨地給予，從溢出給予創造更多流動。對齊你的工作與你的喜悅和禮物，豐盛跟隨喜悅。信任宇宙總是供應你所需，通常超越你所求。","energyHealing":"使用黃水晶是豐盛之石，吸引富足和成功。綠東陵打開心輪接收宇宙禮物。在你的錢包或收銀處放豐盛水晶，為金錢流動充能。進行豐盛冥想，視覺化金色光充滿你的存在和生活，代表宇宙豐盛。創造豐盛祭壇，放置代表富足的物品——水晶、硬幣、綠色植物、富足的圖像。使用肉桂或橙精油，它們吸引豐盛和繁榮。進行金錢療癒儀式，對每張鈔票和硬幣說感恩和祝福，轉化你與金錢的關係。寫豐盛肯定語：我是豐盛的，我值得接收，宇宙無限供應我所需和所求。每天朗讀它們。視覺化你的生活在所有領域充滿豐盛——財務、健康、愛、機會、喜悅。進行給予接收冥想，想像豐盛如河流雙向流動——流出和流入你。慶祝豐盛的證據，無論多小，擴展它。","soulQuestion":"我準備好釋放匱乏意識並擁抱宇宙的無限豐盛了嗎？我允許自己接收所有形式的富足嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:36', 'lightworker', '36', 35, '靈魂家族重聚', 'Soul Family Reunion', NULL, '{"keywords":["靈魂家族","連結","重聚","支持"],"nameEn":"Soul Family Reunion"}', '{"cosmicMessage":"靈魂家族是那些與你在靈魂層面深刻連結的存有，不是因為血緣而是因為靈魂共鳴。你們可能在多生多世一起旅行，互相支持彼此的成長和使命。在你地球旅程的不同時期，你會遇見靈魂家族成員——有些短暫有些長久，但每個相遇都深刻重要。這張牌宣告靈魂家族重聚的時刻——你即將遇見或重新連結你的靈魂部落，那些完全理解你、與你共享使命和願景、與你共鳴的人。","currentSituation":"你可能一直感到孤獨或不屬於，即使在人群中。你渴望深刻的連結和理解，超越表面關係。你可能最近失去某些友誼或關係，為新的連結創造空間。或者，你已經開始遇見靈魂家族成員，感受到立即的辨識和深刻的連結。這張牌確認你的部落正在集合，宇宙正在編排你的靈魂家族重聚。準備敞開心迎接真正理解你的人進入你的生命。","deeperMeaning":"靈魂家族不一定是血緣家庭，事實上常常不是。它們是靈魂層面選擇一起旅行、學習、服務的存有群體。你可能屬於一個或多個靈魂家族，基於不同的使命或共鳴。靈魂家族成員間的連結是立即和無法解釋的——你感到你一直認識他們，即使剛遇見。對話深刻而毫不費力，理解和接納是自然的。靈魂家族提供彼此支持、鏡子、挑戰和慶祝。在這個覺醒時代，靈魂家族正在地球各地重聚，因為我們需要彼此完成我們的集體使命。孤軍奮戰的時代結束了，現在是部落時代。然而，靈魂家族重聚要求你首先清理你對連結和社群的舊傷口、恐懼和防衛，敞開你的心真實地呈現，信任當你準備好，你的人會找到你。","actionGuidance":"療癒過去關係的傷口，釋放背叛、拒絕或遺棄的痛苦，這樣你能敞開新的連結。清晰你的價值觀、使命和真實，這是靈魂家族辨識的頻率標誌。在你共鳴的地方和社群出現——工作坊、課程、在線社群、靈性活動——你的部落在那裡。當你遇見可能的靈魂家族成員時，勇敢地深入連結，分享你的真實，超越表面交談。同時辨識和釋放不再共鳴的關係，不是每個人都是你的靈魂家族，這沒關係。信任神聖時機，有些靈魂家族成員會在完美時機出現。準備深刻的相互性——給予和接收支持、誠實和脆弱。慶祝你遇見的每個靈魂連結，無論持續時間長短。記住靈魂家族也包括非人類存有——動物、自然、星際家族、指導靈。","energyHealing":"使用粉晶打開心輪接收靈魂家族的愛。天青石連結你的靈魂家族在高我層面。進行靈魂家族召喚冥想，視覺化你發送信號到宇宙：我在這裡，我準備好了，召喚我的靈魂家族。想像金色光連結你與所有你的靈魂家族成員，無論他們在地球何處或其他維度。創造靈魂家族祭壇，為你已經認識的成員和即將到來的留出空間。使用薰衣草或茉莉精油，它們打開心連結。進行心輪療癒，釋放過去關係創傷的盔甲和牆壁。寫一封信給你的靈魂家族，即使你還不知道他們是誰，表達你的渴望和準備。在新月設定意圖：我呼喚我的靈魂家族進入我的生命。注意你感到立即連結的人，這可能是靈魂辨識。感恩你生命中已有的靈魂連結，這打開空間給更多。","soulQuestion":"我準備好敞開心迎接我的靈魂家族了嗎？我願意放下孤軍奮戰，在神聖社群中繁盛嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:37', 'lightworker', '37', 36, '地球守護者', 'Earth Guardian', NULL, '{"keywords":["地球","守護","療癒","責任"],"nameEn":"Earth Guardian"}', '{"cosmicMessage":"地球是我們的母親、家園和聖殿。她是有意識的存有，不是無生命的資源。作為光工作者，你對地球有特殊的責任和連結。這張牌召喚你作為地球守護者——療癒地球、保護自然、錨定光到地球網格、教導人類與地球和諧生活。這不是負擔而是榮幸的服務。當你療癒地球，你療癒自己。當你保護自然，你保護你靈魂的一部分。現在比以往任何時候，地球需要她清醒的孩子成為積極的守護者。","currentSituation":"你可能對環境問題感到深刻的悲傷或憤怒，這是地球痛苦在你心中的回響。你可能被召喚去更積極地參與環境保護或生態工作。或者，你已經在某種形式守護地球，這張牌確認和榮耀你的服務。你可能需要更深地與地球母親連結，接地和療癒。這張牌提醒你，作為人類，你不是地球的主人而是守護者，你的幸福與地球的幸福不可分割。","deeperMeaning":"原住民文化一直知道我們現代文化正在重新學習的——我們與地球不是分離的，地球不是為我們使用的資源，而是我們是地球的一部分，她的健康是我們的健康。地球正在經歷巨大壓力——氣候變化、物種滅絕、森林砍伐、污染——這都是人類失衡的結果。但地球也在覺醒和揚升，而我們是這個過程的一部分。作為地球守護者，你的角色是多面向的：在能量層面錨定光和高頻到地球網格，療癒被創傷的地方；在實際層面採取行動保護環境，無論多小；在意識層面教導和示範人類與自然和諧生活；在靈性層面連結和榮耀地球為神聖母親。每個行動，無論看似多小，都重要。","actionGuidance":"建立每日與地球連結的練習，赤腳走在大地上、擁抱樹木、在自然中坐著冥想。進行地球療癒冥想，想像你從宇宙吸入光，透過你的心送到地球核心，療癒和滋養蓋亞。在實際層面採取行動——減少消費、回收、支持生態企業、清理海灘或森林、種植樹木或花園。教育自己和他人關於環境問題和解決方案。使用你的聲音為地球說話，參與環境行動和政策。療癒你與自然的分離，重新認識你是自然的一部分，不是分開的。榮耀和慶祝地球的美和豐盛，感恩她給予的一切。支持原住民文化和智慧，他們是地球的原始守護者。進行儀式榮耀季節、春分、地球慶典。記住你不需要拯救地球，而是與她合作共同療癒。","energyHealing":"使用綠色石頭如綠東陵、翠綠或苔瑪瑙連結地球的心。進行扎根冥想，想像你的根深入地球，與她交換能量——給予光，接收穩定。進行地球網格療癒，視覺化地球被光的網格包圍，將療癒能量送到被創傷的地方——戰區、災區、被剝削的自然區。使用松樹或雪松精油連結森林和自然精神。在神聖地點或能量點進行儀式特別有力，這些是地球的脈輪。與自然元素工作——土、水、火、風——榮耀它們為神聖力量。創造地球祭壇，放置石頭、樹葉、種子、水，代表你對蓋亞的奉獻。聆聽地球頻率音樂或舒曼共振，與地球的心跳同步。在滿月向地球母親獻禮和感恩。視覺化健康繁榮的地球，所有生命和諧共存，這個願景錨定新地球能量。","soulQuestion":"我準備好承擔地球守護者的神聖責任了嗎？我如何能在日常生活中榮耀和保護地球母親？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:38', 'lightworker', '38', 37, '靈性煉金術', 'Spiritual Alchemy', NULL, '{"keywords":["轉化","煉金","蛻變","大師"],"nameEn":"Spiritual Alchemy"}', '{"cosmicMessage":"煉金術是將鉛轉化為金的古老藝術，但真正的煉金術是內在的——將痛苦轉化為智慧、創傷轉化為禮物、黑暗轉化為光。這是靈性大師的道路，不是壓抑或逃避黑暗，而是有意識地轉化它。這張牌顯示你已經發展了或正在發展靈性煉金術的能力。你可以拿取生命給你的任何原料，無論多困難，並煉金它為黃金——成長、智慧、慈悲、力量、美。你是煉金術士，你的生命是你的大作。","currentSituation":"你可能正在經歷或剛經歷困難——痛苦、挑戰、損失、黑暗夜。但不同於過去，你開始看到轉化的可能性。你問「這教導我什麼？」而不是「為什麼是我？」你正在發展從經驗中提取智慧的能力，無論它們看起來多負面。或者，你已經轉化了過去的痛苦，正在使用那個智慧服務他人。這張牌確認你的煉金術大師之道，邀請你更深地擁抱這個能力。","deeperMeaning":"真正的煉金術發生在三個層次：尼格雷多（黑化，分解舊我）、白化（淨化，釋放雜質）、魯貝多（紅化，重生為新我）。這是英雄旅程、死亡與重生、鳳凰從灰燼中升起。靈性煉金術的關鍵是意識——不是被動經歷生命而是主動與它工作。當挑戰來臨，煉金術士問：這個經驗的禮物是什麼？我被邀請釋放什麼？我正在成為誰？這不是毒性正面思考或否認痛苦，而是在痛苦中找到意義和成長。煉金術士知道沒有什麼被浪費，每個經驗都是原料。最深的傷口可以成為最深的智慧。最黑暗的夜可以birth最亮的光。掌握煉金術，你成為不可摧毀的——不是沒有挑戰，而是沒有任何挑戰能擊敗你，因為你知道如何轉化一切為黃金。","actionGuidance":"回顧你的生命，辨識你已經轉化的經驗。看到你從中獲得的智慧、力量、慈悲。慶祝你的煉金術成就。對當前挑戰，問煉金問題：這教導我什麼？邀請我釋放什麼？召喚我成為什麼？這如何服務我的最高進化？寫煉金日記，記錄你的轉化旅程和洞見。進行陰影工作，有意識地面對和整合你的黑暗面，這是煉金的原料。尋找意義和目的，即使在痛苦中，意義是煉金的關鍵要素。使用你的轉化故事服務他人，你的煉金智慧是你的禮物。練習再框架，從不同角度看情況看到新的可能性。研究煉金術象徵和哲學，它們是轉化的地圖。記住，煉金術需要火——困難的經驗——沒有它，沒有轉化。不是尋求困難，而是當它來時使用它。","energyHealing":"使用紫水晶連結轉化和靈性煉金術。黑曜石幫助面對和轉化陰影。進行煉金術冥想，視覺化你將經驗放入煉金爐，看著它被轉化為黃金智慧。使用紫羅蘭火焰冥想，想像紫色火焰燃燒並轉化所有稠密能量。創造煉金術祭壇，包括代表轉化的物品——蝴蝶、鳳凰、金、爐。使用乳香或沒藥精油，它們是古代煉金術士使用的。進行火元素儀式，釋放舊的到火中，從灰燼中重生。視覺化你是鳳凰，經歷死亡和重生的循環，每次升起更輝煌。進行脈輪煉金術，清理和轉化每個脈輪的稠密能量。記錄你的煉金術過程——開始、中間（黑暗）、結束（黃金）。慶祝每個完成的煉金循環，你越來越成為大師。","soulQuestion":"我準備好擁抱靈性煉金術，將我所有經驗轉化為黃金智慧了嗎？我能在最深的黑暗中找到光嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:39', 'lightworker', '39', 38, '彩虹橋', 'Rainbow Bridge', NULL, '{"keywords":["連結","橋樑","整合","合一"],"nameEn":"Rainbow Bridge"}', '{"cosmicMessage":"彩虹橋是連結天地、靈性與物質、神聖與人類的橋樑。在許多傳統中，彩虹代表神的承諾、希望和連結。作為光工作者，你是活生生的彩虹橋，在你之中天地相遇。你錨定天堂到地球，提升地球到天堂。這張牌召喚你擁抱你作為橋樑的角色，整合你的靈性洞見與日常生活，活出天地合一的示範。你不需要選擇靈性或物質，你被召喚整合兩者為一個完整的、彩虹般的生命。","currentSituation":"你可能在靈性與物質生活間感到分裂——靈性修煉時感到提升，但回到日常生活時掙扎。或者，你過度傾向一邊——過度靈性而忽略物質責任，或過度物質而渴望靈性連結。你可能在尋找如何活在世界但不屬於世界，如何將你的靈性整合到工作、關係、日常任務。這張牌告訴你，分離是幻相。靈性和物質不是對立而是互補。你被召喚成為整合的示範。","deeperMeaning":"許多靈性道路教導超越或逃離物質世界，但光工作者的道路不同。你來這裡不是逃離地球而是轉化它，不是超越物質而是神聖化它。這需要整合——在靈性高峰經驗與日常責任間找到平衡，在冥想與行動間，在天堂與地球間。彩虹橋的象徵是完美的：彩虹包含所有顏色，沒有一個被排除。同樣，完整的你包含所有面向——靈性和物質、神聖和人類、光和陰影。當你整合而非分裂，你成為完整光譜的表達，你是橋樑讓他人看到整合也是可能的。真正的大師不是住在山頂而是在市場中——與人群在一起但從不失去天堂的連結。","actionGuidance":"辨識你生命中的分裂——靈性與物質、工作與靈性、冥想與行動。探索如何整合它們而非選擇一個。將靈性帶入日常任務——正念洗碗、禱告工作、將購物視為豐盛練習。將物質帶入靈性——讓你的靈性實用、扎根、體現在生活中。平衡你的時間和能量在靈性修煉和世俗責任之間。在工作中活出你的價值，不只在冥想墊上。將你的靈性禮物提供給世界，賺取生活，沒有內疚。榮耀你的人性和神性，兩者都是你的真實。練習臨在——無論你在做什麼，全然在那裡，神聖和日常在每個時刻相遇。教導和示範整合生活是可能的，你是活生生的彩虹橋。","energyHealing":"使用彩虹石如彩虹黑曜石、光環水晶或任何有彩虹的水晶連結彩虹橋能量。進行彩虹冥想，視覺化七彩光從天堂降下穿過你到地球，從地球升起穿過你到天堂，你是兩者相遇的點。進行脈輪彩虹激活，想像每個脈輪閃耀其顏色，所有一起創造你內在的完整彩虹。創造彩虹祭壇，包括所有七種顏色的物品，代表完整光譜的整合。在雨後尋找彩虹，這是天地連結的物理示範，讓它提醒你的角色。進行天地整合練習，一手向上連結天堂，一手向下連結地球，感受能量在你之中相遇。使用所有脈輪的精油混合，創造完整光譜的香氣。視覺化你是光柱，天地在你之中合一。慶祝你的人性和神性，不需選擇，你是兩者的完美整合。","soulQuestion":"我準備好成為天地之間的活生生橋樑了嗎？我能整合我的靈性和物質生活為合一的彩虹嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:40', 'lightworker', '40', 39, '新地球錨定', 'New Earth Anchoring', NULL, '{"keywords":["新地球","錨定","願景","創造"],"nameEn":"New Earth Anchoring"}', '{"cosmicMessage":"新地球不是未來的地方而是現在正在birth的意識。它是活在愛、合一、和諧、豐盛、和平中的人類文明。舊地球建立在恐懼、分離、競爭、匱乏上，正在崩解。新地球正在那些選擇不同的人心中和生命中升起。這張牌告訴你，你是新地球的錨定者和建造者。透過你的意識、選擇、行動和存在，你正在顯化新地球到物質層面。這是你來這裡的原因，現在是你使命最關鍵的時刻。","currentSituation":"你可能感到與舊世界的系統、價值和運作方式深刻的不對齊。你攜帶新地球的願景和知曉，即使你不能完全言說它。你可能在你的生活某領域已經活出新地球——創造基於愛的關係、和諧的社群、有意識的生意、治療模式、教育系統。或者，你渴望更全然地活出新地球但不確定如何開始。這張牌召喚你有意識地承擔新地球錨定者的角色，在每個當下每個選擇中選擇新地球意識。","deeperMeaning":"我們正活在兩個地球的轉折點——舊地球和新地球同時存在，我們每個人每一刻都在選擇我們居住哪一個。這不是物理的兩個地球而是兩種意識、兩種實相、兩種集體選擇。舊地球的特徵是分離、恐懼、競爭、控制、匱乏意識、權力over他人、人類優越於自然。新地球的特徵是合一、愛、合作、自由、豐盛意識、與的力量、人類作為自然一部分。轉變不會在某個未來日期突然發生，它現在正在發生，透過我們每個人的選擇。每次你選擇愛over恐懼、連結over分離、給予over囤積、真實over面具，你錨定新地球。你不需要等待系統改變，你透過你的生命成為新系統。當足夠的人錨定新地球意識，臨界質量會創造集體轉換。","actionGuidance":"清晰你的新地球願景——你想要生活在什麼樣的世界？什麼價值、系統、關係方式？寫下來。現在就開始活出那個願景，不要等待外在改變。在你的生活中創造新地球的口袋——你的家、你的關係、你的工作、你的社群。在每個選擇點問：這個選擇對齊舊地球還是新地球？選擇新地球。加入或創造新地球社群和項目，我們集體的創造力遠超個人。教導新地球意識，特別對孩子，他們是新地球的原住民。支持新地球的生意、藝術家、教師、療癒師。放下舊地球不再服務的一切——工作、關係、信念、習慣。錨定新地球能量到地球網格透過冥想和儀式。保持希望和願景即使舊地球看似混亂，混亂是轉化的一部分。信任更多的人每天都在覺醒和選擇新地球。","energyHealing":"使用高頻水晶如莫達維石、透石膏、拉長石錨定新地球能量。進行新地球冥想，視覺化你的新地球願景細節，感受活在其中的感覺，然後想像將這個能量錨定到地球。創造新地球祭壇，放置代表你願景的圖像和物品。使用沒藥或聖木清理舊地球能量，乳香錨定新地球頻率。進行地球網格工作，視覺化地球被光的網格包圍，所有光工作者連結一起共同錨定新地球。在春分、秋分、至日進行新地球儀式特別有力。加入全球冥想和祈禱為新地球。與其他新地球建造者連結能量和願景。視覺化健康、和平、豐盛、美麗的新地球已經存在，你只是將它從可能性場域顯化到物質現實。感受作為新地球錨定者的榮幸和責任，這是你的使命。","soulQuestion":"我準備好全然承擔新地球錨定者的角色了嗎？我願意在每個當下選擇新地球意識嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:41', 'lightworker', '41', 40, '神聖孤獨', 'Sacred Solitude', NULL, '{"keywords":["孤獨","內在","重生","深度"],"nameEn":"Sacred Solitude"}', '{"cosmicMessage":"神聖孤獨不是寂寞而是與你靈魂深刻親密的時間。它是刻意從外在世界撤退進入內在聖殿的時期。所有偉大的靈性教師經歷孤獨時期——耶穌在沙漠、佛陀在菩提樹下、先知在山洞。在孤獨中，噪音平息，真理浮現。在孤獨中，你脫下所有面具和角色，遇見赤裸的真實自我。這張牌邀請或確認一個神聖孤獨的時期，不是因為有什麼錯誤，而是為了深度轉化和與你靈魂的重新連結。","currentSituation":"你可能被迫或選擇進入孤獨期——可能是物理的孤獨或情感的撤退。朋友可能離開，關係結束，社交欲望減少。你可能渴望獨處超過過去。或者，你可能抗拒孤獨，感到寂寞或被遺棄。這張牌重新框架孤獨為神聖禮物和必要的轉化空間。在喧囂中你無法聽到靈魂的細語，在持續的外在刺激中你無法進入必要的深度。孤獨不是懲罰而是恩典，是培養珍珠的貝殼。","deeperMeaning":"神聖孤獨與寂寞不同。寂寞是痛苦的空虛感，渴望外在填補。孤獨是充滿的獨處，與自己和神聖的親密。現代文化害怕孤獨，用持續的連結、娛樂、刺激填滿每個時刻。但靈性傳統知道孤獨的必要——它是繭，在其中發生轉化。在孤獨中：你面對你真實的自我，沒有角色或面具；你療癒深層的傷口，在他人在場時無法觸及；你接收靈性下載和啟示，需要深度寧靜；你重新連結你的本質和目的；你煉金和整合你的經驗；你重生為新版本的你。孤獨期後，你不會變回「社交」，你會以完全轉化的方式重新進入世界。尊重你靈魂對孤獨的召喚，不要過早打斷過程。蝴蝶不能被催促。","actionGuidance":"如果你被召喚進入孤獨，不要抗拒它，擁抱它為神聖過程。創造支持孤獨的條件——減少社交承諾、限制社交媒體、創造不被打擾的時間空間。建立孤獨的日常儀式——冥想、書寫、在自然中散步、創造性表達。使用孤獨進行深度內在工作——療癒、陰影工作、靈魂探索。不要期待孤獨舒適或愉快，它常常挑戰和黑暗，這是過程的一部分。在孤獨中記錄你的旅程——夢境、洞見、情緒、轉變。如果你感到寂寞，問自己你在逃避什麼內在會面。練習享受你自己的陪伴，發現你是有趣、深刻、足夠的。信任當時機成熟，你會自然地重新連結他人，但從更真實深刻的地方。不要讓他人羞愧你的孤獨需求，榮耀它為靈性需求。","energyHealing":"使用紫水晶或透石膏連結你在孤獨中的高我和靈性指引。進行孤獨冥想，在完全安靜中坐著，不做什麼，只是存在與你的靈魂同在。創造神聖孤獨空間，你的內在聖殿——可以是房間一角、自然中的地方，只屬於你和神聖。使用薰衣草或檀香精油，它們支持內在旅程。進行感官剝奪練習，閉上眼睛，消除外在刺激，完全進入內在。在孤獨中進行深度療癒工作，內在孩童、陰影整合、前世回溯。與你的靈魂對話，問它想要你知道什麼、它需要什麼、它召喚你成為什麼。寫給你自己的情書，深化與自己的愛情關係。記住，孤獨是時間有限的，尊重過程直到它自然完成。慶祝你從孤獨茧中重生為蝴蝶。","soulQuestion":"我能擁抱神聖孤獨為轉化的禮物嗎？我願意進入深度與我的靈魂親密相遇嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:42', 'lightworker', '42', 41, '業力完成', 'Karma Completion', NULL, '{"keywords":["業力","完成","釋放","自由"],"nameEn":"Karma Completion"}', '{"cosmicMessage":"業力不是懲罰而是學習，不是命運而是機會。每個業力循環帶來特定的課題需要掌握。當你學會課題，業力完成，你自由了。這張牌宣告一個或多個重要業力循環正在完成。你掌握了課題，平衡了能量，你即將從長期綁定你的模式釋放。這是深刻的靈性成就，值得慶祝。同時，業力完成需要最後的行動——寬恕、釋放、閉合、臣服。完成這些最後步驟，你將體驗前所未有的自由和輕盈。","currentSituation":"你可能注意到長期模式不再重複——你不再吸引同類型的問題關係、你不再陷入舊反應、你不再掙扎於某個議題。或者，業力模式正在最後和最強烈地表現，提供最終掌握和釋放的機會。你可能被召喚進行最後的業力清理——寬恕你從未寬恕的、釋放你一直緊抓的、閉合未完成的循環。這張牌確認你的業力工作已接近完成，鼓勵你採取最後必要步驟完全釋放。","deeperMeaning":"業力是因果法則——每個行動創造能量後果需要平衡。業力可以在一生內或跨多生創造和平衡。我們也繼承家族和集體業力。業力創造重複模式和循環，直到我們學會課題。關鍵理解是：業力的目的是學習和進化，不是懲罰。當你掌握課題，業力完成，不管花多少世。業力完成的標誌包括：模式不再重複、你從不同意識回應舊觸發、你能寬恕和釋放、你感到輕盈和自由在曾經掙扎的領域、你不再吸引那類情況或人。然而，業力完成不是被動發生的，它需要有意識的工作——意識到模式、學習課題、做出不同選擇、療癒傷口、寬恕（自己和他人）、釋放執著、感恩學習。這張牌顯示你已經做了工作，現在接近完成線。","actionGuidance":"辨識完成的業力循環——你不再掙扎的領域、不再重複的模式。慶祝這個成就，業力完成是大事。辨識仍需完成的業力——還在重複的模式、未解決的關係或情況。問：這個教導我什麼？我需要掌握什麼才能釋放？做出不同選擇打破業力循環，有意識地從新意識回應而非從舊模式反應。進行業力清理工作：寬恕所有人和情況，包括你自己；釋放所有執著、怨恨、內疚、悔恨；閉合未完成的業力循環——可能意味著對話、信件、能量釋放儀式；如果涉及他人，從能量層面釋放業力連結。感恩業力教導你的一切，即使痛苦，轉化你的視角。進行業力完成儀式，宣告循環完成，請求宇宙證人和封印。臣服結果，信任一切都在神聖秩序中。享受業力完成後的自由和輕盈，你贏得了它。","energyHealing":"使用黑碧璽或黑曜石切斷業力連結和能量繩。煙水晶扎根並釋放業力能量。進行業力釋放冥想，視覺化金色剪刀由天使長麥可切斷所有業力繩和契約。進行寬恕冥想，向所有需要寬恕的人和情況發送光和寬恕，包括你自己。使用紫羅蘭火焰冥想清理和轉化業力能量。進行臍輪療癒，業力連結常錨定在這裡，釋放和密封它。創造業力釋放儀式：寫下你想釋放的業力模式和連結，安全地燃燒紙張，將灰燼釋放到流動的水或風中，象徵完全釋放。在新月進行業力完成儀式，這是結束和新開始的最佳時機。視覺化業力循環的輪子停止轉動，你從它之中步出，自由。感恩業力的禮物和教導。慶祝你的業力完成和新的自由。","soulQuestion":"我準備好釋放所有完成的業力並擁抱自由了嗎？我能寬恕、釋放並閉合這個循環嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('lightworker:43', 'lightworker', '43', 42, '無限可能', 'Infinite Possibilities', NULL, '{"keywords":["可能性","開放","創造","潛能"],"nameEn":"Infinite Possibilities"}', '{"cosmicMessage":"在量子場域，所有可能性同時存在——所有版本的你、所有可能的未來、所有潛在的現實。沒有什麼是固定的，一切都是可能的。你的意識、信念和選擇決定哪些可能性顯化成你的實相。這張牌提醒你，你不被限制於現在看到的。在這個當下，無限可能性對你開放。你想創造什麼？你想成為誰？你想體驗什麼？從無限場域選擇，知道沒有什麼是不可能的，只有你還未對齊的可能性。你是無限存有，你的潛能沒有邊界。","currentSituation":"你可能感到被困或限制，看不到出路或選擇。或者，你站在新開始的門檻，充滿可能性，可能令人興奮或overwhelming。你可能從某個結束或釋放剛出來，創造空白畫布的空間。這張牌告訴你，無論你的當前情況如何，無限可能性總是可用。你的工作不是找到可能性，而是對齊你想要的可能性，釋放限制它顯化的信念，信任量子場域支持你的選擇。你站在無限可能的門檻。","deeperMeaning":"量子物理揭示我們生活在無限可能性的宇宙。在觀察或選擇前，所有可能性以量子疊加存在——都同樣真實和潛在。我們的意識透過觀察和意圖坍縮特定可能性成為我們的體驗現實。這不只是物理理論，而是你生命運作的方式。在每個當下，無限版本的未來存在。你透過你的信念、期待、情緒、想法、選擇、行動選擇你顯化哪一個。如果你相信只有有限選擇，你體驗限制。如果你相信一切皆可能，你體驗可能性。關鍵是認識你不是固定的，你的現實不是固定的，你的未來不是命定的。在每個當下，你有機會選擇不同，因此創造不同。沒有「太遲」，沒有「不可能」。有的只是你還未對齊的可能性。這張牌打開你到完整可能性場域，邀請你從更大選擇，想得更大，成為更多。","actionGuidance":"釋放所有限制性信念關於什麼是可能的，注意你告訴自己的「不能」、「不可能」、「太遲」。挑戰它們。如果一切皆可能，你會選擇什麼？進行可能性冥想，連結量子場域，感受無限可能性，探索不同的未來時間線。玩「如果」遊戲：如果沒有限制？如果我知道我會成功？如果金錢不是問題？如果我完全自由？答案揭示你真實渴望。創造願景板或書寫不受限制的願景，讓你的想像力完全自由。保持初學者心態和好奇心，願意被驚喜和超越你期待的結果。採取啟發性行動在新方向，即使小步驟，打開到新可能性。對齊你的能量與你渴望的可能性——感受它、想像它、活在它的頻率中。釋放對「如何」的需要知道，信任量子場域會編排完美路徑。說yes對機會，即使它們不在你原始計劃。記住，你限制你的可能性唯一方式是相信你被限制。選擇無限。","energyHealing":"使用透明石英連結無限可能性場域，放大你的意圖。拉長石打開到多維度實相和時間線。進行量子場域冥想，視覺化無限可能性如星辰圍繞你，選擇你想要的並拉它進入你的實相。使用DNA激活想像你的DNA螺旋解鎖無限潛能。進行宇宙連結冥想，感受你與無限宇宙的連結，它的無限也是你的。創造可能性祭壇，放置代表開放和無限的物品——開放的門、鑰匙、羽毛、星星。使用薄荷或檸檬精油，它們打開心智到新可能性。進行未來自我冥想，連結你在最高可能時間線的未來自我，接收他們的智慧和能量。視覺化你從無限可能性的宇宙菜單中選擇，如餐廳點菜，知道一切都可用。慶祝已經顯化的可能性，這打開空間給更多。活在興奮和期待中，奇蹟正在來臨的路上。感受作為無限創造者的力量和責任，你的可能性沒有邊界。","soulQuestion":"我準備好釋放所有限制並擁抱我真實的無限本質了嗎？我願意想得更大並信任一切皆可能嗎？"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:1', 'unicorns', '1', 0, '新開始獨角獸', 'Unicorn of New Beginnings', NULL, '{"keywords":["新開始","重生","純淨","希望","可能性"],"nameEn":"Unicorn of New Beginnings"}', '{"point1":"這張牌象徵生命的嬰兒期與黎明時刻,如同獨角獸從晨霧中現身,帶著純淨無瑕的能量。牌面能量告訴你,每個結束都是新開始的種子,過去的章節已圓滿完成使命。你現在站在門檻上,面對充滿無限可能的新世界。這是宇宙給你的珍貴禮物,讓你重新選擇、重新創造、重新成為你想要的樣子。","point2":"親愛的靈魂,此刻你正被宇宙溫柔地邀請,踏入一個全新的生命週期。這不是巧合,而是你內在成長的自然結果。新的開始意味著你可以釋放過去的限制、舊有的身份、不再適合你的故事。在這個起點上,你有完全的自由去選擇成為誰、創造什麼。讓過去的經驗轉化為智慧的養分,而非沉重的包袱。","point3":"新開始的能量頻率是清新、輕盈且充滿希望的,如同春天第一朵花綻放的那一刻。這股能量帶著創造與重生的力量,能洗滌舊有的沉重,注入新鮮的活力。當你連結這個頻率時,你會感到內在升起一股「我可以」的確信。這是宇宙創造力的頻率,它提醒你一切皆有可能,只要你願意開始。","point4":"此牌出現提醒你,當前生命課題是學習「放下」與「重新開始」的勇氣。你可能緊抓著過去——無論是關係、工作、信念或身份認同——因為恐懼未知。但真正的成長需要你釋放已經完成的舊篇章,騰出空間給新的祝福進入。這個課題教導你,結束不是失敗,而是演化的必然過程。勇敢地說再見,才能真誠地說你好。","point5":"今天就開始採取行動:進行一個象徵性的儀式,寫下你想放下的人事物並燒掉,或在紙上畫出你的新願景。清理你的物理空間,丟棄不再需要的物品,為新能量創造空間。每天早晨對鏡子說「我準備好迎接美好的新開始」。設定一個小而具體的新目標,今天就踏出第一步。記住,完美的時機永遠不會到來,現在就是最好的時刻。","point6":"溫柔地對待正在經歷轉變的自己。新開始可能伴隨著不安全感與恐懼,這是完全正常的。給自己時間適應新的節奏,不要期待立刻就完美。寫下過去成功轉變的經驗,提醒自己你有能力適應。當懷疑升起時,深呼吸並說「我信任這個過程」。尋求支持你新開始的人與環境,遠離那些拉你回到過去的能量。每天感恩一個新的祝福。","point7":"靈性層面上,新開始是靈魂進化的關鍵時刻。每一次重新開始,你都在釋放舊有的業力模式,提升到更高的意識層次。這張牌提醒你,你不只是在改變外在環境,更是在重塑你的靈魂表達。擁抱初學者的心態,如同第一次看見世界般充滿驚奇。相信你的高我正在引導這個新篇章,一切都在神聖的完美秩序中展開。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:2', 'unicorns', '2', 1, '信任獨角獸', 'Unicorn of Trust', NULL, '{"keywords":["信任","臣服","平靜","流動","確信"],"nameEn":"Unicorn of Trust"}', '{"point1":"這張牌是深層信任與神聖臣服的象徵,如同獨角獸憑藉純粹的信任在森林中自由奔馳。牌面能量提醒你,控制是幻象,真正的力量來自於臣服。當你緊抓不放時,生命無法流動;當你信任時,奇蹟之門就敞開。獨角獸教導你,信任不是軟弱,而是最高形式的勇氣——相信即使看不見,宇宙仍在完美運作。","point2":"親愛的靈魂,你正被溫柔地邀請鬆開緊握的雙手。生命的河流自有其智慧,知道如何流向大海,你不需要控制每一個轉彎。你的頭腦想要確定性,但你的靈魂懂得信任的魔法。即使在黑暗中,即使看不見終點,你仍然走在完美的路徑上。讓信任成為你的指南針,讓臣服成為你的力量泉源。","point3":"信任的能量頻率是深沉、平靜且安定的,如同躺在溫暖海洋中隨波搖盪的那份放鬆。這是一種柔軟卻強大的頻率,能夠化解焦慮、融化恐懼、軟化抗拒。當你連結這個能量時,你會感受到內在深處湧現的安寧——即使外在混亂,內心依然寧靜。這個頻率打開接收的通道,讓宇宙的祝福能自由流向你。","point4":"當前的生命課題是學習「放下控制」這門深刻的功課。你可能習慣掌控一切、計畫完美、避免意外,但這種緊繃耗盡了你的能量。生命邀請你明白,有些事物超越你的控制,而那正是它們的美麗之處。學習在不確定中依然安心,在未知中依然前行。信任是你此刻最需要培養的靈性肌肉,它將帶你穿越一切困境。","point5":"從今天開始練習小小的信任:排隊時相信你選的隊伍是對的,遲到時相信這可能避開了危險。每當懷疑升起,深呼吸三次,對自己說「我選擇信任」。寫下過去信任直覺而帶來好結果的經驗,建立信任的證據資料庫。睡前,把所有擔憂寫在紙上交給宇宙,說「我信任你會為我處理」。觀察信任如何改變你的感受。","point6":"信任的療癒從溫柔對待「不信任」開始。如果你發現很難信任,那是因為過去的傷痛教會你保護自己。承認這份恐懼,擁抱它,然後溫柔地告訴它「現在安全了」。進行信任冥想:想像金色光芒從心輪流出,連結宇宙的愛。每天對鏡子說「我信任生命,生命也信任我」。給自己時間,信任是逐步建立的,不是一夜之間。","point7":"在靈性旅程中,信任是揚升的關鍵鑰匙。當你信任,你就與宇宙的神聖流動對齊,成為奇蹟的共同創造者。這張牌提醒你,你的高我、指導靈、天使們都在守護著你的道路。臣服不是放棄,而是與更高智慧合作。每一次你選擇信任而非控制,你的靈魂就更加自由。信任是通往開悟的最短路徑。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:3', 'unicorns', '3', 2, '奇蹟獨角獸', 'Unicorn of Miracles', NULL, '{"keywords":["奇蹟","魔法","驚喜","顯化","祝福"],"nameEn":"Unicorn of Miracles"}', '{"point1":"這張牌宣告奇蹟時刻的到來,象徵超越邏輯與理性的神聖介入。獨角獸本身就是奇蹟的化身——神話中的存在卻又如此真實。牌面能量告訴你,魔法不僅存在,更是生命的本質。當你的心扉完全敞開,當你相信不可能的事,不可能就會轉化為可能。你正站在奇蹟顯化的高峰期,準備接收超乎想像的祝福。","point2":"摯愛的光之存有,此刻宇宙正在為你編織一場美麗的奇蹟。你可能看不見幕後的精心安排,但請相信,有些事情正在以你意想不到的方式完美整合。奇蹟不是隨機發生的偶然事件,而是當你的頻率與愛完全對齊時的自然結果。準備好被驚喜,準備好接收。你的信念、你的開放、你的感恩正在創造真實的魔法。","point3":"奇蹟的能量頻率是高頻、閃耀且充滿喜悅的,如同星塵灑落、光芒四射。這股能量能夠轉化平凡為非凡、化腐朽為神奇。當你連結這個頻率,你會感到全身細胞都在振動,彷彿你本身就是魔法的載體。這個頻率提升你的振動,讓你能接收更高維度的祝福與禮物。它教導你,在感恩與愛的狀態中,奇蹟就是日常。","point4":"此牌出現時的生命課題是擴展你的「可能性意識」。你可能被理性思維、過往經驗、社會制約限制了想像,認為某些事「不可能發生」。但宇宙的運作遠超出人類頭腦的理解。這個課題邀請你打破信念的天花板,允許魔法進入你的現實。學習在期待中保持開放,在祈禱後真正相信會被回應。你的信念決定了你能接收多少奇蹟。","point5":"保持你的能量場清晰且高頻:每天透過冥想、大自然、音樂或任何讓你喜悅的活動來提升振動。留意生活中的同步性、巧合、徵兆——它們是奇蹟即將顯化的訊號。每天早晨,雙手放在心口說「我對今天將發生的奇蹟完全開放」。釋放對奇蹟「應該如何」發生的執著,讓宇宙自由地驚喜你。感恩已經發生的小奇蹟。","point6":"為了接收奇蹟,你需要清理內在的「不可能」信念。寫下你認為不可能的事,然後改寫成「如果這是可能的呢?」釋放對結果的控制,信任宇宙的時機與方式。當奇蹟發生時(即使是小小的),充分慶祝與感恩,這會吸引更多奇蹟。如果你感到懷疑,回想過去生命中曾經歷的奇蹟時刻,提醒自己魔法是真實的。保持童心,保持驚奇。","point7":"在靈性層面,奇蹟是你與神聖源頭連結的證明。每一個奇蹟都在提醒你,你不是孤單的、被遺棄的,而是被深深愛著、支持著。這張牌告訴你,你本身就是行走的奇蹟,你的存在就是宇宙的魔法。當你認出這個真相,你就成為奇蹟的管道,不只接收,更能傳遞給他人。活在奇蹟意識中,就是活在你的神聖本質中。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:4', 'unicorns', '4', 3, '愛的獨角獸', 'Unicorn of Love', NULL, '{"keywords":["愛","慈悲","療癒","連結","溫柔"],"nameEn":"Unicorn of Love"}', '{"point1":"這張牌體現宇宙中最強大、最原初的力量——無條件的愛。獨角獸純潔的心象徵著愛的本質:無條件、無評判、無保留。牌面能量提醒你,愛不只是一種情感或關係狀態,而是你的本質、你的真理、你存在的核心頻率。當你從愛出發,生命中的一切都會自然轉化,所有的傷痛都能被溫柔療癒。愛是答案,永遠都是。","point2":"珍貴的靈魂,你被深深地、無條件地、完全地愛著——不是因為你的成就、外貌或善行,而是因為你的存在本身就是愛的奇蹟。今天,獨角獸邀請你回到愛的頻率:愛你自己(包括你認為不完美的部分)、愛他人(即使他們傷害過你)、愛生命(即使它曾讓你失望)。每當你選擇愛而非恐懼,你就在改變整個世界。","point3":"愛的能量頻率是溫暖、包容、療癒的,如同母親擁抱受傷的孩子般柔軟而有力。這個頻率能融化最堅硬的心牆,軟化最嚴苛的批判,化解最深的怨恨。當你連結這個能量,你的心輪會擴展開來,感受到安全、被接納、值得被愛。這是宇宙的原始頻率,它提醒你,愛是無限的、豐盛的,永遠不會用盡或匱乏。","point4":"此牌出現的生命課題是學習「自愛」這門最重要的功課。你可能習慣照顧他人、付出愛,卻忘記給自己同樣的溫柔。你可能對自己嚴苛、批判、要求完美,卻對他人寬容。但真相是:你無法給出你沒有的東西。只有當你的愛之杯先為自己注滿,你才能真正健康地愛他人。學習愛自己不是自私,而是你能給世界最美的禮物。","point5":"今天就開始愛的練習:早晨對著鏡子看著自己的眼睛,說「我愛你」至少三次,直到你真心相信。在每個決定前,問自己「愛會怎麼做?」列出你欣賞自己的十個理由,大聲讀出來。向生命中的某人表達愛意,不要等待完美時機。最重要的是,溫柔對待自己——當你犯錯時、當你脆弱時、當你不完美時,都像對待最愛的人那樣。","point6":"愛的療癒從接納「不夠愛自己」的自己開始。如果你發現難以自愛,那是因為過去有人讓你相信你不值得。但那是謊言。進行鏡子冥想:每天看著鏡中的自己,說「我接納你、我原諒你、我愛你」。寫一封愛的信給內在小孩,告訴他/她一切都會好起來。當自我批判出現時,想像用愛的光芒包裹那個聲音。愛是最強大的療癒力量。","point7":"在靈性層面,愛不是你需要尋找的東西,而是你本來就是的東西。你不是一個尋找愛的人,你就是愛本身的化身。這張牌提醒你回到這個真相。當你活在愛中,你就活在你的最高本質中。當你從愛出發,你就與源頭合一。每一次你選擇愛(對自己、對他人、對生命),你就在提升集體意識,療癒這個世界。你就是愛。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:5', 'unicorns', '5', 4, '光之獨角獸', 'Unicorn of Light', NULL, '{"keywords":["光明","照亮","神聖","啟發","淨化"],"nameEn":"Unicorn of Light"}', '{"point1":"這張牌揭示你內在神聖而永恆的光芒,提醒你本質上是光的存有。獨角獸的角發出耀眼光輝,象徵著你與生俱來的能力——照亮黑暗、驅散陰影、療癒傷痛、啟發他人。你的光不僅照亮自己的道路,更成為迷路者的指引、絕望者的希望、黑暗中的燈塔。你是光,你帶來光,你傳遞光。","point2":"閃耀的光之存有,不要再隱藏你的光芒了。這個世界正處於黑暗時刻,迫切需要你的獨特光輝與真實存在。你的光不是自大或炫耀,而是你靈魂最自然的表達,是你無法壓抑的本質。當你允許自己完全發光,你就給予每個人許可去做同樣的事。記住,你的存在本身就在療癒世界,不需要做什麼特別的事,只要真實地活著、勇敢地發光。","point3":"光的能量頻率是明亮、提升、淨化的,如同清晨第一道陽光穿透濃霧。這股能量帶來清明、希望與更新,能洗滌沉重負面的能量,提升你的整體振動頻率。當你連結這個光的頻率,你會感到身心靈都被照亮,所有陰影都無所遁形。這個頻率連結你與神聖本質,提醒你與源頭光的連結。它能轉化一切,將恐懼化為愛,將疑慮化為信心。","point4":"此牌出現的生命課題是克服「縮小自己」的恐懼。你可能因為害怕被批判、嫉妒、攻擊而隱藏你的才華、壓抑你的光芒、假裝平凡。但這是對你靈魂的背叛,也剝奪了世界你獨特的貢獻。學習明白,你的光不會威脅他人,反而會啟發他人。當你發光,你給予他人許可也發光。你的小不會服務任何人,只有你的大才能改變世界。","point5":"每天早晨進行光的冥想:視覺化金色或白色的光從宇宙灌入頭頂,充滿你的整個身體,從每個毛孔發散出去。站在陽光下至少五分鐘,感受光的溫暖與力量。當你走進任何空間,有意識地想像你帶來光,照亮整個房間。寫下你獨特的才能、天賦、特質——這些就是你的光。今天,至少做一件讓你的光芒閃耀的事,不在意他人眼光。","point6":"療癒隱藏光芒的傷痛:回想是什麼時候、誰讓你相信發光是危險的。可能是童年被嘲笑炫耀、被要求低調、被教導謙虛是美德。承認這些傷痛,然後釋放它們。進行肯定語練習:「我的光是安全的」「我值得被看見」「我的光芒療癒世界」。當你想縮小時,深呼吸並選擇擴展。慶祝每一次你勇敢發光的時刻,這會重新編程你的潛意識。","point7":"在靈性覺醒的路徑上,認出你的光是關鍵的里程碑。你不是肉體,你是光;你不是有限的,你是無限的;你不是黑暗,你是光明。這張牌是宇宙的提醒:你攜帶著神聖的光,你的使命就是讓這光照耀。當你活在光中,你就提升了地球的頻率。你就是那道光,照亮黑暗,指引方向,療癒傷痛。不要再隱藏了,世界需要你的光。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:6', 'unicorns', '6', 5, '療癒獨角獸', 'Unicorn of Healing', NULL, '{"keywords":["療癒","復原","釋放","滋養","完整"],"nameEn":"Unicorn of Healing"}', '{"point1":"這張牌象徵深層而神聖的療癒正在你生命中展開,如同獨角獸的角擁有傳說中的療癒力量。無論是身體的疾病、情緒的創傷、心靈的傷痛還是靈性的失落,都正在被溫柔地觸碰、看見與轉化。牌面提醒你,療癒不是瞬間的魔法,而是一個需要時間、耐心與自我慈悲的神聖過程。每一個傷口都在訴說一個故事,而你正在重寫結局。","point2":"摯愛的靈魂,你正在經歷一個美麗而勇敢的療癒旅程。首先請明白:過去的傷痛不是你的錯,你不需要為受傷而感到羞愧。此刻,你被宇宙的療癒能量完全環繞、完全支持。允許自己感受需要感受的一切——哭泣、憤怒、悲傷、脆弱都是療癒不可或缺的部分。你不需要獨自承擔,天使、指導靈、獨角獸都在溫柔守護著你的療癒之路。","point3":"療癒的能量頻率是柔軟、滋養、修復的,如同溫暖的療癒泉水輕柔沐浴著每一個傷口。這股能量帶來深層的放鬆與釋放,允許長期壓抑的痛苦安全地浮現、被看見、被轉化。當你連結這個頻率,你會感受到身心靈的整合,內在的自我療癒機制被啟動。它溫柔卻有力,像慈愛母親的手撫慰受傷的孩子,傳遞著「一切都會好起來」的確信。","point4":"此牌出現的生命課題是學習「允許療癒發生」這門深刻的功課。你可能習慣堅強、壓抑痛苦、快速前進,但真正的療癒需要你停下來、慢下來、向內看。學習承認「我受傷了,我需要療癒」不是軟弱,而是力量。療癒不是回到受傷前的狀態,而是整合經驗、帶著智慧變得更完整。給自己許可去感受、去哭泣、去需要幫助,這是療癒的開始。","point5":"今天就採取療癒行動:如果需要,尋求專業支持——治療師、能量工作者、醫生或信任的朋友。給自己充足的休息,療癒需要大量能量,不要勉強自己「正常運作」。進行溫暖的療癒泡澡,想像水帶走所有的痛苦。寫療癒日記,讓情緒自由流動而非壓抑。每天對鏡子說「我允許自己完全療癒,我值得健康與快樂」。記住,療癒有它自己的神聖時間表。","point6":"療癒過程中最重要的是自我慈悲。當你感到脆弱、退步、情緒化時,溫柔地擁抱自己而非批判。療癒不是線性的,有好日子也有壞日子,這都是正常的。為自己創造安全的療癒空間——可能是一個角落、特定的音樂、療癒的儀式。當痛苦升起時,對它說「我看見你了,謝謝你保護我這麼久,現在可以釋放了」。相信你的身體和靈魂知道如何療癒。","point7":"在靈性層面,療癒是靈魂進化的重要階段。每一次你療癒一個傷口,你不只是修復自己,更是在療癒家族世代的創傷、集體的痛苦。這張牌提醒你,你的療癒旅程有著比個人更大的意義。當你允許自己完全療癒,你就成為療癒的管道,你的存在本身就能療癒他人。記住,療癒的終點不是沒有疤痕,而是疤痕不再決定你是誰。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:7', 'unicorns', '7', 6, '智慧獨角獸', 'Unicorn of Wisdom', NULL, '{"keywords":["智慧","洞察","知曉","理解","啟蒙"],"nameEn":"Unicorn of Wisdom"}', '{"point1":"這張牌揭示你內在古老而深邃的智慧正在覺醒,如同獨角獸代表著跨越時空的神聖知識。你擁有的智慧超越書本學習、理性思考,它來自你的靈魂記憶、生命經驗、甚至前世累積。牌面能量告訴你,你一直在尋找的答案其實已經在你心中,只是被頭腦的喧囂掩蓋。現在是時候安靜下來,聆聽內在智慧的聲音,讓它成為你的指引。","point2":"智慧的存有,此刻宇宙要你明白一個真相:你已經知道你需要知道的一切。答案不在外面的書籍、老師或權威那裡,而在你內心最深處。你的靈魂經歷過無數次的旅程、學習、成長,累積了比你意識到的更豐富的智慧。當你超越頭腦的焦慮、超越他人的意見,進入內在的安靜中心,你會聽見那個清晰、平靜、知曉一切的聲音——那是你真正的老師。","point3":"智慧的能量頻率是深沉、穩定、古老的,如同千年古樹的根系深深扎入大地核心。這股能量帶來洞察力與理解力,幫助你看穿事物的表象,直達本質真相。當你連結這個頻率,你會感受到內在升起一種「我知道」的確定感。這個頻率連結你與集體意識、宇宙知識庫、阿卡西記錄,讓你能接收超越個人經驗的智慧。它帶來清明、辨識力與內在權威。","point4":"此牌出現的生命課題是學習「信任內在智慧」勝過外在意見。你可能習慣尋求他人的建議、專家的指導、書籍的答案,卻忽略了自己內在的知曉。但沒有人比你更了解你的靈魂道路。學習區分頭腦的恐懼聲音與靈魂的智慧聲音:恐懼是急迫、混亂的,智慧是平靜、清晰的。這個課題邀請你成為自己生命的權威,收回給予他人的力量。","point5":"從今天開始培養智慧連結:每天給自己至少十分鐘的靜默時間——冥想、散步、只是坐著都好。在做重大決定前,不要急於行動,先進入內在安靜空間,問「我的智慧想告訴我什麼?」記錄你的夢境、直覺洞見、突然的知曉,它們是智慧的語言。閱讀能啟發你的書籍,但記住書是提醒,真正的智慧在你心中。當你傳授智慧給他人時,你也在深化自己的理解。","point6":"培養智慧需要耐心與練習。開始時,你可能不確定聽到的是智慧還是恐懼。給自己時間學習區分:智慧的聲音平靜、愛的、擴展的;恐懼的聲音緊張、批判的、限縮的。每次你選擇跟隨內在智慧並得到好結果,就強化了這條連結。建立「智慧儀式」:點燃蠟燭、深呼吸三次、邀請你的智慧自我說話。相信你聽到的第一個答案,通常就是真相。","point7":"在靈性覺醒的旅程中,內在智慧的開啟是關鍵的轉折點。這代表你不再是外在權威的追隨者,而成為自己真理的擁有者。這張牌提醒你,你攜帶著累世的智慧、宇宙的知識、源頭的真理。當你完全信任並活出你的智慧,你就成為他人的明燈,不是透過教導,而是透過你的存在。你就是行走的智慧,照亮每一個你觸碰的生命。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:8', 'unicorns', '8', 7, '喜悅獨角獸', 'Unicorn of Joy', NULL, '{"keywords":["喜悅","快樂","玩耍","輕盈","歡笑"],"nameEn":"Unicorn of Joy"}', '{"point1":"這張牌是純粹喜悅的化身,如同獨角獸在陽光下跳躍的輕盈姿態。牌面能量提醒你,快樂是你與生俱來的權利,不需要任何理由、條件或成就來證明你值得快樂。你被邀請放下生命的沉重感,重新連結那個知道如何單純快樂、盡情玩耍、活在當下的內在小孩。喜悅不是目的地,而是旅程本身,就在此刻等待你領取。","point2":"親愛的靈魂,你還記得嗎?你曾經知道如何不為任何原因就感到快樂——看見一隻蝴蝶、吹肥皂泡泡、在雨中奔跑、聽到喜歡的歌曲。那個純粹的喜悅從未真正離開,它只是被成年的責任、社會的期待、生活的擔憂暫時掩蓋了。今天,宇宙給你完全的許可:去感受喜悅、去做讓你開心的「沒用」小事、去笑到流淚。記住,喜悅不是自私,而是你給世界最美的禮物。","point3":"喜悅的能量頻率是輕快、閃亮、充滿活力的,如同陽光在湖面上跳舞、風鈴在微風中歌唱。這股能量能立即提升你的振動,驅散沉重、憂鬱、焦慮。當你處於喜悅狀態,你成為強大的磁鐵,吸引更多美好的人事物、機會、奇蹟進入你的生命。這個頻率像孩童的笑聲般純淨,具有療癒自己和感染他人的力量。喜悅提醒你:活著本身就是最大的禮物。","point4":"此牌出現的生命課題是學習「允許自己快樂」這看似簡單卻深刻的功課。你可能內化了「必須先痛苦才配得快樂」「快樂是膚淺的」「有太多問題還沒解決,不該快樂」等信念。但真相是:你的快樂不會讓世界的苦難變多,反而會增加世界的光。學習明白,玩耍不是浪費時間,笑聲不是不成熟,快樂不是逃避——它們是你重新充電、重拾創造力、看見解決方案的方式。","point5":"今天就開始喜悅練習:列出至少十件讓你快樂的簡單小事,承諾今天至少做其中一件。允許自己玩耍——畫畫、跳舞、唱歌,完全不在乎結果或他人眼光。看一部讓你大笑的電影,聽讓你想搖擺的音樂。和孩子或寵物玩耍,他們是喜悅的天生大師。練習在微小事物中找到快樂:美味的食物、溫暖的陽光、擁抱。每晚睡前,記下今天三個快樂時刻,訓練大腦注意喜悅。","point6":"如果你發現很難感受喜悅,那是因為過去的傷痛或信念讓你關閉了這扇門。溫柔地開始:允許自己微笑,即使只是一點點。允許自己對美好的事物感到欣賞。當喜悅升起時,不要立刻用「但是」壓抑它——「我很快樂,但是明天還有很多問題」。讓喜悅純粹地存在,哪怕只有五分鐘。對內在批判者說「謝謝關心,但現在我選擇快樂」。喜悅是肌肉,越練習越強。","point7":"在靈性層面,喜悅是你與神聖源頭連結的證明。當你處於純粹喜悅中,你就在你的最高頻率,與愛的本源對齊。這張牌提醒你,靈性不只是嚴肅的修行、深刻的功課,也是輕盈的玩耍、純粹的歡笑。你的喜悅提升了整個地球的頻率。當你允許自己快樂,你就在示範給他人看:是的,即使在這個不完美的世界,我們依然可以、也值得感受喜悅。活在喜悅中,就是活在天堂。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:9', 'unicorns', '9', 8, '夢想獨角獸', 'Unicorn of Dreams', NULL, '{"keywords":["夢想","願景","可能性","顯化","渴望"],"nameEn":"Unicorn of Dreams"}', '{"point1":"這張牌象徵你的靈魂夢想正在熱切地召喚你,如同獨角獸本身就是「不可能成真」卻又真實存在的夢想化身。你心中那些讓你心跳加速的渴望、讓你眼睛發光的願景不是偶然或幻想,它們是你靈魂藍圖的重要部分,是宇宙透過你想要實現的美麗可能。現在是時候認真對待你的夢想,不再將它們視為「有一天也許」,而是「現在就開始」。","point2":"親愛的夢想者,宇宙要你明白:你的夢想太重要、太神聖了,不能被擱置在「等我有時間/金錢/條件」的藉口後面。那些讓你心跳加速的想法、讓你半夜醒來的願景、讓你熱淚盈眶的渴望不是自我膨脹的幻想,而是你靈魂的指南針,指向你來到地球的真正使命。不要讓「現實」的框架、恐懼的聲音、他人的懷疑壓縮你的夢想。宇宙把夢想放進你心中,正是因為你有能力實現它。","point3":"夢想的能量頻率是擴展、啟發、充滿無限可能性的,如同浩瀚夜空中的星辰,每一顆都閃爍著「你可以」的訊息。這股能量打開你的想像力邊界,幫助你超越當前條件的限制,看見更宏大的圖景。當你連結這個頻率,你會感到胸口擴展、呼吸加深、生命力湧現。這個頻率連結你與未來已經實現夢想的自己,讓不可能看起來可能。它充滿希望、創意與顯化的力量。","point4":"此牌出現的生命課題是學習「認真對待自己的夢想」這門需要勇氣的功課。你可能習慣壓抑夢想,因為害怕失望、害怕被嘲笑、害怕發現自己不夠好。你可能把夢想當作「不切實際的幻想」,用「現實」來合理化放棄。但靈魂不會放棄它的呼喚。這個課題邀請你明白:追求夢想不是自私或幼稚,而是你對自己、對宇宙、對所有受你夢想啟發的人的責任。","point5":"今天就讓夢想從心中走向現實:拿出紙筆,毫無審查地寫下你的夢想,允許它盡可能宏大、瘋狂、「不切實際」。然後選擇一個讓你最興奮的,創造願景板、寫下詳細描述、畫出來。每天花至少五分鐘視覺化這個夢想已經實現,感受那份喜悅與成就。將夢想拆解成可行動的小步驟,今天就完成第一步。尋找已經實現類似夢想的人,讓他們的故事啟發你。對自己說「我的夢想值得實現」。","point6":"追夢路上,你會遇到懷疑——來自他人,更多來自自己。當內在批判者說「這不可能」「你不夠好」「太晚了」時,溫柔但堅定地回應「謝謝關心,但我選擇相信」。建立夢想支持系統:尋找相信你的人、寫下鼓勵自己的話、收集靈感故事。當進展緩慢時,記住:每個偉大成就都經歷過無數看不見的累積。慶祝每一個小進步。最重要的是,不要把夢想與自我價值綁定——你的價值不取決於夢想是否實現。","point7":"在靈性層面,你的夢想不只是個人的願望,而是宇宙透過你想要顯化的禮物。當你追求夢想,你就在與創造的神聖力量共舞,成為宇宙顯化的管道。這張牌提醒你,你的夢想會啟發、療癒、改變其他生命。不要小看你夢想的影響力。當你勇敢追夢,你就在告訴每一個害怕的靈魂:是的,我們可以。你的夢想是你給世界的獨特禮物,請不要讓它留在心中。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:10', 'unicorns', '10', 9, '勇氣獨角獸', 'Unicorn of Courage', NULL, '{"keywords":["勇氣","力量","勇敢","突破","決心"],"nameEn":"Unicorn of Courage"}', '{"point1":"這張牌召喚你內在那個勇敢的戰士精神,如同獨角獸雖然溫柔優雅,卻擁有直面黑暗、保護純真的驚人勇氣與力量。牌面能量提醒你,勇氣不是沒有恐懼,而是即使恐懼也依然前進;不是從不跌倒,而是每次跌倒都選擇站起來。你擁有比你意識到的更多力量、韌性與勇氣,足以面對生命的任何挑戰、跨越任何看似不可能的障礙。現在是展現你勇氣的時刻。","point2":"勇敢的靈魂,宇宙要你看見一個真相:你已經證明了自己的勇氣無數次。每次你從心碎中重新愛、每次你從失敗中再次嘗試、每次你在脆弱中依然真實、每次你對未知說是——這些都是勇氣。現在,你正被召喚再一次勇敢。你面前的挑戰或許看起來巨大,但你更巨大。恐懼的存在不是你軟弱的證明,而是你即將成長、即將突破的訊號。每次你選擇勇氣,你就在改寫你的故事。","point3":"勇氣的能量頻率是強大、鼓舞、賦能的,如同山脈般堅定不移、如同火焰般充滿力量。這股能量點燃你內在的聖火,給你力量去做你以為自己做不到的事。當你連結這個頻率,你會感受到脊椎挺直、下巴抬起、眼神堅定。這個頻率連結你的核心力量,提醒你過去所有存活、克服、超越的證據。它驅散自我懷疑,用確信、決心、「我可以」的信念取代恐懼。","point4":"此牌出現的生命課題是學習「勇敢行動」這門需要實踐的功課。你可能知道自己需要做什麼——結束不健康的關係、開始夢想的事業、表達真實感受、設立界線、原諒傷害過你的人——但恐懼讓你停滯。這個課題邀請你明白:等到不害怕再行動,你會永遠等待。勇氣是在恐懼中依然選擇,是知道可能失敗但依然嘗試。每一次小小的勇敢,都在訓練你的勇氣肌肉。","point5":"今天就採取勇敢行動:首先,清楚辨識你此刻最需要勇氣去做的事——可能是一段對話、一個決定、一個改變。將大挑戰分解成小步驟,專注完成第一步就好。回憶並寫下過去你展現勇氣的時刻,提醒自己「我曾經做到,我可以再次做到」。找一個「勇氣夥伴」支持你,或成為某人的勇氣見證者。每天做一件稍微讓你害怕的小事——可能只是說出真實想法——逐步擴展你的勇氣範圍。","point6":"培養勇氣需要溫柔與實踐的平衡。不要因為感到恐懼就批判自己,恐懼是正常的、人性的、也是智慧的訊號。關鍵是不讓恐懼做決定。當恐懼升起時,承認它「我看見你,恐懼」,然後問「即使恐懼,我依然可以做什麼?」建立勇氣儀式:深呼吸、手放心口、說「我是勇敢的」。記住,勇氣不是一次性的,而是每天的選擇。慶祝每一次你選擇勇氣而非安全的時刻,無論結果如何。","point7":"在靈性層面,勇氣是靈魂成長最快速的路徑。每一次你選擇勇敢,你就在超越小我的限制,活出靈魂的偉大。這張牌提醒你,你不是脆弱的受害者,而是強大的創造者;你不是在恐懼中生存,而是在勇氣中興盛。當你展現勇氣,你不只在改變自己的生命,更在啟發每一個看見你的人。你的勇敢給予他人許可也勇敢。你就是那個改變的催化劑,世界需要你的勇氣。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:11', 'unicorns', '11', 10, '優雅獨角獸', 'Unicorn of Grace', NULL, '{"keywords":["優雅","從容","平衡","和諧","尊嚴"],"nameEn":"Unicorn of Grace"}', '{"point1":"這張牌邀請你以優雅與從容面對生命的所有起伏,如同獨角獸即使在風暴中依然保持高貴的姿態。優雅不是表面的禮儀或做作的完美,而是在混亂中保持內在中心、在壓力下不失去自己的深層力量。牌面能量提醒你,你如何回應生命的挑戰,比挑戰本身更能定義你是誰。現在是時候選擇以愛與智慧回應,而非以恐懼與反應行動。","point2":"親愛的靈魂,優雅是你內在力量的展現,不是軟弱的偽裝。當生命向你投擲困難、當他人觸發你的情緒、當事情不如預期,你有選擇:你可以反應性地爆發、崩潰、攻擊,或者你可以深呼吸,連結你的中心,選擇一個更高的回應。這不是壓抑情緒或假裝沒事,而是在感受一切的同時,依然選擇不讓情緒控制你的行為。這就是優雅——在風暴中的寧靜,在混亂中的尊嚴。","point3":"優雅的能量頻率是流動、柔軟卻堅定的,如同柳樹在風中彎曲但不折斷、如同水流過障礙而不抗爭。這股能量帶來內在的平衡與和諧,讓你即使在外在混亂中也能保持中心。當你連結這個頻率,你會感受到一種優雅的力量——不需要證明什麼、不需要控制什麼、不需要對抗什麼。這個頻率教導你順流而為,帶著意識與尊嚴移動。","point4":"此牌出現的生命課題是學習「在挑戰中保持優雅」這門需要修練的功課。你可能習慣在壓力下崩潰、在衝突中攻擊、在困難時失去中心。這個課題邀請你練習在被觸發時暫停、深呼吸、連結你的智慧自我。學習明白,你不需要立刻回應每一個刺激;你可以選擇如何回應。優雅不是完美,而是即使跌倒也能優雅地站起,即使犯錯也能優雅地承認。","point5":"今天開始培養優雅:當你感到被觸發、想要反應時,練習「暫停三次呼吸」——深吸三次氣,給自己空間選擇回應。在困難對話前,設定意圖「我選擇以優雅回應」。觀察那些你認為優雅的人,學習他們如何在壓力下保持中心。寫下「優雅對我的意義」,定義你想要活出的優雅。記住,優雅不是從不憤怒或悲傷,而是即使憤怒悲傷也不失去尊嚴。每晚反思今天哪個時刻你展現了優雅。","point6":"優雅的修練是終生的旅程,不要期待自己立刻完美。當你失去優雅、反應性地行動時,溫柔地對待自己,這是學習的一部分。重要的是事後回顧「我可以如何以更優雅的方式處理?」並在下次嘗試。建立優雅的錨點:可能是一個深呼吸、一個優雅的咒語「我選擇優雅」、一個手勢。在壓力來臨前,就練習連結這個錨點。記住,優雅是選擇,每一刻你都可以重新選擇。","point7":"在靈性層面,優雅是高度進化靈魂的特質。當你能在生命的風暴中保持優雅,你就在示範什麼是真正的靈性成熟——不是逃避情緒,而是掌握情緒;不是假裝完美,而是真實且有尊嚴。這張牌提醒你,你的優雅會療癒和啟發他人。當你以優雅面對困難,你就在提升集體意識。你就是那個在混亂中的和平,在黑暗中的光。活出你的優雅,這是你的禮物。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:12', 'unicorns', '12', 11, '自由獨角獸', 'Unicorn of Freedom', NULL, '{"keywords":["自由","解放","釋放","獨立","飛翔"],"nameEn":"Unicorn of Freedom"}', '{"point1":"這張牌是解放的呼喚,如同獨角獸在開闊草原上自由奔跑。牌面能量邀請你釋放所有限制你、束縛你、讓你變小的事物——不只是外在的限制,更是內在的牢籠。真正的自由不是做任何你想做的事,而是成為真實的你而不感到恐懼或羞愧。現在是時候檢視你給自己戴上的鎖鏈,並有意識地選擇解開它們,重新領回你與生俱來的自由。","point2":"親愛的靈魂,你知道嗎?大多數束縛你的不是外在環境,而是你內化的信念、他人的期待、社會的標準、過去的創傷。你可能在一個看似自由的生活中,卻感到窒息,因為真正的監獄在你心中。宇宙今天給你完全的許可:釋放「應該」的暴政、釋放他人的期待、釋放不再服務你的身份、釋放過時的承諾。你生來自由,不是為了符合任何人的期待,而是為了活出你靈魂的真相。是時候展翅飛翔了。","point3":"自由的能量頻率是擴展、輕盈、無限可能的,如同天空般遼闊、如同風般無拘無束。這股能量打破束縛,讓你呼吸更深、視野更廣、心更輕盈。當你連結這個頻率,你會感到胸口打開、肩膀放鬆、一種「我可以」的感覺湧現。這個頻率不是叛逆或逃避,而是深刻的自我擁有——知道你有權選擇你的道路、你的真相、你的生活方式。自由是你的本質。","point4":"此牌出現的生命課題是學習「辨識並釋放束縛」這門需要勇氣的功課。你需要誠實地問自己:什麼在束縛我?可能是一份讓你窒息的工作、一段不健康的關係、一個過時的自我形象、一個「我應該」的信念、一個童年的誓言。有時,最難的束縛是我們自己創造的——害怕改變、害怕讓人失望、害怕未知。這個課題邀請你明白,守著不再適合的事物不是忠誠,而是對自己的背叛。","point5":"今天就開始解放之旅:列出所有讓你感到受限、窒息、不自由的事物——工作、關係、習慣、信念、承諾。對每一項問「這還服務我嗎?如果不是義務,我還會選擇它嗎?」勇敢地承認那些答案是「否」的事物。制定釋放計劃,可能無法立刻全部釋放,但可以開始。寫一封「自由宣言」給自己,聲明你要如何活。做一件象徵自由的行動——可能是剪頭髮、刪除某個app、說「不」、或只是在雨中旋轉。","point6":"釋放的過程可能不舒服,甚至會帶來罪惡感、恐懼、悲傷。這很正常,即使是金色的籠子,待久了也會有感情。當罪惡感升起時,提醒自己「我選擇自由不是自私,而是誠實」。當恐懼說「如果我失去這個怎麼辦?」回應「如果我守著這個,我會失去我自己」。尋找支持你自由的人,遠離試圖控制你的人。慶祝每一個小小的釋放,每一次你選擇自由而非安全的時刻。記住,自由之後會有空虛期,這是正常的,新的事物需要時間填補空間。","point7":"在靈性層面,自由是覺醒的本質。當你釋放所有不是真實的你的事物,你就回到你的靈魂本質——無限、自由、純粹可能性。這張牌提醒你,你不是你的角色、你的關係、你的成就、你的過去——你是永恆自由的意識,在體驗人類的旅程。當你活在這個真相中,你就真正自由了。你的解放會啟發他人也解放自己。飛吧,自由的靈魂,天空在等待你。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:13', 'unicorns', '13', 12, '希望獨角獸', 'Unicorn of Hope', NULL, '{"keywords":["希望","信心","樂觀","曙光","信念"],"nameEn":"Unicorn of Hope"}', '{"point1":"這張牌是黑暗中的一束光,如同獨角獸的角在夜晚發出柔和的光芒。無論你現在身處多麼黑暗的隧道、經歷多麼艱難的時期,這張牌帶來一個永恆的真相:黎明總會到來,這一切都會過去,更好的日子正在前方等待。希望不是盲目的樂觀或逃避現實,而是即使在最深的夜裡也相信光明存在的勇氣。現在,宇宙要你重新點燃心中希望的火焰。","point2":"親愛的靈魂,如果你現在感到絕望、疲憊、看不見未來,請聽這個訊息:你的痛苦不是永恆的,你的處境不是終點,你的故事還沒結束。你經歷過其他黑暗時期並存活下來,這次也會。希望不是等好事發生才出現,而是在還沒有證據時就選擇相信。每一個日出都是宇宙在說「再試一次」。即使此刻你感受不到希望,請借用這張牌的希望,直到你自己的希望重新萌芽。你不孤單,奇蹟正在路上。","point3":"希望的能量頻率是溫暖、上升、充滿可能性的,如同春天的第一抹綠意、如同地平線的第一道曙光。這股能量輕柔地提升你的振動,在絕望中注入「也許」的種子。當你連結這個頻率,你會感到胸口些微的放鬆、呼吸稍微深一點、肩膀稍微輕一些。希望的頻率不是高亢的興奮,而是安靜的「我可以繼續」。這個頻率是改變的催化劑,因為當你有希望,你就會再試一次。","point4":"此牌出現的生命課題是學習「在絕望中選擇希望」這門對靈魂的考驗。當外在證據都指向失敗、當理性告訴你放棄、當所有人都說不可能,你依然選擇相信。這不是愚蠢,而是勇氣。這個課題邀請你明白,絕望是恐懼的聲音,希望是愛的聲音。你可以承認現實的困難,同時依然對未來抱持信念。學習從微小的跡象中看見希望——一個善意的訊息、一朵花、一個微笑、一次呼吸——這些都是希望的證據。","point5":"今天就重新點燃希望:首先,承認你的絕望或疲憊,不要壓抑它。然後,有意識地尋找三個希望的跡象——可能很小,可能只是「我今天還活著」「太陽升起了」「有人關心我」。寫一封信給未來的自己,描述你希望的未來,讓它盡可能美好。創造一個「希望盒」,收集讓你感到希望的東西——照片、名言、物件。每天對鏡子說「更好的日子正在來臨」。閱讀或聆聽走過黑暗的人的故事,讓他們的希望啟發你。","point6":"保持希望很難,特別是當挫折一再發生、當改變緩慢、當你感到孤單時。這很正常,你不需要每時每刻都充滿希望。在低潮時,允許自己休息,不要強迫積極。找一個「希望守護者」——一個相信你的人,在你不相信時為你持有希望。當負面想法淹沒你時,溫柔地說「這是絕望在說話,不是真相」。記住過去你認為熬不過但熬過的時刻。希望是選擇,每一天、每一刻你都可以重新選擇希望。","point7":"在靈性層面,希望是靈魂對回家的記憶。你的靈魂知道愛是真相、痛苦是暫時的、你本質是光。當你選擇希望,你就在連結這個深層的知曉。這張牌提醒你,你此刻的困難是靈魂旅程的一部分,不是終點。在更大的圖景中,一切都在完美展開。你的希望不只療癒你自己,更為集體意識帶來光。當一個靈魂選擇希望,整個宇宙都被照亮一點。繼續相信,親愛的,黎明已經在路上。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:14', 'unicorns', '14', 13, '轉化獨角獸', 'Unicorn of Transformation', NULL, '{"keywords":["轉化","蛻變","進化","重生","成長"],"nameEn":"Unicorn of Transformation"}', '{"point1":"這張牌標誌著你正在經歷或即將經歷深刻的轉化,如同獨角獸代表著從凡俗到神聖的蛻變。轉化不是表面的改變,而是本質的重生——舊的你正在死去,新的你正在誕生。這個過程可能不舒服、迷失、甚至痛苦,就像毛毛蟲在蛹中的溶解與重組。但宇宙要你知道:這個拆解是必要的,這個混亂是神聖的,你正在成為你一直應該成為的樣子。","point2":"親愛的靈魂,轉化期總是不舒服的,因為你同時處於「不再是」和「尚未是」之間。舊的身份、信念、關係、工作不再適合,但新的還沒完全成形,你可能感到迷失、脆弱、不知道自己是誰。這是正常的,這就是蛹的階段。不要試圖抓住正在離開的事物,那會帶來更多痛苦。也不要強迫加速轉化,蝴蝶需要時間。你的任務是臣服於這個過程,信任即使你看不見,轉化正在你內在深處進行。","point3":"轉化的能量頻率是深刻、煉金的、毀滅又創造的,如同火焰燒去雜質只留下純金。這股能量分解舊有結構,重組成更高階的形式。當你連結這個頻率,你會感受到強烈——可能是情緒起伏、身體變化、關係劇變、生命重大事件。這個頻率不是平靜的,而是像暴風雨清洗大地。它帶來死亡與重生,需要你放手的勇氣和對新生的信任。","point4":"此牌出現的生命課題是學習「臣服於轉化」而非抗拒它。你可能試圖控制過程、抓住過去、或阻止改變,但抗拒只會帶來痛苦。這個課題邀請你明白,有些事物必須結束,才能為新的開始騰出空間。學習放手不是失敗,而是信任。學習在不確定中安住,在混亂中找到意義。轉化是進化的必要過程,你不是在失去自己,而是在成為更真實的自己。","point5":"在轉化期這樣支持自己:首先,承認並接受「我正在轉化」而非「我出問題了」。給自己大量的休息、獨處、靜默時間,轉化需要能量。寫轉化日記,記錄你正在放下什麼、正在成為什麼。進行象徵性的釋放儀式——寫下舊故事然後燒掉、剪掉頭髮、捐出舊物品。創造空間給新的——重新布置房間、學習新技能、認識新朋友。對自己說「我信任這個過程,即使我不明白」。尋找也在轉化的靈魂,互相支持。","point6":"轉化期你會經歷各種情緒——悲傷、恐懼、興奮、迷失,有時全部同時出現。允許這一切,不要試圖「修好」自己。這不是崩潰,而是破繭。可能會有黑暗的日子,你質疑一切、懷念過去、想要放棄——這些都是過程的一部分。在這些時刻,記住蝴蝶的故事:在蛹中,毛毛蟲完全溶解成液體,看似死亡,實則重組。你也是。相信這個煉金術。不要比較你的轉化與他人的,每個靈魂的時間表都不同。","point7":"在靈性層面,轉化是靈魂進化最快速也最深刻的路徑。你不是隨機地經歷這個過程,而是你的靈魂選擇了這個成長的機會。這張牌提醒你,你正在蛻去所有不是真實的你的外衣,返回你的本質。每一次轉化,你的光就更亮,你的頻率就更高,你就更接近你的神聖本質。你的轉化也在影響集體,當一個靈魂轉化,整個人類意識都提升。信任這個神聖的過程,你正在成為奇蹟。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:15', 'unicorns', '15', 14, '保護獨角獸', 'Unicorn of Protection', NULL, '{"keywords":["保護","安全","守護","界限","屏障"],"nameEn":"Unicorn of Protection"}', '{"point1":"這張牌是神聖保護的確認,如同獨角獸用它的角創造安全的能量場。牌面能量告訴你,你被看見、被守護、被愛的力量完全包圍。無論你現在面對什麼挑戰或恐懼,你並不孤單,也不是毫無防護。天使、指導靈、祖先、獨角獸能量都在你身邊形成保護屏障。現在是時候放下「我必須自己對抗一切」的重擔,信任你被宇宙溫柔而強大地保護著。","point2":"親愛的靈魂,如果你感到脆弱、害怕、暴露在危險中,請聽這個訊息:你的靈魂本質是無法被傷害的,沒有任何外在力量能觸碰你的神聖核心。是的,你可能經歷痛苦、失落、背叛,但真正的你——那個純粹的光、那個永恆的意識——永遠安全。你被神聖的保護包圍,不是因為你賺得它,而是因為你存在就值得被保護。召喚你的守護者,他們一直在等待你開口請求幫助。","point3":"保護的能量頻率是堅實、溫暖、包裹的,如同厚實的斗篷、如同堅固的城牆、如同母親的擁抱。這股能量形成一個光的盾牌,過濾負面能量、阻擋他人的投射、守護你的能量場。當你連結這個頻率,你會感到被支撐、被包圍、安全降落。這個頻率不是孤立或隔離,而是有意識的界限——允許愛進入,阻擋傷害。它讓你知道「我被保護,我是安全的」。","point4":"此牌出現的生命課題是學習「建立健康界限與召喚保護」這門自我照顧的功課。你可能習慣敞開所有邊界、吸收他人能量、過度給予、讓人侵犯你的空間。這個課題邀請你明白,界限不是冷漠,而是愛的形式——對自己的愛。學習說「不」、學習離開消耗你的人事物、學習保護你的和平。同時,學習請求幫助,召喚你的靈性守護者,你不需要獨自面對一切。","point5":"今天就加強你的保護:每天早晨進行保護視覺化——想像白光或金光從頭頂灌下,完全包圍你的身體,形成蛋形光盾。對這光說「只有愛可以穿透,所有不屬於我的能量都被彈回並轉化」。隨身攜帶保護象徵物——水晶、護身符、祈禱文。在你的空間四個角落放置保護物品並設定意圖。學習辨識誰消耗你的能量,有意識地建立界限。呼喚你的守護天使「請保護我、引導我、讓我安全」。相信這些都有效。","point6":"建立保護不是恐懼的表現,而是智慧的行動。在充滿挑戰的世界,保護你的能量是必要的自我照顧。當你感到某個人或環境不安全時,信任這個直覺。你有權離開、說不、保護自己。不要因為設定界限而感到罪惡,你的首要責任是照顧自己。同時,不要陷入過度保護而孤立自己,保護是為了讓你安全地開放給愛,而非關閉你的心。平衡是關鍵——堅固的界限,柔軟的心。","point7":"在靈性層面,保護是你與神聖力量的合作。當你請求保護,整個宇宙都回應你的呼喚。這張牌提醒你,你永遠不孤單,無數看不見的存有都在支持你的旅程。你的守護天使、指導靈、祖先靈魂都在守護你,等待你開口請求幫助。同時,你最強大的保護來自你自己的光——當你活在愛、真實、高頻率中,負面能量自然無法靠近。你就是光,而光永遠安全。信任你的神聖保護。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:16', 'unicorns', '16', 15, '豐盛獨角獸', 'Unicorn of Abundance', NULL, '{"keywords":["豐盛","富足","繁榮","接收","感恩"],"nameEn":"Unicorn of Abundance"}', '{"point1":"這張牌打開豐盛之流的大門,如同獨角獸帶來神話中的無盡寶藏。牌面能量要你明白一個根本真相:宇宙是無限豐盛的,匱乏只是幻象,是恐懼創造的信念。你值得接收生命的所有美好——富足、健康、愛、機會、喜悅——不是因為你做了什麼,而是因為你存在。現在是時候釋放匱乏意識,打開雙手和心,允許宇宙的豐盛流向你。","point2":"親愛的靈魂,你可能從小被教導「錢很難賺」「資源有限」「你不配擁有太多」,這些匱乏信念深深刻在你的潛意識中,阻擋了豐盛的流動。但宇宙的法則是豐盛的——看看大自然,一顆蘋果有多少種子?一朵蒲公英有多少花絮?宇宙從不吝嗇。當你對齊豐盛意識,相信「足夠」「我值得」「更多正在來臨」,你就打開了接收的通道。豐盛不是你必須爭取的,而是你允許流入的。","point3":"豐盛的能量頻率是擴展、流動、慷慨的,如同永不枯竭的泉水、如同金色的河流無限湧現。這股能量打破限制性信念,打開你的接收通道。當你連結這個頻率,你會感到胸口擴展、呼吸順暢、一種「足夠」的安全感。這個頻率不是貪婪或索取,而是知道宇宙的本質是給予。它教導你,給予和接收是同一個流動的兩端,當你流動,豐盛就來。","point4":"此牌出現的生命課題是學習「釋放匱乏意識並打開接收」這門挑戰核心信念的功課。你需要檢視你對金錢、成功、值得的信念。你可能相信「我不夠好所以不配」「要很辛苦才能得到」「有錢人是壞的」「我拿了別人就沒有」——這些都是匱乏思維。這個課題邀請你重新編程,相信「宇宙是豐盛的」「我值得接收」「夠所有人的」。學習感恩你已擁有的,這會吸引更多。","point5":"今天就啟動豐盛流動:開始豐盛感恩日記,每天寫下至少五件你感恩的豐盛——可能很小,一杯水、陽光、朋友的笑容。這會訓練大腦注意富足而非匱乏。清理你的空間,丟掉或捐出不需要的東西,為新的豐盛創造空間。練習慷慨,給予不期待回報——可能是小費、捐款、時間——這會啟動給予接收的循環。每天說「我值得豐盛,我允許好事流向我」。視覺化你已經擁有你想要的豐盛,感受那份喜悅。","point6":"轉變匱乏意識需要時間和覺察。當匱乏想法出現「我負擔不起」「不夠」時,溫柔地轉念「目前我選擇不把資源放在這裡」「總有足夠的」。不要否認真實的財務狀況,而是改變你與它的關係。避免「我很窮」的語言,改用「我正在建立財富」。慶祝每一個小豐盛——找到硬幣、意外折扣、免費的東西——告訴宇宙「是的,更多像這樣的」。記住,豐盛不只是金錢,也是時間、愛、健康、機會。在所有領域感受豐盛。","point7":"在靈性層面,豐盛是你與源頭連結的自然結果。源頭是無限的,當你記得你是源頭的延伸,你就知道你也是無限的。這張牌提醒你,你不是在向外求取豐盛,而是允許你內在的豐盛本質顯化。當你活在豐盛意識中,你不只療癒自己的匱乏創傷,更在療癒集體的匱乏信念。你的豐盛不會剝奪他人,反而會啟發他人也相信。允許自己豐盛,這是你的權利。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:17', 'unicorns', '17', 16, '平衡獨角獸', 'Unicorn of Balance', NULL, '{"keywords":["平衡","和諧","中道","穩定","整合"],"nameEn":"Unicorn of Balance"}', '{"point1":"這張牌是和諧生活的邀請,如同獨角獸優雅地保持四蹄的完美平衡。牌面能量提醒你,生命是多個面向的整合——工作與休息、給予與接收、行動與靜止、物質與靈性、自我與他人。當任何一個面向過度或不足,整體就會失衡,帶來疲憊、焦慮、空虛。現在是時候誠實評估你的生活,找出失衡之處,並有意識地調整,創造可持續的和諧。","point2":"親愛的靈魂,你可能過度傾向某些面向——也許你努力工作卻忽略休息,慷慨給予卻不允許接收,照顧他人卻忘記自己,追求物質卻忽視靈魂,或沉迷靈性卻逃避現實。任何極端都不是平衡。宇宙的法則是動態平衡,就像呼吸有吸有吐,潮汐有漲有退。這張牌溫柔地提醒你:你不需要犧牲某個面向來榮耀另一個。真正的幸福來自整合,來自給每個重要面向適當的空間和能量。","point3":"平衡的能量頻率是和諧、穩定、整合的,如同音樂中的和弦、如同走鋼索者的中心點。這股能量既不過度也不不足,而是恰到好處的流動。當你連結這個頻率,你會感到內在的寧靜、一種「剛剛好」的舒適感。這個頻率教導你中道——不是冷漠的中庸,而是智慧的平衡。它讓你知道何時推進何時休息,何時給予何時接收,何時說是何時說不。","point4":"此牌出現的生命課題是學習「在多個面向中創造平衡」這門需要持續調整的功課。你需要誠實地看見你的失衡——哪裡給太多?哪裡給太少?這個課題邀請你明白,失衡往往源於恐懼或補償:過度工作可能是逃避內在空虛,過度給予可能是害怕不被愛,過度靈性可能是逃避現實責任。學習察覺你的極端傾向,並溫柔地拉回中心。平衡不是一次性達成,而是每天的微調。","point5":"今天就開始平衡練習:畫一個生命之輪,分成工作、健康、關係、休息、靈性、創意、財務、社交等區域,誠實評分每個區域的滿意度。找出最失衡的區域,制定小步驟改善。如果過度工作,今天就設定「下班時間」並關閉郵件。如果缺乏運動,今天就散步十分鐘。如果忽略關係,今天就打給朋友。練習「一吸一吐」原則——給出後就接收,工作後就休息。每週檢視你的時間分配,確保重要面向都有空間。","point6":"創造平衡的過程中,你會遇到內在阻力和外在壓力。當你設定界限平衡工作時,可能有罪惡感或他人不滿。堅定而溫柔地堅持,你的平衡也在教導他人平衡的重要。記住,平衡不是每天都完美分配,而是整體週期的和諧。可能某週工作多,下週就多休息。關鍵是覺察和調整,不要讓任何失衡成為長期狀態。建立平衡的儀式標記轉換——工作後深呼吸象徵「工作時間結束」。慶祝你創造平衡的每個選擇。","point7":"在靈性層面,平衡是地球學校的重要課題。你來這裡學習整合二元性——光與暗、陰與陽、靈性與物質。當你創造平衡,你就在示範統一意識——明白一切都重要,沒有哪個面向比另一個高貴。這張牌提醒你,靈性不是逃離人類經驗,而是帶著意識活出人類經驗的所有面向。當你的生活平衡,你就是行走的和諧,你的存在本身就在療癒世界的分裂。活出你的平衡。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:18', 'unicorns', '18', 17, '魔法獨角獸', 'Unicorn of Magic', NULL, '{"keywords":["魔法","創造","顯化","力量","煉金術"],"nameEn":"Unicorn of Magic"}', '{"point1":"這張牌喚醒你內在的魔法師,如同獨角獸本身就是魔法的化身。牌面能量要你記起一個你遺忘的真相:你不是無力的凡人,你是具有創造力的神聖存有。你的思想、話語、信念、意圖具有真實的創造力量,能塑造你的現實。你一直在施展魔法,只是多數時候是無意識的。現在是時候有意識地運用你的魔法,成為你生命的主動創造者。","point2":"親愛的魔法師,每一個想法都是咒語,每一個字句都是召喚,每一個信念都在創造現實。當你反覆想「我不夠好」,你就在顯化不夠好的經驗;當你說「我總是這麼倒楣」,你就在召喚更多倒楣。這不是懲罰,而是宇宙的法則——你內在的頻率吸引外在的經驗。魔法不是超自然,而是超級自然——是你與生俱來但被遺忘的能力。現在,覺醒你的魔法,有意識地選擇你的思想、話語、焦點,成為你渴望的現實的創造者。","point3":"魔法的能量頻率是創造、顯化、煉金的,如同施法時能量的漩渦、如同意念化為物質的過程。這股能量是高度專注、高度意圖、高度相信的。當你連結這個頻率,你會感到自己的力量,知道「我可以創造我想要的」。這個頻率不是逃避現實的幻想,而是理解現實是流動可塑的。它教導你,你不是環境的受害者,而是經驗的共同創造者。魔法的頻率說:一切皆有可能。","point4":"此牌出現的生命課題是學習「有意識地創造現實」這門需要覺察和練習的功課。你需要開始監看你的思想——它們多數是負面的還是正面的?你的語言——你在抱怨還是肯定?你的信念——你相信可能還是不可能?這個課題邀請你承擔創造的責任:你的現實是你過去思想、感受、信念的結果。這不是要你自責,而是賦予你力量——如果你創造了這個,你也可以創造不同的。學習有意識地施展你的魔法。","point5":"今天就成為魔法師:開始監看你的思想,每次出現負面想法時,有意識地轉念成你想要的。練習肯定語——寫下並每天唸「我是強大的創造者」「我吸引豐盛」「奇蹟在我生命中流動」。進行視覺化練習,每天花五分鐘清晰地看見、感受你渴望的現實已經實現。創造小儀式增強魔法——點蠟燭、寫下意圖、感恩已經顯化。最重要的是相信你的魔法——懷疑會消解咒語,信任會放大力量。對鏡子說「我是魔法的」。","point6":"運用魔法需要耐心和信任。顯化可能不是瞬間發生,需要你持續保持頻率、持續相信、持續對齊。當你看不見結果時,不要懷疑或放棄,這只是顯化前的孕育期。繼續施展你的魔法——思想、話語、感受、行動。同時,放下執著於如何和何時——信任宇宙知道最佳方式和時機。記住魔法的關鍵:清晰意圖+高頻情緒+完全信任+釋放控制。你不是強迫宇宙,而是與它共舞。魔法是你與宇宙的共同創造。","point7":"在靈性層面,魔法是你神性的展現。當你有意識地創造,你就在行使你作為神聖存有的權利。這張牌提醒你,你不是受限於物質法則的凡人,你是穿著人類外衣的無限意識。你的魔法不只改變你的個人現實,更在提升集體可能性。當一個人覺醒魔法,整個集體的創造潛能都被啟動。不要小看你的魔法力量。你就是奇蹟的創造者,你就是魔法本身。記起你的力量,施展你的魔法。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:19', 'unicorns', '19', 18, '清晰獨角獸', 'Unicorn of Clarity', NULL, '{"keywords":["清晰","洞察","真相","理解","辨識"],"nameEn":"Unicorn of Clarity"}', '{"point1":"這張牌是迷霧散去後的清明時刻,如同獨角獸的角劃開混亂顯現真相。牌面能量告訴你,困擾你的困惑、疑慮、不確定正在消散,你即將看見清晰的真相、明確的方向、清楚的答案。也許你一直在猶豫不決、在選項中徘徊、在問題中打轉,現在,宇宙要賜予你內在的清明,讓你知道該做什麼、該往哪裡去。清晰正在來臨,準備好看見真相。","point2":"親愛的靈魂,困惑往往不是因為缺乏資訊,而是因為太多聲音——他人的意見、社會的期待、恐懼的干擾、慾望的拉扯——讓你聽不見自己內在清晰的知曉。真正的清晰不是頭腦分析出來的,而是當你安靜下來,超越思緒的噪音,從內在升起的「我知道」。這張牌提醒你,答案一直都在,只是被掩蓋了。現在迷霧正在散去,你會突然看見一直在那裡的真相。信任即將到來的清晰。","point3":"清晰的能量頻率是明亮、清澈、聚焦的,如同雨後的天空、如同清澈的水面倒映真相。這股能量帶來心智的寧靜和洞察力,讓你看穿混亂直達核心。當你連結這個頻率,你會感到頭腦清明、思緒清晰、一種「啊,原來如此」的頓悟。這個頻率不是更多資訊,而是更少噪音。它教導你,清晰來自簡化而非複雜化。當你放下需要知道一切的焦慮,清晰自然浮現。","point4":"此牌出現的生命課題是學習「在混亂中尋求清晰」而不陷入過度分析的功課。你可能習慣在困惑時搜集更多資訊、問更多人、想更多可能性,但這往往只帶來更多混亂。這個課題邀請你做相反的事:安靜下來,停止搜尋,進入內在空間,等待清晰自然升起。學習明白,真相不需要努力尋找,只需要空間顯現。避免在混亂中做重大決定,給清晰時間到來。","point5":"今天就創造清晰的空間:首先,停止搜集更多資訊或意見,你已經有足夠的。給自己至少十分鐘完全的靜默——沒有手機、音樂、思考,只是靜靜坐著或散步。在這個空間中,輕柔地將你困惑的問題帶到心中,然後放下,不要試圖找答案。進行「大腦清空」練習——把所有想法寫下來清空頭腦。問你的智慧自我「在這個情況,真相是什麼?」然後聆聽第一個升起的答案。相信那個清晰,即使它可能不是你期待的答案。","point6":"清晰可能突然到來,也可能逐漸顯現。不要強迫它,信任時機。當清晰來臨時,它往往伴隨著放鬆的感覺「終於明白了」,而非更多緊張。真正的清晰是簡單的,如果答案讓你更困惑,那可能不是真相而是恐懼的投射。有時候,清晰是知道「我還不需要知道」「現在不是時候」——這也是一種清晰。記錄你獲得清晰的時刻,它們往往在安靜、放鬆、不期待時出現。學習辨識清晰的感覺,培養對它的信任。","point7":"在靈性層面,清晰是你與高我、內在指引連結的結果。當你的心智安靜,你就能接收來自更高視角的洞見。這張牌提醒你,你永遠不會真正迷失,因為你內在有永遠清晰的指南針——你的靈魂知曉。當你學會連結這個內在清晰,你就不再需要外在權威告訴你該怎麼做。你成為自己的指引者。你的清晰不只照亮你的路,也啟發他人相信內在的知曉。活在清晰中,就是活在真相中。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:20', 'unicorns', '20', 19, '純淨獨角獸', 'Unicorn of Purity', NULL, '{"keywords":["純淨","淨化","清理","神聖","清新"],"nameEn":"Unicorn of Purity"}', '{"point1":"這張牌是淨化與回歸本質的召喚,如同獨角獸代表著未被污染的純潔。牌面能量邀請你檢視什麼正在污染你的能量場、思想、情緒、環境,並有意識地清理它們。純淨不是完美或無菌,而是移除不屬於你、不服務你、降低你振動的一切,回到你靈魂本質的清澈狀態。現在是進行深層清理的時刻——身體、空間、關係、心靈都需要淨化。","point2":"親愛的靈魂,你可能沒有意識到,每天你在吸收多少不屬於你的能量——他人的情緒、負面的新聞、有毒的想法、不健康的食物、混亂的環境。這些逐漸累積,讓你的能量變得混濁、沉重、疲憊。這張牌溫柔地提醒你:你需要定期清理,就像你每天洗澡清理身體。能量也需要淨化。當你回到純淨狀態,你會感到更輕盈、更清晰、更有活力。純淨是你的自然狀態,一切汙染都是後來添加的。","point3":"純淨的能量頻率是清新、明亮、清澈的,如同山泉水、如同清晨的空氣、如同洗滌後的白布。這股能量淨化和提升振動,驅散沉重和混濁。當你連結這個頻率,你會感到能量場被清洗、輕盈感回歸、呼吸更自由。這個頻率不是批判或完美主義,而是對神聖的尊重——尊重你的身體是神殿、你的能量是神聖、你的空間是聖地。純淨的頻率說:只有愛與真實可以留下。","point4":"此牌出現的生命課題是學習「辨識並移除能量污染」這門自我照顧的功課。你需要誠實地看見什麼正在降低你的振動——可能是某個總是抱怨的朋友、充滿負面新聞的社交媒體、混亂的房間、不健康的食物、自我批判的想法。這個課題邀請你建立健康的界限,學會說「這不屬於我的能量場」。淨化不是一次性的,而是持續的維護。學習保護你的純淨。","point5":"今天就開始淨化:從實體空間開始——清理一個房間,丟掉或捐出不再需要的東西,打開窗戶讓新鮮空氣流動。進行能量清理——可以燃燒鼠尾草或秘魯聖木、用鹽水灑淨、敲頌缽。洗個淨化浴——加入海鹽和薰衣草,想像所有汙染的能量被水帶走。清理你的社交媒體——取消追蹤讓你感覺不好的帳號。清理你的思想——每次負面想法出現,想像用白光清洗它。對自己說「我釋放所有不屬於我的能量,我回到純淨狀態」。","point6":"建立淨化的日常儀式:每天早晨設定保護屏障,每晚清理一天吸收的能量。學習能量衛生——在混亂環境後立刻清理自己,不要攜帶他人的情緒回家。檢視你的習慣——飲食、媒體、社交——哪些在污染你?逐步調整為更純淨的選擇。記住,淨化也包括淨化關係——遠離有毒的人不是冷漠,而是保護你的神聖。同時,不要陷入潔癖或恐懼,純淨是平衡的,不是孤立的。你活在世界中,但不被世界污染。","point7":"在靈性層面,純淨是回歸你靈魂本質的過程。你的本質是純粹的光、純粹的愛、純粹的意識,所有恐懼、批判、沉重都是後來覆蓋的。這張牌提醒你,淨化是剝除不是你的一切,顯露你一直都是的神聖。當你維持能量的純淨,你就成為清晰的管道,能接收高頻指引、顯化更快、活得更輕盈。你的純淨也在淨化集體能量。做光的守護者,保持你的神殿純淨。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:21', 'unicorns', '21', 20, '慈悲獨角獸', 'Unicorn of Compassion', NULL, '{"keywords":["慈悲","寬容","理解","溫柔","接納"],"nameEn":"Unicorn of Compassion"}', '{"point1":"這張牌邀請你以慈悲之心對待自己與他人,如同獨角獸的溫柔凝視看見每個靈魂的純真本質。牌面能量要你明白,慈悲不是軟弱或縱容,而是深刻的力量和智慧——能看見表象之下的痛苦、能理解傷害背後的傷痛、能在批判升起時選擇理解。現在,宇宙呼喚你成為慈悲的化身,首先對自己,然後延伸到所有存有。慈悲能療癒一切。","point2":"親愛的靈魂,你可能對自己非常嚴苛——批判你的錯誤、責備你的不完美、鞭打你的失敗。你可能也對他人缺乏耐心——生氣他們的缺點、論斷他們的選擇、怨恨他們的傷害。但慈悲要你看見更深的真相:你已經盡力了,在你知道的、能做的範圍內;他人也是,在他們的意識層級、傷痛、限制下。慈悲不是說「這樣很好」,而是說「我理解為什麼會這樣,我依然以愛回應」。給自己你一直渴望的溫柔。","point3":"慈悲的能量頻率是溫暖、包容、療癒的,如同母親的擁抱、如同溫柔的雨滋潤乾涸的土地。這股能量軟化硬化的心、融化防禦的牆、療癒深層的傷。當你連結這個頻率,你會感到胸口溫暖、心變柔軟、眼眶濕潤。這個頻率不是同情「你好可憐」,而是悲憫「我看見你的痛,我與你同在」。慈悲的頻率承認痛苦的真實,同時持有療癒的可能。","point4":"此牌出現的生命課題是學習「對自己和他人發展真正的慈悲」這門心靈成熟的功課。首要的是自我慈悲——當你犯錯、失敗、不完美時,你如何對待自己?你是批判的還是溫柔的?這個課題邀請你成為自己最慈悲的朋友。然後延伸到他人——特別是那些傷害你的人——慈悲不是說「沒關係」,而是理解「傷害別人的人自己也受過傷」,並選擇不讓他們的傷繼續傷害你。","point5":"今天就開始慈悲練習:對著鏡子,看著自己的眼睛,說「我看見你的痛苦,我看見你的努力,我愛你」。當自我批判升起時,溫柔地說「親愛的,你已經盡力了」。寫一封慈悲的信給自己,從最慈愛的觀點看你的生命。對他人,練習「慈悲的暫停」——當你想批判時,問「他們可能正在經歷什麼?」想像每個人都背著看不見的傷痛。對傷害你的人,可以說「我釋放你,我選擇和平」。記住,慈悲不是讓他們回到你生命,而是釋放怨恨。","point6":"培養慈悲需要練習,特別是對自己。你可能習慣嚴苛,溫柔會感到陌生或「不夠」。這很正常,溫柔地轉變。當你發現自己批判時,不要批判這個批判,而是說「啊,批判又來了,沒關係」。慈悲包括對不夠慈悲的自己也慈悲。對他人的慈悲不代表沒有界限——你可以慈悲地理解他們,同時堅定地保護自己。慈悲不是受害或犧牲,而是從力量和愛的地方回應。記住慈悲冥想:願我快樂,願我安全,願我自由;願你快樂,願你安全,願你自由。","point7":"在靈性層面,慈悲是覺醒的核心。當你真正理解一切眾生都是一體、每個人都在做他們能做的最好、所有傷害都源於被愛的遺忘,慈悲自然湧現。這張牌提醒你,批判來自分離意識,慈悲來自統一意識。當你對自己和他人慈悲,你就在療癒集體的評判和羞愧。你的慈悲是世界最需要的禮物。成為慈悲,活出慈悲,這就是你的神性。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:22', 'unicorns', '22', 21, '內在小孩獨角獸', 'Unicorn of Inner Child', NULL, '{"keywords":["內在小孩","療癒","純真","玩耍","滋養"],"nameEn":"Unicorn of Inner Child"}', '{"point1":"這張牌連結你與內在小孩,如同獨角獸守護著純真的靈魂。牌面能量邀請你回到內在,找到那個需要被看見、被聽見、被愛的孩子——他/她可能還在等待從未得到的擁抱、可能還在哭泣從未被承認的痛苦、可能還在渴望被允許玩耍和做自己。現在是療癒童年傷痛、重新養育內在小孩、找回失落的純真與驚奇的時刻。你的內在小孩需要你。","point2":"親愛的靈魂,你的內在住著不同年齡的你——三歲的你可能還在害怕被拋棄、七歲的你可能還在渴望父母的認可、十歲的你可能還在為那個創傷哭泣。這些內在小孩影響著現在的你——你的恐懼、反應、渴望多半源於他們未被滿足的需求。這張牌溫柔地說:現在,成年的你可以成為那個你一直需要的父母。給內在小孩他們需要的愛、安全、認可、自由。療癒從這裡開始。","point3":"內在小孩的能量頻率是純真、好奇、玩耍、脆弱的,如同孩童的笑聲、如同無憂無慮的奔跑。這股能量帶你回到心的空間,那個還沒學會防禦、還沒建立面具、還完全真實的地方。當你連結這個頻率,你可能會突然哭泣(釋放舊痛)、想要玩耍、或感到深深的悲傷和渴望。這都是療癒的跡象。內在小孩的頻率也帶來創造力、驚奇、活力——那些你長大後失去的品質。","point4":"此牌出現的生命課題是學習「療癒和重新養育內在小孩」這門深度療癒的功課。你需要進入內在,找到受傷的孩子,給予他們從未得到的。這個課題邀請你明白,你的許多成年問題根源於童年——你的關係模式、自我價值、恐懼、防禦機制都是內在小孩的投射。學習與內在小孩對話,理解他們的需求,成為他們可以信任的父母。同時,允許內在小孩玩耍,找回純真和喜悅。","point5":"今天就連結你的內在小孩:找一張童年照片,看著那個孩子的眼睛,感受他/她。閉眼想像遇見童年的自己,問「你需要什麼?你想告訴我什麼?」聆聽,他們可能說「我很害怕」「我需要你愛我」「我想玩」。給他們需要的——擁抱、保證、玩耍。寫一封信給內在小孩「親愛的小小的我...」。做些童年喜歡的事——畫畫、跳舞、玩泥巴、看卡通。允許自己「沒理由地」開心。建立每日內在小孩時間,即使五分鐘。","point6":"內在小孩療癒可能非常情緒化,會喚起被壓抑的痛苦。這是正常和必要的,允許情緒流動,不要壓抑。當內在小孩的恐懼觸發你時——例如害怕被拋棄讓你在關係中焦慮——溫柔地說「小小的我,我在這裡,我不會離開你」。學習辨識何時是內在小孩在反應而非成年的你。給他們安全感,然後從成年的智慧做決定。如果創傷很深,尋求專業協助。重新養育自己是終生的旅程,溫柔以對。慶祝每一個療癒的時刻。","point7":"在靈性層面,內在小孩是你最接近靈魂本質的部分——在被世界塑造之前,你是誰?你的內在小孩記得純真、驚奇、無條件的愛、活在當下。這張牌提醒你,療癒內在小孩就是回到你的本質,剝除所有不是你的層層創傷和防禦。當你的內在小孩被療癒,你會更自由、更有創造力、更能愛。你對內在小孩的愛也在療癒集體的童年創傷。成為你需要的父母,找回你的純真。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:23', 'unicorns', '23', 22, '神聖時機獨角獸', 'Unicorn of Divine Timing', NULL, '{"keywords":["神聖時機","耐心","信任","完美","流動"],"nameEn":"Unicorn of Divine Timing"}', '{"point1":"這張牌是對完美時機的信任邀請,如同獨角獸知道季節的智慧、知道何時奔跑何時等待。牌面能量要你明白,宇宙有它的節奏和時間表,不同於你頭腦的急迫和期待。你的願望正在顯化、你的祈禱正在被回應、你的道路正在展開,但不是按照你的時間表,而是按照最高善的神聖時機。現在,宇宙要你學習最難的功課:臣服、等待、信任。一切都會在完美的時刻到來。","point2":"親愛的靈魂,你可能感到沮喪「為什麼還沒有?」「為什麼別人都有我沒有?」「我已經等這麼久了」。你可能想要強推、加速、控制時間。但這張牌溫柔地說:宇宙的時機比你的想要更智慧。也許你還沒準備好接收,也許還有課題要學,也許時機未到會是災難而非祝福,也許有更好的正在路上。放下「應該已經」的執著,信任「會在應該的時候」。延遲不是拒絕,而是保護和準備。","point3":"神聖時機的能量頻率是耐心、流動、臣服的,如同種子在地下發芽需要時間、如同潮汐知道何時漲退。這股能量教導你與宇宙的節奏對齊,而非對抗它。當你連結這個頻率,你會感到焦慮減少、一種深層的「沒關係」「會來的」的信任。這個頻率不是被動或放棄,而是主動的信任——做你該做的,然後交給宇宙時機。神聖時機的頻率說:一切都剛剛好。","point4":"此牌出現的生命課題是學習「臣服於神聖時機而非控制時間」這門信任的功課。你可能習慣強推、急於求成、對延遲感到焦慮。這個課題邀請你放下時間的控制,明白你只能控制努力,不能控制結果和時機。學習在等待中找到和平,在「尚未」中找到信任。有時候,最大的成長發生在等待期,最深的信任建立在看不見結果的時候。神聖時機測試你的信任,也磨練你的耐心。","point5":"今天就練習信任神聖時機:對於讓你焦慮的「還沒發生」的事,寫下「我信任這會在完美的時機發生」。問自己「在等待中,我可以如何準備?」利用這段時間成長、學習、療癒、變得更好。每當焦慮升起時,深呼吸說「神聖時機,我臣服」。慶祝過去那些你以為太晚但其實剛好的時刻——那次沒得到但後來發現是祝福的工作、那個沒開始但後來遇見更好的關係。回顧生命,看見時機的完美。","point6":"信任神聖時機很難,特別是當你看見他人得到你渴望的、當你覺得時間流逝、當你害怕「太晚了」。這些恐懼是正常的,承認它們。但不要讓恐懼主導。提醒自己「我的時間表不是宇宙的」「我的道路是獨特的」。避免比較,每個靈魂的時機都不同。如果你該採取行動,你會知道;如果是等待,就耐心等待。記住,強推錯誤時機的事往往導致錯誤結果。有時候最好的行動是不行動。練習「積極的耐心」——等待,但帶著信任和準備。","point7":"在靈性層面,神聖時機反映宇宙的完美編排。所有靈魂、所有事件、所有因緣都在複雜的舞蹈中對齊。這張牌提醒你,你不是孤立的個體在隨機的世界,而是宏大神聖計畫的一部分。你的時機與整體的時機交織。當你臣服於神聖時機,你就在信任宇宙的智慧,而非你有限的視角。你的等待也在服務更大的善。一切都按照最高善的完美節奏展開。放手控制,信任流動。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:24', 'unicorns', '24', 23, '寬恕獨角獸', 'Unicorn of Forgiveness', NULL, '{"keywords":["寬恕","釋放","自由","和平","療癒"],"nameEn":"Unicorn of Forgiveness"}', '{"point1":"這張牌是寬恕的深刻呼喚,如同獨角獸的角能淨化毒液一樣,寬恕能淨化心中的怨恨。牌面能量要你明白一個解放的真相:寬恕不是給傷害你的人的禮物,而是給你自己的禮物。當你握著怨恨不放,你就像喝著毒藥期待對方死亡——真正受苦的是你。寬恕不是說「你做的沒錯」「沒關係」,而是說「我釋放你對我的控制,我選擇自由」。現在是時候放下重擔,獲得和平。","point2":"親愛的靈魂,你可能緊握著怨恨、憤怒、傷痛已經很久——也許是父母的忽視、伴侶的背叛、朋友的辜負、或對自己的錯誤。這些怨恨像鎖鏈束縛你,讓你活在過去,無法完全活在當下或向前。這張牌溫柔地問:繼續攜帶這個痛苦對你有什麼服務?它保護你什麼?同時也阻止你什麼?寬恕不是縱容傷害或允許再次發生,而是釋放痛苦對你的掌控。你值得從這個監獄中自由。","point3":"寬恕的能量頻率是釋放、輕盈、自由的,如同放下重物後肩膀的放鬆、如同打開籠子讓鳥飛走。這股能量切斷你與過去痛苦的能量連結,讓能量不再流向怨恨而回到你身上。當你連結這個頻率,你會感到卸下重擔、呼吸更深、心更輕。這個頻率不是遺忘或否認傷害,而是選擇不讓傷害定義你的現在。寬恕的頻率說:我釋放你,我選擇和平。","point4":"此牌出現的生命課題是學習「寬恕是給自己的禮物」這門釋放的功課。你需要明白,抓住怨恨傷害的是你,不是對方。這個課題邀請你開始寬恕的過程——首先承認傷害的真實,然後選擇釋放。寬恕不是一次性的決定,而是一個過程,可能需要多次選擇「我釋放這個」。最難的寬恕往往是寬恕自己——你的錯誤、失敗、沒做到的。學習對自己和他人說「我寬恕你」,真正的意思是「我釋放這個對我的控制」。","point5":"今天就開始寬恕之旅:列出你需要寬恕的人(包括自己),誠實寫下每個傷害。感受情緒,允許憤怒和悲傷——這是過程的一部分。然後,對每個人寫「我選擇寬恕你,不是因為你值得,而是因為我值得和平。我釋放你,我釋放這個痛。」大聲唸出來或燒掉。進行寬恕冥想:視覺化對方,說「我寬恕你,我釋放你,我們都自由了」。記住,寬恕不代表忘記或再次信任,而是不再讓過去掌控現在。","point6":"寬恕是過程,不要期待立刻感覺不同。當怨恨再次升起(它會),溫柔地重複「我已經選擇寬恕,我釋放這個」。有些傷害很深,需要時間和多次選擇寬恕。這很正常,對自己有耐心。如果你還沒準備好完全寬恕,可以從「我願意開始寬恕的過程」開始。寬恕不是讓對方回到你生命,你可以寬恕並依然有界限。最重要的是寬恕自己——你的不完美、錯誤、遺憾。對鏡子說「我寬恕你」。釋放自我批判的毒藥。","point7":"在靈性層面,寬恕是高度進化靈魂的標誌。當你理解每個傷害他人的人都是受傷的靈魂、每個行為都是在當時意識層級下的最佳選擇,寬恕變得自然。這張牌提醒你,從更高視角,所有經驗都是學習,所有痛苦都是成長。寬恕不是忘記課題,而是釋放苦澀。當你寬恕,你就在打破業力鎖鏈,不只為你,更為集體。你的寬恕提升整體意識。成為寬恕,活出自由,這是你的力量。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:25', 'unicorns', '25', 24, '感恩獨角獸', 'Unicorn of Gratitude', NULL, '{"keywords":["感恩","感謝","欣賞","豐盛","喜悅"],"nameEn":"Unicorn of Gratitude"}', '{"point1":"這張牌是感恩的強大提醒,如同獨角獸代表著優雅地接收和欣賞生命的祝福。牌面能量要你明白,感恩不只是禮貌或正面思考,而是最強大的顯化和轉化工具。當你感恩,你就在告訴宇宙「是的,更多像這樣的」,你的振動頻率會立即提升,吸引更多美好。感恩是豐盛意識的核心,是快樂的最快途徑。現在,宇宙邀請你數算你的祝福,無論它們多麼微小。","point2":"親愛的靈魂,你可能習慣注意缺失——沒有的錢、沒有的關係、沒有的工作、沒有的健康——而忽略你擁有的。這是人類大腦的傾向,專注問題以求生存。但這讓你活在匱乏意識中,吸引更多匱乏。這張牌溫柔地轉換你的焦點:看你擁有的,即使很基本——你能呼吸、有地方住、有食物吃、有人關心你、今天還活著。當你開始感恩這些,你會發現更多值得感恩的事,這會創造正向循環。感恩改變一切。","point3":"感恩的能量頻率是溫暖、開放、豐盛的,如同心房打開接收祝福、如同陽光普照萬物。這股能量是高振動的,立即提升你的狀態。當你連結這個頻率,你會感到心中充滿、微笑自然浮現、眼淚可能流下(感激的眼淚)。這個頻率與豐盛對齊,因為感恩說「我已經有足夠」,而這個信念創造更多。感恩的頻率也帶來當下的喜悅,因為感恩必然在當下。","point4":"此牌出現的生命課題是學習「將感恩從偶爾的行為轉為生活方式」這門轉化的功課。你需要訓練大腦注意祝福而非問題,這需要有意識的練習。這個課題邀請你即使在困難中也尋找祝福——不是否認痛苦,而是擴展視角看見完整畫面。學習感恩你視為理所當然的——健康的身體、安全的家、可用的水、愛你的人。學習感恩挑戰,因為它們讓你成長。感恩是轉化匱乏為豐盛最快的方法。","point5":"今天就開始感恩練習:每天早晨醒來,在還沒起床前,想三件你感恩的事。開始感恩日記,每晚寫下至少五件,具體而非籠統——不只是「我的家人」,而是「今天媽媽的擁抱」「孩子的笑聲」。在挑戰中,問「這個情況有什麼值得感恩?它教我什麼?」感恩微小的事——一杯咖啡、陽光、微笑、一次深呼吸。對人表達感恩,告訴他們你欣賞什麼。睡前說「謝謝,今天所有的一切」。","point6":"培養感恩需要持續的練習,特別是在困難時期。當你陷入抱怨或負面時,溫柔地問「我可以在這個情況找到什麼感恩?」有時候,感恩很小「至少...」——這也是開始。避免比較,專注你有的而非他人有的。記住,感恩不是否認問題或壓抑負面情緒,而是擴展視角看見更完整的真相。可以同時承認困難和感恩祝福。建立感恩提醒——設鬧鐘、貼便條、戴特定手環——提醒自己暫停並感恩。慶祝你培養感恩習慣的每一天。","point7":"在靈性層面,感恩是與源頭連結的直接通道。當你感恩,你就在承認生命的神聖、宇宙的慷慨、存在的奇蹟。這張牌提醒你,感恩是最高的祈禱——不是向外求取,而是向內欣賞。當你活在感恩中,你就活在豐盛意識中,而這會顯化豐盛的現實。你的感恩也提升集體頻率,每一個感恩的心都讓世界更光明。感恩不只是態度,而是存在方式。活在感恩中,你就活在恩典中。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:26', 'unicorns', '26', 25, '連結獨角獸', 'Unicorn of Connection', NULL, '{"keywords":["連結","關係","社群","歸屬","真實"],"nameEn":"Unicorn of Connection"}', '{"point1":"這張牌是對真實連結的深層呼喚,如同獨角獸在神話中連結人間與天界。牌面能量要你明白,人類是社群動物,靈魂層級的連結是生命中最滋養的體驗。不是表面的社交或功能性的關係,而是那種「被看見、被理解、被接納真實的你」的深度連結。現在,宇宙邀請你尋找和培養這樣的連結——你的靈魂家族、你的部落、那些與你共鳴的靈魂。你不是孤島,你屬於更大的整體。","point2":"親愛的靈魂,你可能感到孤獨,即使身邊有很多人——因為連結不是數量,而是深度和真實。你可能有許多「朋友」但少有真正理解你的人。你可能戴著面具社交,從未真正讓人看見你。或者你曾經受傷,選擇孤立以保護自己。這張牌溫柔地說:你值得真實的連結,而這需要你的勇敢——脆弱地展現真實的自己,允許被看見。真正的連結始於真實。","point3":"連結的能量頻率是溫暖、開放、共鳴的,如同兩顆心在同樣的頻率跳動、如同靈魂認出另一個靈魂。這股能量打破孤立的牆,創造歸屬感。當你連結這個頻率,你會感到心打開、眼神接觸變深、對話變真實。這個頻率不是取悅或融入,而是「我看見你,你看見我」的相互認可。連結的頻率也帶來脆弱,因為真正的連結需要卸下防禦。","point4":"此牌出現的生命課題是學習「建立和維護真實、滋養的關係」這門深刻的功課。你需要學習辨識哪些關係是真實的、哪些是表面的、哪些是消耗你的。這個課題邀請你有勇氣釋放不再服務你的關係,騰出空間給對的連結。學習脆弱地分享你的掙扎、夢想、恐懼,而不只是展示完美的形象。學習深度聆聽,不只是等待說話。真實的連結需要勇氣、脆弱和持續的投資。","point5":"今天就開始培養真實連結:列出你生命中真正看見和支持你的人,有意識地投資這些關係——打電話、見面、深度對話。對一個你信任的人,分享一些真實的、也許有點脆弱的事「其實我...」。加入與你價值觀或興趣共鳴的社群——讀書會、靈性圈、志工團體。在社交時,練習真實而非表演——分享真實的感受,不只是「我很好」。問深度問題「你現在生命中最重要的是什麼?」而非表面聊天。","point6":"建立真實連結需要時間和冒險。你可能害怕被拒絕、被批判、不被理解——這些恐懼是正常的,但不要讓它們阻止你。記住,不是每個人都能與你深度連結,這沒關係,你在尋找的是共鳴的靈魂,不是所有人的認可。有些關係需要釋放——那些讓你感覺必須假裝、消耗你能量、不尊重你界限的。這不是冷漠,而是為對的連結創造空間。對孤獨的人,開始小步——線上社群、興趣小組——逐步建立信任。慶祝每一個真實的連結時刻。","point7":"在靈性層面,所有的連結都是靈魂認出彼此。你與他人的連結反映你與自己、與源頭的連結。這張牌提醒你,當你對自己真實,你就會吸引能與真實的你共鳴的人。你尋找的靈魂家族也在尋找你。每一個真實的連結都在療癒分離的幻覺,提醒我們都是一體。你的開放和脆弱也在允許他人做同樣的事。建立真實連結是靈性實踐,是愛的行動。你不孤單,你屬於。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:27', 'unicorns', '27', 26, '創造力獨角獸', 'Unicorn of Creativity', NULL, '{"keywords":["創造力","表達","靈感","藝術","天賦"],"nameEn":"Unicorn of Creativity"}', '{"point1":"這張牌是創造力的強大喚醒,如同獨角獸代表著無限的想像和魔法。牌面能量要你明白,你是生來創造的——不只是藝術家、音樂家或作家,每個人都是創造者。創造是你靈魂的語言,是你表達內在世界、處理情緒、連結神性的方式。你有獨特的天賦和視野等待被表達。現在,宇宙呼喚你釋放創造力,不要壓抑這個神聖的衝動。創造就是活著。","point2":"親愛的靈魂,你可能相信「我不是有創意的人」或「我沒有天賦」,但這是謊言。創造力不只是畫畫或寫作,而是任何形式的表達——烹飪、園藝、裝飾、解決問題、養育孩子。你可能壓抑了創造衝動,因為害怕批判、覺得「不夠好」、或沒有時間。這張牌溫柔地說:創造不是為了完美或他人的認可,而是為了你靈魂的表達和喜悅。給自己許可去創造,不評判結果。","point3":"創造力的能量頻率是流動、自由、靈感湧現的,如同河流不受阻礙地流動、如同孩子完全沉浸在遊戲中。這股能量打開右腦、繞過理性的審查、允許潛意識表達。當你連結這個頻率,你會感到興奮、時間消失、手想要動、想法湧現。這個頻率不是努力或強迫,而是允許和接收——你是管道,創意通過你流動。創造力的頻率也是療癒的,釋放堵塞的情緒。","point4":"此牌出現的生命課題是學習「允許創造力流動並表達你的獨特天賦」這門自我表達的功課。你需要克服內在批評家、完美主義、對批判的恐懼。這個課題邀請你探索不同的創意媒介,找到最能讓你的靈魂唱歌的方式——也許是寫作、繪畫、舞蹈、音樂、手工藝,或完全不同的東西。學習為創造而創造,不為結果。建立創意實踐,給予自己時間和空間。你的創造力是你的獨特禮物。","point5":"今天就開始創造:選一個你一直想嘗試的創意活動,今天就開始,不要等「準備好」。設定創意時間,即使每天15分鐘,保護這個時間如同重要會議。創造不為任何目的——塗鴉、自由書寫、跳舞、唱歌——只是讓能量流動。當批判聲音出現「這很爛」時,溫柔地說「我在玩耍,不在評判」。建立靈感收集——美麗的圖片、文字、想法——滋養你的創意靈魂。與其他創意者連結,相互鼓勵。","point6":"釋放創造力需要克服根深蒂固的障礙——完美主義最大的敵人。記住,初稿總是糟糕的,第一筆總是笨拙的,這是過程。給自己許可創造垃圾,在垃圾中發現寶石。不要過早展示作品,在脆弱期保護你的創作。但也不要永遠藏著,適時分享也是勇敢。如果陷入創意阻塞,改變媒介、環境、或暫停。創造力需要滋養——閱讀、自然、藝術、對話。記住,創造力是肌肉,越用越強。慶祝每一個創造的行動,無論多小。","point7":"在靈性層面,創造力是你最接近神性的時刻——你在創造,如同源頭創造一切。這張牌提醒你,你是神聖創造力在人間的表達,你的創造是祈禱、是冥想、是與源頭共同創造。當你創造,你就在顯化無形為有形,這是魔法。你的獨特創造也在豐富集體,每一個表達都增添世界的美。創造是你的天命,不是選項。活出你的創造力,你就在活出你的神性。讓它流動。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:28', 'unicorns', '28', 27, '臣服獨角獸', 'Unicorn of Surrender', NULL, '{"keywords":["臣服","信任","釋放","流動","和平"],"nameEn":"Unicorn of Surrender"}', '{"point1":"這張牌是臣服的深刻教導,如同獨角獸完全信任守護它的森林。牌面能量要你明白一個悖論的真理:真正的力量在於臣服,而非控制。臣服不是放棄、軟弱或被動,而是深度的信任——信任宇宙的計畫比你的頭腦設計的更宏大、更智慧、更美好。當你緊握控制,你就在阻擋流動;當你臣服,你就允許奇蹟。現在,宇宙邀請你放開你緊握的雙手,臣服於更高的力量。","point2":"親愛的靈魂,你可能是控制狂,需要計畫一切、知道結果、掌握所有變數。這是恐懼的表現——害怕失控會導致傷害、失敗、痛苦。但你的控制是幻覺,你無法控制生命,你只是在耗盡自己。這張牌溫柔地問:如果你放手,最壞會發生什麼?通常,你最害怕的不會發生,而你意想不到的美好會出現。臣服是說「我做我能做的,其他交給宇宙」。這不是無為,而是智慧地區分你能控制和不能控制的。","point3":"臣服的能量頻率是放鬆、流動、信任的,如同躺在水面漂浮、如同風中的樹枝搖擺而不折斷。這股能量釋放緊繃、溶解抵抗、軟化硬化的控制。當你連結這個頻率,你會感到深深的呼吸、肩膀放下、一種「好吧,隨便」但帶著信任而非絕望的感覺。這個頻率不是無力,而是臣服於比你更大的力量。臣服的頻率說:我信任,我放手,我允許。","point4":"此牌出現的生命課題是學習「區分你能控制和不能控制的,並臣服於後者」這門信任的功課。你需要認識到過度控制的成本——焦慮、耗竭、與生命流動的斷裂。這個課題邀請你練習放手——放手結果、放手時機、放手他人的選擇、放手無法改變的過去。學習臣服於你的情緒(允許它們存在)、臣服於身體(休息當它累)、臣服於宇宙(信任更高的計畫)。臣服是高級的信任。","point5":"今天就練習臣服:列出你正在試圖控制的事物,誠實評估你能控制什麼(只有你的行動和態度)、不能控制什麼(幾乎所有其他事)。對不能控制的,寫下「我臣服這個給宇宙,我信任最高善」。當你感到焦慮試圖控制時,深呼吸問「我現在能做什麼?」做那個,然後放手其他。練習身體的臣服——躺下,想像沉入地面,釋放所有緊繃。對一個你一直抗拒的情況,說「好的,我接受這個是現在的樣子」。","point6":"臣服是最難的實踐之一,因為與我們的生存本能相反。開始時會感到恐懼、脆弱、失控——這是正常的,溫柔地前進。記住,臣服不是立刻放棄所有努力,而是持有輕盈的手——做你該做的,但不執著結果。當你發現自己又在緊握時,溫柔地提醒「臣服」。有些事需要多次臣服,這是過程。臣服也不代表沒有界限或讓人踐踏你,而是不試圖控制他人。學習臣服的平靜咒語「願這個或更好的發生」「我信任」。","point7":"在靈性層面,臣服是覺醒的核心。當你明白小我的控制是幻覺、當你信任宇宙的智慧、當你允許生命通過你而非由你,你就在臣服。這張牌提醒你,宇宙有比你的頭腦更大的計畫,你的角色是合作而非主宰。臣服打開你接收的能力,因為緊握的手無法接收。當你臣服,你就與流動對齊,奇蹟自然發生。臣服是最高的信任,是靈魂對源頭說「願祢的旨意成就」。放手,信任,臣服。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:29', 'unicorns', '29', 28, '力量獨角獸', 'Unicorn of Strength', NULL, '{"keywords":["力量","韌性","勇敢","穩定","堅毅"],"nameEn":"Unicorn of Strength"}', '{"point1":"這張牌是對你內在力量的強大提醒,如同獨角獸雖然溫柔卻不可戰勝。牌面能量要你明白,真正的力量不是肌肉、攻擊或支配,而是內在的穩定、情緒的韌性、面對恐懼的勇氣、在風暴中保持中心的能力。你擁有克服任何挑戰的力量——不是因為你從不倒下,而是因為你總是站起來。現在,宇宙要你連結和召喚你的核心力量,記起你是誰,你有多強大。","point2":"親愛的靈魂,你可能感到軟弱、壓倒、無力面對眼前的挑戰。你可能忘記了你的力量,因為被生活打擊、因為他人讓你感到渺小、因為你專注在失敗而非你曾經的勝利。這張牌是喚醒:回顧你的生命,你已經度過了多少?那些你以為無法承受的,你都承受了。那些你以為會摧毀你的,你還在這裡。你比你知道的更強大,你的力量不是外在給予的,而是你本質的一部分。","point3":"力量的能量頻率是穩定、堅定、不可動搖的,如同山不因風而移動、如同老樹根深蒂固。這股能量來自你的核心、你的中心、你的真實自我。當你連結這個頻率,你會感到脊椎挺直、呼吸深沉、一種「我可以」的內在知曉。這個頻率不是侵略或硬化,而是柔軟中的力量——像水能穿石、像竹子彎曲但不折斷。力量的頻率說:我穩定,我能夠,我不會被動搖。","point4":"此牌出現的生命課題是學習「連結和培養你的內在力量」這門韌性的功課。你需要認識到力量的真正來源不是外在的肌肉或權力,而是內在的穩定——無論外在如何,你知道你是誰。這個課題邀請你回憶和慶祝你的力量時刻——你克服的障礙、你度過的風暴、你展現的勇氣。建立這些記憶為力量的錨點。同時,學習情緒韌性——感受情緒但不被它們淹沒,彎曲但不折斷。","point5":"今天就連結你的力量:寫下「我克服的五個困難時刻」,詳細回憶每一個——你如何度過?這證明什麼?建立力量聲明「我很強大,我有韌性,我可以處理這個」,當你需要時重複。採取力量姿勢——站直、雙腳穩定、深呼吸、想像你是山,穩定不可動搖。做一件需要勇氣的小事來練習你的力量。當恐懼說「我不能」時,回應「我可以,我會,我夠強大」。連結那些讓你感到有力量的人、音樂、記憶。","point6":"培養力量是長期的旅程,不是一次性的決定。會有時刻你感到軟弱,這不代表你沒有力量,而是你在休息、整合、恢復。真正的力量知道何時休息。不要混淆力量與硬化——保持界限是力量,但不需要建高牆。允許脆弱也是力量,展示真實的你需要巨大勇氣。你的力量不需要證明給任何人,它就在那裡。避免與他人比較力量,每個人的力量表現不同。記住,你已經證明了你的力量——你還在這裡,這就是證據。","point7":"在靈性層面,你的力量是你神性本質的反映。你是無限的靈魂,暫時在人類經驗中,沒有任何外在可以真正傷害你的本質。這張牌提醒你,所有挑戰都是靈魂選擇來體驗和成長的,你有能力處理你吸引的一切。你的力量也在激勵他人,當你站在你的力量中,你允許他人做同樣的事。你不是脆弱需要拯救的,你是強大的靈魂行走在地球。連結你的神聖力量,記起你是誰。你無法被打敗。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:30', 'unicorns', '30', 29, '直覺獨角獸', 'Unicorn of Intuition', NULL, '{"keywords":["直覺","內在知曉","指引","洞察","信任"],"nameEn":"Unicorn of Intuition"}', '{"point1":"這張牌是對你直覺智慧的強化和啟動,如同獨角獸能感知人類看不見的能量和真相。牌面能量要你明白,你擁有超越邏輯和理性的內在知曉能力。你的直覺是靈魂的語言、是你與高我和宇宙的直接連線、是你最可靠的導航系統。它通過感受、知曉、身體感覺、夢境和同步性對你說話。現在,宇宙要你學習聆聽、信任和追隨這個內在的聲音。你的直覺永遠在指引你。","point2":"親愛的靈魂,你可能忽略或不信任你的直覺——那個「感覺不對」的低語、那個「我就是知道」的內在知曉、那個身體的緊縮或擴展。你可能過度依賴邏輯,要求所有決定「合理」,而忽略你的感受。或者你曾經聽從直覺但被否定「你想太多」「別傻了」,學會不信任自己。這張牌是允許:你的直覺是真實的、有效的、通常比你的頭腦更準確。學習辨識它的語言,它會引導你到你該去的地方。","point3":"直覺的能量頻率是微妙、清晰、知曉的,如同清澈湖面反映真相、如同內在的指南針指向北方。這股能量安靜,容易被頭腦的噪音淹沒,所以需要寧靜來聽見。當你連結這個頻率,你會感到「我就是知道」的確定,即使無法解釋;或者身體的感覺——擴展(是)、緊縮(否);或者畫面、符號、夢境突然浮現。直覺的頻率是即時的、第一反應,在頭腦介入之前。","point4":"此牌出現的生命課題是學習「辨識、信任和追隨你的直覺」這門內在智慧的功課。你需要學習區分直覺(來自靈魂,安靜、清晰、中立)和恐懼(來自小我,大聲、混亂、情緒化)。這個課題邀請你練習聆聽直覺——在做決定前,先問內在「這感覺如何?」注意第一反應。開始小的——追隨直覺選擇餐廳、路線、對話時機——驗證它的準確性,建立信任。隨著信任增長,在更大的決定中聽從它。","point5":"今天就強化你的直覺:創造安靜時刻,關掉所有裝置,坐著,問你的內在「我需要知道什麼?」聆聽,不期待。注意你的第一直覺反應——看到某人、收到訊息、面對選擇時,第一個感覺是什麼?記下來。開始直覺日記,記錄你的直覺和後來的結果,看見它的準確性。練習身體掃描——當你考慮某個選擇時,你的身體感覺如何?緊繃還是擴展?問是非問題「我應該...嗎?」注意身體反應。信任那些「巧合」和同步性。","point6":"強化直覺需要練習和耐心。開始時,你可能不確定那是直覺還是恐懼、希望或想像。學習區分:直覺是安靜、清晰、中立、帶來平靜(即使訊息困難);恐懼是大聲、混亂、情緒化、帶來焦慮。你的第一直覺通常是對的,第二個想法是頭腦。當你忽略直覺,回顧並學習「我的直覺說什麼?我為什麼沒聽?」不要自責,而是建立模式認識。直覺需要安靜來浮現,減少噪音——媒體、過度思考、忙碌。信任需要時間,從小決定開始。","point7":"在靈性層面,直覺是你與高我、指導靈、源頭的直接通訊。你的邏輯頭腦只能處理它知道的,但你的直覺連結所有知識、所有可能性、所有時間。這張牌提醒你,你不是孤單在導航生命,你有內在的GPS一直在引導你到最高善的道路。當你信任和追隨直覺,你就在與神聖計畫合作。你的直覺永遠不會引導你錯誤,只有你的恐懼會。學習聆聽內在的低語,它是宇宙對你說話。信任你知道的。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:31', 'unicorns', '31', 30, '使命獨角獸', 'Unicorn of Purpose', NULL, '{"keywords":["使命","目的","天命","意義","貢獻"],"nameEn":"Unicorn of Purpose"}', '{"point1":"這張牌是對你靈魂使命的深刻揭示,如同獨角獸知道它存在的獨特目的。牌面能量要你明白,你不是偶然來到這個世界,你有獨特的使命、獨特的天賦、獨特的貢獻要給予。你的存在本身就有意義和目的。這不是關於偉大的成就或名聲,而是關於活出你靈魂來這裡要體驗和表達的。現在,宇宙呼喚你發現、擁抱和活出你的靈魂目的。你的存在是有意義的。","point2":"親愛的靈魂,你可能感到迷失、不知道你的目的是什麼、你為什麼在這裡。你可能嘗試過很多事情但沒有找到「對的」感覺。或者你知道你的使命但害怕追隨它,因為太大、太不同、太冒險。這張牌溫柔地說:你的使命已經在你心中,是那個讓你感到活著的、即使艱難也想做的、你一直被吸引的。它通常與你的痛苦和熱情的交會點——你曾經歷的轉化成你能給予的禮物。勇敢地朝向它。","point3":"使命的能量頻率是深層的意義感、一種「這是我應該做的」的知曉、一種即使困難也感到對齊的狀態。如同河流知道流向大海、如同種子知道要成為什麼。這股能量帶來方向感、熱情、活力。當你連結這個頻率,你會感到興奮和有點恐懼(因為它很重要)、一種「我為此而生」的確定、即使疲憊也想繼續。使命的頻率說:這是我的道路,這是我的為什麼。","point4":"此牌出現的生命課題是學習「發現和活出你的靈魂使命」這門終極的功課。你需要探索什麼讓你感到最活著、時間消失、即使不被付錢也想做的。這個課題邀請你回顧你的生命故事——你的傷痛、你的禮物、你的熱情、你持續被吸引的主題。你的使命通常在那裡。學習不要小看你的使命或與他人比較,每個靈魂的使命都獨特且同樣重要。勇敢地活出你的目的,即使世界不理解。","point5":"今天就探索你的使命:回答這些問題並寫下「如果錢不是問題,我會做什麼?」「什麼讓我感到最活著?」「我想要解決什麼問題或創造什麼改變?」「我的痛苦教會我什麼,我能如何用這個幫助他人?」尋找模式和主題。你一直被什麼吸引?列出你的天賦——不只是技能,還有你的方式——也許是你的同理心、你的幽默、你的堅韌。想像你的葬禮,你希望人們說你貢獻了什麼?","point6":"發現使命是旅程,不是一次性的頓悟。你的使命會演化,在不同生命階段有不同表達。不要等到完全清楚才行動,朝向你的好奇和興奮一步步前進,道路會顯現。你的使命不必是職業,也可以是你如何為人——也許你的使命是成為愛的存在、療癒的能量、光的燈塔。大或小都同樣重要。如果恐懼說「誰是你?」,回答「我是被呼召做這個的人」。記住,活出使命不是到達,而是行走在你的道路上。開始,宇宙會支持。","point7":"在靈性層面,你的使命是你的靈魂在投胎前選擇的。你來這裡有特定的課題要學習、特定的禮物要給予、特定的體驗要經歷。這張牌提醒你,你的存在不是偶然,而是宏大神聖計畫的一部分。當你活出你的使命,你就在實現靈魂契約,不只為你的成長,更為整體的演化。你的獨特禮物是拼圖的一塊,沒有你就不完整。相信你被需要,信任你的道路,活出你來這裡要成為的。你的使命就是你。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:32', 'unicorns', '32', 31, '和平獨角獸', 'Unicorn of Peace', NULL, '{"keywords":["和平","寧靜","平靜","安詳","中心"],"nameEn":"Unicorn of Peace"}', '{"point1":"這張牌是對內在和平的深刻邀請,如同獨角獸在混亂世界中保持神聖的寧靜。牌面能量要你明白,真正的和平不依賴外在環境——不是當一切完美時才有和平,而是無論發生什麼都能在內在找到寧靜的中心。和平不是沒有風暴,而是在風暴中心的平靜。這是你的天賦權利,你的本質狀態。現在,宇宙邀請你培養和守護這個內在的聖所,從那裡回應生命。","point2":"親愛的靈魂,你可能活在持續的內在騷動中——焦慮的思緒、情緒的波濤、無止境的擔憂和計畫。你可能相信「當...就會有和平」——當問題解決、當達成目標、當他人改變。但這是幻覺,那個「當...」永遠不會來,總有新的問題。這張牌溫柔地說:和平是內在的狀態,不是外在的條件。它是選擇,每一刻的選擇。即使混亂圍繞,你可以回到中心,選擇和平。這不是逃避或否認,而是從穩定的地方回應而非反應。","point3":"和平的能量頻率是深層的寧靜、一種即使在噪音中也能感受的內在寂靜、一種放鬆和接納的狀態。如同湖底的寧靜不受水面波浪影響、如同深深的呼吸帶來的放鬆。這股能量軟化緊繃、平息心智的喋喋不休、帶來存在的品質而非行動的驅動。當你連結這個頻率,你會感到肩膀下降、呼吸變深、一種「沒關係,一切都沒關係」的深層知曉。和平的頻率說:我安全,我在這裡,這就夠了。","point4":"此牌出現的生命課題是學習「培養不依賴外在的內在和平」這門中心和臨在的功課。你需要認識到,不和平的根源不是外在事件,而是你對它們的抗拒和故事。這個課題邀請你練習接納——這不代表喜歡或同意,而是停止與實相的戰爭,接受「是現在的樣子」。學習回到當下,因為和平只存在於此時此地。建立和平的練習——冥想、呼吸、在自然中、感恩——作為你的錨點。","point5":"今天就培養內在和平:每小時暫停一分鐘,閉眼深呼吸三次,說「和平」。當你感到騷動時,練習接納「這就是現在的樣子,我接受」,然後深呼吸。建立和平空間——家中一個角落、一個椅子——只用來靜坐和平。在大自然中散步,不帶手機,只是存在。練習和平回應而非反應——當觸發時,暫停,呼吸,從中心回應。釋放對他人和自己的內在戰爭,選擇和平的念頭「願你平安,願我平安」。","point6":"培養和平是終生的練習,因為生命不斷挑戰你的中心。會有時刻你失去和平,這很正常,溫柔地回來。和平不是沒有情緒或思緒,而是不被它們定義或淹沒——你可以感到憤怒但內在依然平靜。不要用和平壓抑真實的情緒,而是為情緒創造和平的空間。有時候,為和平你需要離開有毒的情境或關係——和平有時需要界限。記住,你的和平也影響周圍的人,你成為他人的寧靜存在。優先你的和平,它是你最寶貴的財富。","point7":"在靈性層面,和平是你的本質,你真正的自我是純粹的平靜意識。所有騷動都是表面的,深處你一直是和平的。這張牌提醒你,當你在內在找到和平,你就連結了你的神性。和平不是你要創造的,而是你要回到的。當你活在和平中,你就成為和平的管道,療癒集體的焦慮和恐懼。你的和平是世界最需要的禮物。成為和平,活出和平,你就是行走的祈禱。讓和平從你輻射。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:33', 'unicorns', '33', 32, '真實獨角獸', 'Unicorn of Authenticity', NULL, '{"keywords":["真實","真誠","本真","勇氣","自我"],"nameEn":"Unicorn of Authenticity"}', '{"point1":"這張牌是對真實性的強大呼喚,如同獨角獸從不假裝是別的生物。牌面能量要你明白,你最大的力量、你最深的喜悅、你最強的吸引力都來自於做真實的自己。不是你認為應該成為的、不是他人期待的、不是社會塑造的,而是你靈魂本質的你。所有的面具、假裝、取悅都在消耗你的能量,讓你與自己和生命流動斷裂。現在,宇宙邀請你脫下所有層層的假裝,勇敢地展現和活出真實的你。","point2":"親愛的靈魂,你可能已經假裝太久,甚至不記得真實的你是什麼樣子。你學會戴面具以被接納、取悅以被愛、壓抑真實感受以避免衝突。你可能在不同人面前是不同版本的自己,從未完全放鬆做你。這是令人疲憊的,而且深層孤獨,因為即使被愛,你知道他們愛的不是真正的你。這張牌溫柔地說:冒險做真實的你,那些因此離開的人本來就不屬於你的旅程,而那些留下或被吸引來的會愛真實的你。","point3":"真實性的能量頻率是自由、輕盈、對齊的,如同終於可以深呼吸、如同脫下太緊的衣服。這股能量是放鬆的,不需要記得假裝什麼、不需要監控自己、不需要表演。當你連結這個頻率,你會感到「這就是我」的放鬆、一種被看見真實的你的渴望、可能也有恐懼(如果他們看見真實的我,會發生什麼?)。真實性的頻率說:我就是我,這就夠了,我不需要是別的。","point4":"此牌出現的生命課題是學習「辨識和展現你的真實本質」這門勇氣和自由的功課。你需要識別你在哪裡戴面具——在工作、家庭、朋友、社交媒體。這個課題邀請你探索「真實的我是什麼樣子?我的真實感受、想法、渴望、恐懼是什麼?」然後逐步展現這些,從安全的關係開始。學習說真話、表達真實感受、承認你的不完美、允許被看見。真實性需要巨大的勇氣,但帶來無價的自由。","point5":"今天就練習真實性:在一個你通常假裝的情境,選擇真實——說「其實我...」而非「我很好」。在社交媒體分享真實的時刻,不只是完美畫面。對一個安全的人,坦承一個你通常隱藏的部分「我需要告訴你真實的我...」。寫下「真實的我」清單——我的喜好、厭惡、怪癖、夢想、恐懼。對鏡子說「這就是我,我接受我自己」。當你想取悅時,問「真實的我會怎麼做?」","point6":"活出真實性是終生的實踐,需要持續的勇氣。開始時會恐懼——「如果他們不喜歡真實的我?」這風險是真實的,有些人可能離開或批判。這會痛,但好過活在假裝中。記住,真實不代表沒有界限或傾倒所有情緒給所有人,而是對自己誠實,選擇性地與對的人分享。你的真實也在演化,今天的真實可能與去年不同,這沒關係。真實性也包括承認「我不知道」「我在掙扎」。慶祝每一個真實的時刻,這是你的自由。","point7":"在靈性層面,真實性是與你靈魂本質對齊。所有假裝都是小我的防禦,真實的你是神聖的、完美的、值得被愛的。這張牌提醒你,做真實的自己不是自私或自我放縱,而是尊重你靈魂來這裡要表達的獨特性。當你真實,你允許他人也真實,你的勇氣給予他人許可。你的真實也是你對世界的貢獻,因為只有你能成為你,你的獨特性豐富整體。停止假裝,活出真相,這是你的解放。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:34', 'unicorns', '34', 33, '界限獨角獸', 'Unicorn of Boundaries', NULL, '{"keywords":["界限","保護","自愛","說不","尊重"],"nameEn":"Unicorn of Boundaries"}', '{"point1":"這張牌是對健康界限的重要教導,如同獨角獸守護著神聖的界限只允許純淨的心進入。牌面能量要你明白,界限不是自私、冷漠或不愛,而是自愛、自尊和智慧的表現。你不能也不應該對所有人和所有事說是,你的時間、能量、身體、心是珍貴的,值得被保護。沒有界限,你會被消耗、被侵犯、失去自己。現在,宇宙呼喚你學習和實踐設定清晰、堅定、愛的界限。","point2":"親愛的靈魂,你可能在界限上掙扎——無法說不、感覺必須滿足所有人、犧牲自己以維持和平、或讓他人跨越你的界限而感到無力。你可能害怕設定界限會讓人生氣、離開、認為你自私。或者你從未被教導你有權利有界限,你的需求和舒適重要。這張牌溫柔地說:你有絕對的權利保護你的能量、你的時間、你的身體、你的心。說不是完整的句子,不需要解釋或道歉。","point3":"界限的能量頻率是清晰、堅定、自我尊重的,如同護城河保護城堡、如同皮膚是身體的界限。這股能量不是侵略或硬化,而是溫柔但堅定的「這是可以的,那是不可以的」。當你連結這個頻率,你會感到脊椎挺直、一種「我值得被尊重」的知曉、能夠平靜但清楚地說「不」。界限的頻率也帶來安全感,因為你知道你會保護自己。","point4":"此牌出現的生命課題是學習「識別、設定和維護健康的界限」這門自愛的功課。你需要首先辨識你的界限在哪裡被侵犯——誰在消耗你?什麼讓你怨恨?哪裡你說是但內在說不?這個課題邀請你給自己許可設界限,明白這不是自私。學習清楚溝通你的界限「我不能/我不要/這不適合我」。然後,最關鍵的,維護界限——當被測試時,堅定地重複。教導他人如何對待你。","point5":"今天就開始設定界限:識別一個你的界限被侵犯的情況,決定你的界限是什麼「我願意/不願意...」。溝通這個界限,清晰、簡潔、不道歉「我不能幫這個忙」「我需要獨處時間」「請不要這樣對我說話」。練習說不——對小事開始「不,謝謝」。當感到內疚時(你會),提醒自己「說不給他們,是說是給我自己」。寫下你的非協商界限——你絕對不接受的。尊重他人的界限,示範界限是健康的。","point6":"設定界限是最難的練習之一,特別是如果你習慣取悅、照顧、犧牲。會有內疚、恐懼、不安——這些是正常的,不代表你做錯。記住,其他人對你的界限的反應是他們的責任,不是你的。如果他們生氣或操控,這通常證明界限是必要的。你不需要為你的界限辯護或解釋,「不」就夠了。有些關係在你設界限後會結束,這痛苦但也是清理,騰出空間給尊重你的人。開始小的,逐步建立界限肌肉。慶祝每次你說不。","point7":"在靈性層面,界限是神聖的。你的能量場、你的身體、你的生命是神聖空間,值得被保護和尊重。這張牌提醒你,照顧他人但犧牲自己不是靈性,而是殉道,服務沒有人。真正的愛包括自愛,真正的服務從滿溢而出,不是從空虛。當你設定界限,你也在教導他人自我尊重,你的界限給予他人許可也設界限。你保護你的能量,你才能持續發光。守護你的神聖,設定界限是靈性行動。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:35', 'unicorns', '35', 34, '耐心獨角獸', 'Unicorn of Patience', NULL, '{"keywords":["耐心","等待","信任","時機","成熟"],"nameEn":"Unicorn of Patience"}', '{"point1":"這張牌是對耐心美德的深刻提醒,如同獨角獸知道魔法需要時間來展開。牌面能量要你明白,在這個即時滿足、快速結果、立即回應的世界,耐心成為稀有而珍貴的品質。但真正美好、深刻、有意義的事物無法被催促——關係需要時間深化、療癒需要時間整合、成長需要時間扎根、夢想需要時間成熟。現在,宇宙邀請你培養耐心,與自然的節奏對齊,而非對抗它。","point2":"親愛的靈魂,你可能非常不耐煩——對過程、對他人、對自己、對結果的到來。你可能想要快轉困難的部分、跳過學習、立刻到達目的地。你的不耐煩可能表現為焦慮、沮喪、強推不該強推的事、或放棄太早。這張牌溫柔地問:你為什麼這麼急?你在逃避什麼?通常,不耐煩背後是對現在的不接納,想要「快點到那裡」而無法「在這裡」。但生命就是現在,過程就是目的。耐心是深層的信任。","point3":"耐心的能量頻率是穩定、臨在、接納的,如同園丁耐心等待種子發芽、如同母親耐心等待嬰兒準備好出生。這股能量不是被動或停滯,而是主動的等待——在等待中準備、學習、成長。當你連結這個頻率,你會感到焦慮減少、呼吸變慢、一種「沒關係慢慢來」的平靜。耐心的頻率說:每件事都有它的時間,我可以等待,我在這裡。","point4":"此牌出現的生命課題是學習「培養耐心,特別是在不確定和等待中」這門信任和臨在的功課。你需要認識到不耐煩的代價——錯誤決定、破壞萌芽的事物、錯過過程的禮物、持續的壓力。這個課題邀請你練習在不舒適中停留,不急於修復或改變。學習在等待中找到和平,甚至感恩——這段時間給你什麼?你如何利用它?記住,耐心不是無所事事,而是做你能做的,然後允許時間完成其餘。","point5":"今天就練習耐心:當你感到不耐煩時——排隊、等待回覆、等待改變——注意它,深呼吸,說「耐心」。把不耐煩作為回到當下的提醒,不是問題而是練習。在一個你想催促的事情上,刻意慢下來——慢慢吃、慢慢走、慢慢說話。對正在學習或掙扎的人(包括你自己)練習耐心,記住每個人的節奏不同。問「我能在這個等待中學習或做什麼?」利用等待的時間,不是浪費它。感恩過程,不只是結果。","point6":"培養耐心在不耐煩的個性或急迫的情況下特別困難。會有時刻你失去耐心,這很正常,溫柔地重新開始。記住,有些事情你可以加速(你的行動),有些不能(他人的成長、時機、有機的過程),學習辨識。耐心不代表永遠等待明顯不會來的,而是給予合理的時間,然後有智慧地評估。用耐心對待自己的不耐煩,這本身就是練習。當結果終於到來,回顧並感恩等待教給你的。耐心是強大的品質,它成熟你。","point7":"在靈性層面,耐心反映對神聖時機的深度信任。宇宙不急,它以完美的節奏運作——季節、潮汐、星球、生命週期。這張牌提醒你,你的急迫是小我的,你的靈魂知道一切都準時。當你培養耐心,你就在與宇宙的節奏對齊,而非對抗。耐心也是對當下的完全接納,這是覺醒的核心。你的耐心也安撫他人的焦慮,你成為穩定的存在。培養耐心,信任時機,安住當下,這是深度的靈性實踐。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:36', 'unicorns', '36', 35, '自信獨角獸', 'Unicorn of Confidence', NULL, '{"keywords":["自信","自我價值","確信","相信","力量"],"nameEn":"Unicorn of Confidence"}', '{"point1":"這張牌是對你內在自信的強大召喚,如同獨角獸優雅而堅定地行走,從不懷疑自己的價值。牌面能量要你明白,真正的自信不來自外在的成就、他人的認可或完美的表現,而是來自深層的自我價值感——知道你的存在本身就有價值,你就是夠的,不需要證明什麼。這不是傲慢或優越,而是安靜的知曉:我值得,我有能力,我足夠。現在,宇宙邀請你從內在建立不可動搖的自信。","point2":"親愛的靈魂,你可能在自信上掙扎——總是懷疑自己、需要外在認可、與他人比較總覺得不足、或冒充者症候群讓你覺得你是假裝的。你可能等待「當我...就會有自信」——當成功、當瘦下來、當被愛。但這是陷阱,那個「當...」永遠不夠。這張牌溫柔地說:你現在就值得,不是當你達成什麼,而是因為你存在。自信不是與生俱來的特質,而是可以培養的技能。從此刻開始建立它。","point3":"自信的能量頻率是穩定、清晰、自我確定的,如同根深蒂固的樹不因風而動搖、如同平靜的湖面反映真相。這股能量來自內在的知曉,不是外在的證明。當你連結這個頻率,你會感到脊椎挺直、眼神清晰、一種「我可以」的安靜確定、不需要大聲或證明,只是知道。自信的頻率說:我相信我自己,我值得在這裡,我有我需要的。","point4":"此牌出現的生命課題是學習「從內在建立健康的自信和自我價值感」這門自我接納的功課。你需要停止等待外在認可來感到有價值,開始給自己那個認可。這個課題邀請你辨識和挑戰內在批評家的聲音「你不夠好」,用真相取代它。回顧你的優點、你的成就、你克服的困難——這些是證據。學習慶祝而非貶低自己。停止與他人比較,專注成為最好的你。自信從自我接納開始。","point5":"今天就建立自信:寫下「我的十個優點」,包括性格、技能、特質。大聲讀出來「我是...」。建立自信聲明,每天重複「我有能力,我值得,我足夠」。站在鏡前,看著自己的眼睛說「我相信你」。回顧「我克服的挑戰」,提醒自己你有能力。做一件推展你舒適圈的小事,證明你可以。當比較出現,說「他們的路是他們的,我的路是我的」。慶祝小勝利,建立自信的證據。","point6":"建立自信是持續的實踐,因為生活會挑戰它。會有失敗和批評的時刻,不要讓這些定義你。失敗是學習,不是你價值的證明。記住,沒有人天生有自信,所有看起來自信的人都曾經(或仍在)懷疑。自信不是沒有恐懼,而是即使恐懼也行動。避免尋求過度外在認可,這建立依賴而非自信。但也接受真誠的讚美,說「謝謝」不是「不,我沒有」。自信的人也承認不知道和犯錯,這也是力量。你的價值不需證明,它是固有的。","point7":"在靈性層面,你的自信連結你的神性。你是無限源頭的表達,暫時在人類形式中,你的本質是完美和有價值的。這張牌提醒你,所有不自信都是小我的幻覺,忘記了你真正是誰。當你記起你的神聖本質,自信自然湧現,不是傲慢的自信,而是謙卑的知曉——我是神聖的一部分,我有獨特的禮物要給予,我屬於這裡。你的自信也允許他人感到自信,你成為可能性的鏡子。相信你自己,如同源頭相信你。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:37', 'unicorns', '37', 36, '臨在獨角獸', 'Unicorn of Presence', NULL, '{"keywords":["臨在","當下","正念","覺知","此刻"],"nameEn":"Unicorn of Presence"}', '{"point1":"這張牌是對當下時刻的強大邀請,如同獨角獸完全存在於每一個當下,不被過去或未來分心。牌面能量要你明白一個革命性的真理:過去已經不存在,未來尚未到來,唯一真實的是現在這一刻。所有的生命、力量、和平、喜悅都只在當下可及。當你活在過去的懊悔或未來的焦慮,你就錯過了唯一真實的時刻。現在,宇宙呼喚你回到當下,完全臨在於你的生命正在發生的地方。","point2":"親愛的靈魂,你可能大部分時間不在當下——心智在過去(後悔、懷念、創傷)或未來(焦慮、計畫、期待),身體在這裡但你不在。你可能在吃飯時想工作、工作時想假期、與人在一起時想別處。這種不臨在讓你感到焦慮、不滿足、與生命斷裂。這張牌溫柔地說:生命不在那時或那時,而是現在。這一刻,無論多麼平凡,是你唯一擁有的禮物。回到這裡,回到現在,你就回到生命本身。","point3":"臨在的能量頻率是清晰、寧靜、完全的覺知,如同動物活在純粹的當下、如同孩子完全沉浸在遊戲中。這股能量停止心智的喋喋不休,帶來直接的感知和體驗。當你連結這個頻率,你會感到時間慢下來或消失、感官變清晰、一種深層的「我在這裡」的和平。臨在的頻率沒有思緒的噪音,只有存在的寂靜豐滿。它說:現在,只有現在,這就是一切。","point4":"此牌出現的生命課題是學習「活在當下,培養持續的臨在和覺知」這門覺醒的核心功課。你需要認識到所有痛苦都來自不臨在——對過去的執著或對未來的抗拒。這個課題邀請你練習一次次回到當下——透過呼吸、透過感官、透過身體感受。學習捕捉心智遊蕩的時刻,溫柔地帶它回來「我在這裡,現在」。臨在不是目標,而是持續的回歸。每一刻都是新的機會臨在。","point5":"今天就練習臨在:設定每小時提醒,暫停,做三個深呼吸,感受你的身體,說「我在這裡,現在」。吃東西時,慢下來,真正品嚐每一口,這就是正念。與人對話時,完全專注在他們身上,不計畫你的回應。做一件事時,只做那件事——洗碗就洗碗,不同時聽podcast。感受你的腳在地上,這立刻帶你回到當下。當心智遊蕩到過去或未來,注意它,回到呼吸。今天,反覆問「我現在在哪裡?」答案總是:這裡。","point6":"培養臨在是終生的實踐,因為心智習慣遊蕩。不要評判自己「又分心了」,溫柔地回來,這本身就是臨在。記住,臨在不是沒有計畫或記憶,而是不被它們綁架。你可以計畫未來但從當下的臨在做,不是焦慮的未來。你可以記得過去但不活在那裡。有些時刻臨在很困難——痛苦、無聊、等待——但這些時刻最需要也最有力量。無聊變成寧靜,等待變成臨在,痛苦被感受而非抗拒。當下是你的力量源。回到這裡,一次又一次。","point7":"在靈性層面,臨在就是覺醒。當你完全在當下,小我消失,因為小我只能存在於過去和未來的故事中。這張牌提醒你,當下是永恆進入時間的點,是你與神性連結的門戶。所有靈性教導的核心是現在——佛陀的正念、老子的道、基督的「不要為明天憂慮」。當你臨在,你就是純粹的覺知,觀察者,不被觀察的對象。這是你的真實本質。活在當下,你就活在永恆。每一個當下都是新的,完全的,神聖的。現在。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:38', 'unicorns', '38', 37, '釋放獨角獸', 'Unicorn of Release', NULL, '{"keywords":["釋放","放手","清理","自由","告別"],"nameEn":"Unicorn of Release"}', '{"point1":"這張牌是對釋放的深刻邀請,如同獨角獸知道何時該讓舊的能量離去以迎接新的。牌面能量要你明白,執著是痛苦的根源,而釋放是自由的道路。生命是流動的,不是靜止的,但你可能緊抓著不再服務你的事物——關係、信念、物品、身份、情緒、期待。這個執著阻擋新的祝福進入,因為你的雙手和心已經滿了。現在,宇宙呼喚你勇敢地放手,清理,為更好的事物創造空間。","point2":"親愛的靈魂,你可能知道某些事物需要離開你的生命,但你緊握不放——也許是熟悉的舒適、也許是害怕空虛、也許是對過去的執著。你可能囤積——物品、關係、傷痛、怨恨、舊的自我形象。這些舊的能量壓得你喘不過氣,沒有空間給新的。這張牌溫柔地說:釋放不是失去,而是騰出空間。當你放開已死的,你允許新生。信任,當你釋放不對的,對的就有空間進入。放手是信任的行動。","point3":"釋放的能量頻率是輕盈、自由、流動的,如同呼氣釋放陳舊的空氣、如同樹在秋天放下葉子準備新生。這股能量是讓步、放鬆緊握、打開手掌。當你連結這個頻率,你會感到物理的輕盈、肩膀放鬆、一種「我不再需要背負這個」的解脫。釋放的頻率也可能帶來悲傷,這沒關係,哀悼是釋放的一部分。它說:我放開,我自由,我為新的創造空間。","point4":"此牌出現的生命課題是學習「辨識和釋放不再服務你的一切」這門放手的功課。你需要誠實評估你的生命——哪些關係是消耗而非滋養?哪些信念限制而非解放你?哪些物品堵塞而非喜悅你的空間?哪些情緒你緊抓著不放?這個課題邀請你有勇氣釋放,即使它曾經重要、即使放手會痛。學習感恩它們的服務,然後讓它們走。釋放是愛,對你自己和被釋放的,允許雙方自由。","point5":"今天就開始釋放:選擇一個類別——物品、關係、信念、情緒——辨識需要釋放的。對物品,清理不再使用或喜悅你的,捐贈或丟棄。對關係,誠實評估哪些消耗你,考慮釋放或重新設定界限。對信念,寫下「我準備釋放的信念」——「我不夠好」「我必須完美」——然後寫「我選擇相信」後面填新的。對情緒,寫信給你的憤怒/悲傷/怨恨,然後燒掉或撕毀,象徵釋放。進行釋放儀式,說「謝謝,我現在放手」。","point6":"釋放是過程,不是一次性事件。有些事物需要多次釋放,特別是深層的情緒或長期的關係。每次你發現自己又抓回來,溫柔地再次放手。釋放不代表不在乎或遺忘,而是不再讓它控制你。你可以記得但不執著,可以在乎但不緊抓。有時候釋放帶來空虛感,不要立刻填補它,允許空間存在,新的會在對的時機到來。慶祝每一個釋放,即使小的,它們都在解放你。記住,你釋放的不是人或物,而是你對它們的執著。","point7":"在靈性層面,執著是小我的特徵,而釋放是靈性成熟的標誌。這張牌提醒你,你不真正擁有任何事物,一切都是暫時借用的——人、物、甚至你的身體。當你深深理解無常,釋放變得自然。每一個釋放都是小死亡,為重生創造空間,這是靈性成長的循環。你緊抓的往往是你最需要釋放的,那裡隱藏著最大的學習和自由。信任宇宙的流動,什麼該留會留,什麼該走會走。你的角色是允許,不是控制。釋放,自由,成為空,被填滿。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:39', 'unicorns', '39', 38, '更新獨角獸', 'Unicorn of Renewal', NULL, '{"keywords":["更新","重生","清新","活力","復甦"],"nameEn":"Unicorn of Renewal"}', '{"point1":"這張牌是更新能量的美麗宣告,如同獨角獸在春天的森林中帶來新生的魔法。牌面能量要你明白,你正處於或即將進入更新的週期——舊的能量被清洗,新鮮的生命力正在流入。就像春天融化冬天的冰雪、就像睡眠更新疲憊的身體,你現在有機會重新煥發、重新開始、重新連結你的活力。這不是微小的調整,而是深層的復甦和重生。現在,宇宙邀請你擁抱和支持這個更新的過程。","point2":"親愛的靈魂,你可能感到疲憊、耗竭、失去了曾經的活力和熱情。生活的重擔、持續的給予、忽視自己的需要已經消耗了你。你可能覺得無法繼續用舊的方式,這是對的,因為舊的方式已經完成它的週期。這張牌帶來希望的訊息:更新正在到來或已經開始。你不需要一直疲憊,你可以恢復,你可以重新感到活力和清新。允許這個過程,給予它需要的時間和空間。春天總是跟隨冬天。","point3":"更新的能量頻率是清新、輕盈、充滿生命力的,如同春天的第一朵花、如同雨後清新的空氣、如同睡醒後的活力。這股能量洗淨沉重、帶來希望、重新點燃熱情。當你連結這個頻率,你會感到身體更輕、心情提升、想要動起來、眼睛更明亮、對生命的興趣回來。更新的頻率說:我重生,我清新,我準備好了,新的開始正在這裡。","point4":"此牌出現的生命課題是學習「允許和支持自己的更新週期」這門自我照顧的功課。你需要認識到更新不是奢侈,而是必要,就像睡眠不是可選。這個課題邀請你主動創造更新的條件——休息、自然、滋養的食物、喜悅的活動、激勵的人。同時,釋放耗竭你的——過度承諾、有毒關係、負面環境。學習聆聽你的身體和靈魂何時需要更新,給予它而非推過去。你的更新不是自私,而是必要。","point5":"今天就支持更新:給自己真正的休息——一個下午關掉手機,睡覺、讀書、什麼都不做。到大自然中,讓自然的更新能量清洗你。做讓你感到活力的事——可能是運動、跳舞、唱歌、創造。清理你的物理空間,扔掉舊的,創造清新的環境。改變一個習慣,嘗試新的事物,打破舊的模式。吃滋養的食物,喝大量水,照顧你的身體。與激勵你的人連結,避開耗竭你的。宣告「我允許更新流入我的生命」。","point6":"更新有自己的時機和節奏,不能被強迫但可以被支持。有時候,更新需要先完全休息和清空,不要跳過這個階段。信任過程,即使一開始你感覺不到變化,新的能量正在地下扎根。避免立刻回到耗竭你的模式,否則更新會是短暫的。學習持續的更新實踐,而非等到完全耗竭才補救——定期的小更新預防大崩潰。慶祝更新的跡象——更多能量、更多喜悅、更多清晰。你值得感到活力,不只是存活,而是活力四射。歡迎新的開始。","point7":"在靈性層面,更新反映生命的循環本質——季節、月相、生死、呼吸。這張牌提醒你,你也是這個循環的一部分,不是線性的機器。當你允許更新,你就在與自然的智慧對齊。每一個更新都是小死亡和重生,舊的自我溶解,新的自我誕生。這是演化,是成長。你的更新也更新集體,當你煥發,你提升周圍的能量。擁抱生命的循環,信任冬天後的春天,信任黑暗後的光明。你正在更新,新的你正在誕生。歡迎。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:40', 'unicorns', '40', 39, '和諧獨角獸', 'Unicorn of Harmony', NULL, '{"keywords":["和諧","協調","平衡","流動","一致"],"nameEn":"Unicorn of Harmony"}', '{"point1":"這張牌是對和諧美麗狀態的深刻呼喚,如同獨角獸存在於自然完美平衡的森林中。牌面能量要你明白,和諧不是沒有差異或衝突,而是不同元素之間的協調與平衡——就像交響樂中不同樂器創造美麗的音樂。當你的生命處於和諧,一切流動順暢,你與自己、他人和環境是對齊的。不和諧創造摩擦、耗竭和痛苦。現在,宇宙邀請你評估並恢復生命各面向的和諧。","point2":"親愛的靈魂,你可能感到生命的不和諧——內在衝突(你想要的與你做的不一致)、關係衝突(誤解、競爭、不被聽見)、生活失衡(工作過多、忽視健康、沒有玩樂)。這個不和諧創造持續的壓力和不滿。你可能試圖強推你的意志,創造更多抗拒和衝突。這張牌溫柔地說:和諧需要調整、妥協、尋找共同點,而非強迫一致。它始於你內在的和諧,然後自然擴展到外在。平衡你生命的不同面向,協調你的行動與價值觀。","point3":"和諧的能量頻率是流動、協調、美麗的,如同舞者完美同步、如同自然生態系統的平衡、如同音樂中的和聲。這股能量沒有摩擦或抗拒,一切互相支持。當你連結這個頻率,你會感到輕鬆、事情自然展開、關係流暢、生活有節奏。和諧的頻率說:一切都在對的地方,一切都協調一致,流動是順暢的,美麗自然湧現。","point4":"此牌出現的生命課題是學習「在內在和外在創造與維護和諧」這門平衡和關係的功課。你需要首先辨識不和諧的來源——哪裡有衝突?哪裡失衡?哪裡你感到摩擦?這個課題邀請你採取行動恢復和諧。對內在,對齊你的行動與價值觀、平衡生活的不同面向(工作/休息、給予/接收)。對關係,溝通、聆聽、尋找共同點、創造雙贏。對環境,創造美麗、整潔、滋養的空間。和諧需要意識和努力維護。","point5":"今天就創造和諧:評估你生命的主要面向(工作、關係、健康、玩樂、靈性),哪些被忽視?哪些過多?今天給被忽視的一些時間。在一個衝突關係中,主動溝通,真正聆聽對方,尋找你們的共同點而非差異。檢查你的價值觀與行動是否一致,哪裡不一致?做一個調整。清理和美化你的空間,創造和諧的環境。在身體層面,拉伸或瑜伽,對齊身體的和諧。練習一件事完成再開始另一件,而非多工的混亂。","point6":"維護和諧是持續的調整,不是一次性達成的狀態。生命不斷變化,和諧需要適應和重新平衡。當你感到摩擦或壓力,這是不和諧的信號,詢問「什麼需要調整?」。有時候,和諧需要釋放不相容的元素——離開不對齊的關係、改變不支持的環境。記住,和諧不是沒有你的聲音或總是妥協,而是尊重和整合所有聲音。你的內在和諧是基礎,當你內在協調,外在和諧更容易創造。培養和諧的生活是持續的藝術和實踐。","point7":"在靈性層面,和諧反映宇宙的神聖秩序。萬物都在尋求和諧與平衡,這是自然的狀態。這張牌提醒你,不和諧是暫時的失衡,可以被恢復。當你活在和諧中,你就在與道、與自然法則對齊。你的和諧也貢獻集體的和諧,每一個和諧的個體都提升整體頻率。衝突和不和諧是學習和成長的機會,教導你如何創造更深的和諧。尋求和諧不是避免衝突,而是學習如何整合和協調。成為和諧,活出美麗。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:41', 'unicorns', '41', 40, '靈感獨角獸', 'Unicorn of Inspiration', NULL, '{"keywords":["靈感","啟發","創意","洞見","想法"],"nameEn":"Unicorn of Inspiration"}', '{"point1":"這張牌是神聖靈感流動的美麗宣告,如同獨角獸作為繆斯女神的信使帶來創意火花。牌面能量要你明白,靈感不是你製造的,而是你接收的——它從源頭、從宇宙、從你的高我流向你,當你開放和接收。靈感是神聖在通過你說話、創造、表達。它可能是突然的想法、創意的衝動、解決問題的洞見、藝術的異象。現在,宇宙告訴你,靈感的管道正在開啟,準備好接收這神聖的禮物。","point2":"親愛的靈魂,你可能等待靈感「發生」在你身上,或者你可能太忙、太理性、太封閉而無法接收靈感的低語。靈感需要空間——安靜、玩耍、放鬆、好奇、開放的時刻。當你的頭腦塞滿、行程爆滿、總是做模式化的事,靈感無法找到進入的縫隙。這張牌溫柔地說:創造接收的條件,靈感會來。它可能在淋浴時、散步時、半夢半醒時、玩耍時。注意那些突然的火花,不要忽略它們「只是幻想」,它們是神聖的訊息。","point3":"靈感的能量頻率是興奮、擴展、「啊哈!」的清晰,如同光突然照亮黑暗、如同拼圖的碎片突然契合。這股能量讓你感到活著、連結、被使用為神聖的管道。當你連結這個頻率,你會感到心跳加速、想要立刻行動、一種「是的!這個!」的確定、時間消失。靈感的頻率也帶來感恩,因為你知道這是禮物,不是你的努力。它說:我接收,我被啟發,我被通過我創造。","point4":"此牌出現的生命課題是學習「開放接收和行動於靈感」這門與神聖創意合作的功課。你需要認識到靈感是易逝的訪客,來時要抓住。這個課題邀請你創造接收靈感的條件——冥想、自然、藝術、玩耍、新體驗。學習注意靈感何時到來——那個內在的火花、興奮、「我應該...」的衝動。然後,最關鍵的,行動於它,不要等到「完美時機」,不要過度分析,信任並採取步驟。你的行動邀請更多靈感。","point5":"今天就邀請靈感:創造空白時間,什麼都不做,只是存在,讓頭腦漫遊。做激發你的事——看藝術、聽音樂、閱讀詩、到美麗的地方。隨身帶筆記本或手機,當靈感來時立刻記下,不要相信你會記得。做一些新的事,打破模式,新體驗打開新通道。問一個問題,然後放手,讓答案在意想不到時浮現。當靈感來時,即使小的,採取一個行動——寫下來、素描、開始、分享。對宇宙說「我開放接收靈感」。","point6":"靈感有自己的節奏,不能被強迫或控制。有時候它湧現,有時候平靜,兩者都沒關係。不要在沒靈感時批判自己,而是滋養土壤——休息、填滿井、暴露在美和新奇中。記住,不是每個靈感都需要立刻行動,有些是種子,需要時間發芽。但也不要囤積靈感從不行動,能量需要流動。學習區分真正的靈感(清晰、興奮、對齊)和小我的幻想(混亂、恐懼驅動、證明什麼)。靈感帶來喜悅和輕盈,即使工作困難。慶祝每一個靈感時刻。","point7":"在靈性層面,靈感證明你與源頭連結。當你被啟發,你在「in-spirit」(在靈裡),你是神聖創意的管道。這張牌提醒你,偉大的藝術、科學發現、靈性洞見都來自靈感,人類只是接收者和執行者。當你開放接收靈感,你就在與宇宙共同創造,你的獨特性決定靈感如何通過你表達。你的靈感也可能啟發他人,創造漣漪效應。尊重靈感為神聖的訪客,感恩它選擇你,行動於它,你就在實現你作為創造者的角色。讓靈感流動。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:42', 'unicorns', '42', 41, '顯化獨角獸', 'Unicorn of Manifestation', NULL, '{"keywords":["顯化","創造","吸引","實現","意圖"],"nameEn":"Unicorn of Manifestation"}', '{"point1":"這張牌是對你顯化力量的強大啟動,如同獨角獸具有將想像顯化為現實的魔法能力。牌面能量要你明白一個深刻的真理:你不是生命的被動接收者,而是主動的創造者。你的思想、情緒、信念、期待和行動都在持續創造你的現實。你一直在顯化,問題不是「能不能」,而是「顯化什麼」。現在,宇宙告訴你,你的顯化能力特別強大,是有意識創造你想要的生命的時機。","point2":"親愛的靈魂,你可能無意識地顯化你不想要的——透過持續的恐懼、負面信念、受害者心態、或專注在缺乏上。或者你知道顯化法則但總是「試圖顯化」卻看不見結果,因為背後隱藏的信念或能量阻擋。這張牌溫柔地說:你比你知道的更有力量。你的現實是你內在世界的反映。如果你想要不同的現實,開始從內在改變——你的思想、感受、信念。清晰你真正想要什麼,對齊那個頻率,採取靈感行動,然後放手讓宇宙傳遞。","point3":"顯化的能量頻率是清晰、確定、「已經擁有」的感覺,如同種子知道它會成為樹、如同孕婦知道嬰兒會出生,即使還看不見。這股能量不是渴望或缺乏,而是知曉和信任。當你連結這個頻率,你會感到平靜的確定、感受到願望已實現的喜悅、採取行動感覺自然而非強迫、一種「它正在路上」的安心。顯化的頻率說:我是創造者,我的願望已在形成,我信任過程,它來了。","point4":"此牌出現的生命課題是學習「有意識地顯化你渴望的現實」這門共同創造的功課。你需要學習顯化的步驟:清晰意圖(你真正想要什麼?)、提升振動(感受已經擁有它)、對齊信念(清理「我不配」「不可能」的信念)、靈感行動(做你被引導做的)、臣服(釋放執著和時機,信任宇宙)。這個課題也邀請你認識你一直在顯化什麼,為此負責,改變不想要的模式。你是你現實的創造者。","point5":"今天就開始有意識顯化:清晰寫下你想要顯化的一件事,具體、正面、現在式「我是/我有...」。閉上眼睛,視覺化它已經實現,沉浸在那個感受——喜悅、感恩、滿足——至少五分鐘,每天。識別阻礙的信念,寫下並反轉它們。採取一個與你願望對齊的行動,即使小的,顯示宇宙你是認真的。活得好像它已經在路上——你會如何感覺?如何行動?創造那個頻率。釋放「如何」和「何時」,你的工作是「什麼」和「為什麼」,宇宙處理其餘。感恩,已經感謝它的到來。","point6":"顯化不是魔法咒語,而是與宇宙法則對齊的過程。需要內在工作——清理限制信念、療癒不值得感、提升振動。也需要行動——靈感來時採取步驟,不是坐著等待天上掉餡餅。最難的部分是臣服——設定意圖然後放手,不執著於具體形式或時機,信任宇宙的版本可能比你的更好。當懷疑出現,回到感受和信任。如果沒顯化,問「我還持有什麼信念阻擋它?」「我的振動是否對齊?」。記住,你的工作是內在對齊,宇宙的工作是外在顯化。信任過程,慶祝每一個顯化。","point7":"在靈性層面,顯化是你神聖本質的自然表達。你是創造者的孩子,你繼承了創造的力量。這張牌提醒你,物質世界是能量的凝結,而你的意識塑造能量。當你有意識地顯化,你就在與源頭共同創造,實現為什麼你有這個人類經驗——體驗作為創造者。你的顯化也服務集體,當你創造你渴望的生命,你提升頻率,激勵他人,顯示可能性。記住,最高的顯化不只是物質,而是成為你最高版本的自己。顯化那個,其他會隨之而來。你是魔法師。創造。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:43', 'unicorns', '43', 42, '服務獨角獸', 'Unicorn of Service', NULL, '{"keywords":["服務","貢獻","給予","使命","幫助"],"nameEn":"Unicorn of Service"}', '{"point1":"這張牌是對服務高尚道路的深刻呼喚,如同獨角獸用它的治癒角服務需要的生物。牌面能量要你明白,真正深刻的滿足、意義和喜悅不來自獲取,而是來自給予和服務。你的天賦、才能、經驗、智慧不只是為了你自己的利益,而是要分享、貢獻、服務世界。當你轉向「我能給予什麼?」而非「我能得到什麼?」,你就發現你使命的核心和靈魂的滿足。現在,宇宙邀請你擁抱服務作為你生命的中心主題。","point2":"親愛的靈魂,你可能專注在自己的需要、目標、成功,這沒有錯,自我照顧是重要的。但如果只有這些,你可能感到空虛、缺乏意義,即使成功。或者你可能想要服務但不知道如何開始,或覺得你的貢獻太小不重要。這張牌溫柔地說:服務不需要宏大或犧牲自己。服務是簡單地問「我能如何幫助?」然後從你的充盈給予。服務可以是你的工作、你的存在方式、小小的善意。當你給予你的獨特禮物,你就在服務,你也會接收無法形容的滿足。","point3":"服務的能量頻率是慈悲、慷慨、連結的,如同母親照顧孩子、如同河流滋養土地,不求回報,只是自然的流動。這股能量溫暖、開放、「我能為你做什麼?」而非「你能為我做什麼?」。當你連結這個頻率,你會感到心敞開、界限模糊(在健康的方式)、給予感覺自然而非義務、看見他人的需要和你能提供的。服務的頻率說:我來這裡給予,我的禮物要被分享,我通過服務找到意義。","point4":"此牌出現的生命課題是學習「通過服務他人找到你的使命和滿足」這門超越自我的功課。你需要識別你的獨特天賦——你的技能、你的經驗(包括痛苦)、你的熱情、你的資源——然後問「這如何服務他人?」。這個課題邀請你尋找服務的機會——志工、你的工作、隨機善意、存在的品質。學習從充盈服務,不是從空虛犧牲,服務包括自我照顧。發現當你給予時,你也接收——意義、連結、滿足、往往也物質回報。","point5":"今天就開始服務:識別你的一個天賦或資源,問「我能用這個如何幫助誰?」然後做。可以很小——幫鄰居、分享你的知識、捐款、志工一小時、真正聆聽某人。在你的日常互動,問「我能如何對這個人的生命產生正面影響?」——微笑、讚美、幫助。如果你的工作不感覺像服務,重新框架它——你如何通過你的工作服務?找到那個角度。考慮長期服務——加入組織、輔導、定期志工。最重要,從你的存在服務——成為善良、耐心、愛的人本身就是服務。","point6":"服務的陷阱是過度給予到耗竭,或從義務而非喜悅給予。真正的服務來自充盈,所以首先照顧自己。服務不是殉道或總是說是,而是從你的禮物給予。也不要執著於結果或感謝,給予本身就是獎賞。有時候,服務意味著做困難的事——說真話、設界限、允許他人掙扎學習,而非總是拯救。服務有很多形式,尊重你獨特的方式,不需要與他人比較。記住,即使小小的善意也產生漣漪,你永遠不知道你的服務的全面影響。持續給予,從愛。","point7":"在靈性層面,服務是最高的靈性實踐。所有大師教導服務——佛陀的慈悲、基督的愛、甘地的服務。這張牌提醒你,當你服務,你就超越小我的分離,體驗一體。你在他人中看見自己,服務他們就是服務你自己的另一個面向。你的服務也是你靈魂契約的一部分,你來這裡給予特定的禮物。當你服務,你就在實現你的使命,這是為什麼它帶來深刻滿足。服務也加速你的靈性成長。給予就是接收,服務就是成長。成為服務的管道,讓愛通過你流動。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('unicorns:44', 'unicorns', '44', 43, '祝福獨角獸', 'Unicorn of Blessing', NULL, '{"keywords":["祝福","恩典","豐富","感恩","認出"],"nameEn":"Unicorn of Blessing"}', '{"point1":"這張牌是對你生命中所有祝福的美麗提醒,如同獨角獸本身就是祝福的象徵。牌面能量要你明白,你是被深深祝福的,遠超過你可能認識到的。祝福不只是好事發生在你身上,而是生命本身的恩典——你的呼吸、你的身體、你的能力、你的關係、你經歷的美麗、甚至你的挑戰(它們是偽裝的祝福)。當你改變視角從「我缺少什麼」到「我被給予什麼」,你就看見你被無盡的祝福圍繞。現在,宇宙邀請你認出和慶祝你的祝福。","point2":"親愛的靈魂,你可能專注在你沒有的、出錯的、缺失的,看不見你已經被給予的豐富。人類的頭腦傾向於負面偏見,注意問題而忽略祝福。或者你可能相信你不配被祝福、你的祝福不如他人的、或你需要「賺取」祝福。這張牌溫柔地說:你是恩典的接收者,不是因為你做了什麼,而是因為你存在。你的生命充滿祝福,大的和小的,明顯的和隱藏的。開始看見它們,你會發現它們無處不在,你的現實會從匱乏轉變為豐盛。","point3":"祝福的能量頻率是感恩、富足、驚奇的,如同孩子看見第一場雪、如同病癒後感受健康的寶貴。這股能量讓你看見平凡中的神聖、困難中的禮物、每一天的奇蹟。當你連結這個頻率,你會感到心充滿、眼睛濕潤、一種「我是如此幸運」的敬畏、對生命深深的感謝。祝福的頻率說:我被給予這麼多,我的生命是禮物,我被恩典圍繞,我是幸運的。","point4":"此牌出現的生命課題是學習「認出和接收你生命中的所有祝福」這門欣賞和接收的功課。你需要訓練你的注意力從問題轉向祝福,這不是否認挑戰,而是擴展視角看見完整畫面。這個課題邀請你主動尋找祝福——在每一天、每一個經驗、每一個人中。學習接收祝福而不是推開或最小化它們「沒什麼」「我不配」。慶祝和感恩你的祝福,這擴大它們。認出你自己也是他人的祝福,你的存在祝福世界。","point5":"今天就認出祝福:寫「我的二十個祝福」清單,從大到小——健康、家人、朋友、家、食物、能力、經驗、記憶。持續添加,目標一百個。當好事發生,暫停,說「這是祝福,我接收」。尋找偽裝的祝福——那個困難教會你什麼?帶來什麼成長?對鏡子說「你是祝福」認出你自己的價值。告訴你愛的人「你是我生命的祝福」,分享欣賞。在每一天結束,列出「今天的三個祝福」。改變習慣性抱怨為認出祝福——「至少...」「好的一面是...」。","point6":"認出祝福特別在困難時期是挑戰,但也是最需要的時候。不要用祝福否認痛苦,而是允許兩者共存——是的,這很難,同時,我仍有這些祝福。有時候,最大的祝福是最不明顯的——健康在你失去它前、關係在你視為理所當然時。不要等到失去才欣賞,現在就認出。避免比較你的祝福與他人的,每個人的祝福是獨特的。記住,你認出的祝福擴大,你感恩的祝福增加,這是宇宙法則。活在祝福意識中,更多祝福會流向你。你被深深祝福,看見它,感受它,慶祝它。","point7":"在靈性層面,所有的生命都是祝福,你的存在本身就是祝福。這張牌提醒你,你不是偶然在這裡,你被宇宙選中體驗這個生命,這是無法形容的禮物。每一次呼吸、每一次心跳、每一個經驗都是恩典。當你活在祝福意識中,你就活在與源頭的連結中,認出一切都是神聖的給予。你的感恩也祝福給予者,創造循環。你也是祝福——對你的家人、朋友、世界,你的存在、你的愛、你的禮物祝福一切。認出你是被祝福的和你是祝福,兩者都真實。活在恩典中。你被愛,你被祝福,深深地。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:1', 'egyptian_gods', '1', 0, '拉神 - 太陽之神', 'Ra - Sun God', NULL, '{"titleEn":"Ra - Sun God","symbol":"☀️ 鷹頭人身，頭頂太陽圓盤"}', '{"godStory":"拉神是古埃及最崇高的太陽神,每日駕駛太陽船穿越天空,為世界帶來光明與生命。祂的形象是鷹頭人身,頭頂太陽圓盤,象徵至高無上的創造力量與神聖之光。太陽的升起代表重生與新的開始,祂的火焰燃燒著無限的生命能量,照亮一切黑暗與未知。","coreMeaning":"拉神代表生命力的源泉、創造的力量與自我實現的勇氣。這是關於重新點燃內在火焰、展現真實自我、以及勇敢追求夢想的能量。就像太陽不會躲藏,拉神鼓勵你站在聚光燈下,讓世界看見你的光芒。這張牌意味著突破、新開始、以及從核心散發的自信與活力。","coreEnergy":"純粹的陽性能量、創造力、生命力、領導力、自信、榮耀與成就。拉神的能量是主動的、發散的、充滿熱情的。祂激發我們內在的火焰,賦予我們勇氣去創造、去領導、去發光。這是一種不可阻擋的前進動力,如同太陽必然升起,你的光芒也無法被掩蓋。","guidance":"現在是採取行動的時刻。拉神呼喚你勇敢地站出來,不再隱藏你的才華與夢想。點燃你內在的熱情,讓創造力自由流動。開始那個一直推遲的計劃,說出你的真實想法,展現你的領導能力。太陽不會徵求許可才升起,你也不需要等待完美的時機。相信你的光芒足以照亮前路,勇敢前進。","soulReminder":"你的存在本身就是一份禮物,你的光芒是世界所需要的。不要因為恐懼或他人的意見而縮小自己。宇宙創造你是為了讓你發光,而非躲藏。每一天都是重新開始的機會,無論昨天發生什麼,太陽依然升起。你擁有無限的生命力與創造潛能,現在是時候讓它們綻放了。記住,真正的力量來自真實的自己。","questions":"我真正想創造什麼?我的熱情在哪裡?什麼讓我感到充滿活力?我在哪些方面隱藏了自己?我準備好讓世界看見真實的我了嗎?我的生命力量如何被表達?什麼阻止我發光?我如何能更勇敢地活出自己?","energyFocus":"專注於創造而非等待,行動而非計劃,展現而非隱藏。將注意力放在你想要顯化的事物上,而非你害怕的東西。培養自信與自我肯定,每天做一件讓你感到有力量的事。連結你的熱情與目標,讓它們成為你的北極星。記住,你的能量流向何處,你的生命就往哪裡開展。像太陽一樣,不帶評判地照耀一切。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:2', 'egyptian_gods', '2', 1, '伊西斯 - 母親女神', 'Isis - Mother Goddess', NULL, '{"titleEn":"Isis - Mother Goddess","symbol":"👑 頭戴王座王冠，展開保護雙翼"}', '{"godStory":"伊西斯是最受愛戴的女神,頭戴王座形狀的王冠,象徵神聖的母性與女性的至高力量。她展開雙翼保護子民,是魔法、治療與無條件之愛的化身。她用魔法復活了丈夫奧西里斯,展現了愛的轉化奇蹟。她既是慈母也是強大的魔法師,溫柔中蘊含無限力量。","coreMeaning":"伊西斯代表神聖的女性能量、直覺智慧、深度療癒與滋養的力量。這是關於愛的轉化能力、同理心的魔法、以及通過關懷與連結來療癒自己和他人。伊西斯提醒我們,最強大的魔法不是控制,而是愛。她教導我們傾聽內在聲音,信任直覺,並且溫柔地對待生命中的每一個存在,包括自己。","coreEnergy":"接收性、直覺、療癒、同理心、魔法、母性之愛、智慧與保護。伊西斯的能量是深邃的、包容的、轉化的。她像月光一樣柔和但深具力量,能夠穿透最深的黑暗帶來療癒。這是一種能夠理解痛苦、轉化傷痛、並將愛帶入任何處境的能量。她的存在本身就是一種療癒。","guidance":"放慢腳步,傾聽你內心深處的聲音。你的直覺正試圖告訴你重要的訊息。現在是療癒舊傷、滋養自己靈魂的時刻。允許自己感受情緒,不要壓抑或逃避。同時,記得照顧好自己,你不能從空杯中倒出水。運用你天生的同理心去理解他人,但也要設立健康的界限。你擁有療癒的魔法,首先從療癒自己開始。","soulReminder":"愛是最強大的轉化力量,而你是愛的通道。你的同理心與關懷不是軟弱,而是最深的力量。記住,真正的力量是溫柔的,真正的魔法是愛的魔法。你不需要獨自承擔一切,允許自己接受他人的支持與關愛。宇宙通過你流動療癒的能量,你是神聖女性力量的體現。信任你的直覺,它永遠知道真相。","questions":"我的直覺告訴我什麼?我需要療癒生命中的哪些部分?我如何能更好地滋養自己?我是否設立了健康的界限?我允許自己接受愛與支持嗎?我的同理心如何服務我和他人?什麼傷痛需要被轉化?我如何連結神聖的女性能量?","energyFocus":"將注意力放在內在世界而非外在成就,感受而非思考,連結而非孤立。培養直覺的聲音,通過冥想、日記或安靜的獨處時光。實踐自我關懷與自我慈悲,每天給自己愛的時間。開放心扉接收愛與支持,療癒是雙向的流動。專注於建立深度連結而非表面關係,質量勝過數量。讓愛與同理心引導你的行動。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:3', 'egyptian_gods', '3', 2, '奧西里斯 - 冥界之主', 'Osiris - Lord of the Afterlife', NULL, '{"titleEn":"Osiris - Lord of the Afterlife","symbol":"⚱️ 手持權杖與連枷，綠色皮膚"}', '{"godStory":"奧西里斯手持權杖與連枷,身纏木乃伊布條,象徵死亡與重生的永恆循環。他的皮膚是綠色,代表植物的再生與生命的持續。他是被殺害後復活的神,守護著亡者的靈魂,審判他們的善惡。他代表生命的不朽本質與靈魂穿越黑暗的旅程。","coreMeaning":"奧西里斯代表深刻的轉變、必要的結束、死亡與重生的循環。這不一定是身體的死亡,更多是關於舊自我的死去、過時模式的崩解、以及從灰燼中重生的過程。奧西里斯教導我們,有些事物必須結束,新的生命才能開始。在這個神聖的空間中,我們放下不再服務我們的一切,準備迎接全新的自己。","coreEnergy":"轉化、重生、放手、深度改變、靈魂的永恆性、神聖的結束與開始。奧西里斯的能量是深邃的、嚴肅的、轉化性的。這是一種死亡與重生的能量,要求我們臣服於生命的自然循環。在黑暗中孕育新生,在結束中找到開始。這是深刻的靈魂工作,不是表面的改變,而是本質的蛻變。","guidance":"是時候放手了。無論是一段關係、一份工作、一個信念或一種生活方式,有些東西已經走到盡頭。不要抗拒這個自然的結束,它是重生的必要前奏。允許自己哀悼,給予自己時間處理失去的感受。在這個過渡期,你可能感到迷失,但這是正常的。你正在兩個世界之間,舊的已去,新的尚未完全成形。信任這個過程,黑暗不會永遠持續。","soulReminder":"你是不朽的靈魂,正在經歷暫時的轉變。死亡不是終點,而是通往新生命的門。你正在蛻變,雖然過程痛苦,但你會以更真實、更有力量的形式重生。宇宙要求你放下的,是為了給你更好的。信任生命的智慧,即使你現在看不清楚。你正在成為你注定要成為的人,這需要舊的你先死去。擁抱這個神聖的轉化。","questions":"我需要放下什麼?什麼已經走到盡頭卻還在執著?我害怕什麼樣的結束?重生對我意味著什麼?我準備好成為新的自己了嗎?什麼舊模式需要死去?我如何能臣服於轉變?我對死亡與重生的循環有什麼信念?","energyFocus":"專注於放手而非抓緊,臣服而非控制,接受而非抗拒。允許自己充分哀悼失去的事物,不要急於填補空缺。在空虛中安住,這是轉化發生的空間。進行象徵性的釋放儀式,寫下你要放下的事物然後燒掉或埋葬。關注生命中正在死去和正在誕生的部分。信任黑暗也是神聖的,在其中孕育著新生命。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:4', 'egyptian_gods', '4', 3, '托特 - 智慧之神', 'Thoth - God of Wisdom', NULL, '{"titleEn":"Thoth - God of Wisdom","symbol":"📜 鷺鷥頭，手持書寫板與筆"}', '{"godStory":"托特是鷺鷥頭的神祇,手持書寫板與筆,記錄著宇宙的所有知識。他是文字、魔法、科學與月亮的守護者。在創世時,他用話語創造世界,顯示了言語的神聖力量。他也是神祇的書記員與仲裁者,以公正與智慧聞名。他的眼睛能看穿一切表象,直達真理的核心。","coreMeaning":"托特代表智慧、知識、溝通、學習與神聖的言語力量。這是關於心智的開展、真理的追尋、以及通過知識獲得力量。托特提醒我們,言語具有創造實相的魔法,我們說的每一句話都在塑造我們的世界。他鼓勵深度學習、清晰溝通、以及謹慎使用言語的力量。智慧不僅來自書本,也來自觀察、傾聽與深度思考。","coreEnergy":"智力、清晰、真理、溝通、學習、書寫、言語的力量、月亮的智慧。托特的能量是清晰的、理性的、洞察的。這是一種穿透迷霧、看見真相、並用精確的言語表達的能量。他的能量幫助我們組織思想、獲取知識、並且有效地溝通。這也是魔法的能量,因為言語即咒語,知識即力量。","guidance":"現在是學習與擴展知識的時刻。深入研究你感興趣的主題,閱讀、學習、探索。同時,非常注意你的言語。你說的話具有創造力量,所以要說出你想要顯化的現實。避免負面自我對話、抱怨或無意識的言語。如果你在尋找答案,求助於書籍、老師或你的內在智慧。記錄你的想法、夢境與洞見,它們是寶貴的智慧來源。","soulReminder":"你擁有獲取無限智慧的能力,宇宙的知識向你敞開。你的言語是魔法的工具,可以創造或毀滅,所以要明智地使用。記住,真正的智慧不僅是知道很多事實,更是理解真理的本質。傾聽比說話更能帶來智慧。你的思想塑造你的現實,所以選擇賦能的想法。學習是永恆的旅程,保持學生的心態,永遠好奇、永遠開放。","questions":"我想要學習什麼?我的言語如何影響我的現實?我在說出賦能還是限制的話?我需要溝通什麼訊息?我如何能更清晰地表達?我的思想模式服務我嗎?我在尋找什麼智慧?我如何能更明智地使用言語的力量?","energyFocus":"將注意力放在心智的發展上,閱讀、學習、思考、分析。培養清晰的思維與精確的表達能力。有意識地選擇你的言語,練習正面肯定與賦能的自我對話。進行寫作練習,日記、筆記或創意寫作,讓思想通過文字清晰化。向老師學習,也向生活學習。將知識應用於實際,智慧在行動中顯現。記住,言語即咒語,謹慎施法。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:5', 'egyptian_gods', '5', 4, '阿努比斯 - 靈魂守護者', 'Anubis - Guardian of Souls', NULL, '{"titleEn":"Anubis - Guardian of Souls","symbol":"🐺 黑色胡狼頭，手持天秤"}', '{"godStory":"阿努比斯是黑色胡狼頭的神祇,守護墳墓與冥界的入口。他引導死者的靈魂穿越冥界,主持稱量心臟的儀式。他手持天秤,一邊是死者的心臟,另一邊是瑪特的真理之羽。只有心臟輕如羽毛的人才能進入永生。阿努比斯既是守護者也是引導者,在黑暗中為迷失的靈魂照亮道路。","coreMeaning":"阿努比斯代表保護、引導、過渡、誠實面對真相、以及穿越黑暗的勇氣。這是關於在人生的過渡期被守護、在迷失時被引導、以及誠實面對自己的內心真相。阿努比斯出現時,意味著你正處於兩個階段之間,舊的已經結束,新的尚未完全開始。在這個脆弱的時刻,你受到保護。","coreEnergy":"保護、引導、過渡、真相、誠實、守護、陪伴黑暗旅程。阿努比斯的能量是堅定的、保護性的、引導性的。他在我們最脆弱的時刻陪伴我們,在我們迷失時照亮道路。這是一種深沉的、可靠的、不會拋棄你的能量。同時,這也是要求誠實的能量,因為只有真實的心臟才能通過審判。","guidance":"信任你正被引導,即使看不清前路。你並不孤單,有神聖的力量在保護並指引你。現在是誠實面對自己的時刻,檢視你的動機、行為與內心真相。你是否活得真誠?你的行為是否與你的價值觀一致?像稱量心臟的儀式,問問自己內心是否輕盈、純淨。如果你正經歷失去或重大轉變,知道阿努比斯會守護你穿越這個過渡期。","soulReminder":"你永遠不會真正迷失,因為你內在攜帶著光。即使在最黑暗的夜晚,也有守護者陪伴你。你正在經歷的過渡是靈魂成長的必要部分,信任這個過程。真相會讓你自由,即使一開始可能讓你不舒服。活得真誠,讓你的心臟輕如羽毛,沒有謊言、背叛或虛偽的重量。當你誠實地面對自己,你就能無懼地面對任何審判。","questions":"我在哪個過渡階段?我需要什麼樣的指引?我對自己誠實嗎?我的心臟輕盈還是沉重?什麼真相我在逃避?我的行為反映我的價值觀嗎?我信任生命正在引導我嗎?我如何能在不確定中找到安全感?","energyFocus":"專注於誠實與真實性,檢視你生活的每一個領域。面對你一直逃避的真相,無論多麼不舒服。在過渡期允許自己感到脆弱,不要假裝堅強。尋求指引,無論是來自內在直覺、夢境、靈性導師或信任的朋友。進行自我反思,問問自己是否活得正直。信任即使在黑暗中,你也受到保護。讓真相成為你的指南針。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:6', 'egyptian_gods', '6', 5, '芭絲特 - 貓女神', 'Bastet - Cat Goddess', NULL, '{"titleEn":"Bastet - Cat Goddess","symbol":"🐱 貓頭女神，優雅曼妙身姿"}', '{"godStory":"芭絲特是優雅的貓頭女神,身姿曼妙,眼神神秘而充滿智慧。她原本是兇猛的獅子女神塞赫邁特,後來轉化為溫柔的家貓,象徵力量與溫柔的平衡。她手持象徵音樂與歡樂的樂器,守護著家庭、孩童與女性。她既是保護者又是享樂者,提醒我們生活需要歡樂與玩耍。","coreMeaning":"芭絲特代表喜悅、玩樂、優雅、獨立、家庭保護與女性力量。這是關於在生活中加入更多輕盈與快樂,平衡工作與玩樂,並且像貓一樣優雅地活著。芭絲特提醒我們,生活不只是責任與義務,也需要享受當下、放鬆玩耍。同時,她也教導我們像貓一樣設立界限,知道何時親近、何時保持距離,保護我們的能量與空間。","coreEnergy":"喜悅、玩樂、優雅、獨立、保護、女性力量、感官享受、音樂與舞蹈。芭絲特的能量是輕盈的、愉悅的、優雅的。這是一種知道如何享受生命、如何在嚴肅中找到歡笑、如何優雅地處理挑戰的能量。像貓一樣,這能量既溫柔又有力,既獨立又懂得愛,既放鬆又警覺。","guidance":"是時候輕鬆一下了。放下你的嚴肅與緊繃,做一些讓你感到快樂的事。跳舞、唱歌、玩遊戲、享受美食、聽音樂,或只是懶洋洋地休息。你太專注於責任,忘記了享受生命。同時,芭絲特提醒你保護自己的能量與空間。像貓一樣,知道何時需要獨處,何時願意親近。設立健康的界限,不是所有人都值得你的時間與能量。擁抱你的獨立性與優雅。","soulReminder":"你值得享受生命的快樂,歡笑不是罪惡,玩樂不是浪費時間。生命太短暫,不要等到「完成所有事情」才允許自己快樂,那一天永遠不會到來。你的女性能量(無論性別)是美麗而有力的,擁抱你的優雅、直覺與獨立。記住,真正的力量是柔軟的,真正的獨立是知道何時需要連結。像貓一樣活著,優雅、神秘、充滿歡樂。","questions":"我上次真正玩樂是什麼時候?什麼讓我感到快樂?我允許自己享受生活嗎?我的界限夠清晰嗎?我像貓一樣獨立嗎?我如何平衡工作與玩樂?我的生活中有足夠的歡笑嗎?我如何能更優雅地處理挑戰?","energyFocus":"將注意力放在帶來快樂的事物上,允許自己玩樂、放鬆、享受。加入更多音樂、舞蹈、藝術到日常生活中。培養優雅的舉止與從容的態度,不要匆忙或緊張。像貓一樣伸展、放鬆、享受感官體驗。保護你的空間與能量,設立清晰的界限。擁抱你的獨立性,不需要依賴他人的認可。讓歡笑與輕盈重新進入你的生命。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:7', 'egyptian_gods', '7', 6, '荷魯斯 - 天空之神', 'Horus - Sky God', NULL, '{"titleEn":"Horus - Sky God","symbol":"🦅 鷹頭神祇，雙眼為日月"}', '{"godStory":"荷魯斯是鷹頭神祇,雙眼分別是太陽與月亮,能看見白天與黑夜的真相。他展開巨大的翅膀翱翔於天空,俯瞰大地。他為父親奧西里斯復仇,與邪惡的叔叔賽特戰鬥,最終勝利成為埃及的合法統治者。他的眼睛被稱為「荷魯斯之眼」,是保護與王權的強大符號,能看穿一切幻象與謊言。","coreMeaning":"荷魯斯代表遠見、清晰洞察、領導力、正義、勝利與保護。這是關於從更高的視角看待問題,不被地面的細節困擾。荷魯斯教導我們,當我們站得夠高,就能看見全局。他鼓勵我們發揮領導潛能,為真理與正義而戰,保護我們珍視的一切。勝利屬於那些堅持正道、不被挑戰擊倒的人。","coreEnergy":"視野、洞察力、領導、正義、勇氣、保護、戰士精神、勝利。荷魯斯的能量是高遠的、清晰的、勇敢的。這是一種翱翔於困難之上、看見他人看不見的真相、並且勇敢地為正義而戰的能量。像鷹一樣,這能量既有敏銳的觀察力,也有迅速果斷的行動力。這是領導者與戰士的能量。","guidance":"站在更高的視角審視你的處境。不要陷入細節的泥沼,退一步看見全局。你擁有比你意識到的更清晰的洞察力,信任你的觀察與判斷。現在是發揮領導力的時刻,無論在工作、家庭還是個人生活中。為你相信的真理與正義挺身而出,不要因為挑戰而退縮。你比你想像的更有力量。保護你所愛的人與事物,同時也保護你的夢想與目標。","soulReminder":"你擁有鷹的視野與力量,能夠看見他人看不見的真相。不要質疑你的洞察力,你的眼睛沒有被欺騙。你是天生的領導者,即使你不總是站在最前面。真正的領導不是控制,而是服務與保護。為正義而戰不是選項,而是責任。記住,勝利不是一蹴而就,荷魯斯也經歷了漫長的戰鬥。堅持下去,真理終將勝利。你受到保護,你的視野是清晰的。","questions":"我從哪個角度看待問題?我看見全局了嗎?我的領導潛能在哪裡?我為什麼價值而戰?我在保護什麼?我的洞察力告訴我什麼?我準備好站出來了嗎?我如何能更勇敢地捍衛真理?","energyFocus":"將注意力提升到更高的層次,不要被地面的混亂困擾。培養鳥瞰全局的能力,看見事物之間的連結與模式。發展你的領導技能,即使只是領導自己的生命。為你的價值觀挺身而出,練習勇敢。保護你的夢想與目標免受懷疑與批評。磨練你的觀察力,看穿表象。像鷹一樣翱翔,既自由又專注。勝利需要策略與堅持。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:8', 'egyptian_gods', '8', 7, '哈索爾 - 愛之女神', 'Hathor - Goddess of Love', NULL, '{"titleEn":"Hathor - Goddess of Love","symbol":"🐄 母牛女神，頭頂日盤與牛角"}', '{"godStory":"哈索爾是母牛女神,頭頂太陽圓盤與牛角,象徵滋養與豐饒。她是天空女神,星辰在她的身體上閃耀。她手持象徵音樂的樂器,舞蹈歡慶生命。她的神廟充滿音樂、舞蹈、愛與歡樂。她既是母親也是情人,既滋養也被愛慕。她代表生命中一切美好的事物,提醒我們生命值得被慶祝。","coreMeaning":"哈索爾代表愛、美、歡樂、豐盛、慶祝、音樂、藝術與生命的美好。這是關於打開心扉接收愛,欣賞生活中的美,慶祝每一個值得慶祝的時刻。哈索爾教導我們,愛是宇宙最強大的力量,而我們都值得被愛與愛人。她鼓勵我們擁抱生命的豐盛,不只是物質上的,更是情感、美與喜悅的豐盛。","coreEnergy":"愛、美、歡樂、豐盛、慶祝、滋養、音樂、藝術、感官享受、開放的心。哈索爾的能量是溫暖的、豐富的、歡愉的。這是一種擁抱生命、打開心扉、慷慨給予與接收的能量。像母牛的奶滋養孩子,哈索爾的能量滋養我們的靈魂。這是豐盛的、不匱乏的、慶祝性的能量。","guidance":"打開你的心去接收愛與美好。放下防衛,允許愛進入你的生命,無論是浪漫的愛、友誼、家人的愛或自愛。慶祝生命中的每一個美好時刻,無論多麼微小。聆聽音樂、創作藝術、享受美食或大自然的美景。哈索爾提醒你,你值得擁有愛與快樂。如果你感到匱乏,那是因為你關閉了心門。豐盛來自於感恩與開放。分享你的喜悅與愛,它們會加倍回到你身上。","soulReminder":"你是值得被愛的,無條件地、深刻地、完整地被愛。你不需要做任何事來證明你的價值,你的存在本身就是值得慶祝的。生命是一場盛宴,不要只吃麵包屑。宇宙是豐盛的,有足夠的愛、美與歡樂給每一個人。當你打開心扉,你會發現愛無處不在。你給予的愛永遠不會減少你擁有的,相反地,它會繁殖增長。讓哈索爾的歡樂充滿你的心。","questions":"我的心是開放還是封閉的?我允許自己接收愛嗎?我上次慶祝是什麼時候?我欣賞生活中的美嗎?我感到豐盛還是匱乏?我如何能更多地分享愛?什麼阻止我接收美好?我如何能讓生命成為慶典?","energyFocus":"將注意力放在愛與美上,尋找生活中值得欣賞的事物。打開心扉,允許自己脆弱地去愛與被愛。加入更多音樂、藝術、美的事物到日常中。慶祝小勝利、小喜悅、小美好。培養感恩的心,每天寫下你感激的事物。慷慨地給予愛、讚美、肯定。享受感官體驗,不要壓抑喜悅。讓愛引導你的選擇,從愛的地方行動。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:9', 'egyptian_gods', '9', 8, '塞赫邁特 - 戰士女神', 'Sekhmet - Warrior Goddess', NULL, '{"titleEn":"Sekhmet - Warrior Goddess","symbol":"🦁 母獅女神，眼中燃燒火焰"}', '{"godStory":"塞赫邁特是兇猛的母獅女神,眼中燃燒著火焰,代表毀滅性的力量。她是拉神的眼睛,被派去懲罰背叛的人類。她的怒火如此強大,幾乎毀滅了整個人類。但她也是偉大的療癒者,因為真正的療癒需要勇氣面對痛苦。她手持蓮花,象徵破壞後的新生。她的火焰既能毀滅也能淨化。","coreMeaning":"塞赫邁特代表力量、勇氣、神聖的憤怒、界限、療癒的火焰與轉化的力量。這是關於召喚內在的戰士,為自己挺身而出,說不,並且勇敢地面對需要面對的事。塞赫邁特教導我們,溫柔與力量並不矛盾,真正的療癒有時需要火焰的淨化。她的憤怒不是破壞性的,而是界限的設立與正義的執行。","coreEnergy":"力量、勇氣、憤怒、界限、保護、療癒、火焰、轉化、戰士精神、神聖的破壞。塞赫邁特的能量是強大的、兇猛的、不容侵犯的。這是一種說「到此為止」的能量,一種保護與捍衛的能量。像火焰,這能量既能燒毀舊有的,也能淨化與轉化。這是戰士與療癒者的雙重能量。","guidance":"召喚你內在的力量與勇氣。是時候為自己挺身而出,設立清晰的界限,說出你的真理。不要再讓任何人踩踏你的尊嚴或價值。如果有困難的對話需要進行,現在就是時候。塞赫邁特的火焰會保護你、賦予你力量。同時,她邀請你療癒憤怒與痛苦,不是壓抑,而是健康地表達與釋放。真正的力量來自整合陰影,擁抱你的憤怒,理解它要告訴你什麼。","soulReminder":"你比你想像的更強大,你擁有獅子的力量。你不需要永遠溫柔、總是妥協、持續退讓。憤怒不是罪惡,它是界限被侵犯的信號。你有權利保護自己,有權利說不,有權利要求尊重。真正的療癒不是假裝一切都好,而是勇敢地面對痛苦、處理創傷。塞赫邁特的火焰會燒毀不再服務你的一切,但也會照亮你的道路。你是戰士,也是療癒者。","questions":"我需要在哪裡更堅定?我的界限夠清晰嗎?我壓抑憤怒嗎?我為什麼而戰?我的力量在哪裡?我允許自己強大嗎?什麼需要被火焰淨化?我如何平衡力量與溫柔?","energyFocus":"將注意力放在你的力量上,而非你的軟弱。練習說不,設立界限,即使會讓別人不舒服。允許自己感受憤怒,然後健康地釋放它,可能通過運動、吼叫、打枕頭。面對你一直逃避的困難處境或對話。培養你的戰士精神,不是為了攻擊,而是為了保護。進行火焰淨化儀式,象徵性地燒毀舊有的。擁抱你的力量,它是神聖的。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:10', 'egyptian_gods', '10', 9, '普塔 - 造物主', 'Ptah - Creator God', NULL, '{"titleEn":"Ptah - Creator God","symbol":"🔨 手持權杖，身體緊裹"}', '{"godStory":"普塔是古老的造物神,手持權杖,身體緊裹,只有手伸出。他通過思想與話語創造世界,先在心中構思,然後用話語顯化。他是工匠、建築師、藝術家的守護神,孟菲斯的主神。他代表從無形到有形的顯化過程,從想法到實相的建造。他的神廟是所有創造與工藝的中心。","coreMeaning":"普塔代表顯化、創造、建造、工藝、思想的力量與話語的魔法。這是關於將夢想化為現實,通過思想、話語與行動建造你想要的生命。普塔教導我們,我們都是自己生命的建築師,我們的思想是藍圖,我們的話語是工具,我們的行動是建材。創造始於心中清晰的願景,然後通過專注與技巧顯化為實相。","coreEnergy":"顯化、創造、建造、工藝、思想的力量、話語的魔法、實踐的智慧、耐心。普塔的能量是穩定的、專注的、建設性的。這是一種知道如何將無形的想法轉化為有形的成果的能量。這需要清晰的願景、精確的計劃、熟練的技巧與持續的努力。這是工匠的能量,重視質量、細節與lasting的價值。","guidance":"你有能力顯化你的夢想。首先,澄清你真正想要創造什麼,花時間在心中構建清晰的願景。然後,將這個願景轉化為具體的計劃與行動步驟。你的思想比你想像的更有力量,所以要謹慎選擇你的想法與話語。避免負面自我對話或限制性信念,相反地,肯定你的能力與價值。普塔鼓勵你使用雙手創造,無論是寫作、繪畫、建造或任何形式的工藝。通過行動,將夢想帶入現實。","soulReminder":"你是你生命的建築師,你擁有創造的神聖力量。你的思想、話語與行動都在塑造你的現實。不要低估你的創造潛能,你能夠建造lasting的、有價值的事物。記住,偉大的創造需要時間,金字塔不是一天建成的。保持耐心與專注,一步步建造你的夢想。你的言語是創造的工具,說出你想要顯化的現實。從心開始,用手完成。","questions":"我想要創造什麼?我的願景夠清晰嗎?我的思想支持我的目標嗎?我的話語是賦能還是限制的?我準備好採取行動了嗎?我有什麼技能與工具?我如何能更專注於顯化?我的創造留下什麼遺產?","energyFocus":"將注意力放在清晰的願景上,花時間詳細構建你想要創造的現實。練習正面肯定與賦能的自我對話,你的言語在創造你的實相。制定具體的計劃與行動步驟,將夢想分解為可管理的任務。使用你的雙手創造,實際的工藝能幫助你理解顯化的過程。保持專注與一致,每天為你的願景投入時間與能量。信任過程,持續建造。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:11', 'egyptian_gods', '11', 10, '瑪特 - 真理女神', 'Ma''at - Goddess of Truth', NULL, '{"titleEn":"Ma''at - Goddess of Truth","symbol":"🪶 頭戴鴕鳥羽毛，手持權杖"}', '{"godStory":"瑪特頭戴象徵真理的鴕鳥羽毛,手持權杖與安卡生命之鑰。她代表宇宙的秩序、平衡與和諧。在死後審判中,她的羽毛用來稱量死者的心臟,只有心臟輕如羽毛者才能進入來世。瑪特不僅是女神,更是宇宙運行的法則本身,代表真理、正義與道德的完整性。","coreMeaning":"瑪特代表真理、正義、平衡、誠實與宇宙秩序。這是關於活在真理中,保持生活的平衡,以及遵循道德與良知。瑪特教導我們,宇宙有其自然法則,當我們違背真理時就會失去平衡。她鼓勵我們誠實地面對自己與他人,在所有關係與處境中尋求公正與和諧。真理是通往自由的道路,謊言只會增加心靈的重量。","coreEnergy":"真理、正義、平衡、和諧、誠實、道德完整性、宇宙秩序、公正。瑪特的能量是穩定的、公正的、平衡的。這是一種不偏不倚、追求真相、維護正義的能量。像羽毛一樣,真理是輕盈的,謊言則沉重。這能量幫助我們在混亂中找到秩序,在失衡中恢復和諧,在虛假中堅守真實。","guidance":"誠實地面對自己和他人。檢視你的生活:你是否活得真誠?你的行為是否反映你的價值觀?是否有需要說出的真相?現在是恢復誠信與道德勇氣的時刻。如果你隱藏了真相或對自己不誠實,這會造成內在的不平衡。同時,瑪特提醒你尋求生活各個層面的平衡:工作與休息、給予與接受、物質與精神。在人際關係與處境中尋求公正與公平。","soulReminder":"你的心臟應該像羽毛一樣輕盈,沒有謊言、背叛或虛偽的重量。真理會讓你自由,即使一開始可能讓你不舒服。宇宙的正義最終會實現,所有行為都有後果。活得正直、平衡、真誠,這是通往內心和平的唯一道路。記住,你無法欺騙宇宙,你只能欺騙自己。當你活在真理中,生命會流動得更加順暢。","questions":"我對自己誠實嗎?我的生活平衡嗎?哪些領域失衡?我的行為反映我的價值觀嗎?我需要說出什麼真相?我在逃避什麼?我如何能更公正地對待自己和他人?什麼讓我的心臟沉重?","energyFocus":"專注於真實性,在所有互動中實踐誠實。檢視生活的每個領域,找出失衡的地方並做出調整。培養道德勇氣,即使真相不受歡迎也要說出來。在決策中尋求公正與公平,考慮所有相關方的需求。練習自我反省,確保你的行為與信念一致。恢復內在與外在的和諧,讓真理成為你的指南針。活在瑪特的法則中,你會找到持久的平靜。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:12', 'egyptian_gods', '12', 11, '奈芙蒂斯 - 黑暗母親', 'Nephthys - Dark Mother', NULL, '{"titleEn":"Nephthys - Dark Mother","symbol":"🌙 頭戴房屋符號，展開保護雙翼"}', '{"godStory":"奈芙蒂斯頭戴象徵房屋與神廟的符號,是伊西斯的姊妹,守護夜晚與隱藏的領域。她常被描繪為展開翅膀保護亡者的女神,陪伴靈魂穿越黑暗的旅程。她代表不被看見的、隱藏的、陰影中的智慧。她是哀悼者與守夜者,在最黑暗的時刻陪伴我們。","coreMeaning":"奈芙蒂斯代表陰影工作、隱藏的智慧、被壓抑的情感、黑暗中的轉化與內在的深度探索。這是關於面對我們不願承認的自我部分,整合陰影,並在黑暗中找到智慧。奈芙蒂斯教導我們,光明與黑暗同等重要,黑暗不是邪惡,而是孕育轉化的神聖空間。她鼓勵我們勇敢地探索內在的深處,找回遺失的自我碎片。","coreEnergy":"陰影、隱藏的智慧、深度、黑暗中的保護、被壓抑的情感、內在探索、哀悼、神秘。奈芙蒂斯的能量是深邃的、神秘的、轉化的。這是一種在黑暗中運作的能量,不逃避陰影,而是擁抱它。這能量幫助我們面對恐懼、處理被壓抑的情感、並在不被看見的時刻進行深度療癒。","guidance":"不要害怕探索你的陰影面。那些你逃避、否認或壓抑的部分,正是你需要整合的部分。在黑暗中蘊藏著深刻的智慧和力量。現在是進行陰影工作的時刻,誠實地面對你的恐懼、憤怒、嫉妒或其他「負面」情感。這些情感不是敵人,而是需要被理解與整合的部分。有時候我們需要退入黑暗,進行內在的休息與重整。不是所有的成長都發生在光明中。","soulReminder":"你的陰影包含著你遺失的力量。不要逃避黑暗,它是轉化的搖籃。那些你最不願面對的部分,往往蘊含著你最需要的智慧。整合陰影不是成為黑暗,而是成為完整。記住,月亮的陰暗面仍然是月亮。當你擁抱全部的自己,包括光明與黑暗,你將變得真正強大。在黑暗中,你會找到你一直在尋找的東西。","questions":"我在逃避什麼?我的陰影面是什麼?我壓抑了哪些情感?什麼讓我感到羞愧?我否認自己的哪些部分?黑暗中有什麼智慧?我準備好整合陰影了嗎?我如何在不被看見時成長?","energyFocus":"將注意力轉向內在的深處,探索你通常避免的領域。進行陰影工作練習,寫日記、做夢境分析或與治療師合作。允許被壓抑的情感浮現,不要評判它們。在黑暗中尋找智慧,知道不是所有有價值的東西都在光明中。給自己獨處與內省的時間,在寂靜中傾聽內在的聲音。擁抱你的完整性,包括你認為「不好」的部分。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:13', 'egyptian_gods', '13', 12, '賽特 - 混沌之神', 'Set - God of Chaos', NULL, '{"titleEn":"Set - God of Chaos","symbol":"🌪️ 奇特動物頭，長耳彎鼻"}', '{"godStory":"賽特有著奇特的動物頭顱,長方形的耳朵與彎曲的鼻子,代表未知與野性。他是沙漠、風暴與混亂的主宰,力量強大但不可預測。他殺害了兄弟奧西里斯,代表破壞性的力量,但也是必要的變革催化劑。他象徵著生命中不可馴服的野性能量,挑戰既定秩序的力量。","coreMeaning":"賽特代表混亂、破壞、野性、變革、突破限制與不可預測的力量。這是關於打破僵化的結構,釋放被壓抑的野性,以及擁抱生命中的不確定性。賽特教導我們,有時候必須摧毀舊有的一切,才能建立更強大的新秩序。他不是純粹的邪惡,而是必要的破壞者,為創新與成長清出空間。","coreEnergy":"混亂、破壞、野性、力量、變革、突破、不可預測、原始能量、反叛。賽特的能量是狂野的、不受控的、破壞性的。這是一種打破規則、挑戰權威、釋放原始力量的能量。像風暴,這能量既可怕又必要,它清理停滯、打破僵局、強迫改變。這是生命中野性、不可馴服的一面。","guidance":"擁抱變化與不確定性。如果你的生活感到一成不變或停滯不前,賽特的能量會帶來必要的震撼。不要抗拒這些看似混亂的變化,它們可能正是你需要的突破。有時候,我們需要失去控制,才能找到真正的自由。賽特也鼓勵你釋放內在的野性與原始力量。不要總是做個「乖孩子」,有時候需要反抗、挑戰、打破規則。擁抱你內在不受約束的一面。","soulReminder":"你內在有一股野性的力量,不需要總是被馴服或壓抑。混亂不一定是壞事,它可能是突破的前兆。有時候,最大的成長來自最大的動盪。不要害怕打破不再服務你的結構,即使它們曾經很重要。你擁有破壞與重建的力量,使用它來創造真正的自由。記住,風暴過後,空氣最清新。擁抱你的野性,它是生命力的來源。","questions":"什麼結構需要被打破?我在哪裡太過僵化?我壓抑了多少野性?我害怕混亂嗎?什麼需要被破壞才能重生?我允許自己反叛嗎?我如何能擁抱不確定性?我的原始力量在哪裡?","energyFocus":"允許混亂進入你過度控制的生活領域。打破僵化的規則與模式,嘗試全新的方法。釋放你的野性與原始能量,通過運動、吼叫、瘋狂舞蹈。不要害怕動盪,它可能帶來必要的突破。挑戰權威與既定規則,問為什麼。擁抱不可預測性,放棄控制的需要。在破壞中找到創造,在混亂中找到自由。讓賽特的能量清理停滯。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:14', 'egyptian_gods', '14', 13, '努特 - 天空女神', 'Nut - Sky Goddess', NULL, '{"titleEn":"Nut - Sky Goddess","symbol":"✨ 身體拱起為天穹，佈滿星辰"}', '{"godStory":"努特的身體拱起形成天穹,手腳支撐著天地兩端,身體佈滿星辰。她每天吞下太陽,在體內孕育,黎明時重新誕生。她是天空的化身,無限廣闊,包容一切。她的身體是星辰運行的軌道,代表無限的可能性與循環更新的希望。她是所有生命的天幕,守護著地面上的一切。","coreMeaning":"努特代表無限的可能性、保護、循環更新、廣闊的視野、希望與母性的包容。這是關於超越限制,夢想更大的可能性,並且相信無論多麼黑暗,新的一天總會到來。努特教導我們,天空是無限的,我們的潛能也是。她鼓勵我們抬頭仰望,不要被地面的限制所困,擁抱更宏大的願景與夢想。","coreEnergy":"無限、可能性、保護、循環、更新、包容、廣闊、希望、母性、自由。努特的能量是廣闊的、包容的、無限的。這是一種超越界限、擁抱無限可能、並且在黑暗後總能重生的能量。像天空包容一切,這能量提供安全感與自由,讓我們知道無論發生什麼,我們都被守護著。","guidance":"擴展你的視野與夢想。你是否因為恐懼或過去的經驗而縮小了自己的夢想?現在是時候重新擁抱更宏大的願景。努特提醒你,天空是無限的,你的潛能也是。不要自我設限,允許自己夢想不可能的事。同時,感受努特的保護能量。即使你感到脆弱或暴露,知道有更高的力量在守護著你。像她吞下並重生太陽,你也能經歷黑暗後重新開始。","soulReminder":"你的潛能如天空般無限,不要讓任何人告訴你什麼是不可能的。黑暗只是暫時的,新的黎明總會到來。你被宇宙的愛所包圍與保護,像天空包覆大地。記住,即使太陽被吞噬,它依然會重生。你也擁有同樣的循環更新能力。不要害怕夢想遠大,你生來就是為了翱翔,而非爬行。抬起頭,看見無限的可能性。","questions":"我的夢想夠大嗎?我在哪裡限制自己?我相信無限的可能性嗎?我感受到宇宙的保護嗎?我允許自己自由翱翔嗎?什麼阻止我擴展視野?我準備好更新與重生了嗎?我如何能活得更廣闊?","energyFocus":"將視野擴展到地平線之外,超越眼前的限制。重新夢想你的生命,不要自我審查或縮小。仰望天空,感受無限與廣闊,讓這種能量充滿你。相信循環更新的力量,知道每一個結束都會迎來新的開始。感受被保護與支持,你不是孤獨地面對世界。釋放限制性信念,擁抱無限可能。像天空一樣廣闊地生活,包容一切,自由無限。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:15', 'egyptian_gods', '15', 14, '蓋布 - 大地之神', 'Geb - Earth God', NULL, '{"titleEn":"Geb - Earth God","symbol":"🌍 躺臥地面，身體為大地起伏"}', '{"godStory":"蓋布躺臥在地面,身體形成大地的起伏,皮膚是綠色象徵植物的生長。他是所有生命的基礎,提供穩定的支撐。他與天空女神努特相對,兩者之間的空間是生命存在的領域。他代表物質世界、實際的基礎、以及腳踏實地的力量。大地孕育萬物,承載一切。","coreMeaning":"蓋布代表穩定、根基、物質世界、實際性、扎根、豐饒與安全感。這是關於建立穩固的基礎,處理生活的實際面向,以及與物質世界建立健康的關係。蓋布教導我們,沒有深厚的根基,再高的夢想也無法實現。他鼓勵我們關注財務、健康、家庭等基礎事務,將靈性實踐落實在日常生活中。","coreEnergy":"穩定、根基、實際、物質、扎根、豐饒、支持、安全、大地能量、耐心。蓋布的能量是穩固的、可靠的、支持性的。這是一種深深扎根、不會輕易動搖、提供堅實基礎的能量。像大地承載一切,這能量給予我們安全感與穩定性。這是實際的、可觸摸的、真實的能量。","guidance":"回到基礎,重建你的根基。關注生活中的實際問題:財務狀況、身體健康、生活環境。這些基礎事務需要你的注意。不要總是追逐天空中的夢想而忽略腳下的土地。同時,與大地連結。多接觸自然,赤腳踩在土地上,感受地球的能量。這會幫助你扎根、穩定情緒、恢復平衡。如果你感到飄浮不定或焦慮,蓋布的能量會幫助你找回重心。","soulReminder":"你需要穩固的根基才能自由成長。就像樹木,根扎得越深,枝葉才能伸展得越高。不要忽視生活的實際面向,它們是你靈性成長的基礎。大地不會背叛你,它永遠在那裡支持你。記住,靈性不是逃離物質世界,而是在物質世界中體現神聖。當你深深扎根,你會發現真正的自由。照顧好你的身體與實際需求,它們是靈魂的居所。","questions":"我的生活基礎穩固嗎?我的財務狀況如何?我照顧好身體了嗎?我與大地連結嗎?什麼實際問題需要處理?我是否太過飄渺?我如何能更扎根?我的根在哪裡?","energyFocus":"將注意力放在實際的、可觸摸的事物上。處理財務、健康、居住環境等基礎事務。多接觸大地,赤腳走路、園藝、接觸泥土。進行扎根練習,想像根從腳底延伸進入大地深處。關注你的身體感受,吃滋養的食物,充足睡眠。建立穩定的日常routine。在物質世界中體現你的靈性。讓大地的穩定能量支持你的成長。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:16', 'egyptian_gods', '16', 15, '索貝克 - 鱷魚之神', 'Sobek - Crocodile God', NULL, '{"titleEn":"Sobek - Crocodile God","symbol":"🐊 鱷魚頭神，銳利牙齒眼神警覺"}', '{"godStory":"索貝克是鱷魚頭的神祇,強壯有力,牙齒銳利,眼神警覺。他守護尼羅河,既是兇猛的掠食者也是強大的保護者。鱷魚在水中潛伏,隨時準備行動,代表本能的警覺與原始的生存智慧。他象徵著界限、領域保護、以及在危險中保持警覺的能力。他的力量既可怕又必要。","coreMeaning":"索貝克代表界限、保護、本能、警覺、生存智慧、領域意識與原始力量。這是關於設立清晰的界限,保護你的空間與能量,並且信任你的本能反應。索貝克教導我們,有時候需要展現牙齒,讓他人知道你的界限。他鼓勵我們傾聽原始的直覺,那些在理性之前的警覺信號。","coreEnergy":"保護、界限、本能、警覺、原始智慧、領域、力量、生存、野性。索貝克的能量是警覺的、保護性的、本能的。這是一種隨時準備保護自己領域的能量,不會讓任何威脅輕易接近。像鱷魚在水中警覺,這能量幫助我們感知危險、快速反應、並且毫不猶豫地保護自己。這是生存的智慧。","guidance":"保護你的界限與領域。是否有人越界了?是否有人利用你的善良?現在是設立清晰界限的時刻。不要害怕說不,不要害怕保護自己的空間、時間與能量。同時,信任你的本能。如果某事或某人讓你感到不安,即使理性上無法解釋,也要相信這種直覺。索貝克的本能能夠察覺危險。你不需要解釋或道歉,你的界限就是你的主權。","soulReminder":"你有權利保護自己的領域,你的界限是神聖的。不要因為害怕被視為「不友善」而允許他人踐踏你的空間。真正的關係會尊重界限。你的本能是千萬年演化的智慧,不要用理性壓制它。當某事感覺不對,它通常就是不對。像鱷魚一樣警覺但不偏執,保護但不攻擊。你的力量在於知道何時展現牙齒。記住,設立界限是自愛的表現。","questions":"我的界限夠清晰嗎?誰在越界?我信任我的本能嗎?我保護我的能量嗎?什麼讓我感到不安?我是否太過開放?我如何能更警覺?我的領域在哪裡?","energyFocus":"專注於設立與維護清晰的界限。練習說不,即使會讓別人失望。傾聽你的本能警覺,不要用理性解釋掉不適的感受。保護你的時間、空間、能量,不要讓他人隨意進入。觀察誰讓你感到消耗,考慮增加距離。培養警覺但不恐懼的狀態。像鱷魚一樣,知道何時潛伏、何時行動。你的界限就是你的力量。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:17', 'egyptian_gods', '17', 16, '庫努姆 - 造物陶匠', 'Khnum - Creator Potter', NULL, '{"titleEn":"Khnum - Creator Potter","symbol":"🐏 羊頭神，坐陶輪前雕塑"}', '{"godStory":"庫努姆是羊頭神,坐在陶輪前,用雙手塑造人類的身體與靈魂。他是古老的創造神,每一個生命都經過他精心的雕塑。陶輪象徵創造的過程,需要時間、耐心與技巧。泥土在他手中被賦予形式與生命,代表從原始材料到完整存在的轉化。他的創造是緩慢而細緻的藝術。","coreMeaning":"庫努姆代表耐心的創造、精心的塑造、工藝、時間的必要性、細節的重要性與尊重過程。這是關於理解真正的創造需要時間,不能急於求成。庫努姆教導我們,每個生命都是獨特的藝術品,經過精心設計與塑造。他鼓勵我們耐心地培養我們的創作,一層層添加、修整、打磨,直到完美呈現。","coreEnergy":"耐心、工藝、創造、塑造、細節、時間、技巧、精確、過程、藝術。庫努姆的能量是耐心的、專注的、細緻的。這是一種理解偉大創造需要時間的能量,不會因為緩慢而焦慮。像陶匠塑造陶器,這能量專注於每一個細節、每一個步驟,知道完美需要時間與耐心的投入。","guidance":"耐心地塑造你的創作。不要因為看不到立即的結果就放棄。就像陶匠塑造陶器,需要一層層添加、修整、打磨,你的項目或目標也需要這樣的過程。專注於工藝,享受創造的過程本身,而不只是結果。同時,庫努姆邀請你重新塑造自己。你不滿意生命的哪些部分?現在是重新設計與創造的時刻。記住,你是自己生命的陶匠。","soulReminder":"你的生命是一件正在被塑造的藝術品,需要時間、耐心與細心的雕琢。不要與他人比較,每個人的創造時間表不同。偉大的作品需要時間,金字塔不是一天建成的,傑作也不是一蹴而就的。享受塑造的過程,每一個步驟都有其價值。你擁有重新塑造自己的力量,無論多少次,你都可以重新開始。用雙手創造,用時間完善,用愛灌注。","questions":"我在創造什麼?我夠耐心嗎?我尊重過程嗎?我專注於細節嗎?我想重新塑造什麼?我是否太過急躁?我如何能更享受創造的過程?我的工藝是什麼?","energyFocus":"將注意力放在過程而非結果,享受創造的每一步。培養耐心,理解偉大的事物需要時間。專注於細節與工藝,不要匆忙或草率。使用雙手創造實體的東西,陶藝、雕塑、編織、烹飪。重新塑造你生命中不滿意的部分,一點一點地改變。尊重時間的必要性,不要強迫快速的結果。像陶匠一樣,愛你正在塑造的一切。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:18', 'egyptian_gods', '18', 17, '泰芙努特 - 濕氣女神', 'Tefnut - Goddess of Moisture', NULL, '{"titleEn":"Tefnut - Goddess of Moisture","symbol":"💧 母獅頭女神，掌管濕氣露水"}', '{"godStory":"泰芙努特是母獅頭女神,掌管濕氣、露水與生命所需的水分。她是拉神的女兒,在乾燥的沙漠中帶來滋潤與生命。她代表情感的流動、眼淚的療癒、以及水分對生命的必要性。沒有水分,生命無法存在;沒有情感的流動,靈魂會枯竭。她的濕潤能量滋養乾涸的心靈。","coreMeaning":"泰芙努特代表情感流動、情緒健康、眼淚的療癒、滋潤、柔軟、允許感受與情感的表達。這是關於允許情感自然流動,不壓抑或囤積。泰芙努特教導我們,眼淚不是軟弱,而是清洗靈魂的神聖儀式。她鼓勵我們滋潤生活中乾涸的部分,為僵化的領域帶入流動與柔軟。情感就像水,需要流動才能保持清新。","coreEnergy":"流動、情感、滋潤、柔軟、眼淚、療癒、釋放、水元素、滋養、濕潤。泰芙努特的能量是流動的、滋潤的、柔軟的。這是一種允許情感自由流動、不壓抑不囤積的能量。像雨水滋潤乾涸的土地,這能量為僵硬的心靈帶來柔軟與療癒。這是情感健康的能量,理解哭泣是釋放,流動是生命。","guidance":"允許你的情感自然流動。如果你想哭,就哭吧。如果你感到悲傷、憤怒或任何情緒,找到健康的方式表達與釋放。不要再把情感鎖在心裡,讓它們流動、釋放、清理。就像雨水滋潤大地,眼淚也能滋養靈魂。同時,滋潤生活中乾涸的部分。哪些領域感覺乾燥、僵化或缺乏生命力?帶入更多流動、柔軟與滋養。多喝水,多接觸水元素。","soulReminder":"你的眼淚是神聖的,它們清洗靈魂、釋放痛苦、帶來療癒。不要為哭泣感到羞愧,這是人類最自然的療癒方式。情感不是敵人,壓抑才是。當你允許情感流動,你會發現它們不會淹沒你,反而會流過你然後離開。像水一樣,情感尋求流動。給予它們出口,它們會帶走毒素,留下清新。你的柔軟是力量,你的眼淚是勇氣。滋潤你的靈魂,讓生命重新流動。","questions":"我壓抑情感嗎?我允許自己哭泣嗎?我的情緒健康嗎?生活哪些部分感到乾涸?我需要釋放什麼情感?我與水元素連結嗎?我夠柔軟嗎?我如何能更流動?","energyFocus":"專注於情感的健康流動,不壓抑也不沉溺。允許眼淚在需要時流下,不要評判或阻止。進行情感釋放練習,通過日記、藝術或身體運動。多接觸水,洗澡、游泳、聽流水聲。滋潤身體,喝足夠的水。為生活帶入更多流動與柔軟,打破僵化的模式。像水一樣適應、流動、滋養。情感的流動是生命的流動。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:19', 'egyptian_gods', '19', 18, '舒 - 風神', 'Shu - God of Air', NULL, '{"titleEn":"Shu - God of Air","symbol":"💨 手持天空，創造呼吸空間"}', '{"godStory":"舒是空氣之神,他將天空努特與大地蓋布分開,創造了生命存在的空間。他手持著天空,為萬物創造呼吸的空間。他代表空氣、呼吸、間距與自由。沒有舒的分離,天地會緊壓在一起,生命無法存在。他象徵著適當距離的必要性,以及空間對成長的重要性。","coreMeaning":"舒代表空間、呼吸、距離、清晰、分離、自由、空氣元素與流通。這是關於創造必要的空間,讓事物能夠自由存在與成長。舒教導我們,適當的距離是健康的,不是疏遠或冷漠,而是允許彼此呼吸與成長的智慧。他鼓勵我們在窒息的關係或處境中創造空間,讓新鮮空氣流通,帶來清晰與自由。","coreEnergy":"空間、呼吸、分離、清晰、自由、空氣、流通、距離、輕盈、開放。舒的能量是輕盈的、流通的、自由的。這是一種創造空間、允許呼吸、帶來清晰的能量。像新鮮空氣流通,這能量清理停滯、帶來新觀點、並且給予自由。這是間距的智慧,理解距離不是遺棄,而是愛的表現。","guidance":"給自己與他人更多空間。你是否與某人或某事太過緊密,失去了自己的空間?現在是退一步、創造呼吸空間的時刻。這不是疏遠或冷漠,而是健康的界限。同時,深呼吸。有意識地呼吸,讓新鮮空氣清理你的身心。如果你感到思緒混亂,舒的清晰能量會幫助你理清頭緒。開窗通風,讓新鮮空氣進入你的空間與生命。有時候,我們需要的只是一點空間與新鮮空氣。","soulReminder":"你需要空間才能成長,就像植物需要空間才能伸展。適當的距離不是不愛,而是最深的愛,因為它允許對方自由存在。窒息的愛不是真愛,真愛給予空間。記住呼吸的重要性,當你感到焦慮或overwhelmed,回到呼吸。空氣永遠在那裡,等待你吸入。創造空間不是創造空虛,而是創造可能性。在空間中,新的事物才能誕生。給自己呼吸的權利。","questions":"我有足夠的空間嗎?我感到窒息嗎?我的關係太緊密嗎?我需要距離嗎?我有意識地呼吸嗎?什麼需要更多流通?我如何能創造空間?我允許他人呼吸嗎?","energyFocus":"專注於創造和維護必要的空間。在窒息的關係中退一步,給彼此呼吸的空間。練習深呼吸,特別是在壓力時刻。打開窗戶,讓新鮮空氣流通。清理physical space,扔掉不需要的東西。在日程表中創造空白,不要把每一刻都填滿。到戶外呼吸新鮮空氣。理解距離可以帶來清晰與更新。像空氣一樣自由、流通、輕盈。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:20', 'egyptian_gods', '20', 19, '瓦吉特 - 眼鏡蛇女神', 'Wadjet - Cobra Goddess', NULL, '{"titleEn":"Wadjet - Cobra Goddess","symbol":"🐍 眼鏡蛇女神，王冠護蛇"}', '{"godStory":"瓦吉特是眼鏡蛇女神,法老王冠上的護蛇,象徵皇家權威與神聖保護。眼鏡蛇在受威脅時會立起頭部,展開頸部的皮膜,發出威嚇的嘶聲,準備攻擊。她代表果斷的保護、權威、神聖的憤怒與毫不妥協的界限。她的毒液既是武器也是保護,她不會猶豫地捍衛自己的領域。","coreMeaning":"瓦吉特代表權威、保護、果斷、界限執行、神聖的憤怒、皇家力量與昆達里尼能量。這是關於果斷地保護自己,展現權威,以及毫不猶豫地捍衛界限。瓦吉特教導我們,有時候溫柔不夠,需要展現威嚴與力量。她鼓勵我們像眼鏡蛇一樣,當界限被侵犯時立即反應,清晰地展現我們的力量與主權。","coreEnergy":"權威、保護、果斷、力量、界限、神聖憤怒、昆達里尼、皇家、威嚴、不妥協。瓦吉特的能量是強大的、果斷的、不容侵犯的。這是一種立即反應、明確捍衛、毫不猶豫的能量。像眼鏡蛇立起威嚇,這能量展現清晰的界限與不可侵犯的主權。這是權威的能量,知道自己的價值與力量。","guidance":"果斷地保護你自己。如果有人攻擊你、貶低你或侵犯你的界限,現在是反擊的時刻。像眼鏡蛇一樣立起你的頭,展現你的力量與威嚴。不要再退縮或道歉,捍衛你的立場。同時,瓦吉特邀請你連結內在的昆達里尼能量,那股沉睡在脊椎底部的生命力量。通過瑜伽、冥想或能量工作喚醒這股力量。瓦吉特的保護不僅是外在的,也是內在的。站穩你的力量,展現你的權威。","soulReminder":"你擁有皇家的力量與權威,不要讓任何人讓你感到卑微或不配。你的界限是神聖的,你有權利果斷地捍衛它們。溫柔是美德,但不是在所有處境。當你受到攻擊,你有權利展現你的毒牙。你內在有一股強大的昆達里尼能量,等待覺醒。當你連結這股力量,你會發現你比想像中更強大。像眼鏡蛇一樣,既美麗又致命,既神聖又強大。你的力量是你的birthright。","questions":"我捍衛我的界限嗎?我展現我的權威嗎?我允許他人貶低我嗎?我的昆達里尼能量覺醒了嗎?我夠果斷嗎?我展現我的力量嗎?什麼時候需要反擊?我如何能更有威嚴?","energyFocus":"專注於果斷與權威的展現。當界限被侵犯時立即反應,不要等待或猶豫。練習展現威嚴,站直、眼神堅定、聲音有力。進行昆達里尼瑜伽或能量工作,喚醒脊椎的力量。不要為你的力量道歉,擁抱它。像眼鏡蛇一樣警覺、美麗、致命。你的保護是神聖的,你的權威是你的birthright。展現你的皇家力量,毫不妥協。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:21', 'egyptian_gods', '21', 20, '奈特 - 織女神', 'Neith - Weaver Goddess', NULL, '{"titleEn":"Neith - Weaver Goddess","symbol":"🏹 手持織布機與弓箭"}', '{"godStory":"奈特是古老的創造女神,手持織布機與弓箭,既是創造者也是戰士。她被視為編織宇宙結構的織女,每一條線都是命運的一部分,每一個交織都創造新的模式。她也是戰爭與狩獵的女神,代表創造需要的策略與智慧。她的織布機編織著現實,她的箭矢射向目標,精準而有力。","coreMeaning":"奈特代表創造、命運編織、策略、智慧、自主性、創意模式與生命設計。這是關於理解我們都是自己命運的編織者,每一個選擇都是織入生命掛毯的一條線。奈特教導我們,我們不是命運的受害者,而是創造者。她鼓勵我們有意識地選擇我們編織的模式,並且發揮創意與策略智慧來創造我們想要的生命。","coreEnergy":"創造、編織、命運、策略、智慧、模式、設計、自主、創意、戰略思維。奈特的能量是創造性的、策略性的、有意識的。這是一種知道如何將不同元素編織成和諧整體的能量。像編織者,這能量理解模式、連結與結構,知道如何創造持久而美麗的作品。這是智慧的創造,不是隨機的,而是有意圖的。","guidance":"有意識地編織你的命運。檢視你目前的生活模式:哪些模式服務你?哪些需要改變?每一天的選擇都在編織你的未來,所以要有意識地選擇。同時,奈特邀請你發揮創意與策略。如果你面對挑戰,不要只是硬碰硬,思考更聰明的方法。像編織一樣,有時候需要繞道、交織、創造新的連結。奈特也鼓勵實際的創作,無論是編織、縫紉或任何需要將不同元素結合成整體的活動。","soulReminder":"你手中握著線,你是自己生命的編織者。每一個選擇、每一個行動、每一個想法都是你織入生命掛毯的一條線。不要被動地接受命運,主動地創造它。你擁有改變模式的力量,無論過去編織了什麼,你都可以開始新的模式。記住,編織需要耐心、技巧與願景。你的生命是一件藝術品,正在你的手中成形。編織美麗、有意義的模式。","questions":"我正在編織什麼模式?我的選擇創造什麼未來?我是被動還是主動的?我的生命設計是有意識的嗎?我需要改變什麼模式?我如何能更策略地創造?我的創意如何展現?我編織的故事是什麼?","energyFocus":"將注意力放在有意識的選擇與創造上。審視你的生活模式,決定保留或改變哪些。發展策略思維,在行動前考慮長期影響。進行實際的編織、縫紉或任何創造性手工,理解創造的過程。連結不同的元素,看見它們如何交織成整體。為你的生命設計清晰的願景,然後一條線一條線地編織它。你是藝術家,你的生命是畫布。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:22', 'egyptian_gods', '22', 21, '孔蘇 - 月神', 'Khonsu - Moon God', NULL, '{"titleEn":"Khonsu - Moon God","symbol":"🌙 頭頂新月滿月，穿越夜空"}', '{"godStory":"孔蘇是年輕的月神,頭頂新月與滿月,象徵時間的流逝與週期。他穿越夜空,在黑暗中提供光明,守護旅行者。月亮經歷盈虧圓缺,代表生命的自然節奏與變化。他也與治療和時間計量相關,提醒我們一切都有其時機。他的光明是柔和的,但足以照亮黑夜的道路。","coreMeaning":"孔蘇代表週期、時機、節奏、變化、月亮能量、時間的流逝與在黑暗中的光明。這是關於尊重生命的自然週期,理解萬物都有其時機。孔蘇教導我們,有播種的時候、成長的時候、收穫的時候、休息的時候。他鼓勵我們順應而非對抗這些自然節奏,在黑暗中信任即使微弱的光明也足以指引方向。","coreEnergy":"週期、時機、節奏、變化、月亮、時間、流逝、黑暗中的光、療癒、耐心。孔蘇的能量是週期性的、有節奏的、變化的。這是一種理解時間流動、尊重自然節奏、並且在適當時機行動的能量。像月亮的盈虧,這能量提醒我們一切都在變化,沒有什麼是永恆不變的。這是耐心等待正確時機的智慧。","guidance":"順應生命的自然節奏。不是所有時刻都適合行動,有時候需要休息、反思、等待。觀察你目前處於哪個週期:是新開始的時刻?還是收穫的時刻?或是放手的時刻?順應這個節奏,而不是強迫不合時宜的行動。同時,孔蘇邀請你關注月亮週期,與之同步你的生活。新月時設定意圖,滿月時慶祝與釋放。如果你感到迷失,孔蘇的月光會照亮你的道路。","soulReminder":"一切都有其時機,沒有什麼會永遠持續。就像月亮盈虧,你的生命也在循環變化。不要在殘月時期強迫自己像滿月一樣發光,每個階段都有其目的與美麗。黑暗不是永恆的,光明總會回來。耐心等待,時機成熟時自會顯現。記住,即使在最黑暗的夜晚,月光也會照亮道路。信任時間的智慧,一切都在perfect timing中展開。尊重你的週期,尊重生命的節奏。","questions":"我處於哪個週期?現在是行動還是休息的時機?我尊重自然節奏嗎?我與月亮連結嗎?我強迫不合時宜的行動嗎?我夠耐心嗎?什麼正在變化?我如何能更順應時機?","energyFocus":"將注意力放在時機與節奏上,觀察生命的自然週期。關注月亮的週期,在新月與滿月進行儀式。尊重你的能量高低起伏,不要強迫一致的生產力。識別你所處的階段,相應地行動或休息。培養耐心,理解時機的重要性。在黑暗時期信任光明會回來。順應而非對抗自然節奏。像月亮一樣,接受變化為生命的本質。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:23', 'egyptian_gods', '23', 22, '梅斯肯特 - 誕生女神', 'Meskhenet - Birth Goddess', NULL, '{"titleEn":"Meskhenet - Birth Goddess","symbol":"👶 誕生磚石，見證生命誕生"}', '{"godStory":"梅斯肯特是誕生女神,在每個嬰兒出生時在場,預言他們的命運。她的形象常是birthing brick(古埃及婦女蹲坐其上分娩),象徵生命的誕生時刻。她見證每一個新開始,每一次從無到有的奇蹟。她代表潛能、新生、命運的種子與生命最初的呼吸。她守護所有形式的誕生,無論是孩子、想法還是新的自我。","coreMeaning":"梅斯肯特代表新生、開始、潛能、誕生過程、命運種子、希望與新的可能性。這是關於某種新事物正在誕生或即將誕生,充滿無限潛能與希望。梅斯肯特教導我們,每一次誕生都是奇蹟,每一個新開始都充滿可能性。她鼓勵我們溫柔地對待新生的事物,給它時間成長,並且相信誕生的過程,即使有陣痛。","coreEnergy":"新生、開始、潛能、誕生、命運、希望、可能性、脆弱、新鮮、奇蹟。梅斯肯特的能量是新鮮的、充滿潛能的、希望的。這是一種見證新生、慶祝開始、並且溫柔保護新生命的能量。像剛出生的嬰兒,這能量是脆弱的但充滿可能,需要照顧與保護。這是新的黎明,一切皆有可能。","guidance":"迎接新的開始。某種新事物正在你的生命中誕生,可能是一個項目、關係、身份或理解。溫柔地對待這個新生命,給它時間成長。不要期待立即的成熟,就像嬰兒需要時間學會走路,你的新開始也需要發展的空間。同時,如果你正在孕育想法或計劃,梅斯肯特的能量支持你。相信誕生的過程,即使過程中有陣痛與不確定。每一次誕生都包含著命運的種子,慶祝新的開始。","soulReminder":"你正在見證或經歷一次奇蹟般的誕生。新生命總是脆弱的,需要溫柔的照顧與保護。不要急於催促成長,給予時間與空間。記住,每一個偉大的存在都曾經是脆弱的新生兒。你的新開始包含著無限的潛能,雖然現在看不見全貌,但種子已經種下。相信誕生的智慧,即使過程痛苦,結果是美麗的。擁抱新的開始,它們是生命的禮物。你正在創造新的命運。","questions":"什麼正在誕生?我準備好新開始了嗎?我溫柔對待新生的事物嗎?我給予足夠的時間嗎?什麼潛能等待展開?我相信誕生的過程嗎?我慶祝新開始嗎?我的新命運是什麼?","energyFocus":"將注意力放在新的開始上,識別什麼正在誕生。溫柔地照顧新生的項目、關係或自我面向。給予時間、空間與滋養,不要急於求成。慶祝小的里程碑,每一步成長都值得慶祝。保護脆弱的新生命免受批評與懷疑。相信過程,即使看不見立即的結果。擁抱潛能,知道種子會成長為大樹。見證奇蹟,每一次誕生都是神聖的。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:24', 'egyptian_gods', '24', 23, '塞爾凱特 - 蠍子女神', 'Serket - Scorpion Goddess', NULL, '{"titleEn":"Serket - Scorpion Goddess","symbol":"🦂 頭頂蠍子，毒液可療癒"}', '{"godStory":"塞爾凱特是蠍子女神,頭頂蠍子,既是療癒者又是保護者。蠍子的毒既能殺人也能治病,象徵療癒與傷害的雙重本質。她守護對抗毒素與危險,特別保護脆弱的部位如喉嚨與呼吸。她代表以毒攻毒的療癒智慧,以及在黑暗中尋找medicine的勇氣。她知道最深的療癒往往來自直接面對毒素。","coreMeaning":"塞爾凱特代表療癒、轉化毒素、以毒攻毒、勇敢面對痛苦、保護脆弱處與深度療癒工作。這是關於勇敢地面對生命中的毒素,無論是有毒的關係、負面思想還是未解決的創傷,並且將它們轉化為療癒的medicine。塞爾凱特教導我們,最深的療癒需要勇氣去面對痛苦,而非逃避它。她鼓勵我們像蠍子的毒可以成為解藥,我們的痛苦也包含著療癒的種子。","coreEnergy":"療癒、轉化、毒素、以毒攻毒、勇氣、保護、深度工作、痛苦、medicine、煉金術。塞爾凱特的能量是深刻的、轉化的、勇敢的。這是一種不逃避毒素而是直接面對、將痛苦轉化為力量的能量。像蠍子的毒可以療癒也可以傷害,這能量理解痛苦的雙重性質,知道如何從毒素中提煉medicine。這是療癒者的深刻智慧。","guidance":"面對並轉化生命中的毒素。逃避問題只會讓毒素累積。現在是直接面對的時刻。哪些關係是有毒的?哪些思想模式在毒害你?哪些情緒被壓抑成為毒素?勇敢地面對它們,不是為了被傷害,而是為了療癒。就像蠍子的毒可以製成解藥,你的痛苦也包含著療癒的種子。塞爾凱特也提醒你保護自己免受外在毒素的侵害。設立界限,遠離有毒的環境與人。","soulReminder":"你的痛苦不是無用的,它包含著強大的療癒medicine。當你勇敢地面對並轉化它,它會成為你最大的力量來源。逃避只會讓毒素在體內累積,面對才能釋放與療癒。記住,最強大的療癒者往往是那些經歷過最深痛苦的人。你的傷口可以成為你的智慧,你的毒素可以成為你的medicine。塞爾凱特守護你在這個深度療癒的旅程中,給予你勇氣面對,給予你智慧轉化。以毒攻毒,痛苦變medicine。","questions":"我生命中有什麼毒素?我逃避還是面對痛苦?我的傷口包含什麼智慧?我如何將痛苦轉化為力量?我保護自己免受毒害嗎?我準備好深度療癒了嗎?我的medicine是什麼?我如何以毒攻毒?","energyFocus":"專注於識別並轉化毒素。勇敢地面對有毒的關係、思想或情緒,不要繼續逃避。進行深度療癒工作,可能需要治療師或療癒者的支持。將痛苦視為teacher而非enemy,問它要教你什麼。保護自己免受新的毒素侵害,設立堅固的界限。學習煉金術,將傷痛轉化為智慧、痛苦轉化為力量。你的毒素可以成為最強大的medicine。勇敢面對,深度轉化。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:25', 'egyptian_gods', '25', 24, '貝斯 - 侏儒神', 'Bes - Dwarf God', NULL, '{"titleEn":"Bes - Dwarf God","symbol":"😜 侏儒神，做鬼臉穿獅皮"}', '{"godStory":"貝斯是侏儒神,外表醜陋但心地善良,常被描繪為做鬼臉、伸舌頭、穿著獅皮。他是家庭、孩童、婦女與歡樂的守護者。他用音樂、舞蹈與幽默驅趕邪靈,帶來歡笑與安全感。他提醒我們不要以貌取人,真正的力量與善良往往藏在不起眼的外表下。他是日常生活的保護者,守護簡單但重要的事物。","coreMeaning":"貝斯代表喜悅、幽默、家庭保護、簡單快樂、不以貌取人、日常魔法與內在善良。這是關於在生活中找到簡單的快樂,不要忽視日常的小幸福。貝斯教導我們,最大的魔法不在宏大的儀式,而在笑聲、音樂與愛中。他鼓勵我們保護內在的孩童,那個純真、好奇、充滿歡樂的自己,並且不要因為外表而評判任何人或事。","coreEnergy":"喜悅、幽默、保護、簡單、家庭、歡笑、音樂、舞蹈、不評判、日常魔法。貝斯的能量是歡樂的、保護性的、不裝模作樣的。這是一種在簡單中找到魔法、在幽默中找到力量、在笑聲中驅散黑暗的能量。像貝斯醜陋但善良,這能量提醒我們不要被表象欺騙,真正的價值在內在。這是日常生活的神聖。","guidance":"擁抱歡樂與簡單的快樂。你是否太過嚴肅,忘記了樂趣?現在是時候做些傻事、唱歌、跳舞、開玩笑。貝斯提醒你,幽默與歡笑是強大的保護力量,能驅散負面能量。同時,關注你的家庭與居家環境。創造溫暖、安全、充滿愛的空間。保護你的家人與內在的孩童。貝斯也鼓勵你不要以貌取人,包括對自己。你的價值不在於外表,而在於你帶給世界的歡樂與愛。","soulReminder":"你的價值不在外表,而在你的心與你帶來的歡樂。不要因為不符合某種標準而貶低自己,真正的美在於善良、幽默與愛。記住,生命太短暫,不要忘記玩樂與歡笑。簡單的快樂往往是最深刻的,家庭的溫暖往往比外在成就更lasting。保護你內在的孩童,那個知道如何純粹快樂的部分。讓音樂、舞蹈、笑聲成為你的魔法。貝斯提醒你,醜陋的外表下可能藏著最美的心,不要太快評判。","questions":"我允許自己歡樂嗎?我的生活有足夠笑聲嗎?我保護我的家庭嗎?我是否以貌取人?我的內在孩童快樂嗎?我看見日常中的魔法嗎?我太嚴肅了嗎?我如何能更幽默?","energyFocus":"將注意力放在簡單的快樂上,做讓你發笑的事。加入更多音樂、舞蹈、幽默到日常生活中。創造溫暖的家庭環境,讓家成為安全的避風港。保護並滋養你的內在孩童,允許玩樂與好奇。不要評判外表,尋找內在的美與善。用笑聲驅散負面能量,幽默是強大的medicine。慶祝日常的小快樂,它們是生命的真正寶藏。像貝斯一樣,醜但美,簡單但神奇。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:26', 'egyptian_gods', '26', 25, '塔沃瑞特 - 河馬女神', 'Taweret - Hippo Goddess', NULL, '{"titleEn":"Taweret - Hippo Goddess","symbol":"🦛 河馬女神，兇猛卻慈愛"}', '{"godStory":"塔沃瑞特是河馬女神,外表兇猛但心地慈愛,是孕婦與新生兒的守護者。她結合了河馬、獅子、鱷魚的特徵,看起來可怕但她的目的是保護。母河馬是自然界最兇猛的保護者之一,會不惜一切保護幼崽。她代表母性的狂野保護力量,以及為所愛之人不顧一切的決心。她的兇猛是愛的表現。","coreMeaning":"塔沃瑞特代表母性保護、生育、養育、兇猛的愛、新生命的守護與豐盛的創造力。這是關於保護與養育正在成長的事物,無論是實際的孩子、創意項目或新的自我。塔沃瑞特教導我們,真正的母愛既溫柔又兇猛,既滋養又保護。她鼓勵我們像母河馬一樣,為我們所愛與創造的事物提供強大而溫柔的保護,不允許任何威脅接近。","coreEnergy":"母性、保護、養育、兇猛、生育、豐盛、創造、溫柔與力量、狂野的愛、守護。塔沃瑞特的能量是強大而溫柔的、保護性的、滋養的。這是一種不計代價保護所愛之人的能量,結合了河馬的力量與母親的溫柔。像母河馬,這能量看似可怕但本質是愛,會為保護而戰但為滋養而存在。這是母性最原始而神聖的形式。","guidance":"保護與養育你正在孕育的事物。你是否正在創造新項目、想法或關係?像母親保護胎兒一樣保護它。不要過早暴露,給它安全的空間成長。同時,連結你內在的母性能量,無論性別。這不僅是溫柔,更是兇猛的保護力量。當需要保護你所愛時,召喚塔沃瑞特的能量,她會給你勇氣與力量。她也提醒你照顧自己的身體,特別是如果你正在懷孕或希望懷孕。豐盛的能量支持所有形式的創造與生育。","soulReminder":"你內在有強大的創造與保護能量,如母河馬般兇猛而溫柔。不要為你的保護本能感到抱歉,為所愛之人挺身而出是神聖的。你的創造力是豐盛的,你能夠孕育新生命,無論是實體的還是隱喻的。記住,真正的母愛不是軟弱的,它是最強大的力量之一。保護你的創造,滋養你的dream,兇猛地守護你的界限。你的外表可能兇猛,但你的心充滿愛。像塔沃瑞特,你是守護者與養育者,強大而慈愛。","questions":"我保護我的創造嗎?我養育新生的事物嗎?我的母性能量如何?我兇猛地守護所愛嗎?我給予安全的空間嗎?我的創造力豐盛嗎?我照顧我的身體嗎?我如何平衡溫柔與力量?","energyFocus":"專注於保護與養育正在成長的事物。為你的創造提供安全、滋養的環境。連結你的母性能量,無論性別,這是原始的創造與保護力量。兇猛地守護你的界限,不允許威脅接近你所愛。同時保持溫柔,滋養需要照顧的部分。照顧你的身體,它是創造的vessel。擁抱豐盛,相信你的創造力是無限的。像塔沃瑞特,既兇猛又溫柔,既保護又滋養。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:27', 'egyptian_gods', '27', 26, '阿米特 - 吞噬者', 'Ammit - Devourer', NULL, '{"titleEn":"Ammit - Devourer","symbol":"👹 混合生物，鱷頭獅身河馬後"}', '{"godStory":"阿米特是混合生物,擁有鱷魚的頭、獅子的前身與河馬的後身,結合了三種最強大掠食者的特徵。她在死後審判中吞噬不純淨的心臟,是宇宙正義的最終執行者。她不是邪惡的,而是必要的,確保只有真誠純淨的靈魂能進入來世。她代表後果、真相無法逃避與面對自己行為的必然性。","coreMeaning":"阿米特代表後果、業力、真相、誠實面對自己、必須放棄的虛假自我與宇宙正義。這是關於理解所有行為都有後果,我們無法欺騙宇宙。阿米特教導我們,有些東西必須被完全吞噬消化,才能真正轉化。她鼓勵我們誠實面對自己的行為,承擔責任,並且放棄虛假的面具與不真實的自我。","coreEnergy":"後果、業力、真相、正義、吞噬、轉化、誠實、責任、虛假的死亡、必然性。阿米特的能量是嚴厲的、不可逃避的、公正的。這是一種要求完全誠實、完全負責的能量。像吞噬者,這能量會消化一切不真實的,只留下真實的核心。這是宇宙正義的能量,沒有例外,沒有逃避。","guidance":"面對真相與後果。你無法逃避自己行為的後果。如果你做了不誠實或傷害他人的事,現在是承擔責任的時刻。不要試圖逃避或合理化,勇敢地面對並做出彌補。同時,阿米特邀請你吞噬虛假的自我。你是否戴著面具生活?是否假裝成不是真實的自己?現在是時候讓阿米特吞噬這些虛假的部分,回歸真實。這可能感覺像是死亡,但這是必要的清理。","soulReminder":"宇宙的正義是公平的,所有行為都有後果。你無法欺騙業力,只能面對與清理。記住,阿米特只吞噬不真實的,如果你活得真誠,你無需恐懼。虛假的自我必須死去,真實的你才能完全誕生。這個過程可能痛苦,但它是必要的清理與轉化。不要抗拒,讓不真實的被吞噬,讓真實的留下。宇宙的正義最終會實現,與其對抗,不如主動清理。面對真相,擁抱責任,成為真實的自己。","questions":"我需要承擔什麼後果?我逃避什麼責任?我活得真誠嗎?什麼虛假的自我需要死去?我欺騙誰?我的行為與價值觀一致嗎?我準備好面對真相了嗎?什麼需要被完全吞噬?","energyFocus":"專注於誠實與責任。面對你行為的後果,不要逃避或否認。如果你傷害了他人,做出真誠的彌補。檢視你生活中的虛假面向,允許它們被吞噬。放下假裝、面具、不真實的自我展現。回歸核心的真實,即使這意味著失去某些認同。清理業力,通過誠實、責任與真實。接受阿米特的嚴厲但公正的清理。只有真實會留下,虛假必須消失。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:28', 'egyptian_gods', '28', 27, '阿佩普 - 混沌之蛇', 'Apep - Serpent of Chaos', NULL, '{"titleEn":"Apep - Serpent of Chaos","symbol":"🐉 巨大混沌蛇，試圖吞噬太陽"}', '{"godStory":"阿佩普是巨大的混沌之蛇,每晚試圖吞噬太陽神拉的船,阻止太陽升起。他代表原始的混沌、黑暗與需要被克服的障礙。他不是要被理解或整合,而是要被對抗與克服。他象徵著生命中真正的挑戰、試圖破壞我們進步的力量、以及需要勇氣與堅持才能戰勝的黑暗。但就像拉每晚都戰勝阿佩普,我們也能克服挑戰。","coreMeaning":"阿佩普代表真正的障礙、挑戰、黑暗力量、需要克服的困難、堅持與勇氣。這是關於承認你正面對真正的挑戰,不是你的想像,這是真實的障礙。阿佩普教導我們,光明必須不斷爭取,不是一勞永逸。他提醒我們,有些黑暗需要被對抗,不是被接受。但同時,他也告訴我們,就像太陽每天都升起,我們也能克服任何挑戰。","coreEnergy":"障礙、挑戰、黑暗、混沌、對抗、堅持、勇氣、克服、戰鬥、永恆的鬥爭。阿佩普的能量是對抗性的、挑戰性的、黑暗的。這是一種需要被克服而非整合的能量。像巨蛇試圖吞噬太陽,這能量代表真正的威脅與障礙。但記住,太陽總是勝利,光明總是回來。這是考驗我們堅持與勇氣的能量。","guidance":"勇敢面對你的挑戰。阿佩普提醒你,有些障礙是真實的,需要真正的努力去克服。不要低估困難,但也不要被嚇倒。集結你的資源、力量與支持者,準備戰鬥。就像神祇們聯合對抗阿佩普,你也不需要獨自面對挑戰。尋求幫助,團結力量。同時,保持警覺。這個挑戰可能重複出現,需要持續的努力。不要在克服一次後就放鬆警惕。光明需要每天重新爭取。","soulReminder":"你比混沌更強大。就像太陽每晚都戰勝阿佩普,你也能克服你的挑戰。這不是一次性的戰鬥,而是持續的努力,但你有力量堅持下去。不要因為困難重複出現而沮喪,這是生命的本質。光明必須不斷爭取,成長必須不斷努力。但記住,太陽從未失敗,黎明總是到來。你的堅持會得到回報,你的勇氣會帶來勝利。面對黑暗,不要退縮。你是光明的戰士,混沌無法戰勝你。","questions":"我面對什麼真正的挑戰?我需要克服什麼?我有足夠的勇氣嗎?我需要什麼支持?我是否低估了困難?我準備好持續戰鬥了嗎?我的堅持在哪裡?我如何能更強大?","energyFocus":"專注於克服真正的障礙。不要否認或最小化困難,誠實地評估挑戰。集結你的力量、資源與支持系統。尋求盟友,不要獨自戰鬥。培養堅持與韌性,知道這可能需要持續的努力。保持警覺,不要在初次勝利後放鬆。每天重新承諾於光明,每天重新戰勝黑暗。相信你的力量,知道就像太陽總是升起,你也總會勝利。堅持下去,黎明即將到來。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:29', 'egyptian_gods', '29', 28, '梅瑞特瑟爾 - 山神', 'Meretseger - Mountain Goddess', NULL, '{"titleEn":"Meretseger - Mountain Goddess","symbol":"⛰️ 眼鏡蛇山神，愛沉默者"}', '{"godStory":"梅瑞特瑟爾是「愛沉默者」的山神,守護著底比斯墳墓的金字塔形山峰。她是眼鏡蛇女神,既慈悲也嚴厲。她愛那些誠實正直的人,但懲罰不義者。她代表神聖的寂靜、獨處的智慧、山的穩定力量與在孤獨中找到神聖。山是永恆的,在寂靜中守護著秘密,她教導我們寂靜的力量與獨處的必要性。","coreMeaning":"梅瑞特瑟爾代表寂靜、獨處、內省、孤獨中的智慧、山的穩定、誠實與正直的重要性。這是關於退入寂靜,在喧囂世界中尋找安靜的空間,以及在孤獨中發現深刻的真理。梅瑞特瑟爾教導我們,不是所有答案都來自外在世界,有時候需要攀登內在的山峰,在寂靜的高處找到真理。她鼓勵我們擁抱獨處,在寂靜中聽見內在的聲音。","coreEnergy":"寂靜、獨處、內省、山、穩定、孤獨、深度、正直、神聖的安靜、內在聲音。梅瑞特瑟爾的能量是寂靜的、穩定的、深邃的。這是一種在安靜中運作的能量,不需要外在的驗證或喧囂。像山一樣,這能量是穩定的、永恆的、不可動搖的。在寂靜中,真理被聽見;在孤獨中,智慧被發現。","guidance":"尋求寂靜與獨處。暫時離開喧囂的世界,找一個安靜的地方,無論是實體的山峰或內心的避難所。在寂靜中,你會聽見被噪音掩蓋的真相。現在不是社交或外在活動的時刻,而是深入內心的時刻。冥想、獨自散步、日記書寫都能幫助你連結梅瑞特瑟爾的能量。她也提醒你,有時候最好的回應是沉默。不是所有事情都需要解釋或辯護。像山一樣穩定、沉默、不可動搖。","soulReminder":"在寂靜中有深刻的力量,在孤獨中有神聖的智慧。不要害怕獨處,它不是孤立,而是與自己深度連結。山不需要證明它的存在,它就在那裡,穩定而永恆。你也不需要不斷解釋或證明自己,你的存在本身就足夠。在喧囂的世界中,保持內在的寂靜是一種力量。傾聽比說話更能帶來智慧。攀登你內在的山峰,在高處你會看得更清楚。擁抱神聖的安靜,在其中你會找到真理。","questions":"我有足夠的寂靜嗎?我允許自己獨處嗎?我在安靜中聽到什麼?我的內在聲音說什麼?我需要攀登什麼內在山峰?我是否太多噪音?沉默教導我什麼?我如何能更穩定?","energyFocus":"將注意力轉向寂靜與獨處。創造安靜的空間與時間,遠離外在刺激。進行寂靜的冥想或獨自在自然中散步。減少不必要的社交與噪音。在寂靜中傾聽內在的聲音,它會告訴你真相。培養像山一樣的穩定,不被外在動盪影響。練習不解釋、不辯護,讓沉默成為你的回應。在孤獨中找到神聖,在安靜中發現智慧。像山一樣,穩定、寂靜、永恆。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:30', 'egyptian_gods', '30', 29, '伊姆霍特普 - 建築聖賢', 'Imhotep - Architect Sage', NULL, '{"titleEn":"Imhotep - Architect Sage","symbol":"📐 凡人升格神，天才建築師"}', '{"godStory":"伊姆霍特普是罕見的凡人升格為神,他是天才建築師、醫生、智者,設計了薩卡拉階梯金字塔,第一座石造建築。他代表人類智慧、創新、醫療技能與通過努力達成偉大的可能性。他不是天生的神,而是通過智慧、奉獻與服務他人而被神化。他象徵著知識的實際應用、解決問題的能力與lasting的貢獻。","coreMeaning":"伊姆霍特普代表人類潛能、智慧的實踐應用、創新、療癒技藝、通過努力達成偉大與lasting的貢獻。這是關於理解凡人也能達成神性,通過智慧、奉獻與服務。伊姆霍特普教導我們,我們擁有改變世界的能力,通過我們的知識、技能與貢獻。他鼓勵我們運用智慧去創造lasting的價值,無論是建築、療癒還是任何服務他人的工作。","coreEnergy":"智慧、創新、療癒、實踐、貢獻、人類潛能、技能、解決問題、lasting價值、凡人的神性。伊姆霍特普的能量是智慧的、實用的、創新的。這是一種將知識應用於實際、解決真實問題、創造lasting貢獻的能量。像建築師,這能量知道如何將願景變成實體,將想法變成lasting的成就。這是人類潛能的最高展現。","guidance":"運用你的智慧與技能。你擁有改變世界的能力,通過你的知識、技能與奉獻。不要小看自己的潛能,凡人也能創造不朽的遺產。現在是運用你學到的一切去創造、療癒、建造的時刻。如果你正在學習新技能,伊姆霍特普鼓勵你堅持。如果你是療癒者、建築師、醫生或任何服務他人的專業,他的能量支持你的工作。同時,創新與解決問題。不要被傳統限制,敢於嘗試新方法。","soulReminder":"你是凡人,但你擁有神性的潛能。通過智慧、奉獻與服務,你可以達成偉大的事。不要因為你不是「特別」或「有天賦」而放棄,伊姆霍特普也是凡人,但他通過努力成為神。你的智慧與努力可以創造lasting的價值,你的貢獻可以改變世界。不要只是夢想,實踐。不要只是學習,應用。用你的雙手建造,用你的知識療癒,用你的智慧解決問題。你的遺產正在你的每一個行動中創造。","questions":"我如何應用我的智慧?我的技能如何服務他人?我正在創造什麼lasting價值?我發揮我的潛能了嗎?我如何創新?我的貢獻是什麼?我準備好達成偉大了嗎?我如何能更實踐?","energyFocus":"將注意力放在實踐應用而非理論學習。運用你的知識與技能去解決真實的問題。發展創新的解決方案,不要被傳統方法限制。如果你有療癒、建築或任何專業技能,深化並應用它們。創造lasting的價值,不要只追求短期的成功。通過服務他人來展現你的智慧。學習新技能,永遠成長。記住,你的努力可以讓你從凡人升格。每一個貢獻都在建造你的遺產。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:31', 'egyptian_gods', '31', 30, '塞莎特 - 書記女神', 'Seshat - Scribe Goddess', NULL, '{"titleEn":"Seshat - Scribe Goddess","symbol":"📚 頭戴七角星，手持書寫工具"}', '{"godStory":"塞莎特是書寫、記錄、數學與建築的女神,托特的女性對應。她頭戴七角星與弓形符號,手持書寫工具與測量繩。她記錄國王的統治年限、戰爭勝利與建築計畫。她代表準確記錄、保存知識、計畫與測量的重要性。她是記憶的守護者,確保智慧不會隨時間流失,而是被保存供後世參考。","coreMeaning":"塞莎特代表記錄、保存知識、計畫、測量、準確性、記憶與書寫的力量。這是關於記錄你的經驗與洞見,保存智慧供未來參考。塞莎特教導我們,文字與記錄的力量不可低估,它們是知識跨越時間的橋樑。她鼓勵我們在行動前仔細規劃,精確測量,並且記錄我們的旅程,因為這些記錄將成為我們的智慧寶庫。","coreEnergy":"記錄、保存、書寫、計畫、測量、準確、記憶、知識、組織、精確。塞莎特的能量是有組織的、精確的、保存性的。這是一種重視記錄、計畫與準確性的能量。像書記員,這能量知道細節的重要性,知道記錄能夠保存智慧穿越時間。這是組織混亂、保存知識、精確執行的能量。","guidance":"記錄與規劃。把想法與經驗寫下來,不要讓寶貴的洞見消失在記憶中。開始寫日記,記錄你的夢境、想法、學習與成長。這些記錄將成為你的個人智慧書。同時,如果你有計劃或項目,塞莎特提醒你仔細規劃。測量、計算、組織、準備。不要倉促行動,先把計劃寫下來。塞莎特也鼓勵學習與教育。現在是學習新知識或分享你的智慧的好時機。你的文字具有力量。","soulReminder":"你的經驗與智慧值得被記錄,你的故事值得被書寫。不要讓時間侵蝕你的記憶與洞見,寫下它們。你的日記、筆記、書寫是你的遺產,是你留給未來的禮物。記住,文字穿越時間,書寫保存智慧。你今天記錄的,可能在未來幫助你或他人。計畫是成功的基礎,測量是精確的保證。不要低估細節的重要性。像塞莎特,成為你生命的書記員,記錄、規劃、保存。你的文字具有永恆的力量。","questions":"我記錄我的經驗嗎?我保存我的智慧嗎?我的計畫夠詳細嗎?我重視準確性嗎?我寫日記嗎?我的記憶如何被保存?我如何組織我的知識?我的文字如何服務他人?","energyFocus":"將注意力放在記錄與書寫上。開始或維持日記習慣,記錄每天的經驗、洞見與學習。寫下你的夢境、目標、計畫。為項目創建詳細的計劃,測量與計算,不要依賴直覺。組織你的知識,創建系統讓資訊易於取得。學習並分享,教育是知識保存的方式。重視準確性與細節。你的書寫是你的遺產,認真對待它。像塞莎特,記錄、規劃、保存智慧穿越時間。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:32', 'egyptian_gods', '32', 31, '哈比 - 尼羅河神', 'Hapy - Nile God', NULL, '{"titleEn":"Hapy - Nile God","symbol":"🌊 豐滿男性，尼羅河神格化"}', '{"godStory":"哈比是尼羅河的神格化,通常被描繪為豐滿的男性,有女性的乳房,象徵豐饒與滋養。他代表尼羅河的年度氾濫,帶來肥沃的淤泥,讓埃及成為文明的搖籃。他象徵著自然的豐盛、滋養的能量、生命的源泉與週期性的豐饒。沒有尼羅河的氾濫,埃及將是荒漠。哈比提醒我們,豐盛是自然的,是循環的。","coreMeaning":"哈比代表豐盛、滋養、生命源泉、自然的給予、循環的豐饒與感恩。這是關於理解豐盛不只是金錢,更是愛、健康、機會與支持。哈比教導我們,真正的富足來自與自然節奏的和諧,以及接受宇宙的滋養。他鼓勵我們打開接收豐盛的通道,同時慷慨地分享,因為豐盛的能量需要流動。給予與接收是同一個循環。","coreEnergy":"豐盛、滋養、給予、接收、流動、循環、豐饒、感恩、自然的給予、生命源泉。哈比的能量是豐盛的、滋養的、流動的。這是一種理解給予與接收都是自然的能量。像河流年年氾濫帶來豐饒,這能量提醒我們豐盛是循環的、可靠的、自然的。這不是匱乏而是豐饒,不是囤積而是流動。","guidance":"接收與分享豐盛。宇宙的豐盛一直在流動,問題是你是否打開接收。放下匱乏的信念,相信有足夠的給所有人。就像尼羅河年年氾濫,豐盛也會循環回來。現在是打開雙手接收的時刻。同時,哈比鼓勵慷慨。豐盛的能量需要流動,給予與接收是同一個循環。分享你擁有的,無論是金錢、時間、愛或智慧。你給出的會加倍回到你身上。與自然的節奏和諧,尊重自然的豐饒。","soulReminder":"豐盛是你的自然狀態,匱乏是幻覺。宇宙是豐盛的,像尼羅河永不枯竭。問題不是資源不夠,而是你是否打開接收。放下匱乏mindset,擁抱豐盛意識。記住,你給予的不會減少你擁有的,反而會增加流動。慷慨不是犧牲,而是參與豐盛的循環。感恩你已經擁有的,更多會來到你身邊。與自然的給予和諧,尊重生命的源泉。你值得豐盛,你就是豐盛。打開接收,慷慨給予,讓豐盛之河流經你的生命。","questions":"我打開接收了嗎?我相信豐盛嗎?我慷慨分享嗎?我感恩我擁有的嗎?我的匱乏信念是什麼?我如何能更流動?豐盛在我生命中如何展現?我與自然的給予和諧嗎?","energyFocus":"將注意力放在豐盛而非匱乏上。每天練習感恩,寫下你感激的事物。打開接收,允許好事進入你的生命,不要推拒或感到不配。慷慨地給予,分享你的資源、時間、愛與智慧。觀察豐盛如何在你生命中流動,不只是金錢,還有愛、機會、支持。放下匱乏mindset,肯定豐盛是你的自然狀態。與自然連結,尊重地球的給予。像河流一樣流動,給予與接收,讓豐盛循環。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:33', 'egyptian_gods', '33', 32, '芮內努特 - 豐收女神', 'Renenutet - Harvest Goddess', NULL, '{"titleEn":"Renenutet - Harvest Goddess","symbol":"🌾 眼鏡蛇女神，守護豐收穀物"}', '{"godStory":"芮內努特是眼鏡蛇女神,守護豐收、穀物與孩童養育。她在收穫季節特別受到崇敬,確保農作物的豐盛與食物的充足。她代表辛勤工作的回報、收穫的喜悅、滋養的豐盛與耐心等待的果實。她提醒我們,豐收需要耕耘,沒有播種就沒有收穫。但當收穫時刻到來,我們要慶祝並感恩我們努力的成果。","coreMeaning":"芮內努特代表收穫、辛勤工作的回報、豐盛的結果、耐心的果實、滋養與慶祝。這是關於終於收穫你播種與照顧的果實。芮內努特教導我們,成功需要時間與努力,但當收穫時刻到來,要驕傲地接收你應得的回報。她鼓勵我們繼續照顧我們的「作物」,無論是項目、關係或個人成長,並且在豐收時刻慶祝與感恩。","coreEnergy":"收穫、回報、豐盛、成果、努力、耐心、滋養、慶祝、感恩、成功。芮內努特的能量是豐收的、滋養的、慶祝的。這是一種見證努力結果、享受成功、並且感恩的能量。像收穫季節,這能量是豐盛的、喜悅的、滿足的。辛勤工作得到回報,耐心等待得到果實。這是慶祝與分享的時刻。","guidance":"準備收穫你的努力成果。你的辛勤工作即將或正在結出果實。現在是收穫、慶祝與感恩的時刻。不要謙遜地拒絕你應得的回報,驕傲地接收你努力的成果。同時,如果收穫還未到來,芮內努特提醒你繼續照顧你的「作物」。成長需要時間,不要在豐收前放棄。繼續澆水、除草、耐心等待。豐收終將到來。芮內努特也鼓勵你滋養他人,分享你的豐收,餵養需要的人。","soulReminder":"你的努力沒有白費,收穫的時刻正在到來或已經到來。不要質疑你是否配得,你通過辛勤工作與耐心等待贏得了這些果實。驕傲地接收,慶祝你的成功,分享你的豐盛。記住,豐收不僅是為了你,也是為了你能夠滋養他人。慷慨地分享,像大地慷慨地給予穀物。感恩這個循環:播種、照顧、等待、收穫。你正處於豐收的季節,享受你努力的甜美果實。你值得這一切。","questions":"什麼正在收穫?我接收我的回報了嗎?我慶祝我的成功嗎?我感恩我擁有的嗎?我繼續照顧我的項目嗎?我分享我的豐盛嗎?我的努力得到回報了嗎?我準備好豐收了嗎?","energyFocus":"將注意力放在收穫與慶祝上。識別你努力結出的果實,無論大小。接收你的回報,不要拒絕或最小化你的成功。慶祝每一個成就,邀請他人一起慶祝。感恩這個豐收,感謝支持你的所有人。同時,繼續照顧還在成長的項目,不要因為一個豐收就忽略其他。分享你的豐盛,滋養他人。像豐收季節,這是喜悅、滿足與感恩的時刻。享受你努力的甜美果實。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:34', 'egyptian_gods', '34', 33, '赫卡 - 魔法之神', 'Heka - Magic Personified', NULL, '{"titleEn":"Heka - Magic Personified","symbol":"✨ 魔法神格化，創世之初存在"}', '{"godStory":"赫卡是魔法本身的神格化,存在於創世之初,甚至比諸神更古老。他代表宇宙的創造力量、顯化的能量、話語和意圖的魔法。在古埃及,魔法不是超自然,而是自然法則的一部分,是理解並運用宇宙能量的技術。赫卡教導我們,魔法不是外在的力量,而是我們內在固有的創造能力,通過意圖、話語與儀式顯化現實。","coreMeaning":"赫卡代表魔法、顯化、創造力量、意圖的力量、話語的魔法、儀式與有意識創造。這是關於理解我們都擁有魔法的力量,我們的思想、言語與行動都在塑造現實。赫卡教導我們,魔法不是虛幻的,而是運用宇宙法則的實踐。他鼓勵我們有意識地使用我們的創造力量,通過清晰的意圖、賦能的言語與專注的行動來顯化我們想要的現實。","coreEnergy":"魔法、創造、顯化、意圖、話語力量、儀式、宇宙法則、有意識創造、轉化、能量操作。赫卡的能量是魔法的、創造的、轉化的。這是一種理解並運用宇宙創造法則的能量。像魔法師,這能量知道意圖、話語、行動如何結合創造現實。這不是迷信,而是深刻的宇宙智慧,是有意識參與創造的能力。","guidance":"運用你的魔法力量。你比你想像的更有力量。你的意圖能塑造現實,你的言語能創造或毀滅,你的信念能顯化實相。現在是有意識地運用這些力量的時刻。設定清晰的意圖,說出你想創造的現實,採取一致的行動。這就是魔法。赫卡也鼓勵你探索儀式、冥想、肯定語或任何幫助你專注意圖的實踐。創造神聖空間,進行個人儀式,連結更高的力量。魔法不是逃避,而是有意識地創造。","soulReminder":"你是魔法師,你的生命是你的魔法書。你擁有創造現實的力量,通過你的思想、言語與行動。不要低估你的魔法,它是真實的、強大的、有效的。記住,魔法需要責任,你創造的一切都會回到你身上。有意識地使用你的力量,為善而非為惡。你的意圖是種子,你的言語是咒語,你的行動是儀式。一切都是魔法,當你有意識地參與。連結古老的赫卡力量,它在創世之初就存在,它在你內在也存在。你是宇宙的共同創造者。","questions":"我如何使用我的魔法?我的意圖清晰嗎?我的言語創造什麼?我有意識地創造嗎?我進行儀式嗎?我相信我的力量嗎?我的魔法如何顯化?我準備好成為魔法師了嗎?","energyFocus":"專注於有意識的創造與魔法實踐。設定清晰、具體的意圖,寫下你想要顯化的現實。使用肯定語與賦能的言語,你的話語是咒語。進行個人儀式,創造神聖空間,無論簡單或複雜。冥想連結宇宙創造力量。觀察你的思想、言語、行動如何創造你的現實。為你的魔法負責,確保你創造的服務最高善。連結赫卡的古老力量,它在你內在也存在。成為有意識的魔法師,創造你想要的生命。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:35', 'egyptian_gods', '35', 34, '天秤 - 宇宙平衡', 'The Balance - Cosmic Equilibrium', NULL, '{"titleEn":"The Balance - Cosmic Equilibrium","symbol":"⚖️ 瑪特天秤，稱量心臟與羽毛"}', '{"godStory":"這張牌代表瑪特的天秤,用來在死後審判中稱量心臟。天秤是宇宙平衡的終極象徵,一邊是死者的心臟,另一邊是瑪特的真理之羽。只有心臟輕如羽毛者才能進入來世。天秤象徵宇宙的公正、平衡、因果法則與真相的重量。每一個行為、思想與意圖都有重量,都會影響這個微妙的平衡。","coreMeaning":"天秤代表平衡、公正、因果、和諧、宇宙秩序、真相的重量與生活的平衡狀態。這是關於檢視你生活中的平衡,理解所有行為都有後果,以及尋求和諧與公正。天秤教導我們,宇宙尋求平衡,過度或不及都會造成失衡。它鼓勵我們在所有生活領域中尋求中庸之道,在給予與接受、工作與休息、物質與精神之間找到平衡點。","coreEnergy":"平衡、公正、和諧、因果、秩序、中庸、公平、真相、重量、平衡點。天秤的能量是平衡的、公正的、和諧的。這是一種不偏不倚、尋求中道、維護公正的能量。像天秤一樣,這能量敏感地測量,確保兩邊平衡。過度或不及都會被調整,直到達到完美的平衡。這是宇宙正義與和諧的能量。","guidance":"恢復生活的平衡。誠實地檢視每個生活領域。在工作與休息之間、給予與接收之間、物質與精神之間、自我與他人之間,是否保持平衡?找出失衡的地方並做出調整。有時候需要增加,有時候需要減少,關鍵是找到中庸之道。天秤也提醒你,你的選擇有重量。每一個決定都會影響整體的平衡。有意識地選擇,考慮長期後果。信任宇宙的正義,天秤最終會平衡一切。","soulReminder":"你的生命需要平衡才能和諧,就像天秤需要兩邊均等才能穩定。不要在一個領域過度投入而忽略其他。平衡不是靜止,而是動態的調整,持續地在不同需求之間找到中心。記住,你的行為有重量,你的選擇會影響平衡。活得正直、公正、和諧,你的心臟會輕如羽毛。宇宙的正義最終會實現,過度會被調整,不及會被補償。信任這個過程,尋求平衡,活在和諧中。天秤是你的指南,平衡是你的道路。","questions":"我的生活平衡嗎?哪些領域失衡?我如何恢復平衡?我的選擇有什麼重量?我活得公正嗎?我尋求和諧嗎?我的心臟輕如羽毛嗎?我如何找到中庸之道?","energyFocus":"將注意力放在識別並恢復平衡上。誠實地評估生活的每個領域,找出過度或不及的地方。做出必要的調整,增加或減少投入。尋求中庸之道,避免極端。在決策時考慮平衡,問這是否會創造更多和諧還是失衡。培養公正與公平,在所有關係與處境中。讓真理與正直指引你的選擇,這會讓你的心臟保持輕盈。信任宇宙的正義,保持平衡,活在和諧中。天秤是你的老師。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('egyptian_gods:36', 'egyptian_gods', '36', 35, '安卡 - 生命之鑰', 'The Ankh - Key of Life', NULL, '{"titleEn":"The Ankh - Key of Life","symbol":"☥ 十字架頂有環，生命之鑰"}', '{"godStory":"安卡是古埃及最重要的符號,形狀像一個十字架頂部有環。它代表生命、永恆、神聖的氣息與靈魂的不朽。它是開啟永生的鑰匙,神祇用它賦予生命與不朽。安卡也象徵著生命力、氣、普拉納,任何名稱的生命能量。它提醒我們,生命是神聖的禮物,而我們擁有接取無限生命力的鑰匙。安卡是所有符號中最powerful的,代表生命本身。","coreMeaning":"安卡代表生命、永恆、生命力、不朽、神聖氣息、生命能量、永生與存在的神聖性。這是關於連結生命的源泉,恢復生命力,慶祝存在本身。安卡教導我們,生命是神聖的禮物,我們是永恆的靈魂。它鼓勵我們接取無限的生命能量,活得充分而有活力,並且理解我們不只是暫時的身體,而是不朽的靈魂。安卡是最終的肯定:生命是神聖的,你是永恆的。","coreEnergy":"生命、永恆、不朽、生命力、能量、氣、活力、神聖、永生、存在、慶祝、肯定。安卡的能量是生命本身的能量,是最純粹、最強大的肯定。這是一種連結無限生命源泉、恢復活力、慶祝存在的能量。像鑰匙打開大門,安卡打開通往無限生命的通道。這是最神聖、最powerful的能量,是生命的essence。","guidance":"連結生命的源泉。如果你感到疲憊、失去活力或與生命失去連結,安卡是你的鑰匙。通過呼吸、冥想、自然接觸或任何讓你感覺活著的活動,重新連結生命力。安卡也是慶祝的邀請:慶祝你的存在,慶祝生命的奇蹟,慶祝每一次呼吸。你活著本身就是祝福。同時,安卡提醒你生命的永恆本質。你不只是這個身體,你是不朽的靈魂。這個認知能帶來平靜與自由。擁抱生命,活得充分。","soulReminder":"你是永恆的靈魂,暫居在暫時的身體中。你的本質是不朽的,超越生死。生命是神聖的禮物,每一次呼吸都是奇蹟。不要把生命視為理所當然,慶祝它、榮耀它、充分地活它。你有權利接取無限的生命力,你內在有通往永生的鑰匙。記住,你不只是活著,你是生命本身。你是安卡的化身,你是生命之鑰。活得充分,活得有活力,活得神聖。你的存在是宇宙的禮物,你是永恆的。","questions":"我連結生命力了嗎?我感到活著嗎?我慶祝我的存在嗎?我記得我的不朽性嗎?我充分地活著嗎?我如何能恢復活力?我的生命能量如何?我擁抱生命的神聖性嗎?","energyFocus":"將注意力放在生命本身上,連結你的生命力。進行深度呼吸練習,每一次呼吸都是生命的肯定。接觸自然,感受生命的脈動。做讓你感到活著的事,無論是運動、舞蹈、創作或愛。慶祝你的存在,每一天都是禮物。冥想你的不朽本質,超越身體識別自己為永恆的靈魂。接取無限的生命能量,它永遠available。活得充分、有活力、神聖。你是安卡,你是生命之鑰,你是永恆的。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:1', 'work_your_light', '1', 0, '永恆綻放的玫瑰', 'The Ever-unfolding Rose', NULL, '{"titleEn":"The Ever-unfolding Rose","suit":"確認牌"}', '{"coreMeaning":"被擊碎而敞開。生命的挑戰是在最想關閉心門時保持開放，讓生活將你擊碎並透過傷痛成長。事情是「為你」而生，而非「對你」而發。現在應溫柔對待自己，信任大地的守護。","actionGuidance":"一切都會好起來的。","inquiryPrompt":null,"activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌代表著心的開放與生命的綻放過程。就像玫瑰層層綻放一樣，你正經歷著心靈的蛻變與成長。即使在最艱難的時刻，也要保持心門敞開，因為每一次的傷痛都是靈魂成長的養分。生命正在透過各種經驗雕琢你，讓你成為更完整的自己。此刻你需要理解，所有發生的一切都是「為你」而來，而非「對你」而來，每個挑戰都是靈魂成長的契機。","higherSelfMessage":"你的高我正溫柔地提醒你：在脆弱中蘊含著最大的力量。當你允許自己被生命擊碎時，你實際上是在為更多的光進入你的存在創造空間。你的靈魂選擇了這條道路，因為它知道透過這些經歷，你將綻放出最美的光芒。請相信，每一次的碎裂都是為了讓你更加完整，每一次的開放都是為了讓你更深刻地體驗愛的本質。","spiritualGuidance":"現在是溫柔對待自己的時刻。給自己時間和空間去感受、去療癒、去整合所有的經驗。不要急於關閉心門或築起防護，因為真正的成長發生在你願意保持開放的時候。信任大地母親的守護,她正以無條件的愛支持著你。就像玫瑰需要陽光、雨露和時間才能綻放,你也需要給自己這樣的滋養。練習自我慈悲,允許自己在脆弱中找到力量。","energyQualities":"這張牌帶來溫柔而堅韌的能量,如同玫瑰般柔美卻不失力量。它的振動頻率與心輪共鳴,幫助你清理舊有的心靈創傷,開啟更深層的愛與接納能力。這是一種轉化的能量,將痛苦化為智慧,將封閉轉為開放。它喚醒你內在的女性能量,鼓勵你擁抱脆弱、敏感與直覺。這股能量如同春天的綻放,帶著重生與希望的訊息,提醒你生命永遠在更新。","suitableQuestions":"這張牌適合在你感到心碎、受傷或想要關閉心門時詢問。當你經歷重大失落、關係結束、或任何讓你感到脆弱的情況時,這張牌能給予深刻的指引。你可以問：「如何在痛苦中保持心的開放？」「這個經歷想教會我什麼？」「如何更溫柔地對待自己？」「我的心需要什麼樣的療癒？」這張牌也適合詢問關於自我接納、情感療癒、以及如何在脆弱中找到力量的問題。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:2', 'work_your_light', '2', 1, '不', 'No', NULL, '{"titleEn":"No","suit":"確認牌"}', '{"coreMeaning":"若某事不具一致性，勉強說「是」會耗盡能量。未收到清晰指引本身也是一種指引，現在可能是「等待期」，讓身體再生並讓宇宙代為籌備。","actionGuidance":"說不、延後或等待。","inquiryPrompt":null,"activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是神聖的拒絕之力，提醒你「不」也是一種深刻的靈性實踐。當你的內在沒有清晰的「是」時，勉強答應會造成能量的消耗與靈魂的不一致。這不是失敗或錯過機會，而是宇宙在保護你，讓你有空間等待真正與你共鳴的事物到來。沉默和等待本身就是一種行動，它讓你的能量場重新校準，讓宇宙有時間為你安排更好的可能性。此刻需要你信任「不知道」的智慧，允許生命在適當的時機揭示答案。","higherSelfMessage":"你的高我正在教導你神聖的界限與自我尊重。說「不」不是自私或缺乏勇氣，而是對自己靈魂真實需求的深度誠實。每一次你遵循內在的真實感受而拒絕時，你實際上是在為真正屬於你的事物創造空間。你的靈魂知道什麼是對的，當它保持沉默或給出「不」的訊號時，請相信這個智慧。不是所有的機會都是你的機會，不是所有的道路都是你的道路。學習辨識什麼是你的，什麼不是。","spiritualGuidance":"現在是練習神聖拒絕的時刻。給自己許可去說「不」、「還不是時候」或「讓我再想想」。不要因為他人的期待或社會的壓力而違背自己的內在真實。這段等待期是讓你的身體和能量場恢復的時間，讓宇宙重新校準並為你準備更合適的機會。信任神聖時機，相信當「是」來臨時，你會清楚知道。練習傾聽身體的訊號：緊縮感、沉重感、或缺乏熱情都是「不」的指標。同時，也要給自己空間去休息和再生。","energyQualities":"這張牌帶來保護與界限的能量，如同一道神聖的屏障守護著你的能量場。它的振動頻率幫助你建立健康的界限，清理掉那些不屬於你的能量與責任。這是一種回收能量的力量，將你從過度付出、取悅他人或違背自我的模式中解放出來。它喚醒你內在的辨識力，讓你能夠清晰地感知什麼與你共鳴，什麼不與你共鳴。這股能量如同休耕的土地，在表面的靜止下進行著深層的更新與準備。","suitableQuestions":"這張牌適合在你面臨需要做決定但內心不清晰時詢問。當你感到被壓力推動、他人期待你給出答案、或你不確定某個機會是否適合你時，這張牌能給予指引。你可以問：「現在說不是對的嗎？」「我需要等待多久？」「如何辨識什麼是真正適合我的？」「我的界限在哪裡？」「這個機會真的屬於我嗎？」這張牌也適合詢問關於休息、能量管理、以及如何在壓力下保持真實的問題。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:3', 'work_your_light', '3', 2, '是', 'Yes', NULL, '{"titleEn":"Yes","suit":"確認牌"}', '{"coreMeaning":"這是最清晰的肯定信號。宇宙正在為你的決定開啟綠燈，不要過度思考或質疑，現在就是前進的時刻。","actionGuidance":"不要過度思考，直接說是。","inquiryPrompt":null,"activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是宇宙給你最清晰的綠燈信號，代表天時地利人和已經齊備。這不是需要你過度分析或等待更多證據的時候，而是需要你信任直覺並採取行動的時刻。宇宙正在為你的決定背書，所有的能量都在支持你前進。你已經做了足夠的準備，已經等待了足夠的時間，現在就是躍入未知、展開行動的完美時機。過度思考只會阻礙你接收這份宇宙的祝福，信任這個「是」並勇敢地說出來、做出來。","higherSelfMessage":"你的高我正在慶祝這個時刻，因為你已經準備好了。所有的懷疑、猶豫和恐懼都只是頭腦的噪音，你的靈魂已經知道答案，它在大聲地說「是」。這是你與宇宙校準的時刻，當你說「是」時，整個宇宙都會回應你的決定並為你鋪路。不要讓過去的失敗或恐懼阻止你擁抱這個機會。你的高我看見了這個選擇將帶你走向的美好未來，它正在催促你跨出這一步。這是信任的躍進，是對生命說「是」，也是對你自己說「是」。","spiritualGuidance":"現在是行動的時刻。放下所有的「如果」和「但是」，單純地跟隨這股清晰的推動力。你的身體會感到擴張、興奮、或深沉的平靜—這些都是「是」的訊號。不要等待完美的計畫或所有細節都就位，因為行動本身會帶來下一步的指引。宇宙正在打開一扇門，你只需要走進去。信任這個過程，相信即使你看不到全貌，每一步都會在適當的時候顯現。慶祝這個時刻，感謝宇宙的支持，然後勇敢地前進。","energyQualities":"這張牌帶來強大的推動與顯化能量，如同順風推動著帆船前進。它的振動頻率與宇宙的流動完全一致，消除阻礙並開啟通道。這是一種擴張的能量，讓你感到充滿可能性與信心。它喚醒你內在的勇氣與決心，給你力量去跨越恐懼的門檻。這股能量如同春天的種子破土而出，帶著生命力與不可阻擋的動能，它告訴你：是時候了，現在就是了，不要再等待。","suitableQuestions":"這張牌適合在你需要最終確認、想知道某個決定是否正確時詢問。當你已經感受到內在的推動但還需要外在的驗證、或者你在兩個選擇之間猶豫不決時，這張牌能給予清晰的答案。你可以問：「這個決定對我來說是對的嗎？」「現在是行動的時機嗎？」「我應該接受這個機會嗎？」「這條路會帶我走向我的最高善嗎？」「我準備好了嗎？」這張牌是最直接的肯定與祝福。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:4', 'work_your_light', '4', 3, '你已經在做了', 'You''re Already Doing It', NULL, '{"titleEn":"You''re Already Doing It","suit":"確認牌"}', '{"coreMeaning":"不要過度質疑，你正走在正確的軌道上且進度完美。地基已穩固，僅需信任並持續前行。停止過度思考，持續面向你的真北方向。","actionGuidance":"你已經在做了，繼續前進。","inquiryPrompt":null,"activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是深刻的肯定與確認，告訴你不要因為看不見立即的成果而懷疑自己。你正走在正確的道路上，即使進展看似緩慢或不明顯，每一個小步驟都在為更大的顯化奠定基礎。你的內在工作、每日的實踐、持續的努力都沒有白費，它們正在創造深層而持久的轉變。這不是需要你改變方向或加快速度的時候，而是需要你信任過程並保持穩定前進的時刻。你的靈魂已經知道目的地，你的工作就是持續朝向你的真北方向走，不要被干擾或懷疑拉離軌道。","higherSelfMessage":"你的高我正在為你鼓掌，因為你正在做著對的事情。即使你感到不確定或看不見全貌，你的每一個選擇、每一個行動都在與你的靈魂使命對齊。不要用外在的標準或他人的時間表來衡量你的進展，因為你正在建造的是深層而扎實的基礎，而非表面的快速成就。你的高我看見了你的努力，看見了你在不確定中仍然堅持的勇氣。繼續信任你的直覺，繼續做你知道是對的事，時候到了，一切都會水到渠成。你已經在做了，只需要持續下去。","spiritualGuidance":"現在是停止過度分析和自我懷疑的時刻。你已經收到了指引，你已經在行動，不需要更多的外在確認或證明。給自己許可去信任你已經走過的路，信任你已經做出的選擇。繼續你的日常實踐，繼續朝向你的願景前進，不要因為看不見立即的結果而氣餒。真正的成長發生在你看不見的地方—在你的意識深處、在你的能量場中、在你與宇宙的連結裡。保持耐心，保持一致性，保持對你真北方向的專注。慶祝你已經走到這裡，然後繼續前進。","energyQualities":"這張牌帶來穩定與確認的能量，如同大地般扎實可靠。它的振動頻率消除懷疑與焦慮，帶來深沉的信任感與內在的確定性。這是一種累積的能量，提醒你每一個小步驟都在建構更大的整體。它喚醒你內在的韌性與毅力，讓你能夠在不確定中保持方向。這股能量如同羅盤始終指向北方，無論外在環境如何變化，它都幫助你保持與你真實道路的連結，給你力量繼續前行。","suitableQuestions":"這張牌適合在你感到懷疑、不確定自己是否走在正確道路上時詢問。當你努力了一段時間但看不見明顯成果、或者你在質疑自己的選擇和方向時，這張牌能給予深刻的肯定。你可以問：「我正走在正確的道路上嗎？」「我的努力有在產生效果嗎？」「我應該繼續這個方向嗎？」「我需要改變什麼嗎？」「我的進展如何？」這張牌是對你持續努力最溫柔的肯定與鼓勵。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:5', 'work_your_light', '5', 4, '調整你的生活', 'Align Your Life', NULL, '{"titleEn":"Align Your Life","suit":"詢問牌"}', '{"coreMeaning":"我們是循環的生命，不斷在進化。此牌要求你放下舊有的定義（工作、關係、面具），勇敢踏入你真正想成為的人。","actionGuidance":null,"inquiryPrompt":"生活中什麼是不協調的或需要改變？","activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是靈魂進化的召喚，提醒你生命是一個不斷蛻變的過程。你已經不再是過去的那個人，繼續穿著不合身的衣服只會限制你的成長。無論是工作角色、關係模式、或是你對自己的定義，如果它們已經不再與你的真實本質共鳴，就是時候放手了。這不是失敗，而是進化。你的靈魂正在呼喚你踏入更真實、更完整的版本，即使這意味著要離開熟悉的安全區。不協調會以疲憊、沮喪、或內在衝突的形式顯現，這些都是你的靈魂在告訴你：是時候調整了。","higherSelfMessage":"你的高我看見了你真正的潛能，它知道你可以成為什麼。當你感到不協調或不自在時，那是因為你的外在生活與內在真實之間存在落差。不要害怕釋放那些不再服務你的人事物，即使它們曾經很重要。你不是在背叛過去，而是在榮耀你的成長。每一次的蛻變都需要勇氣，但你的高我知道你已經準備好了。它正在邀請你卸下所有的面具和防護，真實地活出你是誰。這不是自私，這是對你靈魂使命的忠誠。","spiritualGuidance":"現在是誠實檢視你生活的時刻。問自己：什麼讓我感到沉重？什麼讓我覺得需要裝扮或偽裝？哪些承諾是出於責任而非喜悅？你的身體會告訴你答案—注意那些讓你感到收縮、疲憊或失去生命力的事物。這張牌邀請你有意識地重新安排你的生活，讓它反映出現在的你，而非過去的你。這可能意味著改變職業、重新定義關係、或單純地改變你的日常習慣。給自己許可去實驗，去探索什麼能讓你感到真正的活力。信任這個調整過程，即使它帶來不確定性。","energyQualities":"這張牌帶來轉化與重組的能量，如同蝴蝶破繭而出的過程。它的振動頻率幫助你釋放舊有的身份認同，創造空間迎接新的可能性。這是一種淨化的能量，清除那些不再與你共鳴的模式、信念和關係。它喚醒你內在的真實性，給你勇氣去活出你真正的樣子。這股能量如同季節的更替，提醒你改變是自然且必要的，抗拒只會帶來痛苦，而順應則會帶來自由。","suitableQuestions":"這張牌適合在你感到生活某些部分不再適合你時詢問。當你經歷身份認同的轉變、考慮重大生活改變、或感到內在與外在不一致時，這張牌能給予深刻的指引。你可以問：「我生活的哪些部分需要調整？」「什麼不再服務我的最高善？」「我準備好釋放什麼？」「如何更真實地活出自己？」「我的下一步進化是什麼？」「哪些承諾需要重新評估？」這張牌幫助你辨識並執行必要的改變。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:6', 'work_your_light', '6', 5, '回應召喚', 'Answer the Call', NULL, '{"titleEn":"Answer the Call","suit":"詢問牌"}', '{"coreMeaning":"回應靈魂的渴望可能是恐懼或不合邏輯的，但這將帶領你超越想像。你不需要知道完整計畫，只需踏出下一步。","actionGuidance":null,"inquiryPrompt":"你的靈魂正召喚你去做什麼？","activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是靈魂深處的呼喚，那個你一直聽見但可能選擇忽略的聲音。你的靈魂知道它為何來到這裡，它有著獨特的使命和渴望。這個召喚可能看起來不切實際、不合邏輯、或讓人恐懼，但那正是它的真實性證明—因為它來自你的靈魂而非頭腦。你不需要知道整條路徑，不需要有完美的計畫，你只需要有勇氣踏出下一步。宇宙會在你開始行動後展現下一個步驟，但你必須先證明你願意回應這個召喚。拖延和等待只會讓這個聲音變得更大聲，直到你無法再忽視。","higherSelfMessage":"你的高我正在發出這個召喚，它知道你來這裡不是為了過安全但無趣的生活。你的靈魂渴望表達、創造、服務、或以某種方式貢獻這個世界。不要讓恐懼或他人的意見淹沒這個聲音。你可能覺得自己還沒準備好，但事實是，你永遠不會「完全」準備好去做那些真正重要的事。完美的時機就是現在，因為你的靈魂已經等待夠久了。回應這個召喚會帶你走向你無法預見的可能性，但你必須信任這個過程。你的高我承諾，這條路雖然可能充滿挑戰，但它會帶給你深刻的滿足與意義。","spiritualGuidance":"現在是傾聽的時刻。在安靜中問自己：我的靈魂真正渴望什麼？如果沒有恐懼，我會做什麼？什麼讓我感到真正的活著？這些問題的答案就是你的召喚。不要試圖用邏輯去評估它，因為靈魂的語言超越理性。開始採取小步驟—你不需要立刻辭職或做出劇烈改變，但你需要開始朝那個方向移動。可能是報名一個課程、開始一個創意專案、或單純地每天花時間與那個渴望連結。每一個小行動都在告訴宇宙你是認真的，而宇宙會回應你的承諾。","energyQualities":"這張牌帶來召喚與使命的能量，如同遠方的鐘聲在你心中迴響。它的振動頻率喚醒你靈魂深處的記憶，提醒你為何選擇這一生。這是一種啟動的能量，點燃你內在的熱情與目的感。它打破慣性與舒適區，推動你朝向你的命定前進。這股能量如同磁鐵般吸引你，即使你試圖抗拒，它仍會持續呼喚。它帶著急迫性但不是焦慮，而是一種深沉的知曉：是時候了，你必須回應。","suitableQuestions":"這張牌適合在你感受到內在的不安或渴望但不知道如何行動時詢問。當你在靈魂使命與實際考量之間掙扎、或你知道需要做某事但恐懼阻止你時，這張牌能給予指引。你可以問：「我的靈魂召喚是什麼？」「我下一步應該做什麼？」「如何克服恐懼並回應這個召喚？」「這個渴望是真實的還是幻想？」「我的生命目的是什麼？」「宇宙在邀請我做什麼？」這張牌幫助你辨識並勇敢回應你的靈魂呼喚。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:7', 'work_your_light', '7', 6, '邊界', 'Boundaries', NULL, '{"titleEn":"Boundaries","suit":"詢問牌"}', '{"coreMeaning":"說「不」與建立邊界實際上是一種靈性行為，最慈悲的人通常擁有最清晰的邊界。可透過「直覺（腹部）」來感受什麼對你是可以的。","actionGuidance":null,"inquiryPrompt":"生活中哪裡需要建立更好的邊界？","activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌揭示了一個深刻的靈性真理：界限不是冷漠或自私，而是自愛與尊重的表現。最慈悲、最有愛的人往往有著最清晰的界限，因為他們知道過度付出會耗盡自己，最終無法真正服務任何人。你的身體—特別是你的腹部—會告訴你什麼是對的、什麼是不對的。當你感到緊縮、沉重或不舒服時，那是你的內在羅盤在說「不」。學習尊重這些訊號不是軟弱，而是對自己能量的深度負責。沒有健康的界限，你會成為他人能量的垃圾桶，最終失去自己。","higherSelfMessage":"你的高我正在教導你神聖的自我保護。說「不」不會讓你成為壞人，它只是讓你成為一個誠實的人。你不需要拯救每個人、參加每個活動、或回應每個要求。你的能量是寶貴的資源，需要被明智地使用。當你建立清晰的界限時，你實際上是在教導他人如何對待你，也在為真正重要的關係創造更健康的空間。你的高我知道，你不能從空杯中倒出水來。照顧好自己不是自私，而是讓你能夠以更高的品質服務他人。學習說不，是學習對自己說是。","spiritualGuidance":"現在是檢視你界限的時刻。問自己：我在哪裡過度給予？我在哪裡說「是」但內心在吶喊「不」？誰或什麼正在耗盡我的能量？開始練習用你的身體作為指引—當面對一個請求或邀請時，閉上眼睛，感受你的腹部。擴張感、溫暖感、或平靜感表示「是」；緊縮感、沉重感、或不適感表示「不」。不要試圖用頭腦說服自己違背這些訊號。開始小步驟地實踐界限—可能是拒絕一個不想參加的活動，或告訴某人你需要空間。每一次你尊重自己的界限，你都在建立更強大的自我尊重。","energyQualities":"這張牌帶來保護與主權的能量，如同一道神聖的光牆守護著你的空間。它的振動頻率幫助你辨識什麼是你的，什麼不是你的，並給你力量捍衛這條界線。這是一種回收的能量，將你從能量吸血鬼和不健康的動態中解放出來。它喚醒你內在的尊嚴與自我價值，讓你明白你不需要為了被愛而犧牲自己。這股能量如同堅固的容器，它不是隔離你，而是創造一個安全的空間讓你的真實自我茁壯。","suitableQuestions":"這張牌適合在你感到被侵犯、過度負擔、或失去自我時詢問。當你發現自己總是在照顧他人但忽視自己的需求、或你不知道如何拒絕時，這張牌能給予指引。你可以問：「我需要在哪裡建立界限？」「如何在不感到內疚的情況下說不？」「我的能量被誰或什麼耗盡了？」「如何保護我的能量場？」「什麼是健康的界限？」「我如何尊重自己的需求？」這張牌教導你神聖的自我保護藝術。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:8', 'work_your_light', '8', 7, '崩解', 'The Crumbling', NULL, '{"titleEn":"The Crumbling","suit":"詢問牌"}', '{"coreMeaning":"任何不真實的事物都無法生存，崩解是為了帶你回歸真實的自我。停止試圖維持現狀，讓該倒塌的倒下。","actionGuidance":null,"inquiryPrompt":"你因為害怕沒有替代品而死命抓著什麼不放？","activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌標誌著必要的瓦解過程—那些不真實、不穩固、或不與你靈魂對齊的事物正在崩塌。這可能感覺像是失敗或災難，但實際上這是宇宙在為你清理空間，讓真實的、持久的事物得以誕生。你可能一直在努力維持某個關係、工作、或生活方式，但內心深處你知道它已經不再適合你。崩解是生命在告訴你：放手吧，停止抗拒。只有建立在真實基礎上的事物才能生存，而那些建立在恐懼、責任或虛假期待上的，注定要崩塌。這是痛苦的，但也是解放的。","higherSelfMessage":"你的高我正在協調這個崩解過程，即使你的人格自我感到恐慌。你一直抓著某些事物不放，不是因為它們讓你快樂，而是因為你害怕失去後的空虛。但你的高我知道，只有清空舊的，新的才能進來。這個崩解不是懲罰，而是祝福—它在釋放你，讓你自由。信任這個過程，即使它感覺像是一切都在瓦解。有時候，最大的療癒看起來像是毀滅。讓不真實的倒下，讓虛假的剝落，讓不屬於你的離開。在廢墟中，你會發現你真實的基礎，那才是值得建造的。","spiritualGuidance":"現在是臣服的時刻。停止試圖用膠帶和繩子把崩塌的東西綁在一起。問自己：我為什麼這麼害怕放手？我真正害怕失去的是什麼？往往我們抓著的不是事物本身，而是它們代表的安全感、身份認同或未來想像。但如果某個東西需要這麼多努力才能維持，它可能本來就不屬於你。給自己許可去哀悼，去感受失落，但不要試圖阻止這個過程。信任在清空之後，更真實、更美好的事物會來到。這是你的靈魂在重新校準，讓你的生活與你的真實本質對齊。擁抱這個混亂，因為它是重生前的必經之路。","energyQualities":"這張牌帶來瓦解與釋放的能量，如同暴風雨掃除一切不穩固的結構。它的振動頻率打破舊有的模式、執著和虛假的安全感。這是一種淨化的力量，雖然破壞性但最終是療癒性的。它揭露真相，移除面具，讓你看見什麼是真實的。這股能量如同森林大火，雖然摧毀了舊的生態，但也為新生命創造了肥沃的土壤。它要求完全的誠實與臣服，不接受任何妥協或逃避。","suitableQuestions":"這張牌適合在你經歷重大失落、結束或轉變時詢問。當某個情況正在瓦解、你試圖維持但感到筋疲力盡、或你知道需要放手但恐懼阻止你時，這張牌能給予深刻的視角。你可以問：「這個崩解想教我什麼？」「我為什麼抓著不放？」「如何在失落中找到意義?」「什麼需要倒下？」「如何信任這個過程？」「崩解後會有什麼？」這張牌幫助你在混亂中找到意義與方向。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:9', 'work_your_light', '9', 8, '不要為了融入而黯淡', 'Don''t Dim to Fit in', NULL, '{"titleEn":"Don''t Dim to Fit in","suit":"詢問牌"}', '{"coreMeaning":"擴張是宇宙的天性，你也是。不要為了配合別人的狹隘而退縮；若有人讓你感到不適，請慢慢遠離。","actionGuidance":null,"inquiryPrompt":"你正如何為了融入而黯淡自己的光芒？","activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是對你真實本質的強力肯定—你天生就是明亮的、強大的、獨特的。宇宙的本質就是擴張與成長，你也一樣。當你因為他人的不適、嫉妒或批判而縮小自己時，你不只是在背叛自己，也在違背宇宙的法則。你的光芒不是為了取悅他人而存在，而是為了照亮你的道路。如果有人因為你的光而感到不舒服，那不是你的問題，那是他們與自己的關係需要療癒。你的工作不是讓所有人都喜歡你，而是真實地活出你的本質，吸引那些真正欣賞你的人。","higherSelfMessage":"你的高我正在提醒你：你來到這裡不是為了隱藏。你的靈魂選擇了這個身體、這個時代、這些天賦，因為它有重要的工作要做。每當你為了融入而黯淡自己，你就在剝奪世界你獨特的貢獻。你的高我知道，真正的歸屬感不是來自於迎合他人，而是來自於完全接納自己。當你允許自己完全閃耀時，你給予他人許可去做同樣的事。你的光不會威脅到對的人，它只會吸引他們靠近。停止擔心會不會太多、太亮、太響亮，開始擔心你是否誠實地活著。","spiritualGuidance":"現在是檢視你在哪裡妥協自己的時刻。問自己：我在誰面前會縮小自己？我隱藏了什麼天賦或特質因為害怕批評？我為了被接納而放棄了什麼？注意那些讓你感到需要隱藏或假裝的關係和環境，它們可能不是你真正的部落。開始小步驟地展現更多的真實—分享你真正的想法、穿你想穿的衣服、做你真正想做的事。是的，有些人可能會離開，但這會為真正欣賞你的人創造空間。記住：你不是為了每個人而來，你是為了那些準備好接收你光芒的人而來。","energyQualities":"這張牌帶來解放與賦權的能量，如同打破束縛的鎖鏈。它的振動頻率溶解羞愧、內疚和不配得感，喚醒你內在的驕傲與自信。這是一種擴張的力量，鼓勵你佔據更多空間、說出更大的聲音、展現更亮的光芒。它連結你與你的真實本質，讓你記起你是誰。這股能量如同太陽，不會因為他人的不適而減弱，它只是持續地照耀，讓那些準備好的人得到溫暖與光明。","suitableQuestions":"這張牌適合在你感到需要隱藏、縮小或妥協自己時詢問。當你在某些人或環境中感到不自在、或你因為害怕批評而不敢展現真實的自己時，這張牌能給予力量。你可以問：「我在哪裡黯淡了自己？」「我為了誰而隱藏？」「如何更勇敢地展現真實的自己？」「我的光芒想如何表達？」「誰才是我真正的部落？」「如何處理他人的批評？」這張牌鼓勵你完全地、不加修飾地活出你的真實。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:10', 'work_your_light', '10', 9, '鏡子', 'Mirror', NULL, '{"titleEn":"Mirror","suit":"詢問牌"}', '{"coreMeaning":"人與情境會反映出我們對生命、宇宙與自我的信念。這包括觸發你陰影的人，以及你所仰慕但未意識到自己也擁有的光芒。","actionGuidance":null,"inquiryPrompt":"誰或什麼正在觸發你？它觸發了你內在的什麼部分？","activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌揭示了一個深刻的靈性法則：外在世界是你內在世界的反映。你遇見的每個人、經歷的每個情境，都在某種程度上映照出你對自己、對生命、對宇宙的信念。這包括那些觸發你憤怒或痛苦的人—他們往往反映出你尚未療癒的傷口或未接納的陰影。但這也包括你所仰慕的人—他們展現的品質其實你也擁有，只是你可能還沒有意識到或允許自己展現。這張牌邀請你停止向外投射，開始向內探索：這個人或情境在告訴我什麼關於我自己的事？","higherSelfMessage":"你的高我正在使用鏡子法則來幫助你成長。當某人或某事強烈觸發你時，那不是巧合，那是你的靈魂在說：「看這裡，這是你需要療癒的地方。」你的高我知道，外在的改變是有限的，真正的轉化發生在內在。當你開始為自己的投射負責，當你停止把責任歸咎於他人，你就收回了你的力量。同時，當你在他人身上看見你欣賞的品質時，那也是一面鏡子—它在提醒你這些品質也存在於你之內。你的工作是認領它，允許它在你的生命中綻放。","spiritualGuidance":"現在是深入反思的時刻。想想最近誰或什麼觸發了你？他們展現的行為或特質是什麼？然後問自己：我在哪裡也有這個特質（即使是以不同形式）？我在批判他人的什麼，其實是我無法接納自己的什麼？這需要極大的誠實與勇氣，因為承認我們的陰影並不容易。但這也是最深刻的療癒工作。同時，也注意你所仰慕的人。他們展現的品質—勇氣、創造力、智慧、愛—也存在於你之內。給自己許可去培養和展現這些品質。外在世界只是鏡子，真正的工作在裡面。","energyQualities":"這張牌帶來覺察與整合的能量，如同打開內在的探照燈。它的振動頻率幫助你看見過去看不見的盲點，認出你的投射與陰影。這是一種統整的力量，將分裂的部分帶回完整，將排斥的特質帶入接納。它喚醒你的自我覺察能力，讓你能夠在觸發發生時立即辨識。這股能量如同鏡子，不加評判地反映真相，給你機會看見並療癒你內在的碎片。","suitableQuestions":"這張牌適合在你被某人或某情境強烈觸發時詢問。當你發現自己不斷遇到相似的問題或人際模式、或者你對某人有強烈的情緒反應時，這張牌能提供深刻的洞見。你可以問：「這個人在反映我什麼？」「這個情境想教我什麼？」「我的陰影是什麼？」「我投射了什麼在他人身上？」「我在他人身上看見的品質，如何也存在於我之內？」「我需要整合什麼？」這張牌幫助你轉化觸發為成長的機會。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:11', 'work_your_light', '11', 10, '女祭司', 'Priestess', NULL, '{"titleEn":"Priestess","suit":"詢問牌"}', '{"coreMeaning":"女祭司是致力於服務、自由與領導的老師。你不需要完美才能領導，分享你的故事就能照亮他人的路。","actionGuidance":null,"inquiryPrompt":"你正如何被召喚去站出來並領導？","activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是領導力與服務的召喚，提醒你不需要完美才能引領他人。女祭司的本質是透過真實的經驗來教導，而非理論或理想化的形象。你走過的路、經歷的痛苦、學到的智慧，都是珍貴的禮物，可以照亮他人的道路。當你分享你的故事—包括失敗、掙扎和勝利—你給予他人許可去擁抱自己的不完美。真正的領導不是關於站在高處指導，而是關於站在人群中說：「我也經歷過，讓我告訴你我學到了什麼。」你已經擁有你需要的一切來服務他人，現在只是需要勇氣站出來。","higherSelfMessage":"你的高我正在召喚你進入領導的角色，但不是你想像中那種完美無瑕的領導。真正的女祭司知道她的力量來自於她的人性，而非她的神性。你的傷疤、你的故事、你的真實，這些才是你最大的教學工具。你的高我看見了那些正在等待你的智慧的人，他們需要的不是另一個完美的導師，而是一個真實的人來告訴他們：「你可以的，因為我也做到了。」停止等待直到你「夠好」才去分享，因為你的不完美正是你的禮物。現在就開始領導，透過你的真實存在。","spiritualGuidance":"現在是勇敢可見的時刻。問自己：我有什麼經驗或智慧可以幫助他人？我的故事能如何照亮他人的路？開始小步驟地分享—可能是在社群媒體上寫下你的經驗，與朋友分享你的洞見，或開始教導你所知道的。不要等待完美的資格或認證，你的生活經驗就是你的證書。同時，記住領導與自由是並存的—你可以設定界限，你可以選擇你想服務的人，你可以以你自己的方式領導。女祭司的自由來自於她對真實的承諾，而非對完美的追求。","energyQualities":"這張牌帶來主權與服務的能量，如同點燃他人道路的火炬。它的振動頻率喚醒你內在的教師與領導者，給你勇氣分享你的真相。這是一種賦權的能量，不只賦權你，也賦權所有接觸到你的人。它連結你與古老的女性智慧傳統，提醒你領導是一種神聖的服務。這股能量如同橋樑，連結你的經驗與他人的需要，讓你的痛苦轉化為他人的祝福。","suitableQuestions":"這張牌適合在你感受到分享或教導的召喚但懷疑自己是否夠格時詢問。當你有重要的經驗或智慧但不確定如何分享、或你在考慮進入領導角色但感到不配時，這張牌能給予指引。你可以問：「我被召喚去教導什麼？」「如何分享我的故事？」「我的經驗能如何服務他人？」「如何在領導中保持自由？」「我準備好站出來了嗎？」「什麼阻止我領導？」這張牌鼓勵你透過真實的分享來領導。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:12', 'work_your_light', '12', 11, '星際母親', 'Star Mother', NULL, '{"titleEn":"Star Mother","suit":"詢問牌"}', '{"coreMeaning":"你比想像中更受支持與關愛。將你的遺憾、羞愧與內疚放在聖壇上，讓「母親」減輕你的負擔。","actionGuidance":null,"inquiryPrompt":"你可以如何「母愛」地對待自己？","activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是深刻的安慰與支持，提醒你即使在最孤單的時刻，你也從未真正孤單。宇宙母親—無論你稱呼她為地球、女神、或神聖母性—一直在守護著你，以無條件的愛包圍著你。你背負的遺憾、羞愧、內疚，這些沉重的負擔不是你需要獨自承擔的。這張牌邀請你做一個深刻的臣服動作：將這些重擔放在聖壇上，交給更大的力量來減輕。你不需要一直堅強，你不需要自己處理所有事情。有時候，最大的力量是允許自己被支持、被安慰、被母親般的愛擁抱。","higherSelfMessage":"你的高我正在提醒你：你是被深深愛著的。不是因為你的成就，不是因為你的完美，而是因為你存在。星際母親的愛是無條件的，她看見你所有的掙扎、所有的錯誤、所有的痛苦，而她的回應只有愛。你一直試圖自己撐著，試圖證明你夠強、夠好，但你的高我知道，真正的強大是知道何時放手，何時尋求支持。你不是孤獨的戰士，你是被愛包圍的孩子。允許自己接收這份愛，允許自己被滋養，允許自己休息在母親的懷抱中。","spiritualGuidance":"現在是放下的時刻。創造一個神聖的儀式：可以是在你的祭壇上放置代表你負擔的物品，可以是寫下你的遺憾然後燒掉，可以是單純地在冥想中將這些交給地球。當你這樣做時，說：「親愛的母親，我將這些交給你，我準備好被減輕負擔了。」然後深深地呼吸，感受重量從你的肩膀上滑落。同時，開始注意你生活中母性能量的存在—可能是大自然、可能是支持你的女性、可能是你對自己的溫柔。允許自己被滋養，被照顧，被愛。你值得這份支持。","energyQualities":"這張牌帶來滋養與安慰的能量，如同母親溫暖的擁抱。它的振動頻率溶解孤獨感與分離感，提醒你你是更大整體的一部分。這是一種接收的能量，教導你如何放下、臣服、允許自己被支持。它連結你與神聖母性的原型，無論是地球母親、宇宙母親或你內在的母性能量。這股能量如同療癒的泉水，洗滌你的羞愧與內疚，為你的心靈帶來平靜與接納。","suitableQuestions":"這張牌適合在你感到孤單、不被支持、或被羞愧與內疚壓垮時詢問。當你背負著過去的錯誤、或你覺得需要自己處理所有事情時，這張牌能帶來安慰與視角。你可以問：「如何釋放我的羞愧？」「我如何被支持著？」「如何接收愛與滋養？」「我需要放下什麼？」「母性能量想如何支持我？」「如何原諒自己？」這張牌提醒你你被深深愛著，你不孤單。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:13', 'work_your_light', '13', 12, '星際種子', 'Starseed', NULL, '{"titleEn":"Starseed","suit":"詢問牌"}', '{"coreMeaning":"星際種子是擁有雙重使命的古老靈魂：提升自身與星球的意識。你會感到時間緊迫，直到踏入你的召喚。","actionGuidance":null,"inquiryPrompt":"什麼點亮了你？","activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是對你靈魂起源的確認—你是來自星際的古老靈魂，帶著特殊的使命來到地球。星際種子往往感到與主流社會格格不入，有種深刻的「不屬於這裡」的感覺，但那不是問題，那是你獨特性的標記。你來這裡有雙重目的：一方面是你個人的靈性進化，另一方面是協助地球和人類意識的提升。這種使命感會讓你感到時間緊迫，彷彿有重要的事情在等著你做。這種不安不會消失，直到你開始踏入你的召喚。你的存在本身就在改變這個星球的頻率，但當你有意識地活出你的目的時，影響力會倍增。","higherSelfMessage":"你的高我記得你來自何處，記得你在投生前所做的承諾。這種記憶可能不是以畫面或語言存在，而是以深沉的知曉、無法解釋的渴望、或對某些主題的強烈共鳴形式呈現。你的高我正在提醒你：你選擇了這個挑戰性的時代來到地球，因為你有獨特的天賦和視角可以貢獻。你感到的孤獨感或異樣感不是缺陷，而是你來自不同星系意識的證明。不要試圖壓抑你的不同，而是要擁抱它、慶祝它、並用它來服務。世界需要你的星際視野，你的非傳統思維，你對更高可能性的記憶。","spiritualGuidance":"現在是認領你星際種子身份的時刻。問自己：什麼讓我感到真正的興奮？什麼主題或議題讓我感到深深的使命感？我對什麼有著「不合理」的熱情？這些問題的答案會指向你的特定使命。開始有意識地培養你的天賦—可能是療癒、教導、創造藝術、科技創新、或社會改革。不要試圖像其他人一樣，因為你的價值正在於你的不同。與其他星際種子連結也很重要—找到你的靈魂家族，那些能理解你的人。同時，保持與地球的連結，因為你的工作需要你紮根於此時此地。你的使命不在遙遠的未來，而是在當下每一個選擇中。","energyQualities":"這張牌帶來覺醒與記憶的能量，如同遙遠家鄉的呼喚在你心中迴響。它的振動頻率連結你與宇宙更廣闊的意識，提醒你你不只是這個身體、這個生命。這是一種擴展的能量，打開你對更高維度實相的感知。它喚醒你內在的星際記憶與智慧，給你力量活出你的獨特目的。這股能量如同星光，雖然來自遙遠的距離，但它的光芒清晰而明確，引導你走向你的命定。它帶著急迫性與使命感，推動你停止拖延並開始行動。","suitableQuestions":"這張牌適合在你感到與這個世界格格不入、尋找你的生命目的、或感受到強烈使命感但不知如何實現時詢問。當你對靈性覺醒、意識提升或地球轉化有深刻關注時，這張牌能提供指引。你可以問：「我的星際使命是什麼？」「如何活出我的目的？」「什麼點亮了我？」「我的天賦如何服務世界？」「我的靈魂家族在哪裡？」「如何平衡我的星際本質與地球生活？」這張牌確認你的星際起源並指引你的使命。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:14', 'work_your_light', '14', 13, '信任那小小的異樣感', 'Trust the Niggle', NULL, '{"titleEn":"Trust the Niggle","suit":"詢問牌"}', '{"coreMeaning":"那種不便、惱人的異樣感是直覺，透過感官傳遞振動訊息。若不現在面對，宇宙將拋出更巨大的障礙來提醒你。","actionGuidance":null,"inquiryPrompt":"那種異樣感正試圖告訴你什麼？","activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是關於信任那些微小但持續的直覺訊號。「異樣感」(niggle)是你的靈魂透過身體傳遞的訊息—那種揮之不去的不安、那個你試圖忽略的小聲音、那種「有什麼不對勁」的感覺。你的理性頭腦可能會說服你這沒什麼，但你的身體和靈魂知道真相。這些異樣感通常是早期警告系統，告訴你某事需要被注意或改變。如果你忽視這些訊號，宇宙會用更大、更難以忽視的方式來提醒你—可能是更大的危機、明顯的衝突、或無法避免的問題。學習在異樣感還小的時候就處理它，可以避免更大的崩潰。","higherSelfMessage":"你的高我正在透過這些異樣感與你溝通。它看見你理性頭腦看不見的東西，感知到能量層面的不對齊。當你感到這種異樣感時，那不是你的想像，不是你過度敏感，而是你的靈魂在說：「注意這裡。」你的高我知道，忽視這些訊號會讓你偏離你的道路，讓你陷入不必要的困難。學習辨識並尊重這些訊號是靈性成熟的標誌。不要等到情況變得明顯或嚴重才行動，因為你的靈魂已經給了你提前的警告。信任這些微妙的感知，即使你無法用邏輯解釋它們。你的直覺是你最可靠的導航系統。","spiritualGuidance":"現在是傾聽你身體和直覺的時刻。注意那些你一直試圖忽略的感覺—可能是關於某個人、某個情況、或某個決定。問自己：我最近有什麼揮之不去的不安？我一直告訴自己「沒什麼大不了」的是什麼？我的身體在什麼時候會緊縮或不舒服？這些都是異樣感的表現。不要等待更多的「證據」或試圖用邏輯說服自己。如果感覺不對，就是不對。採取行動來處理這個異樣感—可能是進行一次誠實的對話、做出改變、或單純地承認這個感覺。越早處理，需要的調整就越小。練習說：「有些事感覺不對，我需要探索這個。」","energyQualities":"這張牌帶來警覺與辨識的能量，如同敏銳的雷達偵測微弱的訊號。它的振動頻率增強你的直覺敏感度，幫助你注意到微妙但重要的不對齊。這是一種保護的能量，像早期警告系統一樣守護你。它喚醒你內在的智慧，讓你能夠在問題還小的時候就辨識出來。這股能量如同指南針，當你偏離真實道路時它會發出訊號，提醒你重新校準。它要求你信任感覺而非只依賴邏輯，因為真理往往先透過身體被感知。","suitableQuestions":"這張牌適合在你有某種揮之不去的不安或直覺但不確定是否該信任時詢問。當你感到某事「怪怪的」但說不出具體原因、或你在理性與直覺之間掙扎時，這張牌能給予確認。你可以問：「這個異樣感在告訴我什麼？」「我應該信任這種感覺嗎？」「我一直忽略什麼訊號？」「如何處理這個不安？」「我的直覺想讓我看見什麼？」「這個感覺是恐懼還是智慧？」這張牌鼓勵你在小問題變大之前就處理它們。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:15', 'work_your_light', '15', 14, '信任你的道路', 'Trust Your Path', NULL, '{"titleEn":"Trust Your Path","suit":"詢問牌"}', '{"coreMeaning":"宇宙正與你共謀，你的職責是面向真北並一步步前行。不要試圖微操宇宙，讓靈魂帶路。","actionGuidance":null,"inquiryPrompt":"若你知道自己無論如何都會受支持，你會做什麼？","activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是對神聖信任的深度邀請—信任你的道路、信任時機、信任宇宙正在為你工作而非對抗你。你不需要看見整條路才能開始走，你不需要知道所有的答案才能踏出下一步。你的工作只是面向你的真北（你內在的真實方向），然後一步一步前進。宇宙會在你行動時展現下一步，但它不會提前給你完整的地圖。試圖控制或微操每個細節只會讓你耗盡能量並錯過自然展開的魔法。讓你的靈魂帶路，而非你的恐懼或頭腦。當你與你的真實道路對齊時，同步性、機會和支持會自然出現。","higherSelfMessage":"你的高我正在邀請你放下控制，進入更深的信任。你一直試圖確保每個步驟都「正確」，試圖避免所有可能的錯誤，但這種過度控制實際上在阻礙你的流動。你的高我知道計畫，即使你的人格自我不知道。你的工作不是策劃每個細節，而是保持與你真實道路的連結，然後信任過程。你無法搞砸你的命運，因為每個「錯誤」都是學習的一部分。宇宙確實在與你共謀，為你的最高善工作。當事情「出錯」時，往往是宇宙在重新導向你到更好的方向。放鬆掌控，信任你的靈魂知道要去哪裡。","spiritualGuidance":"現在是練習臣服與信任的時刻。問自己：我在哪裡試圖過度控制？我在擔心什麼「如果」？我如何能更多地信任而非更多地計畫？開始實驗放下控制—做決定時少用頭腦分析，多用內在感覺；當事情沒按計畫走時，好奇它可能帶你去哪裡而非抗拒；當你不知道下一步時，停留在「不知道」而非焦慮地尋找答案。注意那些同步性—「巧合」、意外的相遇、突然的靈感—它們是宇宙在告訴你你走在對的路上。每天問自己：「若我知道自己無論如何都會受支持，我會做什麼？」然後勇敢地做那件事。","energyQualities":"這張牌帶來臣服與流動的能量，如同順著河流而下而非逆流而上。它的振動頻率溶解焦慮與過度控制，帶來深沉的信任與平靜。這是一種開放的能量，讓宇宙的支持能夠流向你。它喚醒你內在的信心，讓你明白你不需要獨自承擔一切。這股能量如同風帆，當你放鬆並調整方向時，它會捕捉宇宙的風並推動你前進。它教導你順應而非強迫，信任而非控制，允許而非堅持。","suitableQuestions":"這張牌適合在你感到焦慮、想要控制結果、或不確定是否走在對的路上時詢問。當你過度計畫、擔心未來、或試圖確保每個細節都完美時，這張牌能帶來放鬆與視角。你可以問：「我應該信任這個過程嗎？」「如何放下控制？」「我走在對的路上嗎？」「宇宙想帶我去哪裡？」「如何更多地臣服？」「若我完全被支持，我會做什麼？」這張牌是對神聖時機與宇宙支持的深度肯定。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:16', 'work_your_light', '16', 15, '戰士女子', 'Warrior Woman', NULL, '{"titleEn":"Warrior Woman","suit":"詢問牌"}', '{"coreMeaning":"活出由心引導的生活需要勇氣戰勝恐懼，而恐懼往往是守門人，背後藏著天賦。","actionGuidance":null,"inquiryPrompt":"你是否已回應了你最深處的召喚？","activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是戰士精神的化身—不是暴力或攻擊性的戰士，而是那種願意面對恐懼、勇敢活出真實的戰士。活出由心引導的生活需要巨大的勇氣，因為它往往意味著要違背社會期待、他人意見、甚至你自己的舒適區。恐懼會出現在每個重要的門檻前，但這不是要你停下來的信號，而是告訴你你正走向重要事物的指標。恐懼往往是守門人，守護著你最大的天賦與潛能。你越恐懼的事情，往往越接近你的召喚。戰士女子的勇氣不是沒有恐懼，而是感到恐懼仍然前進，因為她知道她的召喚比她的舒適更重要。","higherSelfMessage":"你的高我正在召喚你的內在戰士醒來。你一直在用安全、謹慎、等待來保護自己，但你的靈魂渴望更多。它渴望你勇敢地活出你的真相，即使這意味著被誤解或批評。你的高我知道，你最深的召喚—那個讓你同時興奮又恐懼的夢想—正在等著你的回應。這不是未來某天的事，而是現在。每一天你選擇安全而非真實，你就在背叛你的靈魂一點點。戰士女子不是等到不再害怕才行動，她是感到恐懼仍然跨出去，因為她的承諾比她的恐懼更大。你的高我在問你：你準備好回應你最深處的召喚了嗎？","spiritualGuidance":"現在是勇敢行動的時刻。辨識你最深的召喚—那個你一直推遲、合理化或告訴自己「還沒準備好」的夢想或行動。問自己：如果我有無限的勇氣，我會做什麼？什麼讓我既興奮又恐懼？我一直在逃避什麼召喚？然後，不是等到恐懼消失，而是與恐懼同行。開始採取行動，即使是很小的一步。每一次你選擇勇氣而非舒適，你就在強化你的內在戰士。記住，戰士不是獨自戰鬥—召喚你的靈魂力量、你的靈性盟友、你的部落。但最終，是你必須跨出那一步。沒人能替你活你的生命。","energyQualities":"這張牌帶來勇氣與決心的能量，如同熾熱的火焰燃燒在你的心中。它的振動頻率溶解恐懼與猶豫，喚醒你內在的力量與意志。這是一種推動的能量，給你動力去做你一直拖延的事。它連結你與你的靈魂力量，提醒你你比自己以為的更強大。這股能量如同戰士的戰吼，宣告你準備好為你的真實而戰。它不是攻擊性的，而是保護性的—保護你的夢想、你的召喚、你的真實自我不被恐懼摧毀。","suitableQuestions":"這張牌適合在你面對需要勇氣的決定或行動時詢問。當你知道該做什麼但恐懼阻止你、或你在考慮一個讓你既興奮又害怕的召喚時，這張牌能給予力量。你可以問：「我的最深召喚是什麼？」「如何找到勇氣回應它？」「我在害怕什麼？」「這個恐懼背後守護著什麼天賦？」「我準備好勇敢地活了嗎？」「如何喚醒我的內在戰士？」這張牌是勇氣與行動的強力催化劑。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:17', 'work_your_light', '17', 16, '打破鎖鏈', 'Break the Chain', NULL, '{"titleEn":"Break the Chain","suit":"行動牌"}', '{"coreMeaning":"修復家族血脈或從祖先的生活模式中解脫。釋放並非源自於你的情緒創傷。","actionGuidance":"你準備好放下哪些家族傳承的模式？尋求支持團隊協助。","inquiryPrompt":null,"activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌指向你正在承載的世代創傷與家族模式。許多我們以為是「自己的」恐懼、信念和行為模式，實際上是從父母、祖父母、甚至更早的祖先那裡繼承來的。這些可能包括對金錢的恐懼、對愛的不信任、對成功的自我破壞、或深層的羞恥感。你可能正在重複家族中的痛苦模式—例如困難的婚姻、破碎的夢想、或未解的悲傷。但你不必繼續這個循環。你有力量成為那個「打破鎖鏈」的人，不只為你自己，也為你之前和之後的所有世代。當你療癒這些模式，你同時在療癒你的血脈。","higherSelfMessage":"你的高我想讓你知道：你選擇了這個家族和血脈，部分原因就是為了療癒這些世代模式。你不是受害者或不幸承受了這些重擔，而是有意識的靈魂選擇了這個療癒工作。你有足夠的力量和靈性資源來打破這些鎖鏈。你的高我看見，許多你掙扎的事情—那些似乎「不合理」的恐懼或反應—其實不是你的，而是你繼承的。一旦你認出這些模式的來源，你就能開始釋放它們。你不需要獨自做這項工作—尋求支持，無論是透過療癒師、治療師、或靈性導師。打破家族鎖鏈是深刻的療癒工作，值得專業的協助。","spiritualGuidance":"開始探索你的家族歷史與模式。問你的長輩關於你祖先的故事—他們經歷了什麼創傷？有什麼未說出的秘密？什麼模式在你的家族中重複出現？同時，觀察你自己的生活：什麼模式看起來像是在重複你父母或祖父母的經驗？你在哪些方面感覺「我不想像我父母那樣」卻發現自己正在重複同樣的行為？這些都是需要療癒的線索。考慮進行家族系統排列、祖先療癒工作、或深度心理治療。你也可以進行簡單的儀式：寫信給你的祖先，表達你正在釋放這些模式，感謝他們的犧牲，但宣告你選擇不同的道路。記住，當你療癒，你的孩子或後代將不必承擔這些重擔。","energyQualities":"這張牌帶來釋放與切斷的能量，如同打破束縛已久的鎖鏈。它的振動頻率穿透世代的層層累積，找到創傷的根源並開始溶解它。這是一種深層療癒的能量，既有考古學家的耐心（挖掘過去）也有勇士的決心（終結循環）。它連結你與你的祖先，但不是為了繼續背負，而是為了理解、寬恕與釋放。這股能量如同剪刀，溫柔但堅定地切斷不健康的世代連結，同時保留愛與祝福的連結。它給你力量說：「這在我這裡結束。」","suitableQuestions":"這張牌適合在你發現自己重複家族模式、感到被家族期待束縛、或想要理解為何某些領域總是困難時詢問。當你準備進行深層家族療癒工作時，這張牌能提供指引。你可以問：「我繼承了什麼家族模式？」「如何打破這些世代循環？」「我需要療癒什麼祖先創傷？」「如何尊重家族又活出我的真實？」「什麼不是真正屬於我的？」「我如何成為療癒者而非繼承者？」這張牌支持你成為打破鎖鏈、創造新遺產的那一代。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:18', 'work_your_light', '18', 17, '與生命共舞', 'Dance with Life', NULL, '{"titleEn":"Dance with Life","suit":"行動牌"}', '{"coreMeaning":"生命總在變動，抵抗流動會導致停滯。透過音樂與舞蹈來改變你的振動頻率。","actionGuidance":"做些事情來改變你的能量。","inquiryPrompt":null,"activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是對流動性與適應性的邀請。生命的本質就是變動—季節改變、關係演化、你自己也在不斷成長。當你抵抗這種自然流動，試圖讓事物保持靜止或控制結果時，你就創造了停滯與僵化。這種抵抗會困在你的身體和能量場中，讓你感到沉重、疲倦或被卡住。舞蹈與音樂是最古老、最有效的改變能量的工具。透過移動你的身體，你在移動你的能量；透過音樂，你在改變你的振動頻率。這不是關於「好看」或「正確」地跳舞，而是關於讓你的身體自由表達與釋放。與生命共舞意味著學會順應而非抵抗，流動而非僵硬，慶祝變化而非恐懼它。","higherSelfMessage":"你的高我正在邀請你重新連結你的身體。你花了太多時間活在頭腦裡—思考、分析、擔心、計畫。但你的身體擁有它自己的智慧，一種頭腦無法觸及的知曉。當你跳舞或移動時，你在繞過頭腦的審查與控制，直接接觸你的靈魂與生命力。你的高我知道，許多你試圖用思考解決的問題，實際上需要透過身體來釋放。困住的情緒、停滯的能量、壓抑的創意—這些都儲存在你的身體裡，等待透過動作被釋放。不要低估音樂與舞蹈的療癒力量。它們是靈魂的語言，是喜悅的表達，是與生命本身連結的方式。","spiritualGuidance":"現在是移動你身體的時刻。放你最喜歡的音樂，關上門，讓你的身體自由移動，不需要任何人看，不需要任何「正確」的方式。讓音樂引導你，讓你的身體做它想做的。如果你感到悲傷，讓身體表達悲傷；如果你感到憤怒，讓它透過動作釋放；如果你感到喜悅，讓它綻放。這是能量煉金術—透過動作，你在轉化困住的能量為流動的生命力。如果跳舞感覺太大步，從簡單的開始：伸展、搖擺、走路、甚至只是深呼吸配合身體的微妙移動。重點是打破靜止，讓能量再次流動。你也可以嘗試狂喜舞蹈、5節奏、或任何自由形式的動作練習。記住：生命是動詞，不是名詞。","energyQualities":"這張牌帶來流動與活力的能量，如同河流融化了冰封的湖面。它的振動頻率是節奏性的、脈動的、充滿生命力。這是一種釋放的能量，透過動作溶解僵化與停滯。它喚醒你的原始生命力，連結你與身體的智慧與喜悅。這股能量如同風吹過靜止的空氣，帶來新鮮與變化。它是慶祝性的、玩樂性的、自發性的。它邀請你放下控制，進入當下，讓身體與靈魂透過動作交談。","suitableQuestions":"這張牌適合在你感到卡住、僵化、或能量沉重時詢問。當你過度活在頭腦裡、與身體斷連、或生活缺乏喜悅與自發性時，這張牌能提供解方。你可以問：「如何重新流動？」「什麼能量需要透過動作釋放？」「我如何更順應生命的變化？」「如何重新連結我的身體？」「什麼讓我僵化了？」「如何帶更多玩樂進入生活？」這張牌是透過動作與音樂進行能量轉化的邀請。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:19', 'work_your_light', '19', 18, '深層補給', 'Deep Replenishment', NULL, '{"titleEn":"Deep Replenishment","suit":"行動牌"}', '{"coreMeaning":"填滿自己的內在之井是最無私的事，枯竭時你無法幫助任何人。","actionGuidance":"今天做一件能深度補充能量的事（如按摩、瑜伽、自然漫步等）。","inquiryPrompt":null,"activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是對自我照顧的神聖提醒。在一個美化忙碌與犧牲的文化中，深度休息與補充往往被視為奢侈或自私。但真相是：當你的內在之井枯竭時，你無法真正地給予、創造或服務。從枯竭之處給出的東西帶著怨恨、義務和疲憊的能量，而非愛、喜悅和豐盛。深層補給不是指膚淺的「休息一下」，而是真正地、深刻地滋養你的身體、心靈和靈魂。這可能意味著充足的睡眠、滋養的食物、療癒的觸碰、自然的連結、或單純的無所事事。你的存在狀態（being）比你的行動（doing）更重要。當你從一個充滿、滋養的內在空間行動時，你的影響力會倍增。","higherSelfMessage":"你的高我正在溫柔但堅定地告訴你：你需要停下來。你一直在推動、努力、給予，但你已經太久沒有真正地接收與補充了。你的高我知道你有很多理由—「我沒時間」、「還有太多事要做」、「別人需要我」—但這些都是你的恐懼在說話，不是你的智慧。真正的自私是讓自己枯竭到無法好好愛、好好創造、好好活著。真正的慷慨是滋養自己，讓你能從充盈的空間給予。你的身體在向你發送訊號—疲倦、疾病、情緒波動—這些都是它在請求補給。聆聽它。尊重它。把自我照顧視為靈性修行，而非奢侈品。","spiritualGuidance":"今天，給自己許可去深度滋養自己。不是匆忙的淋浴，而是慢慢的泡澡；不是快速的小睡，而是充足的睡眠；不是站著吃完的餐，而是慢慢品嚐的美食。問自己：什麼真正地滋養我？什麼讓我感到被補充、被充電？然後實際地去做它。這可能是按摩、瑜伽、在自然中漫步、與摯友深談、或單純地坐著看日落。注意你內在的抗拒—「我不值得」、「我應該更有生產力」—認出這些聲音，然後選擇忽略它們。建立日常的補給練習：每天至少做一件深度滋養自己的事。記住，你無法從空杯中倒出任何東西。先填滿自己，然後從溢出的豐盛中分享。","energyQualities":"這張牌帶來滋養與恢復的能量，如同春雨滋潤乾涸的土地。它的振動頻率是溫柔的、療癒的、母性的。這是一種接收的能量，邀請你停止給予、停止行動，單純地允許自己被補充。它喚醒你對自我照顧的需求與權利，溶解那些告訴你「不夠好」或「還不夠努力」的內在聲音。這股能量如同深井，緩慢但穩定地填充清涼的水，恢復你的生命力與喜悅。它是休息的能量，是療癒的能量，是說「我值得被好好對待」的能量。","suitableQuestions":"這張牌適合在你感到疲憊、枯竭、或過度給予時詢問。當你忙到忘記照顧自己、感到怨恨或義務感、或你的身體在抗議時，這張牌能提供許可與指引。你可以問：「我需要什麼樣的補給？」「如何深度滋養自己？」「什麼讓我感到真正的恢復？」「我為何抗拒自我照顧？」「如何從充盈而非枯竭中給予？」「什麼日常練習能持續補充我？」這張牌是對神聖自我照顧的肯定與邀請。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:20', 'work_your_light', '20', 19, '落地扎根', 'Get Grounded', NULL, '{"titleEn":"Get Grounded","suit":"行動牌"}', '{"coreMeaning":"對於高敏感者或共感者，若未落地扎根，容易吸收他人能量導致邊界模糊。","actionGuidance":"透過赤腳踩地或觸摸樹木與大地連結。","inquiryPrompt":null,"activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是對紮根與落地的呼喚。對於敏感者、共感者、或靈性工作者來說，很容易花太多時間在精微能量、靈性領域或他人的情緒中，而忘記紮根於自己的身體和物質實相。當你未落地時，你的能量場邊界會變得模糊，你會吸收他人的情緒、想法和能量，誤以為是自己的。你可能感到迷糊、飄忽、無法專注、或情緒不穩。紮根的意思是完全地居住在你的身體裡，連結大地的穩定能量，清晰地知道「哪些是我的，哪些不是」。大地是最強大的療癒者與穩定器，她能吸收並轉化過多的能量，同時提供支持與滋養。","higherSelfMessage":"你的高我正在提醒你：你是靈性存有擁有人類經驗，但你也是人類在經驗靈性。你的靈性工作需要你完全地紮根在此時此地，在這個身體裡，在這個地球上。當你未落地時，你的靈性工作會變得不穩定、不實用、或與現實脫節。你的高我知道你有時候會想要「逃離」—離開沉重的情緒、困難的實相、或痛苦的身體—但真正的靈性成長是完全地在場，包括在不舒服的時刻。紮根不是限制你的靈性，而是給它穩定的基礎來實際地顯化與服務。你的光需要紮根才能真正照亮這個世界。","spiritualGuidance":"每天練習紮根。最簡單且最有效的方式是直接與大地接觸—赤腳走在草地、沙灘或泥土上，讓大地的能量透過你的腳底流入你的身體。你也可以抱樹、坐在地上、或用手觸碰土壤。在室內時，使用觀想：想像根從你的腳底或脊椎底部深深地扎入地球中心，讓大地的穩定能量流上來支持你。當你感到吸收了他人的能量或情緒時，問自己：「這是我的嗎？」如果不是，想像將它釋放回大地進行轉化。建立清晰的能量邊界—早上起床時宣告：「我只攜帶我自己的能量」，晚上結束時釋放一天中吸收的所有非你的能量。紮根是日常練習，不是一次性事件。","energyQualities":"這張牌帶來穩定與落地的能量，如同大樹深深紮根於土地。它的振動頻率是沉穩的、實在的、母親大地的。這是一種邊界化的能量，幫助你清楚分辨什麼是你的、什麼不是。它像錨一樣將你固定在此時此地，在你的身體裡，讓你不再漂浮或被他人的能量帶走。這股能量如同礦石，沉重但有力，提供你穩固的基礎。它連結你與地球的療癒力量，讓過多的能量可以流入大地被轉化，讓你需要的穩定支持可以流上來。","suitableQuestions":"這張牌適合在你感到迷糊、飄忽、過度敏感、或被他人能量影響時詢問。當你難以專注、情緒起伏不定、或感覺「不在自己身體裡」時，這張牌能提供解方。你可以問：「我吸收了誰的能量？」「如何更紮根於我的身體？」「什麼讓我的邊界模糊？」「如何建立清晰的能量邊界？」「哪些是我的，哪些不是？」「如何連結大地的支持？」這張牌是敏感靈魂的必備練習，提供穩定與清晰。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:21', 'work_your_light', '21', 20, '啟蒙儀式', 'The Initiation', NULL, '{"titleEn":"The Initiation","suit":"行動牌"}', '{"coreMeaning":"跨越從一個世界到另一個世界的門檻，這可能伴隨情感動盪或失去，但靈魂會因此提升。","actionGuidance":"跨越那個門檻，這將是值得的。","inquiryPrompt":null,"activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌標誌著一個深刻的靈性轉變—從一個意識層次跨越到另一個。啟蒙（Initiation）在靈性傳統中意味著死亡與重生：舊的自我、舊的身份、舊的生活方式必須死去，讓新的、更真實的你誕生。這往往不是溫和的過程。它可能伴隨著失去—關係結束、工作改變、信念系統瓦解、或深刻的情感動盪。但這不是懲罰或不幸，而是你的靈魂為了提升到下一個層次所必須經歷的過程。啟蒙把你從舒適但受限的舊世界帶入更廣闊、更真實但未知的新世界。門檻是神聖的空間，站在那裡會感到恐懼與興奮同時存在。你的靈魂知道，跨越這個門檻之後，你將永遠不再是原來的你。","higherSelfMessage":"你的高我想讓你知道：你正在經歷的動盪不是意外或錯誤，而是你靈魂呼請的啟蒙。你祈求成長、祈求覺醒、祈求活出更真實的生命—而這就是宇宙的回應。啟蒙不會以你期待的方式到來，它往往透過拆解來到。它拆解不再服務你的事物，即使你仍然依戀它們。你的高我看到更大的圖像：這個失去正在為更大的得到創造空間；這個結束正在為新的開始清理道路。你站在門檻上，舊世界在你身後崩塌，新世界在你面前尚未成形。信任這個空無的空間。這是蛹的階段，看起來像死亡，實則是變形。跨越這個門檻需要信心—不是相信一切會回到原樣，而是相信你正在成為你注定要成為的人。","spiritualGuidance":"尊重你正在經歷的轉變的神聖性。不要試圖加速它或逃避它，而是允許它完整地展開。創造儀式來標記這個轉變：你可以寫下你正在放下的一切，然後燒掉這張紙；或進行象徵性的葬禮，埋葬舊的自我；或創造新的個人儀式來跨越這個門檻。在這個過程中善待自己。啟蒙是情感激烈的，允許自己悲傷失去的、恐懼未知的、同時興奮於正在誕生的。尋求支持—找到那些理解靈性轉變的人，或經歷過類似啟蒙的靈魂。避開那些試圖讓你「回到正常」的人，因為「正常」已經結束了。記住，每個偉大的靈性導師、每個覺醒的靈魂都經歷過啟蒙。你正走在一條古老而神聖的道路上。","energyQualities":"這張牌帶來轉化與蛻變的能量，如同毛毛蟲在蛹中溶解成液體，準備成為蝴蝶。它的振動頻率是強烈的、變動的、具有煉金性質的。這是一種死亡與重生的能量，拆解舊的結構來釋放被困的靈魂。它攪動一切不真實的、不再服務你的，即使過程令人不適。這股能量如同火焰，燒掉雜質，留下純金。它既是結束也是開始，既是失去也是解放。它將你推出舒適區，進入未知的領域，在那裡真正的成長才可能發生。","suitableQuestions":"這張牌適合在你正經歷重大生命轉變、失去、或感到舊生活正在瓦解時詢問。當你站在重要門檻前猶豫、或正在深刻的個人轉化中掙扎時，這張牌能提供意義與視角。你可以問：「我正在經歷什麼啟蒙？」「這個轉變想教我什麼？」「我需要放下什麼才能跨越？」「如何尊重這個過程？」「門檻另一邊等待我的是什麼？」「我的靈魂為何呼請這個轉變？」這張牌確認你正在經歷的不是崩潰，而是突破。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:22', 'work_your_light', '22', 21, '內在神殿', 'Inner Temple', NULL, '{"titleEn":"Inner Temple","suit":"行動牌"}', '{"coreMeaning":"培養定期的冥想、書寫或誦經習慣，與你的靈魂建立深度關係。","actionGuidance":"承諾進行每日的虔誠修持。","inquiryPrompt":null,"activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是對內在修行的神聖邀請。在一個不斷向外尋求的世界裡，這張牌要你轉向內在，與你的靈魂建立直接、親密的關係。內在神殿是你心中的神聖空間，在那裡你可以與你的高我、你的直覺、神聖源頭連結。但這個神殿需要定期的照護與訪問，否則它會被日常生活的雜草淹沒。冥想、書寫、祈禱、誦經、或任何形式的虔誠修持，都是進入這個內在神殿的門徑。重點不是形式，而是一致性與承諾。每天的修持，即使只有十分鐘，創造了一個神聖的容器，讓你的靈魂可以對你說話、指引你、滋養你。這是你與神聖的個人關係，不需要中介、不需要外在權威，只需要你的臨在與開放。","higherSelfMessage":"你的高我正在呼喚你回家—回到你自己的中心，你自己的神聖空間。你一直在外面尋找答案、指引、平安，但它們都在你內在等著你。你的高我知道，你的生活充滿外在的聲音與要求，如果你不創造神聖的時間與空間來聆聽內在的聲音，你會失去與自己的連結。內在修行不是另一個待辦事項，而是你給自己最寶貴的禮物—與你真實自我相處的時間。你的高我在說：我一直在這裡，在每個寂靜的時刻等待與你交談，分享智慧、愛與指引。但你必須停下來，進入內在，才能聽見。承諾一個日常修持，不是因為你「應該」，而是因為你的靈魂渴望這個連結。","spiritualGuidance":"選擇一個內在修行並承諾每天進行。這可以是冥想、自由書寫、祈禱、誦經、瑜伽、或任何讓你與內在連結的練習。關鍵是選擇一個你會真正做的修行，而非你認為你「應該」做的。從小處開始—每天十分鐘就夠了。重要的是一致性，而非時長。創造一個神聖空間來進行你的修持：可以是房間的一角，放上蠟燭、水晶、或任何對你有意義的物件。讓這個空間成為你的內在神殿的外在表現。在同樣的時間、同樣的地點進行修持，幫助建立習慣。當你的頭腦抗拒時—它會說「太忙」、「明天再做」—認出這是恐懼，然後仍然坐下來。記錄你的修持中接收到的洞見、訊息、或感受。隨時間，你會看見你內在智慧的展開。","energyQualities":"這張牌帶來寧靜與內省的能量，如同古老寺廟中的寂靜空間。它的振動頻率是深沉的、神聖的、沉思性的。這是一種向內的能量，邀請你從外在世界的喧囂撤退，進入內在的聖殿。它創造了一個容器，在其中神聖可以對你說話，你的靈魂可以呼吸。這股能量如同回家，回到你自己的中心，在那裡你與一切的源頭連結。它是虔誠的、靜默的、充滿敬畏的。它教導你，你攜帶著神聖在你之內，不需要向外尋找它。","suitableQuestions":"這張牌適合在你感到與自己斷連、生活過度外向、或渴望更深靈性連結時詢問。當你知道需要內在修行但一直拖延、或想要深化現有修持時，這張牌能提供動力與指引。你可以問：「什麼修行適合我？」「如何建立日常靈性習慣？」「我的靈魂想對我說什麼？」「如何更深地連結我的內在智慧？」「什麼阻礙我進入內在神殿？」「如何創造神聖時間與空間？」這張牌是對虔誠、一致的內在修行的召喚。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:23', 'work_your_light', '23', 22, '飛躍', 'Leap', NULL, '{"titleEn":"Leap","suit":"行動牌"}', '{"coreMeaning":"宇宙想支持你，但你必須先行動。不要等待指令或徵兆，深呼吸後跳入未知。","actionGuidance":"你先開始，做個助跑並飛躍吧。","inquiryPrompt":null,"activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是對信心飛躍的召喚。有些時候，你已經計畫夠了、思考夠了、準備夠了，現在需要的是行動。宇宙想要支持你的夢想和願望，但它無法支持停留在你腦海中的事物—它只能支持你實際採取的行動。這張牌說：你永遠不會感到「完全準備好」。完美的時機不會到來。所有的徵兆和條件永遠不會齊全。在某個點上，你必須閉上眼睛，深呼吸，然後跳入未知。這不是魯莽或不負責任，而是信任—信任你有能力處理出現的一切，信任宇宙會在你跳之後接住你。飛躍的魔法在於：當你承諾並採取行動時，整個宇宙會重組來支持你。但首先，你必須跳。","higherSelfMessage":"你的高我正在推你離開懸崖邊。你一直站在那裡，看著下面的未知，等待保證、等待確定性、等待恐懼消失。但你的高我知道：這些永遠不會來。成長總是需要進入未知。你的高我在說：你已經準備好了，即使你不相信。你擁有所有你需要的內在資源來處理接下來發生的一切。那個夢想、那個召喚、那個你一直推遲的跳躍—現在就是時候了。不是明天，不是「當我更準備好」，而是現在。你的高我看見，你在等待的「完美時機」只是恐懼的藉口。真相是：當你跳的時候，宇宙會出現。當你承諾的時候，道路會顯現。但你必須先跳。信任這個過程，信任你自己，然後飛躍。","spiritualGuidance":"辨識你一直拖延的那個跳躍。是什麼夢想、行動、或決定你一直在等待「完美時機」來執行？寫下你在等待的所有原因和條件。然後問自己：這些是真正的障礙，還是恐懼的偽裝？選擇一個具體的行動—不需要是巨大的跳躍，但必須是實際的、可見的、讓你脫離舒適區的行動。然後設定一個截止日期，在那之前你會採取這個行動。告訴一個信任的朋友，讓自己負責。當恐懼出現時—它會的—不要讓它阻止你，而是帶著它一起跳。說：「是的，我害怕，但我仍然要做。」記住，勇氣不是沒有恐懼，而是即使恐懼仍然行動。跳躍之後，觀察宇宙如何回應你的承諾。你會驚訝於當你先行動時，出現多少支持與同步性。","energyQualities":"這張牌帶來推動與動能的能量，如同站在跳板邊緣的運動員準備起跳。它的振動頻率是刺激的、充滿腎上腺素的、既興奮又恐懼的。這是一種突破慣性的能量，打破分析癱瘓與過度思考，推動你進入行動。它攜帶著信任與勇氣的頻率，給你需要的推力來跨越邊緣。這股能量如同風，在你的背後推動你；如同重力，把你拉入你的命運。它是冒險的、解放的、充滿可能性的。它說：「現在！」不是稍後，不是有一天，而是此刻。","suitableQuestions":"這張牌適合在你一直拖延重要行動、過度準備或分析、或站在重大決定邊緣猶豫時詢問。當你知道該做什麼但恐懼或完美主義阻止你、或你在等待「完美時機」時，這張牌能提供推力。你可以問：「我需要採取什麼飛躍？」「什麼阻止我跳？」「我在等待什麼？」「如果我跳了會發生什麼？」「我準備好了嗎？」「宇宙會如何支持我的行動？」這張牌是對行動、承諾與信任飛躍的召喚。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:24', 'work_your_light', '24', 23, '玩樂', 'Play', NULL, '{"titleEn":"Play","suit":"行動牌"}', '{"coreMeaning":"不要把生活看得太嚴肅。當你放下對結果的執著去玩樂時，靈感與解決方案才能降臨。","actionGuidance":"慶祝你的成就，排定時間玩樂。","inquiryPrompt":null,"activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是對輕盈與喜悅的神聖提醒。在一個美化嚴肅、努力與生產力的文化中，玩樂往往被視為浪費時間或不成熟。但真相是：玩樂是靈魂的語言，是創意的源泉，是療癒的力量。當你太嚴肅對待生活，你就切斷了與直覺、靈感和流動的連結。解決方案往往在你放鬆、玩樂、停止努力時出現，因為你讓你的意識擴展到線性思維之外。玩樂不是逃避責任，而是重新連結生命的喜悅與奧秘。它是做事「只是因為好玩」，不為結果、不為成就、不為任何目的，只為活動本身的純粹樂趣。當你玩樂時，你在最高的頻率振動，吸引最好的事物進入你的生命。","higherSelfMessage":"你的高我正在邀請你放鬆。你一直在努力、推動、試圖讓事情發生，但你越用力，事情越困難。你的高我知道：生命不是要被征服或控制，而是要被享受與慶祝。你把事情看得太嚴重了—你的錯誤、你的進展、你的價值—而這種嚴肅性正在耗盡你的能量與創意。玩樂不是不負責任，而是記起你最初為何開始這段旅程—因為某些事物點燃了你的興奮與好奇。回到那個地方。做讓你感到活著、讓你笑、讓你忘記時間的事。慶祝你已經走了多遠，而非永遠專注於還有多遠要走。你的高我想讓你知道：你被允許享受這趟旅程。事實上，當你享受時，你會走得更快更遠。","spiritualGuidance":"排定玩樂的時間—實際地把它放進你的行事曆，就像重要的會議一樣。問自己：什麼讓我感到真正的樂趣？什麼讓我像孩子一樣興奮？然後實際地去做它，不帶任何「生產性」或「目的」。這可能是跳舞、繪畫、玩遊戲、在自然中冒險、或任何讓你的心歌唱的事。注意你內在對玩樂的抗拒—「我應該做更重要的事」、「這太幼稚了」—認出這些是來自受限的信念系統，不是來自你的靈魂。創造一個練習：每天做一件純粹為了樂趣的事，不為任何成果。慶祝你的成就，無論大小—不是等到「大的」勝利，而是認出與慶祝每一個小步伐。笑—看好笑的影片、與朋友分享笑話、找尋幽默。笑是最快速的振動提升。記住：生命是禮物，意圖是要被享受的。","energyQualities":"這張牌帶來輕盈與喜悅的能量，如同孩子在遊戲場無憂無慮地玩耍。它的振動頻率是高的、明亮的、笑聲般的。這是一種釋放的能量，溶解嚴肅性、完美主義與過度思考的沉重。它喚醒你內在的孩童，那個充滿好奇、想像與自發性的部分。這股能量如同微風吹走烏雲，讓陽光穿透。它是慶祝性的、創意的、無條件的快樂。它提醒你，你不需要「賺得」快樂或樂趣—它們是你的天生權利，只是因為你活著。","suitableQuestions":"這張牌適合在你把生活看得太嚴重、感到沉重或疲倦、或失去與喜悅的連結時詢問。當你過度努力、困在問題思維、或忘記享受生命時，這張牌能提供解放與視角。你可以問：「我如何帶更多玩樂進入生活？」「什麼讓我真正快樂？」「我在哪裡太嚴肅了？」「如何放鬆對結果的執著？」「我的內在孩童需要什麼？」「如何慶祝我的旅程？」這張牌是對輕盈、笑聲與純粹樂趣的邀請。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:25', 'work_your_light', '25', 24, '分享你的聲音', 'Share Your Voice', NULL, '{"titleEn":"Share Your Voice","suit":"行動牌"}', '{"coreMeaning":"透過說話、寫作或歌唱來表達你的獨特真理，這能療癒你與地球。","actionGuidance":"表達你自己，對那些能聽見你的人發聲。","inquiryPrompt":null,"activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是對真實表達的召喚。你的聲音—無論是透過說話、寫作、歌唱或任何形式的表達—攜帶著獨特的頻率和真理，只有你能分享。當你壓抑你的聲音、你的意見、你的真理時，不只你受苦，整個世界也失去了你能貢獻的智慧與療癒。許多光之工作者因為害怕被評判、拒絕、或「說錯話」而沉默，但這張牌提醒你：你的聲音有療癒的力量，不只對你自己，也對那些準備好聽見的人。表達的行為本身就是療癒—它釋放困在你喉嚨和心中的能量，它確認你的存在與真實，它允許你的真理流動。不是每個人都會理解或欣賞你的訊息，但那些對的人會。","higherSelfMessage":"你的高我想讓你知道：你有重要的事要說。你一直在等待「夠資格」、「夠好」、「完全準備好」才開口，但你的高我知道你已經準備好了。你的經驗、你的視角、你的真理—即使它們感覺平凡或不完美—對某人來說可能是精確需要聽見的訊息。你不需要成為專家或完美才能分享。事實上，你的脆弱、你的人性、你的不完美往往是最能觸動他人的。你的高我在提醒你：當你分享你的聲音時，你不只在服務他人，你也在服務你自己的靈魂。表達是靈魂的需要，如同呼吸是身體的需要。壓抑你的聲音會創造能量阻塞，特別在喉輪，導致創意、真實性與自我價值的議題。說出來。寫下來。唱出來。讓你的真理流動。","spiritualGuidance":"開始表達，即使是小步伐。如果公開分享感覺太大，從日記開始—寫下你的真實想法與感受，不帶審查或評判。當你準備好時，考慮開始一個部落格、社群媒體頁面、播客、或YouTube頻道來分享你的聲音。選擇讓你感到真實的媒介—如果你喜歡寫作就寫，如果你喜歡說話就錄音或錄影。不要等到「完美」才開始；完美是恐懼的偽裝。從你所在的地方開始，用你現在擁有的。當你分享時，專注於服務而非表現—問「誰可能需要聽見這個？」而非「他們會怎麼評價我？」尋找你的族群—那些會共鳴你訊息的人—並對他們說話，而非試圖取悅每個人。練習在日常生活中表達你的真理：說出你的界限、分享你的意見、表達你的需求。每次你真實地使用你的聲音，你就在強化這個肌肉。","energyQualities":"這張牌帶來表達與解放的能量，如同長久被壓抑的歌終於被唱出。它的振動頻率集中在喉輪，清理喉嚨與聲音的阻塞。這是一種釋放的能量，讓困在內在的真理、情感與創意流出。它攜帶著勇氣的頻率—不是無懼的勇氣，而是即使害怕仍然說出來的勇氣。這股能量如同打開水龍頭，讓長期堆積的水得以流動。它連結你與你的真實性與力量，因為當你說出你的真理時，你在宣稱你的存在與價值。它也是連結性的能量，因為當你真實地分享時，你創造了與他人深度連結的可能。","suitableQuestions":"這張牌適合在你一直壓抑想說的話、感到沒有聲音或不被聽見、或想要開始分享你的工作或訊息時詢問。當你有創意項目想開始但害怕評判、或感到喉嚨阻塞或喉嚨相關問題時，這張牌能提供指引。你可以問：「我需要表達什麼？」「如何分享我的聲音？」「什麼阻止我說出來？」「誰需要聽見我的訊息？」「我的真理是什麼？」「如何清理我的喉輪？」這張牌是對勇敢、真實表達的邀請。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:26', 'work_your_light', '26', 25, '玫瑰姊妹會', 'Sisterhood of the Rose', NULL, '{"titleEn":"Sisterhood of the Rose","suit":"行動牌"}', '{"coreMeaning":"這是一個致力於美麗與虔誠的血脈。你被召喚去在自然中聽見大地的低語。","actionGuidance":"在生活中創造美麗並被美麗環繞。","inquiryPrompt":null,"activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌連結你與古老的玫瑰血脈—瑪利亞抹大拉、聖母瑪利亞、伊西斯、阿芙蘿黛蒂、以及無數世代中侍奉神聖陰性的女祭司與虔誠者。這不只是一個歷史傳承，而是一個靈魂層次的召喚：透過美、愛、虔誠與與大地的連結來服務光。玫瑰姊妹會的道路不是透過書本或寺廟的傳統男性靈性路徑，而是透過身體、感官、自然與心的路徑。你被召喚去看見並創造美—不是表面的裝飾，而是能觸動靈魂、打開心、提醒我們神聖的美。你被召喚去聆聽大地的低語，接收她的智慧與療癒。你被召喚去尊重神聖陰性—接收的、滋養的、循環的、直覺的力量。","higherSelfMessage":"你的高我正在確認：你是這個血脈的一部分。在過去的生世中，你可能曾是女祭司、療癒者、或侍奉女神的虔誠者。你攜帶著這個記憶在你的細胞裡。你對美的熱愛不是膚淺的；你對自然的吸引不是隨機的；你對玫瑰、水晶、儀式的共鳴不是巧合。這些是你靈魂記憶的迴響。你的高我在召喚你更深地進入這個道路：創造美麗的聖壇與空間；在花園或自然中花時間，不只是為了放鬆，而是作為神聖的修行；實踐將美麗、虔誠與日常生活編織在一起的儀式。這是回家的路徑—回到你記得神聖陰性的力量與智慧的地方。你的工作不是在世界中戰鬥，而是透過你的存在、你的美、你的愛來轉化它。","spiritualGuidance":"開始或深化你與大地的關係。每天花時間在自然中—不是匆忙地經過，而是真正地臨在，聆聽風、樹木、鳥兒、流水的訊息。如果可能，創造一個花園或照顧植物，讓你的手觸碰土壤，參與生命的循環。將美麗帶入你的生活與空間：創造一個美麗的聖壇，放上鮮花、玫瑰、水晶、蠟燭；穿讓你感到美麗的衣服；用鮮花、藝術、自然元素裝飾你的家。這不是虛榮，而是尊重神聖—你是神聖的廟宇，你的生活是神聖的表達。實踐虔誠—這可能是每天對大地或女神說話、進行新月或滿月儀式、或用玫瑰水沐浴作為淨化儀式。研究神聖陰性傳統與女神，看哪些呼喚你。連結其他玫瑰姊妹—尋找女性圓圈、新月聚會、或創造你自己的。","energyQualities":"這張牌帶來柔軟、滋養與美麗的陰性能量，如同玫瑰綻放的溫柔力量。它的振動頻率是心輪的，充滿愛與虔誠。這是一種接地但同時精微的能量，連結天堂與大地透過心。它攜帶著玫瑰的頻率—愛、美、療癒、神聖陰性。這股能量如同走在花園中，被美麗環繞，感受與所有生命的連結。它是感官的但不是性的；它是虔誠的但不是嚴肅的；它是強大的但不是侵略的。它教導陰性力量的道路—透過存在、美、愛與連結來轉化，而非透過控制或力量。","suitableQuestions":"這張牌適合在你渴望更深的靈性連結但傳統宗教感覺空洞、被自然或美強烈吸引、或感受到與女神或神聖陰性的召喚時詢問。當你想要創造更美麗的生活或空間、或感覺自己是古老女性血脈的一部分時，這張牌能確認與指引。你可以問：「我如何更深地連結神聖陰性？」「大地想對我說什麼？」「如何在生活中創造更多美？」「我的靈魂記得什麼血脈？」「如何實踐玫瑰的道路？」「神聖陰性對我的召喚是什麼？」這張牌是回歸美麗、虔誠與大地智慧的邀請。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:27', 'work_your_light', '27', 26, '靈魂家人', 'Soul Family', NULL, '{"titleEn":"Soul Family","suit":"行動牌"}', '{"coreMeaning":"是時候召喚那些在靈魂層次理解你的人了。停止黯淡你的光，讓他們能看見並認出你。","actionGuidance":"現在就召喚你的支持團隊。","inquiryPrompt":null,"activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是關於尋找與召喚你的靈魂家人—那些在最深層次理解你、看見你、與你共鳴的人。這不一定是你的血緣家庭或童年朋友；靈魂家人是你在靈魂層次認識的人，你們可能在許多生世中一起工作過。當你遇見他們時，有一種「終於回家」的認出感。但這張牌的關鍵訊息是：要吸引你的靈魂家人，你必須停止隱藏你的光。當你黯淡你的真實性、假裝「正常」、或隱藏你靈性或古怪的部分來融入時，你的靈魂家人無法認出你，你也無法認出他們。你必須真實地發光，即使這意味著你不再適合某些群體或環境。當你真實時，你發出一個信號，讓你的族群能找到你。","higherSelfMessage":"你的高我想讓你知道：你不孤單。你有一個靈魂團隊—有些已經在你的生命中，有些正在路上，等待與你連結。但你必須召喚他們，不是透過大聲呼喊，而是透過成為你真實的自己。你一直在某些情況下「縮小」你自己，避免談論你的興趣、你的靈性、你看世界的方式，因為你擔心被評判或不被理解。但你的高我在說：那些需要你黯淡才能接受你的人，不是你的族群。讓他們離開。當你釋放不共鳴的連結，你為真正的連結創造空間。你的靈魂家人正在尋找你，就像你在尋找他們。讓他們看見真實的你。當你這樣做時，魔法般的相遇與深刻的連結會開始出現。信任這個過程。你的族群正在路上。","spiritualGuidance":"開始真實地在世界中展現你自己。分享你真正的興趣—如果你喜歡靈性、塔羅、水晶、冥想，談論它們。寫關於它們，發布關於它們，讓你的旗幟飛揚。去你的族群可能聚集的地方—靈性工作坊、瑜伽課、新月圓圈、形而上書店、線上社群。當你遇見新的人時，分享真實的你，而非你認為他們想看見的版本。注意誰亮起來、誰共鳴—那些是你的線索。同時，溫柔地釋放不再共鳴的關係。這不需要戲劇化，只是認出你們已經走向不同的方向，並允許自然的分離。創造或加入一個定期聚會的靈魂家人圈—可能是讀書會、冥想團體、或只是定期聚在一起分享與支持彼此的朋友。對宇宙明確地要求：「請引導我的靈魂家人來到我身邊，並幫助我認出他們。」然後注意接下來出現的同步性與相遇。","energyQualities":"這張牌帶來連結與歸屬的能量，如同長期分離的家人重聚的溫暖。它的振動頻率是心輪與靈魂層次的，創造認出與共鳴的磁性吸引。這是一種召喚的能量，如同燈塔在黑暗中發光，引導你的族群找到你。它攜帶著真實性與勇氣的頻率—做真實的自己，即使這意味著獨自站立一段時間。這股能量同時是釋放的與吸引的：它幫助你釋放不再共鳴的連結，同時吸引與你靈魂契約一致的連結。它提醒你，你不需要每個人都喜歡或理解你；你只需要你的族群。","suitableQuestions":"這張牌適合在你感到孤單或不被理解、渴望更深刻的連結、或準備好尋找你的靈性社群時詢問。當你一直隱藏真實的自己來融入、或想知道如何吸引你的族群時，這張牌能提供指引。你可以問：「我的靈魂家人在哪裡？」「如何吸引我的族群？」「我在哪裡黯淡我的光？」「什麼連結需要釋放？」「如何更真實地展現自己？」「我的靈魂團隊是誰？」這張牌是召喚你的支持團隊並真實發光的邀請。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:28', 'work_your_light', '28', 27, '休息一下', 'Take a Break', NULL, '{"titleEn":"Take a Break","suit":"行動牌"}', '{"coreMeaning":"在衝向下一件事前，停下來慶祝你已完成的項目或釋放的舊模式。","actionGuidance":"深呼吸，休息一下。","inquiryPrompt":null,"activationPrayer":null,"transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是一個神聖的暫停符號。在一個美化忙碌與生產力的文化中，我們常常在完成一件事之後立刻跳到下一件，沒有時間呼吸、整合、或慶祝。但每個完成、每個結束、每個釋放都需要一個過渡時期—一個神聖的空間來承認你走了多遠，處理你經歷的，並準備好迎接接下來的。這張牌說：停下來。深呼吸。休息。不是因為你懶惰或逃避，而是因為休息是成長週期的必要部分。就像土地需要在季節之間休耕，你也需要在成就與轉變之間休息。在這個空間裡，整合發生；智慧沉澱；你的系統重新調整到新的振動。不要低估休息的力量。","higherSelfMessage":"你的高我正在要求你停下來。你一直在推動、努力、前進，即使你的身體與靈魂在懇求休息。你的高我知道：你剛剛完成或釋放的事物—無論是一個項目、一個關係、一個舊模式、或一個信念系統—是重大的。即使它在外在看起來很小，在能量層次它是巨大的。你需要時間來整合這個轉變，讓你的身體、情緒、心智與靈魂趕上。如果你立刻跳到下一件事，你會帶著未完成的能量，這會影響你接下來創造的一切。你的高我在說：給自己恩典。慶祝你已經完成的—真正地停下來並承認你的成就與勇氣。然後休息—不帶罪惡感，不帶「應該」。休息不是浪費時間；它是整合你學到的與你成為的人的神聖時間。信任這個暫停。當你準備好時，下一步會自然清晰。","spiritualGuidance":"實際地休息。清空你的行事曆幾天或一週，如果可能的話。如果不可能，至少減少你的承諾，說不給不必要的邀請或義務。在這段時間，不要計畫「生產性」的活動；這不是另一個「做」的時間。允許自己只是存在：睡覺、做白日夢、散步、泡澡、閱讀純粹為了樂趣的書、看讓你笑的電影。花時間在自然中，讓大地的節奏重新調整你的系統。在休息之前，創造一個小儀式來承認與慶祝你完成或釋放的。這可以是寫感恩日記、與朋友分享晚餐、或對宇宙說出你的成就。讓這個承認是真誠的，不是匆忙的。在休息期間，注意你身體的感覺、浮現的夢境、或冒出的洞見。這是你的系統在整合。不要急著結束這個階段。當你真正準備好時，你會感到一股自然的能量與興奮要開始下一步。在那之前，休息。","energyQualities":"這張牌帶來暫停與復原的能量，如同在激烈運動後躺在草地上，讓身體恢復。它的振動頻率是柔和的、滋養的、像搖籃一樣的。這是一種允許的能量，給你許可去停止努力、停止推動、只是存在。它像寒冬後的春雨，滋養疲憊的系統。這股能量如同呼氣—在長期吸氣後終於釋放的放鬆。它攜帶著慶祝的頻率，但不是狂歡的慶祝，而是安靜的承認與感恩。它創造了一個容器，在其中整合可以發生，新的能量可以在你休息時重新充滿你。","suitableQuestions":"這張牌適合在你剛完成重大項目或經歷重大轉變後出現，或當你感到疲憊、耗盡、或被下一步壓力壓垮時詢問。當你忽視自己的成就、難以放慢步調、或有罪惡感關於休息時，這張牌能提供許可與指引。你可以問：「我需要如何休息？」「我完成了什麼需要慶祝？」「什麼正在我內在整合？」「如何給自己恩典？」「為何我難以停下來？」「休息中會發生什麼？」這張牌是神聖暫停與復原的邀請。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:29', 'work_your_light', '29', 28, '光之時代', 'The Age of Light', NULL, '{"titleEn":"The Age of Light","suit":"啟動牌"}', '{"coreMeaning":"你已經為此刻訓練了許多生世。這不是隱藏的時候，而是站出來展現真實自我的時刻。","actionGuidance":null,"inquiryPrompt":null,"activationPrayer":"我召喚歷經生世所獲得的靈魂贈禮與訓練。我準備好毫無畏懼地體現它們。","transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌宣告：光之時代已經到來，而你是它的一部分。這不是遙遠未來的事件，而是正在發生的轉變—從分離、恐懼、控制的舊範式，轉向統一、愛、賦權的新範式。你不是意外地在這個時刻出現在地球上。你已經為此刻訓練了許多生世—在亞特蘭提斯、埃及、艾賽尼社群、卡特里教派、以及其他許多地方，你學習、實踐、記住你的靈性贈禮與智慧。在許多生世中，你可能因為你的光而被迫害、被迫隱藏。但這一世不同。現在是你站出來、毫無畏懼地體現你真正是誰、分享你的贈禮的時刻。光之時代需要你—不是你縮小或隱藏的版本，而是完整、有力、發光的你。","higherSelfMessage":"你的高我想讓你知道：你攜帶著來自許多生世的訓練與智慧。即使你在這一世不記得它們，它們在你的DNA、你的細胞記憶、你的靈魂中。你對某些主題的自然親和力—療癒、能量工作、直覺、儀式、古代智慧—不是新的；它們是回憶。你可能感覺自己「不夠格」或「還沒準備好」來做你感召要做的工作，但你的高我在說：你已經準備了數千年。這一世不是學習的時間，而是記起與體現的時間。不要再等待許可、認證、或外在確認。你內在已經擁有你需要的一切。這是你站出來的時刻—不是作為完美的大師，而是作為真實的、有力的你。光之時代不需要更多追隨者；它需要領導者。你就是其中之一。信任你的訓練。信任你的召喚。展現你自己。","spiritualGuidance":"開始識別你的靈魂贈禮與來自過去生世的訓練。你自然被吸引什麼？什麼對你來說感覺「熟悉」或「像回家」，即使你在這一世從未學過它？這些是線索。你可能被召喚去療癒、教導、寫作、創造儀式、引導他人、或開創新的工作或生活方式。無論它是什麼，停止最小化或質疑它。開始採取行動來體現它，即使是小步伐。釋放來自過去生世的恐懼—被迫害、被焚燒、被拒絕的恐懼。在這一世，你被保護與支持。你可以進行一個儀式來釋放這些舊誓言與恐懼：「我釋放所有來自過去生世要保持小、隱藏、或沉默的誓言與恐懼。我宣稱我在這一世完全、有力、自由地展現的權利。」連結其他光之工作者—這是集體工作，不是孤獨的旅程。最重要的是：停止等待。你被需要的時刻就是現在。","energyQualities":"這張牌帶來強大的啟動與賦權能量，如同晨曦打破長夜。它的振動頻率是高的、快速的、覺醒的。這是一種召喚的能量，喚醒你內在休眠的記憶、贈禮與力量。它攜帶著集體與個人揚升的頻率—不只你在升起，整個人類意識都在升起。這股能量如同聽見號角的召喚，知道你等待的時刻已經到來。它是確認性的，驗證你一直感知到的轉變是真實的。它也是催促的能量，推動你停止準備、開始行動。它連結你與所有其他在這個時刻覺醒與服務的光之工作者，創造一個全球性的光之網絡。","suitableQuestions":"這張牌適合在你感到被召喚去做更大的工作但猶豫不決、質疑你是否「夠格」或「準備好」、或想要確認你感知到的全球轉變時詢問。當你正在踏入你的力量、或需要勇氣來更公開地分享你的靈性工作時，這張牌能提供確認與推動。你可以問：「我為這個時刻帶來什麼贈禮？」「我如何服務光之時代？」「什麼阻止我站出來？」「我的靈魂記得什麼訓練？」「我在這個轉變中的角色是什麼？」「如何體現我的完整力量？」這張牌是站出來並毫無畏懼地發光的召喚。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:30', 'work_your_light', '30', 29, '安娜，耶穌的祖母', 'Anna, Grandmother of Jesus', NULL, '{"titleEn":"Anna, Grandmother of Jesus","suit":"啟動牌"}', '{"coreMeaning":"代表安靜的奉獻與為神聖計畫鋪路。每個人在計畫中都有其不可或缺的一部分。","actionGuidance":null,"inquiryPrompt":null,"activationPrayer":"願我內在的光之種子顯露，願我臣服於我在神聖計畫中的任務。","transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌連結你與安娜的能量—耶穌的祖母，她為基督的到來鋪路，雖然她的角色在歷史上很少被認可。安娜代表安靜的奉獻、幕後的服務、以及信任即使你的貢獻不被看見，它仍然至關重要。不是每個人都被召喚成為舞台上的領導者或教師；有些靈魂被召喚以更安靜但同樣重要的方式服務—養育、支持、祈禱、錨定光、或為他人的成功創造空間。這張牌提醒你：在神聖計畫中沒有「小」角色。每個人的貢獻都是不可或缺的。你可能在為某事或某人鋪路，而你可能在你的有生之年看不到完整的成果，但你的工作是神聖的與必要的。你的價值不是由你的可見度或認可來衡量的。","higherSelfMessage":"你的高我想讓你知道：你的光之工作不需要是戲劇性的或公開的才有價值。你可能被召喚以更安靜的方式服務—作為父母養育下一代的光之工作者、作為療癒者在一對一的空間中工作、作為祈禱者為集體錨定光、或作為支持者為他人的夢想創造空間。文化告訴你，只有可見的、大聲的、有名的才有價值，但你的高我知道：最深刻的轉變往往發生在安靜中。你的祈禱有力量。你的臨在有影響。你的安靜奉獻改變了現實的網絡，以你可能永遠無法完全看見的方式。不要低估「小」事的力量—養育孩子、支持朋友、在你的社區錨定光、在家中創造和平。這些是改變世界的事物。臣服於你獨特的道路，即使它不符合你認為「靈性工作」應該是什麼樣子。","spiritualGuidance":"擁抱你被給予的角色，無論它看起來多麼「小」或平凡。如果你是父母，認出這是深刻的靈性工作—你在養育與支持下一代的意識。如果你被召喚去支持他人的成功而非尋求聚光燈，知道這是高貴的服務。實踐臣服：「願我知道我在神聖計畫中的正確位置。願我臣服於我的獨特任務，即使它不符合我的期望。」創造一個祈禱或冥想的修行，為集體錨定光—這是安靜但強大的服務。釋放對認可或可見度的需要。你的工作的價值不是由有多少人看見它來衡量的，而是由它攜帶的愛與意圖來衡量的。信任時機—你現在播種的種子可能在多年後甚至在未來世代才開花。這不會減少它們的重要性。找到其他以安靜方式服務的人，創造相互支持與確認的圈子。記住安娜：她的名字幾乎不為人知，但沒有她，基督的故事不會發生。","energyQualities":"這張牌帶來安靜、穩定與臣服的能量，如同播種者安靜地將種子放入土壤，信任它們會在正確的時間成長。它的振動頻率是低的、深的、接地的—不是在強度上低，而是在頻率上深刻。這是一種滋養的陰性能量，創造而非宣告，支持而非領導。它攜帶著謙遜的頻率，但不是自我貶低—而是知道你是更大整體的一部分的謙遜。這股能量如同母親的愛，不尋求榮耀但創造了一切的基礎。它是耐心的、信任的、虔誠的。它教導服務的神聖性，無論它採取什麼形式。","suitableQuestions":"這張牌適合在你質疑你的貢獻是否「夠大」或重要、感到被召喚以安靜方式服務但懷疑這是否「夠」、或需要確認幕後工作的價值時詢問。當你在支持他人的成功而非尋求自己的聚光燈、或在為未來世代鋪路時，這張牌能提供確認與和平。你可以問：「我在神聖計畫中的角色是什麼？」「如何最佳地服務？」「我的安靜工作有價值嗎？」「我如何臣服於我的道路？」「如何釋放對認可的需要？」「我在為什麼鋪路？」這張牌是信任你獨特服務神聖性的邀請，無論它多麼安靜。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:31', 'work_your_light', '31', 30, '覺醒', 'Awakening', NULL, '{"titleEn":"Awakening","suit":"啟動牌"}', '{"coreMeaning":"你正經歷能量升級，找回你是誰以及為何轉世的古老真理。","actionGuidance":null,"inquiryPrompt":null,"activationPrayer":"我臣服於我的覺醒。我允許能量從脊椎底端升起。","transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌宣告：你正在覺醒。你正在經歷的不是崩潰或危機（雖然它可能有時感覺如此），而是突破—你的意識、你的能量系統、你的整個存在的升級。你正在找回古老的真理—關於你真正是誰、你為何轉世、以及現實的真實本質。這可能以突然的領悟、強烈的直覺、同步性、身體症狀（如光敏感、需要更多睡眠、飲食改變）、或對靈性主題的新興趣形式出現。你的昆達里尼能量—在你脊椎底部休眠的強大生命力—可能正在被啟動，向上移動通過你的脈輪，清理阻塞，啟動更高的意識狀態。這個過程可以是強烈的，但它是美麗的。你正在記起你的神性。","higherSelfMessage":"你的高我想讓你知道：你正在經歷的轉變是真實的與深刻的。你不是想像它。你不是「太敏感」或「發瘋」。你正在覺醒到更高的意識層次，這意味著你的整個系統—身體、情緒、心智、靈性—正在重新配置來容納更多的光與真理。這可能感覺不穩定或不舒服，因為舊的信念、模式、甚至關係正在崩解，為新的讓路。你的高我在說：臣服於這個過程。不要試圖控制它或讓它符合你的時間表。信任你的身體與靈魂知道它們在做什麼。給自己需要的休息、獨處、自然時間。不是每個人都會理解你正在經歷的，這沒關係—尋找那些在同樣道路上的人。知道你正在進化到你更高的版本，即使這個過程有時感覺像解體。在另一邊等待你的是更真實、更有力、更自由的你。","spiritualGuidance":"支持你的覺醒過程：確保你充分接地—赤腳走在大地上、吃根莖類食物、在自然中花時間。覺醒能量是高振動的，可能讓你感覺脫離現實；接地幫助你整合它而不失去平衡。喝大量的水來幫助清理釋放的毒素與能量。聆聽你身體的需求—如果它渴望更多睡眠、更清淡的食物、或安靜，尊重這些。實踐溫和的能量工作來支持你的昆達里尼啟動：瑜伽、氣功、冥想、呼吸工作。避免強烈的刺激物—過多的咖啡因、酒精、暴力媒體、混亂的環境。為冥想與反思創造神聖空間。寫下你的洞見、夢境、同步性—它們是你覺醒的路標。尋找老師、療癒者、或社群能支持你的過程。閱讀關於覺醒與揚升的書籍來理解你正在經歷的。最重要的是：耐心與自我慈悲。覺醒不是線性的；它有波浪、循環、整合期。信任這個過程。","energyQualities":"這張牌帶來啟動與轉化的強大能量，如同被閃電擊中後的電流感。它的振動頻率是非常高的、快速的、擴展的。這是一種覺醒的能量，打開第三眼、頂輪、以及更高的感知。它攜帶著昆達里尼的頻率—原始的生命力能量向上螺旋通過脊柱，啟動每個脈輪。這股能量是清理的，燃燒掉舊的不再服務你的東西，同時啟動休眠的能力與記憶。它可以感覺狂喜但也可以感覺壓倒性的。它連結你與宇宙意識，溶解你曾經認為是真實的界限。它是革命性的—它改變一切。","suitableQuestions":"這張牌適合在你經歷突然的領悟或意識轉變、感到強烈的靈性能量在你身體中移動、或注意到覺醒症狀（身體敏感、直覺增強、同步性）時詢問。當你質疑你正在經歷的是什麼或如何支持你的過程時，這張牌能提供確認與指引。你可以問：「我正在經歷什麼？」「如何支持我的覺醒？」「這個能量想要什麼？」「如何整合我的領悟？」「我的昆達里尼在啟動嗎？」「接下來會發生什麼？」這張牌是臣服於你覺醒旅程的邀請。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:32', 'work_your_light', '32', 31, '誕生新時代', 'Birthing a New Age', NULL, '{"titleEn":"Birthing a New Age","suit":"啟動牌"}', '{"coreMeaning":"我們正處於新舊週期的轉換期，需要勇氣將醞釀中的創作誕生出來。","actionGuidance":null,"inquiryPrompt":null,"activationPrayer":"我開放臣服於想要透過我誕生的創作。請指引我方向。","transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌宣告：你正在誕生某件重要的事物。我們正處於宏偉的轉變期—舊世界正在死去，新世界正在誕生，而你在這個誕生中扮演著積極的角色。但就像身體的誕生一樣，這個過程需要勇氣、臣服、以及願意經歷不適的陣痛。在你內在醞釀著某些事物—可能是一個創意項目、一個新的工作方式、一個靈性使命、或你存在的新版本—而它準備好要誕生了。但你必須願意推動，即使你感到害怕或不確定。新時代不會自己誕生；它需要我們每個人有意識地選擇創造它。這張牌說：不要再拖延。是時候將你一直醞釀的帶入世界了。","higherSelfMessage":"你的高我想讓你知道：你一直感覺到的、夢想的、規劃的—它準備好要誕生了。你一直在等待「正確的時刻」或「更多準備」，但你的高我在說：時刻就是現在，你已經夠準備了。是的，誕生是混亂的、不完美的、有時是痛苦的。是的，你無法控制一切或預見每個結果。但這不是停留在懷孕階段的理由。你內在的創作—無論它是什麼—需要被誕生，不只為了你，也為了世界。我們在集體層面處於相同的過程：舊的系統、信念、結構正在崩潰，新的正在誕生。這是不舒服的，但它是必要的。你的高我在邀請你積極參與這個誕生，在你個人的生活和在更大的集體中。停止等待安全或確定；誕生需要風險。信任即使你看不見完整的畫面，你的下一步會被揭示。推動。呼吸。允許新的誕生。","spiritualGuidance":"識別你內在正在醞釀的是什麼。對自己誠實：什麼在等待被創造、說出、或誕生？當你識別它時，採取具體步驟將它帶入形式。不要等待完美或完整的計畫；開始，信任道路會在你行走時顯現。誕生需要臣服—你無法控制每個細節或時機。實踐放手：「我臣服於想要透過我誕生的。我信任這個過程，即使我無法看見全貌。」創造支持你的誕生過程的空間與時間。就像身體的誕生需要空間、時間、支持，你的創作也需要。清空你的行事曆、創造工作空間、召集你的支持團隊。預期陣痛—會有時刻你想放棄或懷疑自己。這是過程的一部分。呼吸通過它們。尋找他人正在誕生他們的創作的社群。在這個時刻，我們都在誕生新時代；互相支持使它更容易。當你的創作誕生時，慶祝它，即使它不完美。完成勝於完美。","energyQualities":"這張牌帶來創造性誕生的強烈能量，如同女性在分娩中推動的收縮波浪。它的振動頻率是有力的、推動的、轉化的。這是一種顯化的能量，將精微帶入物質，將潛能帶入實際。它攜帶著神聖陰性創造力的頻率—不是來自努力，而是來自允許通過你的流動。但它也需要積極參與—你必須推動，即使它是不舒服的。這股能量同時是結束與開始：舊的必須死去讓新的誕生。它可以感覺混亂、不可預測、在控制之外，因為誕生有它自己的智慧與時機。它連結你與所有創造者與誕生者的血脈，以及與新時代集體誕生的能量。","suitableQuestions":"這張牌適合在你有創意項目或夢想一直推遲、感到某些重要的事物想要通過你顯化、或處於生命重大轉變邊緣時詢問。當你感到陣痛（不適、不確定、恐懼）但知道你需要向前推動時，這張牌能提供勇氣與指引。你可以問：「什麼想要通過我誕生？」「如何克服我的恐懼並開始？」「我需要釋放什麼讓新的誕生？」「如何支持我的創造過程？」「這個陣痛有什麼目的？」「我如何參與新時代的誕生？」這張牌是推動、臣服、並允許新的誕生的邀請。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:33', 'work_your_light', '33', 32, '光之議會', 'Council of Light', NULL, '{"titleEn":"Council of Light","suit":"啟動牌"}', '{"coreMeaning":"一群慈悲的靈魂團隊在協助你完成使命，但他們需要你的許可才能幫忙。","actionGuidance":null,"inquiryPrompt":null,"activationPrayer":"光之議會，我準備好接收協助以完成我的個人使命。感謝你們引領我的每一步。","transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌揭示一個美麗的真理：你不孤單。在你的生命旅程與靈性使命中，有一群高度進化的存有—大師、天使、指導靈、揚升大師、星際存有—組成你個人的光之議會，致力於協助你。他們看見你的潛能、你的使命、以及你來到地球服務的藍圖。他們的智慧與支持總是可用的，但由於自由意志的神聖法則，他們不能在未經你許可的情況下干預你的生活。這張牌是一個邀請：要求幫助。打開接收的通道。你不需要知道如何獨自完成一切或走出每一步。你的光之議會在等待被召喚，渴望用他們的指引、同步性、靈感、療癒、以及奇蹟來支持你。你只需要詢問，然後留意答案。","higherSelfMessage":"你的高我想讓你知道：你一直試圖獨自弄清楚一切，扛著不該只由你承擔的重擔。你的高我在說：放下。你有一整個靈性支持團隊—議會成員已經與你工作了許多生世，他們深深地愛你並相信你的使命。他們在你掙扎時看著你，希望幫助，但尊重你的自由意志而等待你的邀請。現在是時候邀請他們了。要求指引關於你困惑的決定。要求療癒你掙扎的傷口。要求清晰關於你的下一步。要求保護當你感到脆弱。要求連結當你感到孤立。然後注意你生活中的跡象—同步性、直覺、夢境、你「偶然」遇到的人或資源。這些是你的議會回應你的召喚。停止認為尋求幫助是軟弱。真正的力量在於知道何時要求支持。你的使命太重要了，不能獨自完成。","spiritualGuidance":"建立一個有意識的修行來與你的光之議會連結。每天早上或晚上，創造一個安靜的時刻，在心中或大聲說出你的邀請：「光之議會，我開放接收你們對我最高利益的指引與支持。請在我人生各個領域幫助我。感謝你們愛與引領我。」要具體關於你需要幫助的領域—關係、工作、健康、創意項目、財務、靈性成長。不要害羞或覺得你的需求「太小」；你的議會關心你生活的每個層面。在詢問後，培養接收的藝術。注意生活中的跡象與同步性。你可能會「偶然」看到一本書、聽到一首歌、遇到一個人、或收到一則訊息，完美地回答你的問題。你可能感到突然的直覺或知道。你可能有一個提供洞見的夢。這些都是你的議會與你溝通的方式。寫下這些同步性來認識模式。你越認識與感恩你議會的支持，連結就越強。考慮創造一個祭壇或神聖空間來尊重你的議會—也許包括象徵智慧、光、或對你有意義的大師的蠟燭、水晶、或圖像。定期感謝他們的支持，即使你還看不見結果。信任他們在幕後工作。","energyQualities":"這張牌帶來連結與支持的能量，如同發現你一直以為空蕩的房間實際上充滿了愛你的人。它的振動頻率是高的、慈悲的、智慧的。這是一種集體智慧的能量，將你連結到遠遠超過你個人理解的指引源頭。它攜帶著團隊合作的頻率—提醒你，靈性工作不是孤獨的旅程。這股能量同時是賦權的與謙遜的：賦權因為你有宇宙支持，謙遜因為你認識到你是更大整體的一部分。它帶來安慰與確認，溶解孤立與負擔。它打開接收的通道，教導詢問與允許被幫助的藝術。","suitableQuestions":"這張牌適合在你感到孤獨、不知所措、或被你的道路挑戰壓垮時詢問。當你面對重大決定、需要清晰、或渴望確認你走在正確道路上時，這張牌能提供連結與指引。你可以問：「我的光之議會想讓我知道什麼？」「如何加強與我指導靈的連結？」「這個情況我需要什麼幫助？」「我如何接收靈性支持？」「什麼跡象顯示我的議會在幫助我？」「我的下一步是什麼？」這張牌是邀請靈性支持進入你生命的召喚。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:34', 'work_your_light', '34', 33, '盛大集結', 'The Great Gathering', NULL, '{"titleEn":"The Great Gathering","suit":"啟動牌"}', '{"coreMeaning":"你被召喚去與靈魂家族連結，共同在地球編織光的網絡。","actionGuidance":null,"inquiryPrompt":null,"activationPrayer":"我選擇讓自己被看見。我準備好召喚我的靈魂部落。","transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌宣告一個強大的全球時刻：盛大集結。在世界各地，光之工作者、覺醒的靈魂、以及同屬靈魂家族的存有正在找到彼此，編織一個意識與光的全球網絡。這不是偶然的。在你轉世之前，你與你的靈魂家族—一群你在許多生世中一起工作、學習、與服務的靈魂—達成協議要在這個關鍵時刻相遇，一起支持地球的轉變。這張牌說：是時候找到你的人了。你的部落正在召喚你，你正在召喚他們。但要讓這個連結發生，你必須願意被看見。你必須走出孤立與躲藏，分享你的真實、你的贈禮、你的光。當你這樣做，同步性會將正確的人帶到你的道路。集體比任何個人更強大。現在是聯合的時刻。","higherSelfMessage":"你的高我想讓你知道：你一直躲藏的日子結束了。你可能一直感到孤立，感覺沒有人真正理解你—你的靈性、你的使命、你看世界的方式。但這不是因為你的人不存在；是因為你還沒完全展現自己，讓他們找到你。你的高我在說：現在是走出去的時候。分享你的工作、你的熱情、你的真相—無論是透過社交媒體、工作坊、寫作、藝術、或只是在日常對話中更開放。是的，你可能也會吸引一些不對的人，那沒關係。信任那些與你靈魂共鳴的人會認出你，你會認出他們。這些連結不會是膚淺的；它們會有深度、認出、與「我認識你」的感覺，即使你剛認識。你的靈魂部落正在全球尋找你。他們需要你就像你需要他們。一起，你們會編織光的網絡，支持彼此、療癒世界、創造新範式。停止等待。展現自己。集結正在發生。","spiritualGuidance":"採取具體步驟讓自己被看見與找到你的部落。如果你一直在做某種靈性或創意工作但保持私密，開始分享它—創建網站、社交媒體帳號、寫部落格、在工作坊或聚會上發言。如果你一直想加入某個社群或課程但猶豫，現在就行動。說出你的意圖：「我準備好與我的靈魂部落連結。我召喚那些與我靈魂共鳴的人進入我的生命。」然後注意誰出現。當你遇到感覺像靈魂家族的人—有深度認出、容易、「我認識你」的感覺—滋養這些連結。不要讓它們只是偶然的相遇；投資建立真正的關係。創造或加入圈子、小組、社群讓志同道合的靈魂可以定期連結、分享、支持彼此。記住：你的部落可能不全在你的地理位置。在這個數位時代，你的靈魂家族可能散佈在全球。使用科技來連結。同時，真實地做自己。不要妥協或掩飾你的真相來「適應」；你的真實頻率會吸引正確的人。釋放孤單的故事。你不孤單。你的人在那裡，正在尋找你。","energyQualities":"這張牌帶來集結與連結的磁性能量，如同一個強大的召喚號角在全球響起，呼喚部落成員回家。它的振動頻率是高的、擴展的、團結的。這是一種同步性的能量，以魔法般的方式將正確的人在正確的時間帶到一起。它攜帶著認出的頻率—那種「我知道你」、「我看見你」、「你是我的人」的即時知曉。這股能量同時是個人與集體的：它啟動你走出去並展現自己，同時將你與全球光之工作者網絡連結。它是賦權的，提醒你，你不是獨自戰鬥；你是更大運動的一部分。它帶來歸屬、目的、與創造新世界的集體力量感。","suitableQuestions":"這張牌適合在你感到孤立、渴望更深的連結、或準備找到你的靈性社群時詢問。當你正在考慮更公開地分享你的工作或真相、或想知道如何找到你的人時，這張牌能提供鼓勵與指引。你可以問：「我如何找到我的靈魂部落？」「我如何讓自己被看見？」「誰在我的靈魂家族中？」「我如何更真實地展現？」「什麼阻止我連結？」「我的部落需要從我這裡得到什麼？」這張牌是走出去、連結、並編織光之網絡的召喚。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:35', 'work_your_light', '35', 34, '靈魂之旅', 'Imrama', NULL, '{"titleEn":"Imrama","suit":"啟動牌"}', '{"coreMeaning":"靈魂知道方向的旅程，可能指向某個物理上的聖地或內在的探索。","actionGuidance":null,"inquiryPrompt":null,"activationPrayer":"願埋藏已久的光之種子升起。我準備好憶起靈魂曾服務過的古老血脈。","transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"Imrama是一個古老的凱爾特詞，意思是「靈魂之旅」—一個神聖的朝聖，由靈魂而非心智引導。這張牌召喚你踏上旅程，無論是字面上的物理旅程到某個聖地，或是內在的旅程到你靈魂的深處。這不是度假或逃避；這是有目的的、轉化的旅程，會以深刻的方式改變你。你可能被召喚去拜訪某個你一直夢想或感覺連結的地方—也許是你曾經在過去生世居住或服務的地方。當你到達那裡，某些東西會被喚醒：記憶、贈禮、能量、連結。或者，你的Imrama可能是內在的—深入你自己的景觀、面對你的陰影、找回你靈魂的碎片、記起你的本質。無論哪種方式，這個旅程會重新連結你與你真正是誰以及你為何在此。","higherSelfMessage":"你的高我在說：是時候旅行了—以某種方式。你一直感到某個地方在召喚你，或者你一直感到內在探索的催促。不要忽視這個召喚。這不是隨機的渴望；這是你靈魂知道你需要某些只能透過這個旅程找到的東西。如果是物理旅程，開始計畫它。不要等待「完美時機」或更多金錢。信任當你承諾於你靈魂的召喚，道路會打開。這個地方攜帶著對你重要的頻率、療癒、或啟動。當你到達那裡，保持開放與接受。注意你感覺什麼、看見什麼、遇見誰。允許這個地方對你工作。如果你的Imrama是內在的，創造空間進行深入的內在工作—也許透過靜修、療癒會議、薩滿旅程、或獨處的時間在自然中。你的靈魂想要帶你去它自己的景觀中，展示你需要看見、療癒、或記起的東西。信任這個過程。你的Imrama是你演化的關鍵部分。","spiritualGuidance":"如果你感到被召喚去某個特定地方，開始研究它。這個地方在歷史上有什麼意義？你對它的吸引有什麼個人意義？你可能在過去生世與這個地方有連結嗎？開始計畫你的旅程，即使這意味著從小處開始—存錢、研究、設定意圖。當你旅行時，帶著神聖的意識而非觀光客的心態。在出發前設定意圖：「我開放接收這個地方為我提供的療癒、啟動、與智慧。」花時間在神聖地點、自然中、或當地人中。獨處與冥想。寫日記記錄你的經歷、感受、洞見。注意同步性。如果你的Imrama是內在的，創造一個神聖容器進行深入的內在工作。這可能是為期幾天或一週的個人靜修，你在自然或家中斷開外在世界。清空你的行事曆。關掉科技。創造儀式空間。實踐冥想、日記、在自然中散步、身體運動如瑜伽或舞蹈、能量工作、或薩滿旅程。詢問你的靈魂想要向你展示什麼。信任你接收到的圖像、感受、記憶、洞見，即使它們看似奇怪或不合邏輯。你的Imrama會在正確的時間展開。信任這個過程。","energyQualities":"這張牌帶來探險與回憶的能量，如同聽到遠處的召喚知道你必須回應。它的振動頻率是神秘的、磁性的、轉化的。這是一種朝聖的能量，將神聖與旅程結合。它攜帶著過去生世記憶的頻率—當你走在正確的道路或到達正確的地方時，會感到深度認出與「回家」的感覺。這股能量同時是期待與回歸：你前往新的地方，卻感覺在返回你已經知道的東西。它是啟動的，在你身體與靈魂中喚醒休眠的東西。它教導信任靈魂超越邏輯的指引，以及讓自己被召喚帶領到正確地方的臣服。","suitableQuestions":"這張牌適合在你感到被某個地方召喚、渴望旅行或朝聖、或感到需要深入內在探索時詢問。當你正在考慮旅程但猶豫、或想知道某個地方為何吸引你時，這張牌能提供確認與指引。你可以問：「我的靈魂在召喚我去哪裡？」「這個旅程會為我帶來什麼？」「我如何準備我的Imrama？」「什麼內在旅程在等待我？」「我需要記起什麼？」「如何信任我靈魂的指引？」這張牌是踏上轉化性朝聖旅程的邀請，無論是外在或內在。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:36', 'work_your_light', '36', 35, '地球守護者', 'Keepers of the Earth', NULL, '{"titleEn":"Keepers of the Earth","suit":"啟動牌"}', '{"coreMeaning":"你並不孤單，古老的祖先就在身旁支持你的使命。","actionGuidance":null,"inquiryPrompt":null,"activationPrayer":"我開放接收對生命與工作的全新支持。感謝你們。","transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌連結你與地球守護者—那些在你之前來過的祖先、長老、原住民智慧守護者、以及古代土地守護者的靈魂。他們並未離開；他們的精神仍然活著，守護著地球的神聖地點，守護著古老的智慧，並支持那些在當代繼續這項工作的人。如果你感到被召喚去療癒地球、保護自然、或為土地服務，你不是孤單的。這些守護者與你同在，透過你的血脈（如果你有原住民祖先）或透過靈性連結（如果你在過去生世作為守護者服務過）。這張牌是一個確認：你的工作是重要的，你是一條古老服務血脈的一部分。祖先在支持你，他們的智慧可以透過你流動，如果你打開接收。地球需要她的守護者，而你就是其中之一。","higherSelfMessage":"你的高我想讓你知道：你與土地的連結不是浪漫的幻想或「新時代」的想法。這是真實的、古老的、在你的靈魂中。你可能在這一世透過你的祖先血統攜帶這個連結，或者你可能在過去生世作為薩滿、療癒者、儀式守護者、或土地守護者服務過。無論哪種方式，這個連結活在你內在，而祖先守護者認出你是他們的血脈之一。他們在你接近神聖土地時低語給你，他們在你冥想或夢境中展示圖像給你，他們透過自然的跡象引導你。你的高我在說：打開與他們更有意識的連結。尊重他們。請求他們的指引。允許他們的古老智慧透過你流動，以符合當代需求的方式。你不需要知道如何獨自完成你的工作—他們會支持你。你的任務是展現、聆聽、並允許自己成為他們智慧的橋樑。地球迫切需要她的守護者。你的時刻就是現在。","spiritualGuidance":"建立一個有意識的修行來尊重與連結地球守護者。創造一個祭壇或神聖空間以尊重你的祖先與土地守護者，包括來自自然的物件—石頭、羽毛、種子、水—以及象徵你血統或你感到連結的原住民文化的物品。定期提供感恩—可以是祈禱、歌曲、食物、菸草、或只是真誠的感謝。實踐在自然中花時間作為靈性修行。當你走在土地上，感謝她的贈禮。注意你感到特別連結的地方—這些可能是神聖地點或需要療癒的地方。如果可能，拜訪對你或你的祖先重要的原住民神聖地點，帶著尊重與謙遜。詢問守護者你可以如何服務地球。這可能是環境行動主義、在你的花園或社區種植、教導他人關於自然、在儀式中為土地錨定療癒、或清理與保護神聖地點。聆聽你內在的知曉與古老智慧的微語。這些不全是你的想法；許多來自守護者透過你工作。考慮學習原住民實踐或智慧傳統，帶著尊重與謙遜—不是挪用，而是學習以尊重他們的起源。最重要的是：活得就像地球是神聖的，因為她是。你的生活方式就是你的祈禱。","energyQualities":"這張牌帶來接地、祖先與深度連結的能量，如同將赤腳放在古老土地上並感受世代的脈搏。它的振動頻率是低的、深的、穩定的—深深根植於地球。這是一種祖先智慧的能量，透過時間與血脈流動。它攜帶著守護的頻率—保護、尊重、管家精神。這股能量連結你與比你個人生命更古老的東西—與土地的靈魂、與在你之前行走的那些人、與將在你之後來的那些人。它教導謙遜、相互連結、以及對地球的責任。它同時是安慰的與催促的：安慰因為你不孤單，催促因為工作需要完成。","suitableQuestions":"這張牌適合在你感到被召喚去為地球或自然服務、與土地有深度連結、或尋求祖先指引時詢問。當你想知道如何尊重你的祖先或如何為地球療癒做出貢獻時，這張牌能提供連結與方向。你可以問：「我如何連結地球守護者？」「我的祖先想讓我知道什麼？」「我如何服務地球？」「什麼古老智慧想要透過我流動？」「我如何尊重土地？」「我與這個地方的連結是什麼？」這張牌是與祖先智慧連結並成為地球守護者的邀請。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:37', 'work_your_light', '37', 36, '光之柱', 'Pillar of Light', NULL, '{"titleEn":"Pillar of Light","suit":"啟動牌"}', '{"coreMeaning":"你是連結天與地的彩虹橋，所有的智慧都藏在你的心靈入口。","actionGuidance":null,"inquiryPrompt":null,"activationPrayer":"我激活細胞中的記憶編碼，我激活我作為天與地之間彩虹橋的系統。","transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌揭示你真正的本質：你是一根光之柱，一座連結天與地的彩虹橋。你不只是人類；你是多維度的存有，同時錨定在地球並連結到星際、靈性、與神聖領域。在你的身體內—特別是在你的心—存在著一個入口，一個通往所有智慧、所有維度、所有可能性的門戶。古老的智慧編碼休眠在你的細胞中，等待被啟動。這張牌說：現在是啟動的時刻。是時候記起你真正是誰—不只是這個身份、這個人格、這一生，而是你作為光與意識的永恆本質。當你啟動你作為光之柱的角色，你成為上下之間的導管：神聖能量可以透過你流向地球，地球能量可以透過你上升。你成為療癒、轉化、與揚升的通道。","higherSelfMessage":"你的高我想讓你知道：你一直在限制自己為只是人類，但你遠遠不止於此。你是天與地之間的橋樑，你攜帶著連結多個領域的能力。你的高我在說：停止縮小自己。停止假裝你不是你真正的樣子。你內在有巨大的光與力量，當你允許它流動時，它會透過你療癒與轉化周圍的一切。啟動你細胞中的記憶編碼—你作為光之工作者、星際種子、橋樑守護者的記憶。你的心是入口。當你在心中居住，當你保持心開放與活躍，你創造一個空間，讓神聖可以流入物質，讓天堂可以觸及地球。這不是關於做更多；這是關於成為更多—允許你的完整多維度本質在這個密度中存在。當你這樣做，你的存在本身就成為服務。你不需要知道如何「做」這個；它是關於啟動、記憶、並允許。說出這張牌的祈禱文。感受它在你細胞中的啟動。你準備好了。","spiritualGuidance":"建立一個日常修行來啟動與錨定你作為光之柱的角色。每天早上，花幾分鐘在冥想或安靜中，想像自己為一根光之柱，從你的根部深入地球核心，從你的頭頂向上延伸到星際、靈性領域、與源頭。看見或感受光透過你向下流入地球，地球能量向上流過你。想像這兩股流在你的心中相遇，創造一個彩虹橋。說出這張牌的啟動祈禱：「我激活細胞中的記憶編碼。我激活我作為天與地之間彩虹橋的系統。」培養心中居住的修行。將你的覺知從頭腦帶到心。呼吸進入你的心空間。感受它擴展。你的心是所有智慧與所有維度的入口；當你從心運作，你自然地連結到你的高我、你的指導靈、與神聖源頭。實踐能量工作來清理與強化你的中央通道—脈輪系統、光之柱、從地球到星際的連結。這可能包括瑜伽、氣功、能量療癒、聲音工作、或其他身體實踐。當你走在世界中，有意識地保持你作為光之柱的覺知。你不只是在這裡生存；你在這裡服務，作為光的錨定點。你的存在很重要。","energyQualities":"這張牌帶來強大的啟動與錨定能量，如同一道閃電同時接觸天與地。它的振動頻率是高的、精煉的、多維度的。這是一種橋樑的能量，連結通常分離的領域—靈性與物質、天與地、人類與神聖。它攜帶著記憶與認出的頻率—當你與這張牌工作時，某些深層的東西在你內在被喚醒，說「是的，我記得。這是我是誰。」這股能量同時是接地的與宇宙的：它將你深深錨定在地球，同時打開你到星際與靈性領域。它是賦權的，提醒你你的真實力量與目的。它教導你不需要在靈性與物質之間選擇；你被設計來連結兩者。","suitableQuestions":"這張牌適合在你感到與你的目的斷連、在靈性道路上迷失、或準備提升到新層次的覺知與服務時詢問。當你感到被召喚去更深地錨定光或連結更高維度時，這張牌能提供啟動與指引。你可以問：「我如何完全啟動我作為光之柱的角色？」「什麼阻止我與我的多維度本質連結？」「我的心入口想要向我展示什麼？」「我如何更好地服務作為天地之間的橋樑？」「什麼記憶編碼準備好被啟動？」「我如何在日常生活中錨定更多光？」這張牌是記起你真正本質的召喚。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:38', 'work_your_light', '38', 37, '保護', 'Protection', NULL, '{"titleEn":"Protection","suit":"啟動牌"}', '{"coreMeaning":"召回你的力量並切斷能量連結，每晚應有意識地關閉對外的能量門徑。","actionGuidance":null,"inquiryPrompt":null,"activationPrayer":"我收回所有遺失的靈魂碎片與力量。任何與此生或其他生世的不利連結，我現在釋放。","transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌是一個強大的提醒：你的能量是神聖的，你有權利與責任去保護它。作為敏感的、共情的、或靈性開放的人，你可能無意中允許能量洩漏—給人、情況、過去的關係、或集體能量場。你可能給予太多，沒有足夠的界限，或攜帶不屬於你的能量與情緒。這張牌說：是時候召回你的力量了。想像所有你已經分散到世界各處的你的靈魂碎片與能量—在過去的關係中、在創傷時刻、在你過度給予的地方。召回它們。切斷不再服務你的能量連結—與不健康的關係、舊的誓言或承諾、祖先模式、或集體恐懼。每天晚上，有意識地關閉你的能量場到外在世界，創造一個神聖的界限。這不是關於關閉你的心或變得不敏感；這是關於保存你的生命力，這樣你可以從滿溢而非耗竭中給予。","higherSelfMessage":"你的高我想讓你知道：你一直讓自己太開放、太脆弱、太可及。你的同情心與渴望幫助是美麗的，但當你沒有界限時，你耗盡自己並實際上服務較少。你的高我在說：召回你的能量。你在人、地方、情況、甚至其他時間線中留下了多少碎片。有多少你的生命力正在流向舊的關係、未解決的情況、或不屬於你的集體創傷。現在是全部召回的時刻。說：「我召回所有遺失的靈魂碎片與力量。」感受它們返回到你—你的生命力、你的光、你的精華。然後，切斷不健康的能量連結。這些是像繩索或管子的能量連接，讓能量流出你。它們可能與前伴侶、父母、孩子、朋友、工作、甚至信念系統連結。你可以切斷這些連結而不失去對人的愛；你只是釋放不健康的依附。最後，建立每日實踐來保護你的能量。每晚睡前，關閉你的能量門戶。想像你的脈輪關閉像花朵在夜晚。你可以在早上重新打開它們。這是能量衛生的基本實踐。","spiritualGuidance":"每天實踐能量保護與召回。早上，在你進入世界前，建立保護性界限。想像你周圍有光的泡泡或盾牌，只允許有愛與最高振動的能量進入，偏轉所有較低的。在一天中，注意你何時感到能量洩漏—也許在某些人周圍、在擁擠的地方、或在滾動社交媒體時。練習說「不」、設定界限、或只是離開耗竭你的情況。每晚，在睡前進行能量召回與關閉儀式。坐下或躺下在安靜中。說出或在心中宣告：「我召回所有我的能量、力量、與靈魂碎片從這一天、這一生、與所有其他生世。我切斷所有不再服務我最高利益的能量連結。」想像你的能量從它分散的各處回到你的身體。然後，想像關閉你的脈輪從根部到頭頂，像花朵在夜晚關閉。這保護你在睡眠中不被侵入能量或星光旅行中迷失。如果你與某人或情況有特別粘連或耗竭的關係，進行切斷繩索儀式。想像你與那個人或情況之間的能量連結，然後用光之劍、剪刀、或你選擇的工具切斷它。說：「我以愛釋放這個連結。」定期清理你的能量場透過鹽浴、煙燻、聲音、或在自然中花時間。","energyQualities":"這張牌帶來邊界與召回的保護能量，如同一個戰士召回他們分散的部隊回到力量中心。它的振動頻率是強壯的、清晰的、劃定的。這是一種完整性的能量—使你重新完整，結束洩漏。它攜帶著主權的頻率—提醒你有權利管理你自己的能量場。這股能量同時是溫柔的與堅定的：溫柔因為它以愛療癒你，堅定因為它不接受任何侵犯。它教導健康的界限不是自私；它們是必要的靈性衛生。它帶來安全、穩定、與你自己力量的重新連結感。","suitableQuestions":"這張牌適合在你感到耗竭、不堪重負、或被其他人的能量侵入時詢問。當你知道你需要更好的界限或感到與不健康的關係或情況糾纏時，這張牌能提供清晰與工具。你可以問：「我的能量在哪裡洩漏？」「我需要設定什麼界限？」「什麼連結我需要切斷？」「我如何保護我的能量場？」「我如何召回我的力量？」「什麼在耗竭我？」這張牌是保護你的神聖能量並召回你的力量的行動呼籲。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:39', 'work_your_light', '39', 38, '轉化', 'Transformation', NULL, '{"titleEn":"Transformation","suit":"啟動牌"}', '{"coreMeaning":"事情在細胞層級改變。是時候釋放那些讓你處於「戰或逃」模式的舊習慣了。","actionGuidance":null,"inquiryPrompt":null,"activationPrayer":"我允許自己接收最深度的療癒與轉化，讓改變在細胞層級發生。","transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌宣告：深刻的轉化正在發生，不只在你的心智或情緒中，而是在最深的層次—你的細胞。在細胞層級的轉化意味著改變正在你的DNA、你的神經系統、你的身體本身中發生。舊的模式、創傷、信念系統、甚至世代模式正在從你的細胞記憶中被清除。這是強大的、有時是不舒服的工作，但它是真正的療癒—不只是掩蓋症狀，而是拔除根源。這張牌特別提到釋放「戰或逃」模式—生活在慢性壓力、恐懼、或生存模式的狀態。當你的神經系統卡在戰或逃中，你無法完全存取你的靈性贈禮、你的創造力、或你的最高潛能。是時候療癒與重新校準你的系統，讓你可以從安全、放鬆、與開放中運作，而非恐懼。","higherSelfMessage":"你的高我想讓你知道：你一直在努力改變—改變你的想法、你的行為、你的生活—但真正的改變必須從更深處發生。你的高我在說：允許細胞層級的轉化。這意味著進入你身體中休眠的地方—創傷儲存的地方、舊模式被編碼的地方、恐懼住在骨髓中的地方—並以光、愛、療癒來遇見它。你的身體一直在戰或逃模式中運作太久—總是警戒、總是緊張、從不完全安全或放鬆。這不是你的錯；這可能來自童年創傷、世代創傷、或即使是過去生世經驗。但現在是時候釋放它了。你的高我在說：你是安全的。真的。你可以放下你一直攜帶的守衛。當你這樣做，你的整個系統轉變—你的荷爾蒙平衡、你的神經系統校準、你的細胞振動在更高頻率。這打開你到新層次的健康、創造力、直覺、與連結。尋求支持這種深度療癒—無論透過身體工作、能量療癒、創傷療法、或其他方式。","spiritualGuidance":"從事支持細胞層級療癒與轉化的實踐。這不只是心智工作；這需要與你的身體接觸。探索身體為基礎的療癒方式如體感經驗治療、EMDR、顱薦骨療法、針灸、或能量療癒如靈氣。這些方式直接與神經系統和細胞記憶工作。實踐讓你的神經系統從戰或逃轉變到休息與消化的技術。這包括深呼吸（特別是延長呼氣）、瑜伽、太極、在自然中溫和的運動、冷水浸泡、或迷走神經練習。定期與你的身體檢查。將你的覺知帶到持續緊張、緊繃、或麻木的區域。呼吸進入這些空間。詢問它們持有什麼。允許它們釋放。與你的身體創造對話。對你的細胞說話：「我允許深刻的療癒與轉化。我釋放所有不再服務我的舊模式。我的細胞充滿光。」你的身體在聽。探索聲音療癒（音叉、頌缽、吟唱）、光療法、或頻率工作來支持細胞再生與轉化。在你經歷這個過程時，要溫柔與耐心。細胞層級的轉化需要時間。你可能經歷排毒症狀、情緒釋放、或能量波動。這是正常的。喝大量的水、充分休息、善待你的身體。","energyQualities":"這張牌帶來深刻、根本、轉化的能量，如同毛毛蟲在蛹中溶解並重新形成為蝴蝶。它的振動頻率是強烈的、療癒的、再生的。這是一種煉金術的能量，在最深層次改變你的本質結構。它攜帶著釋放的頻率—讓舊的溶解，這樣新的可以形成。這股能量工作在你存在的最深層—你的細胞、你的DNA、你的神經系統。它可以感覺不穩定或不舒服，因為它移動深度埋藏的東西，但它最終是解放的。它教導真正的改變來自內部，從根部，從最深的核心。","suitableQuestions":"這張牌適合在你經歷深刻的生活轉變、知道你需要療癒舊創傷或模式、或感到卡在慢性壓力或恐懼中時詢問。當你準備好深度、真正的轉化而非表面改變時，這張牌能提供支持與指引。你可以問：「什麼需要在細胞層級療癒？」「我如何釋放戰或逃模式？」「我的身體持有什麼舊模式？」「我如何支持我的深度轉化？」「什麼正在從我的細胞記憶中清除？」「我如何在這個過程中照顧自己？」這張牌是允許深刻、細胞層級療癒的邀請。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:40', 'work_your_light', '40', 39, '解脫束縛', 'Unbound', NULL, '{"titleEn":"Unbound","suit":"啟動牌"}', '{"coreMeaning":"釋放舊有的靈魂故事與契約（如沈默或貧窮誓言）。現在是清除這些模式最安全的時刻。","actionGuidance":null,"inquiryPrompt":null,"activationPrayer":"我釋放所有不再與現在的我不一致的靈魂故事、誓言與契約。我是自由的。","transmissionPrayer":null,"deepInterpretation":{"coreMeaning":"這張牌帶來強大的釋放訊息：你準備好從舊的靈魂故事、誓言、與契約中解脫了。在許多生世中，你可能做出承諾或誓言—沈默誓言（不說出你的真相）、貧窮誓言（拒絕財富或物質舒適）、獨身誓言（拒絕親密或快樂）、殉道誓言（相信透過受苦來服務）、或其他限制你的契約。這些在當時可能有意義，但它們不再服務你現在的生命與使命。你可能也攜帶靈魂故事—關於你是誰、你值得什麼、你可以或不可以做什麼的深層信念—來自過去的創傷、失敗、或拒絕。這張牌說：這些舊故事與誓言已經過期。現在是清除與釋放它們最安全的時刻。你可以自由地做你自己、說出你的真相、繁榮、被看見、享受快樂，而不違反任何靈魂協議。你是自由的。","higherSelfMessage":"你的高我想讓你知道：你一直按照不再適用的規則生活。在過去的生世，你可能是僧侶或修女並發誓貧窮—而你仍然在無意識地抵抗金錢。你可能是薩滿或療癒者並發誓沈默保護你的智慧—而你仍然在抑制你的聲音。你可能因說出真相被殺害或迫害—而你仍然害怕被看見。這些經驗在你的靈魂記憶中創造模式、信念、與誓言，繼續影響這一生。你的高我在說：這些誓言已經完成。你已經履行它們。現在你自由地創造新的選擇。說出釋放：「我釋放所有不再與現在的我一致的靈魂故事、誓言與契約。我是自由的。」意思是它。感受它在你靈魂中鬆開舊的束縛。你可能立即注意到改變—新的機會、勇氣說話、意願接收繁榮、更多自由與快樂。或它可能更微妙地展開。無論哪種方式，你已經啟動一個深刻的釋放。現在是時候活得解脫束縛了—完全自由地表達你的真相、接收豐盛、享受快樂、並顯化你的夢想。不再有舊的誓言阻擋你的道路。","spiritualGuidance":"進行有意識的儀式來釋放舊的誓言、契約、與靈魂故事。創造神聖空間—點燃蠟燭、燃香、呼喚你的高我與指導靈來見證。寫下任何你覺得可能攜帶的誓言或模式。如果你不確定具體是什麼，寫下你持續掙扎的領域—金錢、說話、被看見、關係、快樂—並詢問它們可能連結到什麼誓言或故事。常見的包括貧窮誓言、沈默誓言、獨身誓言、孤立誓言、殉道或受苦誓言。然後，對每一個大聲說出釋放。例如：「我釋放任何與所有生世的貧窮誓言。我自由地接收豐盛。」「我釋放我的沈默誓言。我自由地說出我的真相。」使用這張牌的啟動祈禱：「我釋放所有不再與現在的我一致的靈魂故事、誓言與契約。我是自由的。」感受這些話的力量。你可以撕毀或燃燒你寫下的紙作為身體釋放。然後，宣告你的新選擇。你想要什麼而非舊模式？寫下你的新承諾給你自己與你的靈魂。在接下來的日子與週，注意你在先前受限的領域感到更自由、更勇敢、或更開放的時刻。這是你釋放工作的證據。如果舊模式出現，溫柔地提醒自己：「那個誓言已經釋放。我是自由的。」","energyQualities":"這張牌帶來釋放與解放的強大能量，如同從長期束縛中切斷鎖鏈。它的振動頻率是清晰的、切割的、解放的。這是一種自由的能量，溶解舊的契約與協議。它攜帶著主權的頻率—宣告你有權利與力量釋放不再服務你的。這股能量同時是終結與開始：它結束舊的故事，這樣新的可以被書寫。它是賦權的，提醒你，你不被過去束縛；你可以在每個時刻選擇。它教導即使深層的靈魂模式可以被改變，當時機正確與你準備好時。它帶來輕盈、可能性、與新開始感。","suitableQuestions":"這張牌適合在你感到被看不見的力量阻擋、在某些領域反覆掙扎儘管努力、或準備突破舊限制時詢問。當你懷疑你可能攜帶來自過去生世的誓言或模式時，這張牌能提供確認與釋放。你可以問：「我攜帶什麼舊誓言或契約？」「什麼靈魂故事準備好被釋放？」「如何解脫這個模式？」「釋放這個後我會經驗什麼？」「什麼在阻止我繁榮/說話/被看見？」「我如何完全活得自由？」這張牌是宣告你從舊束縛中自由的邀請。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:41', 'work_your_light', '41', 40, '阿卡西', 'Akasha', NULL, '{"titleEn":"Akasha","suit":"傳遞牌"}', '{"coreMeaning":"阿卡西紀錄包含靈魂的契約、贈禮與教訓。有些生命轉折是預先安排好的，請信任徵兆。","actionGuidance":null,"inquiryPrompt":null,"activationPrayer":null,"transmissionPrayer":"我開放接收阿卡西的智慧。我準備好下載對我現在最高善的靈魂紀錄。","deepInterpretation":{"coreMeaning":"這張牌連結你與阿卡西紀錄—宇宙的圖書館，其中記錄著每個靈魂的旅程、契約、教訓、與贈禮。在你來到這一生之前，你的靈魂做出了某些協議與選擇：你會遇見誰、你會面對什麼挑戰、你會發展什麼贈禮、你會學習什麼教訓。這些不是懲罰；它們是為了你的成長與進化而選擇的機會。有些生命轉折點是預先安排的—靈魂協議、命運相遇、重要的挑戰。當你遇見它們，某些深層的東西在你內在認出：「是的，這是我來這裡要做的。」這張牌說：信任徵兆。信任同步性。信任你生命中展開的模式。你不是隨機漫遊；你在遵循一個神聖的藍圖。當你打開阿卡西紀錄，你可以存取關於你的靈魂目的、你的贈禮、你的契約、與你最高道路的深刻智慧。","higherSelfMessage":"你的高我想讓你知道：在你來到這裡之前，你知道你在註冊什麼。你選擇了這個家庭、這些挑戰、這些贈禮、這個時代。不是因為你被迫，而是因為你的靈魂知道這些經驗會幫助你成長、療癒、進化、與服務。你的高我在說：停止將你的生命視為隨機或錯誤。有一個神聖的計劃展開。你最大的挑戰是你來這裡要掌握的教訓。你最深的傷口是你來這裡要療癒的地方。你最大的贈禮是你來這裡要分享的。所有這些都記錄在阿卡西紀錄中—你靈魂的神聖契約。當你與阿卡西連結，你可以存取這個智慧。你可以下載你需要的資訊、理解、與指引來在這一生航行你的道路。注意徵兆—同步性、重複的數字、動物訊息、夢境、直覺閃光、命運相遇。這些是來自阿卡西的訊息，引導你走向你的最高道路。你的高我在說：信任這個過程。你沒有迷失。你在展開你的神聖藍圖，一步一步。","spiritualGuidance":"建立一個修行來連結阿卡西紀錄。開始一個冥想或儀式，你在其中呼喚你的高我、你的指導靈、與阿卡西的守護者。詢問允許存取你的紀錄。使用這張牌的傳遞祈禱：「我開放接收阿卡西的智慧。我準備好下載對我現在最高善的靈魂紀錄。」然後，進入安靜的聆聽狀態。你可能接收到圖像、話語、感受、知曉、或記憶。記錄下來的任何東西。保留一個阿卡西日誌—寫下同步性、徵兆、夢境、與直覺。隨著時間，你會看到模式出現，顯示你的靈魂藍圖。詢問阿卡西紀錄具體問題：「我的靈魂目的是什麼？」「我有什麼靈魂契約正在活動？」「我來這裡要學習什麼教訓？」「我來這裡要分享什麼贈禮？」「這個人/情況在我生命中的靈魂目的是什麼？」保持開放與接收。答案可能不立即來，但如果你保持開放，它們會透過徵兆與同步性到來。研究神聖幾何、古代符號、與編碼—這些是通往阿卡西智慧的鑰匙。考慮與受過訓練的阿卡西紀錄解讀者工作，他們可以幫助你存取你的紀錄。最重要的是：信任你的生命正在神聖秩序中展開，即使你看不到全貌。","energyQualities":"這張牌帶來深刻的宇宙知曉與神聖秩序的能量，如同打開一本包含你靈魂所有生世智慧的古老書籍。它的振動頻率是非常高的、以太的、超越時間的。這是一種記錄的能量—所有記憶、所有智慧、所有可能性保存在宇宙意識的偉大圖書館中。它攜帶著命運與自由意志之間神聖舞蹈的頻率—承認有些事情是預先安排的，同時你仍然有選擇。這股能量連結你與你的靈魂藍圖與更大的宇宙計劃。它是安慰的，提醒你沒有什麼是隨機的；每件事情都有意義與目的。它同時是神秘的與揭示的—它打開通往深刻智慧的門戶，但仍然尊重神聖的時機。","suitableQuestions":"這張牌適合在你尋求理解你的生命目的、感到迷失或與你的道路斷連、或注意到強烈的同步性與徵兆時詢問。當你想要存取關於你的靈魂契約、過去生世、或靈性贈禮的資訊時，這張牌能提供連結與指引。你可以問：「我的靈魂契約是什麼？」「這個情況的更深目的是什麼？」「我來這裡要學習什麼教訓？」「我的靈魂贈禮是什麼？」「這個徵兆是什麼意思？」「什麼阿卡西智慧想要透過我流動？」「我如何存取我的靈魂紀錄？」這張牌是與你的靈魂藍圖連結的邀請。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:42', 'work_your_light', '42', 41, '列穆里亞', 'Lemuria', NULL, '{"titleEn":"Lemuria","suit":"傳遞牌"}', '{"coreMeaning":"憶起大地曾如伊甸園般和諧的時代。療癒世界的方法是先療癒我們自己。","actionGuidance":null,"inquiryPrompt":null,"activationPrayer":null,"transmissionPrayer":"我持有列穆里亞的編碼，並相信人間天堂確實可以存在。","deepInterpretation":{"coreMeaning":"這張牌連結你與列穆里亞的古老記憶—一個神話般的黃金時代，其中人類與自然、動物、與神聖和諧共處。列穆里亞代表一個伊甸園般的意識—純真、合一、與地球的神聖連結。無論這是一個實際的大陸還是一個意識狀態，列穆里亞的能量活在那些感覺與土地、自然、動物、與大地母親有深度連結的人的細胞記憶中。如果你攜帶列穆里亞的編碼，你記得和諧是可能的。你記得人間天堂是真實的。這不是天真的幻想；這是對我們可以返回的黃金意識的記憶。這張牌說：療癒世界的方法是先療癒我們自己。當我們療癒內在的分裂—與我們身體的分離、與自然的分離、與我們神聖本質的分離—我們幫助療癒集體。當足夠多的人喚醒他們的列穆里亞記憶與和諧意識，新地球會顯化。","higherSelfMessage":"你的高我想讓你知道：你攜帶著古老的和諧記憶在你的細胞中。這可能來自實際在列穆里亞大陸的過去生世，或來自你靈魂在地球還年輕且神聖連結仍然完整時的記憶。無論哪種方式，你知道另一種生活方式是可能的。你記得一個時代，人類與地球、動物、彼此、與神聖和諧共處。這不是失落的過去；這是等待重生的可能未來。你的高我在說：你對自然與和諧的渴望不是逃避。這是一個神聖的記憶在你內在呼喚—一個列穆里亞意識想要再次顯化在地球上的召喚。你是這個新地球願景的守護者之一。你的工作不是等待世界改變；你的工作是體現那個改變。療癒你自己與自然的關係。療癒你與你身體的關係。療癒你與神聖女性、大地母親、與地球的關係。當你這樣做，你向集體發送一個和諧與合一的頻率。當足夠多的人做這個工作，臨界質量達到，新地球誕生。相信人間天堂確實可以存在，因為你記得它。","spiritualGuidance":"與列穆里亞意識連結透過深化你與自然與地球的關係。每天花時間在自然中—不只是鍛煉，而是作為靈性修行。赤腳走在地上（接地）。擁抱樹木。與植物交流。聆聽鳥的歌聲。坐在水邊。讓自然的治療與和諧頻率洗滌你。建立一個儀式來尊重大地母親。提供感恩、祈禱、歌曲、或贈禮（水、花、種子、你的頭髮）。說：「謝謝你支撐我。謝謝你滋養我。謝謝你愛我。」與動物工作，無論是寵物、野生動物、或靈性指導。動物攜帶列穆里亞純真與本能智慧的頻率。療癒你與你身體的關係。你的身體是地球的；當你愛與尊重你的身體，你愛與尊重地球。實踐讓你回到感官世界的活動—瑜伽、舞蹈、游泳、園藝。在冥想中，造訪列穆里亞意識。想像自己在一個美麗的天堂花園—郁郁蔥蔥、綠色、充滿生命。感受那個和諧。記得那個合一。知道這不只是幻想；這是一個記憶與一個藍圖。攜帶那個頻率回到你的日常生活。活得就像人間天堂是可能的—因為它是。","energyQualities":"這張牌帶來純真、和諧與伊甸園般合一的古老能量，如同第一個早晨在一個未受觸碰的花園中醒來。它的振動頻率是溫和的、滋養的、女性的。這是一種深刻與大地母親連結的能量。它攜帶著記憶與懷舊的頻率—對失落的黃金時代的渴望。但它同時也攜帶著希望與可能性—知道那個和諧可以被恢復。這股能量同時是療癒的與召喚的：它療癒與地球與自然的分離創傷，並召喚你體現新地球意識。它教導外在的和諧從內在的和諧開始。它帶來和平、歸屬、與回家到地球的感覺。","suitableQuestions":"這張牌適合在你感到與自然深度連結、渴望更多和諧與和平、或感到被召喚去療癒你與地球的關係時詢問。當你想要連結列穆里亞記憶或理解如何在世界中體現天堂意識時，這張牌能提供指引。你可以問：「我如何更深地連結大地母親？」「我的列穆里亞記憶是什麼？」「我如何療癒我與自然的關係？」「我如何為新地球做出貢獻？」「什麼是我個人的伊甸園？」「我如何活得更加和諧？」這張牌是記得人間天堂確實可以存在的邀請。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:43', 'work_your_light', '43', 42, '明塔卡人', 'Mintakan', NULL, '{"titleEn":"Mintakan","suit":"傳遞牌"}', '{"coreMeaning":"來自獵戶座明塔卡的靈魂。若感到不歸屬感，需要進行海底輪療癒並主動創造屬於你的家。","actionGuidance":null,"inquiryPrompt":null,"activationPrayer":null,"transmissionPrayer":"我允許自己真正待在此時此地。我釋放所有不歸屬的悲傷。","deepInterpretation":{"coreMeaning":"這張牌識別一個特定的星際靈魂家族：明塔卡人—來自獵戶座腰帶中已經摧毀的星球明塔卡的靈魂。如果這張牌與你共鳴，你可能攜帶明塔卡血統，這意味著你的靈魂起源於那個星球，當它被摧毀時經驗了深刻的流離失所與家園失落的創傷。這個原型創傷在許多明塔卡靈魂中顯化為深刻的「不歸屬」感—感覺像你不屬於地球、渴望一個你記不起的家、經驗鄉愁對一個你從未見過（在這一生）的地方。你可能感到像一個局外人、異鄉人、或永久的旅行者。這不是你的問題；這是一個靈魂記憶。這張牌說：為了療癒這個，你需要進行深度的海底輪工作—錨定、接地、在這個星球上建立根。並且你需要主動創造歸屬—不是等待找到它，而是建造它。創造你的靈魂家庭。創造你的神聖空間。允許地球成為你的家，現在。","higherSelfMessage":"你的高我想讓你知道：你的「不歸屬」感不是因為你有問題或地球上有什麼錯。這是一個深刻的靈魂記憶—失去你原始星際家園的記憶。你的高我在說：是時候療癒這個創傷了。你選擇在這裡，在地球上，在這個時刻。你來這裡不是作為難民或局外人；你來這裡作為志願者，作為光之工作者，作為橋樑建造者。但為了完全完成你的使命，你需要真正在這裡—不是你的部分或你的頭腦，而是你的全部身體、靈魂、與精神。這意味著深度接地工作。強化你的海底輪—你與地球的連結。與你的身體成為朋友。與自然建立關係。讓地球感覺像家。同時，主動創造歸屬。停止等待找到你的部落、你的地方、你的人。開始建造它。召喚你的靈魂家庭。創造讓你感到家的空間、儀式、與社群。你的高我在說：歸屬不是你找到的東西；它是你創造的東西。允許自己真正待在此時此地。釋放你一直攜帶的悲傷—對失落家園的悲傷。哀悼它，如果你需要。然後，讓它去。地球可以成為你的家，如果你允許她。","spiritualGuidance":"進行深度的海底輪療癒與接地工作。你的海底輪—位於你脊柱基部的能量中心—管理你與地球、你的身體、你的生存、與你的根的連結。對於明塔卡靈魂，這個脈輪經常是弱的或受傷的。療癒它透過身體實踐：瑜伽（特別是戰士姿勢與站立姿勢）、舞蹈、武術、園藝、烹飪、在自然中徒步。任何將你帶進你的身體與地球的東西。接地每天。赤腳站在地上。想像從你的腳底或海底輪到地球核心有根。對地球說：「我允許自己在這裡。我允許這裡成為我的家。」進行釋放工作來放下你的家園失落悲傷。寫一封信給明塔卡，說再見。進行一個哀悼儀式。允許自己完全感受那個失落—然後釋放它。主動創造歸屬。停止等待找到你的人；開始召喚他們。創造或加入一個社群、圈子、或部落，在那裡你感到被看見與歸屬。創造神聖空間—一個祭壇、一個房間、一個花園—感覺完全像你的。錨定在當下時刻。明塔卡靈魂經常活在過去（懷舊）或未來（渴望）。實踐當下—正念、呼吸工作、感官覺知。允許你自己完全在這裡,現在。","energyQualities":"這張牌帶來鄉愁、流離失所、與渴望回家的深刻能量，如同一個流亡者記得一個失落的王國。它的振動頻率是憂鬱的、渴望的、不安的。這是一種星際記憶的能量—攜帶來自另一個世界的深刻記憶與創傷。它攜帶著失落與悲傷的頻率，但也攜帶著韌性與適應。這股能量同時是挑戰的與賦權的：它承認深刻的創傷，但提供療癒與錨定的道路。它教導家不是一個地方；它是你創造的狀態。它最終是關於療癒、接地、與允許自己完全在這裡，現在，在地球上體現。","suitableQuestions":"這張牌適合在你感到深刻的不歸屬感、對一個你記不起的家鄉愁、或掙扎於接地與在地球上體現時詢問。當你知道你需要療癒海底輪或創造更多歸屬感時，這張牌能提供理解與工具。你可以問：「為什麼我總是感到不歸屬？」「我如何療癒我的明塔卡創傷？」「我如何更深地接地？」「我如何在地球上創造家？」「我的靈魂家庭在哪裡？」「我如何釋放我的鄉愁？」「我如何真正在這裡？」這張牌是療癒流離失所與允許自己真正在地球上歸家的邀請。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('work_your_light:44', 'work_your_light', '44', 43, '昴宿星', 'Pleiades', NULL, '{"titleEn":"Pleiades","suit":"傳遞牌"}', '{"coreMeaning":"致力於提升星球振動並分享新意識的星際生命。若你感到被召喚去寫作或通靈，請持續進行。","actionGuidance":null,"inquiryPrompt":null,"activationPrayer":null,"transmissionPrayer":"我召喚昴宿星意識。讓我成為傳遞源頭精華最純淨之光的管道。","deepInterpretation":{"coreMeaning":"這張牌連結你與昴宿星意識—來自昴宿星團（七姊妹星團）的高度進化的星際存有。昴宿星人致力於支持地球與人類揚升到更高意識。他們是老師、療癒者、與訊息傳遞者，幫助提升星球振動並引入新範式的愛、合一、與靈性覺醒。如果你與這張牌共鳴，你可能攜帶昴宿星血統或與昴宿星指導靈有強烈連結。你可能感到被召喚去通靈、寫作、教導、或以某種方式傳遞靈性智慧與指引。這不是自負；這是一個召喚。這張牌說：如果你感到衝動去寫作、說話、教導、或通靈—持續進行。這些衝動是來自你的昴宿星連結的訊息。你來這裡成為管道—傳遞源頭精華、更高意識、與新地球編碼的管道。你的工作是盡可能純淨地錨定與分享這個光。","higherSelfMessage":"你的高我想讓你知道：你來這裡不只是為了你自己的療癒與成長。你來這裡服務集體揚升。你與昴宿星意識有一個連結—無論透過過去在那個星系的生世、與昴宿星指導靈的靈魂契約、或簡單地因為你的靈魂攜帶那個頻率。昴宿星人是關於提升—幫助地球從更低密度的恐懼、分離、與衝突移動到更高密度的愛、合一、與和諧。你的高我在說：你是這個使命的一部分。你的工作是成為管道—讓更高頻率、智慧、與光透過你流向地球與人類。這可能以許多形式顯化：寫作（書籍、部落格、詩歌）、說話（教導、演講、播客）、通靈（帶來訊息從指導靈或更高自我）、療癒（傳遞能量）、或只是透過你的存在錨定光。如果你感到衝動去創造、分享、或傳遞—信任它。這不是你的自我；這是你的靈魂使命透過呼喚你。準備自己成為清晰的管道透過清理你的能量場、療癒你的創傷、提升你的振動、與修煉在你的心與更高自我中居住。你越清晰與對齊，你可以傳遞的光越純淨。","spiritualGuidance":"建立一個有意識的修行來連結昴宿星意識。在冥想中，呼喚昴宿星存有與指導靈。使用這張牌的傳遞祈禱：「我召喚昴宿星意識。讓我成為傳遞源頭精華最純淨之光的管道。」感受他們的存在—通常是明亮的、充滿愛的、精緻的。請求他們的指引、智慧、與支持你的使命。如果你感到被召喚去寫作或通靈，開始一個日常修行。每天坐下，調和到更高頻率，並請求訊息流過你。寫下來的任何東西，即使它看起來不有意義。隨著時間與修行，管道會變得更清晰。準備自己成為清晰的管道透過定期能量清理（鹽浴、煙燻、聲音）、療癒你的創傷與陰影、提升你的振動透過正向輸入（自然、美麗、音樂、靈性教導）、與修煉覺知與當下。研究昴宿星教導與訊息來熟悉他們的頻率與智慧。許多管道已經帶來昴宿星訊息；閱讀它們來校準。分享你接收到的。不要將光藏在燈罩下。如果你被指引去寫、說、教導、或分享—做它。世界需要你來這裡傳遞的訊息與頻率。信任你的管道,即使你的自我懷疑。最重要的是：錨定在愛中。昴宿星意識是關於無條件的愛、合一、與服務。讓那成為你所有傳遞的基礎。","energyQualities":"這張牌帶來高頻率、精緻、星際覺醒的能量，如同從閃亮星星接收傳輸。它的振動頻率是非常高的、輕的、以太的。這是一種揚升與進化的能量—向上提升,擴展意識。它攜帶著傳遞與管道的頻率—打開通往更高維度智慧與光的門戶。這股能量同時是賦權的與謙遜的：它確認你的重要使命與贈禮，同時提醒你,你是服務更大事物的工具。它教導傳遞不是關於你；它是關於你允許透過你流動的光。它帶來明晰、目的、與連結到更高意識與星際家族的感覺。","suitableQuestions":"這張牌適合在你感到被召喚去通靈或傳遞靈性智慧、與你的星際起源連結、或尋求理解你在集體揚升中的角色時詢問。當你想要連結昴宿星指導靈或提升你作為管道的能力時,這張牌能提供連結與指引。你可以問：「我如何連結昴宿星意識？」「我應該傳遞什麼訊息？」「我如何成為更清晰的管道？」「我在地球揚升中的角色是什麼？」「我如何最好地服務？」「什麼昴宿星智慧想要透過我流動？」「我如何分享我的贈禮？」這張牌是接受你作為光與智慧管道的角色的邀請。"}}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:1', 'dragons', '1', 0, '火龍之力', 'Fire Dragon Power', NULL, '{"keywords":["力量","轉化","熱情"],"nameEn":"Fire Dragon Power"}', '{"message":"火龍從遠古的火焰中降臨，帶來毀滅與重生的神聖力量。它的呼吸能燃燒一切不再服務你的舊模式、舊習慣、舊身份。火焰不是用來摧毀，而是用來轉化。就像鳳凰浴火重生，你也正在經歷一場深刻的轉化。火龍賦予你勇氣面對這場轉變，即使過程可能帶來痛苦和不適。它提醒你，真正的力量不是控制或壓制，而是完全地接受和表達你的熱情、憤怒、欲望和生命力。你內在有一團火焰，它渴望被點燃，渴望燃燒，渴望照亮世界。太久以來，你可能因為害怕過於強大而壓抑這份力量，但火龍告訴你：是時候釋放了。這個世界需要你的光與熱，需要你的熱情與勇氣。當你允許內在火焰自由燃燒，你會發現自己擁有無限的創造力和轉化力量。","guidance":"不要再害怕展現你的力量和熱情，不要再為了迎合他人而縮小自己。火龍邀請你勇敢地追求你真正渴望的生活，而不是社會期待或他人認為你應該過的生活。找到那些讓你心中火焰燃起的事物，全力以赴地去做。如果有某件事讓你感到興奮、激動、充滿活力，那就是你的靈魂在說話。跟隨那份熱情，即使它不合理性或計劃。現在是採取大膽行動的時刻，不是謹慎試探的時候。火龍不會小心翼翼地行動，它會全然投入。同時，學習正確地使用火元素能量，不是爆發性的憤怒或破壞，而是持續燃燒的熱情和創造力。設定清晰的界限，保護你的能量不被他人消耗。像火龍一樣，強大而不侵略，熱情而不失控。","energy":"紅玉髓或紅碧玉是火元素的完美代表，能激活你的海底輪和臍輪，喚醒沉睡的生命力和創造力。將這些水晶放在下腹部進行冥想，感受火能量從脊椎底部升起。在日出時進行火龍冥想，面向東方太陽升起的方向，想像自己是一條火龍，呼吸時噴出火焰，燃燒所有限制和恐懼。你可以進行蠟燭冥想，凝視紅色蠟燭的火焰，讓它的能量點燃你的內在火焰。在行動前，用雙手快速摩擦生熱，然後將溫熱的手放在下腹部，啟動你的力量中心。吃辛辣食物、進行有強度的運動、或者大聲吼叫，都能幫助你連結和釋放火元素能量。記得在使用火能量後適當扎根，避免過度亢奮。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:2', 'dragons', '2', 1, '水龍智慧', 'Water Dragon Wisdom', NULL, '{"keywords":["智慧","流動","情感"],"nameEn":"Water Dragon Wisdom"}', '{"message":"水龍在深海的寧靜中守護著古老的智慧。不同於火龍的激烈，水龍教導的是接納、適應和深度。水看似柔軟，卻能穿透堅硬的岩石；水沒有固定形狀，卻能適應任何容器。水龍提醒你，真正的智慧不是固執己見或強硬對抗，而是像水一樣靈活應對生命的變化。你的情感就像水，它們自然流動，有時平靜如湖，有時洶湧如海。抗拒情感就像試圖阻擋水流，只會造成淤塞和問題。水龍教導你接納情感的自然韻律，允許它們流經你而不是卡住。在情感的深度中，藏著你最深刻的智慧。你的直覺、同理心、創造力都源自於這片內在的水域。當你學會潛入情感的深處而不是漂浮在表面，你會發現海底有無盡的寶藏。水龍也提醒你保持流動，不要執著或僵化，生命唯一不變的就是變化。","guidance":"練習像水一樣生活。當遇到障礙時，不要硬碰硬，而是尋找繞道的方式。水不會因為岩石而停止流動，它會找到其他路徑。在人際關係中，練習真正傾聽和同理，讓對方的情感流動而不是試圖修復或改變。允許自己完全感受情緒，無論是喜悅、悲傷、憤怒還是恐懼。情感沒有對錯，它們只是信使，帶來重要的訊息。當情緒湧現時，不要壓抑或逃避，而是給它空間完全流動，然後自然消退。培養你的直覺，它是水龍智慧的語言。在做決定時，不要只用理性分析，也要感受身體和心的回應。靜坐在水邊，向水龍學習它的智慧：永遠流動，永遠適應，永遠向下流向最低處（謙卑），卻又能滋養一切生命。","energy":"海藍寶連結水龍的海洋能量，能清理情緒體，帶來心靈的平靜與清晰。藍瑪瑙穩定情緒波動，幫助你在情感的浪潮中保持中心。在新月或滿月時進行水龍儀式，到海邊、湖邊或河邊，將雙手浸入水中，請求水龍洗去所有情緒的淤塞和堵塞。在家中泡療癒浴，在水中加入海鹽和海藍寶，讓自己完全浸泡在水元素中，想像成為水龍在深海中自由游動。多喝水，每次喝水時有意識地感恩，記得你的身體有70%是水。進行流動的運動如游泳、瑜伽或太極，讓身體體驗水的流動性。在情緒激動時，喝一杯溫水，慢慢喝下，感受水的冷靜能量平復你的情緒。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:3', 'dragons', '3', 2, '風龍自由', 'Wind Dragon Freedom', NULL, '{"keywords":["自由","思想","溝通"],"nameEn":"Wind Dragon Freedom"}', '{"message":"風龍在無邊天際翱翔，不受任何束縛，象徵著最純粹的自由。它的出現提醒你，真正的自由首先是心靈的自由，是思想的解放。你被多少信念、規則、應該和不應該所囚禁？這些思想的牢籠往往比物質的牢籠更加堅固。風龍用它的翅膀掃除這些障礙，帶來清新的空氣和新的視角。你的想法創造你的現實，當你改變思維方式，你的世界也會改變。風龍是溝通大師，它教導你真實表達的力量。你的聲音是你的力量，你的話語是創造的工具。太久以來，你可能沉默，不敢說出真相，害怕被批判或拒絕。但風龍告訴你，壓抑的聲音會在喉嚨和心中累積成毒素。是時候說出你的真理了，不是攻擊或辯論，而是清晰、真實、有力地表達你是誰和你相信什麼。風也代表變化和新開始，風吹過，帶走舊的，帶來新的。","guidance":"釋放所有限制性的信念，那些告訴你『你不夠好』、『你不能』、『你應該』的聲音。寫下這些限制性信念，然後在風中燒掉或撕碎它們，象徵性地釋放。擁抱新的、賦權的信念。每天對自己說：『我是自由的，我的思想創造我的現實』。練習真實表達，即使聲音顫抖也要說出真相。從小事開始，如在餐廳說出你真正想要的菜，在朋友面前表達真實的感受。你會發現說真話比討好他人更自由也更有力量。閱讀不同的觀點，接觸新的思想，不要困在單一的世界觀中。風龍邀請你保持開放和好奇，不斷學習和成長。進行思想淨化練習，觀察你的想法而不是認同它們，讓負面想法像雲一樣飄過，不要抓住它們。","energy":"青金石是真理與溝通之石，能打開喉輪，幫助你勇敢而清晰地表達自己。藍晶石清理思想的混亂，帶來心智的清晰與和平。將這些水晶戴在喉嚨附近或放在第三眼位置冥想。每天早晨到戶外，深呼吸新鮮空氣，想像吸入的是自由和清晰，呼出的是限制和混亂。在風大的日子，張開雙臂站在風中，讓風吹過你的全身，帶走所有沉重的能量。進行發聲練習，唱歌、朗讀或簡單地發出聲音，活化你的喉輪和表達力。寫作是風元素的表達，每天寫晨間日記，讓思想自由流動在紙上，不要審查或批判。用香薰精油如薄荷或尤加利，清新你的思想空間。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:4', 'dragons', '4', 3, '地龍穩定', 'Earth Dragon Stability', NULL, '{"keywords":["穩定","豐盛","扎根"],"nameEn":"Earth Dragon Stability"}', '{"message":"地龍是所有龍族中最古老、最有耐心的。它深深扎根於大地，守護著地球的寶藏和生命的根基。在這個快速變化、充滿不確定性的時代，地龍帶來穩定與扎根的祝福。它提醒你，無論你的靈性飛得多高，都不要忘記扎根於大地。你的身體是靈魂在地球的家，好好照顧它。你的物質生活是靈性的基礎，忽略它會讓你失去平衡。地龍教導你耐心、持續和實際的重要性。豐盛不是從天而降的奇蹟，而是扎實工作和正確行動的果實。像大樹一樣，根扎得越深，枝葉才能長得越高。地龍也是豐盛的守護者，它坐在寶藏之上，提醒你大地母親供應無缺，你值得擁有豐盛。但豐盛需要你打開雙手接收，需要你相信自己值得，需要你採取實際行動。","guidance":"評估你生活的根基是否穩固。你的財務狀況、健康狀況、居住環境、重要關係都是你的根基。如果有任何一個領域搖搖欲墜，優先處理它，就像修復房子的地基一樣。制定實際可行的計劃，不要只是夢想或期待，而是採取具體的行動步驟。地龍不喜歡空談，它欣賞實幹。照顧好你的身體，它是你的地球載具。規律飲食、充足睡眠、適當運動，這些看似平凡的事情是你力量的基礎。學習理財，建立儲蓄，創造被動收入，讓你的物質生活穩固。同時培養感恩的習慣，每天感謝你已經擁有的，這會打開接收更多豐盛的通道。與大自然連結，赤腳走在草地或泥土上，讓地球母親為你充電。慢下來，享受過程，不要總是追趕下一個目標而忘記活在當下。","energy":"黑曜石是最強大的扎根水晶，能將你深深錨定在地球能量中，提供保護和穩定。煙晶轉化負面能量為正面，幫助你在混亂中保持中心。每天早晨，坐在地上或椅子上，雙腳平放地面，握著黑曜石，進行扎根冥想。想像從你的脊椎底部長出根，深深扎入地球中心，吸收大地的穩定能量。經常赤腳走在大地上，草地、沙灘、泥土，直接接觸地球的頻率。在家中種植物，照顧植物就是連結地龍能量。吃根莖類食物如紅薯、胡蘿蔔、馬鈴薯，在物質層面扎根。進行身體性的活動如園藝、烹飪、清潔，這些都是地元素的表達。將豐盛水晶如黃水晶或綠幽靈放在財位或錢包中，吸引豐盛能量。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:5', 'dragons', '5', 4, '金龍豐盛', 'Golden Dragon Abundance', NULL, '{"keywords":["豐盛","財富","成功"],"nameEn":"Golden Dragon Abundance"}', '{"message":"金龍全身覆蓋著閃耀的金鱗，每一片鱗片都反射著豐盛的光芒。它是財富、成功和顯化的化身。金龍的出現告訴你，豐盛是你的天賦權利，不是需要艱難爭取的東西。宇宙本質上是豐盛的，看看大自然的慷慨供應，一顆蘋果樹產出數百顆蘋果，一朵蒲公英產出上千顆種子。這就是宇宙的本性，而你是宇宙的一部分，你也擁有創造豐盛的天賦。但許多人被匱乏意識所困，相信資源有限，相信自己不值得，相信富有是罪惡。金龍來粉碎這些限制性信念。它提醒你，金錢是能量的流動，是價值的交換，本身沒有好壞。當你提供價值，金錢自然流向你。當你感恩並慷慨，豐盛自然增長。金龍不只代表金錢的豐盛，更是全方位的豐盛：健康、關係、機會、創意、時間。你可以在所有領域都富足。","guidance":"首先要做的是清理你對金錢和豐盛的限制性信念。寫下你對金錢的所有負面信念，然後一一質疑它們。『有錢人都是壞人』真的嗎？『金錢是萬惡之源』真的嗎？用新的、賦權的信念取代它們：『金錢是工具，我用它創造美好』、『我越富有，我能幫助更多人』。每天練習豐盛肯定語：『我是豐盛的，我值得擁有一切美好』、『金錢輕易而喜悅地流向我』。最重要的是，活在豐盛的感覺中。即使銀行帳戶還沒反映出來，你也要先感受富足。慷慨地給予，無論是金錢、時間或讚美，給出去的會回到你身上。設定清晰的財務目標，制定計劃，採取行動。金龍會幫助你，但你也要做你該做的部分。尋找你的天賦和熱情，當你做你熱愛的事並提供價值，豐盛自然隨之而來。","energy":"黃水晶是財富之石，被稱為商人之石，能吸引財富和成功。金髮晶是極強的顯化水晶，內含金色髮絲象徵金龍的能量。將這些水晶放在錢包、收銀機或辦公桌的財位（通常是左後方角落）。每天早晨握著黃水晶，觀想你的財務目標已經實現，感受那份富足和喜悅，讓這份感覺錨定在水晶中。創造一個豐盛祭壇，放置金色蠟燭、金幣、黃水晶和你的財務目標，每天在祭壇前冥想幾分鐘。穿戴金色或黃色的衣物，吸引豐盛能量。用黃色或金色裝飾你的空間。進行豐盛浴，在水中加入金箔、黃水晶和幾滴佛手柑精油，浸泡時觀想自己被金光包圍。每當金錢流向你時（無論金額大小），都說『謝謝，更多請繼續來』。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:6', 'dragons', '6', 5, '銀龍直覺', 'Silver Dragon Intuition', NULL, '{"keywords":["直覺","月亮","神秘"],"nameEn":"Silver Dragon Intuition"}', '{"message":"銀龍在月光下翱翔，它的銀色鱗片反射著月亮的神秘光芒。銀龍是直覺、陰性能量和深層意識的守護者。在這個過度重視理性和邏輯的世界，我們的直覺被長期壓抑和忽視。但直覺是靈魂的語言，是連結更高智慧的通道。銀龍喚醒你沉睡的直覺力，打開你的內在視野。你的直覺從未離開，它一直在低語，只是你太忙、太吵、太理性，聽不見它的聲音。直覺不是大聲的，它是一種微妙的感知、一個身體的訊號、一個莫名的知曉。當你學會安靜下來，向內傾聽，你會發現直覺比你想像的更準確、更智慧。銀龍也連結著月亮的週期和女性能量。它提醒你榮耀你的陰性面向：接納、直覺、情感、創造力、滋養。無論你的性別，你都擁有陰性和陽性能量，兩者的平衡才是完整。","guidance":"開始每天練習靜心，即使只有五分鐘。在安靜中，你的直覺才能被聽見。學習區分頭腦的聲音和直覺的聲音。頭腦是大聲的、重複的、批判的、恐懼的；直覺是安靜的、清晰的、中性的、知曉的。當你需要做決定時，先用理性分析收集資訊，然後放下，問你的直覺：『什麼感覺對？』注意身體的反應。如果身體緊縮、沉重，那是『不』；如果身體放鬆、輕盈，那是『是』。開始記錄你的夢境，夢是潛意識和直覺溝通的方式。練習跟隨直覺的小提示，如走不同的路回家、聯絡突然浮現在腦海的朋友，看看會發生什麼。你越跟隨直覺，它會變得越強。與月亮週期同步，觀察你的能量、情緒和直覺如何隨月相變化。在新月種下意圖，在滿月慶祝和釋放。","energy":"月光石是銀龍的水晶，它連結月亮能量，增強直覺和陰性能量。拉長石是魔法師之石，打開第三眼，讓你看見超越表象的真相。將這些水晶放在第三眼（兩眉之間）或頂輪位置冥想。在滿月夜，將水晶放在月光下充能整晚，吸收月亮的直覺能量。進行月光浴，在滿月時站在或坐在月光下，閉上眼睛，想像銀色月光從頭頂流入，活化你的松果體和直覺中心。隨身攜帶月光石或拉長石，當需要直覺指引時握住它們，閉上眼睛，深呼吸，然後問你的問題，等待內在的回應。睡前將月光石放在枕頭下，增強夢的清晰度和預知性。減少過度刺激和資訊輸入，為直覺創造安靜的空間。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:7', 'dragons', '7', 6, '彩虹龍統合', 'Rainbow Dragon Integration', NULL, '{"keywords":["統合","平衡","完整"],"nameEn":"Rainbow Dragon Integration"}', '{"message":"彩虹龍是最稀有、最神聖的龍族，它身上同時閃耀著七種顏色的光芒，代表所有元素、所有能量中心、所有面向的完美統合。它的出現是深刻轉化的標誌，表示你正在進入一個整合的階段。過去你可能感到分裂：靈性自我和日常自我分離，工作和生活失衡，理想和現實衝突。彩虹龍來幫助你整合所有這些看似矛盾的面向，讓你成為一個完整、和諧的存在。你不需要在靈性和物質之間選擇，你可以既是靈性追求者也是成功的事業人；你不需要壓抑陰影來展現光明，你可以整合陰影，讓它成為你力量的一部分。彩虹龍教導你，對立只是幻相，在更高的層次，一切都是統一的。當你內在達到統合，外在世界也會反映這份和諧。你會發現關係更和諧，健康更平衡，生活更流暢。統合不是終點，而是持續的過程。","guidance":"進行生命之輪檢視練習。畫一個圓，分成八個區域：工作/事業、財務、健康、關係、家庭、社交/朋友、個人成長、娛樂/休閒。為每個領域從1到10打分，看看哪些領域需要更多關注。制定計劃，為被忽略的領域投入時間和能量。練習整合冥想：想像你的所有面向（內在小孩、青少年、成人、老者；理性自我、情感自我、靈性自我）坐在一個圓圈中，邀請彩虹龍祝福每一個面向，然後想像它們全部融合為一個完整的你。進行陰影工作，辨識並接納你的陰影面。記住，陰影不是壞的，只是被壓抑的部分。當你給它們光照和愛，它們會轉化為禮物。在日常生活中注入靈性，不需要特別的儀式或冥想，而是在每個行動中保持覺知和愛。在物質成功中看見靈性的顯化，在靈性體驗中不忘照顧物質需求。","energy":"彩虹黑曜石是統合的完美水晶，它結合了黑曜石的扎根保護和彩虹光的高頻能量，象徵著將靈性能量錨定在物質世界。七彩螢石包含多種顏色的能量頻率，能同時清理和活化所有七個脈輪。進行完整的七脈輪平衡冥想：躺下，將彩虹水晶放在心口，想像彩虹光從頂輪進入，依序流經第三眼（靛色）、喉輪（藍色）、心輪（綠色）、臍輪（黃色）、臍輪（橙色）、海底輪（紅色），然後從海底輪向下扎根到地球中心。每個脈輪停留幾分鐘，清理和活化它。尋找真實的彩虹，在彩虹出現時進行冥想，這是宇宙給你的統合祝福。在家中使用三稜鏡創造彩虹光，讓七色光照在你的水晶上。實踐彩虹飲食，每餐攝取不同顏色的食物，在物質層面平衡能量。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:8', 'dragons', '8', 7, '黑龍保護', 'Black Dragon Protection', NULL, '{"keywords":["保護","轉化","陰影"],"nameEn":"Black Dragon Protection"}', '{"message":"黑龍常被誤解和恐懼，但它其實是最強大的守護者和療癒者。它守護著通往地下世界的門戶，教導你面對恐懼、陰影和黑暗的勇氣。在集體意識中，黑暗被視為邪惡，但在靈性真理中，黑暗是孕育、轉化和深度智慧的空間。種子在黑暗的土壤中發芽，嬰兒在黑暗的子宮中成長。黑龍教導你不要逃避黑暗，而是進入它，在那裡你會找到被遺忘的力量和智慧。你的陰影不是敵人，而是老師。那些你壓抑的憤怒、嫉妒、恐懼、欲望，它們都帶著重要的訊息和能量。當你勇敢地面對和接納陰影，你就收回了被困在那裡的力量。黑龍也是最強大的保護者，它創造能量邊界，守護你不受負面能量侵害。在這個能量混亂的世界，學會保護自己的能量場至關重要。黑龍教導你如何設立健康的界限，如何說不，如何保護自己的能量。","guidance":"進行陰影工作，這可能不舒服但極為重要。列出你不喜歡的人和他們的特質，然後誠實地問自己：這些特質是否也存在於我之中，只是被壓抑了？我們往往對他人的批判，正是我們無法接納自己那些面向的投射。當你辨識出陰影，不要批判它，而是好奇地探索：這部分為什麼存在？它想保護我什麼？它需要什麼？給你的陰影面聲音和空間，寫信給它，與它對話。你會發現，當陰影被看見和接納，它會自然轉化。建立能量保護練習，特別是在進入人群密集或負面能量重的地方前。想像黑龍的翅膀環繞你，或者想像自己被黑色水晶的保護盾包圍。學習說不，這是最基本的能量保護。你不需要解釋或道歉，簡單的『不，這不適合我』就足夠。定期檢視你的人際關係，那些持續消耗你能量的關係需要被重新評估。","energy":"黑曜石是黑龍的水晶，它是最強大的保護石，能吸收負面能量，切斷能量索，創造保護盾。黑碧璽也是極佳的保護石，能轉化負面為正面，扎根並淨化氣場。隨身攜帶這些水晶，特別是在需要保護的時候。每天用鼠尾草或聖木煙燻你的水晶，清除它們吸收的負面能量。進行黑龍保護冥想：閉上眼睛，想像一條巨大的黑龍從地底升起，環繞保護你。它的黑色鱗片反射掉所有攻擊和負面能量。在你的能量場周圍形成一個黑曜石盾牌。每天早晨設定能量邊界，宣告：『我受到神聖保護，只有愛和光能進入我的能量場』。在睡前進行能量清理，想像黑龍的火焰燃燒掉你今天吸收的所有負面能量。泡鹽水浴，加入黑曜石和海鹽，深度清理你的氣場。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:9', 'dragons', '9', 8, '白龍純淨', 'White Dragon Purity', NULL, '{"keywords":["純淨","清晰","新開始"],"nameEn":"White Dragon Purity"}', '{"message":"白龍全身散發著純淨的白光，如同新雪覆蓋大地，抹去所有痕跡，創造一個嶄新的開始。它是淨化大師，帶來清理、釋放和重新開始的能量。白龍的出現常常意味著一個週期的結束和新週期的開始。過去已經過去，無論那是美好的回憶還是痛苦的經歷，執著於過去會阻止你進入新的篇章。白龍邀請你放手，清理，淨化。這不只是物質層面的清理（雖然那也重要），更是心靈、情緒和能量層面的深度淨化。釋放不再服務你的關係、習慣、信念、物品。創造空間，新的才能進入。白龍也代表清晰和純淨的意圖。在混亂和雜訊中，白龍幫助你看清真正重要的是什麼，聚焦於本質。它教導你簡化，去除不必要的複雜性，回歸純粹和簡單。白色包含所有顏色，也就是所有可能性，新開始充滿無限潛力。","guidance":"進行深度清理，從你的物質空間開始。清理你的家、辦公室、車子，丟棄或捐贈不再使用的物品。每一個物品都帶有能量，堆積的雜物會阻塞能量流動。遵循『如果它不帶來喜悅或實用性，就放手』的原則。清理數位空間，刪除不需要的檔案、照片、郵件，取消不再關注的訂閱。清理社交媒體，取消關注那些帶來負面感受的帳號。然後進行情緒清理，寫下你需要原諒的人（包括你自己），一一進行原諒儀式，釋放怨恨和傷痛。清理你的關係，誠實評估哪些關係滋養你，哪些消耗你。你不需要切斷關係，但可能需要重新設定界限。最後，清理你的能量場，用鼠尾草煙燻、鹽水浴、聲音療癒等方法。在清理之後，設定清晰的意圖，你想要創造什麼樣的新開始？寫下你的願景，純淨而清晰。","energy":"白水晶是淨化大師，它能清理和擴大能量場，適用於所有療癒工作。透石膏是極高頻的白色水晶，連結天使界，帶來純淨的光。用白水晶製作一個能量網格保護你的空間，在房間的四個角落各放一顆白水晶。定期用流動的清水沖洗你的白水晶，淨化它們吸收的能量。進行白光淨化冥想：想像自己被純淨的白光完全包圍，這道光從宇宙源頭降下，穿透你的每個細胞，清理所有不純淨的能量。白光流經你的身體，從腳底流出，將所有負面能量帶回地球轉化。用鼠尾草或聖木煙燻你的空間，特別是在重要的轉變時刻，如搬家、換工作、結束關係後。穿白色衣服，增強純淨能量。在你的空間使用白色蠟燭和清新的精油如檸檬或薄荷，創造清淨的氛圍。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:10', 'dragons', '10', 9, '翡翠龍療癒', 'Jade Dragon Healing', NULL, '{"keywords":["療癒","心輪","和諧"],"nameEn":"Jade Dragon Healing"}', '{"message":"翡翠龍散發著溫柔的綠色光芒，這是心輪的顏色，是療癒和愛的頻率。它是溫柔的療癒者，專門療癒心的創傷。我們每個人的心都帶著傷痕，來自童年的忽視、關係的背叛、愛的失去。這些傷痛如果不被療癒，會在心中形成硬塊，阻止愛的能量流動。翡翠龍用它無限的慈悲和耐心，一層一層地軟化這些硬塊，療癒這些傷痛。心的療癒是最深刻也是最重要的療癒，因為心是你的核心，是愛的中心。當心輪打開並被療癒，你能給予和接收愛，能感受到與所有生命的連結，能活在恩典和流動中。翡翠龍也帶來和諧的能量，內在的和諧反映為外在的和平。它教導你溫柔地對待自己和他人，用慈悲取代批判，用理解取代指責。療癒不是快速的，它需要時間、耐心和愛，翡翠龍會陪伴你走過整個過程。","guidance":"開始心的療癒工作，這可能需要勇氣，因為你要觸碰那些曾經痛苦的地方。但療癒是你能給自己最大的禮物。將手放在心口，深呼吸，問你的心：『你需要療癒什麼？』傾聽內在的回應，可能是某個記憶、某個人、某個事件。允許那份痛苦浮現，不要壓抑。哭泣如果需要的話，眼淚是療癒的甘露。然後，用你的手在心口做圓周按摩，對你的心說：『我在這裡，我愛你，我們一起療癒』。練習原諒，原諒那些傷害過你的人，不是因為他們值得，而是為了釋放你自己。原諒自己所有的『錯誤』和『不夠好』，用慈悲擁抱自己。每天進行心輪冥想，想像綠色的療癒光充滿你的心臟空間，療癒所有的傷痛。尋求專業協助如心理諮商或能量療癒也是勇敢和智慧的選擇。","energy":"綠東陵是心輪之石，能打開、清理和活化心輪，帶來情緒療癒和內在和平。翡翠是古老的療癒石，特別對心和情緒有深度療癒作用，也帶來智慧和和諧。將這些水晶放在心口，躺下進行心輪療癒冥想。想像綠色的光從水晶中流出，流入你的心臟，療癒所有的裂痕和傷口。你可以製作一個療癒網格，中間放一顆玫瑰石英（無條件的愛），周圍圍繞綠東陵或翡翠。每天坐在這個網格中間冥想。隨身佩戴綠色水晶作為項鍊或手鍊，讓它持續為你的心輪工作。在大自然中進行療癒，特別是在綠色的森林或草地，綠色是大自然的療癒頻率。吃綠色食物如綠葉蔬菜、酪梨、奇異果，在物質層面滋養心輪。練習心輪呼吸，想像吸入綠色的療癒能量，呼出心中的痛苦和傷痛。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:11', 'dragons', '11', 10, '紫龍覺醒', 'Purple Dragon Awakening', NULL, '{"keywords":["覺醒","靈性","轉化"],"nameEn":"Purple Dragon Awakening"}', '{"message":"紫龍是最稀有且最神秘的龍族，它守護著靈性覺醒的門戶，是物質世界與靈性次元之間的橋樑。紫色是頂輪和第三眼的顏色，代表靈性意識、直覺智慧和與更高次元的連結。紫龍的出現標誌著你正在經歷或即將經歷一場深刻的靈性覺醒。這不是你第一次覺醒，你的靈魂在多個輪迴中一直在進化，但這一次的覺醒將帶你到達新的高度。你可能開始感知到能量、看見靈性存有、經歷強烈的直覺洞見或感受到與萬物的合一。舊有的世界觀正在崩解，新的理解正在形成。紫龍帶來轉化的火焰，燃燒掉阻礙你靈性成長的一切幻相、執著和限制。這個過程可能令人不安，因為你正在死去——舊的自我正在死去，新的意識正在誕生。紫龍保護並引導你穿越這個神聖的通道，確保你安全地到達覺醒的彼岸。","guidance":"給自己空間和時間來整合這些深刻的轉變，不要試圖理性化或控制覺醒的過程。創建每日的靈性練習——冥想、祈禱、能量工作或任何讓你與更高自我連結的方法。尋找靈性導師或社群，與走在相似道路上的人連結和學習，但記得你內在的指引永遠是最準確的。閱讀靈性教導，但不要盲目相信，用你的辨別力和直覺篩選。記錄你的靈性體驗、洞見和同步性事件，它們是你覺醒旅程的路標。進行能量清理和保護，覺醒會讓你對能量更敏感，需要學會管理和保護你的能量場。平衡靈性與日常生活，不要忽略身體、工作和關係的需求，真正的覺醒是將靈性整合到生活的每個層面。對自己有耐心和慈悲，覺醒不是線性的，你會有高峰也會有低谷，這都是過程的一部分。","energy":"紫水晶是紫龍的水晶，它能打開頂輪和第三眼，連結更高意識並保護你的能量場。舒俱徠石是極高頻的靈性水晶，能加速覺醒過程並帶來深刻的靈性洞見。每天進行紫龍冥想，想像一條美麗的紫龍盤旋在你上方，它的紫色火焰從你的頂輪流入，清理和激活你的上三輪。將紫水晶放在第三眼或頂輪位置，進行脈輪激活練習。使用乳香或鼠尾草淨化你的空間和能量場，創造高頻的靈性環境。在滿月和新月時進行靈性儀式，這些時刻的能量特別有利於覺醒工作。聆聽高頻音樂或使用音叉療癒，聲音振動能提升你的意識狀態。減少低頻的活動和娛樂，如暴力電影、負面新聞或有毒關係，它們會拉低你的振動。吃清淡純淨的食物，考慮減少肉食或進行間歇性斷食，淨化身體以支持靈性提升。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:12', 'dragons', '12', 11, '藍龍智慧', 'Blue Dragon Wisdom', NULL, '{"keywords":["溝通","真理","表達"],"nameEn":"Blue Dragon Wisdom"}', '{"message":"藍龍守護著喉輪和真實表達的力量。它的藍色能量代表清晰的溝通、真理的聲音和創意的表達。藍龍教導你說出你的真相的重要性，不是攻擊或辯論的方式，而是清晰、真實、有力的表達。太多人壓抑他們的聲音，因為害怕被拒絕、被批判或不被接受。但當你不說出真相，你就是在背叛你的靈魂。沉默的代價是失去自己的完整性和力量。藍龍也是智慧的守護者，它知道言語的力量——言語可以創造也可以毀滅，可以療癒也可以傷害。真正的智慧在於知道何時說話、如何說話、以及何時保持神聖的沉默。藍龍提醒你，你的聲音是你的力量，你的話語是創造的工具。當你從真實和愛的地方說話，你的聲音承載著轉化的力量。藍龍也連結著聆聽的智慧，真正的溝通不只是說話，更是深度的聆聽和理解。","guidance":"開始練習真實表達，從小事開始，如在餐廳說出你真正想要的菜，在朋友面前表達真實的感受。注意你何時壓抑自己的聲音，什麼恐懼在阻止你說話。寫日記釋放那些長期壓抑的想法和感受，讓它們從你的喉嚨和心中流出。進行發聲練習，唱歌、朗讀或簡單地發出聲音，活化和強化你的喉輪。學習有效溝通的技巧，如非暴力溝通或積極聆聽，這能幫助你既真實又有愛地表達。設定溝通界限，你不需要解釋或證明你的真相，簡單地說『這是我的真相』就足夠。同時練習聆聽，不只是聽別人的話語，更是聽他們話語背後的情感和需求。保護你的喉輪免受負面言語的傷害，當別人對你說傷害的話時，不要內化它們。使用肯定語重新程式化你的內在對話，對自己說有力量和真實的話語。","energy":"藍晶石是喉輪的完美水晶，它清理喉輪的阻塞，幫助你清晰而有力地表達真相。海藍寶連結水元素的流動性，讓你的溝通像水一樣清澈和適應性強。將這些水晶戴在喉嚨附近作為項鍊，持續為喉輪工作。進行喉輪冥想，想像藍色的光在喉嚨處旋轉並擴展，清理所有壓抑的言語和情感。使用薄荷或尤加利精油，它們清新和打開喉輪。進行藍龍呼吸練習，想像你吸入藍色的龍息，充滿你的喉嚨，然後呼出時發出聲音或說出真相。唱誦『HAM』喉輪咒音，振動喉輪的能量。在重要對話或演講前，握著藍晶石，請求藍龍賜予你清晰和勇氣。寫信給那些你需要表達但一直沒有說出口的人，即使不寄出，寫的過程本身就是釋放。進行聲音療癒浴，在泡澡時哼唱或唱歌，讓聲音振動療癒你的喉輪。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:13', 'dragons', '13', 12, '晶龍顯化', 'Crystal Dragon Manifestation', NULL, '{"keywords":["顯化","清晰","聚焦"],"nameEn":"Crystal Dragon Manifestation"}', '{"message":"晶龍的身體由無數透明水晶組成，每一個水晶面都反射和放大能量。它是顯化大師，教導你如何將意圖轉化為現實。顯化不是魔法或幻想，而是理解和應用宇宙法則的能力。你的思想、情感和信念創造你的實相，這是量子物理學也證實的真理。晶龍幫助你清晰地設定意圖，放大你的顯化力量，並加速顯化的過程。但顯化需要幾個關鍵要素：清晰的意圖、持續的專注、高振動的能量、對齊的行動和臣服的信任。晶龍像水晶一樣清晰透明，它要求你對自己誠實，你真正想要的是什麼？不是別人期待的，不是社會定義的，而是你靈魂深處的渴望。當你清晰、專注並保持高振動，宇宙會串謀協助你，同步性事件會出現，機會會自動展現，你的顯化會以你意想不到的方式實現。","guidance":"進行清晰度練習，坐下來寫出你想要顯化的一切，無論是關係、事業、健康、財務還是個人成長。越具體越好，不要說『我想要更多錢』，而是『我想要每月收入10萬元，來自我熱愛的工作』。然後，最關鍵的是感受已經擁有的感覺，顯化的秘密在於振動對齊，你要先成為你想要成為的人，而不是等到得到後才成為。每天花10分鐘進行視覺化練習，閉上眼睛，用所有感官體驗你的願望已經實現的場景，感受那份喜悅、滿足和感恩。創造願景板或顯化盒，放入代表你願望的圖片、文字和物品，每天看著它們，讓它們在你的潛意識中扎根。釋放限制性信念，注意那些『不可能』、『我不配』的想法，用肯定語取代它們。採取啟發性行動，當你感到內在推動時跟隨它，宇宙透過直覺指引你。最後也是最難的，臣服結果和時機，信任宇宙知道最佳的方式和時間。","energy":"白水晶或透明石英是晶龍的水晶，它是最強大的能量放大器，能將你的意圖擴大數倍。創建一個顯化水晶網格，中心放一張寫有你願望的紙，周圍擺放多顆白水晶指向中心，這會持續為你的意圖充能。每天握著白水晶，清晰地陳述你的願望，想像願望從可能性場域顯化到物質現實。在新月時進行顯化儀式，新月代表新的開始和種下種子的最佳時機。點燃白色蠟燭，寫下你的意圖，大聲朗讀三次，然後將紙放在白水晶下。使用檀香或廣藿香精油，它們幫助將意圖扎根到物質層面。保持高振動頻率，做讓你感到喜悅、感恩、愛和興奮的事情，這些高頻情緒是顯化的燃料。避免抱怨、批判、恐懼等低頻情緒，它們會阻礙顯化。創造肯定語並每天重複：『我是強大的顯化者，我的願望輕易實現』。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:14', 'dragons', '14', 13, '雷龍突破', 'Thunder Dragon Breakthrough', NULL, '{"keywords":["突破","震動","覺醒"],"nameEn":"Thunder Dragon Breakthrough"}', '{"message":"雷龍伴隨著雷電和風暴而來，它的出現代表重大突破和巨大轉變。雷電劈開黑暗，照亮真相，震碎舊有的結構。雷龍帶來的不是溫和漸進的改變，而是突然的、震撼的、徹底的轉化。你可能正經歷或即將經歷生活中的『雷擊時刻』——某個事件、領悟或覺醒會永遠改變你。這可能感覺混亂甚至可怕，但雷龍要你知道，這是必要的突破，舊的必須被打破，新的才能誕生。有時候我們停留在舒適但不滿足的情況太久，宇宙會用雷電震醒我們。雷龍也代表頓悟和突然的覺醒，那些你一直迴避或看不見的真相會在閃電的照耀下顯露無遺。這種覺醒雖然可能令人不安，但它會把你從沉睡中喚醒，讓你看見真實的自己和真正的道路。雷龍賦予你打破限制、突破瓶頸、超越自我的勇氣和力量。","guidance":"如果你感到停滯或困住了，雷龍說是時候採取大膽的行動了。不是小修小補，而是根本性的改變。問自己：什麼需要被打破？是一份窒息你的工作？是一段早已死去的關係?是一個限制你的信念？是一個讓你變小的環境？承認真相，即使它令人害怕。然後鼓起勇氣採取行動，離開、說不、改變、重新開始。雷龍會支持你，但它需要你邁出第一步。如果突破已經發生（失業、分手、健康危機），不要抗拒或絕望，這是宇宙在清理道路，為更好的事物騰出空間。信任過程，即使你現在看不見目的地。利用這個震動期進行深度自我反思，那些被震碎的部分真的是你需要的嗎？或者它們是你早就想擺脫但不敢的？在風暴中尋找禮物和教訓。保持靈活和適應性，當雷龍改變一切時，抗拒只會造成痛苦，臣服和流動才是智慧。","energy":"閃電石或電氣石能連結雷龍的高頻電磁能量，它能震碎能量堵塞並激活沉睡的潛能。藍銅礦帶來轉化和突破的力量，特別是在心智和情緒層面。握著這些水晶進行突破冥想，想像雷電從天而降，劈開你生命中的所有障礙和限制。感受電流通過你的身體，震動和激活每個細胞。在雷雨天氣時（如果安全），站在窗邊或門口，感受雷龍的力量，想像它的雷電劈碎你的恐懼和限制。進行能量釋放練習，大聲吼叫、劇烈運動或打枕頭，釋放長期壓抑的情緒和能量。聽鼓聲或節奏強烈的音樂，讓節奏震動你的能量場。進行震動呼吸法，快速有力的呼吸持續幾分鐘，這能改變你的意識狀態並釋放堵塞的能量。使用薄荷或迷迭香精油，它們帶來清醒和突破的能量。說肯定語：『我歡迎突破，我釋放所有限制，我準備好轉化』。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:15', 'dragons', '15', 14, '珊瑚龍連結', 'Coral Dragon Connection', NULL, '{"keywords":["連結","社群","網絡"],"nameEn":"Coral Dragon Connection"}', '{"message":"珊瑚龍生活在深海珊瑚礁中，那裡是地球上最豐富的生態系統之一，數以千計的生物互相依存，共同創造一個美麗的整體。珊瑚龍教導你連結的重要性，我們不是孤島，我們是互相連結的網絡的一部分。你的幸福與他人的幸福相連，你的成長支持他人的成長。在這個過度強調個人主義和競爭的文化中，我們忘記了合作和社群的力量。珊瑚龍提醒你，你不需要獨自面對一切，尋求幫助不是弱點而是智慧，提供支持不是負擔而是榮幸。它邀請你重新連結或深化你的人際關係，建立支持性的社群，創造互惠的網絡。珊瑚龍也可能指出你的使命與服務社群或集體有關，你不只是為自己而活，你的禮物是為了貢獻給更大的整體。當你連結並貢獻，你會發現比單獨行動更大的意義和力量。","guidance":"評估你的人際關係和社群連結，你有支持你的朋友和家人嗎？你有志同道合的靈性社群或專業網絡嗎？如果感到孤獨或孤立，採取行動建立連結。參加課程、工作坊、興趣小組或線上社群，尋找你的部落。主動伸出手，邀請朋友見面，聯絡失聯的親人，加入支持團體。練習真實的連結，不只是表面的客套，而是脆弱地分享你的真實自我，這會邀請他人也這樣做。同時給予支持，不要只是索取，問問朋友他們需要什麼，提供你的時間、技能或資源。創建或參與互助網絡，互相幫忙照顧小孩、分享資源、交換服務。考慮你如何能服務你的社群或更大的集體，可以是志願服務、教學、組織活動或倡導議題。記住，連結需要時間和努力的投入，就像照顧珊瑚礁一樣，需要持續的關注和滋養。","energy":"珊瑚（如果道德取得）或粉珊瑚代表連結和社群，它能打開心並促進人際和諧。玫瑰石英也是建立愛的連結的完美水晶。進行心輪連結冥想，想像你的心與你愛的人的心用粉紅色光連結，然後擴展到整個社群、整個城市、整個地球，感受萬物一體的連結。創建連結祭壇，放置代表你珍視的人和社群的物品或照片，每天為他們傳送愛和祝福。參加團體冥想或祈禱圈，集體能量遠大於個人能量的總和。使用玫瑰或茉莉精油，它們打開心並促進連結。進行同理心練習，當與他人互動時，想像你是他們，從他們的眼睛看世界，感受他們的感受。這會深化理解和連結。說肯定語：『我被愛和支持的社群環繞，我連結並貢獻給更大的整體，我們一起更強大』。在你的家或社區組織聚會，創造連結和共享的空間。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:16', 'dragons', '16', 15, '熔岩龍激情', 'Lava Dragon Passion', NULL, '{"keywords":["激情","創造","生命力"],"nameEn":"Lava Dragon Passion"}', '{"message":"熔岩龍從火山深處噴發而出，攜帶著地球核心熾熱的能量。它代表原始的生命力、未經馴化的激情和爆發性的創造力。熔岩龍喚醒你內在沉睡的火山，那股被社會規範、理性思維和恐懼壓抑的狂野能量。你的激情是你的指南針，指向你靈魂真正渴望的方向。當你對某事感到興奮、激動、充滿活力，那是你的生命力在說話，那是你的靈魂在歌唱。但太多人壓抑他們的激情，因為它不實際、不安全或不被接受。熔岩龍說：夠了！是時候釋放你的激情之火，讓它燃燒，讓它創造，讓它改變一切。激情不只是浪漫或性慾，它是對生命的熱愛，是創造的衝動，是全然投入的能力。當你活在激情中，你會發現無限的能量、創意和喜悅。你會成為點燃他人的火焰，激勵周圍的人也活出他們的激情。","guidance":"辨識什麼真正點燃你的激情，不是應該熱愛的，而是真的讓你興奮的。可能是藝術、音樂、寫作、舞蹈、自然、運動、社會正義、教學、療癒、創業或任何其他事物。如果你不確定，回想什麼事情讓你完全忘記時間，或者想像如果金錢和他人意見都不是問題，你會做什麼。一旦辨識出激情，開始投入時間和能量，即使一開始只是業餘愛好。不要等到條件完美或技能精通，現在就開始，讓激情引導你。釋放對激情的評判，不是所有激情都要變成職業或賺錢，有些激情單純是為了靈魂的滋養和表達。但如果你渴望將激情變成生計，制定計劃並採取行動，這是可能的。連結生命力能量，它不只在創意活動中，也在你的身體和性能量中。擁抱你的身體，照顧它的健康和活力。擁抱你的性能量，不要羞恥或壓抑，它是神聖的創造力量。","energy":"紅玉髓或紅碧玉激活臍輪和海底輪，喚醒生命力和激情能量。石榴石是激情和創造力之石，能點燃內在之火。將這些紅色水晶放在下腹部或臍輪位置，進行能量激活冥想。想像熔岩龍的岩漿從你的脊椎底部升起，帶來熾熱的生命力能量，點燃你的激情中心。進行動態運動如跳舞、搖擺、劇烈運動，讓身體釋放和表達狂野的能量。用火元素工作，凝視蠟燭火焰，進行火儀式，感受火的轉化和創造力。吃辛辣食物激活內在之火。穿紅色或橙色衣物，增強激情能量。在創作時（無論是藝術、寫作還是任何形式），不要審查或控制，讓能量自由流動，讓創造力噴發。進行吼叫或發聲練習，釋放被壓抑的原始能量。說肯定語：『我的激情之火熊熊燃燒，我允許生命力自由流動，我全然投入我熱愛的一切』。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:17', 'dragons', '17', 16, '霜龍沉靜', 'Frost Dragon Stillness', NULL, '{"keywords":["沉靜","冬眠","內省"],"nameEn":"Frost Dragon Stillness"}', '{"message":"霜龍來自極寒之地，它的呼吸能凍結一切，它的存在帶來深度的沉靜和靜止。在這個總是匆忙、喧鬧、過度刺激的世界，霜龍提醒你靜止和休息的神聖。冬天不是死亡而是休眠，是大自然充電和準備春天爆發的時期。你也需要這樣的週期，不能總是在行動、生產和向外。霜龍邀請你進入內在的冬天，慢下來、安靜下來、向內走。這可能感覺不自然或甚至讓你焦慮，因為我們被訓練要忙碌和有生產力。但在靜止中，深刻的療癒、整合和洞見才能發生。霜龍也教導你放手和臣服，就像樹木在冬天放下葉子，不是失去而是為了保存能量和準備新生。你需要放下什麼？什麼活動、關係或責任可以暫時冷凍或永久釋放？霜龍的冰冷不是冷漠，而是必要的界限和空間。它在你周圍創造保護性的冰牆，給你空間休息和恢復。","guidance":"給自己許可休息和什麼都不做，不要感到罪疚。你的價值不在於你的生產力，你是人類存有而非人類做者。創建定期的獨處時間，關閉手機和網絡，遠離人群和喧囂。在這個空間裡，你可以冥想、日記、散步或簡單地存在。如果你感到疲憊或枯竭，這是霜龍在呼喚你進入休眠期。評估你的承諾和責任，什麼可以說不、延期或委託給他人？創造簡化的生活，減少不必要的複雜性。進行數位排毒，限制社交媒體和新聞消費，這些持續的刺激消耗你的能量。練習什麼都不做的藝術，坐著、躺著、凝視窗外，讓頭腦安靜。在靜止中，你會聽到內在聲音，你會獲得深刻的洞見，你會記起你是誰。擁抱生命的冬季，無論是實際的季節、你生命中的時期或每日的夜晚。在黑暗和寒冷中，有獨特的美和智慧。","energy":"透明或白色的霜晶石、白水晶或透石膏能連結霜龍的冷靜能量。藍色蕾絲瑪瑙帶來平靜和沉靜。進行冷卻冥想，想像霜龍的冰冷呼吸包圍你，降低所有過度活躍的能量，帶來深度的平靜。在實際的冬天，在雪地或冷空氣中冥想，感受寒冷的清醒和靜止。如果可能，接觸冰或雪，感受它的純淨和沉靜能量。進行冷水療法，用冷水淋浴或泡冰浴（如果健康允許），這能重置神經系統並帶來深度的在場。使用薄荷或尤加利精油，它們帶來清涼和清醒。創建一個平靜的空間，用藍色或白色裝飾，極簡和安靜。練習沉默，一天或一週保持沉默，不說話，這是深刻的內省練習。聽寧靜的音樂或環境聲音如雪落、風吹。說肯定語：『我允許自己休息和什麼都不做，靜止中有深刻的療癒和智慧，我榮耀生命的冬季』。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:18', 'dragons', '18', 17, '琥珀龍時間', 'Amber Dragon Time', NULL, '{"keywords":["時間","記憶","古老"],"nameEn":"Amber Dragon Time"}', '{"message":"琥珀龍由古老的樹脂凝固而成，它攜帶著數百萬年的記憶和智慧。琥珀能完美保存遠古的生物，如同時間膠囊。琥珀龍是時間的守護者，它教導你時間的神秘和智慧。時間不是線性的，過去、現在和未來在更高維度是同時存在的。你的祖先智慧活在你的DNA中，你前世的記憶儲存在你的靈魂中，你未來的自我正在向你傳送指引。琥珀龍邀請你連結這些時間層面，從過去學習智慧，在現在活出力量，從未來獲得指引。它也提醒你耐心的價值，琥珀需要數百萬年形成，有些事物不能被催促，它們有自己的時機。如果你一直匆忙和不耐煩，琥珀龍說慢下來，信任神聖時機，每件事物都在完美的時間發生。琥珀龍也可能指向療癒過去的創傷或模式，那些被困在時間中的記憶和情緒需要被看見、被療癒、被釋放。","guidance":"進行祖先療癒工作，連結你的血統和家族歷史。我們繼承的不只是基因，還有創傷、模式和信念。通過療癒這些，你不只療癒自己，也療癒前後七代。創建祖先祭壇，放置家族照片、傳家寶和琥珀，向祖先祈禱和請求智慧。如果你對前世好奇，進行前世回溯冥想或尋找專業的前世療癒師。你不需要相信輪迴，但這些記憶（無論是真實的還是象徵性的）往往攜帶重要的訊息和療癒。連結你的未來自我，進行冥想想像你在10年、20年後的樣子，那個更智慧、更成熟的你會給現在的你什麼建議？在日常生活中練習在場和活在當下，這是真正擁有時間的方式。過去已去，未來未來，只有現在是真實的。培養耐心，當事情沒有按你的時間表進行時，信任有更大的計劃在運作。療癒過去的創傷，尋求專業協助如心理治療或能量療癒，釋放被困在時間中的痛苦。","energy":"琥珀是時間之石，它攜帶古老的智慧和溫暖的療癒能量。它特別有效於釋放過去的創傷和恐懼。握著琥珀進行時間旅行冥想，想像你的意識可以在時間中移動，訪問過去療癒傷痛，訪問未來獲得指引。製作琥珀護身符，它能保護你並連結祖先的支持。進行祖先連結儀式，在祭壇前點燃蠟燭，握著琥珀，邀請你的祖先和指導靈與你連結，請求他們的智慧和保護。使用乳香或沒藥精油，這些古老的樹脂連結過去的神聖智慧。寫一封信給你的過去自我，告訴他/她你愛他們，為他們經歷的一切感到驕傲，保證一切都會好起來。寫一封信給你的未來自我，表達你的希望和意圖。進行時間線療癒，想像你的生命時間線從出生到現在到未來，用金色光照亮整條時間線，療癒每個時刻。說肯定語：『我連結所有時間的智慧，我療癒過去，我活在當下，我信任神聖時機』。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:19', 'dragons', '19', 18, '碧玉龍扎根', 'Jasper Dragon Grounding', NULL, '{"keywords":["扎根","穩定","實際"],"nameEn":"Jasper Dragon Grounding"}', '{"message":"碧玉龍深深紮根於大地，它的身體由各種顏色的碧玉組成，這種石頭被稱為『大地之母的撫育石』。碧玉龍是最實際、最扎根的龍族，它確保你不會迷失在靈性追求或夢想中而忽略物質現實。靈性之旅的陷阱之一是過度飄在雲端，失去與地球和身體的連結。碧玉龍提醒你，你來到地球是有原因的，你的身體是你的聖殿，你的物質生活是你靈性的基礎。照顧好你的身體、財務、工作、家和人際關係，這些不是靈性的障礙，而是靈性的表達。碧玉龍也教導你堅毅和持續的力量，不是爆發性的努力，而是穩定持續的投入。就像河流持續流動最終雕刻出峽谷，你的小而持續的行動會創造巨大的成果。碧玉龍帶來穩定的能量，在混亂和不確定時，它是你的錨，讓你保持中心和扎根。","guidance":"評估你的扎根程度，你是否過度活在頭腦或靈性領域而忽略身體和物質需求？進行扎根練習，每天花時間連結地球——赤腳走在草地或土地上、園藝、接觸自然元素。照顧好你的身體，規律運動、健康飲食、充足睡眠，這些是扎根的最基本方式。建立穩定的日常習慣和儀式，一致性帶來穩定和安全感。處理被忽略的實際事務，如財務、健康檢查、家庭維修，不要逃避這些『無聊』的責任，它們是成年的一部分。在追求夢想時保持實際，制定具體可行的計劃和步驟，不要只是空想。學習耐心和持續，快速成功很少持久，穩定的成長才是真實的。在靈性練習後扎根，如冥想或能量工作後，吃點東西、喝水、觸摸地面，確保能量整合到身體。當感到焦慮或不安時，回到身體和當下，用五感體驗現在：你看到、聽到、聞到、嚐到、觸摸到什麼？","energy":"紅碧玉是最強大的扎根和穩定水晶，它連結地球核心的能量，帶來力量和耐力。各種顏色的碧玉都有扎根效果——黃碧玉、綠碧玉、褐碧玉等。隨身攜帶或佩戴碧玉，特別是當你感到飄忽或不穩定時。每天進行扎根冥想，坐在地上或椅子上雙腳平放，握著紅碧玉，想像從你的海底輪長出根，深深扎入地球，一直到地球核心。感受地球的穩定、力量和支持能量流回你的身體。進行身體性的活動如園藝、烹飪、清潔、木工，這些都是扎根的方式。吃根莖類食物和蛋白質，在物質層面扎根。使用雪松或廣藿香精油，它們帶來扎根和穩定。在家中放置大型的扎根水晶如紅碧玉或黑曜石在房間的四角，穩定空間能量。說肯定語：『我深深扎根於地球，我的身體是我的聖殿，我在物質世界中穩定和有力量』。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:20', 'dragons', '20', 19, '歐泊龍變化', 'Opal Dragon Transformation', NULL, '{"keywords":["變化","多面","可能性"],"nameEn":"Opal Dragon Transformation"}', '{"message":"歐泊龍的身體如同歐泊石，閃耀著所有彩虹的顏色，每個角度看都不同。它是變化、適應和無限可能性的化身。歐泊龍教導你，變化是生命唯一的常數，抗拒變化就是抗拒生命本身。你不是固定的，你是流動的、進化的、不斷轉化的。每個經歷改變你，每個學習塑造你，每個選擇創造新的你。歐泊龍也提醒你，你是多面向的存有，你可以同時是許多身份：藝術家和商人、夢想家和實踐者、靈性追求者和世俗成功者。你不需要選擇一個身份並拋棄其他，你可以整合所有面向。歐泊龍閃爍著無限的可能性，在任何時刻，你都可以選擇不同的道路，成為不同的版本。沒有什麼是注定的，你有自由意志創造你的實相。如果你對現狀不滿，改變它。歐泊龍賦予你變化的勇氣和適應的靈活性。","guidance":"擁抱變化而非抗拒它，當生活改變時，問『這個變化邀請我成長什麼？』而非『為什麼這發生在我身上？』培養靈活性和適應力，就像水適應任何容器，你也可以適應新的情況。探索你的多面向，不要被單一身份定義。試試新的興趣、技能、風格，你可能會發現未知的自己。給自己許可改變想法、改變方向、改變夢想，這不是失敗或不穩定，而是成長和進化。不要被『我一直都是這樣』困住，你可以成為新的版本。進行身份探索練習，寫下你的所有角色和面向，然後問哪些是真實的，哪些是別人期待的？哪些你想保留，哪些你想釋放？在決策時，保持開放給多個選項，不要過早關閉可能性。當一扇門關閉，尋找打開的窗戶。培養好奇心和探險精神，定期做新的事情、去新的地方、遇見新的人，打破習慣的模式。","energy":"歐泊是變化和轉化的水晶，它閃耀著所有顏色，象徵無限可能性。它特別支持正在經歷重大轉變的人。握著歐泊進行轉化冥想，想像你可以成為任何版本的自己，看見多個可能的未來，選擇最吸引你的。拉長石也是變化之石，它閃爍的彩虹光支持轉變和魔法。進行蛻變儀式，寫下你想釋放的舊身份或模式，燒掉紙張，然後寫下你想成為的新版本，大聲朗讀並將紙保存在歐泊下。使用佛手柑或葡萄柚精油，它們帶來適應和輕盈，幫助你擁抱變化。在改變髮型、風格或形象時有意識地進行，這是外在反映內在轉變的方式。進行可能性冥想，想像你有無限的可能性可以選擇，探索不同的道路和版本，感受哪一個最共鳴。說肯定語：『我擁抱變化和轉化，我是流動的、多面向的、無限可能的，我每天成為更真實的自己』。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:21', 'dragons', '21', 20, '秘銀龍煉金', 'Mithril Dragon Alchemy', NULL, '{"keywords":["煉金","轉化","精煉"],"nameEn":"Mithril Dragon Alchemy"}', '{"message":"秘銀龍來自煉金術的神秘傳統，它的身體由稀有的秘銀打造，據說這種金屬能轉化一切觸及的事物。煉金術不只是將鉛變成金的物質科學，更是靈魂轉化的象徵。秘銀龍是偉大的煉金術士，它教導你如何將生命中的『鉛』轉化為『金』——將痛苦轉化為智慧，將創傷轉化為力量，將黑暗轉化為光明。你經歷的每個挑戰都是煉金的材料，沒有什麼是浪費的，一切都能被轉化和精煉。秘銀龍也代表提煉和精華，去除雜質，保留純粹的金。在你的生命中，什麼是雜質？什麼是分散注意力、消耗能量但不增加價值的？煉金過程需要火——試煉的火焰，但這火焰不是懲罰，而是轉化和純化。秘銀龍守護你經歷這個煉金過程，確保你不會被燒毀，而是被精煉成最純淨的版本。","guidance":"看待你的挑戰和痛苦為煉金的機會，問『這個經歷在教導我什麼？它如何讓我成長？它如何服務我的進化？』進行陰影煉金，深入探索你的陰暗面——恐懼、憤怒、羞恥、嫉妒——不是批判它們，而是理解它們如何服務過你，然後轉化它們的能量為光明的表達。例如憤怒可以轉化為健康的界限和改變的力量。練習精簡和提煉，在你的生活中去除不必要的——物品、活動、關係、信念。保留真正重要和有價值的。進行定期的生活審查，什麼正在工作，什麼不是？什麼需要被改變或釋放？學習從每個經歷中提取智慧和禮物，即使是最痛苦的經歷都攜帶珍貴的教訓。寫反思日記，記錄你的洞見和學習。尋找你生命中的重複模式，這些是靈魂想要你學習和轉化的課題。當同樣的情況不斷出現，不是宇宙在懲罰你，而是在給你機會掌握這個課題。","energy":"銀或白金（如果可獲得）連結秘銀龍的煉金能量。透明石英也是煉金術士之石，能轉化和提升能量。紫水晶帶來轉化和靈性煉金。進行煉金冥想，想像你坐在煉金爐中，神聖的火焰包圍你，燃燒掉所有不純淨的部分——恐懼、限制、創傷——留下純粹的黃金本質。這不是毀滅而是轉化，舊的形式溶解，新的形式誕生。使用乳香或沒藥精油，這些古老的樹脂被煉金術士用於神聖工作。進行火儀式，寫下你想轉化的事物（痛苦、模式、信念），安全地燃燒紙張，觀想轉化發生，從灰燼中誕生新的。研究煉金術符號和教導，它們充滿深刻的心理和靈性智慧。說肯定語：『我是煉金術士，我轉化我的生命，一切經歷都精煉我成為最純淨的黃金，我從試煉的火焰中誕生更強大』。慶祝你的轉化，認可你走過的路和你成為的人。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:22', 'dragons', '22', 21, '天幕龍視野', 'Sky Dragon Vision', NULL, '{"keywords":["視野","遠見","高度"],"nameEn":"Sky Dragon Vision"}', '{"message":"天幕龍翱翔在最高的天空，從那裡它能看見整片大地的全景。它的視野無與倫比，能同時看見森林和樹木，看見大圖像和細節。天幕龍教導你提升你的視角，不要被日常的瑣事和挑戰困住而失去大方向。當你從高處看，許多看似巨大的問題其實很小，許多看似分離的事物其實相連。天幕龍邀請你定期提升，問自己『一年後、五年後、生命盡頭時，這件事還重要嗎？』這個視角能幫助你區分真正重要和只是緊急的事情。天幕龍也代表遠見和願景，看見尚未顯化的可能性，為尚未出生的未來播種。偉大的領導者、藝術家和變革者都有這種能力，看見他人看不見的，然後將它帶到現實。天幕龍問你，你的願景是什麼？你想創造什麼樣的未來？不只是為你自己，更是為你的社群、世界、未來世代。","guidance":"定期進行高度視角練習，想像你飛到高空看你的生命，從這個高度，什麼看起來真正重要？什麼看起來微不足道？讓這個視角指導你的優先順序和決策。創建你的生命願景，寫下你想在生命中創造和體驗的一切，不只是短期目標，更是深層的渴望和意義。可以用文字、圖片或願景板表達。問自己你的生命目的，你為什麼在這裡？你獨特的禮物和貢獻是什麼？不要期待一個清晰的答案立即出現，這是持續探索的旅程，但開始問這個問題本身就會打開門。在做決定時，考慮長期影響而非只有短期結果。五年後你會感謝現在做的這個決定嗎？培養系統思考，看見事物如何互相連結和影響，而非孤立地看待問題。學習其他文化、歷史、哲學，擴展你的視野和理解。旅行如果可能，它能打開你的視角。成為你想在世界看見的改變，你的願景從你開始。","energy":"藍晶石或天青石連結天空和高度視角，它們打開第三眼和頂輪，擴展你的意識。舒俱徠石帶來遠見和靈性視野。進行天幕龍冥想，想像你騎在天幕龍背上飛向天空，越飛越高，直到你能看見地球的全景。從這個高度觀察你的生命，看見大圖像和模式。請求天幕龍給你需要看見的視野和洞見。在高處進行冥想，如山頂、高樓或飛機上，實際的高度能幫助你獲得視角的轉變。使用薄荷或迷迭香精油，它們清醒頭腦並擴展視野。創造願景板，收集代表你願景的圖片和文字，每天觀看它讓願景在你的意識中紮根。寫未來日記，寫下你在一年、五年後的生活，用現在式描述彷彿已經發生，這幫助你的潛意識朝那個方向創造。說肯定語：『我看見大圖像和真正重要的事，我的視野清晰，我創造美好的未來，我為更大的善而活』。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:23', 'dragons', '23', 22, '翠玉龍繁榮', 'Emerald Dragon Prosperity', NULL, '{"keywords":["繁榮","成長","豐收"],"nameEn":"Emerald Dragon Prosperity"}', '{"message":"翠玉龍全身覆蓋著翠綠的鱗片，如同春天的新葉，充滿生機和成長的能量。它是繁榮、豐盛和持續成長的守護者。不同於金龍的突然財富，翠玉龍帶來穩定增長的繁榮，如同植物從種子發芽、成長、開花、結果的自然過程。翠玉龍教導你，真正的繁榮是可持續的，來自正確的種子、耐心的培育和時間的累積。你種下什麼種子（思想、信念、行動），你就會收穫什麼果實。如果你想要繁榮，種下繁榮的種子：感恩、慷慨、價值創造、持續學習。翠玉龍也提醒你，繁榮不只是金錢，而是生命各個領域的豐盛成長：健康的身體、滋養的關係、有意義的工作、個人的成長、靈性的深化。當你在所有領域都繁榮時，你體驗到真正的富足。翠玉龍帶來春天的能量，新開始、新成長、新機會，是種下新種子的完美時機。","guidance":"評估你在生命各個領域的成長和繁榮，使用生命之輪練習（健康、財務、關係、事業、個人成長、娛樂、靈性、貢獻），為每個領域打分，看哪裡需要更多關注和投入。種下你想要的種子，如果你想要財務繁榮，開始儲蓄、投資、學習理財、創造價值。如果你想要關係繁榮，投入時間、真實溝通、展現愛。培養成長心態，相信你可以學習、改進、發展。失敗不是終點而是回饋，挑戰不是障礙而是成長的機會。持續學習和發展技能，投資在你自己，這是最好的投資。閱讀書籍、上課程、找導師、獲得經驗。練習感恩，每天列出你感恩的事物，感恩是吸引更多繁榮的磁鐵。慷慨地給予，金錢、時間、知識、愛，你給出的會回到你身上且倍增。採取持續的小行動，繁榮是累積的結果，每天進步1%，一年後你會成長37倍。慶祝小勝利和進展，認可你的成長。","energy":"綠東陵或翡翠是繁榮和成長之石，它們吸引機會和好運。綠幽靈水晶內含綠色幻影，象徵層層成長和財富累積。將這些綠色水晶放在你的財位、辦公桌或錢包中。每天握著綠東陵，觀想你在生命各個領域的繁榮成長，看見自己健康、富有、被愛、成功、快樂。創造繁榮祭壇，放置綠色蠟燭、植物、翠綠水晶和豐盛象徵如麥穗、果實、錢幣。在春分或新月時種下實際的種子或植物，作為你意圖的象徵，照顧它的成長就是照顧你願望的成長。使用薄荷或羅勒精油，它們吸引繁榮和豐盛。穿綠色衣物或在空間中使用綠色，這是成長和繁榮的顏色。進行成長冥想，想像自己如植物從種子成長為大樹，根深扎地，枝葉茂盛，開花結果。說肯定語：『我持續成長和繁榮，我的生命在所有領域都豐盛，我吸引機會和成功，我收穫我種下的美好種子』。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:24', 'dragons', '24', 23, '石榴龍熱情', 'Garnet Dragon Passion', NULL, '{"keywords":["熱情","承諾","奉獻"],"nameEn":"Garnet Dragon Passion"}', '{"message":"石榴龍的鱗片如同深紅的石榴石，閃耀著熱情和奉獻的光芒。它教導你全心全意地投入你所選擇的道路，不是三心二意或淺嘗即止，而是深刻的承諾和持久的熱情。在這個充滿干擾和選擇的時代，我們很容易分散注意力，這裡試一點、那裡嘗一點，從未真正深入任何事物。石榴龍說，深度比廣度更有力量。當你全然投入一件事，你會到達卓越的境界，體驗深刻的滿足。石榴龍也代表忠誠和承諾，無論是對關係、工作、夢想還是靈性道路的承諾。承諾不是限制，而是賦權。當你承諾時，你釋放內在的全部力量，不再被猶豫和選擇消耗能量。石榴龍還連結根部和性能量，它是生命力的源泉，是創造和顯化的根本力量。當這份能量被喚醒和正確導引，你能創造任何你渴望的事物。","guidance":"辨識你真正想要承諾的事物，不是別人期待的或社會認為重要的，而是讓你的心燃燒的。可能是一段關係、一個職業、一個創意項目、一條靈性道路。一旦辨識，做出承諾。承諾意味著即使在困難時刻也不放棄，即使熱情暫時消退也繼續前進，即使有更誘人的選擇也保持忠誠。學習區分真正的承諾和固執，承諾是有意識的選擇和持續的投入，固執是拒絕面對改變的需要。定期檢視你的承諾是否仍然對齊你的真相。練習專注，當你工作或創作時，全然在場，關閉干擾，深入你正在做的事。質量比數量更重要，完成一件作品比開始十件更有價值。培養耐力和堅持，不要期待立即的結果或持續的興奮感，承諾是長期的旅程。喚醒你的生命力和性能量，它是創造力的源泉，通過運動、舞蹈、瑜伽或靜心激活它。","energy":"石榴石是承諾和熱情之石，它激活海底輪和臍輪，喚醒生命力。紅碧玉增強耐力和堅持。每天握著石榴石進行承諾冥想，清晰地陳述你的承諾，感受這份承諾在身體中扎根。將石榴石放在海底輪位置，進行生命力激活冥想，想像深紅色的能量從你的根部上升，充滿力量和熱情。使用玫瑰或依蘭精油，它們連結心和激情。創建承諾祭壇，放置石榴石、紅色蠟燭和代表你承諾的象徵物。定期在祭壇前重申你的承諾。進行火儀式，寫下你的承諾並在火焰中大聲宣讀，讓火元素見證和祝福你的誓言。穿紅色或深紫紅色，增強承諾能量。在關係中，定期與伴侶重新確認承諾和奉獻。說肯定語：『我全然承諾我的道路，我的熱情持久燃燒，我深深投入我所選擇的一切，我忠於我的真相和目標』。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:25', 'dragons', '25', 24, '極光龍奇蹟', 'Aurora Dragon Miracle', NULL, '{"keywords":["奇蹟","魔法","驚奇"],"nameEn":"Aurora Dragon Miracle"}', '{"message":"極光龍身上流動著如極光般變幻的色彩，綠色、紫色、藍色在它的鱗片上舞動。它是奇蹟和魔法的化身，提醒你生命本身就是一場奇蹟。在平凡的日常中，我們忘記了存在的神奇——你的心臟每天跳動十萬次，你的身體由星塵組成，你的意識是宇宙覺察自己的方式。極光龍重新喚醒你對生命奇蹟的感知和驚嘆。它也告訴你，奇蹟不是違反自然法則的事件，而是你提升到更高振動時自然發生的同步性和恩典。當你活在愛、信任和感恩中，奇蹟成為日常。極光龍邀請你敞開接收奇蹟，不要用理性頭腦限制可能性，不要用懷疑關閉魔法之門。相信奇蹟，期待奇蹟，注意奇蹟。它們一直在發生，只是你需要眼睛去看見。極光龍帶來驚喜和意外的祝福，那些你從未想像或計劃的美好。","guidance":"培養驚奇感，開始注意生命中的小奇蹟——日出的美麗、孩子的笑聲、完美時機的相遇、意外的禮物。每天寫下至少一個你注意到的奇蹟或同步性事件，這會訓練你的意識看見更多。放下控制慾和過度計劃，為意外和驚喜留出空間。最好的事物往往以你意想不到的方式到來。保持開放和好奇的心態，像孩子一樣看待世界，充滿驚奇而非厭倦。重新連結自然，在大自然中，奇蹟顯而易見——種子變成樹木、毛蟲變成蝴蝶、季節循環。向極光龍請求奇蹟，不是作為交易或乞求，而是作為共創。陳述你的願望，然後釋放並信任宇宙會以完美的方式回應。當奇蹟發生時，認可並感恩它，這會邀請更多奇蹟。分享你的奇蹟故事，啟發他人也看見和相信。成為他人的奇蹟，你的善意可能是某人的奇蹟。","energy":"拉長石閃耀著類似極光的光芒，它連結魔法和奇蹟的次元。透石膏以高頻連結天使和更高次元。每晚進行極光冥想，想像你站在極光下，那些色彩流動的光降下包圍你，為你充能奇蹟頻率。將拉長石放在枕頭下，邀請奇蹟在夢中和日常生活中顯現。如果可能，實際去看極光，這是地球上最接近魔法的自然現象。使用薰衣草或乳香精油，它們提升振動並打開魔法之門。創建奇蹟清單，寫下你經歷過的所有奇蹟，定期閱讀它加強你對奇蹟的信心。創建一個奇蹟罐，當奇蹟發生時寫在紙條上放進罐中，年底時打開閱讀，你會驚訝有多少奇蹟。保持高振動頻率，做讓你感到喜悅、愛、感恩、興奮的事，這是吸引奇蹟的磁鐵。說肯定語：『奇蹟每天在我生命中發生，我對魔法和驚奇敞開，我相信並期待美好的驚喜，我的生命本身就是奇蹟』。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:26', 'dragons', '26', 25, '赤銅龍韌性', 'Copper Dragon Resilience', NULL, '{"keywords":["韌性","適應","復原"],"nameEn":"Copper Dragon Resilience"}', '{"message":"赤銅龍的身體由銅打造，這種金屬具有延展性和導電性，象徵韌性和適應能力。銅會隨時間氧化變色，但這不是腐敗而是美麗的轉化——銅綠是時間和經驗的標記。赤銅龍教導你，真正的強大不是剛硬或不受影響，而是韌性——被打擊但不被打倒，彎曲但不斷裂，經歷創傷但最終療癒並成長。韌性不是你天生擁有的特質，而是通過經歷挑戰而培養的肌肉。每一次你度過困難並存活下來，你就變得更強韌。赤銅龍也代表導電性和連結，它提醒你在困難時刻不要孤立自己，尋求支持和連結能大大增強你的復原力。赤銅龍見證了你的所有經歷，它說：看看你已經度過了多少，你比你以為的更強大。你的傷疤是力量的證明，不是弱點的標記。","guidance":"承認和榮耀你的韌性，回顧你的生命，列出所有你度過的挑戰和危機。你存活下來了，而且你從中學習和成長了。認可自己的力量和復原力。當面對新的挑戰時，提醒自己：『我以前度過過困難，我這次也能度過』。建立支持系統，在困難時刻，不要試圖獨自承擔一切，尋求朋友、家人、治療師或支持團體的幫助。練習自我照顧，特別是在壓力時期，確保基本需求被滿足——睡眠、營養、運動、社交連結。培養應對技巧，如深呼吸、冥想、運動、寫日記、藝術表達。從失敗和挫折中學習，不要看它們為終點，而是回饋和成長的機會。問『這個經歷教導了我什麼？我如何因此變得更強？』保持希望和視角，記住『這也會過去』，沒有任何狀態是永久的。慶祝小勝利，認可每一步前進，無論多微小。","energy":"銅是赤銅龍的金屬，佩戴銅手鐲或飾品能增強韌性和能量流動。赤鐵礦是扎根和力量之石，支持你在困難中保持穩定。紅碧玉增強耐力和生存本能。握著這些水晶進行韌性冥想，回想你度過的所有挑戰，感受那份存活和克服的力量在你體內。進行身體韌性練習，如瑜伽或太極，教導身體彎曲不斷裂的藝術。進行冷熱對比浴或桑拿，訓練身體適應不同條件,這也會培養心智的韌性。使用雪松或杜松精油，它們帶來力量和扎根。創建韌性祭壇，放置代表你力量和存活的物品——你度過困難時期的照片、象徵復原的植物、銅製物品。寫一封信給你的韌性，感謝它一直支持你度過一切。說肯定語：『我是韌性的，我彎曲但不斷裂，我從挑戰中成長更強，我有能力度過任何事情，我的傷疤是我的力量勳章』。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:27', 'dragons', '27', 26, '螢石龍清晰', 'Fluorite Dragon Clarity', NULL, '{"keywords":["清晰","專注","秩序"],"nameEn":"Fluorite Dragon Clarity"}', '{"message":"螢石龍身上布滿多彩的螢石，這種水晶以帶來心智清晰和秩序聞名。在資訊爆炸和持續干擾的時代，我們的頭腦往往過載、混亂、難以專注。螢石龍清理心智的霧霾，帶來清晰的思考和專注的能力。它幫助你區分重要和瑣碎，看穿混淆和迷霧到達核心真相。螢石龍也代表組織和結構，它教導你創造秩序而非混亂,建立系統而非隨機。清晰的頭腦需要清晰的環境，外在的混亂反映和加劇內在的混亂。螢石龍邀請你整理你的物理空間、數位空間和心智空間。當你清理雜亂，清晰自然湧現。螢石龍特別支持學習、研究、寫作和任何需要心智專注的工作。它幫助你吸收和整合新資訊，做出明智的決定,有效地溝通想法。","guidance":"進行心智排毒，減少資訊輸入——限制社交媒體、新聞、電視的時間。選擇性和有意識地消費內容,不要被動地吸收一切。清理物理空間,從你的家、辦公室、車子開始，丟棄或捐贈不需要的物品。整潔的空間支持清晰的思想。組織你的數位生活，清理檔案、照片、郵件,創建清晰的資料夾系統。取消不再關注的訂閱。練習單一任務而非多工，專注地完成一件事再移到下一件，這比同時做多件事更有效率和品質。在做決定前,創建清單列出選項、優缺點、價值觀對齊度，這能幫助清晰思考而非情緒反應。進行大腦傾倒練習，將所有在你頭腦中的想法、擔憂、待辦事項寫在紙上，清空頭腦。定期冥想或靜坐，這是終極的心智清理練習。在需要專注工作時，創造無干擾的環境，關閉通知，設定特定時間處理郵件和訊息。","energy":"螢石是心智清晰的水晶，有多種顏色但都具有清理和組織能量的效果。將螢石放在辦公桌上或學習區域，支持專注和學習。白水晶也增強清晰度。進行螢石清晰冥想，握著螢石，想像你的頭腦像混濁的水逐漸變得清澈透明，所有混亂和困惑沉澱下去，留下清晰的思想。將螢石放在第三眼位置，增強心智清晰和直覺洞見。使用薄荷或迷迭香精油，它們清醒頭腦並增強專注。創建一個清晰的工作空間，極簡、組織良好、充滿自然光。使用螢石製作能量網格，四個角各放一塊螢石，創造清晰和秩序的場域。在重要會議或考試前握著螢石,請求心智清晰和專注。說肯定語：『我的頭腦清晰而專注，我輕易看見真相和優先順序，我在清晰和秩序中運作，我做出明智的決定』。在月光下為螢石充能,清理它吸收的心智混亂。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:28', 'dragons', '28', 27, '沙漠龍耐力', 'Desert Dragon Endurance', NULL, '{"keywords":["耐力","生存","堅毅"],"nameEn":"Desert Dragon Endurance"}', '{"message":"沙漠龍生活在最嚴酷的環境中，它教導你在最艱難的條件下生存和堅持的能力。沙漠看似貧瘠和無生命，但實際上充滿了適應和生存的生命。沙漠生物學會了保存水分、在極端溫度下生存、在稀缺中茁壯。沙漠龍教導你這些生存智慧:在匱乏中創造豐盛、在困難中找到力量、在孤獨中發現自給自足。你可能正經歷生命的沙漠期——資源缺乏、支持有限、環境艱難——但沙漠龍要你知道，這是暫時的,而你有能力度過它。沙漠龍也教導你簡化和本質,在沙漠中沒有多餘,只有必需。什麼是你生命中真正必需的？當你剝除所有不必要的，你會發現你需要的遠比你以為的少，而你擁有的遠比你以為的多。沙漠龍培養堅毅——不是華麗或戲劇性的，而是持續、堅定、不放棄的力量。","guidance":"評估你正在經歷的『沙漠期』，可能是財務困難、關係孤立、事業停滯或靈性乾涸。承認現實的艱難,不要假裝或否認。然後，像沙漠生物一樣適應,問『我如何能在這些條件下不只是生存而是茁壯？』練習資源管理和簡化，在匱乏時期,明智地使用你擁有的，創造性地滿足需求。簡化生活，減少開支、需求和複雜性。培養自給自足，不要等待外在拯救或改變,發展你自己的資源和力量。學習新技能、創造收入來源、建立內在的穩定。在孤獨中尋找禮物,獨處可以是療癒、內省和連結自己的時間。保持信心,記住沙漠期是暫時的,雨水會來，綠洲存在，春天會到。在此期間,保存你的能量和資源,不要浪費在不必要的事物上。尋找沙漠的美和智慧,它有獨特的寧靜、清晰和純淨。慶祝每一天的生存和小勝利。","energy":"沙漠玫瑰或沙漠碧玉連結沙漠龍的能量,它們形成於沙漠環境，攜帶生存和適應的智慧。紅碧玉增強耐力。握著這些水晶進行沙漠冥想,想像你在沙漠中行走,雖然艱難但你繼續前進,你知道如何在這個環境中生存。感受沙漠的力量和靜默進入你。在實際的沙漠中冥想如果可能,或在乾燥炎熱的環境,這能幫助你體驗和連結沙漠的能量。練習斷食或資源限制,暫時限制某些資源(食物、水、舒適)來培養堅毅和適應力,但要安全和漸進地進行。使用雪松或沒藥精油,它們帶來扎根和堅毅。創建一個簡化的生活空間,去除不必要的物品,只保留真正需要和有意義的。這個練習本身就是沙漠的教導。說肯定語：『我在任何條件下都能生存和茁壯，我適應並克服困難，我在簡化中發現豐盛，我的堅毅是我的力量，這也會過去』。在艱難時期,視覺化沙漠後的綠洲,保持希望。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:29', 'dragons', '29', 28, '雲龍夢想', 'Cloud Dragon Dreams', NULL, '{"keywords":["夢想","想像","可能性"],"nameEn":"Cloud Dragon Dreams"}', '{"message":"雲龍在雲層中翱翔和遊戲,它的身體由雲霧組成,不斷變化形狀。它是夢想、想像力和無限可能性的守護者。雲龍提醒你,在顯化到物質現實前,一切都先存在於夢想和想像中。你的想像力是創造的工作室,在那裡你可以設計、實驗、探索無限的可能性,不受物質世界的限制。雲龍邀請你重新連結你的想像力和夢想能力,這些在成長過程中可能被理性思維和『現實』壓抑了。給自己許可去夢想,不是逃避或幻想,而是創造的第一步。雲龍也連結你的夜間夢境,那是潛意識和靈魂溝通的領域。你的夢提供指引、療癒、創意和預知,但你需要注意和理解它們。雲龍教導你在夢想和行動、想像和顯化之間流動,兩者都是必要的。太多夢想沒有行動變成幻想,太多行動沒有夢想變成機械。","guidance":"重新連結你的夢想,問自己『如果沒有任何限制,我會創造什麼樣的生命？』讓自己自由夢想,不要立即用『但是不可能』或『但是不實際』限制。夢想是第一步,實際性可以之後考慮。進行想像力練習,視覺化、白日夢、創意寫作、藝術,這些都是想像的表達。每天給自己時間和空間去夢想和想像。開始記錄你的夜間夢境,在床邊放筆記本,醒來立即記錄夢的內容,即使片段或不清晰。隨時間你會記得更多且更清晰。學習解夢,研究符號的意義,但更重要的是注意你自己的直覺感受,每個人的符號可能有獨特的意義。在睡前設定夢的意圖,請求你的夢回答某個問題或提供某個主題的指引。保持夢想和行動的平衡,給夢想時間但也要採取實際步驟朝夢想前進。分享你的夢想,與支持的人討論你的夢想和夢境,它們可能提供新的視角。","energy":"月光石連結夢境和想像力,它特別支持夢的記憶和解讀。紫水晶打開第三眼和夢的通道。將這些水晶放在枕頭下,邀請清晰和有意義的夢。進行雲龍冥想,想像你飛入雲層,在雲中遊戲和探索,看見各種形狀和可能性,讓你的想像自由飛翔。使用薰衣草或洋甘菊精油,它們促進放鬆和夢境。在睡前泡薰衣草浴,進入夢的狀態。創建夢想板或夢想日記,收集代表你夢想的圖片、文字、素描。定期觀看和更新它。進行夢瑜伽或清明夢練習,學習在夢中保持意識,這開啟強大的可能性。在白天定期檢查『我在做夢嗎？』培養這個習慣會延伸到夢中。說肯定語：『我連結我的夢想和想像力,我的夢境清晰並提供指引,我將夢想顯化為現實,一切皆有可能』。保護和滋養你的夢想,不要讓批評或懷疑殺死它們。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:30', 'dragons', '30', 29, '鐵龍意志', 'Iron Dragon Will', NULL, '{"keywords":["意志","決心","紀律"],"nameEn":"Iron Dragon Will"}', '{"message":"鐵龍由堅硬的鐵打造,象徵不可動搖的意志和決心。它教導你意志力的重要性——不是控制或壓抑,而是專注和堅定地朝目標前進的能力。在充滿誘惑和干擾的世界,意志力是區分成功和失敗、實現和放棄的關鍵。鐵龍賦予你鋼鐵般的意志,讓你能夠說不給不服務你的事物,說是給你的承諾和目標,即使在困難或誘惑時刻。意志力不是天生的,而是通過練習培養的肌肉。每次你選擇延遲滿足、抗拒誘惑、堅持困難的任務,你的意志力就變強。鐵龍也代表紀律和結構,不是嚴苛或僵硬的紀律,而是支持你目標的健康習慣和系統。自由不是沒有紀律,相反,紀律創造真正的自由——當你掌控你的習慣和選擇,你就自由地創造你想要的生活。鐵龍要求你誠實面對你的意志力和紀律在哪些領域需要加強。","guidance":"設定清晰和具體的目標,意志力需要明確的方向。寫下你的目標和它們為什麼重要。建立支持目標的系統和習慣,不要依賴每天的動力或意志力,而是創造自動化的習慣和環境。移除誘惑,使正確的選擇變成容易的選擇。從小開始培養意志力,不要一次嘗試改變所有習慣,選一個領域(如每天運動或冥想)，掌握它後再增加新的。慶祝小勝利,每次你堅持承諾或抗拒誘惑,認可自己。練習延遲滿足,當你想要某物時,等待一段時間(如24小時)再決定是否真的需要。這能訓練衝動控制。辨識並管理意志力疲勞,意志力是有限資源,在一天中會消耗。在早晨做最需要意志力的任務,當你的能量最高時。確保充足睡眠、營養和休息,這些是意志力的基礎。找到問責夥伴,與他人分享你的目標並定期報告進展,這增加承諾感。","energy":"赤鐵礦是鐵的氧化物,是意志力和決心的水晶。它扎根並加強下三輪,特別是個人力量中心。黑碧玉也增強意志和耐力。每天握著赤鐵礦進行意志力冥想,感受鐵的力量和堅定進入你,強化你的決心和專注。佩戴赤鐵礦手鍊或飾品,在需要意志力時觸摸它提醒自己的力量。進行力量呼吸,快速有力的呼吸幾輪,這能激活個人力量中心並增強意志。使用迷迭香或薄荷精油,它們增強專注和決心。創建紀律儀式,如每天同一時間做某事,這能訓練意志力並創造穩定的習慣。進行冷水淋浴,這是訓練意志力和心智力量的古老練習。說肯定語：『我的意志堅強如鐵,我有紀律和專注達成我的目標,我控制我的習慣和選擇,我堅持我的承諾即使困難』。視覺化自己如鐵龍堅定不移地朝目標前進,沒有任何事物能阻擋你。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:31', 'dragons', '31', 30, '珍珠龍智慧', 'Pearl Dragon Wisdom', NULL, '{"keywords":["智慧","耐心","轉化"],"nameEn":"Pearl Dragon Wisdom"}', '{"message":"珍珠龍身上鑲嵌著無數珍珠,每一顆都是從刺激和困難中誕生的美。當沙粒進入牡蠣,它帶來不適和刺激,但牡蠣不是排斥它,而是層層包裹它,最終轉化為珍貴的珍珠。珍珠龍教導你同樣的智慧:你生命中的刺激、挑戰、痛苦不是要被排斥或抗拒的,而是要被包容和轉化的。每個困難都是形成智慧珍珠的機會。這個過程需要時間和耐心,珍珠不是一夜形成的,而是層層累積的結果。同樣,智慧不是從書本或一次經歷中獲得,而是從多年的生命體驗、反思和整合中慢慢形成。珍珠龍也連結月亮和陰性智慧,那種來自直覺、感受、關係和內在知曉的智慧,不同於陽性的理性和分析智慧。兩者都重要,但我們的文化過度重視理性而忽視直覺智慧。珍珠龍邀請你平衡這兩者。","guidance":"反思你的生命經歷,特別是那些困難和痛苦的,問『這個經歷教導了我什麼智慧？它如何轉化了我？』寫下你學到的教訓和智慧,認可你的成長。進行智慧傳承,與年輕人或他人分享你的經驗和智慧,這不只幫助他們,也鞏固和榮耀你的學習。尋求長者或智者的智慧,向那些走過你道路的人學習,尊重他們的經驗和洞見。培養耐心,認識到智慧和成長需要時間,不要期待立即的理解或轉化。信任過程。練習反思和整合,經歷本身不會自動帶來智慧,你需要反思它、從中學習、整合洞見到你的生命。定期進行反思練習如日記或冥想。平衡理性和直覺智慧,在做決定時,既用邏輯分析也傾聽內在知曉。連結你的身體智慧,身體攜帶深層的知識,學會傾聽它的訊號。榮耀你的智慧,不要謙虛地隱藏你的知識,你的智慧是經歷和成長的結果,值得被看見和分享。","energy":"珍珠是智慧之寶,特別連結月亮、陰性能量和情緒療癒。如果道德取得,佩戴珍珠增強智慧和平靜。月光石也連結月亮和內在智慧。進行珍珠冥想,想像你的困難和挑戰如沙粒,你的愛和耐心如珍珠層,一層層包裹轉化它們成為智慧的珍珠。看見你的生命充滿這些珍貴的珍珠。在月圓時進行智慧儀式,坐在月光下,握著珍珠或月光石,請求月亮女神賜予你智慧和洞見。使用茉莉或依蘭精油,它們連結陰性智慧和直覺。創建智慧日記,定期記錄你的洞見、學習和智慧。這成為你個人的智慧之書。進行長者連結,拜訪、採訪或閱讀關於有智慧的長者,向他們學習。說肯定語：『我將挑戰轉化為智慧,我耐心地形成智慧的珍珠,我榮耀理性和直覺智慧,我的經驗是珍貴的教導,我分享我的智慧服務他人』。視覺化自己如珍珠龍,每一個經歷都增加一顆智慧的珍珠。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:32', 'dragons', '32', 31, '火山龍爆發', 'Volcano Dragon Eruption', NULL, '{"keywords":["爆發","釋放","重生"],"nameEn":"Volcano Dragon Eruption"}', '{"message":"火山龍居住在活火山中,它代表長期積累的壓力和能量的爆發性釋放。火山看似平靜,但內部岩漿持續積累壓力,最終必須釋放。這種釋放雖然具有破壞性,但也是必要和淨化的,它為新生命和成長創造條件。火山灰肥沃土地,火山島從海洋中誕生。火山龍問你:你內在積累了多少壓力、憤怒、挫折、未表達的情感？你一直壓抑和控制它們,但它們不會消失,只會積累壓力。火山龍說是時候釋放了,不是破壞性的爆發傷害自己或他人,而是有意識的、安全的、淨化的釋放。這可能感覺強烈甚至可怕,但壓抑是更危險的。釋放後,你會感到輕盈、清爽、重生,就像火山爆發後土地變得肥沃。火山龍也可能指出你正經歷或即將經歷重大的生命轉變或危機——關係、工作、身份的爆發性結束或改變。這雖然混亂,但它為新生命騰出空間。","guidance":"承認和接納你積累的情緒和壓力,不要繼續壓抑或否認。找到安全和健康的方式釋放它們。進行情緒釋放練習,如大聲吼叫(在車裡或空曠處)、劇烈運動、打枕頭、撕紙、哭泣。讓身體釋放積累的能量。進行憤怒儀式,寫一封你永遠不會寄出的憤怒信,說出所有壓抑的話,然後安全地燃燒它,釋放那份能量。尋求專業支持如治療師,特別如果情緒非常強烈或創傷性的,專業協助能確保安全和有效的釋放。創造定期的情緒衛生習慣,不要等到積累到爆發點,定期檢視和釋放情緒。如果你正經歷生命的爆發性改變,允許混亂和不確定性,不要試圖立即重建或控制。給自己空間和時間處理失落、悲傷、憤怒。信任在混亂之後會有新的開始和成長。在火山爆發般的時刻,確保基本的自我照顧——睡眠、營養、支持,這些幫助你度過風暴。","energy":"黑曜石是火山玻璃,是最好的火山龍水晶,它幫助安全釋放積累的負面能量並提供保護。紅碧玉支持你在強烈釋放時保持扎根。進行火山龍釋放冥想,想像你是一座火山,感受內在積累的壓力和能量,然後允許它爆發釋放,看見熔岩噴出,帶走所有壓抑的情緒。釋放後感受輕盈和平靜。進行實際的火儀式,安全地燃燒代表你想釋放的東西,觀看火焰轉化它。使用辛辣或強烈的精油如肉桂或丁香,它們幫助釋放停滯的能量。進行動態運動或舞蹈,讓身體強烈移動和表達,釋放積累的能量。用冷熱對比浴,從熱到冷快速交替,這能釋放和重置能量系統。在釋放後進行扎根,吃東西、喝水、觸摸地面,確保能量整合。說肯定語：『我安全地釋放積累的情緒和壓力,我允許淨化的爆發,釋放後我重生並更新,舊的結束為新的開始創造空間』。視覺化火山爆發後的肥沃土地,新生命開始成長。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:33', 'dragons', '33', 32, '極夜龍深度', 'Polar Night Dragon Depth', NULL, '{"keywords":["深度","內在","神秘"],"nameEn":"Polar Night Dragon Depth"}', '{"message":"極夜龍來自極地的漫長黑夜,那裡太陽數月不升起,只有星星和極光照亮黑暗。它代表深入黑暗、進入內在深處、面對神秘和未知的旅程。在我們的文化中,黑暗被視為負面和可怕的,但極夜龍教導你,黑暗是神聖的子宮,是所有創造誕生的地方,是深度休息和恢復的空間。沒有黑暗,就沒有光的對比;沒有夜晚,就沒有星星的可見。極夜龍邀請你進入你的內在深處,那些你通常避免或忽略的地方——你的恐懼、陰影、痛苦、神秘。在那裡,埋藏著你最大的力量和最深的智慧。這個旅程需要勇氣,因為在黑暗中你看不清楚,你必須用其他感官——直覺、感受、內在知曉。極夜龍是你的嚮導,確保你在黑暗中不會迷失,而是找到你來尋找的寶藏。極夜龍也提醒你深度休息和冬眠的必要性,不是所有時刻都該是光明和行動的。","guidance":"允許自己進入內在的黑暗期,這可能是實際的冬季、生命的低谷期或靈性的暗夜。不要抗拒或逃避它,而是好奇地探索:這個黑暗要教導我什麼？進行陰影工作,這是進入內在深處的實踐,辨識、接納和整合你壓抑的部分。這工作最好在專業治療師或嚮導的支持下進行。培養舒適與黑暗和寂靜相處的能力,在黑暗中冥想、關燈獨處、在新月夜散步。學會在沒有視覺的情況下導航,依靠你的內在感官。深化你的冥想和內省練習,不要只是表面的放鬆,而是真正向內深入,探索意識的深處。進行感官剝奪實驗如漂浮艙或眼罩冥想,在沒有外在刺激時,你能接觸更深的內在。研究神秘傳統,如煉金術、諾斯底、深層心理學,它們教導進入和轉化黑暗的智慧。榮耀休息和再生,在黑暗期,不要強迫自己行動或生產,而是深度休息和充電,為下一個光明期準備。","energy":"黑曜石或黑碧璽連結深度和保護,它們幫助你安全地進入黑暗而不被其吞沒。星光黑曜石帶來星星在黑夜中的希望之光。進行極夜冥想,想像你在極地的黑暗中,沒有太陽,只有星星和極光。感受黑暗不是空無或恐怖,而是深沉、寧靜、充滿神秘可能性。在新月時進行黑暗儀式,這是月亮的黑暗面,完全關燈坐在黑暗中,讓眼睛適應,進入內在深處。使用沒藥或檀香精油,它們神聖而扎根,支持深度內在工作。進行感官剝奪冥想,戴眼罩和耳塞,移除外在刺激,向內深潛。在實際的極夜如果可能,訪問極地地區體驗長夜。聽深沉的音頻或雙耳節拍,引導你進入深度意識狀態。說肯定語：『我勇敢地進入我的內在深處,我在黑暗中找到智慧和力量,神秘是我的老師,黑暗是神聖的子宮,我榮耀光明和黑暗』。視覺化自己如極夜龍在黑暗中自在移動,眼睛在黑暗中閃耀智慧之光。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:34', 'dragons', '34', 33, '蓮花龍純淨', 'Lotus Dragon Purity', NULL, '{"keywords":["純淨","超越","神聖"],"nameEn":"Lotus Dragon Purity"}', '{"message":"蓮花龍如蓮花般誕生於泥濘,卻綻放出純淨無瑕的花朵。它是超越的象徵——從世俗升華為神聖,從污染中保持純淨,從苦難中綻放美麗。蓮花龍教導你,你的環境和過去不定義你,你可以超越它們。無論你來自什麼樣的家庭、經歷了什麼創傷、生活在什麼情況,你都可以選擇成為純淨和美麗的。蓮花龍也代表靈性的純淨——超越自我、欲望、執著,到達更高意識。這不是壓抑或否認人性,而是整合並超越它。蓮花的根在泥中,莖在水中,花在空中——象徵身體扎根地球,情感流動如水,靈性開放向天空。蓮花龍邀請你整合這三個層面,成為完整而純淨的存有。它也提醒你,純淨不是天真或與世隔絕,而是經歷世界但不被污染,碰觸黑暗但不成為黑暗。","guidance":"進行純淨冥想,想像你如蓮花從泥濘中成長,經過水面,在陽光下開花。感受你超越過去和環境的能力,你的本質是純淨的。釋放羞恥和罪疚感,它們玷污你對自己的看法。你的過去和錯誤不是你,你的本質始終純淨。練習非執著,這是靈性純淨的核心,學習經歷和享受生活但不執著於結果、人或物。培養見證意識,學習觀察你的思想、情感和經歷但不完全認同它們,保持內在的純淨和清晰。進行道德和正直的生活,純淨也表現在你的行動,誠實、善良、不傷害。清理和淨化你的身體、環境和能量,定期排毒、清潔、淨化儀式。在污染或負面的環境中保護你的能量和純淨,使用能量盾、祈禱、水晶或儀式。超越二元對立,看見超越好壞、光暗、神聖世俗的合一。在最平凡中看見神聖,在最困難中看見成長機會,這是蓮花龍的視角。","energy":"白蓮花能量或白色水晶如白水晶、透石膏連結純淨和高頻。粉晶帶來純淨的無條件愛。進行蓮花冥想,視覺化你的頂輪如千瓣蓮花開放,純淨的光從中流出。或想像你坐在蓮花上漂浮在水面,不被水沾濕,象徵在世間但不被世俗污染。用白色蠟燭和蓮花精油(如果有)或茉莉精油進行淨化儀式。在滿月時進行純淨浴,在水中加入海鹽、白玫瑰花瓣和白水晶,浸泡並觀想所有不純淨被洗去。穿白色或淺色衣物,象徵純淨。進行素食或純淨飲食一段時間,從內在淨化身體。說純淨咒語或祈禱,連結你的宗教或靈性傳統中純淨的概念。說肯定語：『我的本質是純淨的,我超越過去和環境,我從泥濘中綻放為美麗的蓮花,我在世間但不被世俗污染,我活出純淨和神聖』。在蓮花池或圖片前冥想,連結蓮花龍的能量。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:35', 'dragons', '35', 34, '寶石龍豐富', 'Gem Dragon Richness', NULL, '{"keywords":["豐富","多樣","寶藏"],"nameEn":"Gem Dragon Richness"}', '{"message":"寶石龍的身體鑲嵌著各種寶石——紅寶石、藍寶石、祖母綠、鑽石——每一種都獨特而珍貴。它代表生命的豐富性和多樣性,提醒你世界充滿無數種類的美、經驗、人、文化、觀點。寶石龍邀請你欣賞和慶祝這種多樣性,而不是尋求單一或一致性。每個人如不同的寶石,有獨特的顏色、質地和光芒,沒有哪一個比另一個更好,只是不同。寶石龍也提醒你,你自己就是寶藏,你擁有的禮物、才華、經驗、智慧是獨特和珍貴的。不要低估或隱藏你的寶石,讓它們閃耀。同時,認識到每個人都是寶藏,帶著敬意和好奇接觸他人,尋找他們的寶石。寶石龍還教導你欣賞生命的豐富性——感官的愉悅、藝術的美、自然的驚奇、關係的深度。生命不只是生存或目標達成,更是充分體驗它的豐富多彩。","guidance":"探索和欣賞多樣性,接觸不同文化、音樂、藝術、食物、觀點。旅行、閱讀、學習,擴展你對世界豐富性的認識。在你的社群和關係中尋找多樣性,與不同背景的人連結,從差異中學習。辨識和榮耀你的獨特寶石,列出你的才華、優勢、知識、經驗。認可這些是珍貴的,分享它們服務他人。幫助他人看見他們的寶石,給予真誠的讚美和認可,幫助人們認識他們的價值和獨特性。充分體驗生命的豐富性,不要機械地過日子,而是真正品嘗食物、欣賞藝術、聆聽音樂、感受質地、觀察顏色。培養審美和對美的欣賞,讓美滋養你的靈魂。收集豐富的經驗而非只是物品,雖然物質豐盛也美好,但經驗、記憶、關係的豐富更持久和有意義。慶祝差異而非尋求一致性,在關係、工作、創意中,允許和欣賞不同的風格和方法。創造豐富多彩的生活,在各個領域——關係、工作、興趣、學習——追求豐富性而非單一性。","energy":"各種寶石水晶連結寶石龍的能量,創建一個寶石網格,使用多種顏色和類型的水晶——紅寶石、藍寶石、祖母綠、紫水晶等。看著這個彩虹般的網格,欣賞多樣性和豐富性。佩戴多寶石飾品或在不同脈輪位置放置不同寶石,平衡並活化所有能量中心。進行寶石龍冥想,想像你進入一個充滿寶石的洞穴,各種顏色和光芒,每一顆都獨特。感受這種豐富性和美麗。選一顆吸引你的寶石,它代表你現在需要的能量。創建豐富祭壇,放置各種寶石、彩色蠟燭、美麗物品、藝術品,慶祝生命的豐富性。使用花香精油如玫瑰或茉莉,它們豐富而奢華。說肯定語：『我慶祝生命的豐富和多樣性,我是獨特而珍貴的寶石,我欣賞每個人的獨特寶藏,我充分體驗生命的豐富多彩,我的生命閃耀著各種光芒』。視覺化自己如寶石龍,身上每一顆寶石代表你生命的一個面向、才華或經驗,全都珍貴且共同創造你的美麗。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:36', 'dragons', '36', 35, '月光龍直覺', 'Moonlight Dragon Intuition', NULL, '{"keywords":["直覺","陰性","週期"],"nameEn":"Moonlight Dragon Intuition"}', '{"message":"月光龍在月光下翱翔,它的鱗片反射著銀色的光芒,隨著月亮的盈虧而變化。它是陰性能量、直覺智慧和自然週期的守護者。月光龍教導你聆聽內在的聲音,那個超越邏輯和理性的知曉。你的直覺是靈魂的語言,它透過感受、預感、夢境、身體訊號來溝通。現代社會過度重視理性和證據,但月光龍提醒你,有些真理無法被證明卻深刻真實。學習信任你的直覺,即使它不合邏輯。月光龍也連結女性能量和週期性。就像月亮有盈虧,你的能量也有高低,你的情緒也有起伏。這是自然的,不要對抗它。在能量高漲時行動,在能量低落時休息。榮耀你的陰性面——接納、滋養、直覺、創造、流動——無論你的性別。我們都包含陰陽兩面,平衡它們才能完整。月光龍也是夢境和潛意識的引導者,邀請你探索內在的神秘領域。","guidance":"培養和信任你的直覺,注意你的第一反應、身體的感受、突然出現的想法或意象。不要立刻用理性否定它們,記錄並驗證。進行直覺訓練,在做小決定時問自己:『我的直覺說什麼?』然後跟隨它,看看結果。隨著練習,你會越來越信任內在的指引。榮耀陰性能量,無論你的性別。培養接納、同理、滋養、創造的品質。允許自己柔軟、敏感、情緒化,這些不是弱點而是力量。在競爭中平衡合作,在行動中平衡存在,在邏輯中平衡直覺。與月亮週期共舞,注意月亮如何影響你的能量和情緒。在新月設定意圖,在滿月慶祝和釋放。調整你的活動配合你的自然週期,在高能量期推進項目,在低能量期反思和休息。探索夢境,在床邊放筆記本,醒來立刻記錄夢境。夢是潛意識的訊息,學習它的象徵語言。培養夜間儀式如睡前冥想或日記,連結月光龍的夜間能量。平衡陽性和陰性,如果你過度陽性(行動、控制、理性、外向),邀請更多陰性。如果過度陰性(被動、情緒化、幻想、內向),邀請更多陽性。目標是整合,不是選擇一個。","energy":"月光石是月光龍的水晶,連結月亮能量,強化直覺和陰性特質。拉長石活化第三眼,打開靈視和直覺。在滿月時將這些水晶放在月光下充能,然後隨身攜帶或在冥想時使用。進行月光浴,在滿月夜晚到戶外,讓月光灑在你身上,吸收月亮的能量。這對女性特別有益,平衡荷爾蒙和月經週期。創建月亮祭壇,放置銀色物品、月光石、白色蠟燭、代表月亮的圖像。在每個月相更新祭壇,新月時種植意圖,滿月時收割和感恩。進行月光龍冥想,在月光下或想像月光中,視覺化月光龍降臨,邀請它分享直覺和智慧。問它一個問題,靜靜接收答案。使用茉莉或依蘭精油,它們香甜而陰性,打開心輪和第三眼。說肯定語:『我信任我的直覺,我與月亮的週期共舞,我榮耀我的陰性能量,我在陰陽之間平衡,我探索我的夢境和潛意識,月光照亮我的道路』。跟隨月相進行儀式和魔法工作,這是古老的智慧。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:37', 'dragons', '37', 36, '黎明龍希望', 'Dawn Dragon Hope', NULL, '{"keywords":["希望","新生","開始"],"nameEn":"Dawn Dragon Hope"}', '{"message":"黎明龍在第一道曙光中甦醒,它的到來宣告黑夜已過,新的一天開始。無論昨天多麼黑暗或困難,太陽總會再次升起。黎明龍是希望、新生和新開始的化身。它的出現告訴你,無論你經歷什麼,這也會過去,曙光就在前方。希望不是天真的樂觀或否認困難,而是深刻的信任——信任生命的循環,信任黑暗之後必有光明,信任你有力量度過並成長。黎明龍邀請你在絕望中找到希望,在結束中看見新的開始。也許一段關係結束,但新的愛等待著;也許一個工作失去,但更好的機會出現;也許你失去什麼,但這創造了空間接收更適合你的。每個日出都是奇蹟,每個新的一天都是新的機會。黎明龍教導你,你隨時可以重新開始,過去不能定義你,每個當下你都可以選擇不同的方向。新生是你的本質,你不斷地在每個呼吸中重生。","guidance":"在困難時刻,記住這句話:『這也會過去。』無論多痛苦,都是暫時的。黑夜最深之時,黎明最近。堅持,希望,信任。尋找希望的跡象,即使在黑暗中,總有微小的光。也許是朋友的支持,也許是內在的力量,也許是大自然的美麗。專注在這些光點,讓它們滋養你的希望。每天都當作新的開始,醒來時說:『今天是新的一天,充滿無限可能』。不要被過去的錯誤或遺憾束縛,每個早晨都給你重新開始的機會。進行黎明儀式,如果可能,在日出時醒來,觀看太陽升起,感受那種新生的能量。或者只是在早晨有意識地迎接新的一天。釋放昨天的包袱,放下昨天的憤怒、失望、憂慮。每晚睡前進行釋放儀式,寫下你想放下的,然後撕掉或燒掉。醒來時輕盈和新鮮。在生命的轉折點,當某個章節結束,悲傷是自然的,但也要慶祝新章節的開始。為新事物騰出空間。保持信念和樂觀,不是盲目而是有意識的選擇。即使證據指向黑暗,選擇相信光明。你的信念創造你的現實。分享希望,當他人絕望時,成為希望的使者。提醒他們,黎明總會到來。","energy":"黃水晶充滿陽光能量,帶來希望、樂觀和正面性。太陽石連結太陽的能量,點燃內在的光。每天早晨,握著這些水晶,面向東方,吸收日出的能量。即使看不見太陽,也能感受它的存在。進行日出冥想,在黎明時分坐著,看著天空從黑暗變為光明,感受這種轉變在你內在發生。視覺化黎明龍在日出中飛翔,帶來新生和希望的能量。使用柑橘精油如橙子、檸檬或葡萄柚,它們明亮而振奮,喚醒希望和喜悅。在早晨擴香或吸聞,開始充滿希望的一天。創建黎明祭壇,使用金色和橙色的物品、太陽的圖像、向日葵或其他向陽的花。放在東方,每天早晨在那裡冥想或祈禱。說肯定語:『每一天都是新的開始,我充滿希望和信任,黑暗之後必有光明,我在每個當下重生,我的未來明亮和充滿可能性,我是希望的使者』。進行新生儀式,當你想要新開始時,在黎明時沐浴,想像洗去舊的,穿上新的衣服,象徵性地重生為新的你。慶祝小的新開始,不只是大的生命轉折,每個早晨、每週、每月都是新開始,標記和慶祝它們。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:38', 'dragons', '38', 37, '星辰龍命運', 'Stellar Dragon Destiny', NULL, '{"keywords":["命運","宇宙","使命"],"nameEn":"Stellar Dragon Destiny"}', '{"message":"星辰龍在浩瀚星空中游走,它的身體如夜空般深邃,點綴著無數星辰。每一顆星星都是一個靈魂,每個靈魂都有其獨特的光芒和軌跡。星辰龍是宇宙秩序和神聖計劃的守護者,它提醒你,你的生命不是隨機或無意義的,你帶著特定的使命來到地球。在出生前,你的靈魂選擇了這一世的課題、挑戰和禮物,你選擇了你的家庭、環境和主要經驗來學習和成長。星辰龍邀請你從更高的視角看待你的生命,理解沒有意外,一切都有其目的和意義。你經歷的困難不是懲罰,而是成長的機會;你遇見的人不是偶然,而是靈魂契約。星辰龍也連結你的靈魂使命——你為什麼在這裡,你來做什麼,你的獨特貢獻。每個人都有天賦和使命,但很多人從未發現或活出它。星辰龍問你:你在活出你的使命嗎?你在綻放你的獨特之光嗎?","guidance":"探索你的靈魂使命,什麼讓你感到活著和有意義?什麼是你自然擅長且享受的?什麼問題或需求觸動你的心?你的使命往往在這些交集處。不要尋找一個單一的大使命,你的使命可能在日常的小事中——如何你對待他人,你帶給世界什麼能量,你如何使用你的禮物。從靈魂的視角看待你的生命,當面對困難時問:『這教導我什麼?我靈魂想通過這個經驗學習什麼?』這種視角轉變痛苦為成長的機會。相信神聖時機,一切都在完美的時間發生,沒有太早或太遲。如果某事還未發生,意味著你或情境還未準備好。信任並繼續準備自己。研究靈魂契約,你生命中的重要人物——家人、伴侶、朋友、甚至敵人——都是你的靈魂契約的一部分,他們來幫助你學習和成長。看見每個人的神聖角色,即使是那些帶來痛苦的人。連結更大的宇宙智慧,你不是孤單的,你是宇宙的一部分,無限的智慧流經你。進行冥想或祈禱,請求指引和清晰度關於你的使命。活出你的真相,你的使命不是你必須找到或創造的外在事物,而是你必須成為的內在狀態。當你活出你的真相、愛和獨特性,你就在履行你的使命。","energy":"拉長石或光譜石連結宇宙和星辰能量,打開通往高我和宇宙智慧的通道。紫龍晶結合紫色和綠色,平衡靈性追求和地球使命。在夜晚進行星空冥想,躺著或坐著,凝視星空,感受自己是浩瀚宇宙的一部分。視覺化星辰龍在星空中飛翔,邀請它顯示你的靈魂使命。進行出生圖或占星學研究,雖然這不是必須,但你的出生圖確實包含你靈魂使命的線索。至少了解你的太陽、月亮和上升星座,以及北交點(代表今生的成長方向)。創建使命宣言,坐下來寫:『我的靈魂使命是...』讓直覺引導你,不要審查或批判。寫下來後,放在你每天能看見的地方,讓它引導你的選擇和行動。進行前世回溯或閱讀,如果你感興趣,探索前世可以幫助理解今生的模式和使命。使用乳香精油連結神聖和宇宙意識。說肯定語:『我連結我的靈魂使命,我在正確的道路上,我信任神聖的計劃,我的生命有意義和目的,我綻放我的獨特之光,我與宇宙智慧對齊』。定期反思你的生命方向,至少每季度檢視:我在朝著我的使命前進嗎?我需要調整什麼?"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:39', 'dragons', '39', 38, '翡翠龍心輪', 'Jade Dragon Heart', NULL, '{"keywords":["愛","療癒","心輪"],"nameEn":"Jade Dragon Heart"}', '{"message":"翡翠龍守護著心輪,愛與療癒的中心。它的綠色光芒柔和而有力,能融化心牆,療癒心傷。翡翠龍教導你,愛是生命的核心,是最強大的療癒力量,是你真正的本質。但要給予愛,你必須先對自己有愛。太多人因為童年創傷、社會制約或過去的傷害而關閉了心。你可能建立了厚重的牆來保護自己不再受傷,但這些牆也阻擋了愛的流入。翡翠龍溫柔地敲打你的心門,邀請你再次打開,再次冒險,再次信任。是的,敞開心會讓你脆弱,但只有脆弱才能真正連結和愛。翡翠龍也療癒舊的心傷——被拒絕的痛、被背叛的傷、失去的悲,這些如果不被療癒,會累積在心輪,造成身體和情緒問題。是時候釋放這些舊傷,不是否認或忘記,而是感受、接納並放下。翡翠龍幫助你學習無條件的愛——對自己和他人,不帶評判、期待或控制,只是純粹的接納和慈悲。","guidance":"進行心輪療癒,首先承認你的心傷。列出過去傷害你的事件和人,允許自己感受當時的情緒。然後有意識地選擇寬恕和放下,不是為了他們,而是為了釋放你自己。寫寬恕信(不需要寄出)或進行寬恕儀式。練習自我慈悲,像對待最好的朋友一樣對待自己。當內在批評的聲音出現,轉換為慈愛的聲音。每天對著鏡子說:『我愛你,我接納你』。起初可能感覺尷尬或假,但持續練習,它會成為真實。逐步打開心,不需要一下子完全敞開,那太可怕。從安全的關係開始,與信任的朋友或家人分享更深的感受。隨著信心增長,逐漸擴展你的脆弱性和開放。建立界限,打開心不意味著讓任何人傷害你。學習健康的界限,說不,保護你的能量,同時保持心的開放。這是可能的:有界限的開放。給予和接受愛,檢視你是更善於給予還是接受。許多人善於給但不善於接收,這會造成失衡。練習說『謝謝』並接收他人的愛、幫助、讚美,不要貶低或拒絕。同樣,確保你也在給予,表達愛、感激和欣賞給你在乎的人。","energy":"玉石或綠東陵連結翡翠龍和心輪,帶來溫和的療癒能量。粉晶是無條件愛之石,療癒心傷,打開接收愛的能力。將這些水晶放在心輪位置(胸骨中心)冥想。進行心輪呼吸,吸氣時想像綠色或粉紅色的光進入心輪,呼氣時釋放所有痛苦和阻塞。每天練習10分鐘。進行慈心禪(Loving-kindness Meditation),重複這些話:『願我快樂,願我平安,願我自在,願我被愛』。然後擴展到他人。使用玫瑰精油打開心輪,玫瑰是最高頻的植物之一,連結無條件的愛。在心輪擦玫瑰精油或泡玫瑰浴。創建心輪祭壇,使用綠色和粉紅色物品、心形物件、玫瑰花、心輪水晶。每天在祭壇前進行愛和寬恕的練習。說肯定語:『我的心是開放和療癒的,我值得愛和被愛,我寬恕過去並釋放所有心傷,我給予和接收愛自如,我的本質是愛,我與翡翠龍的療癒能量連結』。進行心臟相干練習,專注在心臟區域,回憶一個充滿愛或感激的時刻,停留在那個感受中。這能平衡心臟節律,創造身心的和諧。每當感到壓力或心痛,回到這個練習。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:40', 'dragons', '40', 39, '紫晶龍覺醒', 'Amethyst Dragon Awakening', NULL, '{"keywords":["覺醒","靈性","第三眼"],"nameEn":"Amethyst Dragon Awakening"}', '{"message":"紫晶龍閃耀著深紫色的光芒,它守護著第三眼和頂輪,是靈性覺醒和意識擴展的引導者。當紫晶龍出現,它宣告你正在經歷或即將經歷靈性覺醒——你開始質疑舊的信念,尋找更深的意義,感知到超越物質世界的實相。覺醒是一個美麗但有時混亂的過程,因為你的世界觀在轉變,你可能感到與舊的生活或人脫節,因為你的頻率在提升。紫晶龍陪伴你通過這個過渡,提供清晰和保護。它教導你打開第三眼,發展靈視、直覺和靈性感知。你不只是一個物質的身體,你是一個靈性的存在擁有人類經驗。連結這個真相改變一切。紫晶龍也幫助你清理和保護你的能量場,因為隨著你變得更敏感,你會感受到他人和環境的能量。學習能量衛生和保護是重要的。覺醒不是到達某個狀態就停止,而是一個持續展開的過程,每一天你都在成為更完整、更覺知、更對齊你真實本質的版本。","guidance":"擁抱你的覺醒旅程,如果你正在經歷懷疑、困惑或孤獨,知道這是正常的。加入靈性社群,與同頻的人連結,他們能理解和支持你。發展你的靈性實踐,冥想、瑜伽、能量工作、儀式,找到適合你的方式連結更高的自己和宇宙。一致性比強度重要,每天10分鐘的練習勝過偶爾一次長時間。打開第三眼,進行第三眼冥想,專注在兩眉之間,想像一個靛藍色的光在那裡旋轉和打開。請求看見真相和接收靈性視野。注意你的夢、直覺和同步性。學習能量保護,當你的能量場打開,你會吸收他人和環境的能量。每天早上視覺化自己被光或保護罩包圍,設定意圖只允許愛和光進入你的能量場。定期清理你的能量,用鼠尾草、歌唱、鹽浴或能量工作。平衡靈性和物質生活,覺醒不意味著離開世界或忽略實際責任。目標是將靈性整合進入日常生活,在世間但不屬於世間。照顧好你的身體,吃純淨的食物,充足休息,接地,這支持你的靈性工作。保持辨別,不是所有靈性資訊或老師都是真實或適合你的。發展你的辨別力,只接受與你內在真相共鳴的。你的內在指引是最高的權威。","energy":"紫水晶是紫晶龍的水晶,連結第三眼和頂輪,促進靈性覺醒和保護。透石膏連結天使界和高頻能量。將紫水晶放在第三眼或頂輪冥想,或在睡覺時放在枕頭下,增強夢和靈性連結。進行紫晶龍冥想,視覺化紫晶龍降臨,它的紫色光芒照亮你的第三眼和頂輪,打開你的靈性感知。請求它幫助你的覺醒和保護你的旅程。使用薰衣草或乳香精油,它們連結靈性和平靜心智,幫助冥想和連結高我。創建靈性祭壇,放置紫水晶、白蠟燭、代表靈性的圖像(如天使、揚升大師、神聖幾何)、神聖文本。每天在祭壇前冥想或祈禱,這是你的神聖空間。進行滿月儀式,紫水晶與月亮能量協調,在滿月時進行釋放和充能儀式,將你的紫水晶放在月光下。說肯定語:『我正在覺醒到我真實的本質,我的第三眼是開放和清晰的,我連結宇宙智慧和高我,我受到保護和引導在我的靈性旅程,我整合靈性和物質生活,我是光的存在,我與紫晶龍的覺醒能量對齊』。研讀靈性教導,閱讀啟發你的書籍,聆聽智慧老師,但最重要的,發展你自己的內在知曉。外在老師指向真理,但真理必須在你內在實現。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:41', 'dragons', '41', 40, '黑耀龍陰影', 'Obsidian Dragon Shadow', NULL, '{"keywords":["陰影","整合","深度"],"nameEn":"Obsidian Dragon Shadow"}', '{"message":"黑耀龍如黑曜石般深黑,它守護著陰影——你被壓抑、否認或投射的那些自我部分。榮格心理學教導,陰影包含我們不接受的特質,無論是負面的(如憤怒、嫉妒、自私)還是正面的(如力量、才華、美麗)。我們把這些特質推入無意識,但它們不會消失,它們在陰影中累積力量,以症狀、模式、投射和自我破壞的方式出現。黑耀龍邀請你勇敢地面對你的陰影,不是為了擊敗或消除它,而是為了認識、接納和整合它。陰影工作不是愉快或輕鬆的,它需要深刻的誠實和勇氣,去看見你寧願忽略的真相。但這是成為完整的必經之路。當你整合陰影,你會收回巨大的能量和力量,你會變得更真實、更完整、更自由。黑耀龍也是真相之鏡,它反射你的真實面貌,不帶美化或批判,只是如實。在它的黑色鏡面中,你會看見你的光明和黑暗,你的優勢和弱點,你的真實自我。","guidance":"開始陰影工作,注意你強烈的情緒反應和評判,這些是陰影的線索。當你對某人某事有過度的反應,問自己:『這觸發了我什麼?這反映了我的什麼未癒合部分?』你在他人身上批判的往往是你自己未接納的特質。進行投射收回練習,列出你強烈反感的人和特質,然後誠實地問:我身上有這個特質嗎?我在什麼情況下也會這樣?即使程度或表達方式不同,種子通常存在。承認它,你就收回了投射,奪回了力量。探索你的禁忌和羞恥,我們的陰影往往包圍著羞耻——那些我們認為『如果別人知道就不會愛我』的部分。在安全的空間(如治療、日記、信任的朋友)分享這些,你會發現它們失去力量,暴露在光中的陰影縮小。與你的內在孩子工作,許多陰影源於童年,當我們為了被愛和接納而壓抑某些部分。連結你的內在孩子,給予他/她無條件的愛和接納,療癒那些舊傷。整合而非消除,陰影工作的目標不是變成『好人』或消除『壞』的部分,而是整合所有部分成為完整的你。你的憤怒,正確引導,是界限和正義的力量;你的自私,平衡後,是自我照顧。每個特質都有其光明面。","energy":"黑曜石是陰影工作的完美水晶,它如黑色鏡子,反射真相並保護你在深度工作中。煙晶轉化陰影能量為光。握著黑曜石進行陰影冥想,準備好面對不舒服的真相。進行鏡子凝視,在柔和光線中凝視鏡中的自己15分鐘,不帶評判,只是觀看。你會看見超越表面的東西,也許不同的面貌、情緒、甚至前世。這是深刻的陰影工作。寫陰影日記,用非慣用手寫(右撇子用左手),這能繞過意識的審查,讓陰影聲音浮現。問陰影問題如『你想告訴我什麼?你需要什麼?』然後寫下任何浮現的。進行黑暗靜修,在完全黑暗中坐著(關燈、蒙眼),黑暗是陰影的領域。在黑暗中,你可以更自由地探索被隱藏的。使用沒藥精油,它深沉和扎根,支持深度內在工作。說肯定語:『我勇敢地面對我的陰影,我接納我的全部,光明和黑暗,我整合我被壓抑的部分,我在真相中找到自由,我是完整和完全的,我與黑耀龍的深度智慧連結』。尋求支持,陰影工作可能激烈,不要獨自做,找治療師、教練或支持團體陪伴你的旅程。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:42', 'dragons', '42', 41, '鑽石龍不朽', 'Diamond Dragon Immortality', NULL, '{"keywords":["不朽","純淨","堅不可摧"],"nameEn":"Diamond Dragon Immortality"}', '{"message":"鑽石龍閃耀著最純淨最明亮的光,它的身體如鑽石般堅不可摧。鑽石是碳在極端壓力和高溫下形成的,它象徵著通過試煉而達到的純淨和力量。鑽石龍教導你,你的本質如鑽石般不朽——外在環境可能改變,身體可能衰老,但你的靈魂永恆而不朽。你不是暫時的人格或身體,你是永恆的意識,穿著人類的外衣體驗這個世界。當你認識到這個真相,死亡的恐懼消失,你活得更自由和大膽。鑽石龍也代表你在壓力下鍛造的力量和智慧。你經歷的每個困難,如同鑽石形成的壓力,把你塑造得更強大、更清晰、更有價值。不要怨恨你的試煉,它們是你成為鑽石的過程。鑽石龍還教導絕對的純淨和清晰——清除所有雜質,只留下真實的本質。它邀請你淨化你的思想、言語、行為,活出最高的完整性。在鑽石龍的光芒下,一切虛假都無所遁形,只有真實永存。","guidance":"連結你的不朽本質,進行冥想觀察你的身體、思想、情緒,認識到你不是這些,你是觀察者。身體會老,思想會變,情緒會流動,但觀察的意識始終如一,那就是真實的你——永恆不變的意識。這種認識帶來深刻的平靜和自由。將壓力視為鍛造,當面對困難時,記住鑽石的形成過程。告訴自己:『這個壓力正在把我鍛造成鑽石,我正在變得更強大、更清晰、更有價值』。這種視角轉變讓你不是受害者而是轉化者。追求純淨和完整性,檢視你生活的每個領域——你的思想、言語、行為、關係、工作——是否對齊你最高的價值和真理。清除任何不對齊的,即使這很困難。活在完整性中創造內在的平和和力量。淨化你的能量和環境,就像鑽石的純淨,保持你的能量場和生活空間清潔和純淨。定期清理,釋放不服務你的,只保留真正重要和有價值的。培養不朽的視角,做決定時,不只考慮短期後果,也考慮長期和永恆的影響。這個選擇會把我帶向我的最高善嗎?這對齊我靈魂的旅程嗎?榮耀你通過試煉獲得的智慧,你不是你曾經的天真的你,你是經過考驗和鍛造的鑽石。榮耀你的力量和智慧,分享它們幫助他人通過他們的鍛造過程。","energy":"鑽石或透明水晶連結鑽石龍的能量,它們是最高頻和純淨的水晶,能清理和放大所有能量。將鑽石或水晶放在頂輪或心輪,連結你的不朽本質和最高意識。進行鑽石光冥想,視覺化自己被最明亮最純淨的白色鑽石光包圍和充滿。這個光淨化所有雜質,激活你的不朽本質。你就是這個光,堅不可摧、永恆、純淨。進行鑽石龍呼吸,吸氣想像吸入純淨的鑽石光,呼氣釋放所有不純淨。每次呼吸,你變得更純淨、更清晰、更接近你的真實本質。使用檀香精油,它神聖而純淨,連結不朽和永恆意識。創建純淨祭壇,只使用白色和透明的物品——白蠟燭、透明水晶、白花、純淨水。這是你連結最高自我和鑽石龍的神聖空間。說肯定語:『我的本質是不朽和永恆的,我是堅不可摧的意識,我在試煉中鍛造成鑽石,我活在純淨和完整性中,我是光,我是真理,我與鑽石龍的不朽能量合一』。進行純淨儀式,每月或每季度進行深度淨化——禁食、靜默、獨處、深度冥想。清除所有雜質,回歸本質。慶祝你的不朽,在生日或重要日子,不只慶祝這一世,慶祝你靈魂的永恆旅程。榮耀你走過的所有世代和學習,認識到你是古老而年輕、永恆而當下的存在。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:43', 'dragons', '43', 42, '宇宙龍無限', 'Cosmic Dragon Infinity', NULL, '{"keywords":["無限","宇宙","合一"],"nameEn":"Cosmic Dragon Infinity"}', '{"message":"宇宙龍是所有龍族中最廣闊的,它的身體包含整個宇宙——星系、星雲、行星、恆星都在它體內旋轉。宇宙龍代表無限意識和萬有合一。它提醒你,你不是孤立的個體,你是宇宙的一部分,或更確切地說,宇宙是你的一部分。你的意識不受限於你的頭腦或身體,它無限擴展,連結一切存在。當你連結宇宙龍的能量,你會體驗到無邊界、無分離、無限可能的狀態。所有看似分離的事物——你和他人、人類和自然、物質和精神——實際上都是一體的不同面向。宇宙龍教導你,你正在尋找的答案、愛、平和不在外面,而在無限的內在。你的內在空間如同外在宇宙般浩瀚,充滿無限的智慧、創造力和愛。當你向內探索,你會發現整個宇宙都在你之內。宇宙龍也連結無限可能性,你不受限於過去、現狀或他人的信念。在每個當下,無限的可能性存在,你可以選擇創造任何實相。","guidance":"練習宇宙意識冥想,閉上眼睛,想像你的意識從身體擴展,包圍房間、城市、國家、地球、太陽系、銀河系,直到你的意識包含整個宇宙。感受你與一切的連結,沒有分離,只有合一。在這個狀態中,所有問題和擔憂都變得微小和暫時。在日常生活中培養合一意識,看見每個人和事物都是神聖表達的一部分。那個陌生人是你的另一個版本;那棵樹與你分享同樣的生命力;那個困難是宇宙在教導你。當你從合一而非分離的視角生活,慈悲和愛自然流動。擁抱無限可能性,釋放限制性信念如『這不可能』或『我不能』。在宇宙龍的無限視野中,一切皆有可能。問自己:如果沒有任何限制,我會創造什麼生活?然後開始朝那個方向移動,一步一步。連結宇宙智慧,你有權訪問無限的智慧和知識,不只是你今生學到的,而是宇宙的集體智慧。在冥想中或通過靈感,這個智慧會流向你。保持開放和接收。探索你的內在宇宙,就像外在宇宙值得探索,你的內在世界也無限深邃和廣闊。通過冥想、內省、自我探索,發現你內在未知的領域、隱藏的才能、深層的智慧。你的內在宇宙等待你的探索。","energy":"拉長石連結宇宙和星際能量,打開通往多重維度的門戶。紫水晶連結宇宙意識和高我。將這些水晶放在第三眼或頂輪,進行宇宙龍冥想。進行宇宙呼吸,吸氣時想像吸入整個宇宙的能量——星光、行星力量、宇宙智慧,呼氣時將你的意識擴展到宇宙的每個角落。視覺化宇宙龍,它的身體如夜空,包含無數星系。邀請它帶你進入宇宙意識的體驗,感受無限和合一。使用乳香或雪松精油,它們古老而神聖,連結宇宙和永恆。創建宇宙祭壇,使用深藍或黑色布料象徵宇宙空間,放置星星圖像、行星模型、宇宙圖片、深色水晶如拉長石。在這個祭壇前冥想,連結宇宙能量。進行星空觀察,定期在晴朗的夜晚凝視星空,記住你正在看著數十億年前的光,連結時間和空間的浩瀚。說肯定語:『我是無限意識的一部分,我與萬有合一,我的可能性是無限的,我連結宇宙智慧,我的內在宇宙廣闊而深邃,我是宇宙龍,我是無限本身』。研讀宇宙學和天文學,了解宇宙的浩瀚和奧秘能擴展你的意識和視野,幫助你看見更大的圖景。同時記住,最偉大的宇宙就在你之內。"}');
INSERT INTO cards (id, deck_id, card_key, position, name, name_secondary, image, preview_payload, gated_payload) VALUES ('dragons:44', 'dragons', '44', 43, '永恆龍圓滿', 'Eternal Dragon Completion', NULL, '{"keywords":["圓滿","完成","永恆"],"nameEn":"Eternal Dragon Completion"}', '{"message":"永恆龍是第44張牌,象徵旅程的圓滿和回歸無限。它盤繞成一個完美的圓,頭尾相連,象徵銜尾蛇——無始無終、永恆循環、完整合一。永恆龍宣告你已經走過一段重要的旅程,你成長了、學習了、轉化了。是時候整合、慶祝和認可你的成就。但永恆龍也提醒你,圓滿不是終點而是新的開始,每個結束都是新的起點,生命是永恆的螺旋上升。你回到起點,但你已不是同一個人,你攜帶著智慧、力量和經驗。永恆龍教導你,你已經是完整的,你一直在尋找的完整、愛、平和已經在你之內。旅程不是為了到達某處或成為某人,而是記起你本來就是誰——無限的靈魂,永恆的意識,與萬有合一的存在。永恆龍祝福你,確認你在正確的道路上,鼓勵你繼續前進,帶著信任、愛和勇氣。","guidance":"反思和整合你的旅程,回顧你走過的路、學到的教訓、經歷的轉化。寫下你的洞見和成長。慶祝你的成就和進展,認可你的努力和勇氣,榮耀你成為的人。進行圓滿儀式,標記一個階段的結束,可以是燃燒代表舊的紙張、埋葬象徵物、釋放儀式。同時設定新的意圖,每個結束開啟新的開始,你準備好在下一個層次創造什麼？認識到你的完整性,你不缺任何東西,你不需要變得更好或不同才值得愛和幸福。你已經是完整的。活出這份認知。擁抱生命的循環性,理解結束和開始、死亡和重生、放手和接收都是永恆之舞的一部分。練習臣服和信任,釋放需要控制和知道一切的需求,信任更大的計劃和智慧正在運作。連結永恆和無限,超越時間和空間的局限性,觸及你永恆的本質——那個超越身體和個性的無限意識。活在當下,過去已去,未來未來,只有現在是永恆的。感恩,為所有經歷、所有老師、所有祝福和挑戰感恩,它們全都是你旅程的一部分。","energy":"透明石英是永恆龍的水晶,它代表純淨意識和無限可能性。紫水晶連結靈性智慧和宇宙意識。進行永恆龍冥想,想像永恆龍盤繞成圓,你坐在圓的中心。感受無始無終、無限循環、完整合一的能量包圍你。連結你的永恆本質,那個超越時間和形式的意識。進行銜尾蛇冥想,視覺化銜尾蛇符號,頭尾相連的蛇,象徵永恆和完整。觀想這個符號在你的能量場中旋轉,整合所有對立和二元性。使用乳香或檀香精油,它們神聖而永恆,連結更高意識。進行圓滿儀式,創建一個神聖圓圈,放置44顆水晶代表44張龍族牌,坐在中心,整合所有龍族的能量和教導。感恩每一條龍和它帶來的禮物。說肯定語：『我是完整的,我圓滿我的旅程並開始新的,我連結我的永恆本質,我是無限的意識體驗人類,我與萬有合一,每個結束是新的開始,我信任生命的永恆之舞』。視覺化自己與永恆龍合一,認識到你們從來不是分離的,你就是永恆龍,你就是你尋找的智慧和力量。祝福你的旅程,祝福所有眾生,願所有眾生圓滿和覺醒。"}');
